export const SHARANGADHARA_DATA = [
  {
    sthana: "Пурвакханда",
    number: 1,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Авасарпини кала — Временные циклы" },
      { type: "text", text: "Шарангадхара открывает трактат уникальной для аюрведы концепцией временных циклов (авасарпини и утсарпини), объясняющих деградацию медицинских знаний во времени." },
      { type: "verse", number: "1", sanskrit: "श्रियं स दद्याद्भवतां पुरारिर्यदङ्गतेजःप्रसरे भवानी विराजते निर्मलचन्द्रि कायां महौषधीव ज्वलिता हिमाद्रौ", text: "śriyaṃ sa dadyādbhavatāṃ purāriryadaṅgatejaḥprasare bhavānī virājate nirmalacandri kāyāṃ mahauṣadhīva jvalitā himādrau" },
      { type: "verse", number: "2", sanskrit: "प्रसिद्धयोगा मुनिभिः प्रयुक्ताश्चिकित्सकैर्ये बहुशोऽनुभूताः विधीयते शार्ङ्गधरेण तेषां सुसंग्रहः सज्जनरञ्जनाय", text: "prasiddhayogā munibhiḥ prayuktāścikitsakairye bahuśo'nubhūtāḥ vidhīyate śārṅgadhareṇa teṣāṃ susaṃgrahaḥ sajjanarañjanāya" },
      { type: "verse", number: "3", sanskrit: "हेत्वादिरूपाकृतिसात्म्यजातिभेदैः समीक्ष्यातुरसर्वरोगान् चिकित्सितं कर्षणबृंहणाख्यं कुर्वीत वैद्यो विधिवत्सुयोगः", text: "hetvādirūpākṛtisātmyajātibhedaiḥ samīkṣyāturasarvarogān cikitsitaṃ karṣaṇabṛṃhaṇākhyaṃ kurvīta vaidyo vidhivatsuyogaḥ" },
      { type: "verse", number: "4", sanskrit: "दिव्यौषधीनां बहवः प्रभेदा वृन्दारकाणामिव विस्फुरन्ति ज्ञात्वेति संदेहमपास्य धीरैः संभावनीया विविधप्रभावाः", text: "divyauṣadhīnāṃ bahavaḥ prabhedā vṛndārakāṇāmiva visphuranti jñātveti saṃdehamapāsya dhīraiḥ saṃbhāvanīyā vividhaprabhāvāḥ" },
      { type: "verse", number: "5", sanskrit: "स्वाभाविकागन्तुककायिकान्तरा रोगा भवेयुः किल कर्मदोषजाः तच्छेदनार्थं दुरितापहारिणः श्रेयोमयान्योगवरान्नियोजयेत्", text: "svābhāvikāgantukakāyikāntarā rogā bhaveyuḥ kila karmadoṣajāḥ tacchedanārthaṃ duritāpahāriṇaḥ śreyomayānyogavarānniyojayet" },
      { type: "verse", number: "6", sanskrit: "सर्वलोकहितार्थाय वक्ष्याम्यनतिविस्तरात्", text: "sarvalokahitārthāya vakṣyāmyanativistarāt" },
      { type: "verse", number: "7", sanskrit: "प्रथमं परिभाषा स्याद्भैषज्याख्यानकं तथा नाडीपरीक्षाऽदिविधिस्ततोदीपनपाचनम्", text: "prathamaṃ paribhāṣā syādbhaiṣajyākhyānakaṃ tathā nāḍīparīkṣā'dividhistatodīpanapācanam" },
      { type: "verse", number: "8", sanskrit: "ततः कलाऽदिकाख्यानमाहारादिगतिस्तथा रोगाणां गणना चैव पूर्वखण्डोऽयमीरितः", text: "tataḥ kalā'dikākhyānamāhārādigatistathā rogāṇāṃ gaṇanā caiva pūrvakhaṇḍo'yamīritaḥ" },
      { type: "verse", number: "9", sanskrit: "स्वरसः क्वाथफाण्टौ च हिमः कल्कश्च चूर्णकम् तथैव गुटिकालेहौ स्नेहाः संधानमेव च धातुशुद्धी रसाश्चैव खण्डोऽय मध्यमः स्मृतः", text: "svarasaḥ kvāthaphāṇṭau ca himaḥ kalkaśca cūrṇakam tathaiva guṭikālehau snehāḥ saṃdhānameva ca dhātuśuddhī rasāścaiva khaṇḍo'ya madhyamaḥ smṛtaḥ" },
      { type: "verse", number: "10", sanskrit: "स्नेहपानं स्वेदविधिर्वमनं च विरेचनम् ततस्तु स्नेहबस्तिः स्यात्ततश्चापि निरूहणम्", text: "snehapānaṃ svedavidhirvamanaṃ ca virecanam tatastu snehabastiḥ syāttataścāpi nirūhaṇam" },
      { type: "verse", number: "11", sanskrit: "ततश्चाप्युत्तरो बस्तिस्ततो नस्यविधिर्मतः धूमपानविधिश्चैव गण्डूषादिविधिस्तथा", text: "tataścāpyuttaro bastistato nasyavidhirmataḥ dhūmapānavidhiścaiva gaṇḍūṣādividhistathā" },
      { type: "verse", number: "12", sanskrit: "लेपादीनां विधिः ख्यातस्तथा शोणितविस्रुतिः नेत्रकर्मप्रकारश्च खण्डः स्यादुत्तरस्त्वयम्", text: "lepādīnāṃ vidhiḥ khyātastathā śoṇitavisrutiḥ netrakarmaprakāraśca khaṇḍaḥ syāduttarastvayam" },
      { type: "verse", number: "13", sanskrit: "द्वात्रिंशत्संमिताध्याययुक्तेयं संहिता स्मृता षड्विंशतिशतान्यत्र श्लोकानां गणितानि च", text: "dvātriṃśatsaṃmitādhyāyayukteyaṃ saṃhitā smṛtā ṣaḍviṃśatiśatānyatra ślokānāṃ gaṇitāni ca" },
      { type: "verse", number: "14", sanskrit: "न मानेन विना युक्तिर्द्र व्याणां जायते क्वचित् अतः प्रयोगकार्यार्थं मानमत्रोच्यते मया", text: "na mānena vinā yuktirdra vyāṇāṃ jāyate kvacit ataḥ prayogakāryārthaṃ mānamatrocyate mayā" },
      { type: "verse", number: "15", sanskrit: "त्रसरेणुर्बुधैः प्रोक्तस्त्रिंशता परमाणुभिः त्रसरेणुस्तु पर्यायनाम्ना वंशी निगद्यते", text: "trasareṇurbudhaiḥ proktastriṃśatā paramāṇubhiḥ trasareṇustu paryāyanāmnā vaṃśī nigadyate" },
      { type: "verse", number: "16", sanskrit: "जिआ!लान्तरगते भानौ यत्सूक्ष्मं दृश्यते रजः तस्य त्रिंशत्तमो भागः परमाणुः स कथ्यते", text: "jiā!lāntaragate bhānau yatsūkṣmaṃ dṛśyate rajaḥ tasya triṃśattamo bhāgaḥ paramāṇuḥ sa kathyate" },
      { type: "verse", number: "17", sanskrit: "जालान्तरगतैः सूर्यकरेर्वंशी विलोक्यते", text: "jālāntaragataiḥ sūryakarervaṃśī vilokyate" },
      { type: "verse", number: "18", sanskrit: "षड्वंशीभिर्मरीचिः स्यात्ताभिः षड्भिस्तु राजिका तिसृभी राजिकाभिश्च सर्षपः प्रोच्यते बुधैः", text: "ṣaḍvaṃśībhirmarīciḥ syāttābhiḥ ṣaḍbhistu rājikā tisṛbhī rājikābhiśca sarṣapaḥ procyate budhaiḥ" },
      { type: "verse", number: "19", sanskrit: "यवोऽष्टसर्षपैः प्रोक्तो गुञ्जा स्यात्तच्चतुष्टयम् षड्भिस्तु रक्तिकाभिः स्यान्माषको हेमधान्यकौ", text: "yavo'ṣṭasarṣapaiḥ prokto guñjā syāttaccatuṣṭayam ṣaḍbhistu raktikābhiḥ syānmāṣako hemadhānyakau" },
      { type: "verse", number: "20", sanskrit: "माषैश्चतुर्भिः शाणः स्याद्धरणः स निगद्यते टङ्कः स एव कथितस्तद्द्वयं कोल उच्यते क्षुद्र को वटकश्चैव द्र ङ्क्षणः स निगद्यते", text: "māṣaiścaturbhiḥ śāṇaḥ syāddharaṇaḥ sa nigadyate ṭaṅkaḥ sa eva kathitastaddvayaṃ kola ucyate kṣudra ko vaṭakaścaiva dra ṅkṣaṇaḥ sa nigadyate" },
      { type: "verse", number: "21", sanskrit: "कोलद्वयं च कर्षः स्यात्स प्रोक्तः पाणिमानिका", text: "koladvayaṃ ca karṣaḥ syātsa proktaḥ pāṇimānikā" },
      { type: "verse", number: "22", sanskrit: "अक्षं पिचुः पाणितलं किञ्चित्पाणिश्च तिन्दुकम् विडालपदकं चैव तथा षोडशिका मता", text: "akṣaṃ picuḥ pāṇitalaṃ kiñcitpāṇiśca tindukam viḍālapadakaṃ caiva tathā ṣoḍaśikā matā" },
      { type: "verse", number: "23", sanskrit: "करमध्यो हंसपदं सुवर्णं कवलग्रहः उदुम्बरं च पर्यायैः कर्ष एव निगद्यते", text: "karamadhyo haṃsapadaṃ suvarṇaṃ kavalagrahaḥ udumbaraṃ ca paryāyaiḥ karṣa eva nigadyate" },
      { type: "verse", number: "24", sanskrit: "स्यात्कर्षाभ्यामर्द्धपलं शुक्तिरष्टमिका तथा शुक्तिभ्यां च पलं ज्ञेयं मुष्टिराम्रं चतुर्थिका प्रकुञ्चः षोडशी बिल्वं पलमेवात्र कीत्तर्यते", text: "syātkarṣābhyāmarddhapalaṃ śuktiraṣṭamikā tathā śuktibhyāṃ ca palaṃ jñeyaṃ muṣṭirāmraṃ caturthikā prakuñcaḥ ṣoḍaśī bilvaṃ palamevātra kīttaryate" },
      { type: "verse", number: "25", sanskrit: "पलाभ्यां प्रसृतिर्ज्ञेया प्रसृतश्च निगद्यते प्रसृतिभ्यामञ्जलि स्यात्कुडवोऽद्धशरावकः", text: "palābhyāṃ prasṛtirjñeyā prasṛtaśca nigadyate prasṛtibhyāmañjali syātkuḍavo'ddhaśarāvakaḥ" },
      { type: "verse", number: "26", sanskrit: "अष्टमानं च स ज्ञेयः कुडवाभ्यां च मानिका शरावोऽष्टपलं तद्वज्ज्ञेयमत्र विचक्षणैः", text: "aṣṭamānaṃ ca sa jñeyaḥ kuḍavābhyāṃ ca mānikā śarāvo'ṣṭapalaṃ tadvajjñeyamatra vicakṣaṇaiḥ" },
      { type: "verse", number: "27", sanskrit: "शरावाभ्यां भवेत्प्रस्थश्चतुः प्रस्थैस्तथाऽढकम् भाजनं कंसपात्रं च चतुःषष्टिपलं च तत्", text: "śarāvābhyāṃ bhavetprasthaścatuḥ prasthaistathā'ḍhakam bhājanaṃ kaṃsapātraṃ ca catuḥṣaṣṭipalaṃ ca tat" },
      { type: "verse", number: "28", sanskrit: "चतुर्भिराढकैद्रो र्णः! कलशो नल्वणार्मणौ उन्मानश्च घटो राशिद्रो र्ण!पर्यायसंज्ञकाः", text: "caturbhirāḍhakaidro rṇaḥ! kalaśo nalvaṇārmaṇau unmānaśca ghaṭo rāśidro rṇa!paryāyasaṃjñakāḥ" },
      { type: "verse", number: "29", sanskrit: "द्रो णाभ्यां शूर्पकुम्भौ च चतुःषष्टिशरावकः शूर्पाभ्यां च भवेद् द्रो णी वाही गोणी च सा स्मृता", text: "dro ṇābhyāṃ śūrpakumbhau ca catuḥṣaṣṭiśarāvakaḥ śūrpābhyāṃ ca bhaved dro ṇī vāhī goṇī ca sā smṛtā" },
      { type: "verse", number: "30", sanskrit: "द्रो णीचतुष्टयं खारी कथिता सूक्ष्मबुद्धिभिः चतुःसहस्रपलिका षण्णवत्यधिका च सा", text: "dro ṇīcatuṣṭayaṃ khārī kathitā sūkṣmabuddhibhiḥ catuḥsahasrapalikā ṣaṇṇavatyadhikā ca sā" },
      { type: "verse", number: "31", sanskrit: "पलानां द्विसहस्त्रं च भार एकः प्रकीर्त्तितः तुला पलशतं ज्ञेया सर्वत्रैवैष निश्चयः", text: "palānāṃ dvisahastraṃ ca bhāra ekaḥ prakīrttitaḥ tulā palaśataṃ jñeyā sarvatraivaiṣa niścayaḥ" },
      { type: "verse", number: "32", sanskrit: "माषटङ्काक्षबिल्वानि कुडवः प्रस्थमाढकम् राशिर्गोणीः खारिकेति यथोत्तरचतुर्गुणाः", text: "māṣaṭaṅkākṣabilvāni kuḍavaḥ prasthamāḍhakam rāśirgoṇīḥ khāriketi yathottaracaturguṇāḥ" },
      { type: "verse", number: "33", sanskrit: "द्र वार्द्र शुष्कद्र व्याणामनुक्तमानपरिभाषा गुज्जाऽदिमानमारभ्य यावत्स्यात्कुडवस्थितिः द्र वार्द्र शुष्कद्र व्याणां तावन्मानं समं मतम्", text: "dra vārdra śuṣkadra vyāṇāmanuktamānaparibhāṣā gujjā'dimānamārabhya yāvatsyātkuḍavasthitiḥ dra vārdra śuṣkadra vyāṇāṃ tāvanmānaṃ samaṃ matam" },
      { type: "verse", number: "34", sanskrit: "द्र वार्द्र योर्द्विगुणग्रहणार्थं परिभाषा प्रस्थादिमानमारभ्य द्विगुणं तत् द्र वार्द्र योः मानं तथा तुलायास्तु द्विगुणं न क्वचित्स्मृतम्", text: "dra vārdra yordviguṇagrahaṇārthaṃ paribhāṣā prasthādimānamārabhya dviguṇaṃ tat dra vārdra yoḥ mānaṃ tathā tulāyāstu dviguṇaṃ na kvacitsmṛtam" },
      { type: "verse", number: "35", sanskrit: "द्र वमानार्थकुडवपात्रनिर्माणप्रकारः मृद्वृक्षवेणुलोहादेर्भाण्डं यच्चतुरङ्गुलम् विस्तीर्णं च तथोच्चं च तन्मानं कुडवं वदेत्", text: "dra vamānārthakuḍavapātranirmāṇaprakāraḥ mṛdvṛkṣaveṇulohāderbhāṇḍaṃ yaccaturaṅgulam vistīrṇaṃ ca tathoccaṃ ca tanmānaṃ kuḍavaṃ vadet" },
      { type: "verse", number: "36", sanskrit: "यदौषधं तु प्रथमं यस्य योगस्य कथ्यते तन्नाम्नैव स योगो हि कथ्यतेऽत्र विनिश्चयः", text: "yadauṣadhaṃ tu prathamaṃ yasya yogasya kathyate tannāmnaiva sa yogo hi kathyate'tra viniścayaḥ" },
      { type: "verse", number: "37", sanskrit: "स्थितिर्नास्त्येव मात्रायाः कालमग्निं वयो बलम् प्रकृतिं दोषदेशौ च दृष्ट्वा मात्रां प्रकल्पयेत्", text: "sthitirnāstyeva mātrāyāḥ kālamagniṃ vayo balam prakṛtiṃ doṣadeśau ca dṛṣṭvā mātrāṃ prakalpayet" },
      { type: "verse", number: "38", sanskrit: "यतो मन्दाग्नयो ह्रस्वा हीनसत्त्वा नराः कलौ अतस्तु मात्रा तद्योग्या प्रोच्यते सुज्ञसंमता", text: "yato mandāgnayo hrasvā hīnasattvā narāḥ kalau atastu mātrā tadyogyā procyate sujñasaṃmatā" },
      { type: "verse", number: "39", sanskrit: "यवो द्वादशभिर्गौरसर्षपैः प्रोच्यते बुधैः", text: "yavo dvādaśabhirgaurasarṣapaiḥ procyate budhaiḥ" },
      { type: "verse", number: "40", sanskrit: "यवद्वयेन गुञ्जा स्यात् त्रिगुञ्जो वल्ल उच्यते माषो गुञ्जाभिरष्टाभिः सप्तभिर्वा भवेत्क्वचित्", text: "yavadvayena guñjā syāt triguñjo valla ucyate māṣo guñjābhiraṣṭābhiḥ saptabhirvā bhavetkvacit" },
      { type: "verse", number: "41", sanskrit: "स्याच्चतुर्माषकः शाणः स निष्कष्टङ्क एव च गद्याणो माषकैः षड्भिः कर्षः स्याद्दशमाषकः", text: "syāccaturmāṣakaḥ śāṇaḥ sa niṣkaṣṭaṅka eva ca gadyāṇo māṣakaiḥ ṣaḍbhiḥ karṣaḥ syāddaśamāṣakaḥ" },
      { type: "verse", number: "42", sanskrit: "चतुःकर्षैः पलं प्रोक्तं दशशाणमितं बुधैः चतुष्पलैश्च कुडवं प्रस्थाद्याः पूर्ववन्मताः", text: "catuḥkarṣaiḥ palaṃ proktaṃ daśaśāṇamitaṃ budhaiḥ catuṣpalaiśca kuḍavaṃ prasthādyāḥ pūrvavanmatāḥ" },
      { type: "verse", number: "43", sanskrit: "कालिङ्गं मागधं चैव द्विविधं मानमुच्यते कालिङ्गान्मागधं श्रेष्ठं मानं मानविदो विदुः", text: "kāliṅgaṃ māgadhaṃ caiva dvividhaṃ mānamucyate kāliṅgānmāgadhaṃ śreṣṭhaṃ mānaṃ mānavido viduḥ" },
      { type: "verse", number: "44", sanskrit: "औषधपरिभाषौ तत्र द्र व्याणां युक्तायुक्तविचारः नवान्येव हि योज्यानि द्र व्याण्यखिलकर्मसु विना विडङ्गकृष्णाभ्यां गुडधान्याज्यमाक्षिकैः", text: "auṣadhaparibhāṣau tatra dra vyāṇāṃ yuktāyuktavicāraḥ navānyeva hi yojyāni dra vyāṇyakhilakarmasu vinā viḍaṅgakṛṣṇābhyāṃ guḍadhānyājyamākṣikaiḥ" },
      { type: "verse", number: "45", sanskrit: "सदाद्रा र्ण्य!द्विगुणानि द्र व्याणि गुडूची कुटजो वासा कूष्माण्डश्च शतावरी अश्वगन्धा सहचरी शतपुष्पा प्रसारिणी", text: "sadādrā rṇya!dviguṇāni dra vyāṇi guḍūcī kuṭajo vāsā kūṣmāṇḍaśca śatāvarī aśvagandhā sahacarī śatapuṣpā prasāriṇī" },
      { type: "verse", number: "46", sanskrit: "प्रयोक्तव्या सदैवाद्रा र्! द्विगुणा नैव कारयेत्", text: "prayoktavyā sadaivādrā r! dviguṇā naiva kārayet" },
      { type: "verse", number: "47", sanskrit: "शुष्कं नवीनं यद् द्र व्यं योज्यं सकलकर्मसु आद्र रं! च द्विगुणं युंज्यादेष सर्वत्र निश्चयः", text: "śuṣkaṃ navīnaṃ yad dra vyaṃ yojyaṃ sakalakarmasu ādra raṃ! ca dviguṇaṃ yuṃjyādeṣa sarvatra niścayaḥ" },
      { type: "verse", number: "48", sanskrit: "अनुक्तावस्थायां परिभाषाविधिः कालेऽनुक्ते प्रभातं स्यादङ्गेऽनुक्ते जटा भवेत् भागेऽनुक्ते तु साम्यं स्यात्पात्रेऽनुक्ते च मृण्मयम् द्र वेऽनुक्ते जलं ग्राह्यं तैलेऽनुक्ते तिलोद्भवम्", text: "anuktāvasthāyāṃ paribhāṣāvidhiḥ kāle'nukte prabhātaṃ syādaṅge'nukte jaṭā bhavet bhāge'nukte tu sāmyaṃ syātpātre'nukte ca mṛṇmayam dra ve'nukte jalaṃ grāhyaṃ taile'nukte tilodbhavam" },
      { type: "verse", number: "49", sanskrit: "एकमप्यौषधं योगे यस्मिन्यत्पुनरुच्यते मानतो द्विगुणं प्रोक्तं तद् द्र व्यं तत्त्वदर्शिभिः", text: "ekamapyauṣadhaṃ yoge yasminyatpunarucyate mānato dviguṇaṃ proktaṃ tad dra vyaṃ tattvadarśibhiḥ" },
      { type: "verse", number: "50", sanskrit: "चूर्णस्नेहासवा लेहाः प्रायशश्चन्दनान्विताः कषायलेपयोः प्रायो युज्यते रक्तचन्दनम्", text: "cūrṇasnehāsavā lehāḥ prāyaśaścandanānvitāḥ kaṣāyalepayoḥ prāyo yujyate raktacandanam" },
      { type: "verse", number: "51", sanskrit: "प्रसिद्धद्र व्याणां कालातिक्रमेण हीनगुणत्वम् गुणहीनं भवेद्वर्षादूर्ध्वं तद्रू पमौषधम् मासद्वयात्तथा चूर्णं हीनवीर्यत्वमाप्नुयात्", text: "prasiddhadra vyāṇāṃ kālātikrameṇa hīnaguṇatvam guṇahīnaṃ bhavedvarṣādūrdhvaṃ tadrū pamauṣadham māsadvayāttathā cūrṇaṃ hīnavīryatvamāpnuyāt" },
      { type: "verse", number: "52", sanskrit: "हीनत्वं गुटिकालेहौ लभेते वत्सरात्परम् हीनाः स्युर्घृततैलाद्याश्चतुर्मासाधिकात्तथा", text: "hīnatvaṃ guṭikālehau labhete vatsarātparam hīnāḥ syurghṛtatailādyāścaturmāsādhikāttathā" },
      { type: "verse", number: "53", sanskrit: "ओषध्यो लघुपाकाः स्युर्निर्वीर्या वत्सरात्परम् पुराणाः स्युर्गुणैर्युक्ता आसवा धातवो रसाः", text: "oṣadhyo laghupākāḥ syurnirvīryā vatsarātparam purāṇāḥ syurguṇairyuktā āsavā dhātavo rasāḥ" },
      { type: "verse", number: "54", sanskrit: "रोगानुसारियुक्तायुक्तद्र व्यविचारः व्याधेरयुक्तं यद् द्र व्यं गणोक्तमपि तत्त्यजेत् अनुक्तमपि यद्युक्तं योजयेत्तत्र तद् बुधः", text: "rogānusāriyuktāyuktadra vyavicāraḥ vyādherayuktaṃ yad dra vyaṃ gaṇoktamapi tattyajet anuktamapi yadyuktaṃ yojayettatra tad budhaḥ" },
      { type: "verse", number: "55", sanskrit: "द्र व्येषु स्थानभेदेन गुणभेदः आग्नेया विन्ध्यशैलाद्याः सौम्यो हिमगिरिर्मतः अतस्तदौषधानि स्युरनुरूपाणि हेतुभिः अन्येष्वपि प्ररोहन्ति वनेषूपवनेषु च", text: "dra vyeṣu sthānabhedena guṇabhedaḥ āgneyā vindhyaśailādyāḥ saumyo himagirirmataḥ atastadauṣadhāni syuranurūpāṇi hetubhiḥ anyeṣvapi prarohanti vaneṣūpavaneṣu ca" },
      { type: "verse", number: "56", sanskrit: "गृह्णीयात्तानि सुमनाः शुचिः प्रातः सुवासरे", text: "gṛhṇīyāttāni sumanāḥ śuciḥ prātaḥ suvāsare" },
      { type: "verse", number: "57", sanskrit: "आदित्यसंमुखो मौनी नमस्कृत्य शिवं हृदि साधारणधराद्र व्यं गृह्णीयादुत्तराश्रितम्", text: "ādityasaṃmukho maunī namaskṛtya śivaṃ hṛdi sādhāraṇadharādra vyaṃ gṛhṇīyāduttarāśritam" },
      { type: "verse", number: "58", sanskrit: "कुत्सितस्थानोद्भवद्र व्याणां परित्यागः वल्मीककुत्सितानूपश्मशानोषरमार्गजाः जन्तुवह्निहिमव्याप्ता नौषध्यः कार्यसिद्धिदाः", text: "kutsitasthānodbhavadra vyāṇāṃ parityāgaḥ valmīkakutsitānūpaśmaśānoṣaramārgajāḥ jantuvahnihimavyāptā nauṣadhyaḥ kāryasiddhidāḥ" },
      { type: "verse", number: "59", sanskrit: "कार्यभेदेन द्र व्यग्रहणे ऋतुविशेषः शरद्यखिलकार्यार्थं ग्राह्यं सरसमौषधम् विरेकवमनार्थं च वसन्तान्ते समाहरेत्", text: "kāryabhedena dra vyagrahaṇe ṛtuviśeṣaḥ śaradyakhilakāryārthaṃ grāhyaṃ sarasamauṣadham virekavamanārthaṃ ca vasantānte samāharet" },
      { type: "verse", number: "60", sanskrit: "अनुक्तावयवद्र व्याणां ग्रहणेऽङ्गविचारः अतिस्थूलजटा याः स्युस्तासां ग्राह्यास्त्वचो बुधैः गृह्णीयात्सूक्ष्ममूलानि सकलान्यपि बुद्धिमान्", text: "anuktāvayavadra vyāṇāṃ grahaṇe'ṅgavicāraḥ atisthūlajaṭā yāḥ syustāsāṃ grāhyāstvaco budhaiḥ gṛhṇīyātsūkṣmamūlāni sakalānyapi buddhimān" },
      { type: "verse", number: "61", sanskrit: "न्यग्रोधादेस्त्वचो ग्राह्याः सारः स्याद्वीजकादितः तालीसादेश्च पत्राणि फलं स्यात्त्रिफलादितः धातक्यादेश्च पुष्पाणि स्नुह्यादेः क्षीरमाहरेत्", text: "nyagrodhādestvaco grāhyāḥ sāraḥ syādvījakāditaḥ tālīsādeśca patrāṇi phalaṃ syāttriphalāditaḥ dhātakyādeśca puṣpāṇi snuhyādeḥ kṣīramāharet" },
    ],
  },
  {
    sthana: "Пурвакханда",
    number: 2,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Доша санграха — О трёх дошах" },
      { type: "text", text: "Сжатое изложение учения о трёх дошах (Вата, Питта, Капха) с акцентом на практическое применение для диагностики и лечения. Шарангадхара добавляет детализацию XIII века." },
      { type: "verse", number: "1", sanskrit: "औषधभक्षणार्हकालस्य सामान्यनिर्देशः भैषज्यमभ्यवहरेत्प्रभाते प्रायशो बुधः कषायांश्च विशेषेण तत्र भेदस्तु दर्शितः", text: "auṣadhabhakṣaṇārhakālasya sāmānyanirdeśaḥ bhaiṣajyamabhyavaharetprabhāte prāyaśo budhaḥ kaṣāyāṃśca viśeṣeṇa tatra bhedastu darśitaḥ" },
      { type: "verse", number: "2", sanskrit: "औषधभक्षणे पञ्चविधकालनिर्देशः ज्ञेयः पञ्चविधः कालो भैषज्यग्रहणे नृणाम् किंचित्सूर्योदये जाते तथा दिवसभोजने", text: "auṣadhabhakṣaṇe pañcavidhakālanirdeśaḥ jñeyaḥ pañcavidhaḥ kālo bhaiṣajyagrahaṇe nṛṇām kiṃcitsūryodaye jāte tathā divasabhojane" },
      { type: "verse", number: "3", sanskrit: "सायन्तने भोजने च मुहुश्चापि तथा निशि", text: "sāyantane bhojane ca muhuścāpi tathā niśi" },
      { type: "verse", number: "4", sanskrit: "प्रायः पित्तकफोद्रे के विरेकवमनार्थयोः लेखनार्थं च भैषज्यं प्रभाते तत्समाहरेत् एवं स्यात् प्रथमः कालो भैषज्यग्रहणे नृणाम्", text: "prāyaḥ pittakaphodre ke virekavamanārthayoḥ lekhanārthaṃ ca bhaiṣajyaṃ prabhāte tatsamāharet evaṃ syāt prathamaḥ kālo bhaiṣajyagrahaṇe nṛṇām" },
      { type: "verse", number: "5", sanskrit: "भैषज्यं विगुणेऽपाने भोजनाग्रे प्रशस्यते अरुचौ चित्रभोज्यैश्च मिश्रं रुचिरमाहरेत्", text: "bhaiṣajyaṃ viguṇe'pāne bhojanāgre praśasyate arucau citrabhojyaiśca miśraṃ ruciramāharet" },
      { type: "verse", number: "6", sanskrit: "समानवाते विगुणे मन्देऽग्नावग्निदीपनम् दद्याद्भोजनमध्ये च भैषज्यं कुशलो भिषक्", text: "samānavāte viguṇe mande'gnāvagnidīpanam dadyādbhojanamadhye ca bhaiṣajyaṃ kuśalo bhiṣak" },
      { type: "verse", number: "7", sanskrit: "व्यानकोपे च भैषज्यं भोजनान्ते समाहरेत् हिक्काऽक्षेपककम्पेषु पूर्वमन्ते च भोजनात्", text: "vyānakope ca bhaiṣajyaṃ bhojanānte samāharet hikkā'kṣepakakampeṣu pūrvamante ca bhojanāt" },
      { type: "verse", number: "8", sanskrit: "एवं द्वितीयकालश्च प्रोक्तो भैषज्यकर्मणि", text: "evaṃ dvitīyakālaśca prokto bhaiṣajyakarmaṇi" },
      { type: "verse", number: "10", sanskrit: "उदाने कुपिते वाते स्वरभङ्गादिकारिणि ग्रासे ग्रासान्तरे देयं भैषज्यं सान्ध्यभोजने प्राणे प्रदुष्टे सान्ध्यस्य भुक्तस्यान्ते च दीयते औषधं प्रायशो धीरैः कालोऽय स्यात्तृतीयकः", text: "udāne kupite vāte svarabhaṅgādikāriṇi grāse grāsāntare deyaṃ bhaiṣajyaṃ sāndhyabhojane prāṇe praduṣṭe sāndhyasya bhuktasyānte ca dīyate auṣadhaṃ prāyaśo dhīraiḥ kālo'ya syāttṛtīyakaḥ" },
      { type: "verse", number: "11", sanskrit: "मुहुर्मुहुश्च तृट्च्छर्दिहिक्काश्वासगरेषु च सान्नं च भेषजं दद्यादितिकालश्चतुर्थकः", text: "muhurmuhuśca tṛṭcchardihikkāśvāsagareṣu ca sānnaṃ ca bheṣajaṃ dadyāditikālaścaturthakaḥ" },
      { type: "verse", number: "12", sanskrit: "ऊर्ध्वजत्रुविकारेषु लेखने बृंहणे तथा पाचनं शमनं देयमनन्नं भेषजं निशि इति पञ्चमकालः स्यात् प्रोक्तो भैषज्यकर्मणि", text: "ūrdhvajatruvikāreṣu lekhane bṛṃhaṇe tathā pācanaṃ śamanaṃ deyamanannaṃ bheṣajaṃ niśi iti pañcamakālaḥ syāt prokto bhaiṣajyakarmaṇi" },
      { type: "verse", number: "13", sanskrit: "द्र व्ये रसो गुणो वीर्यं विपाकः शक्तिरेव च संबन्धेन क्रमादेताः पञ्चावस्थाः प्रकीर्त्तिताः", text: "dra vye raso guṇo vīryaṃ vipākaḥ śaktireva ca saṃbandhena kramādetāḥ pañcāvasthāḥ prakīrttitāḥ" },
      { type: "verse", number: "14", sanskrit: "मधुरोऽम्ल पटुश्चैव कटुतिक्तकषायकाः इत्येते षड्रसाः ख्याता नानाद्र व्यसमाश्रिताः", text: "madhuro'mla paṭuścaiva kaṭutiktakaṣāyakāḥ ityete ṣaḍrasāḥ khyātā nānādra vyasamāśritāḥ" },
      { type: "verse", number: "15", sanskrit: "वाय्वग्निक्ष्माऽनिलैभूर्तद्वयै रसभवः क्रमात्", text: "vāyvagnikṣmā'nilaibhūrtadvayai rasabhavaḥ kramāt" },
      { type: "verse", number: "16", sanskrit: "गुरुः स्निग्धश्च तीक्ष्णश्च रूक्षो लघुरिति क्रमात् धराऽम्बुवह्निपवनव्योम्नां प्रायो गुणाः स्मृताः", text: "guruḥ snigdhaśca tīkṣṇaśca rūkṣo laghuriti kramāt dharā'mbuvahnipavanavyomnāṃ prāyo guṇāḥ smṛtāḥ" },
      { type: "verse", number: "17", sanskrit: "एष्वेवान्तर्भवन्त्यन्ये गुणेषु गुणसंचयाः", text: "eṣvevāntarbhavantyanye guṇeṣu guṇasaṃcayāḥ" },
      { type: "verse", number: "18", sanskrit: "वीर्यमुष्णं तथा शीतं प्रायशो द्र व्यसंश्रयम् तत्सर्वमग्नीषोमीयं दृश्यते भुवनत्रये अत्रैवान्तर्भविष्यन्ति वीर्याण्न्यानि यान्यपि", text: "vīryamuṣṇaṃ tathā śītaṃ prāyaśo dra vyasaṃśrayam tatsarvamagnīṣomīyaṃ dṛśyate bhuvanatraye atraivāntarbhaviṣyanti vīryāṇnyāni yānyapi" },
      { type: "verse", number: "19", sanskrit: "त्रिधा विपाको द्र व्यस्य स्वाद्वम्लकटुकात्मकः मिष्टः पटुश्च मधुरमम्लोऽम्ल पच्यते रसः", text: "tridhā vipāko dra vyasya svādvamlakaṭukātmakaḥ miṣṭaḥ paṭuśca madhuramamlo'mla pacyate rasaḥ" },
      { type: "verse", number: "20", sanskrit: "कषायकटुतिक्तानां पाकः स्यात्प्रायशः कटुः मधुराज्जायते श्लेष्मा पित्तमम्लाच्च जायते", text: "kaṣāyakaṭutiktānāṃ pākaḥ syātprāyaśaḥ kaṭuḥ madhurājjāyate śleṣmā pittamamlācca jāyate" },
      { type: "verse", number: "21", sanskrit: "कटुकाज्जायते वायुः कर्माणीति विपाकतः", text: "kaṭukājjāyate vāyuḥ karmāṇīti vipākataḥ" },
      { type: "verse", number: "22", sanskrit: "प्रभावस्तु यथा धात्री लकुचस्य रसादिभिः समाऽपि कुरुते दोषत्रितयस्य विनाशनम्", text: "prabhāvastu yathā dhātrī lakucasya rasādibhiḥ samā'pi kurute doṣatritayasya vināśanam" },
      { type: "verse", number: "23", sanskrit: "क्वचित्तु केवलं द्र व्यं कर्म कुर्यात्प्रभावतः ज्वरं हन्ति शिरोबद्धा सहदेवीजटा यथा", text: "kvacittu kevalaṃ dra vyaṃ karma kuryātprabhāvataḥ jvaraṃ hanti śirobaddhā sahadevījaṭā yathā" },
      { type: "verse", number: "24", sanskrit: "रसवीर्यादीनां पृथक् पृथक् प्रभावः क्वचिद्र सो गुणो वीर्यं विपाकः शक्तिरेव च कर्म स्वं स्वं प्रकुर्वन्ति द्र व्यमाश्रित्य ये स्थिताः", text: "rasavīryādīnāṃ pṛthak pṛthak prabhāvaḥ kvacidra so guṇo vīryaṃ vipākaḥ śaktireva ca karma svaṃ svaṃ prakurvanti dra vyamāśritya ye sthitāḥ" },
      { type: "verse", number: "25", sanskrit: "ऋतुभेदेन वातादीनां संचयकोपोपशमाः चयकोपशमा यस्मिन्दोषाणां सम्भवन्ति हि ऋतुषट्कं तदाख्यातं रवे राशिषु संक्रमात्", text: "ṛtubhedena vātādīnāṃ saṃcayakopopaśamāḥ cayakopaśamā yasmindoṣāṇāṃ sambhavanti hi ṛtuṣaṭkaṃ tadākhyātaṃ rave rāśiṣu saṃkramāt" },
      { type: "verse", number: "26", sanskrit: "ग्रीष्मो मेषवृषौ प्रोक्तः प्रावृण्मिथुनकर्कयोः सिंहकन्ये स्मृता वर्षास्तुलावृश्चिकयोः शरत् धनुर्ग्राहौ च हेमन्तो वसन्तः कुम्भमीनयोः", text: "grīṣmo meṣavṛṣau proktaḥ prāvṛṇmithunakarkayoḥ siṃhakanye smṛtā varṣāstulāvṛścikayoḥ śarat dhanurgrāhau ca hemanto vasantaḥ kumbhamīnayoḥ" },
      { type: "verse", number: "27", sanskrit: "ग्रीष्मे सञ्चीयते वायुः प्रावृट्काले प्रकुप्यति वर्षासु चीयते पित्तं शरत्काले प्रकुप्यति", text: "grīṣme sañcīyate vāyuḥ prāvṛṭkāle prakupyati varṣāsu cīyate pittaṃ śaratkāle prakupyati" },
      { type: "verse", number: "28", sanskrit: "हेमन्ते चीयते श्लेष्मा वसन्ते च प्रकुप्यति प्रायेण प्रशमं याति स्वयमेव समीरणः", text: "hemante cīyate śleṣmā vasante ca prakupyati prāyeṇa praśamaṃ yāti svayameva samīraṇaḥ" },
      { type: "verse", number: "29", sanskrit: "शरत्काले वसन्ते च पित्तं प्रावृडृतौ कफः", text: "śaratkāle vasante ca pittaṃ prāvṛḍṛtau kaphaḥ" },
      { type: "verse", number: "30", sanskrit: "कार्त्तिकस्य दिनान्यष्टावष्टावाग्रयणस्य च यमदंष्ट्रा समाख्याता स्वल्पभुक्तो हि जीवति", text: "kārttikasya dinānyaṣṭāvaṣṭāvāgrayaṇasya ca yamadaṃṣṭrā samākhyātā svalpabhukto hi jīvati" },
      { type: "verse", number: "31", sanskrit: "दोषाणामकालेऽपि भोजनादिना चयकोपापचयाः चयकोपशमा दोषा विहाराहारसेवनैः समानैर्यान्त्यकालेऽपि विपरीतैर्विपर्ययम्", text: "doṣāṇāmakāle'pi bhojanādinā cayakopāpacayāḥ cayakopaśamā doṣā vihārāhārasevanaiḥ samānairyāntyakāle'pi viparītairviparyayam" },
      { type: "verse", number: "32", sanskrit: "प्रदोषे कामशोकाभ्यां भीचिन्तारात्रिजागरैः", text: "pradoṣe kāmaśokābhyāṃ bhīcintārātrijāgaraiḥ" },
      { type: "verse", number: "33", sanskrit: "अभिघातादपां गाहाज्जीर्णेऽन्ने धातुसंक्षयात् वायुः प्रकोपं यात्येभिः प्रत्यनीकैश्च शाम्यति", text: "abhighātādapāṃ gāhājjīrṇe'nne dhātusaṃkṣayāt vāyuḥ prakopaṃ yātyebhiḥ pratyanīkaiśca śāmyati" },
      { type: "verse", number: "34", sanskrit: "मध्याह्ने क्षुत्तृषारोधाज्जीर्यत्यन्नेऽद्धरात्रके पित्तं प्रकोपं यात्येभिः प्रत्यनीकैश्च शाम्यति", text: "madhyāhne kṣuttṛṣārodhājjīryatyanne'ddharātrake pittaṃ prakopaṃ yātyebhiḥ pratyanīkaiśca śāmyati" },
      { type: "verse", number: "36", sanskrit: "मधुरस्निग्धशीतादिभोज्यैर्दिवसनिद्र या मन्देऽग्नौ च प्रभाते च भुक्तमात्रे तथाऽश्रमात् श्लेष्मा प्रकोपं यात्येभिः प्रत्यनीकैश्च शाम्यति", text: "madhurasnigdhaśītādibhojyairdivasanidra yā mande'gnau ca prabhāte ca bhuktamātre tathā'śramāt śleṣmā prakopaṃ yātyebhiḥ pratyanīkaiśca śāmyati" },
    ],
  },
  {
    sthana: "Пурвакханда",
    number: 3,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Дхату санграха — О семи тканях" },
      { type: "text", text: "Семь дхату (тканей тела) и их последовательность трансформации. Шарангадхара описывает постепенное питание дхату от расы (плазмы) до шукры (репродуктивной ткани)." },
      { type: "verse", number: "1", sanskrit: "करस्याङ्गुष्ठमूले या धमनी जीवसाक्षिणी तच्चेष्टया सुखं दुःखं ज्ञेयं कायस्य पण्डितैः", text: "karasyāṅguṣṭhamūle yā dhamanī jīvasākṣiṇī tacceṣṭayā sukhaṃ duḥkhaṃ jñeyaṃ kāyasya paṇḍitaiḥ" },
      { type: "verse", number: "2", sanskrit: "नाडी धत्ते मरुत्कोपे जलौकासर्पयोर्गतिम्", text: "nāḍī dhatte marutkope jalaukāsarpayorgatim" },
      { type: "verse", number: "3", sanskrit: "कुलिङ्गकाकमण्डूकगतिं पित्तस्य कोपतः", text: "kuliṅgakākamaṇḍūkagatiṃ pittasya kopataḥ" },
      { type: "verse", number: "4", sanskrit: "हंसपारावतगतिं धत्ते श्लेष्मप्रकोपतः", text: "haṃsapārāvatagatiṃ dhatte śleṣmaprakopataḥ" },
      { type: "verse", number: "5", sanskrit: "लावतित्तिरवर्त्तीनां गमनं सन्निपाततः", text: "lāvatittiravarttīnāṃ gamanaṃ sannipātataḥ" },
      { type: "verse", number: "6", sanskrit: "कदाचिन्मन्दगमना कदाचिद्वेगवाहिनी  द्विदोषकोपतो ज्ञेया", text: "kadācinmandagamanā kadācidvegavāhinī  dvidoṣakopato jñeyā" },
      { type: "verse", number: "7", sanskrit: "स्थित्वा स्थित्वा चलति या सा स्मृता प्राणनाशिनी अतिक्षीणा च शीता च जीवितं हन्त्यसंशयम्", text: "sthitvā sthitvā calati yā sā smṛtā prāṇanāśinī atikṣīṇā ca śītā ca jīvitaṃ hantyasaṃśayam" },
      { type: "verse", number: "8", sanskrit: "ज्वरकोपे तु धमनी सोष्णा वेगवती भवेत्", text: "jvarakope tu dhamanī soṣṇā vegavatī bhavet" },
      { type: "verse", number: "9", sanskrit: "कामक्रोधचिन्ताभययुक्तानां नाडीलक्षणानि कामक्रोधोद्वेगवहा क्षीणा चिन्ताभयप्लुता", text: "kāmakrodhacintābhayayuktānāṃ nāḍīlakṣaṇāni kāmakrodhodvegavahā kṣīṇā cintābhayaplutā" },
      { type: "verse", number: "10", sanskrit: "मन्दाग्नि धातुक्षयरक्तप्रकोपसामावस्थासु नाडीलक्षणानि मन्दाग्नेः क्षीणधातोश्च नाडी मन्दतरा भवेत् असृक्पूर्णा भवेत्कोष्णा गुर्वी सामा गरीयसी", text: "mandāgni dhātukṣayaraktaprakopasāmāvasthāsu nāḍīlakṣaṇāni mandāgneḥ kṣīṇadhātośca nāḍī mandatarā bhavet asṛkpūrṇā bhavetkoṣṇā gurvī sāmā garīyasī" },
      { type: "verse", number: "11", sanskrit: "दीप्ताग्नि सुखितक्षुधित तृप्तपुरुषाणां नाडीलक्षणानि लघ्वी वहति दीप्ताग्नेस्तथा वेगवती मता सुखितस्य स्थिरा ज्ञेया तथा बलवती स्मृता चपला क्षुधितस्य स्यात्तृप्तस्य वहति स्थिरा", text: "dīptāgni sukhitakṣudhita tṛptapuruṣāṇāṃ nāḍīlakṣaṇāni laghvī vahati dīptāgnestathā vegavatī matā sukhitasya sthirā jñeyā tathā balavatī smṛtā capalā kṣudhitasya syāttṛptasya vahati sthirā" },
      { type: "verse", number: "12", sanskrit: "दूताः स्वजातयोऽव्यङ्गाः पटवो निर्मलाम्बराः सुखिनोऽश्ववृषारूढाः शुभ्रपुष्पफलैर्युताः सुजातयः सुचेष्टाश्च सजीवदिशि संश्रिताः भिषजं समये प्राप्ता रोगिणः सुखहेतवे", text: "dūtāḥ svajātayo'vyaṅgāḥ paṭavo nirmalāmbarāḥ sukhino'śvavṛṣārūḍhāḥ śubhrapuṣpaphalairyutāḥ sujātayaḥ suceṣṭāśca sajīvadiśi saṃśritāḥ bhiṣajaṃ samaye prāptā rogiṇaḥ sukhahetave" },
      { type: "verse", number: "13", sanskrit: "यिस्यां प्राणमरुद्वाति सा नाडी जीवसंयुता दूतस्य शकुनानि वैद्याह्वानाय दूतस्य गच्छतो रोगिणः कृते न शुभं सौम्यशकुनं प्रदीप्तं च सुखावहम्", text: "yisyāṃ prāṇamarudvāti sā nāḍī jīvasaṃyutā dūtasya śakunāni vaidyāhvānāya dūtasya gacchato rogiṇaḥ kṛte na śubhaṃ saumyaśakunaṃ pradīptaṃ ca sukhāvaham" },
      { type: "verse", number: "14", sanskrit: "चिकित्सां रोगिणः कर्तुं गच्छतो भिषजः शुभम् यात्रेयं सौम्यशकुनं प्रोक्तं दीप्तं न शोभनम्", text: "cikitsāṃ rogiṇaḥ kartuṃ gacchato bhiṣajaḥ śubham yātreyaṃ saumyaśakunaṃ proktaṃ dīptaṃ na śobhanam" },
      { type: "verse", number: "15", sanskrit: "निजप्रकृतिवर्णाभ्यां युक्तः सत्त्वेन संयुतः चिकित्स्यो भिषजा रोगी वैद्यभक्तो जितेन्द्रि यः", text: "nijaprakṛtivarṇābhyāṃ yuktaḥ sattvena saṃyutaḥ cikitsyo bhiṣajā rogī vaidyabhakto jitendri yaḥ" },
      { type: "verse", number: "16", sanskrit: "स्वप्नेषु नग्नान्मुण्डांश्च रक्तकृष्णाम्बरावृतान् व्यङ्गांश्च विकृतान्कृष्णान्सपाशान्सायुधानपि बध्नतो निघ्नतश्चापि दक्षिणां दिशमाश्रितान् महिषोष्ट्रखरारूढान्स्त्रीपुंसो यस्तु पश्यति स स्वस्थो लभते व्याधिं रोगी यात्येव पञ्चताम्", text: "svapneṣu nagnānmuṇḍāṃśca raktakṛṣṇāmbarāvṛtān vyaṅgāṃśca vikṛtānkṛṣṇānsapāśānsāyudhānapi badhnato nighnataścāpi dakṣiṇāṃ diśamāśritān mahiṣoṣṭrakharārūḍhānstrīpuṃso yastu paśyati sa svastho labhate vyādhiṃ rogī yātyeva pañcatām" },
      { type: "verse", number: "17", sanskrit: "अन्यान्यपि दुःस्वप्नलक्षणानि अधो यो निपतत्युच्चाज्जलेऽग्नौ वा विलीयते श्वापदैर्हन्यते योऽपि मत्स्याद्यैर्गिलितो भवेत्", text: "anyānyapi duḥsvapnalakṣaṇāni adho yo nipatatyuccājjale'gnau vā vilīyate śvāpadairhanyate yo'pi matsyādyairgilito bhavet" },
      { type: "verse", number: "18", sanskrit: "यस्य नेत्रे विलीयेते दीपो निर्वाणतां व्रजेत् तैलं सुरां पिबेद्वाऽपि लोहं वा लभते तिलान्", text: "yasya netre vilīyete dīpo nirvāṇatāṃ vrajet tailaṃ surāṃ pibedvā'pi lohaṃ vā labhate tilān" },
      { type: "verse", number: "19", sanskrit: "पक्वान्नं लभतेऽश्नाति विशेत्कूपं रसातलम् स स्वस्थो लभते रोगं रोगी यात्येव पञ्चताम्", text: "pakvānnaṃ labhate'śnāti viśetkūpaṃ rasātalam sa svastho labhate rogaṃ rogī yātyeva pañcatām" },
      { type: "verse", number: "20", sanskrit: "दुःस्वप्नानेवमादींश्च दृष्ट्वा ब्रूयान्न कस्यचित् स्नानं कुर्यादुषस्येव दद्याद्धेमतिलानयः", text: "duḥsvapnānevamādīṃśca dṛṣṭvā brūyānna kasyacit snānaṃ kuryāduṣasyeva dadyāddhematilānayaḥ" },
      { type: "verse", number: "21", sanskrit: "पठेत्स्तोत्राणि देवानां रात्रौ देवालये वसेत् कृत्वैवंत्रिदिनं मर्त्यो दुःस्वप्नात्परिमुच्यते", text: "paṭhetstotrāṇi devānāṃ rātrau devālaye vaset kṛtvaivaṃtridinaṃ martyo duḥsvapnātparimucyate" },
      { type: "verse", number: "22", sanskrit: "स्वप्नेषु यः सुरान्भूपाञ्जीवतः सुहृदो द्विजान् गोसमिद्धाग्नितीर्थानि पश्येत्सुखमवाप्नुयात्", text: "svapneṣu yaḥ surānbhūpāñjīvataḥ suhṛdo dvijān gosamiddhāgnitīrthāni paśyetsukhamavāpnuyāt" },
      { type: "verse", number: "23", sanskrit: "तीर्त्वा कलुषनीराणि जित्वा शत्रुगणानपि आरुह्य सौधगोशैलकरिवाहान्सुखी भवेत्", text: "tīrtvā kaluṣanīrāṇi jitvā śatrugaṇānapi āruhya saudhagośailakarivāhānsukhī bhavet" },
      { type: "verse", number: "24", sanskrit: "शुभ्रपुष्पाणि वासांसि मांसमत्स्यफलानि च प्राप्यातुरः सुखी भूयात्स्वस्थो धनमवाप्नुयात्", text: "śubhrapuṣpāṇi vāsāṃsi māṃsamatsyaphalāni ca prāpyāturaḥ sukhī bhūyātsvastho dhanamavāpnuyāt" },
      { type: "verse", number: "25", sanskrit: "अगम्यागमनं लेपो विष्ठया रुदितं मृतिः आममांसाशनं स्वप्ने धनारोग्याप्तये विदुः", text: "agamyāgamanaṃ lepo viṣṭhayā ruditaṃ mṛtiḥ āmamāṃsāśanaṃ svapne dhanārogyāptaye viduḥ" },
      { type: "verse", number: "26", sanskrit: "जलौका भ्रमरी सर्पो मक्षिका वाऽपि यं दशेत् रोगी स भूयादुल्लाघः स्वस्थो धनमवाप्नुयात्", text: "jalaukā bhramarī sarpo makṣikā vā'pi yaṃ daśet rogī sa bhūyādullāghaḥ svastho dhanamavāpnuyāt" },
    ],
  },
  {
    sthana: "Пурвакханда",
    number: 4,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Нади парикша — Диагностика пульса" },
      { type: "text", text: "Уникальная глава о пульсовой диагностике (нади-парикша) — наиболее детальное раннее описание этого метода в аюрведической литературе. Характеристики пульса трёх дош." },
      { type: "verse", number: "1", sanskrit: "पचेन्नामं वह्निकृच्च दीपनं तद्यथा मिशिः", text: "pacennāmaṃ vahnikṛcca dīpanaṃ tadyathā miśiḥ" },
      { type: "verse", number: "2", sanskrit: "पाचनदीपनपाचनद्र व्ययोर्लक्षणे पचत्यामं न वह्निं च कुर्याद्यत्तद्धि पाचनम् नागकेशरवद्विद्याच्चित्रो दीपनपाचनः", text: "pācanadīpanapācanadra vyayorlakṣaṇe pacatyāmaṃ na vahniṃ ca kuryādyattaddhi pācanam nāgakeśaravadvidyāccitro dīpanapācanaḥ" },
      { type: "verse", number: "3", sanskrit: "न शोधयति न द्वेष्टि समान्दोषांस्तथोद्धतान् समीकरोति विषमाञ्शमनं तद्यथामृता", text: "na śodhayati na dveṣṭi samāndoṣāṃstathoddhatān samīkaroti viṣamāñśamanaṃ tadyathāmṛtā" },
      { type: "verse", number: "4", sanskrit: "कृत्वा पाकं मलानां यद्भित्त्वा बन्धमधो नयेत् तच्चानुलोमनं ज्ञेयं यथा प्रोक्ता हरीतकी", text: "kṛtvā pākaṃ malānāṃ yadbhittvā bandhamadho nayet taccānulomanaṃ jñeyaṃ yathā proktā harītakī" },
      { type: "verse", number: "5", sanskrit: "पक्तव्यं यदपक्त्वैव श्लिष्टं कोष्ठे मलादिकम् नयत्यधः स्रंसनं तद्यथा स्यात् कृतमालकः", text: "paktavyaṃ yadapaktvaiva śliṣṭaṃ koṣṭhe malādikam nayatyadhaḥ sraṃsanaṃ tadyathā syāt kṛtamālakaḥ" },
      { type: "verse", number: "6", sanskrit: "मलादिकमबद्धं यद्बद्धं वा पिण्डितं मलैः भित्त्वाऽध पातयति यद् भेदनं कटुकी यथा", text: "malādikamabaddhaṃ yadbaddhaṃ vā piṇḍitaṃ malaiḥ bhittvā'dha pātayati yad bhedanaṃ kaṭukī yathā" },
      { type: "verse", number: "7", sanskrit: "विपक्वं यदपक्वं वा मलादि द्र वतां नयेत् रेचयत्यपि तज्ज्ञेयं रेचनं त्रिवृता यथा", text: "vipakvaṃ yadapakvaṃ vā malādi dra vatāṃ nayet recayatyapi tajjñeyaṃ recanaṃ trivṛtā yathā" },
      { type: "verse", number: "8", sanskrit: "अपक्वपित्तश्लेष्माणौ बलादूर्ध्वं नयेत्तु यत् वमनं तद्धि विज्ञेयं मदनस्य फलं यथा", text: "apakvapittaśleṣmāṇau balādūrdhvaṃ nayettu yat vamanaṃ taddhi vijñeyaṃ madanasya phalaṃ yathā" },
      { type: "verse", number: "9", sanskrit: "स्थानाद् बहिर्नयेदूर्ध्वमधो वा मलसंचयम् देहसंशोधनं तत्स्याद् देवदालीफलं यथा", text: "sthānād bahirnayedūrdhvamadho vā malasaṃcayam dehasaṃśodhanaṃ tatsyād devadālīphalaṃ yathā" },
      { type: "verse", number: "10", sanskrit: "श्लिष्टान्कफादिकान्दोषानुन्मूलयति यद्बलात् छेदनं तद्यथा क्षारा मरिचानि शिलाजतु", text: "śliṣṭānkaphādikāndoṣānunmūlayati yadbalāt chedanaṃ tadyathā kṣārā maricāni śilājatu" },
      { type: "verse", number: "11", sanskrit: "धातून्मलान्वा देहस्य विशोष्योल्लेखयेच्च यत् लेखनं तद्यथा क्षौद्रं  नीरमुष्णं वचा यवाः", text: "dhātūnmalānvā dehasya viśoṣyollekhayecca yat lekhanaṃ tadyathā kṣaudraṃ  nīramuṣṇaṃ vacā yavāḥ" },
      { type: "verse", number: "12", sanskrit: "दीपनं पाचनं यत्स्यादुष्णत्वाद् द्र वशोषकम् ग्राहि तच्च यथा शुण्ठी जीरकं गजपिप्पली", text: "dīpanaṃ pācanaṃ yatsyāduṣṇatvād dra vaśoṣakam grāhi tacca yathā śuṇṭhī jīrakaṃ gajapippalī" },
      { type: "verse", number: "13", sanskrit: "रौक्ष्याच्छैत्यात्कषायत्वाल्लघुपाकाच्च यद्भवेत् वातकृत्स्तम्भनं तत्स्याद्यथा वत्सकटुण्टुकौ", text: "raukṣyācchaityātkaṣāyatvāllaghupākācca yadbhavet vātakṛtstambhanaṃ tatsyādyathā vatsakaṭuṇṭukau" },
      { type: "verse", number: "14", sanskrit: "रसायनं च तज्ज्ञेयं यज्जराव्याधिनाशनम् यथाऽमृता रुदन्ती च गुग्गुलुश्च हरीतकी", text: "rasāyanaṃ ca tajjñeyaṃ yajjarāvyādhināśanam yathā'mṛtā rudantī ca gugguluśca harītakī" },
      { type: "verse", number: "15", sanskrit: "यस्माद् द्र व्याद्भवेत्स्त्रीषु हर्षो वाजीकरं च तत् यथा नागबलाऽद्या स्युर्बीजं च कपिकच्छुजम्", text: "yasmād dra vyādbhavetstrīṣu harṣo vājīkaraṃ ca tat yathā nāgabalā'dyā syurbījaṃ ca kapikacchujam" },
      { type: "verse", number: "16", sanskrit: "यस्माच्छुक्रस्य वृद्धिः स्याच्छ्रुकलं हि तदुच्यते यथाऽश्वगन्धा मुसली शर्करा च शतावरी", text: "yasmācchukrasya vṛddhiḥ syācchrukalaṃ hi taducyate yathā'śvagandhā musalī śarkarā ca śatāvarī" },
      { type: "verse", number: "17", sanskrit: "श्रुकस्य जनकानि रेचकानि च द्र व्याणि दुग्धं माषाश्च भल्लातफलमज्जाऽमलानि च प्रवर्त्तकानि कथ्यन्ते जनकानि च रेतसः", text: "śrukasya janakāni recakāni ca dra vyāṇi dugdhaṃ māṣāśca bhallātaphalamajjā'malāni ca pravarttakāni kathyante janakāni ca retasaḥ" },
      { type: "verse", number: "18", sanskrit: "प्रवर्त्तनी स्त्री शुक्रस्य रेचनं बृहतीफलम् जातीफलं स्तम्भकं च शोषणी च हरीतकी", text: "pravarttanī strī śukrasya recanaṃ bṛhatīphalam jātīphalaṃ stambhakaṃ ca śoṣaṇī ca harītakī" },
      { type: "verse", number: "19", sanskrit: "देहस्य सूक्ष्मच्छिद्रे षु विशेद्यत्सूक्ष्ममुच्यते तद्यथा सैन्धवं क्षौद्रं  निम्बतैलं रुबूद्भवम्", text: "dehasya sūkṣmacchidre ṣu viśedyatsūkṣmamucyate tadyathā saindhavaṃ kṣaudraṃ  nimbatailaṃ rubūdbhavam" },
      { type: "verse", number: "20", sanskrit: "पूर्वं व्याप्याखिलं कायं ततः पाकं च गच्छति व्यवायि तद्यथा भङ्गा फेनं चाहिसमुद्भवम्", text: "pūrvaṃ vyāpyākhilaṃ kāyaṃ tataḥ pākaṃ ca gacchati vyavāyi tadyathā bhaṅgā phenaṃ cāhisamudbhavam" },
      { type: "verse", number: "21", sanskrit: "सन्धिबन्धांस्तु शिथिलान्यत्करोति विकाशि तत् विश्लेष्यौजश्च धातुभ्यो यथा क्रमुककोद्र वाः", text: "sandhibandhāṃstu śithilānyatkaroti vikāśi tat viśleṣyaujaśca dhātubhyo yathā kramukakodra vāḥ" },
      { type: "verse", number: "22", sanskrit: "बुद्धिं लुम्पति यद् द्र व्यं मदकारि तदुच्यते तमोगुणप्रधानं च यथा मद्यसुराऽदिकम्", text: "buddhiṃ lumpati yad dra vyaṃ madakāri taducyate tamoguṇapradhānaṃ ca yathā madyasurā'dikam" },
      { type: "verse", number: "23", sanskrit: "व्यवायि च विकाशि स्यात्सूक्ष्मं छेदि मदावहम् आग्नेयं जीवितहरं योगवाहि स्मृतं विषम्", text: "vyavāyi ca vikāśi syātsūkṣmaṃ chedi madāvaham āgneyaṃ jīvitaharaṃ yogavāhi smṛtaṃ viṣam" },
      { type: "verse", number: "24", sanskrit: "निजवीर्येण यद् द्र व्यं स्रोतोभ्यो दोषसञ्चयम् निरस्यति प्रमाथि स्यात्तद्यथा मरिचं वचा", text: "nijavīryeṇa yad dra vyaṃ srotobhyo doṣasañcayam nirasyati pramāthi syāttadyathā maricaṃ vacā" },
      { type: "verse", number: "25", sanskrit: "पैच्छिल्याद्गौरवाद् द्र व्यं रुद्ध्वा रसवहाः शिराः धत्ते यद्गौरवं तत्स्यादभिष्यन्दि यथा दधि", text: "paicchilyādgauravād dra vyaṃ ruddhvā rasavahāḥ śirāḥ dhatte yadgauravaṃ tatsyādabhiṣyandi yathā dadhi" },
    ],
  },
  {
    sthana: "Пурвакханда",
    number: 5,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Муттра парикша — Диагностика мочи" },
      { type: "text", text: "Детальная система диагностики по моче: цвет, запах, консистенция, поведение масла в моче (таила-бинду парикша). Комплексная урологическая диагностика." },
      { type: "verse", number: "1", sanskrit: "तत्र कलादिकाख्यानम् शिआ!रीरम् कलादिकाख्यानम् कलाः सप्ताशयाः सप्त धातवःसप्त तन्मलाः सप्तोपधातवः सप्त त्वचः सप्त प्रकीर्त्तिताः", text: "tatra kalādikākhyānam śiā!rīram kalādikākhyānam kalāḥ saptāśayāḥ sapta dhātavaḥsapta tanmalāḥ saptopadhātavaḥ sapta tvacaḥ sapta prakīrttitāḥ" },
      { type: "verse", number: "2", sanskrit: "त्रयो दोषा नवशतं स्नायूनां सन्धयस्तथा दशाधिकं च द्विशतमस्थ्नां च त्रिशतं तथा", text: "trayo doṣā navaśataṃ snāyūnāṃ sandhayastathā daśādhikaṃ ca dviśatamasthnāṃ ca triśataṃ tathā" },
      { type: "verse", number: "3", sanskrit: "सप्तोत्तरं मर्मशतं शिराः सप्तशतं तथा चतुर्विंशतिराख्याता धमन्यो रसवाहिकाः", text: "saptottaraṃ marmaśataṃ śirāḥ saptaśataṃ tathā caturviṃśatirākhyātā dhamanyo rasavāhikāḥ" },
      { type: "verse", number: "4", sanskrit: "मांसपेश्यः समाख्याता नृणां पञ्चशतं बुधैः स्त्रीणां च विंशत्यधिकाः कण्डराश्चैव षोडश", text: "māṃsapeśyaḥ samākhyātā nṛṇāṃ pañcaśataṃ budhaiḥ strīṇāṃ ca viṃśatyadhikāḥ kaṇḍarāścaiva ṣoḍaśa" },
      { type: "verse", number: "5", sanskrit: "नृदेहे दश रन्ध्राणि नारीदेहे त्रयोदश एतत्समासतः प्रोक्तं विस्तरेणाधुनोच्यते", text: "nṛdehe daśa randhrāṇi nārīdehe trayodaśa etatsamāsataḥ proktaṃ vistareṇādhunocyate" },
      { type: "verse", number: "6", sanskrit: "मांसासृङ्मेदसां तिस्रो यकृत्प्लीह्नोश्चतुर्थिका पञ्चमी च तथाऽन्त्राणां षष्ठी चाग्निधरा मता रेतोधरा सप्तमी स्यादिति सप्त कलाः स्मृताः", text: "māṃsāsṛṅmedasāṃ tisro yakṛtplīhnoścaturthikā pañcamī ca tathā'ntrāṇāṃ ṣaṣṭhī cāgnidharā matā retodharā saptamī syāditi sapta kalāḥ smṛtāḥ" },
      { type: "verse", number: "7", sanskrit: "श्लेष्माशयः स्यादुरसि तस्मादामाशयस्त्वधः", text: "śleṣmāśayaḥ syādurasi tasmādāmāśayastvadhaḥ" },
      { type: "verse", number: "8", sanskrit: "ऊर्ध्वमग्न्याशयो नाभेर्वामभागे व्यवस्थितः तस्योपरि तिलं ज्ञेयं तदधः पवनाशयः", text: "ūrdhvamagnyāśayo nābhervāmabhāge vyavasthitaḥ tasyopari tilaṃ jñeyaṃ tadadhaḥ pavanāśayaḥ" },
      { type: "verse", number: "9", sanskrit: "मलाशयस्त्वधस्तस्माद् बस्तिर्मूत्राशयस्त्वधः जीवरक्ताशयमुरो ज्ञेयाः सप्ताशयस्त्वमी", text: "malāśayastvadhastasmād bastirmūtrāśayastvadhaḥ jīvaraktāśayamuro jñeyāḥ saptāśayastvamī" },
      { type: "verse", number: "10", sanskrit: "पुरुषेभ्योऽधिकाश्चान्ये नारीणामाशयास्त्रयः धरा गर्भाशयः प्रोक्तः स्तनौ स्तन्याशयौ मतौ", text: "puruṣebhyo'dhikāścānye nārīṇāmāśayāstrayaḥ dharā garbhāśayaḥ proktaḥ stanau stanyāśayau matau" },
      { type: "verse", number: "11", sanskrit: "अथ सप्तधातूनां नामानि तदुत्पत्तिक्रमश्च रसासृङ्मांसमेदोऽस्थिमज्जाशुक्राणि धातवः जायन्तेऽन्योऽन्यतः सर्वे पाचिताः पित्ततेजसा", text: "atha saptadhātūnāṃ nāmāni tadutpattikramaśca rasāsṛṅmāṃsamedo'sthimajjāśukrāṇi dhātavaḥ jāyante'nyo'nyataḥ sarve pācitāḥ pittatejasā" },
      { type: "verse", number: "12", sanskrit: "रसाद्र क्तं ततो मांसं मांसान्मेदः प्रजायते मेदसोऽस्थि ततो मज्जा मज्जायाः शुक्रसंभवः", text: "rasādra ktaṃ tato māṃsaṃ māṃsānmedaḥ prajāyate medaso'sthi tato majjā majjāyāḥ śukrasaṃbhavaḥ" },
      { type: "verse", number: "13", sanskrit: "अथ सप्तधातूनां मलास्तदुत्पत्तिक्रमश्च जिह्वानेत्रकपोलानां जलं पित्तं च रञ्जकम् कर्णविड्रसनादन्तकक्षामेढ्रादिजं मलम्", text: "atha saptadhātūnāṃ malāstadutpattikramaśca jihvānetrakapolānāṃ jalaṃ pittaṃ ca rañjakam karṇaviḍrasanādantakakṣāmeḍhrādijaṃ malam" },
      { type: "verse", number: "14", sanskrit: "नखनेत्रमलं वक्त्रे स्निग्धत्वं पिटिकास्तथा जायन्ते सप्तधातूनां मलान्येतान्यनुक्रमात्", text: "nakhanetramalaṃ vaktre snigdhatvaṃ piṭikāstathā jāyante saptadhātūnāṃ malānyetānyanukramāt" },
      { type: "verse", number: "15", sanskrit: "कफः पित्तं मलं खेषु प्रस्वेदो नखरोम च नेत्रविट् त्वक्षु च स्नेहो धातूनां क्रमशो मलाः", text: "kaphaḥ pittaṃ malaṃ kheṣu prasvedo nakharoma ca netraviṭ tvakṣu ca sneho dhātūnāṃ kramaśo malāḥ" },
      { type: "verse", number: "16", sanskrit: "स्तन्यं रजश्च नारीणां काले भवति गच्छति शुद्धमांसभवः स्नेहः सा वसा परिकीर्त्तिता", text: "stanyaṃ rajaśca nārīṇāṃ kāle bhavati gacchati śuddhamāṃsabhavaḥ snehaḥ sā vasā parikīrttitā" },
      { type: "verse", number: "17", sanskrit: "स्वेदो दन्तास्तथा केशास्तथैवौजश्च सप्तमम् इति धातुभवा ज्ञेया एते सप्तोपधातवः", text: "svedo dantāstathā keśāstathaivaujaśca saptamam iti dhātubhavā jñeyā ete saptopadhātavaḥ" },
      { type: "verse", number: "18", sanskrit: "ओजः सर्वशरीरस्थं शीतं स्निग्धं स्थिरं मतम् सोमात्मकं शरीरस्य बलपुष्टिकरं मतम्", text: "ojaḥ sarvaśarīrasthaṃ śītaṃ snigdhaṃ sthiraṃ matam somātmakaṃ śarīrasya balapuṣṭikaraṃ matam" },
      { type: "verse", number: "19", sanskrit: "ज्ञेयाऽवभासिनी पूर्वं सिध्मस्थानं च सा मता द्वितीया लोहिता ज्ञेया तिलकालकजन्मभूः", text: "jñeyā'vabhāsinī pūrvaṃ sidhmasthānaṃ ca sā matā dvitīyā lohitā jñeyā tilakālakajanmabhūḥ" },
      { type: "verse", number: "20", sanskrit: "श्वेता तृतीया संख्याता स्थानं चर्मदलस्य सा ताम्रा चतुर्थी विज्ञेया किलासश्वित्रभूमिका", text: "śvetā tṛtīyā saṃkhyātā sthānaṃ carmadalasya sā tāmrā caturthī vijñeyā kilāsaśvitrabhūmikā" },
      { type: "verse", number: "21", sanskrit: "पञ्चमी वेदनी ख्याता सर्वकुष्ठोद्भवस्ततः विख्याता रोहिणी षष्ठी ग्रन्थिगण्डापचीस्थितिः", text: "pañcamī vedanī khyātā sarvakuṣṭhodbhavastataḥ vikhyātā rohiṇī ṣaṣṭhī granthigaṇḍāpacīsthitiḥ" },
      { type: "verse", number: "22", sanskrit: "स्थूला त्वक्सप्तमी ख्याता विद्र ध्यादेः स्थितिश्च सा इति सप्त त्वचः प्रोक्ताः स्थूला व्रीहिद्विमात्रया", text: "sthūlā tvaksaptamī khyātā vidra dhyādeḥ sthitiśca sā iti sapta tvacaḥ proktāḥ sthūlā vrīhidvimātrayā" },
      { type: "verse", number: "23", sanskrit: "वायुः पित्तं कफो दोषा धातवश्च मलास्तथा तत्रापि पञ्चधा ख्याताः प्रत्येकं देहधारणात्", text: "vāyuḥ pittaṃ kapho doṣā dhātavaśca malāstathā tatrāpi pañcadhā khyātāḥ pratyekaṃ dehadhāraṇāt" },
      { type: "verse", number: "24", sanskrit: "दोषाणां नामान्तरे कारणनिर्देशः शरीरदूषणाद्दोषा धातवो देहधारणात् वातपित्तकफा ज्ञेया मलिनीकरणान्मलाः", text: "doṣāṇāṃ nāmāntare kāraṇanirdeśaḥ śarīradūṣaṇāddoṣā dhātavo dehadhāraṇāt vātapittakaphā jñeyā malinīkaraṇānmalāḥ" },
      { type: "verse", number: "25", sanskrit: "तत्र वायोः प्राधान्यं तत्कार्यवर्णनञ्च पित्तं पङ्गु कफः पङ्गुः पङ्गवो मलधातवः वायुना यत्र नीयन्ते तत्र गच्छन्ति मेघवत्", text: "tatra vāyoḥ prādhānyaṃ tatkāryavarṇanañca pittaṃ paṅgu kaphaḥ paṅguḥ paṅgavo maladhātavaḥ vāyunā yatra nīyante tatra gacchanti meghavat" },
      { type: "verse", number: "26", sanskrit: "पवनस्तेषु बलवान्विभागकरणान्मतः रजोगुणमयः सूक्ष्मः शीतो रूक्षो लघुश्चलः", text: "pavanasteṣu balavānvibhāgakaraṇānmataḥ rajoguṇamayaḥ sūkṣmaḥ śīto rūkṣo laghuścalaḥ" },
      { type: "verse", number: "27", sanskrit: "कार्यभेदेन वायोः पञ्चविधत्वम् मलाशये चरेत्कोष्ठे वह्निस्थाने तथा हृदि कण्ठे सर्वाङ्गदेशेषु वायुः पञ्चप्रकारतः", text: "kāryabhedena vāyoḥ pañcavidhatvam malāśaye caretkoṣṭhe vahnisthāne tathā hṛdi kaṇṭhe sarvāṅgadeśeṣu vāyuḥ pañcaprakārataḥ" },
      { type: "verse", number: "28", sanskrit: "अपानः स्यात्समानश्च प्राणोदानौ तथैव च व्यानश्चेति समीरस्य नामान्युक्तान्यनुक्रमात्", text: "apānaḥ syātsamānaśca prāṇodānau tathaiva ca vyānaśceti samīrasya nāmānyuktānyanukramāt" },
      { type: "verse", number: "29", sanskrit: "पित्तमुष्णं द्र वं पीतं नीलं सत्त्वगुणोत्तरम् कटु तिक्तरसं ज्ञेयं विदग्धं चाम्लतां व्रजेत्", text: "pittamuṣṇaṃ dra vaṃ pītaṃ nīlaṃ sattvaguṇottaram kaṭu tiktarasaṃ jñeyaṃ vidagdhaṃ cāmlatāṃ vrajet" },
      { type: "verse", number: "30", sanskrit: "तस्य स्थानानि कार्याणि नामानि च अग्न्याशये भवेत्पित्तमग्निरूपं तिलोन्मितम् त्वचि कान्तिकरं ज्ञेयं लेपाभ्यङ्गादिपाचकम्", text: "tasya sthānāni kāryāṇi nāmāni ca agnyāśaye bhavetpittamagnirūpaṃ tilonmitam tvaci kāntikaraṃ jñeyaṃ lepābhyaṅgādipācakam" },
      { type: "verse", number: "32", sanskrit: "दृश्यं यकृति यत्पित्तं तद्र सं शोणितं नयेत् यत्पित्तं नेत्रयुगले रूपदर्शनकारि तत् यत्पित्तं हृदये तिष्ठेन्मेधाप्रज्ञाकरं च तत् पाचकं भ्राजकं चैव रञ्जकालोचके तथा साधकं चेति पञ्चैव पित्तनामान्यनुक्रमात्", text: "dṛśyaṃ yakṛti yatpittaṃ tadra saṃ śoṇitaṃ nayet yatpittaṃ netrayugale rūpadarśanakāri tat yatpittaṃ hṛdaye tiṣṭhenmedhāprajñākaraṃ ca tat pācakaṃ bhrājakaṃ caiva rañjakālocake tathā sādhakaṃ ceti pañcaiva pittanāmānyanukramāt" },
      { type: "verse", number: "33", sanskrit: "कफः स्निग्धो गुरुः श्वेतः पिच्छिलः शीतलस्तथा तमोगुणाधिकः स्वादुर्विदग्धो लवणो भवेत्", text: "kaphaḥ snigdho guruḥ śvetaḥ picchilaḥ śītalastathā tamoguṇādhikaḥ svādurvidagdho lavaṇo bhavet" },
      { type: "verse", number: "34", sanskrit: "कफश्चामाशये मूर्ध्नि कण्ठे हृदि च संधिषु तिष्ठन्करोति देहस्य स्थैर्यं सर्वाङ्गपाटवम्", text: "kaphaścāmāśaye mūrdhni kaṇṭhe hṛdi ca saṃdhiṣu tiṣṭhankaroti dehasya sthairyaṃ sarvāṅgapāṭavam" },
      { type: "verse", number: "35", sanskrit: "क्लेदनः स्नेहनश्चैव रसनश्चावलम्बनः श्लेष्मकश्चेति नामानि कफस्योक्तान्यनुक्रमात्", text: "kledanaḥ snehanaścaiva rasanaścāvalambanaḥ śleṣmakaśceti nāmāni kaphasyoktānyanukramāt" },
      { type: "verse", number: "36", sanskrit: "स्नायवो बन्धनं प्रोक्ता देहे मांसास्थिमेदसाम्", text: "snāyavo bandhanaṃ proktā dehe māṃsāsthimedasām" },
      { type: "verse", number: "37", sanskrit: "सन्धयश्चाङ्गसन्धानाद्देहे प्रोक्ताः कफान्विताः", text: "sandhayaścāṅgasandhānāddehe proktāḥ kaphānvitāḥ" },
      { type: "verse", number: "38", sanskrit: "आधारश्च तथा सारः कायेऽस्थीनि बुधा विदुः", text: "ādhāraśca tathā sāraḥ kāye'sthīni budhā viduḥ" },
      { type: "verse", number: "39", sanskrit: "मर्माणि जीवाधाराणि प्रायेण मुनयो जगुः", text: "marmāṇi jīvādhārāṇi prāyeṇa munayo jaguḥ" },
      { type: "verse", number: "40", sanskrit: "सन्धिबन्धनकारिण्यो दोषधातुवहाः शिराः", text: "sandhibandhanakāriṇyo doṣadhātuvahāḥ śirāḥ" },
      { type: "verse", number: "41", sanskrit: "धमन्यो रसवाहिन्यो धमन्ति पवनं तनौ", text: "dhamanyo rasavāhinyo dhamanti pavanaṃ tanau" },
      { type: "verse", number: "42", sanskrit: "मांसपेश्यो बलाय स्युरवष्टम्भाय देहिनाम्", text: "māṃsapeśyo balāya syuravaṣṭambhāya dehinām" },
      { type: "verse", number: "43", sanskrit: "प्रसारणाकुञ्चनयोरङ्गानां कण्डरा मताः", text: "prasāraṇākuñcanayoraṅgānāṃ kaṇḍarā matāḥ" },
      { type: "verse", number: "44", sanskrit: "नासानयनकर्णानां द्वे द्वे रन्ध्रे प्रकीर्त्तिते मेहनापानवक्त्राणामेकैकं रन्ध्रमुच्यते दशमं मस्तके प्रोक्तं रन्ध्राणीति नृणां विदुः स्त्रीणां त्रीण्यधिकानि स्युः स्तनयोर्गर्भवर्त्मनः सूक्ष्मच्छिद्रा णि चान्यानि मतानि त्वचि जन्मिनाम्", text: "nāsānayanakarṇānāṃ dve dve randhre prakīrttite mehanāpānavaktrāṇāmekaikaṃ randhramucyate daśamaṃ mastake proktaṃ randhrāṇīti nṛṇāṃ viduḥ strīṇāṃ trīṇyadhikāni syuḥ stanayorgarbhavartmanaḥ sūkṣmacchidrā ṇi cānyāni matāni tvaci janminām" },
      { type: "verse", number: "45", sanskrit: "तद्वामे फुफ्फुसं प्लीहा दक्षिणे च यकृन्मतम् उदानवायोराधारः फुफ्फुसं प्रोच्यते बुधैः रक्तवाहिशिरामूलं प्लीहा ख्याता महर्षिभिः यकृद्र ञ्जकपित्तस्य स्थानं रक्तस्य संश्रयः", text: "tadvāme phuphphusaṃ plīhā dakṣiṇe ca yakṛnmatam udānavāyorādhāraḥ phuphphusaṃ procyate budhaiḥ raktavāhiśirāmūlaṃ plīhā khyātā maharṣibhiḥ yakṛdra ñjakapittasya sthānaṃ raktasya saṃśrayaḥ" },
      { type: "verse", number: "46", sanskrit: "जलवाहिशिरामूलं तृष्णाऽच्छादनकं तिलम्", text: "jalavāhiśirāmūlaṃ tṛṣṇā'cchādanakaṃ tilam" },
      { type: "verse", number: "47", sanskrit: "वृक्कौ तुष्टिकरौ प्रोक्तौ जठरस्थस्य मेदसः", text: "vṛkkau tuṣṭikarau proktau jaṭharasthasya medasaḥ" },
      { type: "verse", number: "48", sanskrit: "वीर्यवाहिशिराधारौ वृषणौ पौरुषावहौ गर्भाधानकरं लिङ्गमयनं वीर्यमूत्रयोः", text: "vīryavāhiśirādhārau vṛṣaṇau pauruṣāvahau garbhādhānakaraṃ liṅgamayanaṃ vīryamūtrayoḥ" },
      { type: "verse", number: "49", sanskrit: "हृदयं चेतनास्थानमोजसश्चाश्रयो मतम्", text: "hṛdayaṃ cetanāsthānamojasaścāśrayo matam" },
      { type: "verse", number: "50", sanskrit: "शिरा धमन्यो नाभिस्थाः सर्वा व्याप्य स्थितास्तनुम् पुष्णन्ति चानिशं वायोः संयोगात्सर्वधातुभिः", text: "śirā dhamanyo nābhisthāḥ sarvā vyāpya sthitāstanum puṣṇanti cāniśaṃ vāyoḥ saṃyogātsarvadhātubhiḥ" },
      { type: "verse", number: "51", sanskrit: "प्राणवायोः शरीरव्यापारनिर्देशः नाभिस्थः प्राणपवनः स्पृष्ट्वा हृत्कमलान्तरम् कण्ठाद्बहिर्विनिर्याति पातुं विष्णुपदामृतम् पीत्वा चाम्बरपीयूषं पुनरायाति वेगतः प्रीणयन्देहमखिलं जीवयञ्जठरानलम्", text: "prāṇavāyoḥ śarīravyāpāranirdeśaḥ nābhisthaḥ prāṇapavanaḥ spṛṣṭvā hṛtkamalāntaram kaṇṭhādbahirviniryāti pātuṃ viṣṇupadāmṛtam pītvā cāmbarapīyūṣaṃ punarāyāti vegataḥ prīṇayandehamakhilaṃ jīvayañjaṭharānalam" },
      { type: "verse", number: "52", sanskrit: "शरीरप्राणयोरेवं संयोगादायुरुच्यते कालेन तद्वियोगाच्च पञ्चत्वं कथ्यते बुधैः", text: "śarīraprāṇayorevaṃ saṃyogādāyurucyate kālena tadviyogācca pañcatvaṃ kathyate budhaiḥ" },
      { type: "verse", number: "53", sanskrit: "तत्र वैद्यानां कृते कर्त्तव्यकर्मोपदेशः न जन्तुः कश्चिदमरः पृथिव्यां जायते क्वचित् अतो मृत्युरवार्यः स्यात्किन्तु रोगान्निवारयेत्", text: "tatra vaidyānāṃ kṛte karttavyakarmopadeśaḥ na jantuḥ kaścidamaraḥ pṛthivyāṃ jāyate kvacit ato mṛtyuravāryaḥ syātkintu rogānnivārayet" },
      { type: "verse", number: "54", sanskrit: "रोगनिवारणे साध्यादिभेदनिर्देशः याप्यत्वं याति साध्यस्तु याप्यो गच्छत्यसाध्यताम् जीवितं हन्त्यसाध्यस्तु नरस्याप्रतिकारिणः", text: "roganivāraṇe sādhyādibhedanirdeśaḥ yāpyatvaṃ yāti sādhyastu yāpyo gacchatyasādhyatām jīvitaṃ hantyasādhyastu narasyāpratikāriṇaḥ" },
      { type: "verse", number: "56", sanskrit: "धर्मादिसाधनतनो रक्षानिर्देशः धर्मार्थकाममोक्षाणां शरीरं साधनं यतः अतो रुग्भ्यस्तनुं रक्षेन्नरः कर्मविपाकवित् दोषाणां साम्यस्य वैषम्यस्य च फलम् धातवस्तन्मला दोषा नाशयन्त्यसमास्तनुम् समाः सुखाय विज्ञेया बलायोपचयाय च", text: "dharmādisādhanatano rakṣānirdeśaḥ dharmārthakāmamokṣāṇāṃ śarīraṃ sādhanaṃ yataḥ ato rugbhyastanuṃ rakṣennaraḥ karmavipākavit doṣāṇāṃ sāmyasya vaiṣamyasya ca phalam dhātavastanmalā doṣā nāśayantyasamāstanum samāḥ sukhāya vijñeyā balāyopacayāya ca" },
      { type: "verse", number: "57", sanskrit: "जगद्योनेरनिच्छस्य चिदानन्दैकरूपिणः पुंसोऽस्ति प्रकृतिर्नित्या प्रतिच्छायेव भास्वतः", text: "jagadyoneranicchasya cidānandaikarūpiṇaḥ puṃso'sti prakṛtirnityā praticchāyeva bhāsvataḥ" },
      { type: "verse", number: "58", sanskrit: "प्रकृतिपुरुषयोगेन सृष्ट्युत्पत्तिनिर्देशः अचेतनाऽपि चैतन्ययोगेन परमात्मनः अकरोद्विश्वमखिलमनित्यं नाटकाकृति", text: "prakṛtipuruṣayogena sṛṣṭyutpattinirdeśaḥ acetanā'pi caitanyayogena paramātmanaḥ akarodviśvamakhilamanityaṃ nāṭakākṛti" },
      { type: "verse", number: "59", sanskrit: "प्रकृतिर्विश्वजननी पूर्वं बुद्धिमजीजनत् इच्छामयीं महद्रू पामहङ्कारस्ततोऽभवत् त्रिविधः सोऽपि सञ्जातो रजः सत्त्वतमोगुणैः", text: "prakṛtirviśvajananī pūrvaṃ buddhimajījanat icchāmayīṃ mahadrū pāmahaṅkārastato'bhavat trividhaḥ so'pi sañjāto rajaḥ sattvatamoguṇaiḥ" },
      { type: "verse", number: "60", sanskrit: "त्रिगुणात्मकाहङ्कारस्य कार्याणि तस्मात्सत्त्वरजोयुक्तादिन्द्रि याणि दशाभवन् मनश्च जातं तान्याहुः श्रोत्रत्वङ्नयनं तथा", text: "triguṇātmakāhaṅkārasya kāryāṇi tasmātsattvarajoyuktādindri yāṇi daśābhavan manaśca jātaṃ tānyāhuḥ śrotratvaṅnayanaṃ tathā" },
      { type: "verse", number: "61", sanskrit: "जिह्वाघ्राणवचोहस्तपादोपस्थगुदानि च पञ्च बुद्धीन्द्रि याण्याहुः प्राक्तनानीतराणि च कर्मेन्द्रि याणि पञ्च्व कथ्यन्ते सूक्ष्मबुद्धिभिः", text: "jihvāghrāṇavacohastapādopasthagudāni ca pañca buddhīndri yāṇyāhuḥ prāktanānītarāṇi ca karmendri yāṇi pañcva kathyante sūkṣmabuddhibhiḥ" },
      { type: "verse", number: "62", sanskrit: "तमः सत्त्वगुणोत्कृष्टादहङ्कारादथाभवत् तन्मात्रपञ्चकं तस्य नामान्युक्तानि सूरिभिः शब्दतन्मात्रकं स्पर्शतन्मात्रं रूपमात्रकम् रसतन्मात्रकं गन्धतन्मात्रं चेति तद्विदुः", text: "tamaḥ sattvaguṇotkṛṣṭādahaṅkārādathābhavat tanmātrapañcakaṃ tasya nāmānyuktāni sūribhiḥ śabdatanmātrakaṃ sparśatanmātraṃ rūpamātrakam rasatanmātrakaṃ gandhatanmātraṃ ceti tadviduḥ" },
      { type: "verse", number: "63", sanskrit: "तन्मात्रपञ्चकात्तस्मात्संजातं भूतपञ्चकम् व्योमानिलानलजलक्षोणीरूपं च तन्मतम्", text: "tanmātrapañcakāttasmātsaṃjātaṃ bhūtapañcakam vyomānilānalajalakṣoṇīrūpaṃ ca tanmatam" },
      { type: "verse", number: "64", sanskrit: "शब्दः स्पर्शश्च रूपं च रसगन्धावनुक्रमात् तन्मात्राणां विशेषाः स्युः स्थूलभावमुपागताः", text: "śabdaḥ sparśaśca rūpaṃ ca rasagandhāvanukramāt tanmātrāṇāṃ viśeṣāḥ syuḥ sthūlabhāvamupāgatāḥ" },
      { type: "verse", number: "65", sanskrit: "बुद्धीन्द्रि याणां पञ्चैव शब्दाद्या विषया मताः", text: "buddhīndri yāṇāṃ pañcaiva śabdādyā viṣayā matāḥ" },
      { type: "verse", number: "66", sanskrit: "कर्मेन्द्रि याणां विषया भाषादानविहारिताः आनन्दोत्सर्गकौ चैव कथितास्तत्त्वदर्शिभिः", text: "karmendri yāṇāṃ viṣayā bhāṣādānavihāritāḥ ānandotsargakau caiva kathitāstattvadarśibhiḥ" },
      { type: "verse", number: "67", sanskrit: "तत्र प्रथमतत्त्वस्य प्रकृतेर्नामनिर्देशः प्रधानं प्रकृतिः शक्तिर्नित्या चाविकृतिस्तथा एतानि तस्या नामानि शिवमाश्रित्य या स्थिता", text: "tatra prathamatattvasya prakṛternāmanirdeśaḥ pradhānaṃ prakṛtiḥ śaktirnityā cāvikṛtistathā etāni tasyā nāmāni śivamāśritya yā sthitā" },
      { type: "verse", number: "68", sanskrit: "प्रकृतिविकृतिसंज्ञकस्य तत्त्वसप्तकस्य निर्देशः महानहङ्कृतिः पञ्चतन्मात्राणि पृथक्पृथक् प्रकृतिर्विकृतिश्चैव सप्तैतानि बुधा जगुः", text: "prakṛtivikṛtisaṃjñakasya tattvasaptakasya nirdeśaḥ mahānahaṅkṛtiḥ pañcatanmātrāṇi pṛthakpṛthak prakṛtirvikṛtiścaiva saptaitāni budhā jaguḥ" },
      { type: "verse", number: "69", sanskrit: "दशेन्द्रि याणि चित्तं च महाभूतानि पञ्च च विकाराः षोडश ज्ञेयाः सर्वं व्याप्य जगत्स्थिताः", text: "daśendri yāṇi cittaṃ ca mahābhūtāni pañca ca vikārāḥ ṣoḍaśa jñeyāḥ sarvaṃ vyāpya jagatsthitāḥ" },
      { type: "verse", number: "70", sanskrit: "एवं चतुर्विंशतिभिस्तत्त्वैः सिद्धे वपुर्गृहे जीवात्मा नियतो नित्यो वसति स्वान्तदूतवान्", text: "evaṃ caturviṃśatibhistattvaiḥ siddhe vapurgṛhe jīvātmā niyato nityo vasati svāntadūtavān" },
      { type: "verse", number: "71", sanskrit: "स देही कथ्यते पापपुण्यदुःखसुखादिभिः व्याप्तो बद्धश्च मनसा कृत्रिमैः कर्मबन्धनैः", text: "sa dehī kathyate pāpapuṇyaduḥkhasukhādibhiḥ vyāpto baddhaśca manasā kṛtrimaiḥ karmabandhanaiḥ" },
      { type: "verse", number: "72", sanskrit: "कामक्रोधौ लोभमोहावहङ्कारश्च पञ्चमः दशेन्द्रि याणि बुद्धिश्च तस्य बन्धाय देहिनः", text: "kāmakrodhau lobhamohāvahaṅkāraśca pañcamaḥ daśendri yāṇi buddhiśca tasya bandhāya dehinaḥ" },
      { type: "verse", number: "73", sanskrit: "जीवस्य बन्धमोक्षयोर्दुःखसुखयोर्निर्देशः आप्नोति बन्धमज्ञानादात्मज्ञानाच्च मुच्यते तद्दुःखयोगकृद्व्याधिरारोग्यं तत्सुखावहम्", text: "jīvasya bandhamokṣayorduḥkhasukhayornirdeśaḥ āpnoti bandhamajñānādātmajñānācca mucyate tadduḥkhayogakṛdvyādhirārogyaṃ tatsukhāvaham" },
    ],
  },
  {
    sthana: "Пурвакханда",
    number: 6,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Рога парикша — Диагностика болезней" },
      { type: "text", text: "Обобщение методов диагностики: осмотр, расспрос, пальпация, пульс, моча. Шарангадхара синтезирует все диагностические подходы в системное руководство." },
      { type: "verse", number: "1", sanskrit: "यात्यामाशयमाहारः पूर्वं प्राणानिलेरितः माधुर्यं फेनभावं च षड्रसोऽपि लभेत सः", text: "yātyāmāśayamāhāraḥ pūrvaṃ prāṇānileritaḥ mādhuryaṃ phenabhāvaṃ ca ṣaḍraso'pi labheta saḥ" },
      { type: "verse", number: "2", sanskrit: "आहारस्याम्लभाव ग्रहणीनयन कटुभावानां निर्देशः अथ पाचकपित्तेन विदग्धश्चाम्लतां व्रजेत् ततः समानमरुता ग्रहणीमभिनीयते ग्रहण्यां पच्यते कोष्ठवह्विना जायते कटुः", text: "āhārasyāmlabhāva grahaṇīnayana kaṭubhāvānāṃ nirdeśaḥ atha pācakapittena vidagdhaścāmlatāṃ vrajet tataḥ samānamarutā grahaṇīmabhinīyate grahaṇyāṃ pacyate koṣṭhavahvinā jāyate kaṭuḥ" },
      { type: "verse", number: "3", sanskrit: "रसो भवति संपक्वादपक्वादामसंभवः", text: "raso bhavati saṃpakvādapakvādāmasaṃbhavaḥ" },
      { type: "verse", number: "4", sanskrit: "वह्नेर्बलेन माधुर्यं स्निग्धतां याति तद्र सः पुष्णाति धातूनखिलान्सम्यक्पक्वोऽमृतोपमः", text: "vahnerbalena mādhuryaṃ snigdhatāṃ yāti tadra saḥ puṣṇāti dhātūnakhilānsamyakpakvo'mṛtopamaḥ" },
      { type: "verse", number: "5", sanskrit: "मन्दबह्निविदग्धश्च कटुश्चाम्लो भवेद्र सः विषभावं व्रजेद्वाऽपि कुर्याद्वा रोगसंकरम्", text: "mandabahnividagdhaśca kaṭuścāmlo bhavedra saḥ viṣabhāvaṃ vrajedvā'pi kuryādvā rogasaṃkaram" },
      { type: "verse", number: "6", sanskrit: "आहारस्य सारमलपदार्थयोर्निर्देशादिकम् आहारस्य रसः सारः सारहीनो मलद्र वः शिराभिस्तज्जलं नीतं वस्तौ मूत्रत्वमाप्नुयात्", text: "āhārasya sāramalapadārthayornirdeśādikam āhārasya rasaḥ sāraḥ sārahīno maladra vaḥ śirābhistajjalaṃ nītaṃ vastau mūtratvamāpnuyāt" },
      { type: "verse", number: "7", sanskrit: "तत्किट्टं च मलं ज्ञेयं तिष्ठेत्पक्वाशये च तत् वलित्रितयमार्गेण यात्यपानेन नोदितम् प्रवाहिणी सर्जनी च ग्राहिकेति वलित्रयम्", text: "tatkiṭṭaṃ ca malaṃ jñeyaṃ tiṣṭhetpakvāśaye ca tat valitritayamārgeṇa yātyapānena noditam pravāhiṇī sarjanī ca grāhiketi valitrayam" },
      { type: "verse", number: "8", sanskrit: "रसस्तु हृदयं याति समान मरुतेरितः रञ्जितः पाचितस्तत्र पित्तेनायाति रक्तताम्", text: "rasastu hṛdayaṃ yāti samāna maruteritaḥ rañjitaḥ pācitastatra pittenāyāti raktatām" },
      { type: "verse", number: "9", sanskrit: "रक्तस्य प्राधान्यस्वरूपयोर्निर्देशः रक्तं सर्वशरीरस्थं जीवस्याधारमुत्तमम् स्निग्धं गुरु चलं स्वादु विदग्धं पित्तवद्भवेत्", text: "raktasya prādhānyasvarūpayornirdeśaḥ raktaṃ sarvaśarīrasthaṃ jīvasyādhāramuttamam snigdhaṃ guru calaṃ svādu vidagdhaṃ pittavadbhavet" },
      { type: "verse", number: "10", sanskrit: "पाचिताः पित्ततापेन रसाद्या धातवः क्रमात् शुक्रत्वं यान्ति मासेन तथा स्त्रीणां रजो भवेत्", text: "pācitāḥ pittatāpena rasādyā dhātavaḥ kramāt śukratvaṃ yānti māsena tathā strīṇāṃ rajo bhavet" },
      { type: "verse", number: "11", sanskrit: "कामान्मिथुनसंयोगे शुद्धशोणितशुक्रजः गर्भःसंजायते नार्याः स जातो बाल उच्यते", text: "kāmānmithunasaṃyoge śuddhaśoṇitaśukrajaḥ garbhaḥsaṃjāyate nāryāḥ sa jāto bāla ucyate" },
      { type: "verse", number: "12", sanskrit: "स्त्रीपुंनपुंसकोत्पत्तौ हेतुनिर्देशः आधिक्ये रजसः कन्या पुत्रः शुक्राधिके भवेत् नपुंसकं समत्वेन यथेच्छा पारमेश्वरी", text: "strīpuṃnapuṃsakotpattau hetunirdeśaḥ ādhikye rajasaḥ kanyā putraḥ śukrādhike bhavet napuṃsakaṃ samatvena yathecchā pārameśvarī" },
      { type: "verse", number: "13", sanskrit: "बालस्य प्रथमे मासि देया भेषजरक्तिका", text: "bālasya prathame māsi deyā bheṣajaraktikā" },
      { type: "verse", number: "14", sanskrit: "अवलेहीकृतैकैव क्षीरक्षौद्र सिताघृतैः वर्धयेत्तावदेकैका यावद्भवति वत्सरः", text: "avalehīkṛtaikaiva kṣīrakṣaudra sitāghṛtaiḥ vardhayettāvadekaikā yāvadbhavati vatsaraḥ" },
      { type: "verse", number: "15", sanskrit: "माषैर्वृद्धिस्तदूर्ध्वं स्याद्यावत्षोडशवत्सरः ततः स्थिरा भयेत्तावद्यावद्वर्षाणि सप्ततिः", text: "māṣairvṛddhistadūrdhvaṃ syādyāvatṣoḍaśavatsaraḥ tataḥ sthirā bhayettāvadyāvadvarṣāṇi saptatiḥ" },
      { type: "verse", number: "16", sanskrit: "ततो बालकवन्मात्रा ह्रासनीया शनैः शनैः मात्रेयं कल्कचूर्णानां कषायाणां चतुर्गुणा", text: "tato bālakavanmātrā hrāsanīyā śanaiḥ śanaiḥ mātreyaṃ kalkacūrṇānāṃ kaṣāyāṇāṃ caturguṇā" },
      { type: "verse", number: "17", sanskrit: "अञ्जनं च तथा लेपः स्नानमभ्यङ्गकर्म च वमनं प्रतिमर्शश्च जन्मप्रभृति शस्यते", text: "añjanaṃ ca tathā lepaḥ snānamabhyaṅgakarma ca vamanaṃ pratimarśaśca janmaprabhṛti śasyate" },
      { type: "verse", number: "18", sanskrit: "वयोऽनुसारेण कवलादि योजना निर्देशः कवलः पञ्चमाद्वर्षादष्टमान्नस्यकर्म च विरेकः षोडशाद्वर्षाद्विंशतेश्चैव मैथुनम्", text: "vayo'nusāreṇa kavalādi yojanā nirdeśaḥ kavalaḥ pañcamādvarṣādaṣṭamānnasyakarma ca virekaḥ ṣoḍaśādvarṣādviṃśateścaiva maithunam" },
      { type: "verse", number: "19", sanskrit: "बाल्यादीनां ह्राससमयनिर्देशः बाल्यं वृद्धिश्छविर्मेधा त्वग्दृष्टिः शुक्रविक्रमौ बुद्धिः कर्मेन्द्रि यं चेतो जीवितं दशतो ह्र्रसेत्", text: "bālyādīnāṃ hrāsasamayanirdeśaḥ bālyaṃ vṛddhiśchavirmedhā tvagdṛṣṭiḥ śukravikramau buddhiḥ karmendri yaṃ ceto jīvitaṃ daśato hrraset" },
      { type: "verse", number: "20", sanskrit: "अल्पकेशः कृशो रूक्षो वाचालश्चलमानसः आकाशचारी स्वप्नेषु वातप्रकृतिको नरः", text: "alpakeśaḥ kṛśo rūkṣo vācālaścalamānasaḥ ākāśacārī svapneṣu vātaprakṛtiko naraḥ" },
      { type: "verse", number: "21", sanskrit: "अकालपलितैर्व्याप्तो धीमान्स्वेदी च रोषणः स्वप्नेषु ज्योतिषां द्र ष्टा पित्तप्रकृतिको नरः", text: "akālapalitairvyāpto dhīmānsvedī ca roṣaṇaḥ svapneṣu jyotiṣāṃ dra ṣṭā pittaprakṛtiko naraḥ" },
      { type: "verse", number: "22", sanskrit: "गम्भीरबुद्धिः स्थूलाङ्गः स्निग्धकेशो महाबलः स्वप्ने जलाशयालोकी श्लेष्मप्रकृतिको नरः", text: "gambhīrabuddhiḥ sthūlāṅgaḥ snigdhakeśo mahābalaḥ svapne jalāśayālokī śleṣmaprakṛtiko naraḥ" },
      { type: "verse", number: "23", sanskrit: "ज्ञातव्या मिश्रचिह्नैश्च द्वित्रिदोषोल्बणा नराः", text: "jñātavyā miśracihnaiśca dvitridoṣolbaṇā narāḥ" },
      { type: "verse", number: "24", sanskrit: "निद्रा मूर्च्छाभ्रान्तितन्द्रा लक्षणानि तमः कफाभ्यां निद्रा  स्यान्मूर्च्छा पित्ततमोभवा रजः पित्तानिलैर्भ्रान्तिस्तन्द्रा  श्लेष्मतमोऽनिलैः", text: "nidrā mūrcchābhrāntitandrā lakṣaṇāni tamaḥ kaphābhyāṃ nidrā  syānmūrcchā pittatamobhavā rajaḥ pittānilairbhrāntistandrā  śleṣmatamo'nilaiḥ" },
      { type: "verse", number: "25", sanskrit: "ग्लानिरोजःक्षयाद् दुःखादजीर्णाच्च श्रमाद्भवेत् यः सामर्थ्येऽप्यनुत्साहस्तदालस्यमुदीर्यते", text: "glānirojaḥkṣayād duḥkhādajīrṇācca śramādbhavet yaḥ sāmarthye'pyanutsāhastadālasyamudīryate" },
      { type: "verse", number: "28", sanskrit: "चैतन्यशिथिलत्वाद्यः पीत्वैकं श्वासमुद्वमेत् विदीर्णवदनः श्वासं जृम्भा सा कथ्यते बुधैः छिक्कालक्षणम् उदानप्राणयोरूर्ध्वं योगान्मौलिकफस्रवात् शब्दः संजायते नस्तः क्षुतं तत्कथ्यते बुधैः उद्गारलक्षणम् उदानकोपादाहारसुस्थिरत्वाच्च यद्भवेत् पवनस्योर्द्ध्वगमनं तमुद्गारं प्रचक्षते", text: "caitanyaśithilatvādyaḥ pītvaikaṃ śvāsamudvamet vidīrṇavadanaḥ śvāsaṃ jṛmbhā sā kathyate budhaiḥ chikkālakṣaṇam udānaprāṇayorūrdhvaṃ yogānmaulikaphasravāt śabdaḥ saṃjāyate nastaḥ kṣutaṃ tatkathyate budhaiḥ udgāralakṣaṇam udānakopādāhārasusthiratvācca yadbhavet pavanasyorddhvagamanaṃ tamudgāraṃ pracakṣate" },
    ],
  },
  {
    sthana: "Пурвакханда",
    number: 7,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Прана лакшана — Признаки жизненной силы" },
      { type: "text", text: "Признаки сильной и слабой жизненной силы (оджаса и праны). Прогностическая значимость для исходов болезней. Поддержание жизненной силы — высшая цель лечения." },
      { type: "verse", number: "1", sanskrit: "रोगाणां गणना पूर्वं मुनिभिर्या प्रकीर्त्तिता मयाऽत्र प्रोच्यते सैव तद्भेदा बहवो मताः", text: "rogāṇāṃ gaṇanā pūrvaṃ munibhiryā prakīrttitā mayā'tra procyate saiva tadbhedā bahavo matāḥ" },
      { type: "verse", number: "2", sanskrit: "पञ्चविंशतिरुद्दिष्टा ज्वरास्तद्भेद उच्यते पृथग्दोषैस्तथा द्वन्द्वभेदेन त्रिविधः स्मृतः एकश्च सन्निपातेन तद्भेदा बहवः स्मृताः", text: "pañcaviṃśatiruddiṣṭā jvarāstadbheda ucyate pṛthagdoṣaistathā dvandvabhedena trividhaḥ smṛtaḥ ekaśca sannipātena tadbhedā bahavaḥ smṛtāḥ" },
      { type: "verse", number: "3", sanskrit: "प्रायशः सन्निपातेन पञ्चस्युर्विषमज्वराः सन्ततः सततश्चैव अन्येद्युष्कस्तृतीयकः", text: "prāyaśaḥ sannipātena pañcasyurviṣamajvarāḥ santataḥ satataścaiva anyedyuṣkastṛtīyakaḥ" },
      { type: "verse", number: "4", sanskrit: "चातुर्थिकश्च पञ्च्ते कीर्त्तिता विषमज्वराः तथाऽगन्तुज्वरोऽप्येकस्त्रयोदशविधो मतः", text: "cāturthikaśca pañcte kīrttitā viṣamajvarāḥ tathā'gantujvaro'pyekastrayodaśavidho mataḥ" },
      { type: "verse", number: "5", sanskrit: "श्रमाच्छेदात्क्षताद्दाहाच्चतुर्द्धाघातजो ज्वरः", text: "śramācchedātkṣatāddāhāccaturddhāghātajo jvaraḥ" },
      { type: "verse", number: "6", sanskrit: "कामाद्भीतेः शुचो रोषाद्विषादौषधगन्धतः अभिषङ्गज्वराः षट्स्युरेवं ज्वरविनिश्चयः", text: "kāmādbhīteḥ śuco roṣādviṣādauṣadhagandhataḥ abhiṣaṅgajvarāḥ ṣaṭsyurevaṃ jvaraviniścayaḥ" },
      { type: "verse", number: "7", sanskrit: "अतीसारग्रहणीप्रवाहिकाणां भेदाः पृथक्त्रिदोषैः सर्वैश्च शोकादामाद्भयादपि अतीसारः सप्तधा स्याद् ग्रहणी पञ्चधा मता", text: "atīsāragrahaṇīpravāhikāṇāṃ bhedāḥ pṛthaktridoṣaiḥ sarvaiśca śokādāmādbhayādapi atīsāraḥ saptadhā syād grahaṇī pañcadhā matā" },
      { type: "verse", number: "8", sanskrit: "पृथग्दोषैः सन्निपातात्तथा चामेन पञ्चमी प्रवाहिका चतुर्द्धा स्यात्पृथग्दोषैस्तथाऽस्रतः", text: "pṛthagdoṣaiḥ sannipātāttathā cāmena pañcamī pravāhikā caturddhā syātpṛthagdoṣaistathā'srataḥ" },
      { type: "verse", number: "9", sanskrit: "अजीर्णं त्रिविधं प्रोक्तं विष्टब्धं वायुना मतम्", text: "ajīrṇaṃ trividhaṃ proktaṃ viṣṭabdhaṃ vāyunā matam" },
      { type: "verse", number: "10", sanskrit: "पित्ताद्विदग्धं विज्ञेयं कफेनामं तदुच्यते विषाजीर्णं रसादेकं दोषैः स्यादलसस्त्रिधा", text: "pittādvidagdhaṃ vijñeyaṃ kaphenāmaṃ taducyate viṣājīrṇaṃ rasādekaṃ doṣaiḥ syādalasastridhā" },
      { type: "verse", number: "11", sanskrit: "विषूचीदण्डकालसकविलम्बिकानां भेदाः विषूची त्रिविधा प्रोक्ता दोषैः सा स्यात्पृथक्पृथक् दण्डकालसकश्चैव एकैव स्याद्विलम्बिका", text: "viṣūcīdaṇḍakālasakavilambikānāṃ bhedāḥ viṣūcī trividhā proktā doṣaiḥ sā syātpṛthakpṛthak daṇḍakālasakaścaiva ekaiva syādvilambikā" },
      { type: "verse", number: "12", sanskrit: "अर्शांसि षड्विधान्याहुर्वातपित्तकफास्रतः सन्निपाताच्च संसर्गात्तेषां भेदो द्विधा स्मृतः", text: "arśāṃsi ṣaḍvidhānyāhurvātapittakaphāsrataḥ sannipātācca saṃsargātteṣāṃ bhedo dvidhā smṛtaḥ" },
      { type: "verse", number: "13", sanskrit: "सहजोत्तरजन्मभ्यां तथा शुष्कार्द्र भेदतः त्रिधैव चर्मकीलानि वातात्पित्तात्कफादपि", text: "sahajottarajanmabhyāṃ tathā śuṣkārdra bhedataḥ tridhaiva carmakīlāni vātātpittātkaphādapi" },
      { type: "verse", number: "14", sanskrit: "एकविंशतिभेदेन कृमयः स्युर्द्विधा च ते बाह्यास्तथाऽभ्यन्तराः स्युस्तेषु यूका बहिश्चराः", text: "ekaviṃśatibhedena kṛmayaḥ syurdvidhā ca te bāhyāstathā'bhyantarāḥ syusteṣu yūkā bahiścarāḥ" },
      { type: "verse", number: "15", sanskrit: "लिक्षाश्चान्येऽन्तरचराः कफात्ते हृदयादकाः अन्त्रादा उदरावेष्टाश्चुरवश्च महागुदाः", text: "likṣāścānye'ntaracarāḥ kaphātte hṛdayādakāḥ antrādā udarāveṣṭāścuravaśca mahāgudāḥ" },
      { type: "verse", number: "16", sanskrit: "सुगन्धा दर्भकुसुमास्तथा रक्ताच्च मातरः सौरसा लोमविध्वंसा रोमद्वीपा उदुम्बराः", text: "sugandhā darbhakusumāstathā raktācca mātaraḥ saurasā lomavidhvaṃsā romadvīpā udumbarāḥ" },
      { type: "verse", number: "17", sanskrit: "केशादाश्च तथैवान्ये शकृज्जाता मकेरुकाः लेलिहाश्च सशूलाश्च सौसुरादाः ककेरुकाः", text: "keśādāśca tathaivānye śakṛjjātā makerukāḥ lelihāśca saśūlāśca sausurādāḥ kakerukāḥ" },
      { type: "verse", number: "18", sanskrit: "तथाऽन्य कफरक्ताभ्यां संजातः स्नायुकः स्मृतः व्रणस्य कृमयश्चान्ये विषमा बाह्ययोनयः", text: "tathā'nya kapharaktābhyāṃ saṃjātaḥ snāyukaḥ smṛtaḥ vraṇasya kṛmayaścānye viṣamā bāhyayonayaḥ" },
      { type: "verse", number: "19", sanskrit: "पाण्डुरोगाश्च पञ्च स्युर्वातपित्तकफैस्त्रिधा त्रिदोषैर्मृत्तिकाभिश्च तथैका कामला स्मृता स्यात्कुम्भकामला चैका तथैकं च हलीमकम्", text: "pāṇḍurogāśca pañca syurvātapittakaphaistridhā tridoṣairmṛttikābhiśca tathaikā kāmalā smṛtā syātkumbhakāmalā caikā tathaikaṃ ca halīmakam" },
      { type: "verse", number: "20", sanskrit: "रक्तपित्तं त्रिधा प्रोक्तमूर्ध्वगं कफसंभवम् अधोगं मारुतं ज्ञेयं तद्द्वयेन द्विमार्गगम्", text: "raktapittaṃ tridhā proktamūrdhvagaṃ kaphasaṃbhavam adhogaṃ mārutaṃ jñeyaṃ taddvayena dvimārgagam" },
      { type: "verse", number: "21", sanskrit: "कासाः पञ्च समुद्दिष्टास्ते त्रयः स्युस्त्रिभिर्मलैः उरः क्षताच्चतुर्थः स्यात्क्षयाद्धातोश्च पञ्चमः", text: "kāsāḥ pañca samuddiṣṭāste trayaḥ syustribhirmalaiḥ uraḥ kṣatāccaturthaḥ syātkṣayāddhātośca pañcamaḥ" },
      { type: "verse", number: "22", sanskrit: "क्षयाः पञ्चैव विज्ञेयास्त्रिभिर्दोषैस्त्रयश्च ते चतुर्थः सन्निपातेन पञ्चमः स्यादुरःक्षतात्", text: "kṣayāḥ pañcaiva vijñeyāstribhirdoṣaistrayaśca te caturthaḥ sannipātena pañcamaḥ syāduraḥkṣatāt" },
      { type: "verse", number: "23", sanskrit: "शोषाः स्युः षट्प्रकारेण स्त्रीप्रसङ्गाच्छुचो व्रणात् अध्वश्रमाच्च व्यायामाद् बार्धक्यादपि जायते", text: "śoṣāḥ syuḥ ṣaṭprakāreṇa strīprasaṅgācchuco vraṇāt adhvaśramācca vyāyāmād bārdhakyādapi jāyate" },
      { type: "verse", number: "24", sanskrit: "श्वासाश्च पञ्च विज्ञेयाः क्षुद्र ः! स्यात्तमकस्तथा ऊर्ध्वश्वासो महाश्वासच्छिन्नश्वासश्च पञ्चमः", text: "śvāsāśca pañca vijñeyāḥ kṣudra ḥ! syāttamakastathā ūrdhvaśvāso mahāśvāsacchinnaśvāsaśca pañcamaḥ" },
      { type: "verse", number: "25", sanskrit: "कथिताः पञ्च हिक्कास्तु तास्तु क्षुद्रा ऽन्नजा तथा गम्भीरा यमला चैव महती पञ्चमी तथा", text: "kathitāḥ pañca hikkāstu tāstu kṣudrā 'nnajā tathā gambhīrā yamalā caiva mahatī pañcamī tathā" },
      { type: "verse", number: "26", sanskrit: "चत्वारोऽग्नेर्विकाराः स्युर्विषमो वातसम्भवः तीक्ष्णः पित्तात्कफान्मन्दो भस्मको वातपित्तयोः", text: "catvāro'gnervikārāḥ syurviṣamo vātasambhavaḥ tīkṣṇaḥ pittātkaphānmando bhasmako vātapittayoḥ" },
      { type: "verse", number: "27", sanskrit: "पञ्चैवारोचका ज्ञेया वातपित्तकफैस्त्रिधा सन्निपातान्मनस्तापात् छर्दिभेदाः छर्दयः सप्तधा मताः", text: "pañcaivārocakā jñeyā vātapittakaphaistridhā sannipātānmanastāpāt chardibhedāḥ chardayaḥ saptadhā matāḥ" },
      { type: "verse", number: "28", sanskrit: "त्रिभिर्दोषैः पृथक्तिस्रः कृमिभिः सन्निपातजः घृणया च तथा स्त्रीणां गर्भाधानाच्च जायते", text: "tribhirdoṣaiḥ pṛthaktisraḥ kṛmibhiḥ sannipātajaḥ ghṛṇayā ca tathā strīṇāṃ garbhādhānācca jāyate" },
      { type: "verse", number: "29", sanskrit: "स्वरभेदाः षडेव स्युर्वातपित्तकफैस्त्रयः मेदसा सन्निपातेन क्षयात्षष्ठः प्रकीर्तितः", text: "svarabhedāḥ ṣaḍeva syurvātapittakaphaistrayaḥ medasā sannipātena kṣayātṣaṣṭhaḥ prakīrtitaḥ" },
      { type: "verse", number: "30", sanskrit: "तृष्णा च षड्विधा प्रोक्तावातात्पित्तात्कफादपि त्रिदोषैरुपसर्गेण क्षयाद्धातोश्च षष्ठिका", text: "tṛṣṇā ca ṣaḍvidhā proktāvātātpittātkaphādapi tridoṣairupasargeṇa kṣayāddhātośca ṣaṣṭhikā" },
      { type: "verse", number: "31", sanskrit: "मूर्च्छाभ्रमनिद्रा तन्द्रा संन्यासग्लानि भेदाः मूर्च्छा चतुर्विधा ज्ञेयाः वातपित्तकफैः पृथक्", text: "mūrcchābhramanidrā tandrā saṃnyāsaglāni bhedāḥ mūrcchā caturvidhā jñeyāḥ vātapittakaphaiḥ pṛthak" },
      { type: "verse", number: "32", sanskrit: "चतुर्थी सन्निपातेन तथैकश्च भ्रमः स्मृतः निद्रा  तन्द्रा  च संन्यासो ग्लानिश्चैकैकशः स्मृताः", text: "caturthī sannipātena tathaikaśca bhramaḥ smṛtaḥ nidrā  tandrā  ca saṃnyāso glāniścaikaikaśaḥ smṛtāḥ" },
      { type: "verse", number: "33", sanskrit: "मदाः सप्त समाख्याता वातपित्तकफैस्त्रयः त्रिदोषैरसृजा मद्याद्विषादपि स सप्तमः", text: "madāḥ sapta samākhyātā vātapittakaphaistrayaḥ tridoṣairasṛjā madyādviṣādapi sa saptamaḥ" },
      { type: "verse", number: "34", sanskrit: "मदात्ययश्चतुर्द्धा स्याद्वातपित्तकफादपि त्रिदोषैरपि विज्ञेय एकः परमदस्तथा", text: "madātyayaścaturddhā syādvātapittakaphādapi tridoṣairapi vijñeya ekaḥ paramadastathā" },
      { type: "verse", number: "35", sanskrit: "पानाजीर्णं तथा चैकं तथैकः पानविभ्रमः पानात्ययस्तथा चैकः दाहभेदाः दाहाः सप्त मतास्तथा", text: "pānājīrṇaṃ tathā caikaṃ tathaikaḥ pānavibhramaḥ pānātyayastathā caikaḥ dāhabhedāḥ dāhāḥ sapta matāstathā" },
      { type: "verse", number: "36", sanskrit: "रक्तपित्तात्तथा रक्तात्तृष्णायाः पित्ततस्तथा धातुक्षयान्मर्मघाताद्र क्तपूर्णोदरादपि", text: "raktapittāttathā raktāttṛṣṇāyāḥ pittatastathā dhātukṣayānmarmaghātādra ktapūrṇodarādapi" },
      { type: "verse", number: "37", sanskrit: "उन्मादाः षट् समाख्यातास्त्रिभिर्दोषैस्त्रयश्च ते सन्निपाताद्विषाज्ज्ञेयः षष्ठो दुःखेन चेतसः", text: "unmādāḥ ṣaṭ samākhyātāstribhirdoṣaistrayaśca te sannipātādviṣājjñeyaḥ ṣaṣṭho duḥkhena cetasaḥ" },
      { type: "verse", number: "38", sanskrit: "भूतोन्मादा विंशतिः स्युस्ते देवाद्दानवादपि गन्धर्वात्किन्नराद्यक्षात्पितृभ्यो गुरुशापतः", text: "bhūtonmādā viṃśatiḥ syuste devāddānavādapi gandharvātkinnarādyakṣātpitṛbhyo guruśāpataḥ" },
      { type: "verse", number: "39", sanskrit: "प्रेताच्च गुह्यकाद् वृद्धात्सिद्धाद्भूतात्पिशाचतः जलाधिदेवतायाश्च नागाच्च ब्रह्मराक्षसात् राक्षसादपि कूष्माण्डात्कृत्या वेतालयोरपि", text: "pretācca guhyakād vṛddhātsiddhādbhūtātpiśācataḥ jalādhidevatāyāśca nāgācca brahmarākṣasāt rākṣasādapi kūṣmāṇḍātkṛtyā vetālayorapi" },
      { type: "verse", number: "40", sanskrit: "अपस्मारश्चतुर्द्धा स्यात्समीरात्पित्ततस्तथा श्लेष्मणोऽपि तृतीयः स्याच्चतुर्थः सन्निपाततः", text: "apasmāraścaturddhā syātsamīrātpittatastathā śleṣmaṇo'pi tṛtīyaḥ syāccaturthaḥ sannipātataḥ" },
      { type: "verse", number: "41", sanskrit: "चत्वारश्चामवाताः स्युर्वातपित्तकफैस्त्रिधा चतुर्थः सन्निपातेन शूलभेदाः शूलान्यष्टौ बुधा जगुः", text: "catvāraścāmavātāḥ syurvātapittakaphaistridhā caturthaḥ sannipātena śūlabhedāḥ śūlānyaṣṭau budhā jaguḥ" },
      { type: "verse", number: "42", sanskrit: "पृथगदोषैस्त्रिधा द्वन्द्वभेदेन त्रिविधान्यपि आमेन सप्तमं प्रोक्तं सन्निपातेन चाष्टमम्", text: "pṛthagadoṣaistridhā dvandvabhedena trividhānyapi āmena saptamaṃ proktaṃ sannipātena cāṣṭamam" },
      { type: "verse", number: "43", sanskrit: "परिणामभवं शूलमष्टधा परिकीर्त्तितम् मलैर्या शूलसंख्या स्यात्तैरेव परिणामजम्", text: "pariṇāmabhavaṃ śūlamaṣṭadhā parikīrttitam malairyā śūlasaṃkhyā syāttaireva pariṇāmajam" },
      { type: "verse", number: "44", sanskrit: "अन्नद्र वभवं शूलं जरत्पित्तभवं तथा एकैकं गणितं सुज्ञैः उदावर्त्तभेदाः उदावर्त्तास्त्रयोदश", text: "annadra vabhavaṃ śūlaṃ jaratpittabhavaṃ tathā ekaikaṃ gaṇitaṃ sujñaiḥ udāvarttabhedāḥ udāvarttāstrayodaśa" },
      { type: "verse", number: "45", sanskrit: "एकः क्षुन्निग्रहात्प्रोक्तस्तृष्णारोधाद् द्वितीयकः", text: "ekaḥ kṣunnigrahātproktastṛṣṇārodhād dvitīyakaḥ" },
      { type: "verse", number: "46", sanskrit: "निद्रा घातात्तृतीयः स्याच्चतुर्थः श्वासनिग्रहात् छर्दिरोधात्पञ्चमः स्यात्षष्ठः क्षवथुनिग्रहात्", text: "nidrā ghātāttṛtīyaḥ syāccaturthaḥ śvāsanigrahāt chardirodhātpañcamaḥ syātṣaṣṭhaḥ kṣavathunigrahāt" },
      { type: "verse", number: "47", sanskrit: "जृम्भारोधात्सप्तमः स्यादुद्गारग्रहतोऽष्टमः नवमः स्यादश्रुरोधाद्दशमः शुक्रधारणात्", text: "jṛmbhārodhātsaptamaḥ syādudgāragrahato'ṣṭamaḥ navamaḥ syādaśrurodhāddaśamaḥ śukradhāraṇāt" },
      { type: "verse", number: "48", sanskrit: "मूत्ररोधान्मलस्यापि रोधाद्वातविनिग्रहात् उदावर्त्तास्त्रयश्चैते घोरोपद्र वकारकाः", text: "mūtrarodhānmalasyāpi rodhādvātavinigrahāt udāvarttāstrayaścaite ghoropadra vakārakāḥ" },
      { type: "verse", number: "49", sanskrit: "आनाहोद्विविधो ज्ञेय एकः पक्काशयोद्भवः आमाशयोद्भवश्चान्यः प्रत्यानाहः स कथ्यते", text: "ānāhodvividho jñeya ekaḥ pakkāśayodbhavaḥ āmāśayodbhavaścānyaḥ pratyānāhaḥ sa kathyate" },
      { type: "verse", number: "50", sanskrit: "उरोग्रहस्तथा चैको हृद्रो गाः पञ्च कीर्त्तिताः वातादिभिस्त्रयः प्रोक्ताश्चतुर्थः सन्निपाततः पञ्चमः क्रिमिसञ्जातः उदररोगभेदाः तथाऽष्टावुदराणि च", text: "urograhastathā caiko hṛdro gāḥ pañca kīrttitāḥ vātādibhistrayaḥ proktāścaturthaḥ sannipātataḥ pañcamaḥ krimisañjātaḥ udararogabhedāḥ tathā'ṣṭāvudarāṇi ca" },
      { type: "verse", number: "51", sanskrit: "वातात्पित्तात्कफात्त्रीणि त्रिदोषेभ्यो जलादपि प्लीह्नः क्षताद्बद्धगुदादष्टमं परिकीर्त्तितम्", text: "vātātpittātkaphāttrīṇi tridoṣebhyo jalādapi plīhnaḥ kṣatādbaddhagudādaṣṭamaṃ parikīrttitam" },
      { type: "verse", number: "52", sanskrit: "गुल्मास्त्वष्टौ समाख्याता वातपित्तकफैस्त्रयः", text: "gulmāstvaṣṭau samākhyātā vātapittakaphaistrayaḥ" },
      { type: "verse", number: "53", sanskrit: "द्वन्द्वभेदास्त्रयः प्रोक्ताः सप्तमः सन्निपाततः रक्तादष्टमकः ख्यातः मूत्राघातभेदाः मूत्राघातास्त्रयोदश", text: "dvandvabhedāstrayaḥ proktāḥ saptamaḥ sannipātataḥ raktādaṣṭamakaḥ khyātaḥ mūtrāghātabhedāḥ mūtrāghātāstrayodaśa" },
      { type: "verse", number: "54", sanskrit: "वातकुण्डलिका पूर्वा वाताष्ठीला ततः परा वातबस्तिस्तृतीयः स्यान्मूत्रातीतश्चतुर्थकः", text: "vātakuṇḍalikā pūrvā vātāṣṭhīlā tataḥ parā vātabastistṛtīyaḥ syānmūtrātītaścaturthakaḥ" },
      { type: "verse", number: "55", sanskrit: "पञ्चमं मूत्रजठरं षष्ठो मूत्रक्षयः स्मृतः मूत्रोत्सर्गः सप्तमः स्यान्मूत्रग्रन्थिस्तथाऽष्टमः", text: "pañcamaṃ mūtrajaṭharaṃ ṣaṣṭho mūtrakṣayaḥ smṛtaḥ mūtrotsargaḥ saptamaḥ syānmūtragranthistathā'ṣṭamaḥ" },
      { type: "verse", number: "56", sanskrit: "मूत्रशुक्रंतु नवमं विड्घातो दशमः स्मृतः मूत्रसादश्चोष्णवातोबस्तिकुण्डलिका तथा त्रयोऽप्येते मूत्रघाताः पृथग्घोराः प्रकीर्त्तिताः", text: "mūtraśukraṃtu navamaṃ viḍghāto daśamaḥ smṛtaḥ mūtrasādaścoṣṇavātobastikuṇḍalikā tathā trayo'pyete mūtraghātāḥ pṛthagghorāḥ prakīrttitāḥ" },
      { type: "verse", number: "57", sanskrit: "मूत्रकृच्छ्राणि चाष्टौ स्युर्वातपित्तकफैस्त्रिधा", text: "mūtrakṛcchrāṇi cāṣṭau syurvātapittakaphaistridhā" },
      { type: "verse", number: "58", sanskrit: "सन्निपाताचतुर्थं स्याच्छुक्रकृच्छ्रं च पञ्चमं विट्कृच्छ्रं षष्ठमाख्यातं घातकृच्छ्रं च सप्तमम् अष्टमं चाश्मरीकृच्छ्रं अश्मरीभेदाः चतुर्द्धा चाश्मरी मता", text: "sannipātācaturthaṃ syācchukrakṛcchraṃ ca pañcamaṃ viṭkṛcchraṃ ṣaṣṭhamākhyātaṃ ghātakṛcchraṃ ca saptamam aṣṭamaṃ cāśmarīkṛcchraṃ aśmarībhedāḥ caturddhā cāśmarī matā" },
      { type: "verse", number: "59", sanskrit: "वातात्पित्तात्कफाच्छुक्रात् तथा मेहाश्च विंशतिः", text: "vātātpittātkaphācchukrāt tathā mehāśca viṃśatiḥ" },
      { type: "verse", number: "60", sanskrit: "इक्षुमेहः सुरामेहः पिष्टमेहश्च सान्द्र कः शुक्रमेहोदकाख्यौ च लालामेहश्च शीतकः सिकताख्यः शनैर्मेहो दशैते कफसम्भवाः", text: "ikṣumehaḥ surāmehaḥ piṣṭamehaśca sāndra kaḥ śukramehodakākhyau ca lālāmehaśca śītakaḥ sikatākhyaḥ śanairmeho daśaite kaphasambhavāḥ" },
      { type: "verse", number: "61", sanskrit: "मञ्जिष्ठाख्यो हरिद्रा ख्यो नीलमेहश्च रक्तकः कृष्णमेहः क्षारमेहः षडेते पित्तसम्भवाः", text: "mañjiṣṭhākhyo haridrā khyo nīlamehaśca raktakaḥ kṛṣṇamehaḥ kṣāramehaḥ ṣaḍete pittasambhavāḥ" },
      { type: "verse", number: "62", sanskrit: "हस्तिमेहो वसामेहो मज्जामेहो मधुप्रभः चत्वारो वातजा मेहा इति मेहाश्च विंशतिः", text: "hastimeho vasāmeho majjāmeho madhuprabhaḥ catvāro vātajā mehā iti mehāśca viṃśatiḥ" },
      { type: "verse", number: "63", sanskrit: "सोमरोगस्तथा चैकः प्रमेहपिटिका दश शराविका कच्छपिका पुत्रिणी विनताऽलजी", text: "somarogastathā caikaḥ pramehapiṭikā daśa śarāvikā kacchapikā putriṇī vinatā'lajī" },
      { type: "verse", number: "64", sanskrit: "मसूरिका सर्षपिका जालिनी च विदारिका विद्र धिश्च दशैताः स्युः पिटिका मेहसम्भवाः", text: "masūrikā sarṣapikā jālinī ca vidārikā vidra dhiśca daśaitāḥ syuḥ piṭikā mehasambhavāḥ" },
      { type: "verse", number: "65", sanskrit: "मेदो दोषस्तथा चैकः शोथ रोगा नव स्मृताः दोषैः पृथग्द्वयैः सर्वैरभिघाताद्विषादपि", text: "medo doṣastathā caikaḥ śotha rogā nava smṛtāḥ doṣaiḥ pṛthagdvayaiḥ sarvairabhighātādviṣādapi" },
      { type: "verse", number: "66", sanskrit: "वृद्धयः सप्त गदिता वातात्पित्तात्कफेन च रक्तेन मेदसा मूत्रादन्त्रवृद्धिश्च सप्तमी", text: "vṛddhayaḥ sapta gaditā vātātpittātkaphena ca raktena medasā mūtrādantravṛddhiśca saptamī" },
      { type: "verse", number: "67", sanskrit: "अण्डवृद्धि गण्डमालिका गण्डालजीरोगाः अण्डवृद्धिस्तथा चैका तथैका गण्डमालिका गण्डालजीति चैका स्याद् ग्रन्थिभेदाः ग्रन्थयो नवधा मताः", text: "aṇḍavṛddhi gaṇḍamālikā gaṇḍālajīrogāḥ aṇḍavṛddhistathā caikā tathaikā gaṇḍamālikā gaṇḍālajīti caikā syād granthibhedāḥ granthayo navadhā matāḥ" },
      { type: "verse", number: "68", sanskrit: "त्रिभिर्दोषैस्त्रयो रक्ताच्छिराभिर्मेदसो व्रणात् अस्थ्ना मांसेन नवमः अर्बुदभेदाः षड्विधं स्यात्तथाऽबुदम्", text: "tribhirdoṣaistrayo raktācchirābhirmedaso vraṇāt asthnā māṃsena navamaḥ arbudabhedāḥ ṣaḍvidhaṃ syāttathā'budam" },
      { type: "verse", number: "69", sanskrit: "वातात्पित्तात्कफाद्र क्तान्मांसादपि च मेदसः", text: "vātātpittātkaphādra ktānmāṃsādapi ca medasaḥ" },
      { type: "verse", number: "70", sanskrit: "श्लीपदं च त्रिधा प्रोक्तं वातात्पित्तात्कफादपि", text: "ślīpadaṃ ca tridhā proktaṃ vātātpittātkaphādapi" },
      { type: "verse", number: "71", sanskrit: "विद्र धिः षड्विधः ख्यातो वातपित्तकफैस्त्रयः रक्तात् क्षतात् त्रिदोषैश्च व्रणभेदाः व्रणाः पञ्चदशोदिताः", text: "vidra dhiḥ ṣaḍvidhaḥ khyāto vātapittakaphaistrayaḥ raktāt kṣatāt tridoṣaiśca vraṇabhedāḥ vraṇāḥ pañcadaśoditāḥ" },
      { type: "verse", number: "72", sanskrit: "तेषां चतुर्द्धा भेदाः स्युरागन्तुर्देहजस्तथा शुद्धो दुष्टश्च विज्ञेयस्तत्संख्या कथ्यते पृथक् वातव्रणः पित्तजश्च कफजो रक्तजो व्रणः", text: "teṣāṃ caturddhā bhedāḥ syurāganturdehajastathā śuddho duṣṭaśca vijñeyastatsaṃkhyā kathyate pṛthak vātavraṇaḥ pittajaśca kaphajo raktajo vraṇaḥ" },
      { type: "verse", number: "73", sanskrit: "वातपित्तभवश्चान्यो वातश्लेष्मभवस्तथा तथा पित्तकफाभ्यां च सन्निपातेन चाष्टमः", text: "vātapittabhavaścānyo vātaśleṣmabhavastathā tathā pittakaphābhyāṃ ca sannipātena cāṣṭamaḥ" },
      { type: "verse", number: "74", sanskrit: "नवमो वातरक्तेन दशमो रक्तपित्ततः श्लेष्मरक्तभवश्चान्यो वातपित्तासृगुद्भवः", text: "navamo vātaraktena daśamo raktapittataḥ śleṣmaraktabhavaścānyo vātapittāsṛgudbhavaḥ" },
      { type: "verse", number: "75", sanskrit: "वातश्लेष्मासृगुत्पन्नः पित्तश्लेष्मास्रसंभवः सन्निपातासृगुद्भूत इति पञ्चदश व्रणाः", text: "vātaśleṣmāsṛgutpannaḥ pittaśleṣmāsrasaṃbhavaḥ sannipātāsṛgudbhūta iti pañcadaśa vraṇāḥ" },
      { type: "verse", number: "76", sanskrit: "सद्योव्रणस्त्वष्टधा स्यादविकॢप्तविलम्बितौ छिन्नभिन्नप्रचलिता घृष्टविद्धनिपातिताः", text: "sadyovraṇastvaṣṭadhā syādavikḷptavilambitau chinnabhinnapracalitā ghṛṣṭaviddhanipātitāḥ" },
      { type: "verse", number: "77", sanskrit: "कोष्ठभेदो द्विधा प्रोक्तश्छिन्नान्त्रो निःसृतान्त्रकः", text: "koṣṭhabhedo dvidhā proktaśchinnāntro niḥsṛtāntrakaḥ" },
      { type: "verse", number: "78", sanskrit: "अस्थिभङ्गोऽष्टधा प्रोक्तो भग्नपृष्ठविदारितौ विवर्त्तितश्च विश्लिष्टस्तिर्यक्क्षिप्तस्त्वधोगतः ऊर्ध्वगः संधिभग्नश्च वह्निदग्धभेदाः वह्निदग्धश्चतुर्विधः", text: "asthibhaṅgo'ṣṭadhā prokto bhagnapṛṣṭhavidāritau vivarttitaśca viśliṣṭastiryakkṣiptastvadhogataḥ ūrdhvagaḥ saṃdhibhagnaśca vahnidagdhabhedāḥ vahnidagdhaścaturvidhaḥ" },
      { type: "verse", number: "79", sanskrit: "प्लुष्टो विदग्धो दुर्दग्धः सम्यग्दग्धः प्रकीर्त्तितः", text: "pluṣṭo vidagdho durdagdhaḥ samyagdagdhaḥ prakīrttitaḥ" },
      { type: "verse", number: "80", sanskrit: "नाड्यः पञ्च समाख्याता वातपित्तकफैस्त्रिधा त्रिदोषैरपि शल्येन भगन्दरभेदाः तथाऽष्टौ स्युर्भगन्दराः", text: "nāḍyaḥ pañca samākhyātā vātapittakaphaistridhā tridoṣairapi śalyena bhagandarabhedāḥ tathā'ṣṭau syurbhagandarāḥ" },
      { type: "verse", number: "81", sanskrit: "शतपोनस्तु पवनादुष्ट्रग्रीवश्च पित्ततः परिस्रावो कफाज्ज्ञेय ऋजुर्वातकफोद्भवः", text: "śataponastu pavanāduṣṭragrīvaśca pittataḥ parisrāvo kaphājjñeya ṛjurvātakaphodbhavaḥ" },
      { type: "verse", number: "82", sanskrit: "परिक्षेपी मरुत्पित्तादर्शोजः कफपित्ततः आगन्तुजातश्चोन्मार्गी शङ्खावर्तस्त्रिदोषजः", text: "parikṣepī marutpittādarśojaḥ kaphapittataḥ āgantujātaśconmārgī śaṅkhāvartastridoṣajaḥ" },
      { type: "verse", number: "83", sanskrit: "मेढ्रे पञ्चोपदंशाः स्युर्वातपित्तकफैस्त्रिधा सन्निपातेन रक्ताच्च शूकामयभेदाः मेढ्रे शूकामयास्तथा चतुर्विंशतिराख्याता लिङ्गार्शो ग्रथितं तथा", text: "meḍhre pañcopadaṃśāḥ syurvātapittakaphaistridhā sannipātena raktācca śūkāmayabhedāḥ meḍhre śūkāmayāstathā caturviṃśatirākhyātā liṅgārśo grathitaṃ tathā" },
      { type: "verse", number: "84", sanskrit: "निवृत्तमवमन्थश्च मृदितं शतपोनकः अष्ठीलिका सर्षपिका त्वक्पाकश्चावपाटिका", text: "nivṛttamavamanthaśca mṛditaṃ śataponakaḥ aṣṭhīlikā sarṣapikā tvakpākaścāvapāṭikā" },
      { type: "verse", number: "85", sanskrit: "मांसपाकः स्पर्शहानिर्निरुद्धमणिरुत्तमा मांसार्बुदं पुष्करिका संमूढपिडिकाऽलजी", text: "māṃsapākaḥ sparśahānirniruddhamaṇiruttamā māṃsārbudaṃ puṣkarikā saṃmūḍhapiḍikā'lajī" },
      { type: "verse", number: "86", sanskrit: "रक्तार्बुदं विद्र धिश्च कुम्भिकातिलकालकः निरुद्धप्रकशः प्रोक्तस्तथैव परिवर्त्तिका", text: "raktārbudaṃ vidra dhiśca kumbhikātilakālakaḥ niruddhaprakaśaḥ proktastathaiva parivarttikā" },
      { type: "verse", number: "87", sanskrit: "कुष्ठान्यष्टादशोक्तानि वातात् कापालिकं भवेत् पित्तेनोदुम्बरं प्रोक्तं कफान्मण्डलचर्चिके", text: "kuṣṭhānyaṣṭādaśoktāni vātāt kāpālikaṃ bhavet pittenodumbaraṃ proktaṃ kaphānmaṇḍalacarcike" },
      { type: "verse", number: "88", sanskrit: "मरुत्पित्तादृष्यजिह्वं श्लेष्मवाताद्विपादिका तथा सिध्मैककुष्ठं च किटिभं चालसं तथा", text: "marutpittādṛṣyajihvaṃ śleṣmavātādvipādikā tathā sidhmaikakuṣṭhaṃ ca kiṭibhaṃ cālasaṃ tathā" },
      { type: "verse", number: "89", sanskrit: "कफपित्तात् पुनर्दद्रुः पामा विस्फोटकं तथा महाकुष्ठं चर्मदलं पुण्डरीकं शतारुकम्", text: "kaphapittāt punardadruḥ pāmā visphoṭakaṃ tathā mahākuṣṭhaṃ carmadalaṃ puṇḍarīkaṃ śatārukam" },
      { type: "verse", number: "90", sanskrit: "त्रिदोषैः काकणं ज्ञेयं तथाऽन्यच्छिवत्रसंज्ञितम् तथा वातेन पित्तेन श्लेष्मणा च त्रिधा भवेत्", text: "tridoṣaiḥ kākaṇaṃ jñeyaṃ tathā'nyacchivatrasaṃjñitam tathā vātena pittena śleṣmaṇā ca tridhā bhavet" },
      { type: "verse", number: "91", sanskrit: "क्षुद्र रोगाः षष्टिसंख्यास्तेष्वादौ शर्करार्बुदम् इन्द्र वृद्धा पनसिका विवृताऽन्धालजी तथा", text: "kṣudra rogāḥ ṣaṣṭisaṃkhyāsteṣvādau śarkarārbudam indra vṛddhā panasikā vivṛtā'ndhālajī tathā" },
      { type: "verse", number: "92", sanskrit: "वराहदंष्ट्रो वल्मीकं कच्छपी तिलकालकः गर्दभी रकसा चैव यवप्रख्या विदारिका", text: "varāhadaṃṣṭro valmīkaṃ kacchapī tilakālakaḥ gardabhī rakasā caiva yavaprakhyā vidārikā" },
      { type: "verse", number: "93", sanskrit: "कदरं मषकश्चैव नीलिका जालगर्दभः इरिवेल्ली जतुमणिर्गुदभ्रंशोऽग्निरोहिणी", text: "kadaraṃ maṣakaścaiva nīlikā jālagardabhaḥ irivellī jatumaṇirgudabhraṃśo'gnirohiṇī" },
      { type: "verse", number: "94", sanskrit: "सन्निरुद्धगुदः कोठः कुनखोऽनुशयी तथा पद्मिनीकण्टकश्चिप्पमलसो मुखदूषिका", text: "sanniruddhagudaḥ koṭhaḥ kunakho'nuśayī tathā padminīkaṇṭakaścippamalaso mukhadūṣikā" },
      { type: "verse", number: "95", sanskrit: "कक्षावृषणकच्छूश्च गन्धः पाषाणगर्दभः राजिका च तथा व्यङ्गश्चतुर्द्धा परिकीर्त्तितः", text: "kakṣāvṛṣaṇakacchūśca gandhaḥ pāṣāṇagardabhaḥ rājikā ca tathā vyaṅgaścaturddhā parikīrttitaḥ" },
      { type: "verse", number: "96", sanskrit: "वातात्पित्तात्कफाद्र क्तादित्युक्तं व्यङ्गलक्षणम् विस्फोटाः क्षुद्र रोगेषु तेऽष्टधा परिकीर्त्तिताः", text: "vātātpittātkaphādra ktādityuktaṃ vyaṅgalakṣaṇam visphoṭāḥ kṣudra rogeṣu te'ṣṭadhā parikīrttitāḥ" },
      { type: "verse", number: "97", sanskrit: "पृथग्दोषैस्त्रयो द्वन्द्बैस्त्रिविधः सप्तमोऽसृजः अष्टमः सन्निपातेन क्षुद्र रुक्षु मसूरिका", text: "pṛthagdoṣaistrayo dvandbaistrividhaḥ saptamo'sṛjaḥ aṣṭamaḥ sannipātena kṣudra rukṣu masūrikā" },
      { type: "verse", number: "98", sanskrit: "चतुर्दशप्रकारेण त्रिभिर्दोषैस्त्रिधा च सा द्वन्द्वजा विविधा प्रोक्ता सन्निपातेन सप्तमी", text: "caturdaśaprakāreṇa tribhirdoṣaistridhā ca sā dvandvajā vividhā proktā sannipātena saptamī" },
      { type: "verse", number: "99", sanskrit: "अष्टमी त्वग्गता ज्ञेया नवमी रक्तजा स्मृता दशमी मांससञ्जाता चतस्रोऽन्याश्च दुस्तराः मेदोऽस्थिमज्जाशुक्रस्थाः क्षुद्र रोगा इतीरिताः", text: "aṣṭamī tvaggatā jñeyā navamī raktajā smṛtā daśamī māṃsasañjātā catasro'nyāśca dustarāḥ medo'sthimajjāśukrasthāḥ kṣudra rogā itīritāḥ" },
      { type: "verse", number: "100", sanskrit: "विसर्परोगो नवधा वातपित्तकफैस्त्रिधा", text: "visarparogo navadhā vātapittakaphaistridhā" },
      { type: "verse", number: "101", sanskrit: "त्रिधा स द्वन्द्वभेदेन सन्निपातेन सप्तमः अष्टमो वह्निदाहेन नवमश्चाभिघातजः", text: "tridhā sa dvandvabhedena sannipātena saptamaḥ aṣṭamo vahnidāhena navamaścābhighātajaḥ" },
      { type: "verse", number: "102", sanskrit: "तथैकः श्लेष्मपित्ताभ्यामुदर्दः परिकीर्त्तितः वातपित्तेन चैकस्तु शीतपित्तामयः स्मृतः", text: "tathaikaḥ śleṣmapittābhyāmudardaḥ parikīrttitaḥ vātapittena caikastu śītapittāmayaḥ smṛtaḥ" },
      { type: "verse", number: "103", sanskrit: "अम्लपित्तं त्रिधा प्रोक्तं वातेन श्लेष्मणा तथा तृतीयं श्लेष्मवाताभ्याम् वातरक्तभेदाः वातरक्तं तथाऽष्टधा", text: "amlapittaṃ tridhā proktaṃ vātena śleṣmaṇā tathā tṛtīyaṃ śleṣmavātābhyām vātaraktabhedāḥ vātaraktaṃ tathā'ṣṭadhā" },
      { type: "verse", number: "104", sanskrit: "वाताधिक्येन पित्ताच्च कफाद्दोषत्रयेण च रक्ताधिक्येन दोषाणां द्वन्द्वेन त्रिविधः स्मृतः", text: "vātādhikyena pittācca kaphāddoṣatrayeṇa ca raktādhikyena doṣāṇāṃ dvandvena trividhaḥ smṛtaḥ" },
      { type: "verse", number: "105", sanskrit: "अशीतिर्वातजा रोगाः कथ्यन्ते मुनिभाषिताः आक्षेपको हनुस्तम्भ ऊरुस्तम्भः शिरोग्रहः", text: "aśītirvātajā rogāḥ kathyante munibhāṣitāḥ ākṣepako hanustambha ūrustambhaḥ śirograhaḥ" },
      { type: "verse", number: "106", sanskrit: "बाह्यायामोऽन्तरायामः पार्श्वशूलं कटिग्रहः दण्डापतानकः खल्ली जिह्वास्तम्भस्तथाऽदितम्", text: "bāhyāyāmo'ntarāyāmaḥ pārśvaśūlaṃ kaṭigrahaḥ daṇḍāpatānakaḥ khallī jihvāstambhastathā'ditam" },
      { type: "verse", number: "107", sanskrit: "पक्षाघातः क्रोष्टुशीर्षो मन्यास्तम्भश्च पङ्गुता कलायखञ्जता तूनी प्रतितूनी च खञ्जता", text: "pakṣāghātaḥ kroṣṭuśīrṣo manyāstambhaśca paṅgutā kalāyakhañjatā tūnī pratitūnī ca khañjatā" },
      { type: "verse", number: "108", sanskrit: "पादहर्षो गृध्रसी च विश्वाची चापबाहुकः अपतानो व्रणायामो वातकण्टोऽपतन्त्रकः", text: "pādaharṣo gṛdhrasī ca viśvācī cāpabāhukaḥ apatāno vraṇāyāmo vātakaṇṭo'patantrakaḥ" },
      { type: "verse", number: "109", sanskrit: "अङ्गभेदोऽङ्गशोषश्च मिन्मिनत्वं च गद्गदः प्रत्यष्ठीलाऽष्ठीलिका च वामनत्वं च कुब्जता", text: "aṅgabhedo'ṅgaśoṣaśca minminatvaṃ ca gadgadaḥ pratyaṣṭhīlā'ṣṭhīlikā ca vāmanatvaṃ ca kubjatā" },
      { type: "verse", number: "110", sanskrit: "अङ्गपीडाऽङ्गशूलं च संकोचस्तम्भरूक्षताः अङ्गभङ्गोऽङ्गविभ्रंशो विड्ग्रहो बद्धविट्कता", text: "aṅgapīḍā'ṅgaśūlaṃ ca saṃkocastambharūkṣatāḥ aṅgabhaṅgo'ṅgavibhraṃśo viḍgraho baddhaviṭkatā" },
      { type: "verse", number: "111", sanskrit: "मूकत्वमतिजृम्भा स्यादत्युद्गारोऽन्त्रकूजनम् वातप्रवृत्तिः स्फुरणं शिराणां पूरणं तथा", text: "mūkatvamatijṛmbhā syādatyudgāro'ntrakūjanam vātapravṛttiḥ sphuraṇaṃ śirāṇāṃ pūraṇaṃ tathā" },
      { type: "verse", number: "112", sanskrit: "कम्पः कार्श्यं श्यावता च प्रलापः क्षिप्रमूत्रता निद्रा नाशः स्वेदनाशो दुर्बलत्वं बलक्षयः", text: "kampaḥ kārśyaṃ śyāvatā ca pralāpaḥ kṣipramūtratā nidrā nāśaḥ svedanāśo durbalatvaṃ balakṣayaḥ" },
      { type: "verse", number: "113", sanskrit: "अतिप्रवृत्तिः शुक्रस्य कार्श्यं नाशश्च रेतसः अनवस्थितचित्तत्वं काठिन्यं विरसास्यता", text: "atipravṛttiḥ śukrasya kārśyaṃ nāśaśca retasaḥ anavasthitacittatvaṃ kāṭhinyaṃ virasāsyatā" },
      { type: "verse", number: "114", sanskrit: "कषायवक्त्रताऽध्मानं प्रत्याध्मानं च शीतता रोमहर्षश्च भीरुत्वं तोदः कण्डू रसाज्ञता शब्दाज्ञता प्रसुप्तिश्च गन्धाज्ञत्वं दृशः क्षयः", text: "kaṣāyavaktratā'dhmānaṃ pratyādhmānaṃ ca śītatā romaharṣaśca bhīrutvaṃ todaḥ kaṇḍū rasājñatā śabdājñatā prasuptiśca gandhājñatvaṃ dṛśaḥ kṣayaḥ" },
      { type: "verse", number: "115", sanskrit: "अथ पित्तभवा रोगाश्चत्वारिंशदिहोदिताः", text: "atha pittabhavā rogāścatvāriṃśadihoditāḥ" },
      { type: "verse", number: "116", sanskrit: "धूम्रोद्गारो विदाहः स्यादुष्णाङ्गत्वं मतिभ्रमः कान्तिहानिः कण्ठशोषो मुखशोषोऽल्पशुक्रता", text: "dhūmrodgāro vidāhaḥ syāduṣṇāṅgatvaṃ matibhramaḥ kāntihāniḥ kaṇṭhaśoṣo mukhaśoṣo'lpaśukratā" },
      { type: "verse", number: "117", sanskrit: "तिक्तास्यताऽम्लवक्त्रत्वं स्वेदस्रावोऽङ्गपाकता क्लमो हरितवर्णत्वमतृप्तिः पीतगात्रता", text: "tiktāsyatā'mlavaktratvaṃ svedasrāvo'ṅgapākatā klamo haritavarṇatvamatṛptiḥ pītagātratā" },
      { type: "verse", number: "118", sanskrit: "रक्तस्रावोऽङ्गदरणं लोहगन्धास्यता तथा दौर्गन्ध्यं पीतमूत्रत्वमरतिः पीतविट्कता", text: "raktasrāvo'ṅgadaraṇaṃ lohagandhāsyatā tathā daurgandhyaṃ pītamūtratvamaratiḥ pītaviṭkatā" },
      { type: "verse", number: "119", sanskrit: "पीतावलोकनं पीतनेत्रता पीतदन्तता शीतेच्छा पीतनखता तेजोद्वेषोऽल्पनिद्र ता", text: "pītāvalokanaṃ pītanetratā pītadantatā śītecchā pītanakhatā tejodveṣo'lpanidra tā" },
      { type: "verse", number: "120", sanskrit: "कोपश्च गात्रसादश्च भिन्नविट्कत्वमन्धता उष्णोच्छ्वासत्वमुष्णत्वं मूत्रस्य च मलस्य च", text: "kopaśca gātrasādaśca bhinnaviṭkatvamandhatā uṣṇocchvāsatvamuṣṇatvaṃ mūtrasya ca malasya ca" },
      { type: "verse", number: "121", sanskrit: "तमसो दर्शनं पीतमण्डलानां च दर्शनम् निःसहत्वं च पित्तस्य चत्वारिंशद्रुजः स्मृताः", text: "tamaso darśanaṃ pītamaṇḍalānāṃ ca darśanam niḥsahatvaṃ ca pittasya catvāriṃśadrujaḥ smṛtāḥ" },
      { type: "verse", number: "122", sanskrit: "कफस्य विंशतिः प्रोक्ता रोगास्तन्द्रा ऽतिनिद्र ता गौरवं मुखमाधुर्यं मुखलेपः प्रसेकता", text: "kaphasya viṃśatiḥ proktā rogāstandrā 'tinidra tā gauravaṃ mukhamādhuryaṃ mukhalepaḥ prasekatā" },
      { type: "verse", number: "123", sanskrit: "श्वेतावलोकनं श्वेतविट्कत्वं श्वेतमूत्रता श्वेताङ्गवर्णता शैत्यमुष्णेच्छा तिक्तकामिता", text: "śvetāvalokanaṃ śvetaviṭkatvaṃ śvetamūtratā śvetāṅgavarṇatā śaityamuṣṇecchā tiktakāmitā" },
      { type: "verse", number: "124", sanskrit: "मलाधिक्यं च शुक्रस्य बाहुल्यं बहुमूत्रता आलस्यं मन्दबुद्धित्वं तृप्तिर्घर्घरवाक्यता अचैतन्यं च गदिता विंशतिः श्लेष्मजा गदाः", text: "malādhikyaṃ ca śukrasya bāhulyaṃ bahumūtratā ālasyaṃ mandabuddhitvaṃ tṛptirghargharavākyatā acaitanyaṃ ca gaditā viṃśatiḥ śleṣmajā gadāḥ" },
      { type: "verse", number: "125", sanskrit: "रक्तस्य च दश प्रोक्ता व्याधयस्तेषु गौरवम्", text: "raktasya ca daśa proktā vyādhayasteṣu gauravam" },
      { type: "verse", number: "126", sanskrit: "रक्तमण्डलता रक्तनेत्रत्वं रक्तमूत्रता रक्तनिष्ठीवनं रक्तपिटिकानां च दर्शनम् औष्ण्यं च पूतिगन्धित्वं पीडा पाकश्च जायते", text: "raktamaṇḍalatā raktanetratvaṃ raktamūtratā raktaniṣṭhīvanaṃ raktapiṭikānāṃ ca darśanam auṣṇyaṃ ca pūtigandhitvaṃ pīḍā pākaśca jāyate" },
      { type: "verse", number: "127", sanskrit: "चतुःसप्ततिसंख्याका मुखरोगास्तथोदिताः", text: "catuḥsaptatisaṃkhyākā mukharogāstathoditāḥ" },
      { type: "verse", number: "128", sanskrit: "तेष्वोष्ठरोगा गणिता एकादशमिता बुधैः वातपित्तकफैस्त्रेधा त्रिदोषैरसृजा तथा", text: "teṣvoṣṭharogā gaṇitā ekādaśamitā budhaiḥ vātapittakaphaistredhā tridoṣairasṛjā tathā" },
      { type: "verse", number: "129", sanskrit: "क्षतान्मांसार्बुदं चैव खण्डोष्ठं च जलार्बुदम् मेदोऽबुदं चार्बुदं च रोगा एकादशौष्ठजाः", text: "kṣatānmāṃsārbudaṃ caiva khaṇḍoṣṭhaṃ ca jalārbudam medo'budaṃ cārbudaṃ ca rogā ekādaśauṣṭhajāḥ" },
      { type: "verse", number: "130", sanskrit: "दन्तरोगा दशाख्याता दालनः कृमिदन्तकः दन्तहर्षः करालश्च दन्तचालश्च शर्करा अधिदन्तः श्यावदन्तो दन्तभेदः कपालिका", text: "dantarogā daśākhyātā dālanaḥ kṛmidantakaḥ dantaharṣaḥ karālaśca dantacālaśca śarkarā adhidantaḥ śyāvadanto dantabhedaḥ kapālikā" },
      { type: "verse", number: "131", sanskrit: "तथा त्रयोदशमिता दन्तमूलामयाः स्मृताः", text: "tathā trayodaśamitā dantamūlāmayāḥ smṛtāḥ" },
      { type: "verse", number: "132", sanskrit: "शीतादोपकुशौ द्वौ तु दन्तविद्र धिपुप्पुटौ अधिमांसो विदर्भश्च महासौषिरसौषिरौ", text: "śītādopakuśau dvau tu dantavidra dhipuppuṭau adhimāṃso vidarbhaśca mahāsauṣirasauṣirau" },
      { type: "verse", number: "133", sanskrit: "तेष्वेव गतयः पञ्च वातात्पित्तात्कफादपि सन्निपाताद् गतिश्चान्या रक्तनाडी च पञ्चमी", text: "teṣveva gatayaḥ pañca vātātpittātkaphādapi sannipātād gatiścānyā raktanāḍī ca pañcamī" },
      { type: "verse", number: "134", sanskrit: "तथा जिह्वाऽमयाः षट् स्युर्वातपित्तकफैस्त्रिधा अलासश्च चतुर्थः स्यादधिजिह्वश्च पञ्चमः", text: "tathā jihvā'mayāḥ ṣaṭ syurvātapittakaphaistridhā alāsaśca caturthaḥ syādadhijihvaśca pañcamaḥ" },
      { type: "verse", number: "135", sanskrit: "तथाऽष्टौ तालुजा गदाः", text: "tathā'ṣṭau tālujā gadāḥ" },
      { type: "verse", number: "136", sanskrit: "अर्बुदं तालुपिटिका कच्छपी तालुसंहतिः गलशुण्डी तालुशोषस्तालुपाकश्च पुप्पुटः", text: "arbudaṃ tālupiṭikā kacchapī tālusaṃhatiḥ galaśuṇḍī tāluśoṣastālupākaśca puppuṭaḥ" },
      { type: "verse", number: "137", sanskrit: "गलरोगास्तथा ख्याता अष्टादशमिता बुधैः वातरोहिणिका पूर्वं द्वितीया पित्तरोहिणी कफरोहिणिका प्रोक्ता त्रिदोषैरपि रोहिणी", text: "galarogāstathā khyātā aṣṭādaśamitā budhaiḥ vātarohiṇikā pūrvaṃ dvitīyā pittarohiṇī kapharohiṇikā proktā tridoṣairapi rohiṇī" },
      { type: "verse", number: "138", sanskrit: "मेदोरोहिणिका वृन्दो गलौघो गलविद्र धिः स्वरहा तुण्डिकेरी च शतघ्नी शालुकोऽबुदम्", text: "medorohiṇikā vṛndo galaugho galavidra dhiḥ svarahā tuṇḍikerī ca śataghnī śāluko'budam" },
      { type: "verse", number: "139", sanskrit: "गलायुर्वलयश्चापि वाताद् गण्डः कफात्तथा मेदोगण्डस्तथैव स्यादित्यष्टादश कण्ठजाः", text: "galāyurvalayaścāpi vātād gaṇḍaḥ kaphāttathā medogaṇḍastathaiva syādityaṣṭādaśa kaṇṭhajāḥ" },
      { type: "verse", number: "140", sanskrit: "मुखान्तःसम्भवा रोगा अष्टौ ख्याता महर्षिभिः मुखपाको भवेद्वातात्पित्तात्तद्वत्कफादपि", text: "mukhāntaḥsambhavā rogā aṣṭau khyātā maharṣibhiḥ mukhapāko bhavedvātātpittāttadvatkaphādapi" },
      { type: "verse", number: "141", sanskrit: "रक्ताच्च सन्निपाताच्च पूत्यास्योर्ध्वगुदावपि अर्बुदं चेति मुखजाश्चतुः सप्ततिरामयाः", text: "raktācca sannipātācca pūtyāsyordhvagudāvapi arbudaṃ ceti mukhajāścatuḥ saptatirāmayāḥ" },
      { type: "verse", number: "142", sanskrit: "कर्णरोगाः समाख्याता अष्टादशमिता बुधैः वातात्पित्तात्कफाद्र क्तात्सन्निपाताच्च विद्र धिः", text: "karṇarogāḥ samākhyātā aṣṭādaśamitā budhaiḥ vātātpittātkaphādra ktātsannipātācca vidra dhiḥ" },
      { type: "verse", number: "143", sanskrit: "शोथोऽबुदं पूतिकर्णः कर्णार्शः कर्णहल्लिका बाधिर्यं तन्त्रिका कण्डूः शष्कुली कृमिकर्णकः कर्णनादः प्रतीनाह इत्यष्टादश कर्णजाः", text: "śotho'budaṃ pūtikarṇaḥ karṇārśaḥ karṇahallikā bādhiryaṃ tantrikā kaṇḍūḥ śaṣkulī kṛmikarṇakaḥ karṇanādaḥ pratīnāha ityaṣṭādaśa karṇajāḥ" },
      { type: "verse", number: "144", sanskrit: "कर्णपालीसमुद्भूता रोगाः सप्त इहोदिताः", text: "karṇapālīsamudbhūtā rogāḥ sapta ihoditāḥ" },
      { type: "verse", number: "145", sanskrit: "उत्पातः पालिशोषश्च विदारी दुःखवर्द्धनः परिपोटश्च लेही च पिप्पली चेति संस्मृतः", text: "utpātaḥ pāliśoṣaśca vidārī duḥkhavarddhanaḥ paripoṭaśca lehī ca pippalī ceti saṃsmṛtaḥ" },
      { type: "verse", number: "146", sanskrit: "कर्णमूलामयाः पञ्च वातात्पित्तात्कफादपि सन्निपाताच्च रक्ताच्च नासारोगभेदाः तथा नासाभवा गदाः", text: "karṇamūlāmayāḥ pañca vātātpittātkaphādapi sannipātācca raktācca nāsārogabhedāḥ tathā nāsābhavā gadāḥ" },
      { type: "verse", number: "147", sanskrit: "अष्टादशैव संख्याताः प्रतिश्यायस्तु तेष्वपि वातात्पित्तात्कफाद्र क्तात्सन्निपातेन पञ्चमः", text: "aṣṭādaśaiva saṃkhyātāḥ pratiśyāyastu teṣvapi vātātpittātkaphādra ktātsannipātena pañcamaḥ" },
      { type: "verse", number: "148", sanskrit: "अपीनसः पूतिनासो नासाऽशो भ्रंशथुः क्षवः नासाऽनाहः पूतिरक्तमर्बुदं दुष्टपीनसम् नासाशोषो घ्राणपाकः पूयस्रावश्च दीप्तकः", text: "apīnasaḥ pūtināso nāsā'śo bhraṃśathuḥ kṣavaḥ nāsā'nāhaḥ pūtiraktamarbudaṃ duṣṭapīnasam nāsāśoṣo ghrāṇapākaḥ pūyasrāvaśca dīptakaḥ" },
      { type: "verse", number: "149", sanskrit: "तथा दश शिरोरोगा वातेनार्द्धावभेदकः शिरस्तापश्च वातेन पित्तपीडा तृतीयका", text: "tathā daśa śirorogā vātenārddhāvabhedakaḥ śirastāpaśca vātena pittapīḍā tṛtīyakā" },
      { type: "verse", number: "150", sanskrit: "चतुर्थी कफजा पीडा रक्तजा सन्निपातजा सूर्यावर्त्ताच्छिरः कम्पात्क्रिमिभिः शङ्खकेन च", text: "caturthī kaphajā pīḍā raktajā sannipātajā sūryāvarttācchiraḥ kampātkrimibhiḥ śaṅkhakena ca" },
      { type: "verse", number: "152", sanskrit: "तथा कपालरोगाः स्युर्नव तेषूपशीर्षकम् अरुंषिका विद्र धिश्च दारुणं पिटिकाऽबुदम् इन्द्र लुप्तं च खलितं पलितं चेति ते नव", text: "tathā kapālarogāḥ syurnava teṣūpaśīrṣakam aruṃṣikā vidra dhiśca dāruṇaṃ piṭikā'budam indra luptaṃ ca khalitaṃ palitaṃ ceti te nava" },
      { type: "verse", number: "153", sanskrit: "नेत्ररोगभेदास्तत्रादौ वर्त्मरोगभेदाः तथा नेत्रभवाः ख्याताश्चतुर्नवतिरामयाः तेषु वर्त्मगदाः प्रोक्ताश्चतुर्विंशतिसंज्ञकाः", text: "netrarogabhedāstatrādau vartmarogabhedāḥ tathā netrabhavāḥ khyātāścaturnavatirāmayāḥ teṣu vartmagadāḥ proktāścaturviṃśatisaṃjñakāḥ" },
      { type: "verse", number: "154", sanskrit: "कृच्छ्रोन्मीलः पक्ष्मपातः कफोत्क्लिष्टश्च लोहितः अरुङ्निमेषः कथितो रक्तोत्क्लिष्टः कुकूणकः", text: "kṛcchronmīlaḥ pakṣmapātaḥ kaphotkliṣṭaśca lohitaḥ aruṅnimeṣaḥ kathito raktotkliṣṭaḥ kukūṇakaḥ" },
      { type: "verse", number: "155", sanskrit: "पक्ष्मार्शः पक्ष्मरोधश्च पित्तोत्क्लिष्टश्च पोथकी क्लिष्टवर्त्मा च बहलः पक्ष्मोत्सङ्गस्तथाऽबुदम्", text: "pakṣmārśaḥ pakṣmarodhaśca pittotkliṣṭaśca pothakī kliṣṭavartmā ca bahalaḥ pakṣmotsaṅgastathā'budam" },
      { type: "verse", number: "156", sanskrit: "कुम्भिका सिकतावर्त्म लगणोऽञ्जननामिका कर्दमः श्याववर्त्मा च बिसवर्त्मा तथाऽलजी उत्क्लिष्टवर्त्मेति गदाः प्रोक्ता वर्त्मसमुद्भवाः", text: "kumbhikā sikatāvartma lagaṇo'ñjananāmikā kardamaḥ śyāvavartmā ca bisavartmā tathā'lajī utkliṣṭavartmeti gadāḥ proktā vartmasamudbhavāḥ" },
      { type: "verse", number: "157", sanskrit: "नेत्रसन्धिसमुद्भूता नव रोगाः प्रकीर्त्तिताः जलस्रावः कफस्रावो रक्तस्रावश्च पर्वणी", text: "netrasandhisamudbhūtā nava rogāḥ prakīrttitāḥ jalasrāvaḥ kaphasrāvo raktasrāvaśca parvaṇī" },
      { type: "verse", number: "158", sanskrit: "पूयस्रावः क्रिमिग्रन्थिरुपनाहस्तथाऽलजी पूयालस इति प्रोक्ता रोगा नयनसन्धिजाः", text: "pūyasrāvaḥ krimigranthirupanāhastathā'lajī pūyālasa iti proktā rogā nayanasandhijāḥ" },
      { type: "verse", number: "159", sanskrit: "तथा शुक्लगता रोगा बुधैः प्रोक्तास्त्रयोदश", text: "tathā śuklagatā rogā budhaiḥ proktāstrayodaśa" },
      { type: "verse", number: "160", sanskrit: "शिरोत्पातः शिराहर्षः शिराजालं च शुक्तिका शुक्लार्म चाधिमांसार्म प्रस्तार्यर्म च पिष्टकः", text: "śirotpātaḥ śirāharṣaḥ śirājālaṃ ca śuktikā śuklārma cādhimāṃsārma prastāryarma ca piṣṭakaḥ" },
      { type: "verse", number: "161", sanskrit: "शिराजपिटिका चैव कफग्रथितकोऽजुनः स्नाय्वर्म शोणितार्म स्यादिति शुक्लगता गदाः", text: "śirājapiṭikā caiva kaphagrathitako'junaḥ snāyvarma śoṇitārma syāditi śuklagatā gadāḥ" },
      { type: "verse", number: "162", sanskrit: "तथा कृष्णसमुद्भूताः पञ्च रोगाः प्रकीर्तिताः शुद्धशुक्रं शिराशुक्रं क्षतशुक्रं तथाऽजका शिरासङ्गश्च सर्वेऽपि प्रोक्ताः कृष्णगता गदाः", text: "tathā kṛṣṇasamudbhūtāḥ pañca rogāḥ prakīrtitāḥ śuddhaśukraṃ śirāśukraṃ kṣataśukraṃ tathā'jakā śirāsaṅgaśca sarve'pi proktāḥ kṛṣṇagatā gadāḥ" },
      { type: "verse", number: "163", sanskrit: "काचं तु षड्विधं ज्ञेयं वातात्पित्तात्कफादपि सन्निपाताच्च रक्ताच्च षष्ठं संसर्गसम्भवम्", text: "kācaṃ tu ṣaḍvidhaṃ jñeyaṃ vātātpittātkaphādapi sannipātācca raktācca ṣaṣṭhaṃ saṃsargasambhavam" },
      { type: "verse", number: "164", sanskrit: "तिमिराणि षडेव स्युर्वातपित्तकफैस्त्रिधा संसर्गेण च रक्तेन षष्ठं स्यात्सन्निपाततः", text: "timirāṇi ṣaḍeva syurvātapittakaphaistridhā saṃsargeṇa ca raktena ṣaṣṭhaṃ syātsannipātataḥ" },
      { type: "verse", number: "165", sanskrit: "लिङ्गनाशः सप्तधा स्याद्वातात्पित्तात्कफेन च त्रिदोषैरुपसर्गेण संसर्गेणासृजा तथा", text: "liṅganāśaḥ saptadhā syādvātātpittātkaphena ca tridoṣairupasargeṇa saṃsargeṇāsṛjā tathā" },
      { type: "verse", number: "166", sanskrit: "अष्टधा दृष्टिरोगाः स्युस्तेषु पित्तविदग्धकम् अम्लपित्तविदग्धं च तथैवोष्णविदग्धकम्", text: "aṣṭadhā dṛṣṭirogāḥ syusteṣu pittavidagdhakam amlapittavidagdhaṃ ca tathaivoṣṇavidagdhakam" },
      { type: "verse", number: "167", sanskrit: "नकुलान्ध्यं धूसरान्ध्यं रात्र्! यान्ध्यं ह्र्रस्वदृष्टिकः गम्भीरदृष्टिरित्येते रोगा दृष्टिगता मताः", text: "nakulāndhyaṃ dhūsarāndhyaṃ rātr! yāndhyaṃ hrrasvadṛṣṭikaḥ gambhīradṛṣṭirityete rogā dṛṣṭigatā matāḥ" },
      { type: "verse", number: "168", sanskrit: "अभिष्यन्दाश्च चत्वारो रक्ताद्दोषैस्त्रिभिस्तथा", text: "abhiṣyandāśca catvāro raktāddoṣaistribhistathā" },
      { type: "verse", number: "169", sanskrit: "चत्वारश्चाधिमन्थाः स्युर्वातपित्तकफास्रतः", text: "catvāraścādhimanthāḥ syurvātapittakaphāsrataḥ" },
      { type: "verse", number: "170", sanskrit: "सर्वाक्षिरोगाश्चाष्टौ स्युस्तेषु वातविपर्ययः अल्पशोफोऽन्यतोवातस्तथा पाकात्ययः स्मृतः शुष्काक्षिपाकश्च तथा शोफोऽध्युषित एव च हताधिमन्थ इत्येते रोगाः सर्वाक्षिसम्भवाः", text: "sarvākṣirogāścāṣṭau syusteṣu vātaviparyayaḥ alpaśopho'nyatovātastathā pākātyayaḥ smṛtaḥ śuṣkākṣipākaśca tathā śopho'dhyuṣita eva ca hatādhimantha ityete rogāḥ sarvākṣisambhavāḥ" },
      { type: "verse", number: "171", sanskrit: "पुंस्त्वदोषास्तु पञ्चैव प्रोक्तास्तत्रेर्ष्यकः स्मृतः आसेक्यश्चैव कुम्भीकः सुगन्धिः षण्ढसंज्ञकः", text: "puṃstvadoṣāstu pañcaiva proktāstatrerṣyakaḥ smṛtaḥ āsekyaścaiva kumbhīkaḥ sugandhiḥ ṣaṇḍhasaṃjñakaḥ" },
      { type: "verse", number: "172", sanskrit: "शुक्रदोषास्तथाऽष्टौ स्युर्वातात्पित्तात्कफेन च कुणपं श्लेष्मवाताभ्यां पूयाभं श्लेष्मपित्ततः", text: "śukradoṣāstathā'ṣṭau syurvātātpittātkaphena ca kuṇapaṃ śleṣmavātābhyāṃ pūyābhaṃ śleṣmapittataḥ" },
      { type: "verse", number: "173", sanskrit: "क्षीणं च वातपित्ताभ्यां ग्रन्थिलं श्लेष्मवाततः मलाभं सन्निपाताच्च शुक्रदोषा इतीरिताः", text: "kṣīṇaṃ ca vātapittābhyāṃ granthilaṃ śleṣmavātataḥ malābhaṃ sannipātācca śukradoṣā itīritāḥ" },
      { type: "verse", number: "174", sanskrit: "अथ स्त्रीरोगनामानि प्रोच्यन्ते पूर्वशास्त्रतः", text: "atha strīroganāmāni procyante pūrvaśāstrataḥ" },
      { type: "verse", number: "175", sanskrit: "अष्टावार्त्तवदोषाः स्युर्वातपित्तकफैस्त्रिधा पूयाभं कुणपं ग्रन्थिं क्षीणं मलसमं तथा", text: "aṣṭāvārttavadoṣāḥ syurvātapittakaphaistridhā pūyābhaṃ kuṇapaṃ granthiṃ kṣīṇaṃ malasamaṃ tathā" },
      { type: "verse", number: "176", sanskrit: "तथा च रक्तप्रदरं चतुर्विधमुदाहृतम् वातपित्तकफैस्त्रेधा चतुर्थं सन्निपाततः", text: "tathā ca raktapradaraṃ caturvidhamudāhṛtam vātapittakaphaistredhā caturthaṃ sannipātataḥ" },
      { type: "verse", number: "177", sanskrit: "विंशतिर्योनिरोगाः स्युर्वातात्पित्तात्कफादपि सन्निपाताच्च रक्ताच्च लोहितक्षयतस्तथा", text: "viṃśatiryonirogāḥ syurvātātpittātkaphādapi sannipātācca raktācca lohitakṣayatastathā" },
      { type: "verse", number: "178", sanskrit: "शुष्का च वामिनी चैव खण्डिताऽन्तर्मुखी तथा सूचीमुखी विप्लुता च जातघ्नी च परिप्लुता", text: "śuṣkā ca vāminī caiva khaṇḍitā'ntarmukhī tathā sūcīmukhī viplutā ca jātaghnī ca pariplutā" },
      { type: "verse", number: "179", sanskrit: "उपप्लुता प्राक्चरणा महायोनिश्च कर्णिनी स्यान्नन्दा चातिचरणा योनिरोगा इतीरिताः", text: "upaplutā prākcaraṇā mahāyoniśca karṇinī syānnandā cāticaraṇā yonirogā itīritāḥ" },
      { type: "verse", number: "180", sanskrit: "चतुर्विधं योनिकन्दं वातपित्तकफैस्त्रिधा चतुर्थं सन्निपातेन गर्भरोगभेदाः तथाष्टौ गर्भजा गदाः", text: "caturvidhaṃ yonikandaṃ vātapittakaphaistridhā caturthaṃ sannipātena garbharogabhedāḥ tathāṣṭau garbhajā gadāḥ" },
      { type: "verse", number: "181", sanskrit: "उपविष्टकगर्भः स्यात्तथा नागोदरः स्मृतः मक्कल्लो मूढगर्भश्च विष्कम्भो गूढगर्भकः जरायुदोषो गर्भस्य पातश्चाष्टमकः स्मृतः", text: "upaviṣṭakagarbhaḥ syāttathā nāgodaraḥ smṛtaḥ makkallo mūḍhagarbhaśca viṣkambho gūḍhagarbhakaḥ jarāyudoṣo garbhasya pātaścāṣṭamakaḥ smṛtaḥ" },
      { type: "verse", number: "182", sanskrit: "पञ्चैव स्तनरोगाः स्युर्वातात्पित्तात्कफादपि सन्निपातात्क्षताच्चैव स्तन्यरोगभेदाः तथा स्तन्योद्भवा गदाः", text: "pañcaiva stanarogāḥ syurvātātpittātkaphādapi sannipātātkṣatāccaiva stanyarogabhedāḥ tathā stanyodbhavā gadāḥ" },
      { type: "verse", number: "183", sanskrit: "स्त्रीदोषाश्चत्रयः स्मृताः", text: "strīdoṣāścatrayaḥ smṛtāḥ" },
      { type: "verse", number: "184", sanskrit: "अदक्षपुरुषोत्पन्नः सपत्नीविहितस्तथा दैवाज्जातस्तृतीयस्तु सूतिकारोगभेदाः तथा ये सूतिकागदाः", text: "adakṣapuruṣotpannaḥ sapatnīvihitastathā daivājjātastṛtīyastu sūtikārogabhedāḥ tathā ye sūtikāgadāḥ" },
      { type: "verse", number: "185", sanskrit: "ज्वरादयश्चिकित्स्यास्ते यथादोषं यथाबलम्", text: "jvarādayaścikitsyāste yathādoṣaṃ yathābalam" },
      { type: "verse", number: "186", sanskrit: "द्वाविंशतिर्बालरोगास्तेषु क्षीरभवास्त्रयः वातात्पित्तात्कफाच्चैव दन्तोद्भेदश्चतुर्थकः दन्तघातो दन्तशब्दोऽकालदन्ताऽहिपूतनम्", text: "dvāviṃśatirbālarogāsteṣu kṣīrabhavāstrayaḥ vātātpittātkaphāccaiva dantodbhedaścaturthakaḥ dantaghāto dantaśabdo'kāladantā'hipūtanam" },
      { type: "verse", number: "187", sanskrit: "मुखपाको मुखस्रावो गुदपाकोपशीर्षके पद्मारुणस्तालुकण्टो विच्छिन्नं पारिगर्भिकः", text: "mukhapāko mukhasrāvo gudapākopaśīrṣake padmāruṇastālukaṇṭo vicchinnaṃ pārigarbhikaḥ" },
      { type: "verse", number: "188", sanskrit: "दौर्बल्यं गात्रशोषश्च शय्यामूत्रं कुकूणकः रोदनं चाजगल्ली स्यादिति द्वाविंशतिः स्मृताः", text: "daurbalyaṃ gātraśoṣaśca śayyāmūtraṃ kukūṇakaḥ rodanaṃ cājagallī syāditi dvāviṃśatiḥ smṛtāḥ" },
      { type: "verse", number: "189", sanskrit: "तथा बालग्रहाः ख्याता द्वादशैव मुनीश्वरैः स्कन्दग्रहो विशाखः स्याच्छ्वग्रहश्च पितृग्रहः", text: "tathā bālagrahāḥ khyātā dvādaśaiva munīśvaraiḥ skandagraho viśākhaḥ syācchvagrahaśca pitṛgrahaḥ" },
      { type: "verse", number: "190", sanskrit: "नैगमेयग्रहस्तद्वच्छकुनिः शीतपूतना मुखमण्डनिका तद्वत्पूतना चान्धपूतना रेवती चैव सङ्ख्याता तथा स्याच्छुष्करेवती", text: "naigameyagrahastadvacchakuniḥ śītapūtanā mukhamaṇḍanikā tadvatpūtanā cāndhapūtanā revatī caiva saṅkhyātā tathā syācchuṣkarevatī" },
      { type: "verse", number: "192", sanskrit: "तथा चरणभेदास्तु वातरक्तादिकाश्च ये द्विचत्वारिंशदुक्तास्ते रोगेष्वेव मुनीश्वरैः वातादिदोषभेदाः द्विषष्टिर्दोषभेदाः स्युः सन्निपातादिकाश्च ये तेऽपि रोगेषु गणिताः पृथक्प्रोक्ता न ते क्वचित्", text: "tathā caraṇabhedāstu vātaraktādikāśca ye dvicatvāriṃśaduktāste rogeṣveva munīśvaraiḥ vātādidoṣabhedāḥ dviṣaṣṭirdoṣabhedāḥ syuḥ sannipātādikāśca ye te'pi rogeṣu gaṇitāḥ pṛthakproktā na te kvacit" },
      { type: "verse", number: "193", sanskrit: "हीनमिथ्याऽतियोगानां भेदैः पञ्चदशोदिताः पञ्चकर्मभवा रोगा रोगेष्वेव प्रकीर्त्तिताः", text: "hīnamithyā'tiyogānāṃ bhedaiḥ pañcadaśoditāḥ pañcakarmabhavā rogā rogeṣveva prakīrttitāḥ" },
      { type: "verse", number: "194", sanskrit: "स्नेहादीनां हीनादियोगजरोगभेदाः स्नेहस्वेदौ तथा धूमो गण्डूषोऽञ्जनतर्पणे षोढा अष्टादशैतज्जास्ताश्च रोगेषु लक्षिताः", text: "snehādīnāṃ hīnādiyogajarogabhedāḥ snehasvedau tathā dhūmo gaṇḍūṣo'ñjanatarpaṇe ṣoḍhā aṣṭādaśaitajjāstāśca rogeṣu lakṣitāḥ" },
      { type: "verse", number: "195", sanskrit: "शीतोपद्र व एकः स्यादेकश्चोष्णोद्भवो मतः शल्योपद्र व एकश्च क्षाराच्चैकः स्मृतस्तथा", text: "śītopadra va ekaḥ syādekaścoṣṇodbhavo mataḥ śalyopadra va ekaśca kṣārāccaikaḥ smṛtastathā" },
      { type: "verse", number: "196", sanskrit: "स्थावरं जङ्गमं चैव कृत्रिमं च त्रिधा विषम्", text: "sthāvaraṃ jaṅgamaṃ caiva kṛtrimaṃ ca tridhā viṣam" },
      { type: "verse", number: "197", sanskrit: "तेषां च कालकूटाद्यैर्नवधा स्थावरं विषम् जङ्गमं बहुधा प्रोक्तं तत्र लूता भुजङ्गमाः", text: "teṣāṃ ca kālakūṭādyairnavadhā sthāvaraṃ viṣam jaṅgamaṃ bahudhā proktaṃ tatra lūtā bhujaṅgamāḥ" },
      { type: "verse", number: "198", sanskrit: "वृश्चिका मूषिकाः कीटाः प्रत्येकं ते चतुर्विधाः दंष्ट्राविषं नखविषं बालशृङ्गास्थिभिस्तथा", text: "vṛścikā mūṣikāḥ kīṭāḥ pratyekaṃ te caturvidhāḥ daṃṣṭrāviṣaṃ nakhaviṣaṃ bālaśṛṅgāsthibhistathā" },
      { type: "verse", number: "199", sanskrit: "मूत्रात्पुरीषाच्छुक्राच्च दृष्टेर्निश्वासतस्तथा लालायाः स्पर्शतस्तद्वत्तथा शङ्काविषं मतम्", text: "mūtrātpurīṣācchukrācca dṛṣṭerniśvāsatastathā lālāyāḥ sparśatastadvattathā śaṅkāviṣaṃ matam" },
      { type: "verse", number: "200", sanskrit: "कृत्रिमं द्विविधं प्रोक्तं गरदूषीविभेदतः सप्तधातुविषं ज्ञेयं तथा सप्तोपधातुजम्", text: "kṛtrimaṃ dvividhaṃ proktaṃ garadūṣīvibhedataḥ saptadhātuviṣaṃ jñeyaṃ tathā saptopadhātujam" },
      { type: "verse", number: "201", sanskrit: "तथैवोपविषेभ्यश्च जातं सप्तविधं मतम् दुष्टनीरविषं चैकं तथैकं दिग्धजं विषम्", text: "tathaivopaviṣebhyaśca jātaṃ saptavidhaṃ matam duṣṭanīraviṣaṃ caikaṃ tathaikaṃ digdhajaṃ viṣam" },
      { type: "verse", number: "202", sanskrit: "कपिकच्छुभवा कण्डूर्दुष्टनीरभवा तथा तथा सूरणकण्डूश्च शोथो भल्लातजस्तथा", text: "kapikacchubhavā kaṇḍūrduṣṭanīrabhavā tathā tathā sūraṇakaṇḍūśca śotho bhallātajastathā" },
      { type: "verse", number: "203", sanskrit: "मदश्चतुर्विधश्चान्यः पूगभङ्गाऽक्षकोद्र वैः चतुर्विधोऽन्यो द्र व्याणां फलत्वङ्मूलपत्रजः", text: "madaścaturvidhaścānyaḥ pūgabhaṅgā'kṣakodra vaiḥ caturvidho'nyo dra vyāṇāṃ phalatvaṅmūlapatrajaḥ" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 1,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Панча видха кашая — Пять видов отваров" },
      { type: "text", text: "Систематизация пяти форм кашаи (отваров): сварас (свежевыжатый сок), кальпа (паста), квастха (отвар), хима (холодный настой), пханта (горячий настой). Правила приготовления." },
      { type: "verse", number: "1", sanskrit: "अथ स्वरसादिकल्पनानामप्रथमोऽध्यायः अथ पञ्च कषायाः अथातः स्वरसः कल्कः क्वाथश्च हिमफाण्टकौ ज्ञेयाः कषायाः पञ्चैते लघवः स्युर्यथोत्तरम्", text: "atha svarasādikalpanānāmaprathamo'dhyāyaḥ atha pañca kaṣāyāḥ athātaḥ svarasaḥ kalkaḥ kvāthaśca himaphāṇṭakau jñeyāḥ kaṣāyāḥ pañcaite laghavaḥ syuryathottaram" },
      { type: "verse", number: "2", sanskrit: "आहतात्तत्क्षणाकृष्टाद् द्र व्यात् क्षुण्णात्समुद्धरेत् वस्त्रनिष्पीडितो यः स रसः स्वरस उच्यते", text: "āhatāttatkṣaṇākṛṣṭād dra vyāt kṣuṇṇātsamuddharet vastraniṣpīḍito yaḥ sa rasaḥ svarasa ucyate" },
      { type: "verse", number: "3", sanskrit: "कुडवं चूर्णितं द्र व्यं क्षिप्तं च द्विगुणे जले अहोरात्रं स्थितं तस्माद्भवेद्वा रस उत्तमः", text: "kuḍavaṃ cūrṇitaṃ dra vyaṃ kṣiptaṃ ca dviguṇe jale ahorātraṃ sthitaṃ tasmādbhavedvā rasa uttamaḥ" },
      { type: "verse", number: "4", sanskrit: "आदाय शुष्कद्र व्यं वा स्वरसानामसम्भवे जलेऽष्टगुणिते साध्यं पादशिष्टं च गृह्यते", text: "ādāya śuṣkadra vyaṃ vā svarasānāmasambhave jale'ṣṭaguṇite sādhyaṃ pādaśiṣṭaṃ ca gṛhyate" },
      { type: "verse", number: "5", sanskrit: "स्वरसस्य गुरुत्वाच्च पलमर्धं प्रयोजयेत् निशोषितं चाग्निसिद्धं पलमात्रं रसं पिबेत्", text: "svarasasya gurutvācca palamardhaṃ prayojayet niśoṣitaṃ cāgnisiddhaṃ palamātraṃ rasaṃ pibet" },
      { type: "verse", number: "6", sanskrit: "स्वरसे प्रक्षेप्यद्र व्याणि तेषां परिमाणं च मधुश्वेतागुडक्षाराञ्जीरकं लवणं तथा घृतं तैलं च चूर्णादीन्कोलमात्रान् रसे क्षिपेत्", text: "svarase prakṣepyadra vyāṇi teṣāṃ parimāṇaṃ ca madhuśvetāguḍakṣārāñjīrakaṃ lavaṇaṃ tathā ghṛtaṃ tailaṃ ca cūrṇādīnkolamātrān rase kṣipet" },
      { type: "verse", number: "7", sanskrit: "अथ रोगानुसारेण स्वरसप्रयोगाः तत्र प्रमेहेऽमृतास्वरसो धात्रीस्वरसश्चस तथा अमृताया रसः क्षौद्र युक्तः सर्वप्रमेहजित् हरिद्रा चूर्णयुक्तो वा रसो धात्र्! याः समाक्षिकः", text: "atha rogānusāreṇa svarasaprayogāḥ tatra pramehe'mṛtāsvaraso dhātrīsvarasaścasa tathā amṛtāyā rasaḥ kṣaudra yuktaḥ sarvapramehajit haridrā cūrṇayukto vā raso dhātr! yāḥ samākṣikaḥ" },
      { type: "verse", number: "8", sanskrit: "वासकस्वरसः पेयो मधुना रक्तपित्तजित् ज्वरकासक्षयहरः कामलाश्लेष्मपित्तहा", text: "vāsakasvarasaḥ peyo madhunā raktapittajit jvarakāsakṣayaharaḥ kāmalāśleṣmapittahā" },
      { type: "verse", number: "9", sanskrit: "कामलायां त्रिफलाऽदीनां स्वरसचतुष्टयम् त्रिफलाया रसः क्षौद्र युक्तो दार्वीरसोऽथ वा निम्बस्य वा गुडूच्या वा पीतो जयति कामलाम्", text: "kāmalāyāṃ triphalā'dīnāṃ svarasacatuṣṭayam triphalāyā rasaḥ kṣaudra yukto dārvīraso'tha vā nimbasya vā guḍūcyā vā pīto jayati kāmalām" },
      { type: "verse", number: "10", sanskrit: "विषमज्वरे तुलसीद्रो णपुष्पीपत्रस्वरसौ पीतो मरिचचूर्णेन तुलसीपत्रजो रसः द्रो णपुष्पीरसो वाऽपि निहन्ति विषमज्वरान्", text: "viṣamajvare tulasīdro ṇapuṣpīpatrasvarasau pīto maricacūrṇena tulasīpatrajo rasaḥ dro ṇapuṣpīraso vā'pi nihanti viṣamajvarān" },
      { type: "verse", number: "11", sanskrit: "जम्ब्वाम्रामलकीनां च पल्लवोत्थो रसो जयेत् मध्वाज्यक्षीर संयुक्तो रक्तातीसारमुल्बणम्", text: "jambvāmrāmalakīnāṃ ca pallavottho raso jayet madhvājyakṣīra saṃyukto raktātīsāramulbaṇam" },
      { type: "verse", number: "12", sanskrit: "सर्वातिसारे निष्कण्टकबब्बूलदल कुटजादित्वक् स्वरसौ स्थूलबब्बूलिकापत्ररसः पानाद्व्यपोहति सर्वातिसारान्श्योनाककुटजत्वग्रसोऽथ वा", text: "sarvātisāre niṣkaṇṭakababbūladala kuṭajāditvak svarasau sthūlababbūlikāpatrarasaḥ pānādvyapohati sarvātisārānśyonākakuṭajatvagraso'tha vā" },
      { type: "verse", number: "13", sanskrit: "वृषणवातप्रतिश्यायादिष्वार्द्र कस्वरसः आर्द्र कस्वरसः क्षौद्र युक्तो वृषणवातनुत् श्वासकासारुचीर्हन्ति प्रतिश्यायं व्यपोहति", text: "vṛṣaṇavātapratiśyāyādiṣvārdra kasvarasaḥ ārdra kasvarasaḥ kṣaudra yukto vṛṣaṇavātanut śvāsakāsārucīrhanti pratiśyāyaṃ vyapohati" },
      { type: "verse", number: "14", sanskrit: "पार्श्वदिशूलादिषु बीजपूरस्वरसः बीजपूररसः पानान्मधुक्षारयुतो जयेत् पार्श्वहृद्वस्तिशूलानि कोष्ठवातं च दारुणम्", text: "pārśvadiśūlādiṣu bījapūrasvarasaḥ bījapūrarasaḥ pānānmadhukṣārayuto jayet pārśvahṛdvastiśūlāni koṣṭhavātaṃ ca dāruṇam" },
      { type: "verse", number: "15", sanskrit: "पित्तशूले शतावरीस्वरसः प्लीहाऽपच्योः कन्यास्वरसश्च शतावर्याश्च मधुना पित्तशूलहरो रसः निशाचूर्णयुतः कन्यारसः प्लीहाऽपचीहरः", text: "pittaśūle śatāvarīsvarasaḥ plīhā'pacyoḥ kanyāsvarasaśca śatāvaryāśca madhunā pittaśūlaharo rasaḥ niśācūrṇayutaḥ kanyārasaḥ plīhā'pacīharaḥ" },
      { type: "verse", number: "16", sanskrit: "अलम्बुषायाः स्वरसः पीतो द्विपलमात्रया अपचीगण्डमालानां कामलायाश्च नाशनः", text: "alambuṣāyāḥ svarasaḥ pīto dvipalamātrayā apacīgaṇḍamālānāṃ kāmalāyāśca nāśanaḥ" },
      { type: "verse", number: "17", sanskrit: "शशमुण्ड्या रसः कोष्णो मरिचैरवधूलितः जयेत्सप्तदिनाभ्यासात्सूर्यावर्त्तार्धभेदकौ", text: "śaśamuṇḍyā rasaḥ koṣṇo maricairavadhūlitaḥ jayetsaptadinābhyāsātsūryāvarttārdhabhedakau" },
      { type: "verse", number: "18", sanskrit: "सर्वोन्मादे ब्राह्म्यादीनां स्वरसचतुष्टयम् ब्राह्मीकूष्माण्डषड्ग्रन्थाशङ्खिनीस्वरसाः पृथक् मधुकुष्ठयुताः पीताः सर्वोन्मादापहारिणः", text: "sarvonmāde brāhmyādīnāṃ svarasacatuṣṭayam brāhmīkūṣmāṇḍaṣaḍgranthāśaṅkhinīsvarasāḥ pṛthak madhukuṣṭhayutāḥ pītāḥ sarvonmādāpahāriṇaḥ" },
      { type: "verse", number: "19", sanskrit: "कोद्र वजमदे कूष्माण्डकस्वरसः कूष्माण्डकस्य स्वरसो गुडेन सह योजितः दुष्टकोद्र वसञ्जातमदं पानाद्व्यपोहति", text: "kodra vajamade kūṣmāṇḍakasvarasaḥ kūṣmāṇḍakasya svaraso guḍena saha yojitaḥ duṣṭakodra vasañjātamadaṃ pānādvyapohati" },
      { type: "verse", number: "20", sanskrit: "खड्गादिक्षतव्रणे गाङ्गेरुकीस्वरसः खड्गादिच्छिन्नगात्रस्य तत्कालं पूरितो व्रणः गाङ्गेरुकीमूलरसैर्जायते गतवेदनः", text: "khaḍgādikṣatavraṇe gāṅgerukīsvarasaḥ khaḍgādicchinnagātrasya tatkālaṃ pūrito vraṇaḥ gāṅgerukīmūlarasairjāyate gatavedanaḥ" },
      { type: "verse", number: "21", sanskrit: "पुटपाकस्य कल्कस्य स्वरसो गृह्यते यतः अतस्तु पुटपाकानां युक्तिरत्रोच्यते मया", text: "puṭapākasya kalkasya svaraso gṛhyate yataḥ atastu puṭapākānāṃ yuktiratrocyate mayā" },
      { type: "verse", number: "22", sanskrit: "पुटपाकस्य मात्रेयं लेपस्याङ्गारवर्णता लेपं च द्व्यङ्गुलं स्थूलं कुर्याद्वाऽङगुष्ठमात्रकम्", text: "puṭapākasya mātreyaṃ lepasyāṅgāravarṇatā lepaṃ ca dvyaṅgulaṃ sthūlaṃ kuryādvā'ṅaguṣṭhamātrakam" },
      { type: "verse", number: "23", sanskrit: "पलमात्रं रसो ग्राह्यः कर्षमात्रं मधु क्षिपेत् कल्कचूर्णद्र वाद्यास्तु देयाः स्वरसवद् बुधैः", text: "palamātraṃ raso grāhyaḥ karṣamātraṃ madhu kṣipet kalkacūrṇadra vādyāstu deyāḥ svarasavad budhaiḥ" },
      { type: "verse", number: "24", sanskrit: "तत्कालाकृष्टकुटजत्वचं तण्डुलवारिणा", text: "tatkālākṛṣṭakuṭajatvacaṃ taṇḍulavāriṇā" },
      { type: "verse", number: "25", sanskrit: "पिष्टां चतुष्पलमितो जम्बूपल्लववेष्टिताम् सूत्रेण बद्धां गोधूमपिष्टेन परिवेष्टिताम्", text: "piṣṭāṃ catuṣpalamito jambūpallavaveṣṭitām sūtreṇa baddhāṃ godhūmapiṣṭena pariveṣṭitām" },
      { type: "verse", number: "26", sanskrit: "लिप्तां च घनपङ्केन गोमयैर्वह्निना दहेत् अङ्गारवर्णां च मृदं दृष्ट्वा वह्नेः समुद्धरेत्", text: "liptāṃ ca ghanapaṅkena gomayairvahninā dahet aṅgāravarṇāṃ ca mṛdaṃ dṛṣṭvā vahneḥ samuddharet" },
      { type: "verse", number: "27", sanskrit: "ततो रसं गृहीत्वा च शीतं क्षौद्र युतं पिबेत् जयेत्सर्वानतीसारान्दुस्तरान्सुचिरोत्थितान्", text: "tato rasaṃ gṛhītvā ca śītaṃ kṣaudra yutaṃ pibet jayetsarvānatīsārāndustarānsucirotthitān" },
      { type: "verse", number: "28", sanskrit: "कण्डितं तण्डुलपलं जलेऽष्टगुणिते क्षिपेत् भावयित्वा जलं ग्राह्यं देयं सर्वत्र कर्मसु", text: "kaṇḍitaṃ taṇḍulapalaṃ jale'ṣṭaguṇite kṣipet bhāvayitvā jalaṃ grāhyaṃ deyaṃ sarvatra karmasu" },
      { type: "verse", number: "29", sanskrit: "अरलूत्वक्कृतश्चैव पुटपाकोऽग्निदीपनः मधुमोचरसाभ्यां च युक्तः सर्वातिसारनुत्", text: "aralūtvakkṛtaścaiva puṭapāko'gnidīpanaḥ madhumocarasābhyāṃ ca yuktaḥ sarvātisāranut" },
      { type: "verse", number: "30", sanskrit: "सर्वातिसारे न्यग्रोधादितित्तिरपुटपाकः न्यग्रोधादेश्च कल्केन पूरयेद्गौरतित्तिरेः निरन्त्रमुदरं सम्यक्पुटपाकेन तत्पचेत् तत्कल्कस्य रसः क्षौद्र युक्तः सर्वातिसारनुत्", text: "sarvātisāre nyagrodhāditittirapuṭapākaḥ nyagrodhādeśca kalkena pūrayedgauratittireḥ nirantramudaraṃ samyakpuṭapākena tatpacet tatkalkasya rasaḥ kṣaudra yuktaḥ sarvātisāranut" },
      { type: "verse", number: "31", sanskrit: "पुटपाकेन विपचेत्सुपक्वं दाडिमीजलम् तद्र सो मधुसंयुक्तः सर्वातीसारनाशनः", text: "puṭapākena vipacetsupakvaṃ dāḍimījalam tadra so madhusaṃyuktaḥ sarvātīsāranāśanaḥ" },
      { type: "verse", number: "32", sanskrit: "बीजपूराम्रजम्बूनां पल्लवानि जटाः पृथक्", text: "bījapūrāmrajambūnāṃ pallavāni jaṭāḥ pṛthak" },
      { type: "verse", number: "33", sanskrit: "विपचेत्पुटपाकेन क्षौद्र युक्तश्च तद्र सः छर्दिं निवारयेद्धोरां सर्वदोषसमुद्भवाम्", text: "vipacetpuṭapākena kṣaudra yuktaśca tadra saḥ chardiṃ nivārayeddhorāṃ sarvadoṣasamudbhavām" },
      { type: "verse", number: "34", sanskrit: "पिष्टानां वृषपत्राणां पुटपाकरसो हिमः मधुयुक्तो जयेद्र क्तपित्तकासज्वरक्षयान्", text: "piṣṭānāṃ vṛṣapatrāṇāṃ puṭapākaraso himaḥ madhuyukto jayedra ktapittakāsajvarakṣayān" },
      { type: "verse", number: "35", sanskrit: "पचेत्क्षुद्रा ं! सपञ्चाङ्गां पुटपाकेन तद्र सः पिप्पली चूर्णसंयुक्तः कासश्वासकफापहः", text: "pacetkṣudrā ṃ! sapañcāṅgāṃ puṭapākena tadra saḥ pippalī cūrṇasaṃyuktaḥ kāsaśvāsakaphāpahaḥ" },
      { type: "verse", number: "36", sanskrit: "बिभीतकफलं किञ्चिद् घृतेनाभ्यज्य लेपयेत् गोधूमपिष्टेनाङ्गारैर्विपचेत्पुटपाकवत्", text: "bibhītakaphalaṃ kiñcid ghṛtenābhyajya lepayet godhūmapiṣṭenāṅgārairvipacetpuṭapākavat" },
      { type: "verse", number: "37", sanskrit: "ततः पक्वं समुद्धृत्य त्वचं तस्य मुखे क्षिपेत् कासश्वासप्रतिश्यायस्वरभङ्गाञ्जयेत्ततः", text: "tataḥ pakvaṃ samuddhṛtya tvacaṃ tasya mukhe kṣipet kāsaśvāsapratiśyāyasvarabhaṅgāñjayettataḥ" },
      { type: "verse", number: "38", sanskrit: "चूर्णं किञ्चिद् घृताभ्यक्तं शुण्ठ्या एरण्डजैर्दलैः वेष्टितं पुटपाकेन विपचेन्मन्दवह्निना", text: "cūrṇaṃ kiñcid ghṛtābhyaktaṃ śuṇṭhyā eraṇḍajairdalaiḥ veṣṭitaṃ puṭapākena vipacenmandavahninā" },
      { type: "verse", number: "39", sanskrit: "तत उद्धृत्य तच्चूर्णं ग्राह्य प्रातः सितासमम् येन यान्ति शमं पीडा आमातीसारसंभवाः", text: "tata uddhṛtya taccūrṇaṃ grāhya prātaḥ sitāsamam yena yānti śamaṃ pīḍā āmātīsārasaṃbhavāḥ" },
      { type: "verse", number: "40", sanskrit: "शुण्ठीकल्कं विनिक्षिप्य रसैरेरण्डमूलजैः विपचेत्पुटपाकेन तद्र सः क्षौद्र संयुतः आमवातसमुद्भूतां पीडां जयति दुस्तराम्", text: "śuṇṭhīkalkaṃ vinikṣipya rasaireraṇḍamūlajaiḥ vipacetpuṭapākena tadra saḥ kṣaudra saṃyutaḥ āmavātasamudbhūtāṃ pīḍāṃ jayati dustarām" },
      { type: "verse", number: "41", sanskrit: "सौरणं कन्दमादाय पुटपाकेन पाचयेत् सतैललवणस्तस्य रसश्चार्शोविकारनुत्", text: "sauraṇaṃ kandamādāya puṭapākena pācayet satailalavaṇastasya rasaścārśovikāranut" },
      { type: "verse", number: "42", sanskrit: "हृच्छूले पुटपाकजमृगशृङ्गभस्म शरावसम्पुटे दग्धं शृङ्गं हरिणजं पिबेत् गव्येन सर्पिषा युक्तं हृच्छूलं नाशयेद् ध्रुवम्", text: "hṛcchūle puṭapākajamṛgaśṛṅgabhasma śarāvasampuṭe dagdhaṃ śṛṅgaṃ hariṇajaṃ pibet gavyena sarpiṣā yuktaṃ hṛcchūlaṃ nāśayed dhruvam" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 2,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Сварасади санграха — Соки и отвары" },
      { type: "text", text: "Подробное описание двенадцати фармакологических форм аюрведы: от свежих соков до порошков и паст. Правила приготовления, хранения и применения каждой формы." },
      { type: "verse", number: "1", sanskrit: "अथ क्वाथकल्पनानामद्वितीयोऽध्यायः क्वाथकल्पना पानीयं षोडशगुणं क्षुण्णे द्र व्यपले क्षिपेत् मृत्पात्रे क्वाथयेद् ग्राह्यमष्टमांशावशेषितम् तज्जलं पाययेद्धीमान्कोष्णं मृद्वग्निसाधितम्", text: "atha kvāthakalpanānāmadvitīyo'dhyāyaḥ kvāthakalpanā pānīyaṃ ṣoḍaśaguṇaṃ kṣuṇṇe dra vyapale kṣipet mṛtpātre kvāthayed grāhyamaṣṭamāṃśāvaśeṣitam tajjalaṃ pāyayeddhīmānkoṣṇaṃ mṛdvagnisādhitam" },
      { type: "verse", number: "2", sanskrit: "शृतः क्वाथः कषायश्च निर्यूहः स निगद्यते", text: "śṛtaḥ kvāthaḥ kaṣāyaśca niryūhaḥ sa nigadyate" },
      { type: "verse", number: "3", sanskrit: "आहाररसपाके च सञ्जाते द्विपलोन्मितम् वृद्धवैद्योपदेशेन पिबेत्क्वाथं सुपाचितम्", text: "āhārarasapāke ca sañjāte dvipalonmitam vṛddhavaidyopadeśena pibetkvāthaṃ supācitam" },
      { type: "verse", number: "4", sanskrit: "क्वाथे सितामधुनोः प्रक्षेपपरिमाणम् क्वाथे क्षिपेत्सितामंशैश्चतुर्थाष्टमषोडशैः वातपित्तकफातंके विपरीतं मधु स्मृतम्", text: "kvāthe sitāmadhunoḥ prakṣepaparimāṇam kvāthe kṣipetsitāmaṃśaiścaturthāṣṭamaṣoḍaśaiḥ vātapittakaphātaṃke viparītaṃ madhu smṛtam" },
      { type: "verse", number: "5", sanskrit: "चूर्णद्र व्याणां प्रक्षेपपरिमाणम् जीरकं गुग्गुलं क्षारं लवणं च शिलाजतु हिङ्गु त्रिकटुकं चैव क्थाथे शाणोन्मितं क्षिपेत्", text: "cūrṇadra vyāṇāṃ prakṣepaparimāṇam jīrakaṃ guggulaṃ kṣāraṃ lavaṇaṃ ca śilājatu hiṅgu trikaṭukaṃ caiva kthāthe śāṇonmitaṃ kṣipet" },
      { type: "verse", number: "6", sanskrit: "द्र वद्र व्याणां प्रक्षेपपरिमाणम् क्षीरं घृतं गुडं तैलं मूत्रं चान्यद् द्र वं तथा कल्कं चूर्णादिकं क्वाथे निक्षिपेत्कर्षसम्मितम्", text: "dra vadra vyāṇāṃ prakṣepaparimāṇam kṣīraṃ ghṛtaṃ guḍaṃ tailaṃ mūtraṃ cānyad dra vaṃ tathā kalkaṃ cūrṇādikaṃ kvāthe nikṣipetkarṣasammitam" },
      { type: "verse", number: "7", sanskrit: "पाकसमये क्वाथपात्रपिधाननिषेधः सपिधानमुखे पात्रे जलं दुर्जरतां व्रजेत् तस्मादावरणं त्यक्त्वा क्वाथादीनां विनिश्चयः", text: "pākasamaye kvāthapātrapidhānaniṣedhaḥ sapidhānamukhe pātre jalaṃ durjaratāṃ vrajet tasmādāvaraṇaṃ tyaktvā kvāthādīnāṃ viniścayaḥ" },
      { type: "verse", number: "8", sanskrit: "सर्वज्वरे दाहादौ च गुडूच्यादिक्वाथः गुडूचीधान्यकारिष्टरक्तचन्दनपद्मकैः गुडूच्यादिगणक्वाथः सर्वज्वरहरः स्मृतः दीपनो दाहहृल्लासतृष्णाच्छर्द्यरुचीर्जयेत्", text: "sarvajvare dāhādau ca guḍūcyādikvāthaḥ guḍūcīdhānyakāriṣṭaraktacandanapadmakaiḥ guḍūcyādigaṇakvāthaḥ sarvajvaraharaḥ smṛtaḥ dīpano dāhahṛllāsatṛṣṇācchardyarucīrjayet" },
      { type: "verse", number: "9", sanskrit: "नागरं देवकाष्ठं च धान्यकं बृहतीद्वयम् दद्यात्पाचनकं पूर्वं ज्वरितानां ज्वरापहम्", text: "nāgaraṃ devakāṣṭhaṃ ca dhānyakaṃ bṛhatīdvayam dadyātpācanakaṃ pūrvaṃ jvaritānāṃ jvarāpaham" },
      { type: "verse", number: "10", sanskrit: "क्षुद्रा  किराततिक्तं च शुण्ठी छिन्ना च पौष्करम् कषाय एषां शमयेत्पीतश्चाष्टविधं ज्वरम्", text: "kṣudrā  kirātatiktaṃ ca śuṇṭhī chinnā ca pauṣkaram kaṣāya eṣāṃ śamayetpītaścāṣṭavidhaṃ jvaram" },
      { type: "verse", number: "11", sanskrit: "गुडूचीपिप्पलीमूलनागरैः पाचनं स्मृतम् दद्याद्वातज्वरे पूर्णलिङ्गे सप्तमवासरे", text: "guḍūcīpippalīmūlanāgaraiḥ pācanaṃ smṛtam dadyādvātajvare pūrṇaliṅge saptamavāsare" },
      { type: "verse", number: "12", sanskrit: "शालपर्णी बला द्रा क्षा गुडूची सारिवा तथा आसां क्वाथं पिबेत्कोष्णं तीव्रवातज्वरच्छिदम्", text: "śālaparṇī balā drā kṣā guḍūcī sārivā tathā āsāṃ kvāthaṃ pibetkoṣṇaṃ tīvravātajvaracchidam" },
      { type: "verse", number: "13", sanskrit: "काश्मरीसारिवाद्रा क्षात्रायमाणाऽमृताभवः कषायः सगुडः पीतोवातज्वरविनाशनः", text: "kāśmarīsārivādrā kṣātrāyamāṇā'mṛtābhavaḥ kaṣāyaḥ saguḍaḥ pītovātajvaravināśanaḥ" },
      { type: "verse", number: "14", sanskrit: "कट्फलेन्द्र यवापाठातिक्तामुस्तैः शृतं जलम् पाचनं दशमेऽह्नि स्यात्तीव्रे पित्तज्वरे नृणाम्", text: "kaṭphalendra yavāpāṭhātiktāmustaiḥ śṛtaṃ jalam pācanaṃ daśame'hni syāttīvre pittajvare nṛṇām" },
      { type: "verse", number: "15", sanskrit: "पर्पटो वासकस्तिक्ता कैरातो धन्वयासकः", text: "parpaṭo vāsakastiktā kairāto dhanvayāsakaḥ" },
      { type: "verse", number: "16", sanskrit: "प्रियङ्गुश्च कृतः क्वाथ एषां शर्करया युतः पिपासादाहपित्तास्रयुतं पित्तज्वरं जयेत्", text: "priyaṅguśca kṛtaḥ kvātha eṣāṃ śarkarayā yutaḥ pipāsādāhapittāsrayutaṃ pittajvaraṃ jayet" },
      { type: "verse", number: "17", sanskrit: "द्रा क्षा हरीतकी मुस्तं कटुकी कृतमालकः पर्पटश्च कृतः क्वाथ एषां पित्तज्वरापहः तृण्मूर्च्छादाहपित्तासृक्शमनो भेदनः स्मृतः", text: "drā kṣā harītakī mustaṃ kaṭukī kṛtamālakaḥ parpaṭaśca kṛtaḥ kvātha eṣāṃ pittajvarāpahaḥ tṛṇmūrcchādāhapittāsṛkśamano bhedanaḥ smṛtaḥ" },
      { type: "verse", number: "18", sanskrit: "पर्पटक्वाथप्रशंसौ तत्र विशेषश्च एकः पर्पटकः श्रेष्ठः पित्तज्वरविनाशनः किं पुनर्यदि युज्येत चन्दनोशीरबालकैः", text: "parpaṭakvāthapraśaṃsau tatra viśeṣaśca ekaḥ parpaṭakaḥ śreṣṭhaḥ pittajvaravināśanaḥ kiṃ punaryadi yujyeta candanośīrabālakaiḥ" },
      { type: "verse", number: "19", sanskrit: "बीजपूरशिफापथ्यानागरग्रन्थिकैः शृतम् सक्षारं पाचनं श्लेष्मज्वरे द्वादशवासरे", text: "bījapūraśiphāpathyānāgaragranthikaiḥ śṛtam sakṣāraṃ pācanaṃ śleṣmajvare dvādaśavāsare" },
      { type: "verse", number: "20", sanskrit: "भूनिम्बनिम्बपिप्पल्यः शटी शुण्ठी शतावरी गुडूची बृहती चेति क्वाथो हन्यात्कफज्वरम्", text: "bhūnimbanimbapippalyaḥ śaṭī śuṇṭhī śatāvarī guḍūcī bṛhatī ceti kvātho hanyātkaphajvaram" },
      { type: "verse", number: "21", sanskrit: "क्वाथो मधुयुतः पीतो हन्यात्कफकृतं ज्वरम्", text: "kvātho madhuyutaḥ pīto hanyātkaphakṛtaṃ jvaram" },
      { type: "verse", number: "22", sanskrit: "तत्र वातपित्तज्वरे पञ्चभद्र क्वाथः पर्पटाब्दामृताविश्वकैरातैः साधितं जलम् पञ्चभद्र मिदं ज्ञेयं वातपित्तज्वरापहम्", text: "tatra vātapittajvare pañcabhadra kvāthaḥ parpaṭābdāmṛtāviśvakairātaiḥ sādhitaṃ jalam pañcabhadra midaṃ jñeyaṃ vātapittajvarāpaham" },
      { type: "verse", number: "23", sanskrit: "कफवातज्वरादौ लघुक्षुद्रा दिक्वाथः क्षुद्रा शुण्ठीगुडूचीनां कषायः पौष्करस्य च", text: "kaphavātajvarādau laghukṣudrā dikvāthaḥ kṣudrā śuṇṭhīguḍūcīnāṃ kaṣāyaḥ pauṣkarasya ca" },
      { type: "verse", number: "24", sanskrit: "कफवाताधिके पेयो ज्वरे वाऽपि त्रिदोषजे कासश्वासारुचिकरे पार्श्वशूलविधायिनि", text: "kaphavātādhike peyo jvare vā'pi tridoṣaje kāsaśvāsārucikare pārśvaśūlavidhāyini" },
      { type: "verse", number: "25", sanskrit: "क्वाथः शमयति क्षिप्रं ज्वरं वातकफोद्भवम् आमशूलप्रशमनो भेदी दीपनपाचनः", text: "kvāthaḥ śamayati kṣipraṃ jvaraṃ vātakaphodbhavam āmaśūlapraśamano bhedī dīpanapācanaḥ" },
      { type: "verse", number: "26", sanskrit: "अमृतारिष्टकटुकामुस्तेन्द्र यवनागरैः पटोलचन्दनाभ्यां च पिप्पलीचूर्णयुक्शृतम्", text: "amṛtāriṣṭakaṭukāmustendra yavanāgaraiḥ paṭolacandanābhyāṃ ca pippalīcūrṇayukśṛtam" },
      { type: "verse", number: "27", sanskrit: "अमृताष्टकमेतच्च पित्तश्लेष्मज्वरापहम् छर्द्यरोचकहृल्लासदाहतृष्णाविनाशनम्", text: "amṛtāṣṭakametacca pittaśleṣmajvarāpaham chardyarocakahṛllāsadāhatṛṣṇāvināśanam" },
      { type: "verse", number: "28", sanskrit: "पित्तश्लेष्मज्वरादौ पटोलादिक्वाथः पटोलं चन्दनं मूर्वातिक्तापाठाऽमृतागणः पित्तश्लेष्मज्वरच्छर्दिदाहकण्डूविषापहः", text: "pittaśleṣmajvarādau paṭolādikvāthaḥ paṭolaṃ candanaṃ mūrvātiktāpāṭhā'mṛtāgaṇaḥ pittaśleṣmajvaracchardidāhakaṇḍūviṣāpahaḥ" },
      { type: "verse", number: "29", sanskrit: "सर्वज्वरे कण्टकार्यादिक्वाथः कण्टकारीद्वयं शुण्ठी धान्यकं सुरदारु च एभिः शृतं पाचनं स्यात्सर्वज्वरविनाशनम्", text: "sarvajvare kaṇṭakāryādikvāthaḥ kaṇṭakārīdvayaṃ śuṇṭhī dhānyakaṃ suradāru ca ebhiḥ śṛtaṃ pācanaṃ syātsarvajvaravināśanam" },
      { type: "verse", number: "30", sanskrit: "शालिपर्णीपृश्निपर्णीबृहतीद्वयगोक्षुरैः", text: "śāliparṇīpṛśniparṇībṛhatīdvayagokṣuraiḥ" },
      { type: "verse", number: "31", sanskrit: "दशमूलमिति ख्यातं क्वथितं तज्जलं पिबेत्", text: "daśamūlamiti khyātaṃ kvathitaṃ tajjalaṃ pibet" },
      { type: "verse", number: "32", sanskrit: "पिप्पलीचूर्णसंयुक्तं वातश्लेष्मज्वरापहम् सन्निपातज्वरहरं सूतिकादोषनाशनम्", text: "pippalīcūrṇasaṃyuktaṃ vātaśleṣmajvarāpaham sannipātajvaraharaṃ sūtikādoṣanāśanam" },
      { type: "verse", number: "33", sanskrit: "हृत्कण्ठग्रहपार्श्वार्त्तितन्द्रा मस्तकशूलहृत्", text: "hṛtkaṇṭhagrahapārśvārttitandrā mastakaśūlahṛt" },
      { type: "verse", number: "34", sanskrit: "वासकेन्द्र यवोशीरगुडूचीकृतमालकैः", text: "vāsakendra yavośīraguḍūcīkṛtamālakaiḥ" },
      { type: "verse", number: "35", sanskrit: "पाठानागरतिक्ताभिः पिप्पलीचूर्णयुक्शृतम् पिबेत्त्रिदोषज्वरजित्पिपासाकासदाहनुत्", text: "pāṭhānāgaratiktābhiḥ pippalīcūrṇayukśṛtam pibettridoṣajvarajitpipāsākāsadāhanut" },
      { type: "verse", number: "36", sanskrit: "प्रलापश्वासतन्द्रा घ्नं दीपनं पाचनं परम् विण्मूत्रानिलविष्टम्भवमिशोषारुचिच्छिदम्", text: "pralāpaśvāsatandrā ghnaṃ dīpanaṃ pācanaṃ param viṇmūtrānilaviṣṭambhavamiśoṣārucicchidam" },
      { type: "verse", number: "37", sanskrit: "वचासातिविषाऽजाजीपाठावत्सकरेणुकैः", text: "vacāsātiviṣā'jājīpāṭhāvatsakareṇukaiḥ" },
      { type: "verse", number: "38", sanskrit: "किराततिक्तकं मूर्वा सर्षपा मरिचानि च कटुकं पुष्करं भार्ङ्गी विडङ्गं कर्कटाह्वयम्", text: "kirātatiktakaṃ mūrvā sarṣapā maricāni ca kaṭukaṃ puṣkaraṃ bhārṅgī viḍaṅgaṃ karkaṭāhvayam" },
      { type: "verse", number: "39", sanskrit: "अर्कमूलं बृहत्सिंही श्रेयसी सदुरालभा दीप्यकं चाजमोदा च शुकनासादिहिङ्गुभिः", text: "arkamūlaṃ bṛhatsiṃhī śreyasī sadurālabhā dīpyakaṃ cājamodā ca śukanāsādihiṅgubhiḥ" },
      { type: "verse", number: "40", sanskrit: "एतानि समभागानि गणोऽष्टाविंशको मतः कषायमुपभुञ्जीत वातश्लेष्मज्वरापहम्", text: "etāni samabhāgāni gaṇo'ṣṭāviṃśako mataḥ kaṣāyamupabhuñjīta vātaśleṣmajvarāpaham" },
      { type: "verse", number: "41", sanskrit: "हन्ति वातं तथा शीतं स्वेदजं प्रबलं कफम् प्रलापं चातिनिद्रा ं! च रोमहर्षारुची तथा", text: "hanti vātaṃ tathā śītaṃ svedajaṃ prabalaṃ kapham pralāpaṃ cātinidrā ṃ! ca romaharṣārucī tathā" },
      { type: "verse", number: "42", sanskrit: "महावातेऽपतन्त्रे च सर्वगात्रे च शून्यताम् अयं सर्वज्वरान्हन्ति सन्निपातांस्त्रयोदश", text: "mahāvāte'patantre ca sarvagātre ca śūnyatām ayaṃ sarvajvarānhanti sannipātāṃstrayodaśa" },
      { type: "verse", number: "43", sanskrit: "किरातकटुकीमुस्ताधान्येन्द्र यवनागरैः दशमूलमहादारुगजपिप्पलिकायुतैः", text: "kirātakaṭukīmustādhānyendra yavanāgaraiḥ daśamūlamahādārugajapippalikāyutaiḥ" },
      { type: "verse", number: "44", sanskrit: "कृतः कषायः पार्श्वार्त्तिसन्निपातज्वरं जयेत् कासश्वासवमीहिक्कातन्द्रा हृद्ग्रहनाशनः", text: "kṛtaḥ kaṣāyaḥ pārśvārttisannipātajvaraṃ jayet kāsaśvāsavamīhikkātandrā hṛdgrahanāśanaḥ" },
      { type: "verse", number: "45", sanskrit: "वचा हरीतकीशृङ्गीदेवदारुमहौषधैः हिक्काकासं ज्वरं हन्ति श्वासश्लेष्मगलग्रहान्", text: "vacā harītakīśṛṅgīdevadārumahauṣadhaiḥ hikkākāsaṃ jvaraṃ hanti śvāsaśleṣmagalagrahān" },
      { type: "verse", number: "46", sanskrit: "जीर्णज्वरे गुडूचीक्वाथः पित्तज्वरे पर्पटक्वाथश्च क्वाथो जीर्णज्वरं हन्ति गुडूच्याः पिप्पलीयुतः", text: "jīrṇajvare guḍūcīkvāthaḥ pittajvare parpaṭakvāthaśca kvātho jīrṇajvaraṃ hanti guḍūcyāḥ pippalīyutaḥ" },
      { type: "verse", number: "47", sanskrit: "तथा पर्पटजः क्वाथः पित्तज्वरहरः परः किं पुनर्यदि युज्येत चन्दनोदीच्यनागरैः", text: "tathā parpaṭajaḥ kvāthaḥ pittajvaraharaḥ paraḥ kiṃ punaryadi yujyeta candanodīcyanāgaraiḥ" },
      { type: "verse", number: "48", sanskrit: "जीर्णज्वरे निदिग्धिकादिक्वाथः निदिग्धिकाऽमृताशुण्ठीकषायं पाययेद्भिषक् पिप्पलीचूर्णसंयुक्तं श्वासकासार्दितापहम् पीनसारुचिवैस्वर्यशूलाजीर्णज्वरच्छिदम्", text: "jīrṇajvare nidigdhikādikvāthaḥ nidigdhikā'mṛtāśuṇṭhīkaṣāyaṃ pāyayedbhiṣak pippalīcūrṇasaṃyuktaṃ śvāsakāsārditāpaham pīnasārucivaisvaryaśūlājīrṇajvaracchidam" },
      { type: "verse", number: "49", sanskrit: "प्रसूतिदोषे देवदार्वादिक्वाथः देवदारु वचा कुष्ठं पिप्पली विश्वभेषजम्", text: "prasūtidoṣe devadārvādikvāthaḥ devadāru vacā kuṣṭhaṃ pippalī viśvabheṣajam" },
      { type: "verse", number: "50", sanskrit: "कट्फलंमुस्तभूनिम्बतिक्तधान्या हरीतकी गजकृष्णा च दुःस्पर्शा गोक्षुरुर्धन्वयासकम्", text: "kaṭphalaṃmustabhūnimbatiktadhānyā harītakī gajakṛṣṇā ca duḥsparśā gokṣururdhanvayāsakam" },
      { type: "verse", number: "51", sanskrit: "बृहत्यतिविषा छिन्ना कर्कटं कृष्णजीरकम् क्वाथमष्टावशेषं तु प्रसूतां पाययेत्स्त्रियम् शूलकासज्वरश्वासमूर्च्छाकम्पशिरोर्त्तिजित्", text: "bṛhatyativiṣā chinnā karkaṭaṃ kṛṣṇajīrakam kvāthamaṣṭāvaśeṣaṃ tu prasūtāṃ pāyayetstriyam śūlakāsajvaraśvāsamūrcchākampaśirorttijit" },
      { type: "verse", number: "52", sanskrit: "तत्र शीतपूर्वविषमज्वरे बृहत्क्षुद्रा दिक्वाथः क्षुद्रा धान्यकशुण्ठीभिर्गुडूचीमुस्तपद्मकैः रक्तचन्दनभूनिम्बपटोलवृषपौष्करैः", text: "tatra śītapūrvaviṣamajvare bṛhatkṣudrā dikvāthaḥ kṣudrā dhānyakaśuṇṭhībhirguḍūcīmustapadmakaiḥ raktacandanabhūnimbapaṭolavṛṣapauṣkaraiḥ" },
      { type: "verse", number: "53", sanskrit: "कटुकेन्द्रा यवारिष्टभार्ङ्गीपर्पटकैः समैः क्वाथं प्रातर्निषेवेत सर्वशीतज्वरच्छिदम्", text: "kaṭukendrā yavāriṣṭabhārṅgīparpaṭakaiḥ samaiḥ kvāthaṃ prātarniṣeveta sarvaśītajvaracchidam" },
      { type: "verse", number: "54", sanskrit: "मुस्ताक्षुद्रा मृताशुण्ठीधात्रीक्वाथः समाक्षिकः पिप्पलीचूर्णसंयुक्तो विषमज्वरनाशनः", text: "mustākṣudrā mṛtāśuṇṭhīdhātrīkvāthaḥ samākṣikaḥ pippalīcūrṇasaṃyukto viṣamajvaranāśanaḥ" },
      { type: "verse", number: "55", sanskrit: "पटोलेन्द्र यवादारुत्रिफलामुस्तगोस्तनैः मधुकामृतवासानां क्वाथं क्षौद्र युतं पिबेत्", text: "paṭolendra yavādārutriphalāmustagostanaiḥ madhukāmṛtavāsānāṃ kvāthaṃ kṣaudra yutaṃ pibet" },
      { type: "verse", number: "56", sanskrit: "सन्तते सतते चैव द्वितीयकतृतीयके एकाहिके वा विषमे दाहपूर्वे नवज्वरे", text: "santate satate caiva dvitīyakatṛtīyake ekāhike vā viṣame dāhapūrve navajvare" },
      { type: "verse", number: "57", sanskrit: "पटोलत्रिफलानिम्बद्रा क्षाशम्याकवासकैः क्वाथः सितामधुयुतो जयेदैकाहिकं ज्वरम्", text: "paṭolatriphalānimbadrā kṣāśamyākavāsakaiḥ kvāthaḥ sitāmadhuyuto jayedaikāhikaṃ jvaram" },
      { type: "verse", number: "58", sanskrit: "तृतीयकज्वरे गुडूच्यादिक्वाथः गुडूचीधान्यमुस्ताभिश्चन्दनोशीरनागरैः", text: "tṛtīyakajvare guḍūcyādikvāthaḥ guḍūcīdhānyamustābhiścandanośīranāgaraiḥ" },
      { type: "verse", number: "59", sanskrit: "कृतं क्वाथं पिबेत्क्षौद्र सितायुक्तं ज्वरातुरः तृतीयज्वरनाशाय तृष्णादाहनिवारणम्", text: "kṛtaṃ kvāthaṃ pibetkṣaudra sitāyuktaṃ jvarāturaḥ tṛtīyajvaranāśāya tṛṣṇādāhanivāraṇam" },
      { type: "verse", number: "60", sanskrit: "चातुर्थिकज्वरे देवदार्वादिक्वाथः देवदारुशिवावासाशालिपर्णीमहौषधैः चातुर्थिकज्वरे श्वासे कासे मन्दानले तथा धात्रीयुतं शृतं शीतं दद्यान्मधुसितायुतम्", text: "cāturthikajvare devadārvādikvāthaḥ devadāruśivāvāsāśāliparṇīmahauṣadhaiḥ cāturthikajvare śvāse kāse mandānale tathā dhātrīyutaṃ śṛtaṃ śītaṃ dadyānmadhusitāyutam" },
      { type: "verse", number: "61", sanskrit: "ज्वरातीसारे गुडूच्यादिक्वाथः गुडूचीधान्यकोशीरशुण्ठीबालकपर्पटैः बिल्वप्रतिविषापाठारक्तचन्दनवत्सकैः", text: "jvarātīsāre guḍūcyādikvāthaḥ guḍūcīdhānyakośīraśuṇṭhībālakaparpaṭaiḥ bilvaprativiṣāpāṭhāraktacandanavatsakaiḥ" },
      { type: "verse", number: "62", sanskrit: "किरातमुस्तेन्द्र यवः क्वथितं शिशिरं पिबेत् सक्षौद्रं रक्तपित्तघ्नं ज्वरातीसारनाशनम्", text: "kirātamustendra yavaḥ kvathitaṃ śiśiraṃ pibet sakṣaudraṃ raktapittaghnaṃ jvarātīsāranāśanam" },
      { type: "verse", number: "63", sanskrit: "नागरं कुटजो मुस्तं भूनिम्बातिविषाऽमृताः एभिः कृतं पिबेत्क्वाथं ज्वरातीसारनाशनम्", text: "nāgaraṃ kuṭajo mustaṃ bhūnimbātiviṣā'mṛtāḥ ebhiḥ kṛtaṃ pibetkvāthaṃ jvarātīsāranāśanam" },
      { type: "verse", number: "64", sanskrit: "धान्यबालक बिल्वाब्दनागरैः साधितं जलम् आमशूलहरं ग्राहि दीपनं पाचनं परम्", text: "dhānyabālaka bilvābdanāgaraiḥ sādhitaṃ jalam āmaśūlaharaṃ grāhi dīpanaṃ pācanaṃ param" },
      { type: "verse", number: "65", sanskrit: "धान्यनागरजः क्वाथः पाचनो दीपनस्तथा एरण्डमूलयुक्तश्च जयेदामानिलव्यथाम्", text: "dhānyanāgarajaḥ kvāthaḥ pācano dīpanastathā eraṇḍamūlayuktaśca jayedāmānilavyathām" },
      { type: "verse", number: "66", sanskrit: "सामरक्तातीसारे वत्सकादिक्वाथः वत्सकातिविषाबिल्वमुस्तबालकजः शृतः अतीसारं जयेत्सामं चिरजं रक्तशूलजित्", text: "sāmaraktātīsāre vatsakādikvāthaḥ vatsakātiviṣābilvamustabālakajaḥ śṛtaḥ atīsāraṃ jayetsāmaṃ cirajaṃ raktaśūlajit" },
      { type: "verse", number: "67", sanskrit: "ह्रीबेरदाडिमयुतैः कृतः क्वाथः समाक्षिकः", text: "hrīberadāḍimayutaiḥ kṛtaḥ kvāthaḥ samākṣikaḥ" },
      { type: "verse", number: "68", sanskrit: "पेयो मोचरसेनैव कुटजाष्टकसंज्ञकः अतीसाराञ्जयेद्दाहरक्तशूलामदुस्तरान्", text: "peyo mocarasenaiva kuṭajāṣṭakasaṃjñakaḥ atīsārāñjayeddāharaktaśūlāmadustarān" },
      { type: "verse", number: "69", sanskrit: "चिरजातीसारे ह्रीबेरादिक्वाथः ह्रीबेरधातकीलोध्रपाठालज्जालुवत्सकैः धान्यकातिविषामुस्तागुडूचीबिल्वनागरैः", text: "cirajātīsāre hrīberādikvāthaḥ hrīberadhātakīlodhrapāṭhālajjāluvatsakaiḥ dhānyakātiviṣāmustāguḍūcībilvanāgaraiḥ" },
      { type: "verse", number: "70", sanskrit: "कृतः कषायः शमयेदतीसारं चिरोत्थितम् अरोचकामशूलास्रज्वरघ्नः पाचनः स्मृतः", text: "kṛtaḥ kaṣāyaḥ śamayedatīsāraṃ cirotthitam arocakāmaśūlāsrajvaraghnaḥ pācanaḥ smṛtaḥ" },
      { type: "verse", number: "71", sanskrit: "धातकी बिल्वरोध्राणि बालकं गजपिप्पली एभिः कृतं शृतं शीतं शिशुभ्यः क्षौद्र संयुतम् प्रदद्यादवलेहं वा सर्वातीसारशान्तये", text: "dhātakī bilvarodhrāṇi bālakaṃ gajapippalī ebhiḥ kṛtaṃ śṛtaṃ śītaṃ śiśubhyaḥ kṣaudra saṃyutam pradadyādavalehaṃ vā sarvātīsāraśāntaye" },
      { type: "verse", number: "72", sanskrit: "वातजग्रहण्यां शालिपर्ण्यादिक्वाथः शालिपर्णीबलाबिल्वधान्यशुण्ठीकृतः शृतः आध्मानशूलसहितां वातजां ग्रहणीं जयेत्", text: "vātajagrahaṇyāṃ śāliparṇyādikvāthaḥ śāliparṇībalābilvadhānyaśuṇṭhīkṛtaḥ śṛtaḥ ādhmānaśūlasahitāṃ vātajāṃ grahaṇīṃ jayet" },
      { type: "verse", number: "73", sanskrit: "सामग्रहण्यां चातुर्भद्र कक्वाथः गुडूच्यतिविषाशुण्ठीमुस्तैः क्वाथः कृतो जयेत् आमानुषक्तां ग्रहणीं ग्राही पाचनदीपनः", text: "sāmagrahaṇyāṃ cāturbhadra kakvāthaḥ guḍūcyativiṣāśuṇṭhīmustaiḥ kvāthaḥ kṛto jayet āmānuṣaktāṃ grahaṇīṃ grāhī pācanadīpanaḥ" },
      { type: "verse", number: "74", sanskrit: "सर्वातिसारेष्विन्द्र यवादिक्वाथः यवधान्यपटोलानां क्वाथः सक्षौद्र शर्करः योज्यः सर्वातिसारेषु बिल्वाम्रास्थिभवस्तथा", text: "sarvātisāreṣvindra yavādikvāthaḥ yavadhānyapaṭolānāṃ kvāthaḥ sakṣaudra śarkaraḥ yojyaḥ sarvātisāreṣu bilvāmrāsthibhavastathā" },
      { type: "verse", number: "75", sanskrit: "त्रिफला देवदारुश्च मुस्ता मूषकपर्णिका शिग्रुरेतैः कृतः क्वाथः पिप्पलीचूर्णसंयुतः", text: "triphalā devadāruśca mustā mūṣakaparṇikā śigruretaiḥ kṛtaḥ kvāthaḥ pippalīcūrṇasaṃyutaḥ" },
      { type: "verse", number: "76", sanskrit: "विडङ्गचूर्णयुक्तश्च कृमिघ्नःकृमिरोगहा", text: "viḍaṅgacūrṇayuktaśca kṛmighnaḥkṛmirogahā" },
      { type: "verse", number: "77", sanskrit: "जयेन्मधुयुतः क्वाथः कामलां पाण्डुतां तथा", text: "jayenmadhuyutaḥ kvāthaḥ kāmalāṃ pāṇḍutāṃ tathā" },
      { type: "verse", number: "78", sanskrit: "पाण्डुशोथादौ पुनर्नवादिक्वाथः पुनर्नवाऽभयानिम्बदार्वीतिक्तापटोलकैः", text: "pāṇḍuśothādau punarnavādikvāthaḥ punarnavā'bhayānimbadārvītiktāpaṭolakaiḥ" },
      { type: "verse", number: "79", sanskrit: "गुडूचीनागरयुतैः क्वाथो गोमूत्रसंयुतः पाण्डुकासोदरश्वासशूलसर्वाङ्गशोथहा", text: "guḍūcīnāgarayutaiḥ kvātho gomūtrasaṃyutaḥ pāṇḍukāsodaraśvāsaśūlasarvāṅgaśothahā" },
      { type: "verse", number: "80", sanskrit: "वासाद्रा क्षाऽभयाक्वाथः पीतः सक्षौद्र शर्करः निहन्ति रक्तपित्तार्त्तिश्वासकासान्सुदारुणान्", text: "vāsādrā kṣā'bhayākvāthaḥ pītaḥ sakṣaudra śarkaraḥ nihanti raktapittārttiśvāsakāsānsudāruṇān" },
      { type: "verse", number: "81", sanskrit: "रक्तपित्तक्षयं कासं श्लेष्मपित्तज्वरं तथा केवलो वासकक्वाथः पीतः क्षौद्रे ण नाशयेत्", text: "raktapittakṣayaṃ kāsaṃ śleṣmapittajvaraṃ tathā kevalo vāsakakvāthaḥ pītaḥ kṣaudre ṇa nāśayet" },
      { type: "verse", number: "82", sanskrit: "वासाक्षुद्रा ऽमृताक्वाथः क्षौद्रे ण ज्वरकासहा कासघ्नःपिप्पलीचूर्णयुक्तः क्षुद्रा शृतस्तथा", text: "vāsākṣudrā 'mṛtākvāthaḥ kṣaudre ṇa jvarakāsahā kāsaghnaḥpippalīcūrṇayuktaḥ kṣudrā śṛtastathā" },
      { type: "verse", number: "83", sanskrit: "श्वासकासयोः क्षुद्रा दिक्वाथः क्षुद्रा कुलत्थवासाभिर्नागरेण च साधितः क्वाथः पुष्करचूर्णाढ्य श्वासकासौ निवारयेत्", text: "śvāsakāsayoḥ kṣudrā dikvāthaḥ kṣudrā kulatthavāsābhirnāgareṇa ca sādhitaḥ kvāthaḥ puṣkaracūrṇāḍhya śvāsakāsau nivārayet" },
      { type: "verse", number: "84", sanskrit: "रेणुकापिप्पलीक्वाथो हिङ्गुकल्केन संयुतः पानादेव हि पञ्चापि हिक्कां नाशयति क्षणात्", text: "reṇukāpippalīkvātho hiṅgukalkena saṃyutaḥ pānādeva hi pañcāpi hikkāṃ nāśayati kṣaṇāt" },
      { type: "verse", number: "85", sanskrit: "बिल्वत्वचोगुडूच्या वा क्वाथः क्षौद्रे ण संयुतः जयेत्त्रिदोषजां छर्दिं पर्पटः पित्तजां तथा", text: "bilvatvacoguḍūcyā vā kvāthaḥ kṣaudre ṇa saṃyutaḥ jayettridoṣajāṃ chardiṃ parpaṭaḥ pittajāṃ tathā" },
      { type: "verse", number: "86", sanskrit: "हिङ्गुपुष्करचूर्णाढ्यं दशमूलशृतं जयेत् गृध्रसीं केवलः क्वाथः शेफालीपत्रजस्तथा", text: "hiṅgupuṣkaracūrṇāḍhyaṃ daśamūlaśṛtaṃ jayet gṛdhrasīṃ kevalaḥ kvāthaḥ śephālīpatrajastathā" },
      { type: "verse", number: "87", sanskrit: "सप्तधातुगतवाते रास्नापञ्चकक्वाथः रास्नाऽमृतामहादारुनागरैरण्डजैः शृतम् सप्तधातुगते वाते सामे सर्वाङ्गजे पिबेत्", text: "saptadhātugatavāte rāsnāpañcakakvāthaḥ rāsnā'mṛtāmahādārunāgarairaṇḍajaiḥ śṛtam saptadhātugate vāte sāme sarvāṅgaje pibet" },
      { type: "verse", number: "88", sanskrit: "जङ्घावातादौ रास्नासप्तकक्वाथः रास्नागोक्षुरकैरण्डदेवदारुपुनर्नवा गुडूच्यारग्वधश्चैव क्वाथमेषां विपाचयेत्", text: "jaṅghāvātādau rāsnāsaptakakvāthaḥ rāsnāgokṣurakairaṇḍadevadārupunarnavā guḍūcyāragvadhaścaiva kvāthameṣāṃ vipācayet" },
      { type: "verse", number: "89", sanskrit: "शुण्ठीचूर्णेन संयुक्तं पिबेज्जङ्घाकटीग्रहे पार्श्वपृष्ठोरुपीडायामामवाते सुदुस्तरे", text: "śuṇṭhīcūrṇena saṃyuktaṃ pibejjaṅghākaṭīgrahe pārśvapṛṣṭhorupīḍāyāmāmavāte sudustare" },
      { type: "verse", number: "90", sanskrit: "सर्ववातरोगे महारास्नादिक्वाथः रास्ना द्विगुणभागा स्यादेकभागास्ततः परे धन्वयासबलैरण्डदेवदारुशटीवचाः", text: "sarvavātaroge mahārāsnādikvāthaḥ rāsnā dviguṇabhāgā syādekabhāgāstataḥ pare dhanvayāsabalairaṇḍadevadāruśaṭīvacāḥ" },
      { type: "verse", number: "91", sanskrit: "वासको नागरं पथ्या चव्या मुस्ता पुनर्नवा गुडूची वृद्धदारुश्च शतपुष्पा च गोक्षुरः", text: "vāsako nāgaraṃ pathyā cavyā mustā punarnavā guḍūcī vṛddhadāruśca śatapuṣpā ca gokṣuraḥ" },
      { type: "verse", number: "92", sanskrit: "अश्वगन्धा प्रतिविषा कृतमालः शतावरी कृष्णा सहचरश्चैव धान्यकं बृहतीद्वयम्", text: "aśvagandhā prativiṣā kṛtamālaḥ śatāvarī kṛṣṇā sahacaraścaiva dhānyakaṃ bṛhatīdvayam" },
      { type: "verse", number: "93", sanskrit: "एभिः कृतं पिबेत्क्वाथं शुण्ठीचूर्णेन संयुतम् कृष्णाचूर्णेन वा योगराजगुग्गुलुनाऽथवा", text: "ebhiḥ kṛtaṃ pibetkvāthaṃ śuṇṭhīcūrṇena saṃyutam kṛṣṇācūrṇena vā yogarājaguggulunā'thavā" },
      { type: "verse", number: "94", sanskrit: "अजमोदादिना वाऽपि तैलेनैरण्डजेन वा सर्वाङ्गकम्पे कुब्जत्वे पक्षाघातेऽवबाहुके", text: "ajamodādinā vā'pi tailenairaṇḍajena vā sarvāṅgakampe kubjatve pakṣāghāte'vabāhuke" },
      { type: "verse", number: "95", sanskrit: "गृध्रस्यामामवाते च श्लीपदे चापतानके अन्त्रवृद्धौ तथाऽध्माने जङ्घाजानुगतेऽदिते", text: "gṛdhrasyāmāmavāte ca ślīpade cāpatānake antravṛddhau tathā'dhmāne jaṅghājānugate'dite" },
      { type: "verse", number: "96", sanskrit: "शुक्रामये मेढ्ररोगे वन्ध्यायोन्यामयेषु च महारास्नादिराख्यातो ब्रह्मणा गर्भकारणम्", text: "śukrāmaye meḍhraroge vandhyāyonyāmayeṣu ca mahārāsnādirākhyāto brahmaṇā garbhakāraṇam" },
      { type: "verse", number: "97", sanskrit: "स्तनादिगतवाते एरण्डसप्तकक्वाथः एरण्डो बीजपूरश्च गोक्षुरो बृहतीद्वयम् अश्मभेदस्तथा बिल्व एतन्मूलैः कृतः शृतः", text: "stanādigatavāte eraṇḍasaptakakvāthaḥ eraṇḍo bījapūraśca gokṣuro bṛhatīdvayam aśmabhedastathā bilva etanmūlaiḥ kṛtaḥ śṛtaḥ" },
      { type: "verse", number: "98", sanskrit: "एरण्डतैलहिङ्ग्वाढ्यः सयवक्षारसैन्धवः स्तनस्कन्धकटी मेढ्रहृदयोत्थां व्यथां जयेत्", text: "eraṇḍatailahiṅgvāḍhyaḥ sayavakṣārasaindhavaḥ stanaskandhakaṭī meḍhrahṛdayotthāṃ vyathāṃ jayet" },
      { type: "verse", number: "99", sanskrit: "वातशूले नागरादीन्द्र यवयोः क्वाथौ नागरैरण्डजः क्वाथः क्वाथ इन्द्र यवस्य च हिंगुसौवर्चलोपेतो वातशूलनिवारणः", text: "vātaśūle nāgarādīndra yavayoḥ kvāthau nāgarairaṇḍajaḥ kvāthaḥ kvātha indra yavasya ca hiṃgusauvarcalopeto vātaśūlanivāraṇaḥ" },
      { type: "verse", number: "100", sanskrit: "त्रिफलाऽरग्वधक्वाथः शर्कराक्षौद्र संयुतः रक्तपित्तहरो दाहपित्तशूलनिवारणः", text: "triphalā'ragvadhakvāthaḥ śarkarākṣaudra saṃyutaḥ raktapittaharo dāhapittaśūlanivāraṇaḥ" },
      { type: "verse", number: "101", sanskrit: "एरण्डमूलं द्विपलं जलेऽष्टगुणिते पचेत् तत्क्वाथो यावशूकाढ्यः पार्श्वहृत्कफशूलहा", text: "eraṇḍamūlaṃ dvipalaṃ jale'ṣṭaguṇite pacet tatkvātho yāvaśūkāḍhyaḥ pārśvahṛtkaphaśūlahā" },
      { type: "verse", number: "102", sanskrit: "दशमूलकृतः क्वाथः सयवक्षारसैन्धवः हृद्रो गगुल्मशूलानि कासं श्वासं च नाशयेत्", text: "daśamūlakṛtaḥ kvāthaḥ sayavakṣārasaindhavaḥ hṛdro gagulmaśūlāni kāsaṃ śvāsaṃ ca nāśayet" },
      { type: "verse", number: "103", sanskrit: "मूत्रकृच्छ्रादौ हरीतक्यादिक्वाथः हरीतकीदुरालम्भाकृतमालकगोक्षुरैः पाषाणभेदसहितैः क्वाथो माक्षिकसंयुतः विबन्धे मूत्रकृच्छ्रे च सदाहे सरुजे हितः", text: "mūtrakṛcchrādau harītakyādikvāthaḥ harītakīdurālambhākṛtamālakagokṣuraiḥ pāṣāṇabhedasahitaiḥ kvātho mākṣikasaṃyutaḥ vibandhe mūtrakṛcchre ca sadāhe saruje hitaḥ" },
      { type: "verse", number: "104", sanskrit: "अश्मरीरोगादौ वीरतर्वादिगणक्वाथः वीरतरुर्वृक्षवन्दा काशः सहचरत्रयम् कुशद्वयं नलो गुन्द्रा  बकपुष्पोऽग्निमन्थकः", text: "aśmarīrogādau vīratarvādigaṇakvāthaḥ vīratarurvṛkṣavandā kāśaḥ sahacaratrayam kuśadvayaṃ nalo gundrā  bakapuṣpo'gnimanthakaḥ" },
      { type: "verse", number: "105", sanskrit: "मूर्वा पाषाणभेदश्च स्योनाको गोक्षुरस्तथा अपामार्गश्च कमलं ब्राह्मी चेति गणो वरः", text: "mūrvā pāṣāṇabhedaśca syonāko gokṣurastathā apāmārgaśca kamalaṃ brāhmī ceti gaṇo varaḥ" },
      { type: "verse", number: "106", sanskrit: "वीरतर्वादिरित्युक्तः शर्कराऽश्मरिकृच्छ्रहा मूत्राघातं वायुरोगान्नाशयेन्निखिलानपि", text: "vīratarvādirityuktaḥ śarkarā'śmarikṛcchrahā mūtrāghātaṃ vāyurogānnāśayennikhilānapi" },
      { type: "verse", number: "107", sanskrit: "शर्कराऽश्मर्यादौ एलादिक्वाथः एलामधुकगोकण्टरेणुकैरण्डवासकाः", text: "śarkarā'śmaryādau elādikvāthaḥ elāmadhukagokaṇṭareṇukairaṇḍavāsakāḥ" },
      { type: "verse", number: "108", sanskrit: "कृष्णाऽश्मभेदसहिताः क्वाथ एषां सुसाधितः शिलाजतुयुतः पेयः शर्कराऽश्मरिकृच्छ्रहा", text: "kṛṣṇā'śmabhedasahitāḥ kvātha eṣāṃ susādhitaḥ śilājatuyutaḥ peyaḥ śarkarā'śmarikṛcchrahā" },
      { type: "verse", number: "109", sanskrit: "मूत्रकृच्छ्रादौ गोक्षुरक्वाथः समूलगोक्षुरक्वाथः सितामाक्षिकसंयुतः नाशयेन्मूत्रकृच्छ्राणि तथा चोष्णसमीरणम्", text: "mūtrakṛcchrādau gokṣurakvāthaḥ samūlagokṣurakvāthaḥ sitāmākṣikasaṃyutaḥ nāśayenmūtrakṛcchrāṇi tathā coṣṇasamīraṇam" },
      { type: "verse", number: "110", sanskrit: "वरादार्व्यब्ददारूणां क्वाथः क्षौद्रे ण मेहहा वत्सकत्रिफलादार्वीमुस्तको बीजकस्तथा", text: "varādārvyabdadārūṇāṃ kvāthaḥ kṣaudre ṇa mehahā vatsakatriphalādārvīmustako bījakastathā" },
      { type: "verse", number: "111", sanskrit: "फलत्रिकाब्ददार्वीणां विशालायाः शृतं पिबेत् निशाकल्कयुतं सर्वप्रमेहविनिवृत्तये", text: "phalatrikābdadārvīṇāṃ viśālāyāḥ śṛtaṃ pibet niśākalkayutaṃ sarvapramehavinivṛttaye" },
      { type: "verse", number: "112", sanskrit: "दार्वी रसाञ्जनं मुस्तं भल्लातः श्रीफलं वृषः कैरातश्च पिबेदेषां क्वाथं शीतं समाक्षिकम् जयेत्सशूलं प्रदरं पीतश्वेतासितारुणम्", text: "dārvī rasāñjanaṃ mustaṃ bhallātaḥ śrīphalaṃ vṛṣaḥ kairātaśca pibedeṣāṃ kvāthaṃ śītaṃ samākṣikam jayetsaśūlaṃ pradaraṃ pītaśvetāsitāruṇam" },
      { type: "verse", number: "113", sanskrit: "योनिरोगव्रणादौ न्यग्रोधादिक्वाथः न्यग्रोधप्लक्षकोशाम्रवेतसा बदरी तुणिः मधुयष्टी प्रियालश्च लोध्रद्वयमुदुम्बरः", text: "yonirogavraṇādau nyagrodhādikvāthaḥ nyagrodhaplakṣakośāmravetasā badarī tuṇiḥ madhuyaṣṭī priyālaśca lodhradvayamudumbaraḥ" },
      { type: "verse", number: "114", sanskrit: "पिप्पलश्च मधूकश्च तथा पारिसपिप्पलः शल्लकी तिन्दुकी जम्बूद्वयमाम्रतरुः शिवा", text: "pippalaśca madhūkaśca tathā pārisapippalaḥ śallakī tindukī jambūdvayamāmrataruḥ śivā" },
      { type: "verse", number: "115", sanskrit: "कदम्बककुभौ चैव भल्लातकफलानि च न्यग्रोधादिगणक्वाथं यथालाभं च कारयेत्", text: "kadambakakubhau caiva bhallātakaphalāni ca nyagrodhādigaṇakvāthaṃ yathālābhaṃ ca kārayet" },
      { type: "verse", number: "116", sanskrit: "अयं क्वाथो महाग्राही व्रण्यो भग्नं च साधयेत् योनिदोषहरो दाहमेदोमेहविषापहः", text: "ayaṃ kvātho mahāgrāhī vraṇyo bhagnaṃ ca sādhayet yonidoṣaharo dāhamedomehaviṣāpahaḥ" },
      { type: "verse", number: "117", sanskrit: "बिल्वोऽग्निमन्थः स्योनाकः काश्मरी पाटला तथा क्वाथ एषां जयेन्मेदोदोषं क्षौद्रे ण संयुतः", text: "bilvo'gnimanthaḥ syonākaḥ kāśmarī pāṭalā tathā kvātha eṣāṃ jayenmedodoṣaṃ kṣaudre ṇa saṃyutaḥ" },
      { type: "verse", number: "118", sanskrit: "क्षौद्रे ण त्रिफलाक्वाथः पीतो मेदोहरः स्मृतः शीतीभूतं तथोष्णाम्बु मेदोहृत्क्षौद्र संयुतम्", text: "kṣaudre ṇa triphalākvāthaḥ pīto medoharaḥ smṛtaḥ śītībhūtaṃ tathoṣṇāmbu medohṛtkṣaudra saṃyutam" },
      { type: "verse", number: "119", sanskrit: "चव्यचित्रकविश्वानां साधितो देवदारुणा क्वाथस्त्रिवृच्चूर्णयुतो गोमूत्रेणोदराञ्जयेत्", text: "cavyacitrakaviśvānāṃ sādhito devadāruṇā kvāthastrivṛccūrṇayuto gomūtreṇodarāñjayet" },
      { type: "verse", number: "120", sanskrit: "गोमूत्रगुग्गुलुयुतः क्वाथः शोथोदरापहः", text: "gomūtragugguluyutaḥ kvāthaḥ śothodarāpahaḥ" },
      { type: "verse", number: "121", sanskrit: "यकृत्प्लीहगुल्मोदरे पथ्याऽदिक्वाथः पथ्यारोहितकक्वाथं यवक्षारकणायुतम् पिबेत्प्रातर्यकृत्प्लीहगुल्मोदरनिवृत्तये", text: "yakṛtplīhagulmodare pathyā'dikvāthaḥ pathyārohitakakvāthaṃ yavakṣārakaṇāyutam pibetprātaryakṛtplīhagulmodaranivṛttaye" },
      { type: "verse", number: "122", sanskrit: "पुनर्नवा दारुनिशा निशा शुण्ठी हरीतकी", text: "punarnavā dāruniśā niśā śuṇṭhī harītakī" },
      { type: "verse", number: "123", sanskrit: "गुडूची चित्रको भार्ङ्गी देवदारु च तैः शृतः पाणिपादोदरमुखप्राप्तं शोफं निवारयेत्", text: "guḍūcī citrako bhārṅgī devadāru ca taiḥ śṛtaḥ pāṇipādodaramukhaprāptaṃ śophaṃ nivārayet" },
      { type: "verse", number: "124", sanskrit: "फलत्रिकोद्भवं क्वाथं गोमूत्रेणैव पाययेत् वातश्लेष्मकृतं हन्ति शोथं वृषणसम्भवम्", text: "phalatrikodbhavaṃ kvāthaṃ gomūtreṇaiva pāyayet vātaśleṣmakṛtaṃ hanti śothaṃ vṛṣaṇasambhavam" },
      { type: "verse", number: "125", sanskrit: "रास्नाऽमृताबलायष्टीगोकण्टैरण्डजः शृतः एरण्डतैलसंयुक्तो वृद्धिमन्त्रभवां जयेत्", text: "rāsnā'mṛtābalāyaṣṭīgokaṇṭairaṇḍajaḥ śṛtaḥ eraṇḍatailasaṃyukto vṛddhimantrabhavāṃ jayet" },
      { type: "verse", number: "126", sanskrit: "गण्डामालायां काञ्चनारत्वक्क्वाथः काञ्चनारत्वचः क्वाथः शुण्ठीचूर्णेन नाशयेत् गण्डमालां तथा क्वाथः क्षौद्रे ण वरुणत्वचः", text: "gaṇḍāmālāyāṃ kāñcanāratvakkvāthaḥ kāñcanāratvacaḥ kvāthaḥ śuṇṭhīcūrṇena nāśayet gaṇḍamālāṃ tathā kvāthaḥ kṣaudre ṇa varuṇatvacaḥ" },
      { type: "verse", number: "127", sanskrit: "श्लीपदमेदोरोगयोः शाखोटकत्वक्क्वाथः शाखोटवल्कलक्वाथं गोम्रूत्रेण युतं पिबेत् श्लीपदानां विनाशाय मेदोदोषनिवृत्तये", text: "ślīpadamedorogayoḥ śākhoṭakatvakkvāthaḥ śākhoṭavalkalakvāthaṃ gomrūtreṇa yutaṃ pibet ślīpadānāṃ vināśāya medodoṣanivṛttaye" },
      { type: "verse", number: "128", sanskrit: "पुनर्नवावरुणयोः क्वाथोऽन्तर्विद्र धीञ्जयेत् तथा शिग्रुभवः क्वाथो हिङ्गुसैन्धवसंयुतः", text: "punarnavāvaruṇayoḥ kvātho'ntarvidra dhīñjayet tathā śigrubhavaḥ kvātho hiṅgusaindhavasaṃyutaḥ" },
      { type: "verse", number: "129", sanskrit: "अपक्वान्तर्विद्र धौ वरुणादिगणक्वाथः वरुणादिगणक्वाथमपक्वे मध्यविद्र धौ ऊषकादिरजोयुक्तं पिबेच्छमनहेतवे", text: "apakvāntarvidra dhau varuṇādigaṇakvāthaḥ varuṇādigaṇakvāthamapakve madhyavidra dhau ūṣakādirajoyuktaṃ pibecchamanahetave" },
      { type: "verse", number: "130", sanskrit: "वरुणो बकपुष्पश्च बिल्वापामार्गचित्रकाः अग्निमन्थद्वयं शिग्रुद्वयं च बृहतीद्वयम्", text: "varuṇo bakapuṣpaśca bilvāpāmārgacitrakāḥ agnimanthadvayaṃ śigrudvayaṃ ca bṛhatīdvayam" },
      { type: "verse", number: "131", sanskrit: "सैरेयकत्रयं मूर्वा मेषशृङ्गी किरातकः अजशृङ्गी च बिम्बी च करञ्जश्च शतावरी", text: "saireyakatrayaṃ mūrvā meṣaśṛṅgī kirātakaḥ ajaśṛṅgī ca bimbī ca karañjaśca śatāvarī" },
      { type: "verse", number: "132", sanskrit: "वरुणादिगणक्वाथः कफमेदोहरः स्मृतः हन्ति गुल्मं शिरः शूलन्तथाभ्यन्तरविद्र धीन्", text: "varuṇādigaṇakvāthaḥ kaphamedoharaḥ smṛtaḥ hanti gulmaṃ śiraḥ śūlantathābhyantaravidra dhīn" },
      { type: "verse", number: "133", sanskrit: "खदिरत्रिफलाक्वाथो महिषीघृतसंयुतः विडङ्गचूर्णयुक्तश्च भगन्दरविनाशनः", text: "khadiratriphalākvātho mahiṣīghṛtasaṃyutaḥ viḍaṅgacūrṇayuktaśca bhagandaravināśanaḥ" },
      { type: "verse", number: "134", sanskrit: "क्वाथः पीतो जयेत्सर्वानुपदंशान्सगुग्गुलुः", text: "kvāthaḥ pīto jayetsarvānupadaṃśānsagugguluḥ" },
      { type: "verse", number: "135", sanskrit: "अमृतैरण्डवासानां क्वाथ एरण्डतैलयुक् पीतः सर्वाङ्गसञ्च्रारिवातरक्तं जयेद् ध्रुवम्", text: "amṛtairaṇḍavāsānāṃ kvātha eraṇḍatailayuk pītaḥ sarvāṅgasañcrārivātaraktaṃ jayed dhruvam" },
      { type: "verse", number: "136", sanskrit: "पटोलं त्रिफला तिक्ता गुडूची च शतावरी एतत्क्वाथो जयेत्पीतो वातास्रं दाहसंयुतम्", text: "paṭolaṃ triphalā tiktā guḍūcī ca śatāvarī etatkvātho jayetpīto vātāsraṃ dāhasaṃyutam" },
      { type: "verse", number: "137", sanskrit: "श्वेतकुष्ठेऽवल्गुजचूर्णयुग्धात्र्! यादिक्वाथः क्वाथोऽवल्गुजचूर्णाढ्यो धात्रीखदिरसारयोः जयेत्सुशीलितो नित्यं श्वित्रं पथ्याशिनां नृणाम्", text: "śvetakuṣṭhe'valgujacūrṇayugdhātr! yādikvāthaḥ kvātho'valgujacūrṇāḍhyo dhātrīkhadirasārayoḥ jayetsuśīlito nityaṃ śvitraṃ pathyāśināṃ nṛṇām" },
      { type: "verse", number: "138", sanskrit: "वातरक्तकुष्ठादौ लघुमञ्जिष्ठाऽदिक्वाथः मञ्जिष्ठा त्रिफला तिक्ता वचा दारुनिशाऽमृता निम्बश्चैषां कृतः क्वाथो वातरक्तविनाशनः पामाकपालिकाकुष्ठरक्तमण्डलजिन्मतः", text: "vātaraktakuṣṭhādau laghumañjiṣṭhā'dikvāthaḥ mañjiṣṭhā triphalā tiktā vacā dāruniśā'mṛtā nimbaścaiṣāṃ kṛtaḥ kvātho vātaraktavināśanaḥ pāmākapālikākuṣṭharaktamaṇḍalajinmataḥ" },
      { type: "verse", number: "139", sanskrit: "सर्वकुष्ठे बृहन्मञ्जिष्ठादिक्वाथः मञ्जिष्ठामुस्तकुटजगुडूचीकुष्ठनागरैः भार्ङ्गीक्षुद्रा वचानिम्बनिशाद्वयफलत्रिकैः", text: "sarvakuṣṭhe bṛhanmañjiṣṭhādikvāthaḥ mañjiṣṭhāmustakuṭajaguḍūcīkuṣṭhanāgaraiḥ bhārṅgīkṣudrā vacānimbaniśādvayaphalatrikaiḥ" },
      { type: "verse", number: "140", sanskrit: "शतावरीत्रायमाणाकृष्णेन्द्र यववासकैः", text: "śatāvarītrāyamāṇākṛṣṇendra yavavāsakaiḥ" },
      { type: "verse", number: "141", sanskrit: "त्रिवृद्वरुणकैरातवाकुचीकृतमालकैः", text: "trivṛdvaruṇakairātavākucīkṛtamālakaiḥ" },
      { type: "verse", number: "142", sanskrit: "इन्द्र वारुणिकानन्तासारिवापर्पटैः समैः", text: "indra vāruṇikānantāsārivāparpaṭaiḥ samaiḥ" },
      { type: "verse", number: "143", sanskrit: "एमिः कृतं पिबेत्क्वाथं कणागुग्गुलुसंयुतम् अष्टादशसु कुष्ठेषु वातरक्तार्दिते तथा", text: "emiḥ kṛtaṃ pibetkvāthaṃ kaṇāguggulusaṃyutam aṣṭādaśasu kuṣṭheṣu vātaraktārdite tathā" },
      { type: "verse", number: "144", sanskrit: "उपदंशे श्लीपदे च प्रसुप्तौ पक्षघातके मेदोदोषे नेत्ररोगे मञ्जिष्ठादिः प्रशस्यते", text: "upadaṃśe ślīpade ca prasuptau pakṣaghātake medodoṣe netraroge mañjiṣṭhādiḥ praśasyate" },
      { type: "verse", number: "145", sanskrit: "शिरोरोगे नेत्ररोगादौ च पथ्यादिषडङ्गक्वाथः पथ्याऽक्षधात्रीभूनिम्बनिशानिम्बामृतायुतैः", text: "śiroroge netrarogādau ca pathyādiṣaḍaṅgakvāthaḥ pathyā'kṣadhātrībhūnimbaniśānimbāmṛtāyutaiḥ" },
      { type: "verse", number: "146", sanskrit: "कृतः क्वाथः षडङ्गोऽय सगुडः शीर्षशूलहृत् भ्रूशङ्खकर्णशूलानि तथाऽधशिरसो रुजम्", text: "kṛtaḥ kvāthaḥ ṣaḍaṅgo'ya saguḍaḥ śīrṣaśūlahṛt bhrūśaṅkhakarṇaśūlāni tathā'dhaśiraso rujam" },
      { type: "verse", number: "147", sanskrit: "सूर्यावर्त्तं शङ्खकं च दन्तपातं च तद्रुजम् नक्तान्ध्यं पटलं शुक्रं चक्षुःपीडां व्यपोहति", text: "sūryāvarttaṃ śaṅkhakaṃ ca dantapātaṃ ca tadrujam naktāndhyaṃ paṭalaṃ śukraṃ cakṣuḥpīḍāṃ vyapohati" },
      { type: "verse", number: "148", sanskrit: "भूनिम्बनिम्बकटुकापटोलत्रिफलाऽम्बुदैः", text: "bhūnimbanimbakaṭukāpaṭolatriphalā'mbudaiḥ" },
      { type: "verse", number: "149", sanskrit: "यवकालिङ्गकुटजैः क्वाथः सर्वाक्षिरोगहा वैस्वर्यं पीनसं श्वासं नाशयेदुरसः क्षतम्", text: "yavakāliṅgakuṭajaiḥ kvāthaḥ sarvākṣirogahā vaisvaryaṃ pīnasaṃ śvāsaṃ nāśayedurasaḥ kṣatam" },
      { type: "verse", number: "150", sanskrit: "अमृतात्रिफलाक्वाथः पिप्पलीचूर्णसंयुतः सक्षौद्र ः! शीलितो नित्यं सर्वनेत्रव्यथां जयेत्", text: "amṛtātriphalākvāthaḥ pippalīcūrṇasaṃyutaḥ sakṣaudra ḥ! śīlito nityaṃ sarvanetravyathāṃ jayet" },
      { type: "verse", number: "151", sanskrit: "व्रणक्षालनादौ पञ्चवल्कलक्वाथः अश्वत्थोदुम्बरप्लक्षवटवेतसजं शृतम् व्रणशोथोपदंशानां नाशनं क्षालनात्स्मृतम्", text: "vraṇakṣālanādau pañcavalkalakvāthaḥ aśvatthodumbaraplakṣavaṭavetasajaṃ śṛtam vraṇaśothopadaṃśānāṃ nāśanaṃ kṣālanātsmṛtam" },
      { type: "verse", number: "152", sanskrit: "प्रमथ्या प्रोच्यते द्र व्यपलात्कल्कीकृताच्छृतात् तोयेऽष्टगुणिते यस्याः पानमाहुः पलद्वयम्", text: "pramathyā procyate dra vyapalātkalkīkṛtācchṛtāt toye'ṣṭaguṇite yasyāḥ pānamāhuḥ paladvayam" },
      { type: "verse", number: "153", sanskrit: "रक्तातिसारे मुस्तकादिप्रमथ्या मुस्तकेन्द्र यवैः सिद्धा प्रमथ्या द्विपलोन्मिता सुशीता मधुसंयुक्ता रक्तातीसारनाशिनी", text: "raktātisāre mustakādipramathyā mustakendra yavaiḥ siddhā pramathyā dvipalonmitā suśītā madhusaṃyuktā raktātīsāranāśinī" },
      { type: "verse", number: "154", sanskrit: "साध्यं चतुष्पलं द्र व्यं चतुःषष्टिपले जले तत्क्वाथेनार्धशिष्टेन यवागूं साधयेद्घनाम्", text: "sādhyaṃ catuṣpalaṃ dra vyaṃ catuḥṣaṣṭipale jale tatkvāthenārdhaśiṣṭena yavāgūṃ sādhayedghanām" },
      { type: "verse", number: "155", sanskrit: "आम्राम्रातकजम्बूत्वक्कषाये विपचेद् बुधः यवागूं शालिभिर्युक्तां तां भुक्त्वा ग्रहणीं जयेत्", text: "āmrāmrātakajambūtvakkaṣāye vipaced budhaḥ yavāgūṃ śālibhiryuktāṃ tāṃ bhuktvā grahaṇīṃ jayet" },
      { type: "verse", number: "156", sanskrit: "कल्कद्र व्यपलं शुण्ठी पिप्पली चार्धकार्षिकी वारिप्रस्थेन विपचेत्स द्र वो यूष उच्यते", text: "kalkadra vyapalaṃ śuṇṭhī pippalī cārdhakārṣikī vāriprasthena vipacetsa dra vo yūṣa ucyate" },
      { type: "verse", number: "157", sanskrit: "कुलत्थयवकोलैश्च मुद्गैर्मूलकग्रन्थिकैः शुण्ठीधान्याकयुक्तैश्च यूषः श्लेष्मानिलापहः", text: "kulatthayavakolaiśca mudgairmūlakagranthikaiḥ śuṇṭhīdhānyākayuktaiśca yūṣaḥ śleṣmānilāpahaḥ" },
      { type: "verse", number: "158", sanskrit: "सप्तमुष्टिक इत्येष सन्निपातज्वरं जयेत् आमवातहरः कण्ठहृद्वक्त्राणां विशोधनः", text: "saptamuṣṭika ityeṣa sannipātajvaraṃ jayet āmavātaharaḥ kaṇṭhahṛdvaktrāṇāṃ viśodhanaḥ" },
      { type: "verse", number: "159", sanskrit: "क्षुण्णं द्र व्यपलं साध्यं चतुःषष्टिपले जले अर्द्धशिष्टं च तद्देयं पाने भक्तादिसंविधौ", text: "kṣuṇṇaṃ dra vyapalaṃ sādhyaṃ catuḥṣaṣṭipale jale arddhaśiṣṭaṃ ca taddeyaṃ pāne bhaktādisaṃvidhau" },
      { type: "verse", number: "160", sanskrit: "जलं शृतं हिमं पेयं पिपासाज्वरनाशनम्", text: "jalaṃ śṛtaṃ himaṃ peyaṃ pipāsājvaranāśanam" },
      { type: "verse", number: "161", sanskrit: "अष्टमेनांशशेषेण चतुर्थेनार्धकेन वा अथवा क्वथनेनैव सिद्धमुष्णोदकं वदेत्", text: "aṣṭamenāṃśaśeṣeṇa caturthenārdhakena vā athavā kvathanenaiva siddhamuṣṇodakaṃ vadet" },
      { type: "verse", number: "162", sanskrit: "श्लेष्मामवातमेदोघ्नं बस्तिशोधनदीपनम् कासश्वासज्वरहरं पीतमुष्णोदकं निशि", text: "śleṣmāmavātamedoghnaṃ bastiśodhanadīpanam kāsaśvāsajvaraharaṃ pītamuṣṇodakaṃ niśi" },
      { type: "verse", number: "163", sanskrit: "क्षीरमष्टगुणं द्र व्यात्क्षीरान्नीरं चतुर्गुणम् क्षीरावशेषं तत्पीतं शूलमामोद्भवं जयेत्", text: "kṣīramaṣṭaguṇaṃ dra vyātkṣīrānnīraṃ caturguṇam kṣīrāvaśeṣaṃ tatpītaṃ śūlamāmodbhavaṃ jayet" },
      { type: "verse", number: "164", sanskrit: "सिर्वज्वराणां जीर्णानां क्षीरं भैषज्यमुत्तमम् श्वासात्कासाच्छिरः शूलात्पार्श्वशूलात्सपीनसात् मुच्यते ज्वरितः पीत्वा पञ्चमूलीशृतं पयः", text: "sirvajvarāṇāṃ jīrṇānāṃ kṣīraṃ bhaiṣajyamuttamam śvāsātkāsācchiraḥ śūlātpārśvaśūlātsapīnasāt mucyate jvaritaḥ pītvā pañcamūlīśṛtaṃ payaḥ" },
      { type: "verse", number: "165", sanskrit: "वर्चोमूत्रविबन्धघ्नं कफज्वरहरं पयः", text: "varcomūtravibandhaghnaṃ kaphajvaraharaṃ payaḥ" },
      { type: "verse", number: "166", sanskrit: "अन्नप्रक्रिया तत्र यवागूकृशरासाधनविधिः अथान्नप्रक्रियाऽत्रैव प्रोच्यते नातिविस्तरा यवागूः षड्गुणजले सिद्धा स्यात्कृशरा घना", text: "annaprakriyā tatra yavāgūkṛśarāsādhanavidhiḥ athānnaprakriyā'traiva procyate nātivistarā yavāgūḥ ṣaḍguṇajale siddhā syātkṛśarā ghanā" },
      { type: "verse", number: "167", sanskrit: "तण्डुलैर्मुद्गमाषैश्च तिलैर्वा साधिता हिता यवागूर्ग्राहिणीबल्या तर्पणी वातनाशिनी", text: "taṇḍulairmudgamāṣaiśca tilairvā sādhitā hitā yavāgūrgrāhiṇībalyā tarpaṇī vātanāśinī" },
      { type: "verse", number: "168", sanskrit: "विलेपी घनसिक्था स्यात्सिद्धा नीरे चतुर्गुणे बृंहणी तर्पणी हृद्या मधुरा पित्तनाशिनी", text: "vilepī ghanasikthā syātsiddhā nīre caturguṇe bṛṃhaṇī tarpaṇī hṛdyā madhurā pittanāśinī" },
      { type: "verse", number: "169", sanskrit: "द्र वाधिका स्वल्पसिक्था चतुर्दशगुणे जले सिद्धा पेया बुधैर्ज्ञेया यूषः किञ्चिद् घनः स्मृतः", text: "dra vādhikā svalpasikthā caturdaśaguṇe jale siddhā peyā budhairjñeyā yūṣaḥ kiñcid ghanaḥ smṛtaḥ" },
      { type: "verse", number: "170", sanskrit: "पेया लघुतराज्ञेया ग्राहिणी धातुपुष्टिदा यूषो बल्यस्ततः कण्ठ्यो लघुपाकः कफापहः", text: "peyā laghutarājñeyā grāhiṇī dhātupuṣṭidā yūṣo balyastataḥ kaṇṭhyo laghupākaḥ kaphāpahaḥ" },
      { type: "verse", number: "171", sanskrit: "जले चतुर्दशगुणे तण्डुलानां चतुष्पलम् विपचेत्स्रावयेन्मण्डं स भक्तो मधुरो लघुः", text: "jale caturdaśaguṇe taṇḍulānāṃ catuṣpalam vipacetsrāvayenmaṇḍaṃ sa bhakto madhuro laghuḥ" },
      { type: "verse", number: "172", sanskrit: "नीरे चतुर्दशगुणे सिद्धो मण्डस्त्वसिक्थकः शुण्ठीसैन्धवसंयुक्तः पाचनो दीपनः परः", text: "nīre caturdaśaguṇe siddho maṇḍastvasikthakaḥ śuṇṭhīsaindhavasaṃyuktaḥ pācano dīpanaḥ paraḥ" },
      { type: "verse", number: "173", sanskrit: "भृष्टश्च हिङ्गुतैलाभ्यां स मण्डोऽष्टगुणः स्मृतः", text: "bhṛṣṭaśca hiṅgutailābhyāṃ sa maṇḍo'ṣṭaguṇaḥ smṛtaḥ" },
      { type: "verse", number: "174", sanskrit: "दीपनः प्राणदो बस्तिशोधनो रक्तवर्धनः ज्वरजित्सर्वदोषघ्नो मण्डोऽष्टगुण उच्यते", text: "dīpanaḥ prāṇado bastiśodhano raktavardhanaḥ jvarajitsarvadoṣaghno maṇḍo'ṣṭaguṇa ucyate" },
      { type: "verse", number: "175", sanskrit: "सुकण्डितैस्तथा भृष्टैर्वाट्यमण्डो यवैर्भवेत् कफपित्तहरः कण्ठ्यो रक्तपित्तप्रसादनः", text: "sukaṇḍitaistathā bhṛṣṭairvāṭyamaṇḍo yavairbhavet kaphapittaharaḥ kaṇṭhyo raktapittaprasādanaḥ" },
      { type: "verse", number: "176", sanskrit: "लाजैर्वा तण्डुलैभृष्टैर्लाजमण्डः प्रकीर्त्तितः श्लेष्मपित्तहरो ग्राही पिपासाज्वरजिन्मतः", text: "lājairvā taṇḍulaibhṛṣṭairlājamaṇḍaḥ prakīrttitaḥ śleṣmapittaharo grāhī pipāsājvarajinmataḥ" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 3,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Калка чурна санграха — Пасты и порошки" },
      { type: "text", text: "Приготовление и применение калки (пасты) и чурны (порошка). Детальные правила помола, просеивания, хранения и дозировки порошковых форм." },
      { type: "verse", number: "1", sanskrit: "अथ फाण्टादिकल्पना नाम तृतीयोऽध्यायः फाण्टकल्पना क्षुण्णे द्र व्यपले सम्यग्जलमुष्णं विनिक्षिपेत् मृत्पात्रे कुडवोन्मानं ततस्तु स्रावयेत्पटात्", text: "atha phāṇṭādikalpanā nāma tṛtīyo'dhyāyaḥ phāṇṭakalpanā kṣuṇṇe dra vyapale samyagjalamuṣṇaṃ vinikṣipet mṛtpātre kuḍavonmānaṃ tatastu srāvayetpaṭāt" },
      { type: "verse", number: "2", sanskrit: "स स्याच्चूर्णद्र वः फाण्टस्तन्मानं द्विपलोन्मितम् सितामधुगुडादींश्च क्वाथवत्तत्र निक्षिपेत्", text: "sa syāccūrṇadra vaḥ phāṇṭastanmānaṃ dvipalonmitam sitāmadhuguḍādīṃśca kvāthavattatra nikṣipet" },
      { type: "verse", number: "3", sanskrit: "वातपित्तज्वरादौ बृहन्मधूकपुष्पादिफाण्टः मधूकपुष्पं मधुकं चन्दनं सपरूषकम् मृणालं कमलं लोध्रं गम्भारीं नागकेशरम्", text: "vātapittajvarādau bṛhanmadhūkapuṣpādiphāṇṭaḥ madhūkapuṣpaṃ madhukaṃ candanaṃ saparūṣakam mṛṇālaṃ kamalaṃ lodhraṃ gambhārīṃ nāgakeśaram" },
      { type: "verse", number: "4", sanskrit: "त्रिफलां सारिवां द्रा क्षां लाजान्कोष्णजले क्षिपेत् सितामधुयुतः पेयः फाण्टो वाऽसौ हिमोऽथवा", text: "triphalāṃ sārivāṃ drā kṣāṃ lājānkoṣṇajale kṣipet sitāmadhuyutaḥ peyaḥ phāṇṭo vā'sau himo'thavā" },
      { type: "verse", number: "5", sanskrit: "वातपित्तज्वरं दाहं तृष्णामूर्च्छाऽरतिभ्रमान् रक्तपित्तं मदं हन्यान्नात्र कार्या विचारणा", text: "vātapittajvaraṃ dāhaṃ tṛṣṇāmūrcchā'ratibhramān raktapittaṃ madaṃ hanyānnātra kāryā vicāraṇā" },
      { type: "verse", number: "6", sanskrit: "उशीरेण कृतः फाण्टः सक्षौद्रो  ज्वरनाशनः पिपासाच्छर्द्यतीसारान्मूर्च्छां जयति दुस्तराम्", text: "uśīreṇa kṛtaḥ phāṇṭaḥ sakṣaudro  jvaranāśanaḥ pipāsācchardyatīsārānmūrcchāṃ jayati dustarām" },
      { type: "verse", number: "7", sanskrit: "दाहपित्तादौ लघुमधूकपुष्पादिफाण्टः मधूकपुष्पगम्भारीचन्दनोशीरधान्यकैः", text: "dāhapittādau laghumadhūkapuṣpādiphāṇṭaḥ madhūkapuṣpagambhārīcandanośīradhānyakaiḥ" },
      { type: "verse", number: "8", sanskrit: "द्रा क्षया च कृतः फाण्टः शीतः शर्करया युतः तृष्णापित्तहरः प्रोक्तो दाहमूर्च्छाभ्रमाञ्जयेत्", text: "drā kṣayā ca kṛtaḥ phāṇṭaḥ śītaḥ śarkarayā yutaḥ tṛṣṇāpittaharaḥ prokto dāhamūrcchābhramāñjayet" },
      { type: "verse", number: "9", sanskrit: "मन्थोऽपि फाण्टभेदः स्यात्तेन चात्रैव कथ्यते जले चतुष्पले शीते क्षुण्णं द्र व्यपलं क्षिपेत् मृत्पात्रे मन्थयेत्सम्यक्तस्माच्च द्विपलं पिबेत्", text: "mantho'pi phāṇṭabhedaḥ syāttena cātraiva kathyate jale catuṣpale śīte kṣuṇṇaṃ dra vyapalaṃ kṣipet mṛtpātre manthayetsamyaktasmācca dvipalaṃ pibet" },
      { type: "verse", number: "10", sanskrit: "खर्जूरदाडिमीद्रा क्षातिन्तिडीकाम्लिकामलैः सपरूषैः कृतो मन्थः सर्वमद्यविकारनुत्", text: "kharjūradāḍimīdrā kṣātintiḍīkāmlikāmalaiḥ saparūṣaiḥ kṛto manthaḥ sarvamadyavikāranut" },
      { type: "verse", number: "11", sanskrit: "क्षौद्र युक्ता मसूराणां सक्तवो दाडिमाम्भसा मथिता वारयन्त्याशु छर्दिं दोषत्रयोद्भवाम्", text: "kṣaudra yuktā masūrāṇāṃ saktavo dāḍimāmbhasā mathitā vārayantyāśu chardiṃ doṣatrayodbhavām" },
      { type: "verse", number: "12", sanskrit: "प्लावितैः शीतनीरेण सघृतैर्यवसक्तुभिः नातिसान्द्र द्र वो मन्थस्तृष्णादाहास्रपित्तहा", text: "plāvitaiḥ śītanīreṇa saghṛtairyavasaktubhiḥ nātisāndra dra vo manthastṛṣṇādāhāsrapittahā" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 4,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Хрим видхи — Приготовление препаратов" },
      { type: "text", text: "Общие принципы приготовления аюрведических препаратов. Важность чистоты ингредиентов, оборудования и намерения готовящего. Концепция «бхавана» — насыщения препарата." },
      { type: "verse", number: "1", sanskrit: "अथ हिमकल्पना नाम चतुर्थोऽध्यायः हिमकल्पना क्षुण्णं द्र व्यपलं सम्यक्षड्भिर्नीरपलैः प्लुतम् निशोषितं हिमः स स्यात्तथा शीतकषायकः तन्मानं फाण्टवज्ज्ञेयं सर्वत्रैवैष निश्चयः", text: "atha himakalpanā nāma caturtho'dhyāyaḥ himakalpanā kṣuṇṇaṃ dra vyapalaṃ samyakṣaḍbhirnīrapalaiḥ plutam niśoṣitaṃ himaḥ sa syāttathā śītakaṣāyakaḥ tanmānaṃ phāṇṭavajjñeyaṃ sarvatraivaiṣa niścayaḥ" },
      { type: "verse", number: "2", sanskrit: "आम्रं जम्बूं च ककुभं चूर्णीकृत्य जले क्षिपेत् हिमं तस्य पिबेत्प्रातः सक्षौद्रं  रक्तपित्तजित्", text: "āmraṃ jambūṃ ca kakubhaṃ cūrṇīkṛtya jale kṣipet himaṃ tasya pibetprātaḥ sakṣaudraṃ  raktapittajit" },
      { type: "verse", number: "3", sanskrit: "मरिचं मधुयष्टी च काकोदुम्बरपल्लवाः नीलोत्पलं हिमस्तज्जस्तृष्णाच्छर्दिनिवारणः", text: "maricaṃ madhuyaṣṭī ca kākodumbarapallavāḥ nīlotpalaṃ himastajjastṛṣṇācchardinivāraṇaḥ" },
      { type: "verse", number: "4", sanskrit: "वातपित्तज्वरादौ नीलोत्पलादिहिमः नीलोत्पलं बला द्रा क्षा मधूकं मधुकं तथा उशीरं पद्मकं चैव काश्मरी च परूषकम्", text: "vātapittajvarādau nīlotpalādihimaḥ nīlotpalaṃ balā drā kṣā madhūkaṃ madhukaṃ tathā uśīraṃ padmakaṃ caiva kāśmarī ca parūṣakam" },
      { type: "verse", number: "5", sanskrit: "एष शीतकषायश्च वातपित्तज्वराञ्जयेत् सप्रलापभ्रमच्छर्दिमोहतृष्णानिवारणः", text: "eṣa śītakaṣāyaśca vātapittajvarāñjayet sapralāpabhramacchardimohatṛṣṇānivāraṇaḥ" },
      { type: "verse", number: "6", sanskrit: "जीर्णज्वरे गुडूचीहिमो रक्तपित्ते वासाहिमश्च अमृताया हिमः पेयो जीर्णज्वरहरः स्मृतः वासायाश्च हिमः कासं रक्तपित्तज्वराञ्जयेत्", text: "jīrṇajvare guḍūcīhimo raktapitte vāsāhimaśca amṛtāyā himaḥ peyo jīrṇajvaraharaḥ smṛtaḥ vāsāyāśca himaḥ kāsaṃ raktapittajvarāñjayet" },
      { type: "verse", number: "7", sanskrit: "प्रातः सशर्करः पेयो हिमो धान्याकसम्भवः अन्तर्दाहं तथा तृष्णां जयेत्स्रोतोविशोधनः", text: "prātaḥ saśarkaraḥ peyo himo dhānyākasambhavaḥ antardāhaṃ tathā tṛṣṇāṃ jayetsrotoviśodhanaḥ" },
      { type: "verse", number: "8", sanskrit: "धान्याकधात्रीवासानां द्रा क्षापर्पटयोर्हिमः रक्तपित्तं ज्वरं दाहं तृष्णां शोषं च नाशयेत्", text: "dhānyākadhātrīvāsānāṃ drā kṣāparpaṭayorhimaḥ raktapittaṃ jvaraṃ dāhaṃ tṛṣṇāṃ śoṣaṃ ca nāśayet" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 5,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Снеха санграха — Масляные препараты" },
      { type: "text", text: "Детальное описание приготовления снеха-препаратов (масляных форм). Три степени готовности масла (мрду, мадхья, кхара) и их клинические показания." },
      { type: "verse", number: "1", sanskrit: "अथ कल्ककल्पनानाम पञ्चमोऽध्यायः कल्ककल्पना द्रव्यमाद्र रं! शिलापिष्टं शुष्कं वा सजलं भवेत् प्रक्षेपावापकल्कास्ते तन्मानं कर्षसंमितम्", text: "atha kalkakalpanānāma pañcamo'dhyāyaḥ kalkakalpanā dravyamādra raṃ! śilāpiṣṭaṃ śuṣkaṃ vā sajalaṃ bhavet prakṣepāvāpakalkāste tanmānaṃ karṣasaṃmitam" },
      { type: "verse", number: "2", sanskrit: "कल्के मधु घृतं तैलं देयं द्विगुणमात्रया सिता गुडं समं दद्याद् द्र वा देयाश्चतुर्गुणाः", text: "kalke madhu ghṛtaṃ tailaṃ deyaṃ dviguṇamātrayā sitā guḍaṃ samaṃ dadyād dra vā deyāścaturguṇāḥ" },
      { type: "verse", number: "3", sanskrit: "त्रिवृद्ध्या पञ्चवृद्ध्या वा सप्तवृद्ध्याऽथवा कणाः पिबेत्पिष्ट्वा दशदिनं तास्तथैवापकर्षयेत्", text: "trivṛddhyā pañcavṛddhyā vā saptavṛddhyā'thavā kaṇāḥ pibetpiṣṭvā daśadinaṃ tāstathaivāpakarṣayet" },
      { type: "verse", number: "4", sanskrit: "एवं विंशद्दिनैः सिद्धं पिप्पलीवर्द्धमानकम् अनेन पाण्डुवातास्रकासश्वासारुचिज्वराः उदरार्शः क्षयश्लेष्मवाता नश्यन्त्युरोग्रहाः", text: "evaṃ viṃśaddinaiḥ siddhaṃ pippalīvarddhamānakam anena pāṇḍuvātāsrakāsaśvāsārucijvarāḥ udarārśaḥ kṣayaśleṣmavātā naśyantyurograhāḥ" },
      { type: "verse", number: "5", sanskrit: "लेपान्निम्बदलैः कल्को व्रणशोधनरोपणः भक्षणाच्छर्दिकुष्ठानि पित्तश्लेष्मकृमीञ्जयेत्", text: "lepānnimbadalaiḥ kalko vraṇaśodhanaropaṇaḥ bhakṣaṇācchardikuṣṭhāni pittaśleṣmakṛmīñjayet" },
      { type: "verse", number: "6", sanskrit: "महानिम्बजटाकल्को गृध्रसीनाशनः स्मृतः", text: "mahānimbajaṭākalko gṛdhrasīnāśanaḥ smṛtaḥ" },
      { type: "verse", number: "7", sanskrit: "रसोनकल्को वातरोगविषमज्वरादिषु शुद्धः कल्को रसोनस्य तिलतैलेन मिश्रितः वातरोगाञ्जयेत्तीव्रान्विषमज्वरनाशनः", text: "rasonakalko vātarogaviṣamajvarādiṣu śuddhaḥ kalko rasonasya tilatailena miśritaḥ vātarogāñjayettīvrānviṣamajvaranāśanaḥ" },
      { type: "verse", number: "8", sanskrit: "द्वितीयो रसोनकल्को वातव्याधौ पक्वकन्दरसोनस्य गुलिका निस्तुषीकृता पाटयित्वा च मध्यस्थं दूरीकुर्यात्तदङ्कुरम्", text: "dvitīyo rasonakalko vātavyādhau pakvakandarasonasya gulikā nistuṣīkṛtā pāṭayitvā ca madhyasthaṃ dūrīkuryāttadaṅkuram" },
      { type: "verse", number: "9", sanskrit: "तदुग्रगन्धनाशाय रात्रौ तक्रे विनिक्षिपेत् अपनीय च तन्मध्याच्छिलायां पेषयेत्ततः", text: "tadugragandhanāśāya rātrau takre vinikṣipet apanīya ca tanmadhyācchilāyāṃ peṣayettataḥ" },
      { type: "verse", number: "10", sanskrit: "तन्मध्ये पञ्चमांशेन चूर्णमेषां विनिक्षिपेत् सौवर्चलं यवानीं च भर्जितं हिङ्गुसैन्धवम्", text: "tanmadhye pañcamāṃśena cūrṇameṣāṃ vinikṣipet sauvarcalaṃ yavānīṃ ca bharjitaṃ hiṅgusaindhavam" },
      { type: "verse", number: "11", sanskrit: "कटुत्रिकं जीरकं च समभागानि चूर्णयेत् एकीकृत्य ततः सर्वं कल्कं कर्षप्रमाणतः", text: "kaṭutrikaṃ jīrakaṃ ca samabhāgāni cūrṇayet ekīkṛtya tataḥ sarvaṃ kalkaṃ karṣapramāṇataḥ" },
      { type: "verse", number: "12", sanskrit: "खादेदग्निबलापेक्षी ऋतुदोषाद्यपेक्षया अनुपानं ततः कुर्यादेरण्डशृतमन्वहम्", text: "khādedagnibalāpekṣī ṛtudoṣādyapekṣayā anupānaṃ tataḥ kuryāderaṇḍaśṛtamanvaham" },
      { type: "verse", number: "13", sanskrit: "सर्वाङ्गैकाङ्गजं वातमर्दितं चापतन्त्रकम् अपस्मारमथोन्मादमूरुस्तम्भं च गृध्रसीम्", text: "sarvāṅgaikāṅgajaṃ vātamarditaṃ cāpatantrakam apasmāramathonmādamūrustambhaṃ ca gṛdhrasīm" },
      { type: "verse", number: "14", sanskrit: "उरःपृष्ठकटीपार्श्वकुक्षिपीडां क्रिमीञ्जयेत् अजीर्णमातपं रोषमतिनीरं पयो गुडम्", text: "uraḥpṛṣṭhakaṭīpārśvakukṣipīḍāṃ krimīñjayet ajīrṇamātapaṃ roṣamatinīraṃ payo guḍam" },
      { type: "verse", number: "15", sanskrit: "मद्यं मासं तथाऽम्ल च रसं सेवेत नित्यशः", text: "madyaṃ māsaṃ tathā'mla ca rasaṃ seveta nityaśaḥ" },
      { type: "verse", number: "16", sanskrit: "पिप्पली पिप्पलीमूलं भल्लातकफलानि च एतत्कल्कश्च सक्षौद्र  ऊरुस्तम्भनिवारणः", text: "pippalī pippalīmūlaṃ bhallātakaphalāni ca etatkalkaśca sakṣaudra  ūrustambhanivāraṇaḥ" },
      { type: "verse", number: "17", sanskrit: "विष्णुक्रान्ताकल्कः परिणामशूले विष्णुक्रान्ताजटाकल्कः सिताक्षौद्र घृतैर्युतः परिणामभवं शूलं नाशयेत्सप्तभिर्दिनैः", text: "viṣṇukrāntākalkaḥ pariṇāmaśūle viṣṇukrāntājaṭākalkaḥ sitākṣaudra ghṛtairyutaḥ pariṇāmabhavaṃ śūlaṃ nāśayetsaptabhirdinaiḥ" },
      { type: "verse", number: "18", sanskrit: "शुण्ठीकल्कः परिणामशूलामवातयोः शुण्ठीतिलगुडैः कल्कं दुग्धेन सह योजयेत् परिणामभवं शूलमामवातं च नाशयेत्", text: "śuṇṭhīkalkaḥ pariṇāmaśūlāmavātayoḥ śuṇṭhītilaguḍaiḥ kalkaṃ dugdhena saha yojayet pariṇāmabhavaṃ śūlamāmavātaṃ ca nāśayet" },
      { type: "verse", number: "19", sanskrit: "अपामार्गस्य बीजानां कल्कस्तण्डुलवारिणा पीतो रक्तार्शसां नाशं कुरुते नात्र संशयः", text: "apāmārgasya bījānāṃ kalkastaṇḍulavāriṇā pīto raktārśasāṃ nāśaṃ kurute nātra saṃśayaḥ" },
      { type: "verse", number: "20", sanskrit: "बदरीमूलकल्केन तिलकल्कश्च योजितः मधुक्षारयुतः कुर्याद्र क्तातीसारनाशनम्", text: "badarīmūlakalkena tilakalkaśca yojitaḥ madhukṣārayutaḥ kuryādra ktātīsāranāśanam" },
      { type: "verse", number: "21", sanskrit: "कूष्माण्डकरसोपेतां लाक्षां कर्षद्वयं पिबेत् रक्तक्षयमुरोघातं क्षयरोगं च नाशयेत्", text: "kūṣmāṇḍakarasopetāṃ lākṣāṃ karṣadvayaṃ pibet raktakṣayamuroghātaṃ kṣayarogaṃ ca nāśayet" },
      { type: "verse", number: "22", sanskrit: "तण्डुलीयजटाकल्कः सक्षौद्र ः! सरसाञ्जनः तण्डुलोदकसंपीतो रक्तप्रदरनाशनः", text: "taṇḍulīyajaṭākalkaḥ sakṣaudra ḥ! sarasāñjanaḥ taṇḍulodakasaṃpīto raktapradaranāśanaḥ" },
      { type: "verse", number: "23", sanskrit: "अङ्कोलमूलकल्कश्च सक्षौद्र स्तण्डुलाम्बुना अतीसारहरः प्रोक्तस्तथा विषहरः स्मृतः", text: "aṅkolamūlakalkaśca sakṣaudra staṇḍulāmbunā atīsāraharaḥ proktastathā viṣaharaḥ smṛtaḥ" },
      { type: "verse", number: "24", sanskrit: "वन्ध्याकर्कोटिकाऽदीनां मूलकल्को विषे वन्ध्याकर्कोटिकामूलं पाटलाया जटा तथा घृतेन बिल्वमूलं वा द्विविधं नाशयेद्विषम्", text: "vandhyākarkoṭikā'dīnāṃ mūlakalko viṣe vandhyākarkoṭikāmūlaṃ pāṭalāyā jaṭā tathā ghṛtena bilvamūlaṃ vā dvividhaṃ nāśayedviṣam" },
      { type: "verse", number: "25", sanskrit: "अभयादिकल्कः त्रिदोषनाशने पथ्यादिकल्कः पाचनादौ च अभयासैन्धवकणाशुण्ठीकल्कस्त्रिदोषहा पथ्यासैन्धवशुण्ठीभिः कल्को दीपनपाचनः", text: "abhayādikalkaḥ tridoṣanāśane pathyādikalkaḥ pācanādau ca abhayāsaindhavakaṇāśuṇṭhīkalkastridoṣahā pathyāsaindhavaśuṇṭhībhiḥ kalko dīpanapācanaḥ" },
      { type: "verse", number: "26", sanskrit: "त्रिवृत्पलाशबीजानि पारसीकयवानिका कम्पिल्लकं विडङ्गं च गुडश्च समभागकः तक्रेण कल्कमेतेषां पिबेत्क्रिमिगणापहम्", text: "trivṛtpalāśabījāni pārasīkayavānikā kampillakaṃ viḍaṅgaṃ ca guḍaśca samabhāgakaḥ takreṇa kalkameteṣāṃ pibetkrimigaṇāpaham" },
      { type: "verse", number: "27", sanskrit: "नवनीततिलैः कल्को जेता रक्तार्शसां स्मृतः नवनीतसितानागकेशरैश्चापि तद्विधः", text: "navanītatilaiḥ kalko jetā raktārśasāṃ smṛtaḥ navanītasitānāgakeśaraiścāpi tadvidhaḥ" },
      { type: "verse", number: "28", sanskrit: "शुण्ठ्यादि बृहतीकल्कौ संग्रहण्याम् पीतो मसूरयूषेण कल्कः शुण्ठीशलाटुजः जयेत् संग्रहणीं तद्वत्तक्रेण बृहतीभवः", text: "śuṇṭhyādi bṛhatīkalkau saṃgrahaṇyām pīto masūrayūṣeṇa kalkaḥ śuṇṭhīśalāṭujaḥ jayet saṃgrahaṇīṃ tadvattakreṇa bṛhatībhavaḥ" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 6,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Таила гхрита санграха — Масла и гхи" },
      { type: "text", text: "Специфика приготовления таила (растительных масел) и гхрита (медицинского гхи). Сравнение их свойств и показаний. Правила уваривания с растительными веществами." },
      { type: "verse", number: "1", sanskrit: "अथ चूर्णकल्पनानाम षष्ठोऽध्यायः तत्रादौ चूर्णलक्षणम् अत्यन्तशुष्कं यद्द्र व्यं सुपिष्टं वस्त्रगालितम् तत्स्याच्चूर्णंरजः क्षोदस्तन्मात्रा कर्षसंमिता", text: "atha cūrṇakalpanānāma ṣaṣṭho'dhyāyaḥ tatrādau cūrṇalakṣaṇam atyantaśuṣkaṃ yaddra vyaṃ supiṣṭaṃ vastragālitam tatsyāccūrṇaṃrajaḥ kṣodastanmātrā karṣasaṃmitā" },
      { type: "verse", number: "2", sanskrit: "चूर्णे गुडः समो देयः शर्कराद्विगुणा भवेत् चूर्णेषु भर्जितं हिंगु देयं नोत्क्लेदकृद्भवेत्", text: "cūrṇe guḍaḥ samo deyaḥ śarkarādviguṇā bhavet cūrṇeṣu bharjitaṃ hiṃgu deyaṃ notkledakṛdbhavet" },
      { type: "verse", number: "3", sanskrit: "लिहेच्चूर्णं द्र वैः सर्वैर्घृताद्यैर्द्विगुणोन्मितैः पिबेच्चतुर्गुणैरेव चूर्णमालोडितं द्र वैः", text: "liheccūrṇaṃ dra vaiḥ sarvairghṛtādyairdviguṇonmitaiḥ pibeccaturguṇaireva cūrṇamāloḍitaṃ dra vaiḥ" },
      { type: "verse", number: "4", sanskrit: "चूर्णादीनां दोषानुसारेणानुपानमानकल्पना चूर्णावलेहगुटिकाकल्कानामनुपानकम् वातपित्तकफातङ्के त्रिद्व्येकपलमाहरेत्", text: "cūrṇādīnāṃ doṣānusāreṇānupānamānakalpanā cūrṇāvalehaguṭikākalkānāmanupānakam vātapittakaphātaṅke tridvyekapalamāharet" },
      { type: "verse", number: "5", sanskrit: "यथा तैलं जले क्षिप्तं क्षणेनैव प्रसर्पति अनुपानबलादङ्गे तथा सर्पति भेषजम्", text: "yathā tailaṃ jale kṣiptaṃ kṣaṇenaiva prasarpati anupānabalādaṅge tathā sarpati bheṣajam" },
      { type: "verse", number: "6", sanskrit: "चूर्णार्थे भावनापरिमाणनिर्देशः द्र वेण यावता सम्यक्चूर्णं सर्वं प्लुतं भवेत् भावनायाः प्रमाणं तु चूर्णे प्रोक्तं भिषग्वरैः", text: "cūrṇārthe bhāvanāparimāṇanirdeśaḥ dra veṇa yāvatā samyakcūrṇaṃ sarvaṃ plutaṃ bhavet bhāvanāyāḥ pramāṇaṃ tu cūrṇe proktaṃ bhiṣagvaraiḥ" },
      { type: "verse", number: "7", sanskrit: "आमलं चित्रकः पथ्या पिप्पली सैन्धवं तथा चूर्णितोऽय गणो ज्ञेयः सर्वज्वरविनाशनः भेदी रुचिकरः श्लेष्मजेता दीपनपाचनः", text: "āmalaṃ citrakaḥ pathyā pippalī saindhavaṃ tathā cūrṇito'ya gaṇo jñeyaḥ sarvajvaravināśanaḥ bhedī rucikaraḥ śleṣmajetā dīpanapācanaḥ" },
      { type: "verse", number: "8", sanskrit: "पिप्पलीचूर्णं हिक्काज्वरादिषु मधुनापिप्पलीचूर्णं लिहेत्कासज्वरापहम् हिक्काश्वासहरं कण्ठ्यं प्लीहघ्नं बालकोचितम्", text: "pippalīcūrṇaṃ hikkājvarādiṣu madhunāpippalīcūrṇaṃ lihetkāsajvarāpaham hikkāśvāsaharaṃ kaṇṭhyaṃ plīhaghnaṃ bālakocitam" },
      { type: "verse", number: "9", sanskrit: "एका हरीतकी योज्या द्वौ च योज्यौ बिभीतकौ चत्वार्यामलकान्येव त्रिफलैषा प्रकीर्त्तिता", text: "ekā harītakī yojyā dvau ca yojyau bibhītakau catvāryāmalakānyeva triphalaiṣā prakīrttitā" },
      { type: "verse", number: "10", sanskrit: "त्रिफला मेहशोथघ्नी नाशयेद्विषमज्वरान् दीपनी श्लेष्मपित्तघ्नी कुष्ठहन्त्री रसायनी", text: "triphalā mehaśothaghnī nāśayedviṣamajvarān dīpanī śleṣmapittaghnī kuṣṭhahantrī rasāyanī" },
      { type: "verse", number: "11", sanskrit: "सर्पिर्मधुभ्यां संयुक्ता सर्वनेत्रामयाञ्जयेत्", text: "sarpirmadhubhyāṃ saṃyuktā sarvanetrāmayāñjayet" },
      { type: "verse", number: "12", sanskrit: "पिप्पली मरिचंशुण्ठी त्रिभिस्त्र्! यूषणमुच्यते दीपनं श्लेष्ममेदोघ्नं कुष्ठपीनसनाशनम् जयेदरोचकं सामं मेहगुल्मगलामयान्", text: "pippalī maricaṃśuṇṭhī tribhistr! yūṣaṇamucyate dīpanaṃ śleṣmamedoghnaṃ kuṣṭhapīnasanāśanam jayedarocakaṃ sāmaṃ mehagulmagalāmayān" },
      { type: "verse", number: "13", sanskrit: "पिप्पलीचव्यविश्वाह्वपिप्पलीमूलचित्रकैः", text: "pippalīcavyaviśvāhvapippalīmūlacitrakaiḥ" },
      { type: "verse", number: "14", sanskrit: "पञ्चकोलमिति ख्यातं रुच्यं पाचनदीपनम् आनाहप्लीहगुल्मघ्नं शूलश्लेष्मोदरापहम्", text: "pañcakolamiti khyātaṃ rucyaṃ pācanadīpanam ānāhaplīhagulmaghnaṃ śūlaśleṣmodarāpaham" },
      { type: "verse", number: "15", sanskrit: "त्रिगन्धमेलात्वक्पत्रैश्चतुर्जातं सकेशरैः त्रिगन्धं सचतुर्जातं रूक्षोष्णं लघु पित्तकृत् वर्ण्यं रुचिकरं तीक्ष्णं पित्तश्लेष्मामयाञ्जयेत्", text: "trigandhamelātvakpatraiścaturjātaṃ sakeśaraiḥ trigandhaṃ sacaturjātaṃ rūkṣoṣṇaṃ laghu pittakṛt varṇyaṃ rucikaraṃ tīkṣṇaṃ pittaśleṣmāmayāñjayet" },
      { type: "verse", number: "16", sanskrit: "कृष्णादिचूर्णं शिशूनां ज्वरातिसारादौ कृष्णारुणामुस्तकशृङ्गिकाणां तुल्येन चूर्णेन समाक्षिकेण ज्वरातिसारः प्रशमं प्रयाति सश्वासकासः सवमिः शिशूनाम्", text: "kṛṣṇādicūrṇaṃ śiśūnāṃ jvarātisārādau kṛṣṇāruṇāmustakaśṛṅgikāṇāṃ tulyena cūrṇena samākṣikeṇa jvarātisāraḥ praśamaṃ prayāti saśvāsakāsaḥ savamiḥ śiśūnām" },
      { type: "verse", number: "17", sanskrit: "काकोली क्षीरकाकोली जीवकर्षभकौ तथा मेदा चान्या महामेदा जीवन्ती मधुकं तथा", text: "kākolī kṣīrakākolī jīvakarṣabhakau tathā medā cānyā mahāmedā jīvantī madhukaṃ tathā" },
      { type: "verse", number: "18", sanskrit: "मुद्गपर्णी माषपर्णी जीवनीयो गणस्त्वयम् जीवनीयो गणः स्वादुर्गर्भसन्धानकृद् गुरुः", text: "mudgaparṇī māṣaparṇī jīvanīyo gaṇastvayam jīvanīyo gaṇaḥ svādurgarbhasandhānakṛd guruḥ" },
      { type: "verse", number: "19", sanskrit: "स्तन्यकृद् बृंहणो वृष्यः स्निग्धः शीतस्तृषाऽपहः रक्तपित्तं क्षतं शोषं ज्वरदाहानिलाञ्जयेत्", text: "stanyakṛd bṛṃhaṇo vṛṣyaḥ snigdhaḥ śītastṛṣā'pahaḥ raktapittaṃ kṣataṃ śoṣaṃ jvaradāhānilāñjayet" },
      { type: "verse", number: "20", sanskrit: "द्वे मेदे द्वे च काकोल्यौ जीवकर्षभकौ तथा", text: "dve mede dve ca kākolyau jīvakarṣabhakau tathā" },
      { type: "verse", number: "21", sanskrit: "ऋद्धिवृद्धी च तैः सर्वैरष्टवर्ग उदाहृतः अष्टवर्गो बुधैः प्रोक्तो जीवनीयसमो गुणैः", text: "ṛddhivṛddhī ca taiḥ sarvairaṣṭavarga udāhṛtaḥ aṣṭavargo budhaiḥ prokto jīvanīyasamo guṇaiḥ" },
      { type: "verse", number: "22", sanskrit: "लवणपञ्चकचूर्णं सृष्टविण्मूत्रादौ सिन्धु सौवर्चलं चैव विडं सामुद्रि कं गुडम् एकद्वित्रिचतुः पञ्चलवणानि क्रमाद्विदुः", text: "lavaṇapañcakacūrṇaṃ sṛṣṭaviṇmūtrādau sindhu sauvarcalaṃ caiva viḍaṃ sāmudri kaṃ guḍam ekadvitricatuḥ pañcalavaṇāni kramādviduḥ" },
      { type: "verse", number: "23", sanskrit: "तेषु मुख्यं सैन्धवं स्यादनुक्ते तत्प्रयोजयेत् सैन्धवाद्यं रोमकान्तं ज्ञेयं लवणपञ्चकम्", text: "teṣu mukhyaṃ saindhavaṃ syādanukte tatprayojayet saindhavādyaṃ romakāntaṃ jñeyaṃ lavaṇapañcakam" },
      { type: "verse", number: "24", sanskrit: "मधुरं सृष्टविण्मूत्रं स्निग्धं सूक्ष्मं बलापहम् वीर्योष्णं दीपनं तीक्ष्णं कफपित्तविवर्द्धनम्", text: "madhuraṃ sṛṣṭaviṇmūtraṃ snigdhaṃ sūkṣmaṃ balāpaham vīryoṣṇaṃ dīpanaṃ tīkṣṇaṃ kaphapittavivarddhanam" },
      { type: "verse", number: "25", sanskrit: "स्वर्जिका यावशूकश्च क्षारयुग्ममुदाहृतम् ज्ञेयौ वह्निसमौ क्षारौ स्वर्जिकायाव शूकजौ", text: "svarjikā yāvaśūkaśca kṣārayugmamudāhṛtam jñeyau vahnisamau kṣārau svarjikāyāva śūkajau" },
      { type: "verse", number: "26", sanskrit: "क्षाराश्चान्येऽपि गुल्मार्शोग्रहणीरुक्छिदः सराः पाचनाः कृमिपुंस्त्वघ्नाः शर्कराऽश्मरिनाशनाः", text: "kṣārāścānye'pi gulmārśograhaṇīrukchidaḥ sarāḥ pācanāḥ kṛmipuṃstvaghnāḥ śarkarā'śmarināśanāḥ" },
      { type: "verse", number: "27", sanskrit: "त्रिफला रजनीयुग्मं कण्टकारीयुगं शटी त्रिकटु ग्रन्थिकं मूर्वा गुडूची धन्वयासकः", text: "triphalā rajanīyugmaṃ kaṇṭakārīyugaṃ śaṭī trikaṭu granthikaṃ mūrvā guḍūcī dhanvayāsakaḥ" },
      { type: "verse", number: "28", sanskrit: "कटुका पर्पटो मुस्तं त्रायमाणा च बालकम् निम्बः पुष्करमूलं च मधुयष्टी च वत्सकम्", text: "kaṭukā parpaṭo mustaṃ trāyamāṇā ca bālakam nimbaḥ puṣkaramūlaṃ ca madhuyaṣṭī ca vatsakam" },
      { type: "verse", number: "29", sanskrit: "यवानीन्द्र यवो भार्ङ्गीशिग्रुबीजं सुराष्ट्रजा वचात्वक्पद्मकोशीरचन्दनातिविषाबलाः", text: "yavānīndra yavo bhārṅgīśigrubījaṃ surāṣṭrajā vacātvakpadmakośīracandanātiviṣābalāḥ" },
      { type: "verse", number: "30", sanskrit: "शालिपर्णी पृश्निपर्णी विडङ्गं तगरं तथा चित्रको देवकाष्ठं च चव्यं पत्रं पटोलजम्", text: "śāliparṇī pṛśniparṇī viḍaṅgaṃ tagaraṃ tathā citrako devakāṣṭhaṃ ca cavyaṃ patraṃ paṭolajam" },
      { type: "verse", number: "31", sanskrit: "जीवकर्षभकौ चैव लवङ्गं वंशलोचना पुण्डरीकं च काकोली पत्रकं जातिपत्रकम्", text: "jīvakarṣabhakau caiva lavaṅgaṃ vaṃśalocanā puṇḍarīkaṃ ca kākolī patrakaṃ jātipatrakam" },
      { type: "verse", number: "32", sanskrit: "तालीसपत्रं च तथा समभागानि चूर्णयेत् सर्वचूर्णस्य चार्द्धांशं कैरातं निक्षिपेत्सुधीः", text: "tālīsapatraṃ ca tathā samabhāgāni cūrṇayet sarvacūrṇasya cārddhāṃśaṃ kairātaṃ nikṣipetsudhīḥ" },
      { type: "verse", number: "33", sanskrit: "एतत्सुदर्शनं नाम चूर्णं दोषत्रयापहम् ज्वरांश्च निखिलान्हन्यान्नात्र कार्या विचारणा", text: "etatsudarśanaṃ nāma cūrṇaṃ doṣatrayāpaham jvarāṃśca nikhilānhanyānnātra kāryā vicāraṇā" },
      { type: "verse", number: "34", sanskrit: "पृथग्द्वन्द्वागन्तुजांश्च धातुस्थान्विषमज्वरान् सन्निपातोद्भवांश्चापि मानसानपि नाशयेत्", text: "pṛthagdvandvāgantujāṃśca dhātusthānviṣamajvarān sannipātodbhavāṃścāpi mānasānapi nāśayet" },
      { type: "verse", number: "35", sanskrit: "शीतज्वरैकाहिकादीन्मोहं तन्द्रा ं! भ्रमं तृषाम् श्वासं कासं च पाण्डुं च हृद्रो गं हन्ति कामलाम्", text: "śītajvaraikāhikādīnmohaṃ tandrā ṃ! bhramaṃ tṛṣām śvāsaṃ kāsaṃ ca pāṇḍuṃ ca hṛdro gaṃ hanti kāmalām" },
      { type: "verse", number: "36", sanskrit: "शीताम्बुना पिबेद्धीमान्सर्वज्वरनिवृत्तये", text: "śītāmbunā pibeddhīmānsarvajvaranivṛttaye" },
      { type: "verse", number: "37", sanskrit: "सुदर्शनं यथा चक्रं दानवानां विनाशनम् तद्वज्ज्वराणां सर्वेषामिदं चूर्णं प्रणाशनम्", text: "sudarśanaṃ yathā cakraṃ dānavānāṃ vināśanam tadvajjvarāṇāṃ sarveṣāmidaṃ cūrṇaṃ praṇāśanam" },
      { type: "verse", number: "38", sanskrit: "त्रिफलापिप्पलीचूर्णं कासश्वासज्वरेषु कासश्वासज्वरहरा त्रिफला पिप्पलीयुता चूर्णिता मधुना लीढा भेदिनी चाग्निबोधिनी", text: "triphalāpippalīcūrṇaṃ kāsaśvāsajvareṣu kāsaśvāsajvaraharā triphalā pippalīyutā cūrṇitā madhunā līḍhā bhedinī cāgnibodhinī" },
      { type: "verse", number: "39", sanskrit: "कट्फलं मुस्तकं तिक्ता शटी शृङ्गी च पौष्करम् चूर्णमेषां च मधुना शृङ्गवेररसेन वा", text: "kaṭphalaṃ mustakaṃ tiktā śaṭī śṛṅgī ca pauṣkaram cūrṇameṣāṃ ca madhunā śṛṅgaverarasena vā" },
      { type: "verse", number: "40", sanskrit: "लिहेज्ज्वरहरं कण्ठ्यं कासश्वासारुचीर्जयेत् वायुं छर्दिं तथा शूलं क्षयं चैव व्यपोहति", text: "lihejjvaraharaṃ kaṇṭhyaṃ kāsaśvāsārucīrjayet vāyuṃ chardiṃ tathā śūlaṃ kṣayaṃ caiva vyapohati" },
      { type: "verse", number: "41", sanskrit: "बृहत्कट्फलादिचूर्णं शूलानिलादिषु कट्फलं पौष्करं शृङ्गी मुस्ता त्रिकटुकं शटी समस्तान्येकशो वाऽपि सूक्ष्मचूर्णानि कारयेत्", text: "bṛhatkaṭphalādicūrṇaṃ śūlānilādiṣu kaṭphalaṃ pauṣkaraṃ śṛṅgī mustā trikaṭukaṃ śaṭī samastānyekaśo vā'pi sūkṣmacūrṇāni kārayet" },
      { type: "verse", number: "42", sanskrit: "आर्द्र कस्वरसक्षौद्रै र्लिह्यात्कफविनाशनम् शूलानिलारुचिच्छर्दिकासश्वासक्षयापहम्", text: "ārdra kasvarasakṣaudrai rlihyātkaphavināśanam śūlānilārucicchardikāsaśvāsakṣayāpaham" },
      { type: "verse", number: "43", sanskrit: "द्वितीयं कट्फलादिचूर्णं श्वासादिषु कट्फलं पौष्करं कृष्णा शृङ्गी च मधुना सह श्वासकासज्वरहरः श्रेष्ठो लेहः कफान्तकृत्", text: "dvitīyaṃ kaṭphalādicūrṇaṃ śvāsādiṣu kaṭphalaṃ pauṣkaraṃ kṛṣṇā śṛṅgī ca madhunā saha śvāsakāsajvaraharaḥ śreṣṭho lehaḥ kaphāntakṛt" },
      { type: "verse", number: "44", sanskrit: "शृङ्ग्यादिचूर्णं विषाचूर्णं च शिशोः कासज्वरच्छर्दिषु शृङ्गी प्रतिविषा कृष्णा चूर्णिता मधुना लिहेत् शिशोः कासज्वरच्छर्दिशान्त्यै वा केवला विषा", text: "śṛṅgyādicūrṇaṃ viṣācūrṇaṃ ca śiśoḥ kāsajvaracchardiṣu śṛṅgī prativiṣā kṛṣṇā cūrṇitā madhunā lihet śiśoḥ kāsajvaracchardiśāntyai vā kevalā viṣā" },
      { type: "verse", number: "45", sanskrit: "चूर्णं क्षौद्र युतं लीढंपञ्चकासाञ्जयेच्छिशोः", text: "cūrṇaṃ kṣaudra yutaṃ līḍhaṃpañcakāsāñjayecchiśoḥ" },
      { type: "verse", number: "46", sanskrit: "चूर्णमुष्णाम्बुना पीतमामातीसारनाशनम्", text: "cūrṇamuṣṇāmbunā pītamāmātīsāranāśanam" },
      { type: "verse", number: "47", sanskrit: "हरीतकी प्रतिविषा सिन्धु सौवर्चलं वचा हिङ्गु चेति कृतं चूर्णं पिबेदुष्णेन वारिणा", text: "harītakī prativiṣā sindhu sauvarcalaṃ vacā hiṅgu ceti kṛtaṃ cūrṇaṃ pibeduṣṇena vāriṇā" },
      { type: "verse", number: "48", sanskrit: "आमातीसारशमनं ग्राहि चाग्निप्रबोधनम् लघुगङ्गाधरचूर्णं पक्वातिसारे मुस्तमिन्द्र यवं बिल्वं लोध्रं मोचरसं तथा धातकीं चूर्णयेत्तक्रगुडाभ्यां पाययेत्सुधीः", text: "āmātīsāraśamanaṃ grāhi cāgniprabodhanam laghugaṅgādharacūrṇaṃ pakvātisāre mustamindra yavaṃ bilvaṃ lodhraṃ mocarasaṃ tathā dhātakīṃ cūrṇayettakraguḍābhyāṃ pāyayetsudhīḥ" },
      { type: "verse", number: "49", sanskrit: "सर्वातीसारशमनं निरुणद्धि प्रवाहिकाम् लघुगङ्गाधरं नाम चूर्णं संग्राहकं परम्", text: "sarvātīsāraśamanaṃ niruṇaddhi pravāhikām laghugaṅgādharaṃ nāma cūrṇaṃ saṃgrāhakaṃ param" },
      { type: "verse", number: "50", sanskrit: "बृहद्गङ्गाधरचूर्णं प्रवाहिकादौ मुस्तारलुकशुण्ठीभिर्धातकीलोध्रबालकैः बिल्वमोचरसाभ्यां च पाठेन्द्र यववत्सकैः", text: "bṛhadgaṅgādharacūrṇaṃ pravāhikādau mustāralukaśuṇṭhībhirdhātakīlodhrabālakaiḥ bilvamocarasābhyāṃ ca pāṭhendra yavavatsakaiḥ" },
      { type: "verse", number: "51", sanskrit: "आम्रबीजं प्रतिविषा लज्जालुरिति चूर्णितम् क्षौद्र तण्डुलपानीयैः पीतैर्याति प्रवाहिका", text: "āmrabījaṃ prativiṣā lajjāluriti cūrṇitam kṣaudra taṇḍulapānīyaiḥ pītairyāti pravāhikā" },
      { type: "verse", number: "52", sanskrit: "सर्वातिसारा ग्रहणी प्रशमं याति वेगतः वृद्धगङ्गाधरं चूर्णं सरिद्वेगविबन्धकम्", text: "sarvātisārā grahaṇī praśamaṃ yāti vegataḥ vṛddhagaṅgādharaṃ cūrṇaṃ saridvegavibandhakam" },
      { type: "verse", number: "53", sanskrit: "अजमोदा मोचरसं सशृङ्गवेरं सधातकीकुसुमम् गोदधिमन्थितयुक्तं गङ्गामपि वाहिनीं रुन्ध्यात्", text: "ajamodā mocarasaṃ saśṛṅgaveraṃ sadhātakīkusumam godadhimanthitayuktaṃ gaṅgāmapi vāhinīṃ rundhyāt" },
      { type: "verse", number: "54", sanskrit: "तक्रेण यः पिबेन्नित्यं चूर्णं मरिचसंभवम्", text: "takreṇa yaḥ pibennityaṃ cūrṇaṃ maricasaṃbhavam" },
      { type: "verse", number: "55", sanskrit: "चित्रसौवर्चलोपेतं ग्रहणी तस्य नश्यति उदरप्लीहमन्दाग्निगुल्मार्शोनाशनं भवेत्", text: "citrasauvarcalopetaṃ grahaṇī tasya naśyati udaraplīhamandāgnigulmārśonāśanaṃ bhavet" },
      { type: "verse", number: "56", sanskrit: "कपित्थाष्टकं चूर्णं ग्रहण्यादौ अष्टौ भागाः कपित्थस्य षड्भागा शर्करा मता दाडिमं तिन्तिडीकं च श्रीफलं धातकी तथा", text: "kapitthāṣṭakaṃ cūrṇaṃ grahaṇyādau aṣṭau bhāgāḥ kapitthasya ṣaḍbhāgā śarkarā matā dāḍimaṃ tintiḍīkaṃ ca śrīphalaṃ dhātakī tathā" },
      { type: "verse", number: "57", sanskrit: "अजमोदा च पिप्पल्यः प्रत्येकं स्युस्त्रिभागिकाः मरिचं जीरकं धान्यं ग्रन्थिकं बालकं तथा", text: "ajamodā ca pippalyaḥ pratyekaṃ syustribhāgikāḥ maricaṃ jīrakaṃ dhānyaṃ granthikaṃ bālakaṃ tathā" },
      { type: "verse", number: "58", sanskrit: "सौवर्चलं यवानी च चातुर्जातं सचित्रकम् नागरं चैकभागाः स्युः प्रत्येकं सूक्ष्मचूर्णितम्", text: "sauvarcalaṃ yavānī ca cāturjātaṃ sacitrakam nāgaraṃ caikabhāgāḥ syuḥ pratyekaṃ sūkṣmacūrṇitam" },
      { type: "verse", number: "59", sanskrit: "कपित्थाष्टकसंज्ञं स्याच्चूर्णमेतद् गलामयान् अतीसारं क्षयं गुल्मं ग्रहणीं च व्यपोहति", text: "kapitthāṣṭakasaṃjñaṃ syāccūrṇametad galāmayān atīsāraṃ kṣayaṃ gulmaṃ grahaṇīṃ ca vyapohati" },
      { type: "verse", number: "60", sanskrit: "लघुदाडिमाष्टकचूर्णमरुच्यादौ कासज्वरादिषु च दाडिमी द्विपला ग्राह्या खंडा चाष्टपलाऽपि च त्रिगंधस्य पलं चैकं त्रिकटु स्यात्पलत्रयम्", text: "laghudāḍimāṣṭakacūrṇamarucyādau kāsajvarādiṣu ca dāḍimī dvipalā grāhyā khaṃḍā cāṣṭapalā'pi ca trigaṃdhasya palaṃ caikaṃ trikaṭu syātpalatrayam" },
      { type: "verse", number: "61", sanskrit: "एतदेकीकृतं सर्वं चूर्णं स्याद्दाडिमाष्टकम् रुचिकृद्दीपनं कंठ्यं ग्राहि कासज्वरापहम्", text: "etadekīkṛtaṃ sarvaṃ cūrṇaṃ syāddāḍimāṣṭakam rucikṛddīpanaṃ kaṃṭhyaṃ grāhi kāsajvarāpaham" },
      { type: "verse", number: "62", sanskrit: "दाडिमस्य पलान्यष्टौ शर्करायाः पलाष्टकम् पिप्पली पिप्पलीमूलं यवानी मरिचं तथा", text: "dāḍimasya palānyaṣṭau śarkarāyāḥ palāṣṭakam pippalī pippalīmūlaṃ yavānī maricaṃ tathā" },
      { type: "verse", number: "63", sanskrit: "धान्यकं जीरकं शुण्ठी प्रत्येकं पलसम्मितम् कर्षमात्रा तुगाक्षीरीत्वक्पत्रैलाश्च केशरम्", text: "dhānyakaṃ jīrakaṃ śuṇṭhī pratyekaṃ palasammitam karṣamātrā tugākṣīrītvakpatrailāśca keśaram" },
      { type: "verse", number: "64", sanskrit: "प्रत्येकं कोलमात्राः स्युस्तच्चूर्णं दाडिमाष्टकम् अतीसारं क्षयं गुल्मं ग्रहणीं च गलग्रहम् मन्दाग्निं पीनसं कासं चूर्णमेतद्व्यपोहति", text: "pratyekaṃ kolamātrāḥ syustaccūrṇaṃ dāḍimāṣṭakam atīsāraṃ kṣayaṃ gulmaṃ grahaṇīṃ ca galagraham mandāgniṃ pīnasaṃ kāsaṃ cūrṇametadvyapohati" },
      { type: "verse", number: "65", sanskrit: "पिप्पल्यादिचूर्णं वातग्रहण्याम् इ!पिप्पली बृहती व्याघ्री यवक्षारकलिङ्गकाः चित्रकं सारिवा पाठा शटी लवणपञ्चकम्", text: "pippalyādicūrṇaṃ vātagrahaṇyām i!pippalī bṛhatī vyāghrī yavakṣārakaliṅgakāḥ citrakaṃ sārivā pāṭhā śaṭī lavaṇapañcakam" },
      { type: "verse", number: "66", sanskrit: "तच्चूर्णं पाययेद्दध्ना सुरयोष्णाम्बुनाऽपि वा मारुतग्रहणीदोषशमनं परमं हितमि!", text: "taccūrṇaṃ pāyayeddadhnā surayoṣṇāmbunā'pi vā mārutagrahaṇīdoṣaśamanaṃ paramaṃ hitami!" },
      { type: "verse", number: "67", sanskrit: "लवङ्गं शुद्धकर्पूरमेलात्वङ्नागकेशरम् जातीफलमुशीरं च नागरं कृष्णजीरकम्", text: "lavaṅgaṃ śuddhakarpūramelātvaṅnāgakeśaram jātīphalamuśīraṃ ca nāgaraṃ kṛṣṇajīrakam" },
      { type: "verse", number: "68", sanskrit: "कृष्णागरुस्तुगाक्षीरी मांसी नीलोत्पलंकणा चन्दनं तगरं बालं कङ्कोलंचेति चूर्णयेत्", text: "kṛṣṇāgarustugākṣīrī māṃsī nīlotpalaṃkaṇā candanaṃ tagaraṃ bālaṃ kaṅkolaṃceti cūrṇayet" },
      { type: "verse", number: "69", sanskrit: "समभागानि सर्वाणि सर्वेभ्योऽद्धा सिता भवेत् लवङ्गाद्यमिदं चूर्णं राजार्हं वह्निदीपनम्", text: "samabhāgāni sarvāṇi sarvebhyo'ddhā sitā bhavet lavaṅgādyamidaṃ cūrṇaṃ rājārhaṃ vahnidīpanam" },
      { type: "verse", number: "70", sanskrit: "रोचनं तर्पणं वृष्यं त्रिदोषघ्नं बलप्रदम् हृद्रो गं कण्ठरोगं च कासं हिक्कां च पीनसम्", text: "rocanaṃ tarpaṇaṃ vṛṣyaṃ tridoṣaghnaṃ balapradam hṛdro gaṃ kaṇṭharogaṃ ca kāsaṃ hikkāṃ ca pīnasam" },
      { type: "verse", number: "71", sanskrit: "यक्ष्माणं तमकं श्वासमतीसारमुरःक्षतम् प्रमेहारुचिगुल्मादीन्ग्रहणीमपि नाशयेत्", text: "yakṣmāṇaṃ tamakaṃ śvāsamatīsāramuraḥkṣatam pramehārucigulmādīngrahaṇīmapi nāśayet" },
      { type: "verse", number: "72", sanskrit: "जातीफललवङ्गैलापत्रत्वङ्नागकेशरैः", text: "jātīphalalavaṅgailāpatratvaṅnāgakeśaraiḥ" },
      { type: "verse", number: "73", sanskrit: "तालीसपिप्पलीपथ्यास्थूलजीरकचित्रकैः", text: "tālīsapippalīpathyāsthūlajīrakacitrakaiḥ" },
      { type: "verse", number: "74", sanskrit: "शुण्ठीविडङ्गमरिचैः समभागविचूर्णितैः यावन्त्येतानि सर्वाणि कुर्याद्भङ्गां च तावतीम्", text: "śuṇṭhīviḍaṅgamaricaiḥ samabhāgavicūrṇitaiḥ yāvantyetāni sarvāṇi kuryādbhaṅgāṃ ca tāvatīm" },
      { type: "verse", number: "75", sanskrit: "सर्वचूर्णसमा देया शर्करा च भिषग्वरैः कर्षमात्रं ततः खादेन्मधुना प्लावितं सुधीः", text: "sarvacūrṇasamā deyā śarkarā ca bhiṣagvaraiḥ karṣamātraṃ tataḥ khādenmadhunā plāvitaṃ sudhīḥ" },
      { type: "verse", number: "76", sanskrit: "अस्य प्रभावाद् ग्रहणीकासश्वासारुचिक्षयाः वातश्लेष्मप्रतिश्यायाः प्रशमं यान्ति वेगतः", text: "asya prabhāvād grahaṇīkāsaśvāsārucikṣayāḥ vātaśleṣmapratiśyāyāḥ praśamaṃ yānti vegataḥ" },
      { type: "verse", number: "77", sanskrit: "मरिचं नागपुष्पाणि तालीसं लवणानि च प्रत्येकमेकभागाः स्युः पिप्पलीमूलचित्रकैः", text: "maricaṃ nāgapuṣpāṇi tālīsaṃ lavaṇāni ca pratyekamekabhāgāḥ syuḥ pippalīmūlacitrakaiḥ" },
      { type: "verse", number: "78", sanskrit: "त्वक्कणातिन्तिडीकं च जीरकं च द्बिभागिकम् धान्याम्लवेतसौ विश्वं भद्रै ला बदराणि च", text: "tvakkaṇātintiḍīkaṃ ca jīrakaṃ ca dbibhāgikam dhānyāmlavetasau viśvaṃ bhadrai lā badarāṇi ca" },
      { type: "verse", number: "79", sanskrit: "अजमोदा जलधरः प्रत्येकं स्युस्त्रिभागिकाः सर्वौषधिचतुर्थांशं दाडिमस्य फलं भवेत्", text: "ajamodā jaladharaḥ pratyekaṃ syustribhāgikāḥ sarvauṣadhicaturthāṃśaṃ dāḍimasya phalaṃ bhavet" },
      { type: "verse", number: "80", sanskrit: "द्र व्येभ्यो निखिलेभ्यश्च सिता देयाऽद्धमात्रया महाखाण्डवसंज्ञं स्याच्चूर्णमेतत्सुरोचनम्", text: "dra vyebhyo nikhilebhyaśca sitā deyā'ddhamātrayā mahākhāṇḍavasaṃjñaṃ syāccūrṇametatsurocanam" },
      { type: "verse", number: "81", sanskrit: "अग्निदीप्तिकरं हृद्यं कासातीसारनाशनम् हृद्रो गकण्ठजठरमुखरोगप्रणाशनम्", text: "agnidīptikaraṃ hṛdyaṃ kāsātīsāranāśanam hṛdro gakaṇṭhajaṭharamukharogapraṇāśanam" },
      { type: "verse", number: "82", sanskrit: "विषूचिकां तथाध्मानमर्शोगुल्मकृमीनपि छर्दिं पञ्चविधां श्वासं चूर्णमेतद्व्यपोहति", text: "viṣūcikāṃ tathādhmānamarśogulmakṛmīnapi chardiṃ pañcavidhāṃ śvāsaṃ cūrṇametadvyapohati" },
      { type: "verse", number: "83", sanskrit: "चित्रकं त्रिफला व्योषं जीरकं हपुषा वचा यवानी पिप्पलीमूलं शतपुष्पाऽजगन्धिका", text: "citrakaṃ triphalā vyoṣaṃ jīrakaṃ hapuṣā vacā yavānī pippalīmūlaṃ śatapuṣpā'jagandhikā" },
      { type: "verse", number: "84", sanskrit: "अजमोदा शटी धान्यं विडङ्गं स्थूलजीरकम् हेमाह्वा पौष्करं मूलं क्षारौ लवणपञ्चकम्", text: "ajamodā śaṭī dhānyaṃ viḍaṅgaṃ sthūlajīrakam hemāhvā pauṣkaraṃ mūlaṃ kṣārau lavaṇapañcakam" },
      { type: "verse", number: "85", sanskrit: "कुष्ठं चेति समांशानि विशाला स्याद् द्विभागिका त्रिवृत्त्रिभागा विज्ञेया दन्त्या भागत्रयं भवेत्", text: "kuṣṭhaṃ ceti samāṃśāni viśālā syād dvibhāgikā trivṛttribhāgā vijñeyā dantyā bhāgatrayaṃ bhavet" },
      { type: "verse", number: "86", sanskrit: "चतुर्भागा शातला स्यात्सर्वाण्येकत्र चूर्णयेत् पाचनस्नेहनाद्यैश्च स्निग्धकोष्ठस्य रोगिणः", text: "caturbhāgā śātalā syātsarvāṇyekatra cūrṇayet pācanasnehanādyaiśca snigdhakoṣṭhasya rogiṇaḥ" },
      { type: "verse", number: "87", sanskrit: "दद्याच्चूर्णं विरेकाय सर्वरोगप्रणाशनम् हृद्रो गे पाण्डुरोगे च कासे श्वासे भगन्दरे", text: "dadyāccūrṇaṃ virekāya sarvarogapraṇāśanam hṛdro ge pāṇḍuroge ca kāse śvāse bhagandare" },
      { type: "verse", number: "88", sanskrit: "मन्देऽग्नौ च ज्वरे कुष्ठे ग्रहण्यां च गलग्रहे दद्याद्युक्तानुपानेन तथाध्माने सुरादिभिः", text: "mande'gnau ca jvare kuṣṭhe grahaṇyāṃ ca galagrahe dadyādyuktānupānena tathādhmāne surādibhiḥ" },
      { type: "verse", number: "89", sanskrit: "गुल्मे बदरनीरेण विड्भेदे दधिमस्तुना उष्णाम्बुभिरजीर्णे च वृक्षाम्लैः परिकर्त्तिषु", text: "gulme badaranīreṇa viḍbhede dadhimastunā uṣṇāmbubhirajīrṇe ca vṛkṣāmlaiḥ parikarttiṣu" },
      { type: "verse", number: "90", sanskrit: "उष्ट्रीदुग्धेनोदरेषु तथा तक्रेण वा गवाम् प्रसन्नया वातरोगे दाडिमाम्भोभिरर्शसि", text: "uṣṭrīdugdhenodareṣu tathā takreṇa vā gavām prasannayā vātaroge dāḍimāmbhobhirarśasi" },
      { type: "verse", number: "91", sanskrit: "द्विविधे च विषे दद्याद् घृतेन विषनाशनम् चूर्णं नारायणं नाम दुष्टरोगगणापहम्", text: "dvividhe ca viṣe dadyād ghṛtena viṣanāśanam cūrṇaṃ nārāyaṇaṃ nāma duṣṭarogagaṇāpaham" },
      { type: "verse", number: "92", sanskrit: "हपुषा त्रिफला चैव त्रायमाणा च पिप्पली हेमक्षीरी त्रिवृच्चैव शातला कटुका वचा", text: "hapuṣā triphalā caiva trāyamāṇā ca pippalī hemakṣīrī trivṛccaiva śātalā kaṭukā vacā" },
      { type: "verse", number: "93", sanskrit: "नीलिनी सैन्धवं कृष्णं लवणं चेति चूर्णयेत् उष्णोदकेन मूत्रेण दाडिमत्रिफलारसैः", text: "nīlinī saindhavaṃ kṛṣṇaṃ lavaṇaṃ ceti cūrṇayet uṣṇodakena mūtreṇa dāḍimatriphalārasaiḥ" },
      { type: "verse", number: "94", sanskrit: "तथा मांसरसेनापि यथायोग्यं पिबेन्नरः अजीर्णे प्लीह्नि गुल्मेषु शोफार्शोविषमाग्निषु", text: "tathā māṃsarasenāpi yathāyogyaṃ pibennaraḥ ajīrṇe plīhni gulmeṣu śophārśoviṣamāgniṣu" },
      { type: "verse", number: "95", sanskrit: "शुण्ठी हरीतकी कृष्णा त्रिवृत्सौवर्चलं तथा समभागानि सर्वाणि सूक्ष्मचूर्णानि कारयेत्", text: "śuṇṭhī harītakī kṛṣṇā trivṛtsauvarcalaṃ tathā samabhāgāni sarvāṇi sūkṣmacūrṇāni kārayet" },
      { type: "verse", number: "96", sanskrit: "ज्ञेयं पञ्च समं चूर्णमेतच्छूलहरं परम् आध्मानजठरार्शोघ्नमामवातहरंस्मृतम्", text: "jñeyaṃ pañca samaṃ cūrṇametacchūlaharaṃ param ādhmānajaṭharārśoghnamāmavātaharaṃsmṛtam" },
      { type: "verse", number: "97", sanskrit: "कर्षमात्रा भवेत्कृष्णा त्रिवृता स्यात्पलोन्मिता खण्डात्पलं च विज्ञेयं चूर्णमेकत्र कारयेत्", text: "karṣamātrā bhavetkṛṣṇā trivṛtā syātpalonmitā khaṇḍātpalaṃ ca vijñeyaṃ cūrṇamekatra kārayet" },
      { type: "verse", number: "98", sanskrit: "कर्षोन्मितं लिहेदेतत्क्षौद्रे णाध्माननाशनम् गाढविट्कोदरकफान्पित्तशूलं च नाशयेत्", text: "karṣonmitaṃ lihedetatkṣaudre ṇādhmānanāśanam gāḍhaviṭkodarakaphānpittaśūlaṃ ca nāśayet" },
      { type: "verse", number: "99", sanskrit: "लवणत्रितयाद्यं चूर्णं यकृत्प्लीहादौ लवणत्रितयं क्षारौ शतपुष्पाद्वयं वचा अजमोदाऽजगन्धा च हपुषा जीरकद्वयम्", text: "lavaṇatritayādyaṃ cūrṇaṃ yakṛtplīhādau lavaṇatritayaṃ kṣārau śatapuṣpādvayaṃ vacā ajamodā'jagandhā ca hapuṣā jīrakadvayam" },
      { type: "verse", number: "100", sanskrit: "मरिचं पिप्पलीमूलं पिप्पली गजपिप्पली हिङ्गु च हिङ्गुपत्री च शटी पाठोपकुञ्चिका", text: "maricaṃ pippalīmūlaṃ pippalī gajapippalī hiṅgu ca hiṅgupatrī ca śaṭī pāṭhopakuñcikā" },
      { type: "verse", number: "101", sanskrit: "शुण्ठीचित्रकचव्यानि विडङ्गं चाम्लवेतसम् दाडिमं तिन्तिडीकं च त्रिवद् दन्ती शतावरी", text: "śuṇṭhīcitrakacavyāni viḍaṅgaṃ cāmlavetasam dāḍimaṃ tintiḍīkaṃ ca trivad dantī śatāvarī" },
      { type: "verse", number: "102", sanskrit: "इन्द्र वारुणिका भार्ङ्गी देवदारु यवानिका कुस्तुम्बुरुस्तुम्बुरूणि पौष्करं बदराणि च", text: "indra vāruṇikā bhārṅgī devadāru yavānikā kustumburustumburūṇi pauṣkaraṃ badarāṇi ca" },
      { type: "verse", number: "103", sanskrit: "शिवा चेति समांशानां चूर्णमेकत्र कारयेत् भावयेदार्द्र करसैर्बीजपूररसैस्तथा", text: "śivā ceti samāṃśānāṃ cūrṇamekatra kārayet bhāvayedārdra karasairbījapūrarasaistathā" },
      { type: "verse", number: "104", sanskrit: "तत्पिबेत्सर्पिषा जीर्णमद्येनोष्णोदकेन वा कोलाम्भसा वा तक्रेण दुग्धेनौष्ट्रेण मस्तुना", text: "tatpibetsarpiṣā jīrṇamadyenoṣṇodakena vā kolāmbhasā vā takreṇa dugdhenauṣṭreṇa mastunā" },
      { type: "verse", number: "105", sanskrit: "अर्शोविष्टम्भमन्दाग्निगुल्मप्लीहोदराणि च", text: "arśoviṣṭambhamandāgnigulmaplīhodarāṇi ca" },
      { type: "verse", number: "106", sanskrit: "हिक्काध्मानश्वासकासाञ्जयेदेतान्न संशयः एतैरेवौषधैः सम्यग्घृतं वा साधयेद्भिषक्", text: "hikkādhmānaśvāsakāsāñjayedetānna saṃśayaḥ etairevauṣadhaiḥ samyagghṛtaṃ vā sādhayedbhiṣak" },
      { type: "verse", number: "107", sanskrit: "तुम्बुरूणि त्रिलवणं यवानी पुष्कराह्वयम्", text: "tumburūṇi trilavaṇaṃ yavānī puṣkarāhvayam" },
      { type: "verse", number: "108", sanskrit: "यवक्षाराभयाहिङ्गुविडङ्गानि समानि च त्रिवृत् त्रिभागा विज्ञेया सूक्ष्मचूर्णानि कारयेत्", text: "yavakṣārābhayāhiṅguviḍaṅgāni samāni ca trivṛt tribhāgā vijñeyā sūkṣmacūrṇāni kārayet" },
      { type: "verse", number: "109", sanskrit: "पिबेदुष्णेन तोयेन यवक्वाथेन वा पिबेत् जयेत्सर्वाणि शूलानि गुल्माध्मानोदराणि च", text: "pibeduṣṇena toyena yavakvāthena vā pibet jayetsarvāṇi śūlāni gulmādhmānodarāṇi ca" },
      { type: "verse", number: "110", sanskrit: "चित्रकाद्यं चूर्णं मन्दाग्न्यादौ चित्रको नागरं हिङ्गु पिप्पली पिप्पलीजटा चव्याजमोदामरिचं प्रत्येकं कर्षसम्मितम्", text: "citrakādyaṃ cūrṇaṃ mandāgnyādau citrako nāgaraṃ hiṅgu pippalī pippalījaṭā cavyājamodāmaricaṃ pratyekaṃ karṣasammitam" },
      { type: "verse", number: "111", sanskrit: "स्वर्जिका च यवक्षारः सिन्धु सौवर्चलं बिडम् सामुद्र कं रोमकं च कोलमात्राणि कारयेत्", text: "svarjikā ca yavakṣāraḥ sindhu sauvarcalaṃ biḍam sāmudra kaṃ romakaṃ ca kolamātrāṇi kārayet" },
      { type: "verse", number: "112", sanskrit: "एकीकृत्याखिलं चूर्णं भावयेन्मातुलुङ्गजैः रसैर्दाडिमजैर्वाऽपि शोषयेदातपेन च", text: "ekīkṛtyākhilaṃ cūrṇaṃ bhāvayenmātuluṅgajaiḥ rasairdāḍimajairvā'pi śoṣayedātapena ca" },
      { type: "verse", number: "113", sanskrit: "एतच्चूर्णं जयेद् गुल्मं ग्रहणीमामजां रुजम् अग्निं च कुरुते दीप्तं रुचिकृत्कफनाशनम्", text: "etaccūrṇaṃ jayed gulmaṃ grahaṇīmāmajāṃ rujam agniṃ ca kurute dīptaṃ rucikṛtkaphanāśanam" },
      { type: "verse", number: "114", sanskrit: "सैन्धवं पिप्पलीमूलं पिप्पलीचव्य चित्रकम् शुण्ठी हरीतकी चेति क्रमवृद्धानि चूर्णयेत्", text: "saindhavaṃ pippalīmūlaṃ pippalīcavya citrakam śuṇṭhī harītakī ceti kramavṛddhāni cūrṇayet" },
      { type: "verse", number: "114", sanskrit: "वडवानलनामैतच्चूर्णं स्यादग्निदीपनम्", text: "vaḍavānalanāmaitaccūrṇaṃ syādagnidīpanam" },
      { type: "verse", number: "115", sanskrit: "अजमोदा विडङ्गानि सैन्धवं देवदारु च चित्रकः पिप्पलीमूलं शतपुष्पा च पिप्पली", text: "ajamodā viḍaṅgāni saindhavaṃ devadāru ca citrakaḥ pippalīmūlaṃ śatapuṣpā ca pippalī" },
      { type: "verse", number: "116", sanskrit: "मरिचं चेति कर्षांशं प्रत्येकं कारयेद् बुधः कर्षास्तु पञ्च पथ्याया दश स्युर्वृद्धदारुकात्", text: "maricaṃ ceti karṣāṃśaṃ pratyekaṃ kārayed budhaḥ karṣāstu pañca pathyāyā daśa syurvṛddhadārukāt" },
      { type: "verse", number: "117", sanskrit: "नागराच्च दशैव स्युः सर्वाण्येकत्र चूर्णयेत् पिबेत्कोष्णजलेनैव चूर्णं श्वयथुनाशनम्", text: "nāgarācca daśaiva syuḥ sarvāṇyekatra cūrṇayet pibetkoṣṇajalenaiva cūrṇaṃ śvayathunāśanam" },
      { type: "verse", number: "118", sanskrit: "आमवातरुजं हन्ति सन्धिपीडां च गृध्रसीम् कटिपृष्ठगुदस्थां च जङ्घयोश्च रुजं जयेत्", text: "āmavātarujaṃ hanti sandhipīḍāṃ ca gṛdhrasīm kaṭipṛṣṭhagudasthāṃ ca jaṅghayośca rujaṃ jayet" },
      { type: "verse", number: "119", sanskrit: "समेन वा गुडेनास्य वटकान्कारयेद्भिषक्", text: "samena vā guḍenāsya vaṭakānkārayedbhiṣak" },
      { type: "verse", number: "120", sanskrit: "शुण्ठी सौवर्चलं हिङ्गु दाडिमं चाम्लवेतसम् चूर्णमुष्णाम्बुना पेयं श्वासहृद्रो गशान्तये", text: "śuṇṭhī sauvarcalaṃ hiṅgu dāḍimaṃ cāmlavetasam cūrṇamuṣṇāmbunā peyaṃ śvāsahṛdro gaśāntaye" },
      { type: "verse", number: "121", sanskrit: "हिङ्गु पाठाऽभया धान्यं दाडिमं चित्रकः शटी", text: "hiṅgu pāṭhā'bhayā dhānyaṃ dāḍimaṃ citrakaḥ śaṭī" },
      { type: "verse", number: "122", sanskrit: "अजमोदा त्रिकटुकं हपुषा चाम्लवेतसम् अजगन्धा तिन्तिडीकं जीरकं पौष्करं वचा", text: "ajamodā trikaṭukaṃ hapuṣā cāmlavetasam ajagandhā tintiḍīkaṃ jīrakaṃ pauṣkaraṃ vacā" },
      { type: "verse", number: "123", sanskrit: "चव्यं क्षारद्वयं पञ्च लवणानि विचूर्णयेत् प्राग्भोजनस्य मध्ये वा चूर्णमेतत्प्रयोजयेत्", text: "cavyaṃ kṣāradvayaṃ pañca lavaṇāni vicūrṇayet prāgbhojanasya madhye vā cūrṇametatprayojayet" },
      { type: "verse", number: "124", sanskrit: "पिबेद्वा जीर्णमद्येन तक्रेणोष्णोदकेन वा गुल्मे वातकफोद्भूते हृद्ग्रहेऽष्ठीलिकासु च", text: "pibedvā jīrṇamadyena takreṇoṣṇodakena vā gulme vātakaphodbhūte hṛdgrahe'ṣṭhīlikāsu ca" },
      { type: "verse", number: "125", sanskrit: "हृद्वस्तिपार्श्वशूलेषु शूले च गुदयोनिजे मूत्रकृच्छ्रे तथानाहे पाण्डुरोगेऽरुचौ तथा", text: "hṛdvastipārśvaśūleṣu śūle ca gudayonije mūtrakṛcchre tathānāhe pāṇḍuroge'rucau tathā" },
      { type: "verse", number: "126", sanskrit: "हिक्कायां यकृति प्लीह्नि कासे श्वासे गलग्रहे ग्रहण्यर्शोविकारेषु चूर्णमेतत्प्रशस्यते", text: "hikkāyāṃ yakṛti plīhni kāse śvāse galagrahe grahaṇyarśovikāreṣu cūrṇametatpraśasyate" },
      { type: "verse", number: "127", sanskrit: "भावितं मातुलुङ्गस्य बहुशः स्वरसेन वा कुर्याच्च गुटिका बह्व्यो वातश्लेष्मामयापहाः", text: "bhāvitaṃ mātuluṅgasya bahuśaḥ svarasena vā kuryācca guṭikā bahvyo vātaśleṣmāmayāpahāḥ" },
      { type: "verse", number: "128", sanskrit: "यवानी दाडिमं शुण्ठी तिन्तिडीकाम्लवेतसौ बदराम्लं च कुर्वीत चतुःशाणमितानि च", text: "yavānī dāḍimaṃ śuṇṭhī tintiḍīkāmlavetasau badarāmlaṃ ca kurvīta catuḥśāṇamitāni ca" },
      { type: "verse", number: "129", sanskrit: "सार्धद्विशाणंमरिचं पिप्पली दशशाणिका त्वक्सौवर्चलधान्याकं जीरकं द्विद्विशाणकम्", text: "sārdhadviśāṇaṃmaricaṃ pippalī daśaśāṇikā tvaksauvarcaladhānyākaṃ jīrakaṃ dvidviśāṇakam" },
      { type: "verse", number: "130", sanskrit: "चतुःषष्टिमितैः शाणैः शर्करामत्र योजयेत् चूर्णितं सर्वमेकत्र यवानीखाण्डवाभिधम्", text: "catuḥṣaṣṭimitaiḥ śāṇaiḥ śarkarāmatra yojayet cūrṇitaṃ sarvamekatra yavānīkhāṇḍavābhidham" },
      { type: "verse", number: "131", sanskrit: "चूर्णं जयेत्पाण्डुरोगं हृद्रो गं ग्रहणीं ज्वरम् छर्दिशोकातिसारांश्च प्लीहानाहविबन्धताः अरुचिं शूलमन्दाग्निमर्शोजिह्वागलामयान्", text: "cūrṇaṃ jayetpāṇḍurogaṃ hṛdro gaṃ grahaṇīṃ jvaram chardiśokātisārāṃśca plīhānāhavibandhatāḥ aruciṃ śūlamandāgnimarśojihvāgalāmayān" },
      { type: "verse", number: "132", sanskrit: "तालीसं मरिचं शुण्ठी पिप्पली वंशरोचना एकद्वित्रिचतुःपञ्चकर्षैर्भागान्प्रकल्पयेत्", text: "tālīsaṃ maricaṃ śuṇṭhī pippalī vaṃśarocanā ekadvitricatuḥpañcakarṣairbhāgānprakalpayet" },
      { type: "verse", number: "133", sanskrit: "एलात्वचोस्तु कर्षार्द्धं प्रत्येकं भागमाचरेत् द्वात्रिंशत्कर्षतुलिता प्रदेया शर्करा बुधैः", text: "elātvacostu karṣārddhaṃ pratyekaṃ bhāgamācaret dvātriṃśatkarṣatulitā pradeyā śarkarā budhaiḥ" },
      { type: "verse", number: "134", sanskrit: "तालीसाद्यमिदं चूर्णं रोचनं पाचनं स्मृतम् कासश्वासज्वरहरं छर्द्यतीसारनाशनम्", text: "tālīsādyamidaṃ cūrṇaṃ rocanaṃ pācanaṃ smṛtam kāsaśvāsajvaraharaṃ chardyatīsāranāśanam" },
      { type: "verse", number: "135", sanskrit: "शोषाध्मानहरं प्लीहाग्रहणीपाण्डुरोगजित् पक्त्वा वा शर्करां चूर्णं क्षिपेत्स्याद् गुटिका ततः", text: "śoṣādhmānaharaṃ plīhāgrahaṇīpāṇḍurogajit paktvā vā śarkarāṃ cūrṇaṃ kṣipetsyād guṭikā tataḥ" },
      { type: "verse", number: "136", sanskrit: "सितोपलादिचूर्णं कासक्षयपित्तदाहादौ सितोपला षोडश स्यादष्टौ स्याद्वंशरोचना पिप्पली स्याच्चतुष्कर्षा स्यादेला च द्विकार्षिकी", text: "sitopalādicūrṇaṃ kāsakṣayapittadāhādau sitopalā ṣoḍaśa syādaṣṭau syādvaṃśarocanā pippalī syāccatuṣkarṣā syādelā ca dvikārṣikī" },
      { type: "verse", number: "137", sanskrit: "एकः कर्षस्त्वचः कार्यश्चूर्णयेत्सर्वमेकतः सितोपलादिकं चूर्णं मधुसर्पिर्युतं लिहेत्", text: "ekaḥ karṣastvacaḥ kāryaścūrṇayetsarvamekataḥ sitopalādikaṃ cūrṇaṃ madhusarpiryutaṃ lihet" },
      { type: "verse", number: "138", sanskrit: "श्वासकासक्षयहरं हस्तपादाङ्गदाहजित् मन्दाग्निं सुप्तजिह्वत्वं पार्श्वशूलमरोचकम् ज्वरमूर्ध्वगतं रक्तं पित्तमाशु व्यपोहति", text: "śvāsakāsakṣayaharaṃ hastapādāṅgadāhajit mandāgniṃ suptajihvatvaṃ pārśvaśūlamarocakam jvaramūrdhvagataṃ raktaṃ pittamāśu vyapohati" },
      { type: "verse", number: "139", sanskrit: "लवणभास्करचूर्णं ग्रहणीगुल्मादौ समुद्र लवणं कार्यमष्टकर्षमितं बुधैः पञ्चसौवर्चलं ग्राह्यं बिडं सैन्धवधान्यके", text: "lavaṇabhāskaracūrṇaṃ grahaṇīgulmādau samudra lavaṇaṃ kāryamaṣṭakarṣamitaṃ budhaiḥ pañcasauvarcalaṃ grāhyaṃ biḍaṃ saindhavadhānyake" },
      { type: "verse", number: "140", sanskrit: "पिप्पली पिप्पलीमूलं कृष्णजीरकपत्रकम् नागकेशरतालीसमम्लवेतसकं तथा", text: "pippalī pippalīmūlaṃ kṛṣṇajīrakapatrakam nāgakeśaratālīsamamlavetasakaṃ tathā" },
      { type: "verse", number: "141", sanskrit: "द्विकर्षमात्राण्येतानि प्रत्येकं कारयेद् बुधः मरिचं जीरकं विश्वमेकैकं कर्षमात्रकम्", text: "dvikarṣamātrāṇyetāni pratyekaṃ kārayed budhaḥ maricaṃ jīrakaṃ viśvamekaikaṃ karṣamātrakam" },
      { type: "verse", number: "142", sanskrit: "दाडिमंस्याच्चतुष्कर्षं त्वगेला चार्द्धकार्षिकी एतच्चूर्णीकृतं सर्वं लवणं भास्कराभिधम्", text: "dāḍimaṃsyāccatuṣkarṣaṃ tvagelā cārddhakārṣikī etaccūrṇīkṛtaṃ sarvaṃ lavaṇaṃ bhāskarābhidham" },
      { type: "verse", number: "143", sanskrit: "शाणप्रमाणं देयं तु मस्तुतक्रसुरासवैः वातश्लेष्मभवं गुल्मं प्लीहानमुदरं क्षयम्", text: "śāṇapramāṇaṃ deyaṃ tu mastutakrasurāsavaiḥ vātaśleṣmabhavaṃ gulmaṃ plīhānamudaraṃ kṣayam" },
      { type: "verse", number: "144", sanskrit: "अर्शांसि ग्रहणीं कुष्ठं विबन्धं च भगन्दरम् शोफं शूलं श्वासकासावामवातं च हृद्रुजम्", text: "arśāṃsi grahaṇīṃ kuṣṭhaṃ vibandhaṃ ca bhagandaram śophaṃ śūlaṃ śvāsakāsāvāmavātaṃ ca hṛdrujam" },
      { type: "verse", number: "145", sanskrit: "मन्दाग्निं नाशयेदेतद् दीपनं पाचनं परम् सर्वलोकहितार्थाय भास्करेणोदितं पुरा", text: "mandāgniṃ nāśayedetad dīpanaṃ pācanaṃ param sarvalokahitārthāya bhāskareṇoditaṃ purā" },
      { type: "verse", number: "146", sanskrit: "एलाप्रियङ्गुमुस्तानि कोलमज्जा च पिप्पली श्रीचन्दनं तथा लाजा लवङ्गं नागकेशरम्", text: "elāpriyaṅgumustāni kolamajjā ca pippalī śrīcandanaṃ tathā lājā lavaṅgaṃ nāgakeśaram" },
      { type: "verse", number: "147", sanskrit: "एतच्चूर्णीकृतं सर्वं सिताक्षौद्र युतं लिहेत् वातपित्तकफोद्भूतां छर्दिं हन्त्यतिवेगतः", text: "etaccūrṇīkṛtaṃ sarvaṃ sitākṣaudra yutaṃ lihet vātapittakaphodbhūtāṃ chardiṃ hantyativegataḥ" },
      { type: "verse", number: "148", sanskrit: "व्यिआ!घ्रीजीरकधात्रीणां चूर्णं मधुयुतंलिहेत् ऊर्ध्ववातमहाश्वासतमकैर्मुच्यते क्षणात्", text: "vyiā!ghrījīrakadhātrīṇāṃ cūrṇaṃ madhuyutaṃlihet ūrdhvavātamahāśvāsatamakairmucyate kṣaṇāt" },
      { type: "verse", number: "149", sanskrit: "मूलं पत्रं फलं पुष्पं त्वचं निम्बात्समाहरेत् सूक्ष्मचूर्णमिदंकुर्यात्पलैः पञ्चदशोन्मितैः", text: "mūlaṃ patraṃ phalaṃ puṣpaṃ tvacaṃ nimbātsamāharet sūkṣmacūrṇamidaṃkuryātpalaiḥ pañcadaśonmitaiḥ" },
      { type: "verse", number: "150", sanskrit: "लोहभस्महरीतक्यौ चक्रमर्दकचित्रकौ भल्लातकं बिडङ्गानि शर्करामलकं निशा", text: "lohabhasmaharītakyau cakramardakacitrakau bhallātakaṃ biḍaṅgāni śarkarāmalakaṃ niśā" },
      { type: "verse", number: "151", sanskrit: "पिप्पली मरिचं शुण्ठी वाकुची कृतमालकः गोक्षुरश्च पलोन्मानमेकैकं कारयेद् बुधः", text: "pippalī maricaṃ śuṇṭhī vākucī kṛtamālakaḥ gokṣuraśca palonmānamekaikaṃ kārayed budhaḥ" },
      { type: "verse", number: "152", sanskrit: "सर्वमेकीकृतं चूर्णं भृङ्गराजेन भावयेत् अष्टभागावशिष्टेन खदिरासनवारिणा", text: "sarvamekīkṛtaṃ cūrṇaṃ bhṛṅgarājena bhāvayet aṣṭabhāgāvaśiṣṭena khadirāsanavāriṇā" },
      { type: "verse", number: "153", sanskrit: "भावयित्वा च संशुष्कं कर्षमात्रं ततः पिबेत् खदिरासनतोयेन सर्पिषा पयसाथवा", text: "bhāvayitvā ca saṃśuṣkaṃ karṣamātraṃ tataḥ pibet khadirāsanatoyena sarpiṣā payasāthavā" },
      { type: "verse", number: "154", sanskrit: "मासेन सर्वकुष्ठानि विनिहन्ति रसायनम् पञ्चनिम्बमिदं चूर्णं सर्वरोगप्रणाशनम्", text: "māsena sarvakuṣṭhāni vinihanti rasāyanam pañcanimbamidaṃ cūrṇaṃ sarvarogapraṇāśanam" },
      { type: "verse", number: "155", sanskrit: "शतावरी गोक्षुरश्च बीजं च कपिकच्छुजम् गाङ्गेरुकी चातिबला बीजमिक्षुरकोद्भवम्", text: "śatāvarī gokṣuraśca bījaṃ ca kapikacchujam gāṅgerukī cātibalā bījamikṣurakodbhavam" },
      { type: "verse", number: "156", sanskrit: "चूर्णितं सर्वमेकत्र गोदुग्धेन पिबेन्निशि न तृप्तिं याति नारीभिर्नरश्चूर्णप्रभावतः", text: "cūrṇitaṃ sarvamekatra godugdhena pibenniśi na tṛptiṃ yāti nārībhirnaraścūrṇaprabhāvataḥ" },
      { type: "verse", number: "157", sanskrit: "अश्वगन्धा दशपला तन्मात्रो वृद्धदारकः चूर्णीकृत्योभयं विद्वान्घृतभाण्डे निधापयेत्", text: "aśvagandhā daśapalā tanmātro vṛddhadārakaḥ cūrṇīkṛtyobhayaṃ vidvānghṛtabhāṇḍe nidhāpayet" },
      { type: "verse", number: "158", sanskrit: "कर्षैकं पयसा पीत्वा नारीभिर्नैव तृप्यति अगत्वा प्रमदां भूयाद्वलीपलितवर्जितः", text: "karṣaikaṃ payasā pītvā nārībhirnaiva tṛpyati agatvā pramadāṃ bhūyādvalīpalitavarjitaḥ" },
      { type: "verse", number: "159", sanskrit: "मुसलीकन्दचूर्णं तु गुडूचीसत्त्वसंयुतम् वानरीगोक्षुराभ्यां च शाल्मलीशर्करामलैः आलोड्य घृतदुग्धेन पाययेत्कामवर्धनम्", text: "musalīkandacūrṇaṃ tu guḍūcīsattvasaṃyutam vānarīgokṣurābhyāṃ ca śālmalīśarkarāmalaiḥ āloḍya ghṛtadugdhena pāyayetkāmavardhanam" },
      { type: "verse", number: "160", sanskrit: "चित्रकं त्रिफला मुस्तं विडङ्गं त्र्! यूषणानि च समभागानि कार्याणि नव भागा हतायसः", text: "citrakaṃ triphalā mustaṃ viḍaṅgaṃ tr! yūṣaṇāni ca samabhāgāni kāryāṇi nava bhāgā hatāyasaḥ" },
      { type: "verse", number: "161", sanskrit: "एतदेकीकृतं चूर्णं मधुसर्पिर्युतं लिहेत् गोमूत्रमथवा तक्रमनुपाने प्रशस्यते", text: "etadekīkṛtaṃ cūrṇaṃ madhusarpiryutaṃ lihet gomūtramathavā takramanupāne praśasyate" },
      { type: "verse", number: "162", sanskrit: "पाण्डुरोगं जयत्युग्रं हृद्रो गं च भगन्दरम् शोथकुष्ठोदरार्शांसि मन्दाग्निमरुचिं कृमीन्", text: "pāṇḍurogaṃ jayatyugraṃ hṛdro gaṃ ca bhagandaram śothakuṣṭhodarārśāṃsi mandāgnimaruciṃ kṛmīn" },
      { type: "verse", number: "163", sanskrit: "आकारकरभः शुण्ठी कङ्कोलं कुङ्कुमं कणा जातीफलं लवङ्गं च चन्दनं चेति कार्षिकान्", text: "ākārakarabhaḥ śuṇṭhī kaṅkolaṃ kuṅkumaṃ kaṇā jātīphalaṃ lavaṅgaṃ ca candanaṃ ceti kārṣikān" },
      { type: "verse", number: "164", sanskrit: "चूर्णानि मानतः कुर्यादहिफेनं पलोन्मितं सर्वमेकीकृतं चूर्णं माषैकं मधुना लिहेत्", text: "cūrṇāni mānataḥ kuryādahiphenaṃ palonmitaṃ sarvamekīkṛtaṃ cūrṇaṃ māṣaikaṃ madhunā lihet" },
      { type: "verse", number: "165", sanskrit: "शुक्रस्तम्भकरं चूर्णं पुंसामानन्दकारकम् नारीणां प्रीतिजननं सेवेत निशि कामुकः", text: "śukrastambhakaraṃ cūrṇaṃ puṃsāmānandakārakam nārīṇāṃ prītijananaṃ seveta niśi kāmukaḥ" },
      { type: "verse", number: "166", sanskrit: "बकुलत्वक्चूर्णं दन्तदार्ढ्ये बकुलत्वग्भवं चूर्णं घर्षयेद्दन्तपङ्क्तिषु वज्रादपि दृढीभूता दन्ताः स्युश्चपला ध्रुवम्", text: "bakulatvakcūrṇaṃ dantadārḍhye bakulatvagbhavaṃ cūrṇaṃ gharṣayeddantapaṅktiṣu vajrādapi dṛḍhībhūtā dantāḥ syuścapalā dhruvam" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 7,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Вашира санграха — Вертикальные препараты" },
      { type: "text", text: "Ваши, аришта и асава — алкоголь-содержащие ферментированные препараты. Описывается технология ферментации, сроки готовности и показания." },
      { type: "verse", number: "1", sanskrit: "अथ वटककल्पनानाम सप्तमोऽध्यायः वटकनामानि वटकाश्चाथ कथ्यन्ते तन्नाम गुटिका वटी मोदको वटिका पिण्डी गुडो वर्त्तिस्तथोच्यते", text: "atha vaṭakakalpanānāma saptamo'dhyāyaḥ vaṭakanāmāni vaṭakāścātha kathyante tannāma guṭikā vaṭī modako vaṭikā piṇḍī guḍo varttistathocyate" },
      { type: "verse", number: "2", sanskrit: "लेहवत्साध्यते वह्नौ गुडो वा शर्करा तथा गुग्गुलुर्वा क्षिपेत्तत्र चूर्णं तन्निर्मिता वटी", text: "lehavatsādhyate vahnau guḍo vā śarkarā tathā guggulurvā kṣipettatra cūrṇaṃ tannirmitā vaṭī" },
      { type: "verse", number: "3", sanskrit: "कुर्यादवह्निसिद्धेन क्वचिद् गुग्गुलुना वटीम् द्र वेण मधुना वाऽपि गुटिकां कारयेद् बुधः", text: "kuryādavahnisiddhena kvacid guggulunā vaṭīm dra veṇa madhunā vā'pi guṭikāṃ kārayed budhaḥ" },
      { type: "verse", number: "4", sanskrit: "वटिकायां गुडशर्करामाननिर्णयः सिता चतुर्गुणा देया वटीषु द्विगुणो गुडः चूर्णाच्चूर्णसमः कार्यो गुग्गुलुर्मधु तत्समम् द्र वं च द्विगुणं देयं मोदकेषु भिषग्वरैः", text: "vaṭikāyāṃ guḍaśarkarāmānanirṇayaḥ sitā caturguṇā deyā vaṭīṣu dviguṇo guḍaḥ cūrṇāccūrṇasamaḥ kāryo guggulurmadhu tatsamam dra vaṃ ca dviguṇaṃ deyaṃ modakeṣu bhiṣagvaraiḥ" },
      { type: "verse", number: "5", sanskrit: "कर्षप्रमाणा तन्मात्रा बलं दृष्ट्वा प्रयुज्यताम्", text: "karṣapramāṇā tanmātrā balaṃ dṛṣṭvā prayujyatām" },
      { type: "verse", number: "6", sanskrit: "इन्द्र वारुणिका मुस्तं शुण्ठी दन्ती हरीतकी त्रिवृच्छटी विडङ्गानि गोक्षुरश्चित्रकस्तथा", text: "indra vāruṇikā mustaṃ śuṇṭhī dantī harītakī trivṛcchaṭī viḍaṅgāni gokṣuraścitrakastathā" },
      { type: "verse", number: "7", sanskrit: "तेजोह्वा च द्विकर्षाणि पृथग्द्र व्याणि कारयेत् सूरणस्य पलान्यष्टौ वृद्धदारु चतुष्पलम्", text: "tejohvā ca dvikarṣāṇi pṛthagdra vyāṇi kārayet sūraṇasya palānyaṣṭau vṛddhadāru catuṣpalam" },
      { type: "verse", number: "8", sanskrit: "चतुष्पलं स्याद् भल्लातः क्वाथयेत्सर्वमेकतः जलद्रो णे चतुर्थांशं गृह्णीयात्क्वाथमुत्तमम्", text: "catuṣpalaṃ syād bhallātaḥ kvāthayetsarvamekataḥ jaladro ṇe caturthāṃśaṃ gṛhṇīyātkvāthamuttamam" },
      { type: "verse", number: "9", sanskrit: "क्वाथ्यद्र व्यात्त्रिगुणितं गुडं क्षिप्त्वा पुनः पचेत् सम्यक्पक्वं च विज्ञाय चूर्णमेतत्प्रदापयेत्", text: "kvāthyadra vyāttriguṇitaṃ guḍaṃ kṣiptvā punaḥ pacet samyakpakvaṃ ca vijñāya cūrṇametatpradāpayet" },
      { type: "verse", number: "10", sanskrit: "चित्रकत्रिवृतादन्तीतेजोह्वाःपलिकाः पृथक् पृथक्त्रिपलिकाः कार्या व्योषैलामरिचत्वचः", text: "citrakatrivṛtādantītejohvāḥpalikāḥ pṛthak pṛthaktripalikāḥ kāryā vyoṣailāmaricatvacaḥ" },
      { type: "verse", number: "11", sanskrit: "निक्षिपेन्मधु शीते च तस्मिन्प्रस्थप्रमाणतः एवं सिद्धो भवेच्छ्रीमान्बाहुशालगुडः शुभः", text: "nikṣipenmadhu śīte ca tasminprasthapramāṇataḥ evaṃ siddho bhavecchrīmānbāhuśālaguḍaḥ śubhaḥ" },
      { type: "verse", number: "12", sanskrit: "जयेदर्शांसि सर्वाणि गुल्मं वातोदरं तथा आमवातप्रतिश्यायग्रहणीक्षयपीनसान् हलीमकं पाण्डुरोगं प्रमेहं च रसायनम्", text: "jayedarśāṃsi sarvāṇi gulmaṃ vātodaraṃ tathā āmavātapratiśyāyagrahaṇīkṣayapīnasān halīmakaṃ pāṇḍurogaṃ pramehaṃ ca rasāyanam" },
      { type: "verse", number: "13", sanskrit: "मरिचं कर्षमात्रं स्यात्पिप्पली कर्षसंमिता", text: "maricaṃ karṣamātraṃ syātpippalī karṣasaṃmitā" },
      { type: "verse", number: "14", sanskrit: "अर्धकर्षो यवक्षारः कर्षयुग्मं च दाडिमम् एतच्चूर्णीकृतं युञ्ज्यादष्टकर्षगुडेन हि", text: "ardhakarṣo yavakṣāraḥ karṣayugmaṃ ca dāḍimam etaccūrṇīkṛtaṃ yuñjyādaṣṭakarṣaguḍena hi" },
      { type: "verse", number: "15", sanskrit: "शाणप्रमाणां गुटिकां कृत्वा वक्त्रे विधारयेत् अस्याः प्रभावात्सर्वेऽपि कासा यान्त्येव सङ्क्षयम्", text: "śāṇapramāṇāṃ guṭikāṃ kṛtvā vaktre vidhārayet asyāḥ prabhāvātsarve'pi kāsā yāntyeva saṅkṣayam" },
      { type: "verse", number: "16", sanskrit: "गुडवटिका बिभीतकप्रयोगश्च श्वासकासादौ गुडशुण्ठीशिवामुस्तैर्गुटिकां धारयेन्मुखे श्वासकासेषु सर्वेषु बिभीतं वाऽपि केवलम्", text: "guḍavaṭikā bibhītakaprayogaśca śvāsakāsādau guḍaśuṇṭhīśivāmustairguṭikāṃ dhārayenmukhe śvāsakāseṣu sarveṣu bibhītaṃ vā'pi kevalam" },
      { type: "verse", number: "17", sanskrit: "आमलं कमलं कुष्ठं लाजाश्च वटरोहकम् एतच्चूर्णस्य मधुना गुटिकां धारयेन्मुखे तृष्णां प्रवृद्धां हन्त्येषा मुखशोषं च दारुणम्", text: "āmalaṃ kamalaṃ kuṣṭhaṃ lājāśca vaṭarohakam etaccūrṇasya madhunā guṭikāṃ dhārayenmukhe tṛṣṇāṃ pravṛddhāṃ hantyeṣā mukhaśoṣaṃ ca dāruṇam" },
      { type: "verse", number: "18", sanskrit: "सञ्जीवनीवटी सन्निपातज्वरे सर्पदष्टादौ च विडङ्गं नागरं कृष्णा पथ्यामलबिभीतकम्", text: "sañjīvanīvaṭī sannipātajvare sarpadaṣṭādau ca viḍaṅgaṃ nāgaraṃ kṛṣṇā pathyāmalabibhītakam" },
      { type: "verse", number: "19", sanskrit: "वचागुडूची भल्लातं सविषं चात्र योजयेत् एतानि समभागानि गोमूत्रेणैव पेषयेत्", text: "vacāguḍūcī bhallātaṃ saviṣaṃ cātra yojayet etāni samabhāgāni gomūtreṇaiva peṣayet" },
      { type: "verse", number: "20", sanskrit: "गुञ्जाभा गुटिका कार्या दद्यादार्द्र कजै रसैः एकामजीर्णगुल्मेषु द्वे विषूच्यां प्रदापयेत्", text: "guñjābhā guṭikā kāryā dadyādārdra kajai rasaiḥ ekāmajīrṇagulmeṣu dve viṣūcyāṃ pradāpayet" },
      { type: "verse", number: "21", sanskrit: "तिस्रश्च सर्पदष्टे तु चतस्रः सान्निपातिके वटी सञ्जीवनी नाम्ना सञ्जीवयति मानवम्", text: "tisraśca sarpadaṣṭe tu catasraḥ sānnipātike vaṭī sañjīvanī nāmnā sañjīvayati mānavam" },
      { type: "verse", number: "22", sanskrit: "व्योषाम्लवेतसंचव्यं तालीसं चित्रकं तथा जीरकंतिन्तिडीकं च प्रत्येकं कर्षभागिकम्", text: "vyoṣāmlavetasaṃcavyaṃ tālīsaṃ citrakaṃ tathā jīrakaṃtintiḍīkaṃ ca pratyekaṃ karṣabhāgikam" },
      { type: "verse", number: "23", sanskrit: "त्रिसुगन्धं त्रिशाणं स्याद् गुडः स्यात्कर्षविंशतिः व्योषादिगुटिका सामपीनसश्वासकासजित् रुचिस्वरकरा ख्याता प्रतिश्यायप्रणाशिनी", text: "trisugandhaṃ triśāṇaṃ syād guḍaḥ syātkarṣaviṃśatiḥ vyoṣādiguṭikā sāmapīnasaśvāsakāsajit rucisvarakarā khyātā pratiśyāyapraṇāśinī" },
      { type: "verse", number: "24", sanskrit: "आमेषु सगुडां शुण्ठीमजीर्णे गुडपिप्पलीम् कृच्छ्रे जीरगुडं दद्यादर्शःसु सगुडाभयाम्", text: "āmeṣu saguḍāṃ śuṇṭhīmajīrṇe guḍapippalīm kṛcchre jīraguḍaṃ dadyādarśaḥsu saguḍābhayām" },
      { type: "verse", number: "25", sanskrit: "वृद्धदारुकभल्लातशुण्ठीचूर्णेन योजितः मोदकः सगुडो हन्यात्षड्विधार्शःकृतां रुजम्", text: "vṛddhadārukabhallātaśuṇṭhīcūrṇena yojitaḥ modakaḥ saguḍo hanyātṣaḍvidhārśaḥkṛtāṃ rujam" },
      { type: "verse", number: "26", sanskrit: "शुष्कशूरणचूर्णस्य भागान्द्वात्रिंशदाहरेत् भागान्षोडश चित्रस्य शुण्ठ्या भागचतुष्टयम्", text: "śuṣkaśūraṇacūrṇasya bhāgāndvātriṃśadāharet bhāgānṣoḍaśa citrasya śuṇṭhyā bhāgacatuṣṭayam" },
      { type: "verse", number: "27", sanskrit: "द्वौ भागौ मरिचस्यापि सर्वाण्येकत्र चूर्णयेत् गुडेन पिण्डिकां कुर्यादर्शसां नाशनीं पराम्", text: "dvau bhāgau maricasyāpi sarvāṇyekatra cūrṇayet guḍena piṇḍikāṃ kuryādarśasāṃ nāśanīṃ parām" },
      { type: "verse", number: "28", sanskrit: "शूरणो वृद्धदारुश्च भागैः षोडशभिः पृथक्", text: "śūraṇo vṛddhadāruśca bhāgaiḥ ṣoḍaśabhiḥ pṛthak" },
      { type: "verse", number: "29", sanskrit: "मुसलीचित्रकौ ज्ञेयावष्टभागमितौ पृथक् शिवा बिभीतकी धात्री विडङ्गं नागरं कणा", text: "musalīcitrakau jñeyāvaṣṭabhāgamitau pṛthak śivā bibhītakī dhātrī viḍaṅgaṃ nāgaraṃ kaṇā" },
      { type: "verse", number: "30", sanskrit: "भल्लातः पिप्पलीमूलं तालीसं च पृथक्पृथक् चतुर्भागप्रमाणानि त्वगेलामरिचं तथा", text: "bhallātaḥ pippalīmūlaṃ tālīsaṃ ca pṛthakpṛthak caturbhāgapramāṇāni tvagelāmaricaṃ tathā" },
      { type: "verse", number: "31", sanskrit: "द्विभागमात्राणि पृथक् ततस्त्वेकत्र चूर्णयेत् द्विगुणेन गुडेनाथ वटकान्कारयेद् बुधः", text: "dvibhāgamātrāṇi pṛthak tatastvekatra cūrṇayet dviguṇena guḍenātha vaṭakānkārayed budhaḥ" },
      { type: "verse", number: "32", sanskrit: "प्रबलार्न्गिकरा एते तथाऽशोनाशनाः पराः ग्रहणीं वातकफजां श्वासं कासं क्षयामयम्", text: "prabalārngikarā ete tathā'śonāśanāḥ parāḥ grahaṇīṃ vātakaphajāṃ śvāsaṃ kāsaṃ kṣayāmayam" },
      { type: "verse", number: "33", sanskrit: "प्लीहानं श्लीपदं शोथं हिक्कां मेहं भगन्दरम् निहन्युः पलितं वृद्ध्या तथा मेध्या रसायनाः", text: "plīhānaṃ ślīpadaṃ śothaṃ hikkāṃ mehaṃ bhagandaram nihanyuḥ palitaṃ vṛddhyā tathā medhyā rasāyanāḥ" },
      { type: "verse", number: "34", sanskrit: "त्रिफला त्र्! यूषणं चव्यं पिप्पलीमूलचित्रकौ दारुमाक्षिकधातुस्त्वग्दार्वी मुस्तं विडङ्गकम्", text: "triphalā tr! yūṣaṇaṃ cavyaṃ pippalīmūlacitrakau dārumākṣikadhātustvagdārvī mustaṃ viḍaṅgakam" },
      { type: "verse", number: "35", sanskrit: "प्रत्येकं कर्षमात्राणि सर्वंद्विगुणितं तथा मण्डूरं चूर्णयेत्सर्वं गोमूत्रेऽष्टगुणे क्षिपेत्", text: "pratyekaṃ karṣamātrāṇi sarvaṃdviguṇitaṃ tathā maṇḍūraṃ cūrṇayetsarvaṃ gomūtre'ṣṭaguṇe kṣipet" },
      { type: "verse", number: "36", sanskrit: "पक्त्वा च वटकान्कृत्वा दद्यात्तक्रानुपानतः कामलापाण्डुमेहार्शः शोथकुष्ठकफामयान् ऊरुस्तम्भमजीर्णं च प्लीहानं नाशयेदपि", text: "paktvā ca vaṭakānkṛtvā dadyāttakrānupānataḥ kāmalāpāṇḍumehārśaḥ śothakuṣṭhakaphāmayān ūrustambhamajīrṇaṃ ca plīhānaṃ nāśayedapi" },
      { type: "verse", number: "37", sanskrit: "क्षौद्रा द् द्विगुणितं सर्पिर्घृताद् द्विगुणपिप्पली", text: "kṣaudrā d dviguṇitaṃ sarpirghṛtād dviguṇapippalī" },
      { type: "verse", number: "38", sanskrit: "सिता द्विगुणिता तस्याः क्षीरं देयं चतुर्गुणम् चातुर्जातं क्षौद्र तुल्यं पक्त्वा कुर्याच्च मोदकान्", text: "sitā dviguṇitā tasyāḥ kṣīraṃ deyaṃ caturguṇam cāturjātaṃ kṣaudra tulyaṃ paktvā kuryācca modakān" },
      { type: "verse", number: "39", sanskrit: "धातुस्थांश्च ज्वरान्सर्वान् श्वासं कासं च पाण्डुताम् धातुक्षयं वह्निमान्द्यं पिप्पलीमोदको जयेत्", text: "dhātusthāṃśca jvarānsarvān śvāsaṃ kāsaṃ ca pāṇḍutām dhātukṣayaṃ vahnimāndyaṃ pippalīmodako jayet" },
      { type: "verse", number: "40", sanskrit: "चन्द्र प्रभां वचां मुस्तं भूनिम्बामृतदारुकम् हरिद्रा ऽतिविषा दार्वी पिप्पलीमूलचित्रकौ", text: "candra prabhāṃ vacāṃ mustaṃ bhūnimbāmṛtadārukam haridrā 'tiviṣā dārvī pippalīmūlacitrakau" },
      { type: "verse", number: "41", sanskrit: "धान्यकं त्रिफला चव्यं विडङ्गं गजपिप्पली व्योषं माक्षिकधातुश्च द्वौ क्षारौ लवणत्रयम्", text: "dhānyakaṃ triphalā cavyaṃ viḍaṅgaṃ gajapippalī vyoṣaṃ mākṣikadhātuśca dvau kṣārau lavaṇatrayam" },
      { type: "verse", number: "42", sanskrit: "एतानि शाणमात्राणि प्रत्येकं कारयेद् बुधः त्रिवृद्दन्ती पत्रकं च त्वगेला वंशरोचना", text: "etāni śāṇamātrāṇi pratyekaṃ kārayed budhaḥ trivṛddantī patrakaṃ ca tvagelā vaṃśarocanā" },
      { type: "verse", number: "43", sanskrit: "प्रत्येकं कर्षमात्राणि कुर्यादेतानि बुद्धिमान् द्विकर्षं हतलोहं स्याच्चतुष्कर्षा सिताभवेत्", text: "pratyekaṃ karṣamātrāṇi kuryādetāni buddhimān dvikarṣaṃ hatalohaṃ syāccatuṣkarṣā sitābhavet" },
      { type: "verse", number: "44", sanskrit: "शिलाजत्वष्टकर्षं स्यादष्टौ कर्षाश्च गुग्गुलोः एभिरेकत्रसंक्षुण्णैः कर्त्तव्या गुटिका शुभा", text: "śilājatvaṣṭakarṣaṃ syādaṣṭau karṣāśca gugguloḥ ebhirekatrasaṃkṣuṇṇaiḥ karttavyā guṭikā śubhā" },
      { type: "verse", number: "45", sanskrit: "चन्द्र प्रभेति विख्याता सर्वरोगप्रणाशिनी प्रमेहान्विंशतिं कृच्छ्रं मूत्राघातं तथाऽश्मरीम्", text: "candra prabheti vikhyātā sarvarogapraṇāśinī pramehānviṃśatiṃ kṛcchraṃ mūtrāghātaṃ tathā'śmarīm" },
      { type: "verse", number: "46", sanskrit: "विबन्धानाहशूलानि मेहनं ग्रन्थिमर्बुदम् अण्डवृद्धिं तथा पाण्डुं कामलां च हलीमकम्", text: "vibandhānāhaśūlāni mehanaṃ granthimarbudam aṇḍavṛddhiṃ tathā pāṇḍuṃ kāmalāṃ ca halīmakam" },
      { type: "verse", number: "47", sanskrit: "अन्त्रवृद्धिं कटीशूलं श्वासं कासं विचर्चिकाम् कुष्ठान्यर्शांसि कण्डूं च प्लीहोदरभगन्दरं", text: "antravṛddhiṃ kaṭīśūlaṃ śvāsaṃ kāsaṃ vicarcikām kuṣṭhānyarśāṃsi kaṇḍūṃ ca plīhodarabhagandaraṃ" },
      { type: "verse", number: "48", sanskrit: "दन्तरोगं नेत्ररोगं स्त्रीणामार्त्तवजां रुजम् पुंसां शुक्रगतान्दोषान्मन्दाग्निमरुचिं तथा", text: "dantarogaṃ netrarogaṃ strīṇāmārttavajāṃ rujam puṃsāṃ śukragatāndoṣānmandāgnimaruciṃ tathā" },
      { type: "verse", number: "49", sanskrit: "वायुं पित्तं कफं हन्याद् बल्या वृष्या रसायनी चन्द्र प्रभायां कर्षस्तु चतुःशाणो विधीयते", text: "vāyuṃ pittaṃ kaphaṃ hanyād balyā vṛṣyā rasāyanī candra prabhāyāṃ karṣastu catuḥśāṇo vidhīyate" },
      { type: "verse", number: "50", sanskrit: "यवानी जीरकं धान्यं मरिचं गिरिकर्णिका अजमोदोपकुञ्ची च चतुःशाणाः पृथक्पृथक्", text: "yavānī jīrakaṃ dhānyaṃ maricaṃ girikarṇikā ajamodopakuñcī ca catuḥśāṇāḥ pṛthakpṛthak" },
      { type: "verse", number: "51", sanskrit: "हिङ्गु षट्शाणिकं कार्यं क्षारौ लवणपञ्चकम् त्रिवृच्चाष्टमितैः शाणैः प्रत्येकं कल्पयेत्सुधीः", text: "hiṅgu ṣaṭśāṇikaṃ kāryaṃ kṣārau lavaṇapañcakam trivṛccāṣṭamitaiḥ śāṇaiḥ pratyekaṃ kalpayetsudhīḥ" },
      { type: "verse", number: "52", sanskrit: "दन्ती शटी पौष्करं च विडङ्गं दाडिमं शिवा चित्रोऽम्लवेतसः शुण्ठी शाणैः षोडशभिः पृथक्", text: "dantī śaṭī pauṣkaraṃ ca viḍaṅgaṃ dāḍimaṃ śivā citro'mlavetasaḥ śuṇṭhī śāṇaiḥ ṣoḍaśabhiḥ pṛthak" },
      { type: "verse", number: "53", sanskrit: "बीजपूररसेनैषां गुटिकां कारयेद् बुधः घृतेन पयसा मद्यैरम्लैरुष्णोदकेन वा", text: "bījapūrarasenaiṣāṃ guṭikāṃ kārayed budhaḥ ghṛtena payasā madyairamlairuṣṇodakena vā" },
      { type: "verse", number: "54", sanskrit: "पिबेत्काङ्कायनप्रोक्तां गुटिकां गुल्मनाशिनीम् मद्येन वातिकं गुल्मं गोक्षीरेण च पैत्तिकम्", text: "pibetkāṅkāyanaproktāṃ guṭikāṃ gulmanāśinīm madyena vātikaṃ gulmaṃ gokṣīreṇa ca paittikam" },
      { type: "verse", number: "55", sanskrit: "मूत्रेण कफगुल्मं च दशमूलैस्त्रिदोषजम् उष्ट्रीदुग्धेन नारीणां रक्तगुल्मं निवारयेत् हृद्रो गं ग्रहणीं शूलं कृमीनर्शांसि नाशयेत्", text: "mūtreṇa kaphagulmaṃ ca daśamūlaistridoṣajam uṣṭrīdugdhena nārīṇāṃ raktagulmaṃ nivārayet hṛdro gaṃ grahaṇīṃ śūlaṃ kṛmīnarśāṃsi nāśayet" },
      { type: "verse", number: "56", sanskrit: "योगराजगुग्गुलुर्वातरोगे आमवाते वा नागरं पिप्पलीमूलं पिप्पली चव्यचित्रकौ", text: "yogarājaguggulurvātaroge āmavāte vā nāgaraṃ pippalīmūlaṃ pippalī cavyacitrakau" },
      { type: "verse", number: "57", sanskrit: "भृष्टं हिङ्ग्वजमोदा च सर्षपो जीरकद्वयम् रेणुकेन्द्र यवाः पाठा विडङ्गं गजपिप्पली", text: "bhṛṣṭaṃ hiṅgvajamodā ca sarṣapo jīrakadvayam reṇukendra yavāḥ pāṭhā viḍaṅgaṃ gajapippalī" },
      { type: "verse", number: "58", sanskrit: "कटुकाऽतिविषा भार्ङ्गी वचा मूर्वेति भागतः प्रत्येकं शाणिकानि स्युर्द्र व्याणीमानि विंशतिः", text: "kaṭukā'tiviṣā bhārṅgī vacā mūrveti bhāgataḥ pratyekaṃ śāṇikāni syurdra vyāṇīmāni viṃśatiḥ" },
      { type: "verse", number: "59", sanskrit: "द्र व्येभ्यः सकलेभ्यश्च त्रिफला द्विगुणा भवेत् एभिश्चूर्णीकृतैः सर्वैः समो देयश्च गुग्गुलुः", text: "dra vyebhyaḥ sakalebhyaśca triphalā dviguṇā bhavet ebhiścūrṇīkṛtaiḥ sarvaiḥ samo deyaśca gugguluḥ" },
      { type: "verse", number: "60", sanskrit: "विङ्गं रौप्यं च नागं च लोहसारस्तथाभ्रकम् मण्डूरं रससिन्दूरं प्रत्येकं पलसम्मितम्", text: "viṅgaṃ raupyaṃ ca nāgaṃ ca lohasārastathābhrakam maṇḍūraṃ rasasindūraṃ pratyekaṃ palasammitam" },
      { type: "verse", number: "61", sanskrit: "गुडपाकसमं कृत्वा इमं दद्याद्यथोचितम् एकपिण्डं ततः कृत्वा धारयेद् घृतभाजने", text: "guḍapākasamaṃ kṛtvā imaṃ dadyādyathocitam ekapiṇḍaṃ tataḥ kṛtvā dhārayed ghṛtabhājane" },
      { type: "verse", number: "62", sanskrit: "गुटिकाः शाणमात्रास्तु कृत्वा ग्राह्या यथोचिताः गुग्गुलुर्योगराजोऽय त्रिदोषघ्नो रसायनः", text: "guṭikāḥ śāṇamātrāstu kṛtvā grāhyā yathocitāḥ gugguluryogarājo'ya tridoṣaghno rasāyanaḥ" },
      { type: "verse", number: "63", sanskrit: "मैथुनाहारपानानां त्यागो नैवात्र विद्यते सर्वान्वातामयान्कुष्ठानर्शांसि ग्रहणीगदम्", text: "maithunāhārapānānāṃ tyāgo naivātra vidyate sarvānvātāmayānkuṣṭhānarśāṃsi grahaṇīgadam" },
      { type: "verse", number: "64", sanskrit: "प्रमेहं वातरक्तं च नाभिशूलं भगन्दरम् उदावर्तं क्षयं गुल्ममपस्मारमुरोग्रहम्", text: "pramehaṃ vātaraktaṃ ca nābhiśūlaṃ bhagandaram udāvartaṃ kṣayaṃ gulmamapasmāramurograham" },
      { type: "verse", number: "65", sanskrit: "मन्दाग्निश्वासकासांश्च नाशयेदरुचिं तथा रेतोदोषहरः पुंसां रजोदोषहरः स्त्रियाः", text: "mandāgniśvāsakāsāṃśca nāśayedaruciṃ tathā retodoṣaharaḥ puṃsāṃ rajodoṣaharaḥ striyāḥ" },
      { type: "verse", number: "66", sanskrit: "पुंसामपत्यजनको वन्ध्यानां गर्भदस्तथा रास्नादिक्वाथसंयुक्तो विविधं हन्ति मारुतम्", text: "puṃsāmapatyajanako vandhyānāṃ garbhadastathā rāsnādikvāthasaṃyukto vividhaṃ hanti mārutam" },
      { type: "verse", number: "67", sanskrit: "काकोल्यादिशृतात्पित्तं कफमारग्वधादिना दार्वीशृतेन मेहांश्च गोमूत्रेण च पाण्डुताम्", text: "kākolyādiśṛtātpittaṃ kaphamāragvadhādinā dārvīśṛtena mehāṃśca gomūtreṇa ca pāṇḍutām" },
      { type: "verse", number: "68", sanskrit: "मेदोवृद्धिं च मधुना कुष्ठं निम्बशृतेन वा छिन्नाक्वाथेन वातास्रं शोथं शूलं कणाशृतात्", text: "medovṛddhiṃ ca madhunā kuṣṭhaṃ nimbaśṛtena vā chinnākvāthena vātāsraṃ śothaṃ śūlaṃ kaṇāśṛtāt" },
      { type: "verse", number: "69", sanskrit: "पाटलाक्वाथसहितो विषं मूषकजं जयेत् त्रिफलाक्वाथसहितो नेत्रार्त्तिं हन्ति दारुणाम् पुनर्नवादिक्वाथेन हन्यात्सर्वोदरान्यपि", text: "pāṭalākvāthasahito viṣaṃ mūṣakajaṃ jayet triphalākvāthasahito netrārttiṃ hanti dāruṇām punarnavādikvāthena hanyātsarvodarānyapi" },
      { type: "verse", number: "70", sanskrit: "त्रिफलायास्त्रयः प्रस्थाः प्रस्थैका चामृता भवेत्", text: "triphalāyāstrayaḥ prasthāḥ prasthaikā cāmṛtā bhavet" },
      { type: "verse", number: "71", sanskrit: "संकुट्य लोहपात्रे तु सार्धद्रो णाम्बुना पचेत् जलमर्धशृतंज्ञात्वा गृह्णीयाद्वस्त्रगालितम्", text: "saṃkuṭya lohapātre tu sārdhadro ṇāmbunā pacet jalamardhaśṛtaṃjñātvā gṛhṇīyādvastragālitam" },
      { type: "verse", number: "72", sanskrit: "ततः क्वाथे क्षिपेच्छुद्धं गुग्गुलुं प्रस्थसम्मितम् पुनः पचेदयः पात्रे दर्व्या सङ्घट्टयेन्मुहुः", text: "tataḥ kvāthe kṣipecchuddhaṃ gugguluṃ prasthasammitam punaḥ pacedayaḥ pātre darvyā saṅghaṭṭayenmuhuḥ" },
      { type: "verse", number: "73", sanskrit: "सान्द्री भूतं च तं ज्ञात्वा गुडपाकसमाकृतिम् चूर्णीकृत्य ततस्तत्र द्र व्याणीमानि निक्षिपेत्", text: "sāndrī bhūtaṃ ca taṃ jñātvā guḍapākasamākṛtim cūrṇīkṛtya tatastatra dra vyāṇīmāni nikṣipet" },
      { type: "verse", number: "74", sanskrit: "त्रिफला द्विपला ज्ञेया गुडूची पलिका मता षडक्षंत्र्! यूषणं प्रोक्तं विडङ्गानां पलार्धकम्", text: "triphalā dvipalā jñeyā guḍūcī palikā matā ṣaḍakṣaṃtr! yūṣaṇaṃ proktaṃ viḍaṅgānāṃ palārdhakam" },
      { type: "verse", number: "75", sanskrit: "दन्ती कर्षमिता कार्या त्रिवृत्कर्षमिता स्मृता ततः पिण्डीकृतं सर्वं घृतपात्रे विनिक्षिपेत्", text: "dantī karṣamitā kāryā trivṛtkarṣamitā smṛtā tataḥ piṇḍīkṛtaṃ sarvaṃ ghṛtapātre vinikṣipet" },
      { type: "verse", number: "76", sanskrit: "गुटिकाः शाणमात्रेण युञ्ज्याद् दोषाद्यपेक्षया अनुपाने भिषग्दद्यात्कोष्णं नीरं पयोऽथवा", text: "guṭikāḥ śāṇamātreṇa yuñjyād doṣādyapekṣayā anupāne bhiṣagdadyātkoṣṇaṃ nīraṃ payo'thavā" },
      { type: "verse", number: "77", sanskrit: "मञ्जिष्ठादिशृतं वाऽपि युक्तियुक्तमतः परम् जयेत्सर्वाणि कुष्ठानि वातरक्तं त्रिदोषजम्", text: "mañjiṣṭhādiśṛtaṃ vā'pi yuktiyuktamataḥ param jayetsarvāṇi kuṣṭhāni vātaraktaṃ tridoṣajam" },
      { type: "verse", number: "78", sanskrit: "सर्वव्रणांश्च गुल्मांश्च प्रमेहपिडिकास्तथा प्रमेहोदरमन्दाग्निकासश्वयथुपाण्डुजान्", text: "sarvavraṇāṃśca gulmāṃśca pramehapiḍikāstathā pramehodaramandāgnikāsaśvayathupāṇḍujān" },
      { type: "verse", number: "79", sanskrit: "हन्ति सर्वामयान्नित्यमुपयुक्तो रसायनः केशोरकाभिधानोऽय गुग्गुलुः कान्तिकारकः", text: "hanti sarvāmayānnityamupayukto rasāyanaḥ keśorakābhidhāno'ya gugguluḥ kāntikārakaḥ" },
      { type: "verse", number: "80", sanskrit: "वासादिना नेत्रगदान्गुल्मादीन्वरुणादिना क्वाथेन खदिरस्यापि व्रणकुष्ठानि नाशयेत्", text: "vāsādinā netragadāngulmādīnvaruṇādinā kvāthena khadirasyāpi vraṇakuṣṭhāni nāśayet" },
      { type: "verse", number: "81", sanskrit: "अम्लं तीक्ष्णमजीर्णं च व्यवायं श्रममातपम् मद्यंरोषंत्यजेत्सम्यग्गुणार्थी पुरसेवकः", text: "amlaṃ tīkṣṇamajīrṇaṃ ca vyavāyaṃ śramamātapam madyaṃroṣaṃtyajetsamyagguṇārthī purasevakaḥ" },
      { type: "verse", number: "82", sanskrit: "त्रिपलं त्रिफलाचूर्णं कृष्णाचूर्णं पलोन्मितम् गुग्गुलुः पाञ्चपलिकः क्षोदयेत्सर्वमेकतः", text: "tripalaṃ triphalācūrṇaṃ kṛṣṇācūrṇaṃ palonmitam gugguluḥ pāñcapalikaḥ kṣodayetsarvamekataḥ" },
      { type: "verse", number: "83", sanskrit: "ततस्तुगुटिकां कृत्वा प्रयुञ्ज्याद्वह्न्यपेक्षया भगन्दरं गुल्मशोथावर्शांसि च विनाशयेत्", text: "tatastuguṭikāṃ kṛtvā prayuñjyādvahnyapekṣayā bhagandaraṃ gulmaśothāvarśāṃsi ca vināśayet" },
      { type: "verse", number: "84", sanskrit: "गोक्षुरादिगुग्गुलः प्रमेहादौ अष्टाविंशतिसंख्यानि पलान्यानीय गोक्षुरात् विपचेत्षङ्गुणेनीरे क्वाथो ग्राह्योऽद्धशेषितः", text: "gokṣurādiguggulaḥ pramehādau aṣṭāviṃśatisaṃkhyāni palānyānīya gokṣurāt vipacetṣaṅguṇenīre kvātho grāhyo'ddhaśeṣitaḥ" },
      { type: "verse", number: "85", sanskrit: "ततः पुनः पचेत्तत्र पुटं सप्तपलं क्षिपेत् गुडपाकसमाकारं ज्ञात्वा तत्र विनिक्षिपेत्", text: "tataḥ punaḥ pacettatra puṭaṃ saptapalaṃ kṣipet guḍapākasamākāraṃ jñātvā tatra vinikṣipet" },
      { type: "verse", number: "86", sanskrit: "त्रिकटु त्रिफला मुस्तं चूर्णितं पलसप्तकम् ततः पिण्डीकृतस्यास्य गुटिकामुपयोजयेत्", text: "trikaṭu triphalā mustaṃ cūrṇitaṃ palasaptakam tataḥ piṇḍīkṛtasyāsya guṭikāmupayojayet" },
      { type: "verse", number: "87", sanskrit: "हन्यात्प्रमेहं कृच्छ्रं च प्रदरं मूत्रघातकम् वातास्रं वातरोगांश्च शुक्रदोषं तथाऽश्मरीम्", text: "hanyātpramehaṃ kṛcchraṃ ca pradaraṃ mūtraghātakam vātāsraṃ vātarogāṃśca śukradoṣaṃ tathā'śmarīm" },
      { type: "verse", number: "88", sanskrit: "त्रिफलाऽष्टपला कार्या भल्लातं च चतुष्पलम् बाकुची पञ्चपलिका विडङ्गानां चतुष्पलम्", text: "triphalā'ṣṭapalā kāryā bhallātaṃ ca catuṣpalam bākucī pañcapalikā viḍaṅgānāṃ catuṣpalam" },
      { type: "verse", number: "89", sanskrit: "हतलोहं त्रिवृच्चैव गुग्गुलुश्च शिलाजतु एकैकं पलमात्रं स्यात्पलार्द्धं पौष्करं भवेत्", text: "hatalohaṃ trivṛccaiva gugguluśca śilājatu ekaikaṃ palamātraṃ syātpalārddhaṃ pauṣkaraṃ bhavet" },
      { type: "verse", number: "90", sanskrit: "चित्रकस्य पलार्धंस्याद् द्विशाणं मरिचं भवेत् नागरं पिप्पली मुस्ता त्वगेलापत्रकुङ्कुमम्", text: "citrakasya palārdhaṃsyād dviśāṇaṃ maricaṃ bhavet nāgaraṃ pippalī mustā tvagelāpatrakuṅkumam" },
      { type: "verse", number: "91", sanskrit: "शाणोन्मितं स्यादेकैकं चूर्णयेत्सर्वमेकतः ततस्तत्प्रक्षिपेच्चूर्णं पक्वखण्डे च तत्समे", text: "śāṇonmitaṃ syādekaikaṃ cūrṇayetsarvamekataḥ tatastatprakṣipeccūrṇaṃ pakvakhaṇḍe ca tatsame" },
      { type: "verse", number: "92", sanskrit: "मोदकान्पलिकान्कृत्वा प्रयुञ्जीत यथोचितान् हन्युः सर्वाणि कुष्ठानि त्रिदोषप्रभवामयान्", text: "modakānpalikānkṛtvā prayuñjīta yathocitān hanyuḥ sarvāṇi kuṣṭhāni tridoṣaprabhavāmayān" },
      { type: "verse", number: "93", sanskrit: "शिरोऽक्षिभ्रूगतान्रोगान्हन्यात्पृष्ठगतानपि", text: "śiro'kṣibhrūgatānrogānhanyātpṛṣṭhagatānapi" },
      { type: "verse", number: "94", sanskrit: "प्राग्भोजनस्य देयं स्यादधः कायस्थिते गदे भेषजं भक्तमध्ये च रोगे जठरसंस्थिते भोजनस्योपरि ग्राह्यमूर्ध्वजत्रुगदेषु च", text: "prāgbhojanasya deyaṃ syādadhaḥ kāyasthite gade bheṣajaṃ bhaktamadhye ca roge jaṭharasaṃsthite bhojanasyopari grāhyamūrdhvajatrugadeṣu ca" },
      { type: "verse", number: "95", sanskrit: "काञ्चनारत्वचो ग्राह्यं पलानां दशकं बुधैः", text: "kāñcanāratvaco grāhyaṃ palānāṃ daśakaṃ budhaiḥ" },
      { type: "verse", number: "96", sanskrit: "त्रिफला षट्पला कार्या त्रिकटु स्यात्पलत्रयम् पलैकं वरुणं कुर्यादेलात्वक्पत्रकं तथा", text: "triphalā ṣaṭpalā kāryā trikaṭu syātpalatrayam palaikaṃ varuṇaṃ kuryādelātvakpatrakaṃ tathā" },
      { type: "verse", number: "97", sanskrit: "एकैकं कर्षमात्रं स्यात्सर्वाण्येकत्र चूर्णयेत् यावच्चूर्णमिदं सर्वं तावन्मात्रस्तु गुग्गुलुः", text: "ekaikaṃ karṣamātraṃ syātsarvāṇyekatra cūrṇayet yāvaccūrṇamidaṃ sarvaṃ tāvanmātrastu gugguluḥ" },
      { type: "verse", number: "98", sanskrit: "सङ्कुट्य सर्वमेकत्र पिण्डं कृत्वा च धारयेत् गुटिकाः शाणिकाः कार्याः प्रातर्ग्राह्या यथोचितम्", text: "saṅkuṭya sarvamekatra piṇḍaṃ kṛtvā ca dhārayet guṭikāḥ śāṇikāḥ kāryāḥ prātargrāhyā yathocitam" },
      { type: "verse", number: "99", sanskrit: "गण्डमालां जयत्युग्रामपचीमर्बुदानि च ग्रन्थीन्व्रणांश्च गुल्मांश्च कुष्ठानि च भगन्दरम्", text: "gaṇḍamālāṃ jayatyugrāmapacīmarbudāni ca granthīnvraṇāṃśca gulmāṃśca kuṣṭhāni ca bhagandaram" },
      { type: "verse", number: "100", sanskrit: "प्रदेयश्चानुपानार्थं क्वाथो मुण्डतिकाभवः क्वाथः खदिरसारस्य पथ्याक्वाथोष्णकं जलम्", text: "pradeyaścānupānārthaṃ kvātho muṇḍatikābhavaḥ kvāthaḥ khadirasārasya pathyākvāthoṣṇakaṃ jalam" },
      { type: "verse", number: "101", sanskrit: "निस्तुषं माषचूर्णं स्यात्तथा गोधूमसम्भवम् निस्तुषं यवचूर्णं च शालितण्डुलजं तथा", text: "nistuṣaṃ māṣacūrṇaṃ syāttathā godhūmasambhavam nistuṣaṃ yavacūrṇaṃ ca śālitaṇḍulajaṃ tathā" },
      { type: "verse", number: "102", sanskrit: "सूक्ष्मं च पिप्पलीचूर्णं पलिकान्युपकल्पयेत् एतदेकीकृतं सर्वं भर्जयेद्गोघृतेन च", text: "sūkṣmaṃ ca pippalīcūrṇaṃ palikānyupakalpayet etadekīkṛtaṃ sarvaṃ bharjayedgoghṛtena ca" },
      { type: "verse", number: "103", sanskrit: "अर्धमात्रेण सर्वेभ्यस्ततः खण्डं समं क्षिपेत् जलं च द्विगुणं दत्त्वा पाचयेत्तं शनैः शनैः", text: "ardhamātreṇa sarvebhyastataḥ khaṇḍaṃ samaṃ kṣipet jalaṃ ca dviguṇaṃ dattvā pācayettaṃ śanaiḥ śanaiḥ" },
      { type: "verse", number: "104", sanskrit: "ततः पक्वं समुद्धृत्य वृत्तान्कुर्वीत मोदकान् भुक्त्वा सायं पलैकं च पिबेत्क्षीरं चतुर्गुणम्", text: "tataḥ pakvaṃ samuddhṛtya vṛttānkurvīta modakān bhuktvā sāyaṃ palaikaṃ ca pibetkṣīraṃ caturguṇam" },
      { type: "verse", number: "105", sanskrit: "वर्जनीयौ विशेषेण क्षाराम्लौ द्वौ रसावपि कृत्वैवं रमयेन्नारीर्बह्वीर्न क्षीयते नरः", text: "varjanīyau viśeṣeṇa kṣārāmlau dvau rasāvapi kṛtvaivaṃ ramayennārīrbahvīrna kṣīyate naraḥ" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 8,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Мода ка санграха — Пилюли и таблетки" },
      { type: "text", text: "Гутика (пилюли) и модака (таблетки) — твёрдые лекарственные формы аюрведы. Описываются правила формовки, сушки, обёртывания и хранения твёрдых форм." },
      { type: "verse", number: "1", sanskrit: "अथ अवलेहकल्पनानामाष्टमोऽध्यायः अवलेहस्य लक्षणनाममात्रानिर्देशः क्वाथादीनां पुनः पाकाद्घनत्वं सा रसक्रिया सोऽवलेहश्च लेहः स्यात्तन्मात्रा स्यात्पलोन्मिता", text: "atha avalehakalpanānāmāṣṭamo'dhyāyaḥ avalehasya lakṣaṇanāmamātrānirdeśaḥ kvāthādīnāṃ punaḥ pākādghanatvaṃ sā rasakriyā so'valehaśca lehaḥ syāttanmātrā syātpalonmitā" },
      { type: "verse", number: "2", sanskrit: "अनुक्ते सितादीनां परिमाणनिर्देशः सिता चतुर्गुणा कार्या चूर्णाच्च द्विगुणो गुडः द्र वं चतुर्गुणं दद्यादिति सर्वत्र निश्चयः", text: "anukte sitādīnāṃ parimāṇanirdeśaḥ sitā caturguṇā kāryā cūrṇācca dviguṇo guḍaḥ dra vaṃ caturguṇaṃ dadyāditi sarvatra niścayaḥ" },
      { type: "verse", number: "3", sanskrit: "सुपक्वे तन्तुमत्त्वं स्यादवलेहोऽप्सु मज्जति खरत्वं पीडिते मुद्रा गन्धवर्णरसोद्भवः", text: "supakve tantumattvaṃ syādavaleho'psu majjati kharatvaṃ pīḍite mudrā gandhavarṇarasodbhavaḥ" },
      { type: "verse", number: "4", sanskrit: "दुग्धमिक्षुरसो यूषः पञ्चमूलकषायजः वासाक्वाथो यथायोग्यमनुपानं प्रशस्यते", text: "dugdhamikṣuraso yūṣaḥ pañcamūlakaṣāyajaḥ vāsākvātho yathāyogyamanupānaṃ praśasyate" },
      { type: "verse", number: "5", sanskrit: "कण्टकारीतुलां नीरद्रो णे पक्त्वा कषायकम् पादशेषं गृहीत्वा च तस्मिंश्चूर्णानि दापयेत्", text: "kaṇṭakārītulāṃ nīradro ṇe paktvā kaṣāyakam pādaśeṣaṃ gṛhītvā ca tasmiṃścūrṇāni dāpayet" },
      { type: "verse", number: "6", sanskrit: "पृथक्पलानि चैतानि गुडूचीचव्यचित्रकाः मुस्तं कर्कटशृङ्गी च त्र्! यूषणं धन्वयासकः", text: "pṛthakpalāni caitāni guḍūcīcavyacitrakāḥ mustaṃ karkaṭaśṛṅgī ca tr! yūṣaṇaṃ dhanvayāsakaḥ" },
      { type: "verse", number: "7", sanskrit: "भार्ङ्गी रास्ना शटी चैव शर्करा पलविंशतिः प्रत्येकं च पलान्यष्टौ प्रदद्याद् घृततैलयोः", text: "bhārṅgī rāsnā śaṭī caiva śarkarā palaviṃśatiḥ pratyekaṃ ca palānyaṣṭau pradadyād ghṛtatailayoḥ" },
      { type: "verse", number: "8", sanskrit: "पक्त्वा लेहत्वमानीय शीते मधुपलाष्टकम् चतुष्पलं तुगाक्षीर्याः पिप्पलीनां चतुष्पलम्", text: "paktvā lehatvamānīya śīte madhupalāṣṭakam catuṣpalaṃ tugākṣīryāḥ pippalīnāṃ catuṣpalam" },
      { type: "verse", number: "9", sanskrit: "क्षिप्त्वा निदध्यात्सुदृढे मृण्मये भाजने शुभे लेहोऽय हन्ति हिक्काऽत्तिश्वासकासानशेषतः", text: "kṣiptvā nidadhyātsudṛḍhe mṛṇmaye bhājane śubhe leho'ya hanti hikkā'ttiśvāsakāsānaśeṣataḥ" },
      { type: "verse", number: "10", sanskrit: "पर्ण्यौ बृहत्यौ पिप्पल्यः शृङ्गी द्रा क्षाऽमृताऽभया", text: "parṇyau bṛhatyau pippalyaḥ śṛṅgī drā kṣā'mṛtā'bhayā" },
      { type: "verse", number: "11", sanskrit: "बला भूम्यामली वासाऋद्धिर्जीवन्तिका शटी जीवकर्षभकौ मुस्तं पौष्करं काकनासिका", text: "balā bhūmyāmalī vāsāṛddhirjīvantikā śaṭī jīvakarṣabhakau mustaṃ pauṣkaraṃ kākanāsikā" },
      { type: "verse", number: "12", sanskrit: "मुद्गपर्णीं माषपर्णी विदारी च पुनर्नवा काकोल्यौ कमलं मेदे सूक्ष्मैलागरुचन्दनम्", text: "mudgaparṇīṃ māṣaparṇī vidārī ca punarnavā kākolyau kamalaṃ mede sūkṣmailāgarucandanam" },
      { type: "verse", number: "13", sanskrit: "एकैकं पलसम्मानं स्थूलचूर्णितमौषधम् एकीकृत्य बृहत्पात्रे पञ्चामलशतानि च", text: "ekaikaṃ palasammānaṃ sthūlacūrṇitamauṣadham ekīkṛtya bṛhatpātre pañcāmalaśatāni ca" },
      { type: "verse", number: "14", sanskrit: "पचेद्द्रो णजलेक्षिप्त्वाग्राह्यमष्टांशशेषितम् ततस्तुतान्यामलानिनिष्कुलीकृत्यवाससा", text: "paceddro ṇajalekṣiptvāgrāhyamaṣṭāṃśaśeṣitam tatastutānyāmalāniniṣkulīkṛtyavāsasā" },
      { type: "verse", number: "15", sanskrit: "दृढहस्तेन सम्पीड्यक्षिप्त्वा तत्र ततोघृतम् पलसप्तमितं तानि किञ्चिद् भृष्ट्वाऽल्पवह्निना", text: "dṛḍhahastena sampīḍyakṣiptvā tatra tatoghṛtam palasaptamitaṃ tāni kiñcid bhṛṣṭvā'lpavahninā" },
      { type: "verse", number: "16", sanskrit: "ततस्तत्र क्षिपेत्क्वाथं खण्डं चार्धतुलोन्मितम् लेहवत्साधयित्वा च चूर्णानीमानि दापयेत्", text: "tatastatra kṣipetkvāthaṃ khaṇḍaṃ cārdhatulonmitam lehavatsādhayitvā ca cūrṇānīmāni dāpayet" },
      { type: "verse", number: "17", sanskrit: "पिप्पली द्विपला देया तुगाक्षीरी चतुष्पला प्रत्येकं च त्रिशाणं स्यात्त्वगेलापत्रकेशराः", text: "pippalī dvipalā deyā tugākṣīrī catuṣpalā pratyekaṃ ca triśāṇaṃ syāttvagelāpatrakeśarāḥ" },
      { type: "verse", number: "18", sanskrit: "ततस्त्वेकीकृते तस्मिन्क्षिपेत्क्षौद्रं  च षट्पलम् इत्येतच्च्यवनप्रोक्तं च्यवनप्राशसंज्ञितम्", text: "tatastvekīkṛte tasminkṣipetkṣaudraṃ  ca ṣaṭpalam ityetaccyavanaproktaṃ cyavanaprāśasaṃjñitam" },
      { type: "verse", number: "19", sanskrit: "लेहं वह्निबलं दृष्ट्वा खादेत्क्षीणो रसायनम् बालवृद्धक्षतक्षीणा नारीक्षीणाश्च शोषिणः", text: "lehaṃ vahnibalaṃ dṛṣṭvā khādetkṣīṇo rasāyanam bālavṛddhakṣatakṣīṇā nārīkṣīṇāśca śoṣiṇaḥ" },
      { type: "verse", number: "20", sanskrit: "हृद्रो गिणः स्वरक्षीणा ये नरास्तेषु युज्यते कासं श्वासं पिपासां च वातास्रमुरसो ग्रहम्", text: "hṛdro giṇaḥ svarakṣīṇā ye narāsteṣu yujyate kāsaṃ śvāsaṃ pipāsāṃ ca vātāsramuraso graham" },
      { type: "verse", number: "21", sanskrit: "वातपित्तं शुक्रदोषं मूत्रदोषं च नाशयेत् मेधां स्मृतिं स्त्रीषु हर्षं कान्तिं वर्णप्रसन्नताम् अस्य प्रयोगादाप्नोति नरो जीर्णविवर्जितः", text: "vātapittaṃ śukradoṣaṃ mūtradoṣaṃ ca nāśayet medhāṃ smṛtiṃ strīṣu harṣaṃ kāntiṃ varṇaprasannatām asya prayogādāpnoti naro jīrṇavivarjitaḥ" },
      { type: "verse", number: "22", sanskrit: "कूष्माण्डावलेहो रक्तपित्तादौ निष्कुलीकृत्य कूष्माण्डखण्डान्पलशतं पचेत् निक्षिप्य द्वितुलं नीरमर्धशिष्टं च गृह्यते", text: "kūṣmāṇḍāvaleho raktapittādau niṣkulīkṛtya kūṣmāṇḍakhaṇḍānpalaśataṃ pacet nikṣipya dvitulaṃ nīramardhaśiṣṭaṃ ca gṛhyate" },
      { type: "verse", number: "23", sanskrit: "तानि कूष्माण्डखण्डानि पीडयेद् दृढवाससा आतपे शोषयेत्किञ्चिच्छूलाग्रैर्बहुशोव्यधेत्", text: "tāni kūṣmāṇḍakhaṇḍāni pīḍayed dṛḍhavāsasā ātape śoṣayetkiñcicchūlāgrairbahuśovyadhet" },
      { type: "verse", number: "24", sanskrit: "क्षिप्त्वा ताम्रकटाहे च दद्यादष्टपलं घृतम् तेन किञ्चिद्भर्जयित्वा पूर्वोक्तं तज्जलं क्षिपेत्", text: "kṣiptvā tāmrakaṭāhe ca dadyādaṣṭapalaṃ ghṛtam tena kiñcidbharjayitvā pūrvoktaṃ tajjalaṃ kṣipet" },
      { type: "verse", number: "25", sanskrit: "खण्डं पलशतं दत्त्वा सर्वमेकत्र पाचयेत् सुपक्वे पिप्पली शुण्ठी जीरकं द्विपलं पृथक्", text: "khaṇḍaṃ palaśataṃ dattvā sarvamekatra pācayet supakve pippalī śuṇṭhī jīrakaṃ dvipalaṃ pṛthak" },
      { type: "verse", number: "26", sanskrit: "पृथक्पलार्धं धान्याकं पत्रैलामरिचंत्वचम् चूर्णीकृत्य क्षिपेत्तत्र घृतार्धं क्षौद्र मावहेत्", text: "pṛthakpalārdhaṃ dhānyākaṃ patrailāmaricaṃtvacam cūrṇīkṛtya kṣipettatra ghṛtārdhaṃ kṣaudra māvahet" },
      { type: "verse", number: "27", sanskrit: "खादेदग्निबलं दृष्ट्वा रक्तपित्ती क्षयी ज्वरी शोषतृष्णाभ्रमच्छर्दिश्वासकासक्षतातुरः", text: "khādedagnibalaṃ dṛṣṭvā raktapittī kṣayī jvarī śoṣatṛṣṇābhramacchardiśvāsakāsakṣatāturaḥ" },
      { type: "verse", number: "28", sanskrit: "कूष्माण्डकावलेहोऽय बालवृद्धेषु युज्यते उरःसन्धानकृद् वृष्यो बृंहणो बलकृन्मतः", text: "kūṣmāṇḍakāvaleho'ya bālavṛddheṣu yujyate uraḥsandhānakṛd vṛṣyo bṛṃhaṇo balakṛnmataḥ" },
      { type: "verse", number: "29", sanskrit: "युक्त्या कूष्माण्डखण्डस्य शूरणं विपचेत्सुधीः अर्शसां मूढवातानां मन्दाग्नीनां च युज्यते", text: "yuktyā kūṣmāṇḍakhaṇḍasya śūraṇaṃ vipacetsudhīḥ arśasāṃ mūḍhavātānāṃ mandāgnīnāṃ ca yujyate" },
      { type: "verse", number: "30", sanskrit: "हरीतकीशतं भद्रं  यवानामाढकं तथा", text: "harītakīśataṃ bhadraṃ  yavānāmāḍhakaṃ tathā" },
      { type: "verse", number: "31", sanskrit: "पलानि दशमूलस्य विंशतिं च नियोजयेत् चित्रकः पिप्पलीमूलमपामार्गः शटी तथा", text: "palāni daśamūlasya viṃśatiṃ ca niyojayet citrakaḥ pippalīmūlamapāmārgaḥ śaṭī tathā" },
      { type: "verse", number: "32", sanskrit: "कपिकच्छूः शंखपुष्पी भार्ङ्गी च गजपिप्पली बला पुष्करमूलं च पृथग्द्विपलमात्रया", text: "kapikacchūḥ śaṃkhapuṣpī bhārṅgī ca gajapippalī balā puṣkaramūlaṃ ca pṛthagdvipalamātrayā" },
      { type: "verse", number: "33", sanskrit: "पचेत्पञ्चाढके नीरे यवैः स्विन्नैः शृतं नयेत् तच्चाभयाशतंदद्यात्क्वाथे तस्मिन्विचक्षणः", text: "pacetpañcāḍhake nīre yavaiḥ svinnaiḥ śṛtaṃ nayet taccābhayāśataṃdadyātkvāthe tasminvicakṣaṇaḥ" },
      { type: "verse", number: "34", sanskrit: "सर्पिस्तैलाष्टपलकं क्षिपेद्गुडतुलां तथा पक्त्वा लेहत्वमानीय सिद्धे शीते पृथक्पृथक्", text: "sarpistailāṣṭapalakaṃ kṣipedguḍatulāṃ tathā paktvā lehatvamānīya siddhe śīte pṛthakpṛthak" },
      { type: "verse", number: "35", sanskrit: "क्षौद्रं  च पिप्पलीचूर्णं दद्यात्कुडवमात्रया हरीतकीद्वयं खादेत्तेन लेहेन नित्यशः", text: "kṣaudraṃ  ca pippalīcūrṇaṃ dadyātkuḍavamātrayā harītakīdvayaṃ khādettena lehena nityaśaḥ" },
      { type: "verse", number: "36", sanskrit: "क्षयं कासं ज्वरं श्वासं हिक्काऽशोऽरुचिपीनसान् ग्रहणीं नाशयेदेष वलीपलितनाशनः", text: "kṣayaṃ kāsaṃ jvaraṃ śvāsaṃ hikkā'śo'rucipīnasān grahaṇīṃ nāśayedeṣa valīpalitanāśanaḥ" },
      { type: "verse", number: "37", sanskrit: "बलवर्णकरः पुंसामवलेहो रसायनम् विहितोऽगस्त्यमुनिना सर्वरोगप्रणाशनः", text: "balavarṇakaraḥ puṃsāmavaleho rasāyanam vihito'gastyamuninā sarvarogapraṇāśanaḥ" },
      { type: "verse", number: "38", sanskrit: "कुटजत्वक्तुलां द्रो णे जलस्य विपचेत्सुधीः कषायं पादशेषं च गृह्णीयाद्वस्त्रगालितम्", text: "kuṭajatvaktulāṃ dro ṇe jalasya vipacetsudhīḥ kaṣāyaṃ pādaśeṣaṃ ca gṛhṇīyādvastragālitam" },
      { type: "verse", number: "39", sanskrit: "त्रिंशत्पलंगुडस्यात्र दत्त्वा च विपचेत्पुनः सान्द्र त्वमागतं ज्ञात्वा चूर्णानीमानि दापयेत्", text: "triṃśatpalaṃguḍasyātra dattvā ca vipacetpunaḥ sāndra tvamāgataṃ jñātvā cūrṇānīmāni dāpayet" },
      { type: "verse", number: "40", sanskrit: "रसाञ्जनं मोचरसं त्रिकटु त्रिफलां तथा लज्जालुं चित्रकं पाठां बिल्वमिन्द्र यवं त्वचम्", text: "rasāñjanaṃ mocarasaṃ trikaṭu triphalāṃ tathā lajjāluṃ citrakaṃ pāṭhāṃ bilvamindra yavaṃ tvacam" },
      { type: "verse", number: "41", sanskrit: "भल्लातकं प्रतिविषां विडङ्गानि च बालकम् प्रत्येकं पलसंमानं घृतस्य कुडवं तथा", text: "bhallātakaṃ prativiṣāṃ viḍaṅgāni ca bālakam pratyekaṃ palasaṃmānaṃ ghṛtasya kuḍavaṃ tathā" },
      { type: "verse", number: "42", sanskrit: "सिद्धशीते ततो दद्यान्मधुनः कुडवं तथा जयेदेषोऽवलेहस्तु सर्वाण्यर्शांसि वेगतः", text: "siddhaśīte tato dadyānmadhunaḥ kuḍavaṃ tathā jayedeṣo'valehastu sarvāṇyarśāṃsi vegataḥ" },
      { type: "verse", number: "43", sanskrit: "ग्रहणीं पाण्डुरोगं च रक्तपित्तं च कामलाम्", text: "grahaṇīṃ pāṇḍurogaṃ ca raktapittaṃ ca kāmalām" },
      { type: "verse", number: "44", sanskrit: "अम्लपित्तं तथा शोथं कार्श्यं चैव प्रवाहिकाम् अनुपाने प्रयोक्तव्यमाजं तक्रं पयो दधि घृतं जलं वा जीर्णे च पथ्यभोजी भवेन्नरः", text: "amlapittaṃ tathā śothaṃ kārśyaṃ caiva pravāhikām anupāne prayoktavyamājaṃ takraṃ payo dadhi ghṛtaṃ jalaṃ vā jīrṇe ca pathyabhojī bhavennaraḥ" },
      { type: "verse", number: "45", sanskrit: "कुटजत्वक्तुलामाद्रा रं! द्रो णनीरे विपाचयेत् पादशेषं शृतं नीत्वा चूर्णान्येतानि दापयेत्", text: "kuṭajatvaktulāmādrā raṃ! dro ṇanīre vipācayet pādaśeṣaṃ śṛtaṃ nītvā cūrṇānyetāni dāpayet" },
      { type: "verse", number: "46", sanskrit: "लज्जालुर्धातकी बिल्वं पाठा मोचरसस्तथा मुस्तं प्रतिविषा चैव प्रत्येकं स्यात्पलं पलम्", text: "lajjālurdhātakī bilvaṃ pāṭhā mocarasastathā mustaṃ prativiṣā caiva pratyekaṃ syātpalaṃ palam" },
      { type: "verse", number: "47", sanskrit: "ततस्तु विपचेद् भूयो यावद्दर्वीप्रलेपनम् जलेन छागदुग्धेन पीतो मण्डेन वा जयेत्", text: "tatastu vipaced bhūyo yāvaddarvīpralepanam jalena chāgadugdhena pīto maṇḍena vā jayet" },
      { type: "verse", number: "48", sanskrit: "सर्वातिसारान्घोरांस्तु नानावर्णान्सवेदनान् असृग्दरं समस्तं च सर्वार्शांसि प्रवाहिकाम्", text: "sarvātisārānghorāṃstu nānāvarṇānsavedanān asṛgdaraṃ samastaṃ ca sarvārśāṃsi pravāhikām" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 9,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Авале ха санграха — Лечебные джемы" },
      { type: "text", text: "Авалеха и лехья — полутвёрдые, сладкие, лечебные формы, приготовляемые из порошков, джема, мёда и гхи. Самый популярный пример — Чьяванпраш." },
      { type: "verse", number: "1", sanskrit: "अथ स्नेहकल्पनानाम नवमोऽध्यायः घृततैलकल्पना कल्काच्चतुर्गुणीकृत्य घृतं वा तैलमेव वा चतुर्गुणे द्र वे साध्यं तस्य मात्रा पलोन्मिता", text: "atha snehakalpanānāma navamo'dhyāyaḥ ghṛtatailakalpanā kalkāccaturguṇīkṛtya ghṛtaṃ vā tailameva vā caturguṇe dra ve sādhyaṃ tasya mātrā palonmitā" },
      { type: "verse", number: "2", sanskrit: "निक्षिप्य क्वाथयेत्तोयं क्वाथ्यद्र व्याच्चतुर्गुणम् पादशिष्टं गृहीत्वा च स्नेहं तेनैव साधयेत्", text: "nikṣipya kvāthayettoyaṃ kvāthyadra vyāccaturguṇam pādaśiṣṭaṃ gṛhītvā ca snehaṃ tenaiva sādhayet" },
      { type: "verse", number: "3", sanskrit: "मृदुद्र व्यादौ क्वथने जलप्रमाणम् चतुर्गुणं मृदुद्र व्ये कठिनेऽष्टगुणं जलम् तथा च मध्यमे द्र व्ये दद्यादष्टगुणं पयः अत्यन्तकठिने द्र व्ये नीरं षोडशकं मतम्", text: "mṛdudra vyādau kvathane jalapramāṇam caturguṇaṃ mṛdudra vye kaṭhine'ṣṭaguṇaṃ jalam tathā ca madhyame dra vye dadyādaṣṭaguṇaṃ payaḥ atyantakaṭhine dra vye nīraṃ ṣoḍaśakaṃ matam" },
      { type: "verse", number: "4", sanskrit: "कर्षादितः पलं यावत्क्षिपेत्षोडशकं जलम्", text: "karṣāditaḥ palaṃ yāvatkṣipetṣoḍaśakaṃ jalam" },
      { type: "verse", number: "5", sanskrit: "तदूर्ध्वं कुडवं यावद्भवेदष्टगुणं पयः प्रस्थादितः क्षिपेन्नीरं खारीं यावच्चतुर्गुणम्", text: "tadūrdhvaṃ kuḍavaṃ yāvadbhavedaṣṭaguṇaṃ payaḥ prasthāditaḥ kṣipennīraṃ khārīṃ yāvaccaturguṇam" },
      { type: "verse", number: "6", sanskrit: "अम्ब्वादिभिर्यत्र स्नेहसाधनं तत्र कल्कप्रमाणम् अम्बुक्वाथरसैर्यत्र पृथक्स्नेहस्य साधनम् कल्कस्यांशं तत्र दद्याच्चतुर्थं षष्ठमष्टमम्", text: "ambvādibhiryatra snehasādhanaṃ tatra kalkapramāṇam ambukvātharasairyatra pṛthaksnehasya sādhanam kalkasyāṃśaṃ tatra dadyāccaturthaṃ ṣaṣṭhamaṣṭamam" },
      { type: "verse", number: "7", sanskrit: "दुग्धे दध्नि रसे तक्रे कल्को देयोऽष्टमांशकः कल्कस्य सम्यक्पाकार्थं तोयमत्र चतुर्गुणम्", text: "dugdhe dadhni rase takre kalko deyo'ṣṭamāṃśakaḥ kalkasya samyakpākārthaṃ toyamatra caturguṇam" },
      { type: "verse", number: "8", sanskrit: "स्नेहे पञ्चाधिकद्र वव्यवस्था द्र वाणि यत्र स्नेहेषु पञ्चादीनि भवन्ति हि तत्र स्नेहसमान्याहुर्यथापूर्वं चतुर्गुणम्", text: "snehe pañcādhikadra vavyavasthā dra vāṇi yatra sneheṣu pañcādīni bhavanti hi tatra snehasamānyāhuryathāpūrvaṃ caturguṇam" },
      { type: "verse", number: "9", sanskrit: "केवलद्र व्यस्य स्नेहपाकार्थं मानम् द्र व्येण केवलेनैव स्नेहपाको भवेद्यदि तत्राम्बुपिष्टः कल्कः स्याज्जलं चात्र चतुर्गुणम्", text: "kevaladra vyasya snehapākārthaṃ mānam dra vyeṇa kevalenaiva snehapāko bhavedyadi tatrāmbupiṣṭaḥ kalkaḥ syājjalaṃ cātra caturguṇam" },
      { type: "verse", number: "10", sanskrit: "केवलक्वाथस्य स्नेहपाकार्थं मानम् क्वाथेन केवलेनैव पाको यत्रेरितः क्वचित् क्वाथ्यद्र व्यस्य कल्कोऽपि तत्र स्नेहे प्रयुज्यते", text: "kevalakvāthasya snehapākārthaṃ mānam kvāthena kevalenaiva pāko yatreritaḥ kvacit kvāthyadra vyasya kalko'pi tatra snehe prayujyate" },
      { type: "verse", number: "11", sanskrit: "कल्कहीनस्तु यः स्नेहः स साध्यः केवले द्र वे", text: "kalkahīnastu yaḥ snehaḥ sa sādhyaḥ kevale dra ve" },
      { type: "verse", number: "12", sanskrit: "पुष्पकल्कस्तु यः स्नेहस्तत्र तोयं चतुर्गुणम् स्नेहे स्नेहाष्टमांशश्च पुष्पकल्कः प्रयुज्यते", text: "puṣpakalkastu yaḥ snehastatra toyaṃ caturguṇam snehe snehāṣṭamāṃśaśca puṣpakalkaḥ prayujyate" },
      { type: "verse", number: "13", sanskrit: "वर्त्तिवत्स्नेहकल्कः स्याद्यदाङ्गुल्याविमर्दितः शब्दहीनोग्निनिक्षिप्तःस्नेहःसिद्धोभवेत्तदा", text: "varttivatsnehakalkaḥ syādyadāṅgulyāvimarditaḥ śabdahīnogninikṣiptaḥsnehaḥsiddhobhavettadā" },
      { type: "verse", number: "14", sanskrit: "घृततैलपाकयोः सिद्धौ स्वरूपनिर्देशः यदा फेनोद्गमस्तैले फेनशान्तिश्च सर्पिषि गन्धवर्णरसोत्पत्तिः स्नेहः सिद्धस्तदा भवेत्", text: "ghṛtatailapākayoḥ siddhau svarūpanirdeśaḥ yadā phenodgamastaile phenaśāntiśca sarpiṣi gandhavarṇarasotpattiḥ snehaḥ siddhastadā bhavet" },
      { type: "verse", number: "15", sanskrit: "स्नेहपाकस्य भेदास्तल्लक्षणानि च स्नेहपाकस्त्रिधा प्रोक्तो मृदुर्मध्यः खरस्तथा ईषत्सरसकल्कस्तु स्नेहपाको मृदुर्भवेत्", text: "snehapākasya bhedāstallakṣaṇāni ca snehapākastridhā prokto mṛdurmadhyaḥ kharastathā īṣatsarasakalkastu snehapāko mṛdurbhavet" },
      { type: "verse", number: "16", sanskrit: "मध्यपाकस्य सिद्धिश्च कल्के नीरसकोमले ईषत्कठिनकल्कश्च स्नेहपाको भवेत्खरः तदूर्ध्वं दग्धपाकः स्याद्दाहकृन्निष्प्रयोजनः", text: "madhyapākasya siddhiśca kalke nīrasakomale īṣatkaṭhinakalkaśca snehapāko bhavetkharaḥ tadūrdhvaṃ dagdhapākaḥ syāddāhakṛnniṣprayojanaḥ" },
      { type: "verse", number: "17", sanskrit: "आमपाकश्च निर्वीर्यो वह्निमान्द्यकरो गुरुः", text: "āmapākaśca nirvīryo vahnimāndyakaro guruḥ" },
      { type: "verse", number: "18", sanskrit: "नस्यार्थं स्यान्मृदुः पाको मध्यमः सर्वकर्मसु अभ्यङ्गार्थं खरः प्रोक्तो युञ्ज्यादेवं यथोचितम्", text: "nasyārthaṃ syānmṛduḥ pāko madhyamaḥ sarvakarmasu abhyaṅgārthaṃ kharaḥ prokto yuñjyādevaṃ yathocitam" },
      { type: "verse", number: "19", sanskrit: "घृततैलगुडादींश्च साधयेन्नैकवासरे प्रकुर्वन्त्युषिता ह्येते विशेषाद् गुणसञ्चयम्", text: "ghṛtatailaguḍādīṃśca sādhayennaikavāsare prakurvantyuṣitā hyete viśeṣād guṇasañcayam" },
      { type: "verse", number: "20", sanskrit: "ससैन्धवैश्च पलिकैर्घृतप्रस्थं विपाचयेत् क्षीरं चतुर्गुणं दत्त्वा तद् घृतं प्लीहनाशनम् विषमज्वरमन्दाग्निहरं रुचिकरं परम्", text: "sasaindhavaiśca palikairghṛtaprasthaṃ vipācayet kṣīraṃ caturguṇaṃ dattvā tad ghṛtaṃ plīhanāśanam viṣamajvaramandāgniharaṃ rucikaraṃ param" },
      { type: "verse", number: "21", sanskrit: "पिप्पली पिप्पलीमूलं चित्रको हस्तिपिप्पली श्वदंष्ट्रा नागरं धान्यं पाठा बिल्वं यवानिका", text: "pippalī pippalīmūlaṃ citrako hastipippalī śvadaṃṣṭrā nāgaraṃ dhānyaṃ pāṭhā bilvaṃ yavānikā" },
      { type: "verse", number: "22", sanskrit: "द्र व्यैश्च पलिकैरेतैश्चतुः षष्टिपलं घृतम् घृताच्चतुर्गुणं दद्याच्चाङ्गेरीस्वरसं बुधः", text: "dra vyaiśca palikairetaiścatuḥ ṣaṣṭipalaṃ ghṛtam ghṛtāccaturguṇaṃ dadyāccāṅgerīsvarasaṃ budhaḥ" },
      { type: "verse", number: "23", sanskrit: "तथा चतुर्गुणं दत्त्वा दधि सर्पिर्विपाचयेत् शनैः शनैर्विपक्तव्यं चाङ्गेरीघृतमुत्तमम्", text: "tathā caturguṇaṃ dattvā dadhi sarpirvipācayet śanaiḥ śanairvipaktavyaṃ cāṅgerīghṛtamuttamam" },
      { type: "verse", number: "24", sanskrit: "तद् घृतं कफवातघ्नं ग्रहण्यर्शोविकारनुत् हन्त्यानाहं गुदभ्रंशं मूत्रकृच्छ्रं प्रवाहिकाम्", text: "tad ghṛtaṃ kaphavātaghnaṃ grahaṇyarśovikāranut hantyānāhaṃ gudabhraṃśaṃ mūtrakṛcchraṃ pravāhikām" },
      { type: "verse", number: "25", sanskrit: "मसूराणां पलशतं नीरद्रो णे विपाचयेत् पादशेषं शृतं नीत्वा दत्त्वा बिल्वपलाष्टकम्", text: "masūrāṇāṃ palaśataṃ nīradro ṇe vipācayet pādaśeṣaṃ śṛtaṃ nītvā dattvā bilvapalāṣṭakam" },
      { type: "verse", number: "26", sanskrit: "घृतप्रस्थं पचेत्तेन सर्वातीसारनाशनम् ग्रहणीं भिन्नविट्कं च नाशयेच्च प्रवाहिकाम्", text: "ghṛtaprasthaṃ pacettena sarvātīsāranāśanam grahaṇīṃ bhinnaviṭkaṃ ca nāśayecca pravāhikām" },
      { type: "verse", number: "27", sanskrit: "अश्वगन्धा तुलैका स्यात्तदर्धो गोक्षुरः स्मृतः बलाऽमृता शालिपर्णी विदारी च शतावरी", text: "aśvagandhā tulaikā syāttadardho gokṣuraḥ smṛtaḥ balā'mṛtā śāliparṇī vidārī ca śatāvarī" },
      { type: "verse", number: "28", sanskrit: "अश्वत्थस्य च शुङ्गानि पद्मबीजं पुनर्नवा काश्मर्याश्च फलं चैव माषबीजं तथैव च", text: "aśvatthasya ca śuṅgāni padmabījaṃ punarnavā kāśmaryāśca phalaṃ caiva māṣabījaṃ tathaiva ca" },
      { type: "verse", number: "29", sanskrit: "पृथग्दशपलान् भागाँ श्चतुद्रो र्णे!ऽम्भसि पचेत् द्रो णशेषे रसे तस्मिन् पचेच्चैव घृताढकम्", text: "pṛthagdaśapalān bhāgā~ ścatudro rṇe!'mbhasi pacet dro ṇaśeṣe rase tasmin paceccaiva ghṛtāḍhakam" },
      { type: "verse", number: "30", sanskrit: "मृद्वीका पद्मकं कुष्ठं पिप्पली रक्तचन्दनम् पत्रकं नागपुष्पं च आत्मगुप्ताफलं तथा", text: "mṛdvīkā padmakaṃ kuṣṭhaṃ pippalī raktacandanam patrakaṃ nāgapuṣpaṃ ca ātmaguptāphalaṃ tathā" },
      { type: "verse", number: "31", sanskrit: "नीलोत्पलं सारिवे द्वे जीवनीयो गणस्तथा पृथक् कर्षसमा भागाः शर्करायाः पलद्वयम्", text: "nīlotpalaṃ sārive dve jīvanīyo gaṇastathā pṛthak karṣasamā bhāgāḥ śarkarāyāḥ paladvayam" },
      { type: "verse", number: "32", sanskrit: "रसश्च पौण्ड्रकेक्षूणामाढकैकं समाहरेत् चतुर्गुणेन पयसा घृताढकं विपाचयेत्", text: "rasaśca pauṇḍrakekṣūṇāmāḍhakaikaṃ samāharet caturguṇena payasā ghṛtāḍhakaṃ vipācayet" },
      { type: "verse", number: "33", sanskrit: "घृतमेतन्निहन्त्याशु रक्तपित्तमुरःक्षतम् हलीमकं पाण्डुरोगं वर्णभेदं स्वरक्षयम्", text: "ghṛtametannihantyāśu raktapittamuraḥkṣatam halīmakaṃ pāṇḍurogaṃ varṇabhedaṃ svarakṣayam" },
      { type: "verse", number: "34", sanskrit: "मूत्रकृच्छ्रमुरोदाहं पार्श्वशूलं च नाशयेत् एतत् सर्पिः प्रयोक्तव्यं बह्वन्तः पुरवासिनाम्", text: "mūtrakṛcchramurodāhaṃ pārśvaśūlaṃ ca nāśayet etat sarpiḥ prayoktavyaṃ bahvantaḥ puravāsinām" },
      { type: "verse", number: "35", sanskrit: "स्त्रीणां चैवाप्रजातानां दुर्बलानां च देहिनाम् श्रेष्ठं बलकरं वर्ण्यं हृद्यं पुष्टिरसायनम्", text: "strīṇāṃ caivāprajātānāṃ durbalānāṃ ca dehinām śreṣṭhaṃ balakaraṃ varṇyaṃ hṛdyaṃ puṣṭirasāyanam" },
      { type: "verse", number: "36", sanskrit: "ओजस्तेजस्करं हृद्यमायुष्यं प्राणवर्द्धनम् संवर्द्धयति शुक्रस्य पुरुषं दुर्बलेन्द्रि यम्", text: "ojastejaskaraṃ hṛdyamāyuṣyaṃ prāṇavarddhanam saṃvarddhayati śukrasya puruṣaṃ durbalendri yam" },
      { type: "verse", number: "37", sanskrit: "सर्वरोगविनिर्मुक्तः पयःसिक्तो यथा द्रुमः कामदेव इति ख्यातं सर्पिरुक्तं महागुणम्", text: "sarvarogavinirmuktaḥ payaḥsikto yathā drumaḥ kāmadeva iti khyātaṃ sarpiruktaṃ mahāguṇam" },
      { type: "verse", number: "38", sanskrit: "त्रिफला द्वे निशे कौन्ती सारिवे द्वे प्रियङ्गुका शालिपर्णी पृष्ठिपर्णी देवदार्व्येलवालुकम्", text: "triphalā dve niśe kauntī sārive dve priyaṅgukā śāliparṇī pṛṣṭhiparṇī devadārvyelavālukam" },
      { type: "verse", number: "39", sanskrit: "नतं विशाला दन्ती च दाडिमं नागकेशरम् नीलोत्पलैला मञ्जिष्ठा विडङ्गं कुष्ठपद्मकम्", text: "nataṃ viśālā dantī ca dāḍimaṃ nāgakeśaram nīlotpalailā mañjiṣṭhā viḍaṅgaṃ kuṣṭhapadmakam" },
      { type: "verse", number: "40", sanskrit: "जातिपुष्पं चन्दनं च तालीसं बृहती तथा एतैः कर्षसमैः कल्कैर्जलं दत्त्वा चतुर्गुणम्", text: "jātipuṣpaṃ candanaṃ ca tālīsaṃ bṛhatī tathā etaiḥ karṣasamaiḥ kalkairjalaṃ dattvā caturguṇam" },
      { type: "verse", number: "41", sanskrit: "घृतप्रस्थं पचेद्धीमानपस्मारे ज्वरे क्षये उन्मादे वातरक्ते च कासे मन्दानले तथा", text: "ghṛtaprasthaṃ paceddhīmānapasmāre jvare kṣaye unmāde vātarakte ca kāse mandānale tathā" },
      { type: "verse", number: "42", sanskrit: "प्रतिश्याये कटीशूले तृतीयक चतुर्थके मूत्रकृच्छ्रे विसर्पे च कण्डूपाण्ड्वामये तथा", text: "pratiśyāye kaṭīśūle tṛtīyaka caturthake mūtrakṛcchre visarpe ca kaṇḍūpāṇḍvāmaye tathā" },
      { type: "verse", number: "43", sanskrit: "विषद्वये प्रमेहेषु सर्वथैवोपयुज्यते वन्ध्यानां पुत्रदं भूतयक्षरक्षोहरं स्मृतम्", text: "viṣadvaye prameheṣu sarvathaivopayujyate vandhyānāṃ putradaṃ bhūtayakṣarakṣoharaṃ smṛtam" },
      { type: "verse", number: "44", sanskrit: "अमृताक्वाथकल्काभ्यां सक्षीरं विपचेद् घृतम् वातरक्तं जयत्याशु कुष्ठं जयति दुस्तरम्", text: "amṛtākvāthakalkābhyāṃ sakṣīraṃ vipaced ghṛtam vātaraktaṃ jayatyāśu kuṣṭhaṃ jayati dustaram" },
      { type: "verse", number: "45", sanskrit: "महातिक्तकघृतं वातरक्तकुष्ठादौ सप्तच्छदः प्रतिविषा शम्याकः कटुरोहिणी पाठा मुस्तमुशीरं च त्रिफला पर्पटस्तथा", text: "mahātiktakaghṛtaṃ vātaraktakuṣṭhādau saptacchadaḥ prativiṣā śamyākaḥ kaṭurohiṇī pāṭhā mustamuśīraṃ ca triphalā parpaṭastathā" },
      { type: "verse", number: "46", sanskrit: "पटोलनिम्बमञ्जिष्ठाः पिप्पली पद्मकं शटी चन्दनं धन्वयासश्च विशाले द्वे निशे तथा", text: "paṭolanimbamañjiṣṭhāḥ pippalī padmakaṃ śaṭī candanaṃ dhanvayāsaśca viśāle dve niśe tathā" },
      { type: "verse", number: "47", sanskrit: "गुडूची सारिवे द्वे च मूर्वा वासा शतावरी त्रायन्तीन्द्र यवा यष्टी भूनिम्बश्चाक्षभागिकाः", text: "guḍūcī sārive dve ca mūrvā vāsā śatāvarī trāyantīndra yavā yaṣṭī bhūnimbaścākṣabhāgikāḥ" },
      { type: "verse", number: "48", sanskrit: "घृतं चतुर्गुणं दद्यात् घृतादामलकीरसः द्विगुणः सर्पिषश्चात्र जलमष्टगुणं भवेत्", text: "ghṛtaṃ caturguṇaṃ dadyāt ghṛtādāmalakīrasaḥ dviguṇaḥ sarpiṣaścātra jalamaṣṭaguṇaṃ bhavet" },
      { type: "verse", number: "49", sanskrit: "तत्सिद्धं पाययेत्सर्पिर्वातरक्तेषु सर्वथा कुष्ठानि रक्तपित्तं च रक्तार्शांसि च पाण्डुताम्", text: "tatsiddhaṃ pāyayetsarpirvātarakteṣu sarvathā kuṣṭhāni raktapittaṃ ca raktārśāṃsi ca pāṇḍutām" },
      { type: "verse", number: "50", sanskrit: "हृद्रो गगुल्मवीसर्पप्रदरं गण्डमालिकाम् क्षुद्र रोगाञ्ज्वरांश्चैव महातिक्तमिदं जयेत्", text: "hṛdro gagulmavīsarpapradaraṃ gaṇḍamālikām kṣudra rogāñjvarāṃścaiva mahātiktamidaṃ jayet" },
      { type: "verse", number: "51", sanskrit: "कासीसाद्यघृतं कुष्ठे दद्रू पामाशिरः स्फोटादौ कासीसं द्वे निशे मुस्तं हरितालं मनः शिलाम् कम्पिल्लकं गन्धकं च विडङ्गं गुग्गुलुं तथा", text: "kāsīsādyaghṛtaṃ kuṣṭhe dadrū pāmāśiraḥ sphoṭādau kāsīsaṃ dve niśe mustaṃ haritālaṃ manaḥ śilām kampillakaṃ gandhakaṃ ca viḍaṅgaṃ gugguluṃ tathā" },
      { type: "verse", number: "52", sanskrit: "सिक्थकं मरिचं कुष्ठं तुत्थकं गौरसर्षपान् रसाञ्जनं च सिन्दूरं श्रीवासं रक्तचन्दनम्", text: "sikthakaṃ maricaṃ kuṣṭhaṃ tutthakaṃ gaurasarṣapān rasāñjanaṃ ca sindūraṃ śrīvāsaṃ raktacandanam" },
      { type: "verse", number: "53", sanskrit: "इरिमेदं निम्बपत्रं करञ्जं सारिवां वचाम् मञ्जिष्ठां मधुकं मांसीं शिरीषं लोध्रपद्मकम्", text: "irimedaṃ nimbapatraṃ karañjaṃ sārivāṃ vacām mañjiṣṭhāṃ madhukaṃ māṃsīṃ śirīṣaṃ lodhrapadmakam" },
      { type: "verse", number: "54", sanskrit: "हरीतकीं प्रपुन्नाटं चूर्णयेत्कार्षिकान्पृथक् ततस्तच्चूर्णमालोड्य त्रिंशत्पलमिते घृते", text: "harītakīṃ prapunnāṭaṃ cūrṇayetkārṣikānpṛthak tatastaccūrṇamāloḍya triṃśatpalamite ghṛte" },
      { type: "verse", number: "55", sanskrit: "स्थापयेत्ताम्रपात्रे च घर्मे सप्तदिनानि वै अस्याभ्यङ्गेन कुष्ठानि दद्रुपामाविचर्चिकाः", text: "sthāpayettāmrapātre ca gharme saptadināni vai asyābhyaṅgena kuṣṭhāni dadrupāmāvicarcikāḥ" },
      { type: "verse", number: "56", sanskrit: "शूकदोषा विसर्पाश्च विस्फोटा वातरक्तजाः शिरः स्फोटोपदंशाश्च नाडीदुष्टव्रणानि च", text: "śūkadoṣā visarpāśca visphoṭā vātaraktajāḥ śiraḥ sphoṭopadaṃśāśca nāḍīduṣṭavraṇāni ca" },
      { type: "verse", number: "57", sanskrit: "शोथो भगन्दरश्चैव लूताः शाम्यन्ति देहिनाम् शोधनं रोपणं चैव सवर्णकरणं घृतम्", text: "śotho bhagandaraścaiva lūtāḥ śāmyanti dehinām śodhanaṃ ropaṇaṃ caiva savarṇakaraṇaṃ ghṛtam" },
      { type: "verse", number: "58", sanskrit: "जातीनिम्बपटोलाश्च द्वे निशे कटुरोहिणी मञ्जिष्ठा मधुकं सिक्थं करञ्जोशीरसारिवाः", text: "jātīnimbapaṭolāśca dve niśe kaṭurohiṇī mañjiṣṭhā madhukaṃ sikthaṃ karañjośīrasārivāḥ" },
      { type: "verse", number: "59", sanskrit: "तुत्थं च विपचेत्सम्यक्कल्कैरेभिर्घृतं बुधः अस्य लेपात्प्ररोहन्ति सूक्ष्मनाडीव्रणा अपि", text: "tutthaṃ ca vipacetsamyakkalkairebhirghṛtaṃ budhaḥ asya lepātprarohanti sūkṣmanāḍīvraṇā api" },
      { type: "verse", number: "60", sanskrit: "मर्माश्रिताः क्लेदिनश्च गम्भीराः सरुजो व्रणाः", text: "marmāśritāḥ kledinaśca gambhīrāḥ sarujo vraṇāḥ" },
      { type: "verse", number: "61", sanskrit: "चित्रकः शङ्खिनी पथ्या कंपिल्लास्त्रिवृतायुगम् वृद्धदारुश्च शम्याको दन्ती दंतीफलं तथा", text: "citrakaḥ śaṅkhinī pathyā kaṃpillāstrivṛtāyugam vṛddhadāruśca śamyāko dantī daṃtīphalaṃ tathā" },
      { type: "verse", number: "62", sanskrit: "कोशातकी देवदाली नीलिनी गिरिकर्णिका सातला पिप्पलीमूलं विडङ्गं कुटकी तथा", text: "kośātakī devadālī nīlinī girikarṇikā sātalā pippalīmūlaṃ viḍaṅgaṃ kuṭakī tathā" },
      { type: "verse", number: "63", sanskrit: "हेमक्षीरी च विपचेत्कल्कैरेभिः पिचून्मितैः घृतप्रस्थं स्नुहीक्षीरे षट्पले तु पलद्वये", text: "hemakṣīrī ca vipacetkalkairebhiḥ picūnmitaiḥ ghṛtaprasthaṃ snuhīkṣīre ṣaṭpale tu paladvaye" },
      { type: "verse", number: "64", sanskrit: "अर्कक्षीरस्य मतिमांस्तत्सिद्धं गुल्मकुष्ठहृत् हन्ति शूलमुदावर्त्तं शोथाध्मानं भगन्दरम्", text: "arkakṣīrasya matimāṃstatsiddhaṃ gulmakuṣṭhahṛt hanti śūlamudāvarttaṃ śothādhmānaṃ bhagandaram" },
      { type: "verse", number: "65", sanskrit: "शमयत्युदराण्यष्टौ निपातं बिन्दुसङ्ख्यया गोदुग्धेनोष्ट्रदुग्धेन कौलत्थेन शृतेन वा", text: "śamayatyudarāṇyaṣṭau nipātaṃ bindusaṅkhyayā godugdhenoṣṭradugdhena kaulatthena śṛtena vā" },
      { type: "verse", number: "66", sanskrit: "उष्णोदकेन वा पीत्वा बिन्दुवेगैर्विरेचयेत् एतद्विन्दुघृतं नाम नाभिलेपाद्वि रेचयेत्", text: "uṣṇodakena vā pītvā binduvegairvirecayet etadvindughṛtaṃ nāma nābhilepādvi recayet" },
      { type: "verse", number: "67", sanskrit: "त्रिफलाद्यं घृतं नेत्ररोगे तिमिरादौ त्रिफलाया रसप्रस्थं प्रस्थं वासारसोद्भवम् भृङ्गराजरसप्रस्थं प्रस्थमाजं पयः स्मृतम् दत्त्वा तत्र घृतप्रस्थं कल्कैः कर्षमितैः पृथक्", text: "triphalādyaṃ ghṛtaṃ netraroge timirādau triphalāyā rasaprasthaṃ prasthaṃ vāsārasodbhavam bhṛṅgarājarasaprasthaṃ prasthamājaṃ payaḥ smṛtam dattvā tatra ghṛtaprasthaṃ kalkaiḥ karṣamitaiḥ pṛthak" },
      { type: "verse", number: "68", sanskrit: "त्रिफला पिप्पली द्रा क्षा चन्दनं सैन्धवं बला काकोली क्षीरकाकोली मेदा मरिचनागरम्", text: "triphalā pippalī drā kṣā candanaṃ saindhavaṃ balā kākolī kṣīrakākolī medā maricanāgaram" },
      { type: "verse", number: "69", sanskrit: "शर्करा पुण्डरीकं च कमलं च पुनर्नवा निशायुग्मं च मधुकं सर्वै रेभिर्विपाचयेत्", text: "śarkarā puṇḍarīkaṃ ca kamalaṃ ca punarnavā niśāyugmaṃ ca madhukaṃ sarvai rebhirvipācayet" },
      { type: "verse", number: "70", sanskrit: "नक्तान्ध्यं नकुलान्ध्यं च कण्डूं पिल्लं तथैव च नेत्रस्रावं च पटलं तिमिरं काचकं जयेत्", text: "naktāndhyaṃ nakulāndhyaṃ ca kaṇḍūṃ pillaṃ tathaiva ca netrasrāvaṃ ca paṭalaṃ timiraṃ kācakaṃ jayet" },
      { type: "verse", number: "71", sanskrit: "अन्येऽपि प्रशमं यान्ति नेत्ररोगाः सुदारुणाः त्रैफलं घृतमेतद्धि पाने नस्यादिषूचितम्", text: "anye'pi praśamaṃ yānti netrarogāḥ sudāruṇāḥ traiphalaṃ ghṛtametaddhi pāne nasyādiṣūcitam" },
      { type: "verse", number: "72", sanskrit: "द्वे हरिद्रे  स्थिरा मूर्वा सारिवा चन्दनद्वयम् मधुपर्णी च मधुकपद्मकेशरपद्मकैः", text: "dve haridre  sthirā mūrvā sārivā candanadvayam madhuparṇī ca madhukapadmakeśarapadmakaiḥ" },
      { type: "verse", number: "73", sanskrit: "कल्कैः कर्षमितैरेतैर्घृतप्रस्थं विपाचयेत्", text: "kalkaiḥ karṣamitairetairghṛtaprasthaṃ vipācayet" },
      { type: "verse", number: "74", sanskrit: "गौराद्यमिति विख्यातं सर्पिर्विषहरं परम्", text: "gaurādyamiti vikhyātaṃ sarpirviṣaharaṃ param" },
      { type: "verse", number: "75", sanskrit: "पृथग्द्विपलिकैरेभिद्रो र्ण!नीरेण पाचयेत्", text: "pṛthagdvipalikairebhidro rṇa!nīreṇa pācayet" },
      { type: "verse", number: "76", sanskrit: "मयूरं पक्षपित्तान्त्रयकृत्पादास्यवर्जितम् पादशेषं शृतं नीत्वा क्षीरं दत्त्वा च तत्समम्", text: "mayūraṃ pakṣapittāntrayakṛtpādāsyavarjitam pādaśeṣaṃ śṛtaṃ nītvā kṣīraṃ dattvā ca tatsamam" },
      { type: "verse", number: "77", sanskrit: "घृतप्रस्थं पचेत्सम्यग्जीवनीयैः पिचून्मितैः तत्सिद्धं शिरसः पीडां मन्यापृष्ठग्रहं तथा", text: "ghṛtaprasthaṃ pacetsamyagjīvanīyaiḥ picūnmitaiḥ tatsiddhaṃ śirasaḥ pīḍāṃ manyāpṛṣṭhagrahaṃ tathā" },
      { type: "verse", number: "78", sanskrit: "अर्दितं कर्णनासाऽक्षिजिह्वागलरुजो जयेत् पाने नस्ये तथाऽभ्यङ्गे कर्णपूरेषु युज्यते", text: "arditaṃ karṇanāsā'kṣijihvāgalarujo jayet pāne nasye tathā'bhyaṅge karṇapūreṣu yujyate" },
      { type: "verse", number: "79", sanskrit: "हेमन्तकालशिशिरवसन्तेषु च शस्यते", text: "hemantakālaśiśiravasanteṣu ca śasyate" },
      { type: "verse", number: "80", sanskrit: "त्रिफला मधुकं कुष्ठं द्वे निशे कटुरोहिणी विडङ्गं पिप्पली मुस्ता विशाला कट्फलं वचा", text: "triphalā madhukaṃ kuṣṭhaṃ dve niśe kaṭurohiṇī viḍaṅgaṃ pippalī mustā viśālā kaṭphalaṃ vacā" },
      { type: "verse", number: "81", sanskrit: "द्वे मेदे द्वे च काकोल्यौ सारिवे द्वे प्रियङ्गुका शतपुष्पा हिङ्गु रास्ना चन्दनं रक्तचन्दनम्", text: "dve mede dve ca kākolyau sārive dve priyaṅgukā śatapuṣpā hiṅgu rāsnā candanaṃ raktacandanam" },
      { type: "verse", number: "82", sanskrit: "जाती पुष्पं तुगाक्षीरी कमलं शर्करा तथा अजमोदा च दन्ती च कल्कैरेतैश्च कार्षिकैः", text: "jātī puṣpaṃ tugākṣīrī kamalaṃ śarkarā tathā ajamodā ca dantī ca kalkairetaiśca kārṣikaiḥ" },
      { type: "verse", number: "83", sanskrit: "जीवद्वत्सैकवर्णाया घृतप्रस्थं च गोः क्षिपेत् चतुर्गुणेन पयसा पचेदारण्यगोमयैः", text: "jīvadvatsaikavarṇāyā ghṛtaprasthaṃ ca goḥ kṣipet caturguṇena payasā pacedāraṇyagomayaiḥ" },
      { type: "verse", number: "84", sanskrit: "सुतिथौ पुष्यनक्षत्रे मृद्भाण्डे ताम्रजे तथा ततः पिबेच्छुभदिने नारी वा पुरुषोऽथवा", text: "sutithau puṣyanakṣatre mṛdbhāṇḍe tāmraje tathā tataḥ pibecchubhadine nārī vā puruṣo'thavā" },
      { type: "verse", number: "85", sanskrit: "एतत्सर्पिर्नरः पीत्वा स्त्रीषु नित्यं वृषायते पुत्रानुत्पादयेद्धीमान्वन्ध्याऽपि लभते सुतम्", text: "etatsarpirnaraḥ pītvā strīṣu nityaṃ vṛṣāyate putrānutpādayeddhīmānvandhyā'pi labhate sutam" },
      { type: "verse", number: "86", sanskrit: "अनायुषं या जनयेद्या च सूता पुनः स्थिता पुत्रं प्राप्नोति सा नारी बुद्धिमन्तं शतायुषम्", text: "anāyuṣaṃ yā janayedyā ca sūtā punaḥ sthitā putraṃ prāpnoti sā nārī buddhimantaṃ śatāyuṣam" },
      { type: "verse", number: "87", sanskrit: "एतत्फलघृतं नाम भरद्वाजेन भाषितम् अनुक्तं लक्ष्मणामूलं क्षिपेत्तत्र चिकित्सकः", text: "etatphalaghṛtaṃ nāma bharadvājena bhāṣitam anuktaṃ lakṣmaṇāmūlaṃ kṣipettatra cikitsakaḥ" },
      { type: "verse", number: "88", sanskrit: "त्रिफलां द्वे सहचरे गुडूचीं सपुनर्नवाम् शुकनासां हरिद्रे  द्वे रास्नां मेदां शतावरीम्", text: "triphalāṃ dve sahacare guḍūcīṃ sapunarnavām śukanāsāṃ haridre  dve rāsnāṃ medāṃ śatāvarīm" },
      { type: "verse", number: "89", sanskrit: "कल्कीकृत्य घृतप्रस्थं पचेत्क्षीरे चतुर्गुणे तत्सिद्धंपाययेन्नारीं योनिशूलनिपीडिताम्", text: "kalkīkṛtya ghṛtaprasthaṃ pacetkṣīre caturguṇe tatsiddhaṃpāyayennārīṃ yoniśūlanipīḍitām" },
      { type: "verse", number: "90", sanskrit: "पीडिता चलिता या च निःसृता विवृता च या पित्तयोनिश्च विभ्रान्ता षण्ढयोनिश्च या स्मृता", text: "pīḍitā calitā yā ca niḥsṛtā vivṛtā ca yā pittayoniśca vibhrāntā ṣaṇḍhayoniśca yā smṛtā" },
      { type: "verse", number: "91", sanskrit: "प्रपद्यन्ते हिताः स्थानं गर्भं गृह्णन्ति चासकृत् एतत्फलघृतं नाम योनिदोषहरं परम्", text: "prapadyante hitāḥ sthānaṃ garbhaṃ gṛhṇanti cāsakṛt etatphalaghṛtaṃ nāma yonidoṣaharaṃ param" },
      { type: "verse", number: "92", sanskrit: "पञ्चतित्तकं घृतं विषमज्वरादौ वृषनिम्बामृताव्याघ्रीपटोलानां शृतेन च कल्केन पक्वं सर्पिस्तु निहन्याद्विषमज्वरान् पाण्डुं कुष्ठं विसर्पं च कृमीनर्शांसि नाशयेत्", text: "pañcatittakaṃ ghṛtaṃ viṣamajvarādau vṛṣanimbāmṛtāvyāghrīpaṭolānāṃ śṛtena ca kalkena pakvaṃ sarpistu nihanyādviṣamajvarān pāṇḍuṃ kuṣṭhaṃ visarpaṃ ca kṛmīnarśāṃsi nāśayet" },
      { type: "verse", number: "93", sanskrit: "लाक्षाढकं क्वाथयित्वा जलस्य चतुराढकैः चतुर्थांशं शृतं नीत्वा तैलप्रस्थे विनिक्षिपेत्", text: "lākṣāḍhakaṃ kvāthayitvā jalasya caturāḍhakaiḥ caturthāṃśaṃ śṛtaṃ nītvā tailaprasthe vinikṣipet" },
      { type: "verse", number: "94", sanskrit: "मस्त्वाढकं च गोदध्नस्तत्रैव विनियोजयेत् शतपुष्पामश्वगन्धां हरिद्रा ं! देवदारु च", text: "mastvāḍhakaṃ ca godadhnastatraiva viniyojayet śatapuṣpāmaśvagandhāṃ haridrā ṃ! devadāru ca" },
      { type: "verse", number: "95", sanskrit: "कुटकीं रेणुकां मूर्वां कुष्ठं च मधुयष्टिकाम् चन्दनं मुस्तकं रास्नां पृथक्कर्षप्रमाणतः", text: "kuṭakīṃ reṇukāṃ mūrvāṃ kuṣṭhaṃ ca madhuyaṣṭikām candanaṃ mustakaṃ rāsnāṃ pṛthakkarṣapramāṇataḥ" },
      { type: "verse", number: "96", sanskrit: "चूर्णयेत्तत्र निक्षिप्य साधयेन्मृदुवह्निना अस्याभ्यङ्गात्प्रशाम्यन्ति सर्वेऽपि विषमज्वराः", text: "cūrṇayettatra nikṣipya sādhayenmṛduvahninā asyābhyaṅgātpraśāmyanti sarve'pi viṣamajvarāḥ" },
      { type: "verse", number: "97", sanskrit: "वातं पित्तमपस्मारमुन्मादं यक्षराक्षसान्", text: "vātaṃ pittamapasmāramunmādaṃ yakṣarākṣasān" },
      { type: "verse", number: "98", sanskrit: "कण्डूशूलं च दौर्गन्ध्यं गात्राणां स्फुरणं जयेत् पुष्टगर्भा भवेदस्य गर्भिण्यभ्यङ्गतो भृशम्", text: "kaṇḍūśūlaṃ ca daurgandhyaṃ gātrāṇāṃ sphuraṇaṃ jayet puṣṭagarbhā bhavedasya garbhiṇyabhyaṅgato bhṛśam" },
      { type: "verse", number: "99", sanskrit: "मूर्वा लाक्षा हरिद्रे  द्वे मञ्जिष्ठा सेन्द्र वारुणी बृहती सैन्धवं कुष्ठं रास्ना मांसी शतावरी", text: "mūrvā lākṣā haridre  dve mañjiṣṭhā sendra vāruṇī bṛhatī saindhavaṃ kuṣṭhaṃ rāsnā māṃsī śatāvarī" },
      { type: "verse", number: "100", sanskrit: "आरनालाढके तत्र तैलप्रस्थं विपाचयेत् तैलमङ्गारकं नाम सर्वज्वरविमोक्षणम्", text: "āranālāḍhake tatra tailaprasthaṃ vipācayet tailamaṅgārakaṃ nāma sarvajvaravimokṣaṇam" },
      { type: "verse", number: "101", sanskrit: "अश्वगन्धां बलां बिल्वं पाटलां बृहतीद्वयम् श्वदंष्ट्राऽतिबलानिम्बं स्योनाकं च पुनर्नवाम्", text: "aśvagandhāṃ balāṃ bilvaṃ pāṭalāṃ bṛhatīdvayam śvadaṃṣṭrā'tibalānimbaṃ syonākaṃ ca punarnavām" },
      { type: "verse", number: "102", sanskrit: "प्रसारिणीमग्निमन्थं कुर्याद्दशपलं पृथक् चतुद्रो र्णे! जले पक्त्वा पादशेषं शृतं नयेत्", text: "prasāriṇīmagnimanthaṃ kuryāddaśapalaṃ pṛthak catudro rṇe! jale paktvā pādaśeṣaṃ śṛtaṃ nayet" },
      { type: "verse", number: "103", sanskrit: "तैलाढकेन संयोज्य शतावर्या रसाढकम् क्षिपेत्तत्र च गोक्षीरं तैलात्तस्माच्चतुर्गुणम्", text: "tailāḍhakena saṃyojya śatāvaryā rasāḍhakam kṣipettatra ca gokṣīraṃ tailāttasmāccaturguṇam" },
      { type: "verse", number: "104", sanskrit: "शनैर्विपाचयेदेभिः कल्कैर्द्विपलिकैः पृथक् कुष्ठैलाचन्दनं मूर्वा वचा मांसी ससैन्धवैः", text: "śanairvipācayedebhiḥ kalkairdvipalikaiḥ pṛthak kuṣṭhailācandanaṃ mūrvā vacā māṃsī sasaindhavaiḥ" },
      { type: "verse", number: "105", sanskrit: "अश्वगन्धावचारास्नाशतपुष्पेन्द्र दारुभिः पर्णीचतुष्टयेनैव तगरेण च साधयेद्", text: "aśvagandhāvacārāsnāśatapuṣpendra dārubhiḥ parṇīcatuṣṭayenaiva tagareṇa ca sādhayed" },
      { type: "verse", number: "106", sanskrit: "तत्तैलं नावनेऽभ्यङ्गे पाने बस्तौ न योजयेत् पक्षाघातं हनुस्तम्भं मन्यास्तम्भं गलग्रहम्", text: "tattailaṃ nāvane'bhyaṅge pāne bastau na yojayet pakṣāghātaṃ hanustambhaṃ manyāstambhaṃ galagraham" },
      { type: "verse", number: "107", sanskrit: "खल्लत्वं बधिरत्वं च गतिभङ्गं कटिग्रहम् गात्रशोषेन्द्रि यध्वंसावसृक्शुक्रज्वरक्षयान्", text: "khallatvaṃ badhiratvaṃ ca gatibhaṅgaṃ kaṭigraham gātraśoṣendri yadhvaṃsāvasṛkśukrajvarakṣayān" },
      { type: "verse", number: "108", sanskrit: "अन्त्रवृद्धिं कुरण्डं च दन्तरोगं शिरोग्रहम् पार्श्वशूलं च पाङ्गुल्यं बुद्धिहानिं च गृध्रसीम्", text: "antravṛddhiṃ kuraṇḍaṃ ca dantarogaṃ śirograham pārśvaśūlaṃ ca pāṅgulyaṃ buddhihāniṃ ca gṛdhrasīm" },
      { type: "verse", number: "109", sanskrit: "अन्यांश्च विषमान्वाताञ्जयेत्सर्वाङ्गसंश्रयान् अस्य प्रभावाद्वन्ध्याऽपि नारी पुत्रं प्रसूयते", text: "anyāṃśca viṣamānvātāñjayetsarvāṅgasaṃśrayān asya prabhāvādvandhyā'pi nārī putraṃ prasūyate" },
      { type: "verse", number: "110", sanskrit: "मर्त्यो गजो वा तुरगस्तैलादस्मात्सुखी भवेत् यथा नारायणो देवो दुष्टदैत्यविनाशनः", text: "martyo gajo vā turagastailādasmātsukhī bhavet yathā nārāyaṇo devo duṣṭadaityavināśanaḥ" },
      { type: "verse", number: "111", sanskrit: "तथैव वातरोगाणां नाशनं तैलमुत्तमम्", text: "tathaiva vātarogāṇāṃ nāśanaṃ tailamuttamam" },
      { type: "verse", number: "112", sanskrit: "वारुण्या औत्तरं मूलं कुट्टितं तु पलत्रयम् पलद्वादशकं तैलं क्षणं वह्नौ विपाचितम्", text: "vāruṇyā auttaraṃ mūlaṃ kuṭṭitaṃ tu palatrayam paladvādaśakaṃ tailaṃ kṣaṇaṃ vahnau vipācitam" },
      { type: "verse", number: "113", sanskrit: "निष्कत्रयं भक्तयुक्तं सेवेतास्माद्विनश्यति हस्तकम्पः शिरःकम्पः कम्पो मन्याशिराभवः", text: "niṣkatrayaṃ bhaktayuktaṃ sevetāsmādvinaśyati hastakampaḥ śiraḥkampaḥ kampo manyāśirābhavaḥ" },
      { type: "verse", number: "114", sanskrit: "कुलत्थयवकोलानां क्वाथेन पयसा तथा", text: "kulatthayavakolānāṃ kvāthena payasā tathā" },
      { type: "verse", number: "115", sanskrit: "अष्टाष्टभागयुक्तेन भागमेकं च तैलकम् गणेन जीवनीयेन शतावर्येन्द्र दारुणा", text: "aṣṭāṣṭabhāgayuktena bhāgamekaṃ ca tailakam gaṇena jīvanīyena śatāvaryendra dāruṇā" },
      { type: "verse", number: "116", sanskrit: "वचापुनर्नवामांसीसारिवाद्वयपत्रकैः", text: "vacāpunarnavāmāṃsīsārivādvayapatrakaiḥ" },
      { type: "verse", number: "117", sanskrit: "शतपुष्पाऽश्वगंधाभ्यामेलया च विपाचयेत् गर्भार्थिनीनां नारीणां नराणांक्षीणरेतसाम्", text: "śatapuṣpā'śvagaṃdhābhyāmelayā ca vipācayet garbhārthinīnāṃ nārīṇāṃ narāṇāṃkṣīṇaretasām" },
      { type: "verse", number: "118", sanskrit: "व्यायामक्षीणगात्राणां सूतिकानां च युज्यते राजयोग्यमिदं तैलं सुखिनां च विशेषतः बलातैलमिति ख्यातं सर्ववातामयापहम्", text: "vyāyāmakṣīṇagātrāṇāṃ sūtikānāṃ ca yujyate rājayogyamidaṃ tailaṃ sukhināṃ ca viśeṣataḥ balātailamiti khyātaṃ sarvavātāmayāpaham" },
      { type: "verse", number: "119", sanskrit: "प्रसारिणीपलशतं जलद्रो णे विपाचयेत् पादशिष्टः शृतो ग्राह्यस्तैलं दधि च तत्समम्", text: "prasāriṇīpalaśataṃ jaladro ṇe vipācayet pādaśiṣṭaḥ śṛto grāhyastailaṃ dadhi ca tatsamam" },
      { type: "verse", number: "120", sanskrit: "काञ्जिकं च समं तैलात्क्षीरं तैलाच्चतुर्गुणम् तैलात्तथाऽष्टमांशेन सर्वकल्कानि योजयेत्", text: "kāñjikaṃ ca samaṃ tailātkṣīraṃ tailāccaturguṇam tailāttathā'ṣṭamāṃśena sarvakalkāni yojayet" },
      { type: "verse", number: "121", sanskrit: "मधुकं पिप्पलीमूलं चित्रकः सैन्धवं वचा प्रसारिणी देवदारु रास्ना च गजपिप्पली", text: "madhukaṃ pippalīmūlaṃ citrakaḥ saindhavaṃ vacā prasāriṇī devadāru rāsnā ca gajapippalī" },
      { type: "verse", number: "122", sanskrit: "भल्लातः शतपुष्पा च मांसी चैभिर्विपाचयेत् एतत्तैलं वरं पक्वं वातश्लेष्मामयाञ्जयेत्", text: "bhallātaḥ śatapuṣpā ca māṃsī caibhirvipācayet etattailaṃ varaṃ pakvaṃ vātaśleṣmāmayāñjayet" },
      { type: "verse", number: "123", sanskrit: "कौब्जं पङ्गुत्वखञ्जत्वे गृध्रसीमर्दितं तथा हनुपृष्ठशिरोग्रीवाकटिस्तम्भान्विनाशयेत्", text: "kaubjaṃ paṅgutvakhañjatve gṛdhrasīmarditaṃ tathā hanupṛṣṭhaśirogrīvākaṭistambhānvināśayet" },
      { type: "verse", number: "124", sanskrit: "अन्यांश्च विषमान्वातान्सर्वानाशु व्यपोहति", text: "anyāṃśca viṣamānvātānsarvānāśu vyapohati" },
      { type: "verse", number: "125", sanskrit: "माषा यवातसी क्षुद्रा  मर्कटी च कुरण्टकः गोकण्टष्टुण्टुकश्चैषां कुर्यात्सप्तपलं पृथक्", text: "māṣā yavātasī kṣudrā  markaṭī ca kuraṇṭakaḥ gokaṇṭaṣṭuṇṭukaścaiṣāṃ kuryātsaptapalaṃ pṛthak" },
      { type: "verse", number: "126", sanskrit: "चतुर्गुणाम्बुना पक्त्वा पादशेषं शृतं नयेत् कर्पासास्थीनि बदरं शणबीजं कुलत्थकम्", text: "caturguṇāmbunā paktvā pādaśeṣaṃ śṛtaṃ nayet karpāsāsthīni badaraṃ śaṇabījaṃ kulatthakam" },
      { type: "verse", number: "127", sanskrit: "पृथक्चतुर्दशपलं चतुर्गुणजले पचेत् चतुर्थांशावशिष्टं च गृह्णीयात्क्वाथमुत्तमम्", text: "pṛthakcaturdaśapalaṃ caturguṇajale pacet caturthāṃśāvaśiṣṭaṃ ca gṛhṇīyātkvāthamuttamam" },
      { type: "verse", number: "128", sanskrit: "प्रस्थैकं छागमांसस्य चतुःषष्टिपले जले निक्षिप्य पाचयेद्धीमान्पादशेषं शृतं नयेत्", text: "prasthaikaṃ chāgamāṃsasya catuḥṣaṣṭipale jale nikṣipya pācayeddhīmānpādaśeṣaṃ śṛtaṃ nayet" },
      { type: "verse", number: "129", sanskrit: "तैलप्रस्थे ततः सर्वान्क्वाथानेतान्विनिक्षिपेत् कल्कैरेभिश्च विपचेदमृताकुष्ठनागरैः", text: "tailaprasthe tataḥ sarvānkvāthānetānvinikṣipet kalkairebhiśca vipacedamṛtākuṣṭhanāgaraiḥ" },
      { type: "verse", number: "130", sanskrit: "रास्नापुनर्नवैरण्डैः पिप्पल्या शतपुष्पया बलाप्रसारिणीभ्यां च मांस्या कटुकया तथा", text: "rāsnāpunarnavairaṇḍaiḥ pippalyā śatapuṣpayā balāprasāriṇībhyāṃ ca māṃsyā kaṭukayā tathā" },
      { type: "verse", number: "131", sanskrit: "पृथगर्द्धपलैरेतैः साधयेन्मृदुवह्निना हन्यात्तैलमिदं शीघ्रं ग्रीवास्तम्भापबाहुकौ", text: "pṛthagarddhapalairetaiḥ sādhayenmṛduvahninā hanyāttailamidaṃ śīghraṃ grīvāstambhāpabāhukau" },
      { type: "verse", number: "132", sanskrit: "शाखाकम्पं शिरः कम्पं विश्वाचीमर्दितं तथा माषादिकमिदं तैलं सर्ववातविकारनुत्", text: "śākhākampaṃ śiraḥ kampaṃ viśvācīmarditaṃ tathā māṣādikamidaṃ tailaṃ sarvavātavikāranut" },
      { type: "verse", number: "133", sanskrit: "शतावरी बलायुग्मं पर्ण्यौ गन्धर्वहस्तकः अश्वगन्धा श्वदंष्ट्रश्च बिल्वः काशः कुरण्टकः", text: "śatāvarī balāyugmaṃ parṇyau gandharvahastakaḥ aśvagandhā śvadaṃṣṭraśca bilvaḥ kāśaḥ kuraṇṭakaḥ" },
      { type: "verse", number: "134", sanskrit: "एषां सार्द्धपलान्भागान्कल्पयेच्च विपाचयेत् चतुर्गुणेन नीरेण पादशेषं शृतं नयेत्", text: "eṣāṃ sārddhapalānbhāgānkalpayecca vipācayet caturguṇena nīreṇa pādaśeṣaṃ śṛtaṃ nayet" },
      { type: "verse", number: "135", sanskrit: "नियोज्य तैलप्रस्थे च क्षीरप्रस्थं विनिक्षिपेत् शतावरीरसप्रस्थं जलप्रस्थं च योजयेत्", text: "niyojya tailaprasthe ca kṣīraprasthaṃ vinikṣipet śatāvarīrasaprasthaṃ jalaprasthaṃ ca yojayet" },
      { type: "verse", number: "136", sanskrit: "शतपुष्पा बला कुष्ठमेला शैलेयमुत्पलम्", text: "śatapuṣpā balā kuṣṭhamelā śaileyamutpalam" },
      { type: "verse", number: "137", sanskrit: "ऋद्धिर्मेदा च मधुकं काकोली जीवकस्तथा एषां कर्षसमैः कल्कैस्तैलं गोमयवह्निना", text: "ṛddhirmedā ca madhukaṃ kākolī jīvakastathā eṣāṃ karṣasamaiḥ kalkaistailaṃ gomayavahninā" },
      { type: "verse", number: "138", sanskrit: "पचेत्तेनैव तैलेन स्त्रीषु नित्यं वृषायते नारी च लभते पुत्रं योनिशूलं च नश्यति", text: "pacettenaiva tailena strīṣu nityaṃ vṛṣāyate nārī ca labhate putraṃ yoniśūlaṃ ca naśyati" },
      { type: "verse", number: "139", sanskrit: "अङ्गशूलं शिरः शूलं कामलां पाण्डुतां गरम् गृध्रसीप्लीहशोषांश्च मेहान्दण्डापतानकम्", text: "aṅgaśūlaṃ śiraḥ śūlaṃ kāmalāṃ pāṇḍutāṃ garam gṛdhrasīplīhaśoṣāṃśca mehāndaṇḍāpatānakam" },
      { type: "verse", number: "140", sanskrit: "सदाहं वातरक्तं च वातपित्तगदार्दितम् असृग्दरं तथाध्मानं रक्तपित्तं च नश्यति", text: "sadāhaṃ vātaraktaṃ ca vātapittagadārditam asṛgdaraṃ tathādhmānaṃ raktapittaṃ ca naśyati" },
      { type: "verse", number: "141", sanskrit: "शतावरीतैलमिदं कृष्णात्रेयेण भाषितम् ॐ नारायण्यै स्वाहा उत्तराभिमुखो भूत्वा खनेत्खदिरशङ्कुना", text: "śatāvarītailamidaṃ kṛṣṇātreyeṇa bhāṣitam oṃ nārāyaṇyai svāhā uttarābhimukho bhūtvā khanetkhadiraśaṅkunā" },
      { type: "verse", number: "142", sanskrit: "ॐ सर्वव्याधिनाशिन्यै स्वाहा  इत्युत्पाटनमन्त्रः ॐ कुमारजीविन्यै स्वाहा  इति पानमन्त्रः", text: "oṃ sarvavyādhināśinyai svāhā  ityutpāṭanamantraḥ oṃ kumārajīvinyai svāhā  iti pānamantraḥ" },
      { type: "verse", number: "143", sanskrit: "कासीसं लाङ्गली कुष्ठं शुण्ठी कृष्णा च सैन्धवम् मनः शिलाश्वमारश्च विडङ्गं चित्रको वृषः", text: "kāsīsaṃ lāṅgalī kuṣṭhaṃ śuṇṭhī kṛṣṇā ca saindhavam manaḥ śilāśvamāraśca viḍaṅgaṃ citrako vṛṣaḥ" },
      { type: "verse", number: "144", sanskrit: "दन्ती कोशातकीबीजं हेमाह्वा हरितालकम् कल्कैः कर्षमितैरेतैस्तैलप्रस्थं विपाचयेत्", text: "dantī kośātakībījaṃ hemāhvā haritālakam kalkaiḥ karṣamitairetaistailaprasthaṃ vipācayet" },
      { type: "verse", number: "145", sanskrit: "स्नुह्यर्कपयसी दद्यात्पृथग्द्विपलसंमिते चतुर्गुणं गवां मूत्रं दत्त्वा सम्यक्प्रसाधयेत्", text: "snuhyarkapayasī dadyātpṛthagdvipalasaṃmite caturguṇaṃ gavāṃ mūtraṃ dattvā samyakprasādhayet" },
      { type: "verse", number: "146", sanskrit: "कथितं खरनादेन तैलमर्शोविनाशनम् क्षारवत्पातयत्येतदर्शांस्यभ्यङ्गतो भृशम् वलीर्न दूषयत्येतत्क्षारकर्मकरं स्मृतम्", text: "kathitaṃ kharanādena tailamarśovināśanam kṣāravatpātayatyetadarśāṃsyabhyaṅgato bhṛśam valīrna dūṣayatyetatkṣārakarmakaraṃ smṛtam" },
      { type: "verse", number: "147", sanskrit: "मञ्जिष्ठासारिवासर्जयष्टीसिक्थैः पलोन्मितैः पिण्डाख्यं साधयेत्तैलमभ्यङ्गात् वातरक्तनुत्", text: "mañjiṣṭhāsārivāsarjayaṣṭīsikthaiḥ palonmitaiḥ piṇḍākhyaṃ sādhayettailamabhyaṅgāt vātaraktanut" },
      { type: "verse", number: "148", sanskrit: "अर्कपत्ररसे पक्वं हरिद्रा कल्कसंयुतम् नाशयेत्सार्षपं तैलं पामां कच्छूं विचर्चिकाम्", text: "arkapatrarase pakvaṃ haridrā kalkasaṃyutam nāśayetsārṣapaṃ tailaṃ pāmāṃ kacchūṃ vicarcikām" },
      { type: "verse", number: "149", sanskrit: "मरिचं हरितालं च त्रिवृतं रक्तचन्दनम् मुस्तं मनःशिला मांसी द्वे निशे देवदारु च", text: "maricaṃ haritālaṃ ca trivṛtaṃ raktacandanam mustaṃ manaḥśilā māṃsī dve niśe devadāru ca" },
      { type: "verse", number: "150", sanskrit: "विशाला करवीरं च कुष्ठमर्कपयस्तथा तथैव गोमयरसं कुर्यात्कर्षमितान्पृथक्", text: "viśālā karavīraṃ ca kuṣṭhamarkapayastathā tathaiva gomayarasaṃ kuryātkarṣamitānpṛthak" },
      { type: "verse", number: "151", sanskrit: "विषं चार्द्धपलं देयं प्रस्थं च कटुतैलकम् गोमूत्रं द्विगुणं दद्याज्जलं च द्विगुणं भवेत्", text: "viṣaṃ cārddhapalaṃ deyaṃ prasthaṃ ca kaṭutailakam gomūtraṃ dviguṇaṃ dadyājjalaṃ ca dviguṇaṃ bhavet" },
      { type: "verse", number: "152", sanskrit: "मरिचाद्यमिदं तैलं सिध्मकुष्ठहरं परम् जयेत्कुष्ठानि सर्वाणि पुण्डरीकं विचर्चिकाम् पामां श्वित्राणि रक्तं च कण्डूं कच्छूं प्रणाशयेत्", text: "maricādyamidaṃ tailaṃ sidhmakuṣṭhaharaṃ param jayetkuṣṭhāni sarvāṇi puṇḍarīkaṃ vicarcikām pāmāṃ śvitrāṇi raktaṃ ca kaṇḍūṃ kacchūṃ praṇāśayet" },
      { type: "verse", number: "153", sanskrit: "त्रिफलाऽरिष्टभूनिम्बं द्वे निशे रक्तचन्दनम् एतैः सिद्धमरूंषीणां तैलमभ्यज्जने हितम्", text: "triphalā'riṣṭabhūnimbaṃ dve niśe raktacandanam etaiḥ siddhamarūṃṣīṇāṃ tailamabhyajjane hitam" },
      { type: "verse", number: "154", sanskrit: "भावयेन्निम्बबीजानि भृङ्गराजरसेन हि तथाऽसनस्य तोयेन तत्तैलं हन्ति नस्यतः", text: "bhāvayennimbabījāni bhṛṅgarājarasena hi tathā'sanasya toyena tattailaṃ hanti nasyataḥ" },
      { type: "verse", number: "155", sanskrit: "अकालपलितं सद्यः पुंसां दुग्धान्नभोजिनाम्", text: "akālapalitaṃ sadyaḥ puṃsāṃ dugdhānnabhojinām" },
      { type: "verse", number: "156", sanskrit: "यष्टीमधुकक्षाराभ्यां नवधात्रीफलैः शृतम् तैलं नस्यकृतं कुर्यात्केशाञ्श्मश्रूणि सङ्घशः", text: "yaṣṭīmadhukakṣārābhyāṃ navadhātrīphalaiḥ śṛtam tailaṃ nasyakṛtaṃ kuryātkeśāñśmaśrūṇi saṅghaśaḥ" },
      { type: "verse", number: "157", sanskrit: "करञ्जश्चित्रको जाती करवीरश्च पाचितम् तैलमेभिर्द्रुतं हन्यादभ्यङ्गादिन्द्र लुप्तकम्", text: "karañjaścitrako jātī karavīraśca pācitam tailamebhirdrutaṃ hanyādabhyaṅgādindra luptakam" },
      { type: "verse", number: "158", sanskrit: "नीलिका केतकीकन्दं भृङ्गराजः कुरण्टकः तथाऽजुनस्य पुष्पाणि बीजकात्कुसुमान्यपि", text: "nīlikā ketakīkandaṃ bhṛṅgarājaḥ kuraṇṭakaḥ tathā'junasya puṣpāṇi bījakātkusumānyapi" },
      { type: "verse", number: "159", sanskrit: "कृष्णास्तिलाश्च तगरं समूलं कमलं तथा अयोरजः प्रियङ्गुश्च दाडिमत्वग्गुडूचिका", text: "kṛṣṇāstilāśca tagaraṃ samūlaṃ kamalaṃ tathā ayorajaḥ priyaṅguśca dāḍimatvagguḍūcikā" },
      { type: "verse", number: "160", sanskrit: "त्रिफला पद्मपङ्कश्च कल्कैरेभिः पृथक्पृथक् कर्षमात्रः पचेत्तैलं त्रिफलाक्वाथसंयुतम्", text: "triphalā padmapaṅkaśca kalkairebhiḥ pṛthakpṛthak karṣamātraḥ pacettailaṃ triphalākvāthasaṃyutam" },
      { type: "verse", number: "161", sanskrit: "भृङ्गराजरसेनैव सिद्धं केशस्थिरीकृतम् अकालपलितं हन्ति दारुणं चोपजिह्विकाम्", text: "bhṛṅgarājarasenaiva siddhaṃ keśasthirīkṛtam akālapalitaṃ hanti dāruṇaṃ copajihvikām" },
      { type: "verse", number: "162", sanskrit: "भृङ्गराजरसेनैव लोहकिट्टं फलत्रिकम् सारिवां च पचेत्कल्कैस्तैलं दारुणनाशनम् अकालपलितं कण्डूमिन्द्र लुप्तं च नाशयेत्", text: "bhṛṅgarājarasenaiva lohakiṭṭaṃ phalatrikam sārivāṃ ca pacetkalkaistailaṃ dāruṇanāśanam akālapalitaṃ kaṇḍūmindra luptaṃ ca nāśayet" },
      { type: "verse", number: "163", sanskrit: "इरिमेदाद्यं तैलं मुखदन्तरोगादौ इरिमेदत्वचं क्षुण्णां पचेच्छतपलोन्मिताम् जलद्रो णेततः क्वाथं गृह्णीयात्पादशेषितम्", text: "irimedādyaṃ tailaṃ mukhadantarogādau irimedatvacaṃ kṣuṇṇāṃ pacecchatapalonmitām jaladro ṇetataḥ kvāthaṃ gṛhṇīyātpādaśeṣitam" },
      { type: "verse", number: "164", sanskrit: "तैलस्यार्द्धाढकं दत्त्वा कल्कैः कर्षमितैः पचेत् इरिमेदलवङ्गाभ्यां गैरिकागरुपद्मकैः", text: "tailasyārddhāḍhakaṃ dattvā kalkaiḥ karṣamitaiḥ pacet irimedalavaṅgābhyāṃ gairikāgarupadmakaiḥ" },
      { type: "verse", number: "165", sanskrit: "त्वग्जातीफलकर्पूरकङ्कोलखदिरैस्तथा", text: "tvagjātīphalakarpūrakaṅkolakhadiraistathā" },
      { type: "verse", number: "166", sanskrit: "कट्फलेन च संसिद्धं तैलं मुखरुजं जयेत्", text: "kaṭphalena ca saṃsiddhaṃ tailaṃ mukharujaṃ jayet" },
      { type: "verse", number: "167", sanskrit: "प्रदुष्टमांसं पलितं शीर्णदन्तं च सौषिरम् श्यावदन्तं प्रहर्षं च विद्र धिं कृमिदन्तकम्", text: "praduṣṭamāṃsaṃ palitaṃ śīrṇadantaṃ ca sauṣiram śyāvadantaṃ praharṣaṃ ca vidra dhiṃ kṛmidantakam" },
      { type: "verse", number: "168", sanskrit: "दन्तस्फुटं च दौर्गन्ध्यं जिह्वाताल्वोष्ठजां रुजम्", text: "dantasphuṭaṃ ca daurgandhyaṃ jihvātālvoṣṭhajāṃ rujam" },
      { type: "verse", number: "169", sanskrit: "जातीनिम्बपटोलानां नक्तमालस्य पल्लवाः सिक्थं समधुकं कुष्ठं द्वेनिशे कटुरोहिणी", text: "jātīnimbapaṭolānāṃ naktamālasya pallavāḥ sikthaṃ samadhukaṃ kuṣṭhaṃ dveniśe kaṭurohiṇī" },
      { type: "verse", number: "170", sanskrit: "मञ्जिष्ठापद्मकं लोध्रमभया नीलमुत्पलम् तुत्थकं सारिवाबीजं नक्तमालस्य दापयेत्", text: "mañjiṣṭhāpadmakaṃ lodhramabhayā nīlamutpalam tutthakaṃ sārivābījaṃ naktamālasya dāpayet" },
      { type: "verse", number: "171", sanskrit: "एतानि समभागानि पिष्ट्वा तैलं विपाचयेत् नाडीव्रणे समुत्पन्ने स्फोटके कच्छुरोगिषु", text: "etāni samabhāgāni piṣṭvā tailaṃ vipācayet nāḍīvraṇe samutpanne sphoṭake kacchurogiṣu" },
      { type: "verse", number: "172", sanskrit: "सद्यः शस्त्रप्रहारेषु दग्धविद्धेषु चैव हि नखदन्तक्षते देहे व्रणे दुष्टे प्रशस्यते", text: "sadyaḥ śastraprahāreṣu dagdhaviddheṣu caiva hi nakhadantakṣate dehe vraṇe duṣṭe praśasyate" },
      { type: "verse", number: "173", sanskrit: "हिङ्गुतुम्बुरुशुण्ठीभिः कटुतैलं विपाचयेत् तस्य पूरणमात्रेण कर्णशूलं प्रणश्यति", text: "hiṅgutumburuśuṇṭhībhiḥ kaṭutailaṃ vipācayet tasya pūraṇamātreṇa karṇaśūlaṃ praṇaśyati" },
      { type: "verse", number: "174", sanskrit: "बालबिल्वानि गोमूत्रे पिष्ट्वा तैलं विपाचयेत् साजक्षीरं च नीरं च बाधिर्यं हन्ति पूरणात्", text: "bālabilvāni gomūtre piṣṭvā tailaṃ vipācayet sājakṣīraṃ ca nīraṃ ca bādhiryaṃ hanti pūraṇāt" },
      { type: "verse", number: "175", sanskrit: "बालमूलकशिम्बीनां क्षारः क्षारयुगं तथा लवणानि च पञ्चैव हिङ्गुशिग्रु महौषधम्", text: "bālamūlakaśimbīnāṃ kṣāraḥ kṣārayugaṃ tathā lavaṇāni ca pañcaiva hiṅguśigru mahauṣadham" },
      { type: "verse", number: "176", sanskrit: "देवदारु वचा कुष्ठं शतपुष्पा रसाञ्जनम् ग्रन्थिकं भद्र मुस्तं च कल्कैः कर्षमितैः पृथक्", text: "devadāru vacā kuṣṭhaṃ śatapuṣpā rasāñjanam granthikaṃ bhadra mustaṃ ca kalkaiḥ karṣamitaiḥ pṛthak" },
      { type: "verse", number: "177", sanskrit: "तैलप्रस्थं च विपचेत्कदलीबीजपूरयोः रसाभ्यां मधुशुक्तेन चातुर्गुण्यमितेन च", text: "tailaprasthaṃ ca vipacetkadalībījapūrayoḥ rasābhyāṃ madhuśuktena cāturguṇyamitena ca" },
      { type: "verse", number: "178", sanskrit: "पूयस्रावं कर्णनादं शूलं बधिरतां कृमीन् अन्यांश्च कर्णजान्रोगान्मुखरोगांश्च नाशयेत्", text: "pūyasrāvaṃ karṇanādaṃ śūlaṃ badhiratāṃ kṛmīn anyāṃśca karṇajānrogānmukharogāṃśca nāśayet" },
      { type: "verse", number: "179", sanskrit: "जम्बीराणां फलरसः प्रस्थैकः कुडवोन्मितम् माक्षिकं तत्र दातव्यं पलैका पिप्पली स्मृता", text: "jambīrāṇāṃ phalarasaḥ prasthaikaḥ kuḍavonmitam mākṣikaṃ tatra dātavyaṃ palaikā pippalī smṛtā" },
      { type: "verse", number: "180", sanskrit: "एतदेकीकृतं सर्वं मृद्भाण्डे च निधापयेत् यवाम्भो मधुसंयुक्तं शृङ्गवेरगुडान्वितम् धान्यराशौ त्रिरात्रस्थं मधुशुक्तमुदाहृतम्", text: "etadekīkṛtaṃ sarvaṃ mṛdbhāṇḍe ca nidhāpayet yavāmbho madhusaṃyuktaṃ śṛṅgaveraguḍānvitam dhānyarāśau trirātrasthaṃ madhuśuktamudāhṛtam" },
      { type: "verse", number: "181", sanskrit: "पाठा द्वे च निशे मूर्वा पिप्पली जातिपल्लवैः दन्त्या च तैलं संसिद्धं नस्यं स्याद्दुष्टपीनसे", text: "pāṭhā dve ca niśe mūrvā pippalī jātipallavaiḥ dantyā ca tailaṃ saṃsiddhaṃ nasyaṃ syādduṣṭapīnase" },
      { type: "verse", number: "182", sanskrit: "कल्कश्च पाचनं तैलं पूतिनासागदापहम्", text: "kalkaśca pācanaṃ tailaṃ pūtināsāgadāpaham" },
      { type: "verse", number: "183", sanskrit: "कुष्ठंबिल्वकणाशुण्ठीद्रा क्षाकल्ककषायवत् साधितं तैलमाज्यं वा नस्यात्क्षवथुनाशनम्", text: "kuṣṭhaṃbilvakaṇāśuṇṭhīdrā kṣākalkakaṣāyavat sādhitaṃ tailamājyaṃ vā nasyātkṣavathunāśanam" },
      { type: "verse", number: "184", sanskrit: "सिद्धं शिखरिबीजैश्च तैलं नासार्शसां हितम्", text: "siddhaṃ śikharibījaiśca tailaṃ nāsārśasāṃ hitam" },
      { type: "verse", number: "185", sanskrit: "वज्रीक्षीरं रविक्षीरं द्र वं धत्तूरचित्रजम्", text: "vajrīkṣīraṃ ravikṣīraṃ dra vaṃ dhattūracitrajam" },
      { type: "verse", number: "186", sanskrit: "महिषीविड्भवं द्रा वं सर्वांशं तिलतैलकम् पचेत्तैलावशेषं च गोमूत्रेऽथ चतुर्गुणे", text: "mahiṣīviḍbhavaṃ drā vaṃ sarvāṃśaṃ tilatailakam pacettailāvaśeṣaṃ ca gomūtre'tha caturguṇe" },
      { type: "verse", number: "187", sanskrit: "तैलावशेषं पक्त्वा च तत्तैलं प्रस्थमात्रकम् गन्धकाग्निशिलातालं विडङ्गातिविषाविषम्", text: "tailāvaśeṣaṃ paktvā ca tattailaṃ prasthamātrakam gandhakāgniśilātālaṃ viḍaṅgātiviṣāviṣam" },
      { type: "verse", number: "188", sanskrit: "पीतदारु च यष्ट्याह्वं स्वर्जिकाक्षारजीरकम्", text: "pītadāru ca yaṣṭyāhvaṃ svarjikākṣārajīrakam" },
      { type: "verse", number: "189", sanskrit: "देवदारु च कर्षांशं चूर्णं तैले विनिक्षिपेत् वज्रतैलमिदं ख्यातमभ्यङ्गात्सर्वकुष्ठनुत्", text: "devadāru ca karṣāṃśaṃ cūrṇaṃ taile vinikṣipet vajratailamidaṃ khyātamabhyaṅgātsarvakuṣṭhanut" },
      { type: "verse", number: "190", sanskrit: "करवीरशिफादन्ती त्रिवृत्कोशातकी फलम् रम्भाक्षारोदके तैलं प्रशस्तं लोमशातनम्", text: "karavīraśiphādantī trivṛtkośātakī phalam rambhākṣārodake tailaṃ praśastaṃ lomaśātanam" },
      { type: "verse", number: "191", sanskrit: "चन्दनाम्बुनखैर्याम्यं यष्टीशैलेयपद्मकम् मञ्जिष्ठा सरलं दारु सेव्यैलं पूतिकेसरम्", text: "candanāmbunakhairyāmyaṃ yaṣṭīśaileyapadmakam mañjiṣṭhā saralaṃ dāru sevyailaṃ pūtikesaram" },
      { type: "verse", number: "192", sanskrit: "पत्रकैलं मुरामांसी कङ्कोलं वनिताऽम्बुदम् हरिद्रा  सारिवा तिक्ता लवङ्गागरुकुङ्कुमम्", text: "patrakailaṃ murāmāṃsī kaṅkolaṃ vanitā'mbudam haridrā  sārivā tiktā lavaṅgāgarukuṅkumam" },
      { type: "verse", number: "193", sanskrit: "त्वग्रेणुनलिका चेति तैलं मस्तु चतुर्गुणम् लाक्षारससमं सिद्धं ग्रहघ्नं बलवर्द्धनम्", text: "tvagreṇunalikā ceti tailaṃ mastu caturguṇam lākṣārasasamaṃ siddhaṃ grahaghnaṃ balavarddhanam" },
      { type: "verse", number: "194", sanskrit: "आयुः पुष्टिकरं चैव वशीकरणमुत्तमम् विशेषात्क्षयरोगघ्नं रक्तपित्तहरं परम्", text: "āyuḥ puṣṭikaraṃ caiva vaśīkaraṇamuttamam viśeṣātkṣayarogaghnaṃ raktapittaharaṃ param" },
      { type: "verse", number: "195", sanskrit: "वचां शटीं हरिद्रे  द्वे देवदारु महौषधी हरीतकीमतिविषां मुस्तकेन्द्र यवान्समान्", text: "vacāṃ śaṭīṃ haridre  dve devadāru mahauṣadhī harītakīmativiṣāṃ mustakendra yavānsamān" },
      { type: "verse", number: "196", sanskrit: "एतान्दशपलान्भागांश्चतुद्रो र्णे!ऽम्भसः पचेत् चक्रमर्दरसैस्तैलं कटुकं मृदुनाऽग्निना", text: "etāndaśapalānbhāgāṃścatudro rṇe!'mbhasaḥ pacet cakramardarasaistailaṃ kaṭukaṃ mṛdunā'gninā" },
      { type: "verse", number: "197", sanskrit: "पादशेषे विनिक्षिप्य सिन्दूरमवतारयेत् एतत्तैलं निहन्त्याशु गण्डमालां सुदारुणाम्", text: "pādaśeṣe vinikṣipya sindūramavatārayet etattailaṃ nihantyāśu gaṇḍamālāṃ sudāruṇām" },
      { type: "verse", number: "198", sanskrit: "निर्गुण्डीस्वरसे तैलं लाङ्गलीमूलकल्कितम् तैलं नस्यान्निहन्त्याशु गण्डमालां सुदारुणाम्", text: "nirguṇḍīsvarase tailaṃ lāṅgalīmūlakalkitam tailaṃ nasyānnihantyāśu gaṇḍamālāṃ sudāruṇām" },
      { type: "verse", number: "199", sanskrit: "धत्तूररसमादाय हयमारान्तिकारसम् भृङ्गराजरसश्चैव सारिणी निम्बपत्रकम्", text: "dhattūrarasamādāya hayamārāntikārasam bhṛṅgarājarasaścaiva sāriṇī nimbapatrakam" },
      { type: "verse", number: "200", sanskrit: "शोभाञ्जनश्चित्रकश्च अश्वगन्धा प्रसारिणी शिरीषः कुटजोऽनन्ता शाल्मली नक्तपत्रकम्", text: "śobhāñjanaścitrakaśca aśvagandhā prasāriṇī śirīṣaḥ kuṭajo'nantā śālmalī naktapatrakam" },
      { type: "verse", number: "201", sanskrit: "रविप्रियो महानिम्बो डिण्डिघोषा महेरणा बला ज्योतिष्मती चैव श्यामाकश्चक्रमर्दकः", text: "ravipriyo mahānimbo ḍiṇḍighoṣā maheraṇā balā jyotiṣmatī caiva śyāmākaścakramardakaḥ" },
      { type: "verse", number: "202", sanskrit: "एतैस्तु रसमादाय तैलतुल्यं च दीयते देवदारु हरिद्रे  द्वे मांसी कुष्ठं सचन्दनम्", text: "etaistu rasamādāya tailatulyaṃ ca dīyate devadāru haridre  dve māṃsī kuṣṭhaṃ sacandanam" },
      { type: "verse", number: "203", sanskrit: "मरिचं त्रिवृता दन्ती हरितालं मनः शिला कम्पिल्लको गन्धकश्च खदिरः पिप्पली वचा", text: "maricaṃ trivṛtā dantī haritālaṃ manaḥ śilā kampillako gandhakaśca khadiraḥ pippalī vacā" },
      { type: "verse", number: "204", sanskrit: "रसाञ्जनं च सिन्दूरं श्रीवासो रक्तचन्दनम् इरिमेदस्तथा तुम्बी मञ्जिष्ठा सिन्दुवारकः", text: "rasāñjanaṃ ca sindūraṃ śrīvāso raktacandanam irimedastathā tumbī mañjiṣṭhā sinduvārakaḥ" },
      { type: "verse", number: "205", sanskrit: "करवीरजटा रास्ना विश्वा श्रेष्ठा च पौष्करम् शटी तालीसपत्रं च प्रियङ्गू रेणुका तथा", text: "karavīrajaṭā rāsnā viśvā śreṣṭhā ca pauṣkaram śaṭī tālīsapatraṃ ca priyaṅgū reṇukā tathā" },
      { type: "verse", number: "206", sanskrit: "चातुर्जातकमञ्जीरं कङ्कोलं जातिपत्रिका ज्योतिष्मती च पलिका विषस्य द्विपलं भवेत्", text: "cāturjātakamañjīraṃ kaṅkolaṃ jātipatrikā jyotiṣmatī ca palikā viṣasya dvipalaṃ bhavet" },
      { type: "verse", number: "207", sanskrit: "आढकं कटुतैलस्य गोमूत्रं च चतुर्गुणम् मृत्पात्रे लोहपात्रे च शनैर्मृद्वग्नि पचेत्", text: "āḍhakaṃ kaṭutailasya gomūtraṃ ca caturguṇam mṛtpātre lohapātre ca śanairmṛdvagni pacet" },
      { type: "verse", number: "208", sanskrit: "मज्जाश्रितं त्वग्गतं च वातं चास्थिगतं तथा ऊरुग्रहं चाढ्यवातं कृच्छ्रं दण्डापतानकम्", text: "majjāśritaṃ tvaggataṃ ca vātaṃ cāsthigataṃ tathā ūrugrahaṃ cāḍhyavātaṃ kṛcchraṃ daṇḍāpatānakam" },
      { type: "verse", number: "209", sanskrit: "कुब्जत्वं चाथ शोथं च पक्षाघातं तथाऽदितम् हनुस्तम्भं शिरः कम्पं मूर्च्छितं दृष्टिविभ्रमम्", text: "kubjatvaṃ cātha śothaṃ ca pakṣāghātaṃ tathā'ditam hanustambhaṃ śiraḥ kampaṃ mūrcchitaṃ dṛṣṭivibhramam" },
      { type: "verse", number: "210", sanskrit: "अपस्मारं तथोन्मादं तथा चैवापतन्त्रकम् आक्षेपकं चास्थिभग्नं सन्धिभग्नं च नाशयेत्", text: "apasmāraṃ tathonmādaṃ tathā caivāpatantrakam ākṣepakaṃ cāsthibhagnaṃ sandhibhagnaṃ ca nāśayet" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 10,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Дхупа санграха — Фумигационные средства" },
      { type: "text", text: "Дхупа — лекарственный дым для фумигации помещений, дезинфекции ран и терапии дыхательных путей. Перечень ингредиентов и их применение в различных целях." },
      { type: "verse", number: "1", sanskrit: "अथासवारिष्टादिसन्धानकल्पनानाम दशमोऽध्यायः आसवारिष्टसंज्ञा द्र वेषु चिरकालस्थं द्र व्यं यत्संधितं भवेत् आसावारिष्टभेदैस्तु प्रोच्यते भेषजोचितम्", text: "athāsavāriṣṭādisandhānakalpanānāma daśamo'dhyāyaḥ āsavāriṣṭasaṃjñā dra veṣu cirakālasthaṃ dra vyaṃ yatsaṃdhitaṃ bhavet āsāvāriṣṭabhedaistu procyate bheṣajocitam" },
      { type: "verse", number: "2", sanskrit: "यदपक्वौषधाम्बुभ्यां सिद्धं मद्यं स आसवः अरिष्टः क्वाथसाध्यः स्यात्तयोर्मानं पलोन्मितम्", text: "yadapakvauṣadhāmbubhyāṃ siddhaṃ madyaṃ sa āsavaḥ ariṣṭaḥ kvāthasādhyaḥ syāttayormānaṃ palonmitam" },
      { type: "verse", number: "3", sanskrit: "अनुक्तमानारिष्टेषु जलादिमानव्यवस्था अनुक्तमानारिष्टेषु द्र वद्रो णे तुलां गुडम् क्षौद्रं  क्षिपेद् गुडादर्द्धं प्रक्षेपं दशमांशिकम्", text: "anuktamānāriṣṭeṣu jalādimānavyavasthā anuktamānāriṣṭeṣu dra vadro ṇe tulāṃ guḍam kṣaudraṃ  kṣiped guḍādarddhaṃ prakṣepaṃ daśamāṃśikam" },
      { type: "verse", number: "4", sanskrit: "ज्ञेयः शीतरसःसीधुरपक्वमधुरद्र वैः सिद्धः पक्वरसः सीधुः सम्पक्वमधुरद्र वैः", text: "jñeyaḥ śītarasaḥsīdhurapakvamadhuradra vaiḥ siddhaḥ pakvarasaḥ sīdhuḥ sampakvamadhuradra vaiḥ" },
      { type: "verse", number: "5", sanskrit: "सुराप्रसन्नादीनां मद्यभेदानां लक्षणानि परिपक्वान्नसन्धानसमुत्पन्नां सुरां जगुः सुरामण्डः प्रसन्ना स्यात्ततः कादम्बरी घना", text: "surāprasannādīnāṃ madyabhedānāṃ lakṣaṇāni paripakvānnasandhānasamutpannāṃ surāṃ jaguḥ surāmaṇḍaḥ prasannā syāttataḥ kādambarī ghanā" },
      { type: "verse", number: "6", sanskrit: "तदधो जगलो ज्ञेयो मेदको जगलाद्घनः पक्वोऽसौ हृतसारः स्यात्सुराबीजं च किण्वकम्", text: "tadadho jagalo jñeyo medako jagalādghanaḥ pakvo'sau hṛtasāraḥ syātsurābījaṃ ca kiṇvakam" },
      { type: "verse", number: "7", sanskrit: "यत्तालखर्जूररसैः संधिता सा हि वारुणी कन्दमूलफलादीनि सस्नेहलवणानि च यत्र द्र वेऽभिषूयन्ते तच्छुक्तमभिधीयते", text: "yattālakharjūrarasaiḥ saṃdhitā sā hi vāruṇī kandamūlaphalādīni sasnehalavaṇāni ca yatra dra ve'bhiṣūyante tacchuktamabhidhīyate" },
      { type: "verse", number: "8", sanskrit: "विनष्टमम्लतां यातं मद्यं वा मधुरद्र वः विनष्टः सन्धितो यस्तु तच्च्रुकमभिधीयते", text: "vinaṣṭamamlatāṃ yātaṃ madyaṃ vā madhuradra vaḥ vinaṣṭaḥ sandhito yastu taccrukamabhidhīyate" },
      { type: "verse", number: "9", sanskrit: "गुडशुक्तेक्षुशुक्तद्रा क्षाशुक्तानां लक्षणानि गुडाम्बुना सतैलेन कन्दमूलफलैस्तथा सन्धितं चाम्लतां यातं गुडशुक्तं तदुच्यते", text: "guḍaśuktekṣuśuktadrā kṣāśuktānāṃ lakṣaṇāni guḍāmbunā satailena kandamūlaphalaistathā sandhitaṃ cāmlatāṃ yātaṃ guḍaśuktaṃ taducyate" },
      { type: "verse", number: "10", sanskrit: "एवमेवेक्षुशुक्तं स्यान्मृद्वीकासम्भवं तथा", text: "evamevekṣuśuktaṃ syānmṛdvīkāsambhavaṃ tathā" },
      { type: "verse", number: "11", sanskrit: "तुषाम्बु सन्धितं ज्ञेयमामैर्विदलितैर्यवैः यवैस्तु निस्तुषैः पक्वैः सौवीरं सन्धितं भवेत्", text: "tuṣāmbu sandhitaṃ jñeyamāmairvidalitairyavaiḥ yavaistu nistuṣaiḥ pakvaiḥ sauvīraṃ sandhitaṃ bhavet" },
      { type: "verse", number: "12", sanskrit: "कुल्माषधान्यमण्डादिसन्धितं काञ्जिकं विदुः सण्डाकी सन्धिता ज्ञेया मूलकैः सर्षपादिभिः", text: "kulmāṣadhānyamaṇḍādisandhitaṃ kāñjikaṃ viduḥ saṇḍākī sandhitā jñeyā mūlakaiḥ sarṣapādibhiḥ" },
      { type: "verse", number: "13", sanskrit: "तत्रादावुशीरासवो रक्तपित्तादौ उशीरं बालकं पद्मं काश्मरीं नीलमुत्पलम् प्रियङ्गुं पद्मकं लोध्रं मञ्जिष्ठां धन्वयासकम्", text: "tatrādāvuśīrāsavo raktapittādau uśīraṃ bālakaṃ padmaṃ kāśmarīṃ nīlamutpalam priyaṅguṃ padmakaṃ lodhraṃ mañjiṣṭhāṃ dhanvayāsakam" },
      { type: "verse", number: "14", sanskrit: "पाठां किराततिक्तं च न्यग्रोधोदुम्बरं शटीम् पर्पटं पुण्डरीकं च पटोलं काञ्चनारकम्", text: "pāṭhāṃ kirātatiktaṃ ca nyagrodhodumbaraṃ śaṭīm parpaṭaṃ puṇḍarīkaṃ ca paṭolaṃ kāñcanārakam" },
      { type: "verse", number: "15", sanskrit: "जंबूशाल्मलिनिर्यासं प्रत्येकं पलसम्मितान् भागान्सुचूर्णितान्कृत्वा द्रा क्षायाः पलविंशतिम्", text: "jaṃbūśālmaliniryāsaṃ pratyekaṃ palasammitān bhāgānsucūrṇitānkṛtvā drā kṣāyāḥ palaviṃśatim" },
      { type: "verse", number: "16", sanskrit: "धातकीं षोडशपलां जलद्रो णद्वये क्षिपेत् शर्करायास्तुलां दत्त्वा क्षौद्र स्यैकतुलां तथा", text: "dhātakīṃ ṣoḍaśapalāṃ jaladro ṇadvaye kṣipet śarkarāyāstulāṃ dattvā kṣaudra syaikatulāṃ tathā" },
      { type: "verse", number: "17", sanskrit: "मासैकं स्थापयेद्भाण्डे मांसीमरिचधूपिते उशीरासव इत्येष रक्तपित्तविनाशनः पाण्डुकुष्ठप्रमेहार्शः कृमिशोथहरस्तथा", text: "māsaikaṃ sthāpayedbhāṇḍe māṃsīmaricadhūpite uśīrāsava ityeṣa raktapittavināśanaḥ pāṇḍukuṣṭhapramehārśaḥ kṛmiśothaharastathā" },
      { type: "verse", number: "18", sanskrit: "सुपक्वरससंशुद्धं कुमार्याः पत्रमाहरेत् यत्नेन रसमादाय पात्रे पाषाणमृण्मये", text: "supakvarasasaṃśuddhaṃ kumāryāḥ patramāharet yatnena rasamādāya pātre pāṣāṇamṛṇmaye" },
      { type: "verse", number: "19", sanskrit: "द्रो णे गुडतुलां दत्त्वा घृत भाण्डे निधापयेत् माक्षिकं पक्वलोहं च तस्मिन्नर्द्धतुलां क्षिपेत्", text: "dro ṇe guḍatulāṃ dattvā ghṛta bhāṇḍe nidhāpayet mākṣikaṃ pakvalohaṃ ca tasminnarddhatulāṃ kṣipet" },
      { type: "verse", number: "20", sanskrit: "कटुत्रिकं लवङ्गं च चातुर्जातकमेव च चित्रकं पिप्पलीमूलं विडङ्गं गजपिप्पली", text: "kaṭutrikaṃ lavaṅgaṃ ca cāturjātakameva ca citrakaṃ pippalīmūlaṃ viḍaṅgaṃ gajapippalī" },
      { type: "verse", number: "21", sanskrit: "चविकं हपुषा धान्यं क्रमुकं कटुरोहणी मुस्ता फलत्रिकं रास्ना देवदारु निशाद्वयम्", text: "cavikaṃ hapuṣā dhānyaṃ kramukaṃ kaṭurohaṇī mustā phalatrikaṃ rāsnā devadāru niśādvayam" },
      { type: "verse", number: "22", sanskrit: "मूर्वा मधुरसा दन्ती मूलं पुष्करसम्भवम् बला चातिबला चैव कपिकच्छुस्त्रिकण्टकम्", text: "mūrvā madhurasā dantī mūlaṃ puṣkarasambhavam balā cātibalā caiva kapikacchustrikaṇṭakam" },
      { type: "verse", number: "23", sanskrit: "शतपुष्पा हिङ्गुपत्री आकल्लकमुटिङ्गणम् पुनर्नवाद्वयं लोध्रं धातुमाक्षिकमेव च", text: "śatapuṣpā hiṅgupatrī ākallakamuṭiṅgaṇam punarnavādvayaṃ lodhraṃ dhātumākṣikameva ca" },
      { type: "verse", number: "24", sanskrit: "एषां चार्द्धपलं दत्त्वा धातक्यास्तु पलाष्टकम् पलं चार्द्धपलं चैव पलद्वयमुदाहृतम्", text: "eṣāṃ cārddhapalaṃ dattvā dhātakyāstu palāṣṭakam palaṃ cārddhapalaṃ caiva paladvayamudāhṛtam" },
      { type: "verse", number: "25", sanskrit: "वपुर्वयः प्रमाणेन बलवर्णाग्निदीपनम् बृंहणं रोचनं वृष्यं पक्तिशूलनिवारणम्", text: "vapurvayaḥ pramāṇena balavarṇāgnidīpanam bṛṃhaṇaṃ rocanaṃ vṛṣyaṃ paktiśūlanivāraṇam" },
      { type: "verse", number: "26", sanskrit: "अष्टावुदरजान्रोगान्क्षयमुग्रं च नाशयेत् विंशतिं मेहजान्रोगानुदावर्त्तमपस्मृतिम्", text: "aṣṭāvudarajānrogānkṣayamugraṃ ca nāśayet viṃśatiṃ mehajānrogānudāvarttamapasmṛtim" },
      { type: "verse", number: "27", sanskrit: "मूत्रकृच्छ्रमपस्मारं शुक्रदोषं तथाऽश्मरीम् कृमिजं रक्तपित्तं च नाशयेत्तु न संशयः", text: "mūtrakṛcchramapasmāraṃ śukradoṣaṃ tathā'śmarīm kṛmijaṃ raktapittaṃ ca nāśayettu na saṃśayaḥ" },
      { type: "verse", number: "28", sanskrit: "पिप्पली मरिचं चव्यं हरिद्रा  चित्रको घनः", text: "pippalī maricaṃ cavyaṃ haridrā  citrako ghanaḥ" },
      { type: "verse", number: "29", sanskrit: "विडङ्गं क्रमुको लोध्रः पाठा धात्र्! येलवालुकम् उशीरं चन्दनं कुष्ठं लवंगं तगरं तथा", text: "viḍaṅgaṃ kramuko lodhraḥ pāṭhā dhātr! yelavālukam uśīraṃ candanaṃ kuṣṭhaṃ lavaṃgaṃ tagaraṃ tathā" },
      { type: "verse", number: "30", sanskrit: "मांसी त्वगेलापत्रं च प्रियङ्गुर्नागकेशरम् एषामर्द्धपलान्भागान्सूक्ष्मचूर्णीकृताञ्छुभान्", text: "māṃsī tvagelāpatraṃ ca priyaṅgurnāgakeśaram eṣāmarddhapalānbhāgānsūkṣmacūrṇīkṛtāñchubhān" },
      { type: "verse", number: "31", sanskrit: "जलद्रो णद्वये क्षिप्त्वा दद्याद् गुडतुलात्रयम् पलानि दश धातक्या द्रा क्षा षष्टिपला भवेत्", text: "jaladro ṇadvaye kṣiptvā dadyād guḍatulātrayam palāni daśa dhātakyā drā kṣā ṣaṣṭipalā bhavet" },
      { type: "verse", number: "32", sanskrit: "एतान्येकत्र संयोज्य मृद्भाण्डे च विनिक्षिपेत् ज्ञात्वागतरसं सर्वं पाययेदग्न्यपेक्षया", text: "etānyekatra saṃyojya mṛdbhāṇḍe ca vinikṣipet jñātvāgatarasaṃ sarvaṃ pāyayedagnyapekṣayā" },
      { type: "verse", number: "33", sanskrit: "क्षयं गुल्मोदरं कार्श्यं ग्रहणीं पांडुतां तथा अर्शांसि नाशयेच्छीघ्रं पिप्पल्याद्यासवस्त्वयम्", text: "kṣayaṃ gulmodaraṃ kārśyaṃ grahaṇīṃ pāṃḍutāṃ tathā arśāṃsi nāśayecchīghraṃ pippalyādyāsavastvayam" },
      { type: "verse", number: "34", sanskrit: "लोहचूर्णं त्रिकटुकं त्रिफलां च यवानिकाम् विडङ्गं मुस्तकं चित्रं चतुःसङ्ख्यापलंपृथक्", text: "lohacūrṇaṃ trikaṭukaṃ triphalāṃ ca yavānikām viḍaṅgaṃ mustakaṃ citraṃ catuḥsaṅkhyāpalaṃpṛthak" },
      { type: "verse", number: "35", sanskrit: "धातकीकुसुमानां तु प्रक्षिपेत्पलविंशतिम् चूर्णीकृत्य ततः क्षौद्रं  चतुःषष्टिपलं क्षिपेत्", text: "dhātakīkusumānāṃ tu prakṣipetpalaviṃśatim cūrṇīkṛtya tataḥ kṣaudraṃ  catuḥṣaṣṭipalaṃ kṣipet" },
      { type: "verse", number: "36", sanskrit: "दद्याद् गुडतुलां तत्र जलद्रो णद्वयं तथा घृतभाण्डे विनिक्षिप्य निदध्यान्मासमात्रकम्", text: "dadyād guḍatulāṃ tatra jaladro ṇadvayaṃ tathā ghṛtabhāṇḍe vinikṣipya nidadhyānmāsamātrakam" },
      { type: "verse", number: "37", sanskrit: "लोहासवममुं मत्तर्यः पिबेद्वह्निकरं परम् पाण्डुश्वयथुगुल्मानि जठराण्यर्शसां रुजम्", text: "lohāsavamamuṃ mattaryaḥ pibedvahnikaraṃ param pāṇḍuśvayathugulmāni jaṭharāṇyarśasāṃ rujam" },
      { type: "verse", number: "38", sanskrit: "कुष्ठं प्लीहामयं कण्डूं कासं श्वासं भगन्दरम् अरोचकं च ग्रहणीं हृद्रो गं च विनाशयेत्", text: "kuṣṭhaṃ plīhāmayaṃ kaṇḍūṃ kāsaṃ śvāsaṃ bhagandaram arocakaṃ ca grahaṇīṃ hṛdro gaṃ ca vināśayet" },
      { type: "verse", number: "39", sanskrit: "तत्रादौ मृदीकारिष्टोऽश प्रभृतिरोगेषु मृद्वीकायाः पलशतं चतुद्रो र्णे!ऽम्भसः पचेत् द्रो णशेषे सुशीते च पूते तस्मिन्प्रदापयेत्", text: "tatrādau mṛdīkāriṣṭo'śa prabhṛtirogeṣu mṛdvīkāyāḥ palaśataṃ catudro rṇe!'mbhasaḥ pacet dro ṇaśeṣe suśīte ca pūte tasminpradāpayet" },
      { type: "verse", number: "40", sanskrit: "तुले द्वे क्षौद्र खण्डाभ्यां धातक्याः प्रस्थमेव च कङ्कोलकं लवङ्गं च फलं जात्यास्तथैव च", text: "tule dve kṣaudra khaṇḍābhyāṃ dhātakyāḥ prasthameva ca kaṅkolakaṃ lavaṅgaṃ ca phalaṃ jātyāstathaiva ca" },
      { type: "verse", number: "41", sanskrit: "पलांशकं च मरिचत्वगेलापत्रकेसराः पिप्पली चित्रकं चव्यं पिप्पलीमूलरेणुके", text: "palāṃśakaṃ ca maricatvagelāpatrakesarāḥ pippalī citrakaṃ cavyaṃ pippalīmūlareṇuke" },
      { type: "verse", number: "42", sanskrit: "घृतभाण्डे विनिक्षिप्य चन्दनागरुधूपिते कर्पूरवासितो ह्येष ग्रहण्या दीपनः परः", text: "ghṛtabhāṇḍe vinikṣipya candanāgarudhūpite karpūravāsito hyeṣa grahaṇyā dīpanaḥ paraḥ" },
      { type: "verse", number: "43", sanskrit: "अर्शसां नाशने श्रेष्ठ उदावर्त्तस्य गुल्मनुत् जठरकृमिकुष्ठानि व्रणास्तु विविधास्तथा", text: "arśasāṃ nāśane śreṣṭha udāvarttasya gulmanut jaṭharakṛmikuṣṭhāni vraṇāstu vividhāstathā" },
      { type: "verse", number: "44", sanskrit: "तुलां कुटजमूलस्य मृद्वीकाऽद्धतुलां तथा मधूकपुष्पकाश्मर्यौ भागान्दशपलोन्मितान्", text: "tulāṃ kuṭajamūlasya mṛdvīkā'ddhatulāṃ tathā madhūkapuṣpakāśmaryau bhāgāndaśapalonmitān" },
      { type: "verse", number: "45", sanskrit: "चतुद्रो र्णे!ऽम्भसः पक्त्वा क्वाथे द्रो णावशेषिते धातक्या विंशतिपलं गुडस्य च तुलां क्षिपेत्", text: "catudro rṇe!'mbhasaḥ paktvā kvāthe dro ṇāvaśeṣite dhātakyā viṃśatipalaṃ guḍasya ca tulāṃ kṣipet" },
      { type: "verse", number: "46", sanskrit: "मासमात्रं स्थितो भाण्डे कुटजारिष्टसञ्ज्ञितः ज्वरान्प्रशमयेत्सर्वान्कुर्यात्तीक्ष्णं धनञ्जयम्", text: "māsamātraṃ sthito bhāṇḍe kuṭajāriṣṭasañjñitaḥ jvarānpraśamayetsarvānkuryāttīkṣṇaṃ dhanañjayam" },
      { type: "verse", number: "47", sanskrit: "विडङ्गं ग्रन्थिकं रास्ना कुटजत्वक्फलानि च", text: "viḍaṅgaṃ granthikaṃ rāsnā kuṭajatvakphalāni ca" },
      { type: "verse", number: "48", sanskrit: "पाठैलवालुकं धात्री भागान्पञ्चपलान्पृथक् अष्टद्रो णेऽम्भसः पक्त्वा कुर्याद् द्रो णावशेषितम्", text: "pāṭhailavālukaṃ dhātrī bhāgānpañcapalānpṛthak aṣṭadro ṇe'mbhasaḥ paktvā kuryād dro ṇāvaśeṣitam" },
      { type: "verse", number: "49", sanskrit: "पूते शीते क्षिपेत्तत्र क्षौद्रं  पलशतत्रयम् धातकीं विंशतिपलां त्रिजातं द्विपलं तथा", text: "pūte śīte kṣipettatra kṣaudraṃ  palaśatatrayam dhātakīṃ viṃśatipalāṃ trijātaṃ dvipalaṃ tathā" },
      { type: "verse", number: "50", sanskrit: "प्रियङ्गुकाञ्चनाराणां सलोध्राणां पलंपलम् व्योषस्य च पलान्यष्टौ चूर्णीकृत्य प्रदापयेत्", text: "priyaṅgukāñcanārāṇāṃ salodhrāṇāṃ palaṃpalam vyoṣasya ca palānyaṣṭau cūrṇīkṛtya pradāpayet" },
      { type: "verse", number: "51", sanskrit: "घृतभाण्डे विनिक्षिप्य मासमेकं विधारयेत् ततः पिबेद्यथाऽह तु जयेद्विद्र धिमूर्जितम्", text: "ghṛtabhāṇḍe vinikṣipya māsamekaṃ vidhārayet tataḥ pibedyathā'ha tu jayedvidra dhimūrjitam" },
      { type: "verse", number: "52", sanskrit: "गण्डमालां हनुस्तम्भं विडङ्गारिष्टसञ्ज्ञितः", text: "gaṇḍamālāṃ hanustambhaṃ viḍaṅgāriṣṭasañjñitaḥ" },
      { type: "verse", number: "53", sanskrit: "देवदार्वाद्यरिष्टः प्रमेहादौ तुलाऽद्ध देवदारु स्याद्वासा च पलविंशतिः मज्जिष्ठेन्द्र यवा दन्ती तगरं रजनीद्वयम्", text: "devadārvādyariṣṭaḥ pramehādau tulā'ddha devadāru syādvāsā ca palaviṃśatiḥ majjiṣṭhendra yavā dantī tagaraṃ rajanīdvayam" },
      { type: "verse", number: "54", sanskrit: "रास्ना कृमिघ्नं मुस्तं च शिरीषं खदिरार्जुनौ भागान्दशपलान्दद्याद्यवान्या वत्सकस्य च", text: "rāsnā kṛmighnaṃ mustaṃ ca śirīṣaṃ khadirārjunau bhāgāndaśapalāndadyādyavānyā vatsakasya ca" },
      { type: "verse", number: "55", sanskrit: "चन्दनस्य गुडूच्याश्च रोहिण्याश्चित्रकस्य च भागानष्टपलानेतानष्टद्रो णेऽम्भसः पचेत्", text: "candanasya guḍūcyāśca rohiṇyāścitrakasya ca bhāgānaṣṭapalānetānaṣṭadro ṇe'mbhasaḥ pacet" },
      { type: "verse", number: "56", sanskrit: "द्रो णशेषे कषाये च पूते शीते प्रदापयेत् धातक्याः षोडशपलं माक्षिकस्य तुलात्रयम्", text: "dro ṇaśeṣe kaṣāye ca pūte śīte pradāpayet dhātakyāḥ ṣoḍaśapalaṃ mākṣikasya tulātrayam" },
      { type: "verse", number: "57", sanskrit: "व्योषस्य द्विपलं दद्यात् त्रिजातस्य चतुष्पलम् चतुष्पलं प्रियङ्गोश्च द्विपलं नागकेशरम्", text: "vyoṣasya dvipalaṃ dadyāt trijātasya catuṣpalam catuṣpalaṃ priyaṅgośca dvipalaṃ nāgakeśaram" },
      { type: "verse", number: "58", sanskrit: "सर्वाण्येतानि सञ्चूर्ण्य घृतभाण्डे निधापयेत् मासादूर्ध्वं पिबेदेनं प्रमेहं हन्ति दुर्जयम्", text: "sarvāṇyetāni sañcūrṇya ghṛtabhāṇḍe nidhāpayet māsādūrdhvaṃ pibedenaṃ pramehaṃ hanti durjayam" },
      { type: "verse", number: "59", sanskrit: "वातरोगान्ग्रहण्यर्शो मूत्रकृच्छ्राणि नाशयेत् देवदार्वादिकोऽरिष्टः कण्डूकुष्ठविनाशनः", text: "vātarogāngrahaṇyarśo mūtrakṛcchrāṇi nāśayet devadārvādiko'riṣṭaḥ kaṇḍūkuṣṭhavināśanaḥ" },
      { type: "verse", number: "60", sanskrit: "खदिरस्य तुलाऽद्ध तु देवदारु च तत्समम् वाकुची द्वादशपला दार्वी स्यात्पलविंशतिः", text: "khadirasya tulā'ddha tu devadāru ca tatsamam vākucī dvādaśapalā dārvī syātpalaviṃśatiḥ" },
      { type: "verse", number: "61", sanskrit: "त्रिफला विंशतिपला ह्यष्टद्रो णेऽम्भसः पचेत् कषाये द्रो णशेषे च पूते शीते विनिक्षिपेत्", text: "triphalā viṃśatipalā hyaṣṭadro ṇe'mbhasaḥ pacet kaṣāye dro ṇaśeṣe ca pūte śīte vinikṣipet" },
      { type: "verse", number: "62", sanskrit: "तुलाद्वयं माक्षिकस्य तुलैका शर्करा मता धातक्या विंशतिपलं कङ्कोलं नागकेशरम्", text: "tulādvayaṃ mākṣikasya tulaikā śarkarā matā dhātakyā viṃśatipalaṃ kaṅkolaṃ nāgakeśaram" },
      { type: "verse", number: "63", sanskrit: "जातीफलं लवङ्गैलात्वक्पत्राणि पृथक्पृथक् पलोन्मितानि कृष्णाया दद्यात्पलचतुष्टयम्", text: "jātīphalaṃ lavaṅgailātvakpatrāṇi pṛthakpṛthak palonmitāni kṛṣṇāyā dadyātpalacatuṣṭayam" },
      { type: "verse", number: "64", sanskrit: "घृतभाण्डे विनिक्षिप्य मासादूर्ध्वं पिबेन्नरः महाकुष्ठानि हृद्रो गं पाण्डुरोगार्बुदे तथा", text: "ghṛtabhāṇḍe vinikṣipya māsādūrdhvaṃ pibennaraḥ mahākuṣṭhāni hṛdro gaṃ pāṇḍurogārbude tathā" },
      { type: "verse", number: "65", sanskrit: "गुल्मं ग्रन्थिं कृमीन्कासं श्वासं प्लीहोदरं जयेत् एष वै खदिरारिष्टः सर्वकुष्ठनिवारणः", text: "gulmaṃ granthiṃ kṛmīnkāsaṃ śvāsaṃ plīhodaraṃ jayet eṣa vai khadirāriṣṭaḥ sarvakuṣṭhanivāraṇaḥ" },
      { type: "verse", number: "66", sanskrit: "तुलाद्वयं तु बब्बूल्याश्चतुद्रो र्णे! जले पचेत् द्रो णशेषे रसे शीते गुडस्य त्रितुलां क्षिपेत्", text: "tulādvayaṃ tu babbūlyāścatudro rṇe! jale pacet dro ṇaśeṣe rase śīte guḍasya tritulāṃ kṣipet" },
      { type: "verse", number: "67", sanskrit: "धातकीं षोडशपलां कृष्णां च द्विपलां तथा जातीफलानि कङ्कोलमेलात्वक्पत्रकेशरम्", text: "dhātakīṃ ṣoḍaśapalāṃ kṛṣṇāṃ ca dvipalāṃ tathā jātīphalāni kaṅkolamelātvakpatrakeśaram" },
      { type: "verse", number: "68", sanskrit: "लवङ्गं मरिचं चैव पलिकान्युपकल्पयेत् मासं भाण्डे स्थितस्त्वेष बब्बूलारिष्टको जयेत् क्षयं कुष्ठमतीसारं प्रमेहश्वासकासकम्", text: "lavaṅgaṃ maricaṃ caiva palikānyupakalpayet māsaṃ bhāṇḍe sthitastveṣa babbūlāriṣṭako jayet kṣayaṃ kuṣṭhamatīsāraṃ pramehaśvāsakāsakam" },
      { type: "verse", number: "69", sanskrit: "द्रा क्षातुलाऽद्ध द्विद्रो णे जलस्य विपचेत् सुधीः पादशेषे कषाये च पूते शीते विनिक्षिपेत्", text: "drā kṣātulā'ddha dvidro ṇe jalasya vipacet sudhīḥ pādaśeṣe kaṣāye ca pūte śīte vinikṣipet" },
      { type: "verse", number: "70", sanskrit: "गुडस्य द्वितुलां तत्र त्वगेलापत्रकेशरम् प्रियङ्गुर्मरिचं कृष्णा विडङ्गं चेति चूर्णयेत्", text: "guḍasya dvitulāṃ tatra tvagelāpatrakeśaram priyaṅgurmaricaṃ kṛṣṇā viḍaṅgaṃ ceti cūrṇayet" },
      { type: "verse", number: "71", sanskrit: "पृथक्पलोन्मितैर्भागैस्ततो भाण्डे निधापयेत् समन्ततो घट्टयित्वा पिबेञ्जातरसंततः", text: "pṛthakpalonmitairbhāgaistato bhāṇḍe nidhāpayet samantato ghaṭṭayitvā pibeñjātarasaṃtataḥ" },
      { type: "verse", number: "72", sanskrit: "उरःक्षतं क्षयं हन्ति कासश्वासगलामयान् द्रा क्षाऽरिष्टाह्वयः प्रोक्तो बलकृन्मलशोधनः", text: "uraḥkṣataṃ kṣayaṃ hanti kāsaśvāsagalāmayān drā kṣā'riṣṭāhvayaḥ prokto balakṛnmalaśodhanaḥ" },
      { type: "verse", number: "73", sanskrit: "रोहितकारिष्टो गुदजग्रहण्यादौ रोहितकतुलामेकां चतुद्रो र्णे! जले पचेत् पादशेषे रसे शीते पूते पलशतद्वयम्", text: "rohitakāriṣṭo gudajagrahaṇyādau rohitakatulāmekāṃ catudro rṇe! jale pacet pādaśeṣe rase śīte pūte palaśatadvayam" },
      { type: "verse", number: "74", sanskrit: "दद्याद् गुडस्य धातक्याः पलषोडशिका मता पञ्चकोलं त्रिजातं च त्रिफलां च विनिक्षिपेत्", text: "dadyād guḍasya dhātakyāḥ palaṣoḍaśikā matā pañcakolaṃ trijātaṃ ca triphalāṃ ca vinikṣipet" },
      { type: "verse", number: "75", sanskrit: "चूर्णयित्वापलांशेन ततोभाण्डेनिधापयेत् मासादूर्ध्वं च पिबतां गुदजा यान्ति संक्षयम्", text: "cūrṇayitvāpalāṃśena tatobhāṇḍenidhāpayet māsādūrdhvaṃ ca pibatāṃ gudajā yānti saṃkṣayam" },
      { type: "verse", number: "76", sanskrit: "ग्रहणीपाण्डुहृद्रो गप्लीहगुल्मोदराणि च कुष्ठशोफारुचिहरो रोहितारिष्टसञ्ज्ञितः", text: "grahaṇīpāṇḍuhṛdro gaplīhagulmodarāṇi ca kuṣṭhaśophāruciharo rohitāriṣṭasañjñitaḥ" },
      { type: "verse", number: "77", sanskrit: "पर्ण्यौ बृहत्यौ गोकण्टो बिल्वोऽग्निमन्थकोऽरलुः", text: "parṇyau bṛhatyau gokaṇṭo bilvo'gnimanthako'raluḥ" },
      { type: "verse", number: "78", sanskrit: "पाटला काश्मरी चेति दशमूलमिहोच्यते दशमूलानि कुर्वीत भागैः पञ्चपलैःपृथक्", text: "pāṭalā kāśmarī ceti daśamūlamihocyate daśamūlāni kurvīta bhāgaiḥ pañcapalaiḥpṛthak" },
      { type: "verse", number: "79", sanskrit: "पञ्चविंशत्पलं कुर्याच्चित्रकं पौष्करं तथा कुर्याद्विंशपलं लोध्रं गुडूची तत्समा भवेत्", text: "pañcaviṃśatpalaṃ kuryāccitrakaṃ pauṣkaraṃ tathā kuryādviṃśapalaṃ lodhraṃ guḍūcī tatsamā bhavet" },
      { type: "verse", number: "80", sanskrit: "पलैः षोडशभिर्धात्री रविसङ्ख्यैर्दुरालभा खदिरो बीजसारश्च पथ्या चेति पृथक्पलैः", text: "palaiḥ ṣoḍaśabhirdhātrī ravisaṅkhyairdurālabhā khadiro bījasāraśca pathyā ceti pṛthakpalaiḥ" },
      { type: "verse", number: "81", sanskrit: "अष्टभिर्गणितः कुष्ठं मञ्जिष्ठा देवदारु च विडङ्गं मधुकं भार्ङ्गी कपित्थोऽक्ष पुनर्नवा", text: "aṣṭabhirgaṇitaḥ kuṣṭhaṃ mañjiṣṭhā devadāru ca viḍaṅgaṃ madhukaṃ bhārṅgī kapittho'kṣa punarnavā" },
      { type: "verse", number: "82", sanskrit: "चव्यं मांसी प्रियङ्गुश्च सारिवा कृष्णजीरकम् त्रिवृता रेणुकं रास्ना पिप्पली क्रमुकः शटी", text: "cavyaṃ māṃsī priyaṅguśca sārivā kṛṣṇajīrakam trivṛtā reṇukaṃ rāsnā pippalī kramukaḥ śaṭī" },
      { type: "verse", number: "83", sanskrit: "हरिद्रा  शतपुष्पा च पद्मकं नागकेशरम् मुस्तमिन्द्र यवः शुण्ठी जीवकर्षभकौ तथा", text: "haridrā  śatapuṣpā ca padmakaṃ nāgakeśaram mustamindra yavaḥ śuṇṭhī jīvakarṣabhakau tathā" },
      { type: "verse", number: "84", sanskrit: "मेदा चान्या महामेदा काकोल्यौ ऋद्धिवृद्धिके कुर्यात्पृथग्द्विपलिकान्पचेदष्टगुणे जले", text: "medā cānyā mahāmedā kākolyau ṛddhivṛddhike kuryātpṛthagdvipalikānpacedaṣṭaguṇe jale" },
      { type: "verse", number: "85", sanskrit: "चतुर्थाशं शृतं नीत्वा मृद्भाण्डे संनिधापयेत् चतुःषष्टिपलां द्रा क्षां पचेन्नीरे चतुर्गुणे", text: "caturthāśaṃ śṛtaṃ nītvā mṛdbhāṇḍe saṃnidhāpayet catuḥṣaṣṭipalāṃ drā kṣāṃ pacennīre caturguṇe" },
      { type: "verse", number: "86", sanskrit: "त्रिपादशेषं शीतं च पूर्वक्वाथे शृतं क्षिपेत् द्वात्रिंशत्पलिकं क्षौद्रं  दद्याद् गुणचतुःशतम्", text: "tripādaśeṣaṃ śītaṃ ca pūrvakvāthe śṛtaṃ kṣipet dvātriṃśatpalikaṃ kṣaudraṃ  dadyād guṇacatuḥśatam" },
      { type: "verse", number: "87", sanskrit: "त्रिंशत्पलानि धातक्याः कङ्कोलं जलचन्दनम् जातीफलं लवङ्गं च त्वगेलापत्रकेशरम्", text: "triṃśatpalāni dhātakyāḥ kaṅkolaṃ jalacandanam jātīphalaṃ lavaṅgaṃ ca tvagelāpatrakeśaram" },
      { type: "verse", number: "88", sanskrit: "पिप्पली चेति संचूर्ण्य भागैर्द्विपलिकः पृथक् शाणमात्रां च कस्तूरीं सर्वमेकत्र निक्षिपेत्", text: "pippalī ceti saṃcūrṇya bhāgairdvipalikaḥ pṛthak śāṇamātrāṃ ca kastūrīṃ sarvamekatra nikṣipet" },
      { type: "verse", number: "89", sanskrit: "भूमौ निखातयेद्भाण्डं ततो जातरसं पिबेत् कतकस्य फलं क्षिप्त्वा रसं निर्मलतां नयेत्", text: "bhūmau nikhātayedbhāṇḍaṃ tato jātarasaṃ pibet katakasya phalaṃ kṣiptvā rasaṃ nirmalatāṃ nayet" },
      { type: "verse", number: "90", sanskrit: "ग्रहणीमरुचिं श्वासं कासं गुल्मं भगन्दरम् वातव्याधिं क्षयं छर्दिं पाण्डुरोगं च कामलाम्", text: "grahaṇīmaruciṃ śvāsaṃ kāsaṃ gulmaṃ bhagandaram vātavyādhiṃ kṣayaṃ chardiṃ pāṇḍurogaṃ ca kāmalām" },
      { type: "verse", number: "91", sanskrit: "कुष्ठान्यर्शांसि मेहांश्च मन्दाग्निमुदराणि च शर्करामश्मरीं मूत्रकृच्छ्रं धातुक्षयं जयेत्", text: "kuṣṭhānyarśāṃsi mehāṃśca mandāgnimudarāṇi ca śarkarāmaśmarīṃ mūtrakṛcchraṃ dhātukṣayaṃ jayet" },
      { type: "verse", number: "92", sanskrit: "कृशानां पुष्टिजननो वन्ध्यानां गर्भदः परः अरिष्टो दशमूलाख्यस्तेजः शुक्रबलप्रदः", text: "kṛśānāṃ puṣṭijanano vandhyānāṃ garbhadaḥ paraḥ ariṣṭo daśamūlākhyastejaḥ śukrabalapradaḥ" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 11,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Аришта санграха — Ферментированные препараты" },
      { type: "text", text: "Подробная систематика аришт — классических ферментированных отваров аюрведы. Каждая аришта имеет специфические показания, состав и технологию приготовления." },
      { type: "verse", number: "1", sanskrit: "अथ धातुशोधनमारणकल्पनानामैकादशोऽध्यायः अथ धातूनां समुदायेन शोधनमारणम् तत्रादौ धातूनां संख्या नामानि च स्वर्णतारारताम्राणि नागवङ्गौ च तीक्ष्णकम् धातवः सप्त विज्ञेयास्ततस्ताञ्छोधयेद् बुधः", text: "atha dhātuśodhanamāraṇakalpanānāmaikādaśo'dhyāyaḥ atha dhātūnāṃ samudāyena śodhanamāraṇam tatrādau dhātūnāṃ saṃkhyā nāmāni ca svarṇatārāratāmrāṇi nāgavaṅgau ca tīkṣṇakam dhātavaḥ sapta vijñeyāstatastāñchodhayed budhaḥ" },
      { type: "verse", number: "2", sanskrit: "स्वर्णतारारताम्रायः पत्राण्यग्नौ प्रतापयेत् निषिञ्चेत्तप्ततप्तानि तैले तक्रे च काञ्जिके", text: "svarṇatārāratāmrāyaḥ patrāṇyagnau pratāpayet niṣiñcettaptataptāni taile takre ca kāñjike" },
      { type: "verse", number: "3", sanskrit: "गोमूत्रे च कुलत्थानां कषाये च त्रिधा त्रिधा एवं स्वर्णादिलोहानां विशुद्धिः सम्प्रजायते", text: "gomūtre ca kulatthānāṃ kaṣāye ca tridhā tridhā evaṃ svarṇādilohānāṃ viśuddhiḥ samprajāyate" },
      { type: "verse", number: "4", sanskrit: "नागवङ्गौ प्रतप्तौ च गालितौ तौ निषेचयेत् त्रिधा त्रिधा विशुद्धिः स्याद्र विदुग्धेन च त्रिधा", text: "nāgavaṅgau prataptau ca gālitau tau niṣecayet tridhā tridhā viśuddhiḥ syādra vidugdhena ca tridhā" },
      { type: "verse", number: "5", sanskrit: "स्वर्णाच्च द्विगुणं सूतमम्लेन सह मर्दयेत् तद्गोलकसमं गन्धं निदध्यादधरोत्तरम्", text: "svarṇācca dviguṇaṃ sūtamamlena saha mardayet tadgolakasamaṃ gandhaṃ nidadhyādadharottaram" },
      { type: "verse", number: "6", sanskrit: "गोलकं च ततो रुन्ध्याच्छरावदृढसम्पुटे त्रिंशद्वनोपलैर्दद्यात्पुटान्येवं चतुर्दश निरुत्थं जायते भस्म गन्धो देयः पुनः पुनः", text: "golakaṃ ca tato rundhyāccharāvadṛḍhasampuṭe triṃśadvanopalairdadyātpuṭānyevaṃ caturdaśa nirutthaṃ jāyate bhasma gandho deyaḥ punaḥ punaḥ" },
      { type: "verse", number: "7", sanskrit: "काञ्चने गालिते नागं षोडशांशेन निक्षिपेत्", text: "kāñcane gālite nāgaṃ ṣoḍaśāṃśena nikṣipet" },
      { type: "verse", number: "8", sanskrit: "चूर्णयित्वा तथाऽम्लेन घृष्ट्वा कृत्वा च गोलकम् गोलकेन समं गन्धं दत्त्वा चैवाधरोत्तरम्", text: "cūrṇayitvā tathā'mlena ghṛṣṭvā kṛtvā ca golakam golakena samaṃ gandhaṃ dattvā caivādharottaram" },
      { type: "verse", number: "9", sanskrit: "शरावसम्पुटे धृत्वा पुटेत् त्रिंशद्वनोपलैः एवं सप्तपुटैर्हेम निरुत्थं भस्म जायते", text: "śarāvasampuṭe dhṛtvā puṭet triṃśadvanopalaiḥ evaṃ saptapuṭairhema nirutthaṃ bhasma jāyate" },
      { type: "verse", number: "10", sanskrit: "काञ्चनाररसैर्घृष्ट्वा समसूतकगन्धयोः कज्जल्या हेमपत्राणि लेपयेत्सममात्रया", text: "kāñcanārarasairghṛṣṭvā samasūtakagandhayoḥ kajjalyā hemapatrāṇi lepayetsamamātrayā" },
      { type: "verse", number: "11", sanskrit: "काञ्चनारत्वचः कल्को मूषायुग्मं प्रकल्पयेत् धृत्वा तत्संपुटे गोलं मृण्मूषासंपुटे च तत्", text: "kāñcanāratvacaḥ kalko mūṣāyugmaṃ prakalpayet dhṛtvā tatsaṃpuṭe golaṃ mṛṇmūṣāsaṃpuṭe ca tat" },
      { type: "verse", number: "12", sanskrit: "निधाय संधिरोधं च कृत्वा संशोष्य गोमयैः वह्निं खरतरं कुर्यादेवं दद्यात्पुटत्रयम् निरुत्थं जायते भस्म सर्वकार्येषु योजयेत्", text: "nidhāya saṃdhirodhaṃ ca kṛtvā saṃśoṣya gomayaiḥ vahniṃ kharataraṃ kuryādevaṃ dadyātpuṭatrayam nirutthaṃ jāyate bhasma sarvakāryeṣu yojayet" },
      { type: "verse", number: "13", sanskrit: "काञ्चनारप्रकारेण लाङ्गली हन्ति काञ्चनम् ज्वालामुखी यथा हन्यात्तथा हन्ति मनः शिला", text: "kāñcanāraprakāreṇa lāṅgalī hanti kāñcanam jvālāmukhī yathā hanyāttathā hanti manaḥ śilā" },
      { type: "verse", number: "14", sanskrit: "शिलासिन्दूरयोश्चूर्णं समयोरर्कदुग्धकैः", text: "śilāsindūrayoścūrṇaṃ samayorarkadugdhakaiḥ" },
      { type: "verse", number: "15", sanskrit: "सप्तैव भावना दद्याच्छोषयेच्च पुनः पुनः ततस्तु गालिते हेम्नि कल्कोऽय दीयते समः", text: "saptaiva bhāvanā dadyācchoṣayecca punaḥ punaḥ tatastu gālite hemni kalko'ya dīyate samaḥ" },
      { type: "verse", number: "16", sanskrit: "पुनर्धमेदतितरां यथा कल्को विलीयते एवं वेलात्रयं दद्यात्कल्कं हेममृतिर्भवेत्", text: "punardhamedatitarāṃ yathā kalko vilīyate evaṃ velātrayaṃ dadyātkalkaṃ hemamṛtirbhavet" },
      { type: "verse", number: "17", sanskrit: "पारावतमलैर्लिम्पेदथवा कुक्कुटोद्भवैः हेमपत्राणि तेषां च प्रदद्यादधरोत्तरम्", text: "pārāvatamalairlimpedathavā kukkuṭodbhavaiḥ hemapatrāṇi teṣāṃ ca pradadyādadharottaram" },
      { type: "verse", number: "18", sanskrit: "गन्धचूर्णं समं दत्त्वा शरावयुगसम्पुटे प्रदद्यात्कुक्कुटपुटं पञ्चभिर्गोमयोपलैः", text: "gandhacūrṇaṃ samaṃ dattvā śarāvayugasampuṭe pradadyātkukkuṭapuṭaṃ pañcabhirgomayopalaiḥ" },
      { type: "verse", number: "19", sanskrit: "एवं नवपुटान्दद्याद्दशमं च महापुटम् त्रिंशद्वनोपलैर्देयं जायते हेमभस्मकम्", text: "evaṃ navapuṭāndadyāddaśamaṃ ca mahāpuṭam triṃśadvanopalairdeyaṃ jāyate hemabhasmakam" },
      { type: "verse", number: "20", sanskrit: "सुवर्णं च भवेत्स्वादु तिक्तं स्निग्धं हिमं गुरु बुद्धिविद्यास्मृतिकरं विषहारि रसायनम्", text: "suvarṇaṃ ca bhavetsvādu tiktaṃ snigdhaṃ himaṃ guru buddhividyāsmṛtikaraṃ viṣahāri rasāyanam" },
      { type: "verse", number: "21", sanskrit: "भागैकं तालकं मर्द्यं जम्भेनाम्लेन केनचित् तेन भागत्रयं तारपत्राणि परिलेपयेत्", text: "bhāgaikaṃ tālakaṃ mardyaṃ jambhenāmlena kenacit tena bhāgatrayaṃ tārapatrāṇi parilepayet" },
      { type: "verse", number: "22", sanskrit: "धृत्वा मूषापुटे रुद्ध्वा पुटेत्त्रिंशद्वनोपलैः समुद्धृत्य पुनस्तालं दत्त्वा रुद्ध्वा पुटे पचेत् एवं चतुर्दशपुटैस्तारभस्म प्रजायते", text: "dhṛtvā mūṣāpuṭe ruddhvā puṭettriṃśadvanopalaiḥ samuddhṛtya punastālaṃ dattvā ruddhvā puṭe pacet evaṃ caturdaśapuṭaistārabhasma prajāyate" },
      { type: "verse", number: "23", sanskrit: "स्नुहीक्षीरेण सम्पिष्टं माक्षिकं तेन लेपयेत्", text: "snuhīkṣīreṇa sampiṣṭaṃ mākṣikaṃ tena lepayet" },
      { type: "verse", number: "24", sanskrit: "तालकस्य प्रकारेण तारपत्राणि बुद्धिमान् पुटेच्चतुर्दशपुटैस्तार भस्म प्रजायते", text: "tālakasya prakāreṇa tārapatrāṇi buddhimān puṭeccaturdaśapuṭaistāra bhasma prajāyate" },
      { type: "verse", number: "25", sanskrit: "अर्कक्षीरेण सम्पिष्टो गन्धकस्तेन लेपयेत् समेनारस्य पत्राणि शुद्धान्यम्लद्र वैर्मुहुः", text: "arkakṣīreṇa sampiṣṭo gandhakastena lepayet samenārasya patrāṇi śuddhānyamladra vairmuhuḥ" },
      { type: "verse", number: "26", sanskrit: "ततो मूषापुटे धृत्वा पुटेद्गजपुटेन च एवं पुटद्वयेनैव भस्मारं भवति ध्रुवम् आरवत्कांस्यमप्येवं भस्मतां याति निश्चितम्", text: "tato mūṣāpuṭe dhṛtvā puṭedgajapuṭena ca evaṃ puṭadvayenaiva bhasmāraṃ bhavati dhruvam āravatkāṃsyamapyevaṃ bhasmatāṃ yāti niścitam" },
      { type: "verse", number: "27", sanskrit: "अर्कक्षीरवदाजं स्यात्क्षीरं निर्गुण्डिका तथा ताम्ररीतिध्वनिवधे समगन्धकयोगतः", text: "arkakṣīravadājaṃ syātkṣīraṃ nirguṇḍikā tathā tāmrarītidhvanivadhe samagandhakayogataḥ" },
      { type: "verse", number: "28", sanskrit: "सूक्ष्माणि ताम्रपत्राणि कृत्वा संस्वेदयेद् बुधः वासरत्रयमम्लेन ततः खल्वे विनिक्षिपेत्", text: "sūkṣmāṇi tāmrapatrāṇi kṛtvā saṃsvedayed budhaḥ vāsaratrayamamlena tataḥ khalve vinikṣipet" },
      { type: "verse", number: "29", sanskrit: "पादांशं सूतकं दत्त्वा याममम्लेन मर्दयेत् तत उद्धृत्य पत्राणि लेपयेद् द्विगुणेन च", text: "pādāṃśaṃ sūtakaṃ dattvā yāmamamlena mardayet tata uddhṛtya patrāṇi lepayed dviguṇena ca" },
      { type: "verse", number: "30", sanskrit: "गन्धकेनाम्लघृष्टेन तस्य कुर्याच्च गोलकम् ततः पिष्ट्वा च मीनाक्षीं चाङ्गेरीं वा पुनर्नवाम्", text: "gandhakenāmlaghṛṣṭena tasya kuryācca golakam tataḥ piṣṭvā ca mīnākṣīṃ cāṅgerīṃ vā punarnavām" },
      { type: "verse", number: "31", sanskrit: "तत्कल्केन बहिर्गोलं लेपयेदङ्गुलोन्मितम् धृत्वा तद्गोलकं भाण्डे शरावेण च रोधयेत्", text: "tatkalkena bahirgolaṃ lepayedaṅgulonmitam dhṛtvā tadgolakaṃ bhāṇḍe śarāveṇa ca rodhayet" },
      { type: "verse", number: "32", sanskrit: "वालुकाभिः प्रपूर्याथ विभूतिलवणांबुभिः दत्त्वा भांडमुखे मुद्रा ं! ततश्चुल्यां विपाचयेत्", text: "vālukābhiḥ prapūryātha vibhūtilavaṇāṃbubhiḥ dattvā bhāṃḍamukhe mudrā ṃ! tataśculyāṃ vipācayet" },
      { type: "verse", number: "33", sanskrit: "क्रमवृद्धाग्निना सम्यग्यावद्याम चतुष्टयम् स्वाङ्गशीतलमुद्धृत्य मर्दयेत्सूरणद्र वैः", text: "kramavṛddhāgninā samyagyāvadyāma catuṣṭayam svāṅgaśītalamuddhṛtya mardayetsūraṇadra vaiḥ" },
      { type: "verse", number: "34", sanskrit: "दिनैकं गोलकं कुर्यादर्द्धगन्धेन लेपयेत् सघृतेन ततो मूषां पुटे गजपुटे पचेत्", text: "dinaikaṃ golakaṃ kuryādarddhagandhena lepayet saghṛtena tato mūṣāṃ puṭe gajapuṭe pacet" },
      { type: "verse", number: "35", sanskrit: "स्वाङ्गशीतं समुद्धृत्य मृतं ताम्रं शुभं भवेत् वांतिं भ्रांतिं क्लमं मूर्च्छां न करोति कदाचन", text: "svāṅgaśītaṃ samuddhṛtya mṛtaṃ tāmraṃ śubhaṃ bhavet vāṃtiṃ bhrāṃtiṃ klamaṃ mūrcchāṃ na karoti kadācana" },
      { type: "verse", number: "36", sanskrit: "ताम्बूलीरससम्पिष्टशिलालेपात्पुनः पुनः द्वात्रिंशद्भिः पुटैर्नागो निरुत्थो याति भस्मताम्", text: "tāmbūlīrasasampiṣṭaśilālepātpunaḥ punaḥ dvātriṃśadbhiḥ puṭairnāgo niruttho yāti bhasmatām" },
      { type: "verse", number: "37", sanskrit: "अश्वत्थचिञ्चात्वक्चूर्णं चतुर्थांशेन निक्षिपेत् मृत्पात्रे द्रा विते नागे लोहदर्व्या प्रचालयेत्", text: "aśvatthaciñcātvakcūrṇaṃ caturthāṃśena nikṣipet mṛtpātre drā vite nāge lohadarvyā pracālayet" },
      { type: "verse", number: "38", sanskrit: "यामैकेन भवेद्भस्म तत्तुल्यां च मनःशिलाम् काञ्जिकेन द्वयं पिष्ट्वा पचेद् दृढपुटेन च", text: "yāmaikena bhavedbhasma tattulyāṃ ca manaḥśilām kāñjikena dvayaṃ piṣṭvā paced dṛḍhapuṭena ca" },
      { type: "verse", number: "39", sanskrit: "स्वाङ्गशीतं पुनः पिष्ट्वा शिलया काञ्जिकेन च पुनः पुटेच्छरावाभ्यामेवं षष्टिपुटैर्मृतिः", text: "svāṅgaśītaṃ punaḥ piṣṭvā śilayā kāñjikena ca punaḥ puṭeccharāvābhyāmevaṃ ṣaṣṭipuṭairmṛtiḥ" },
      { type: "verse", number: "40", sanskrit: "मृत्पात्रे द्रा विते वङ्गे चिञ्चाऽश्वत्थत्वचो रजः", text: "mṛtpātre drā vite vaṅge ciñcā'śvatthatvaco rajaḥ" },
      { type: "verse", number: "41", sanskrit: "क्षिप्त्वा तेन चतुर्थांशमयोदर्व्या प्रचालयेत् ततो द्वियाममात्रेण वङ्गभस्म प्रजायते", text: "kṣiptvā tena caturthāṃśamayodarvyā pracālayet tato dviyāmamātreṇa vaṅgabhasma prajāyate" },
      { type: "verse", number: "42", sanskrit: "अथ भस्मसमं तालं क्षिप्त्वाऽम्लेन प्रमर्दयेत् ततो गजपुटे पक्त्वा पुनरम्लेन मर्दयेत्", text: "atha bhasmasamaṃ tālaṃ kṣiptvā'mlena pramardayet tato gajapuṭe paktvā punaramlena mardayet" },
      { type: "verse", number: "43", sanskrit: "तालेन दशमांशेन याममेकं ततः पुटेत् एवं दशपुटैः पक्वो वङ्गस्तु म्रियते ध्रुवम्", text: "tālena daśamāṃśena yāmamekaṃ tataḥ puṭet evaṃ daśapuṭaiḥ pakvo vaṅgastu mriyate dhruvam" },
      { type: "verse", number: "44", sanskrit: "शुद्धं लोहभवं चूर्णं पातालगरुडीरसैः मर्दयित्वा पुटेद्वह्नौ दद्यादेवं पुटत्रयम्", text: "śuddhaṃ lohabhavaṃ cūrṇaṃ pātālagaruḍīrasaiḥ mardayitvā puṭedvahnau dadyādevaṃ puṭatrayam" },
      { type: "verse", number: "45", sanskrit: "पुटत्रयं कुमार्या च कुठारच्छिन्निकारसैः पुटषट्कं ततो दद्यादेवं तीक्ष्णमृतिर्भवेत्", text: "puṭatrayaṃ kumāryā ca kuṭhāracchinnikārasaiḥ puṭaṣaṭkaṃ tato dadyādevaṃ tīkṣṇamṛtirbhavet" },
      { type: "verse", number: "46", sanskrit: "क्षिपेत्तु द्वादशांशेन दरदं तीक्ष्णचूर्णतः मर्दयेत्कन्यकाद्रा वैर्यामयुग्मं ततः पुटेत्", text: "kṣipettu dvādaśāṃśena daradaṃ tīkṣṇacūrṇataḥ mardayetkanyakādrā vairyāmayugmaṃ tataḥ puṭet" },
      { type: "verse", number: "47", sanskrit: "एवं सप्तपुटैर्मृत्युं लोहचूर्णमवाप्नुयात् रसैः कुठारच्छिन्नायाः पातालगरुडीरसैः स्तन्येन चार्कदुग्धेन तीक्ष्णस्यैवं मृतिर्भवेत्", text: "evaṃ saptapuṭairmṛtyuṃ lohacūrṇamavāpnuyāt rasaiḥ kuṭhāracchinnāyāḥ pātālagaruḍīrasaiḥ stanyena cārkadugdhena tīkṣṇasyaivaṃ mṛtirbhavet" },
      { type: "verse", number: "48", sanskrit: "सूतकाद् द्विगुणं गन्धं दत्वा कुर्याच्च कज्जलीम् द्वयोः समं लोहचूर्णं मर्दयेत्कन्यकाद्र वैः", text: "sūtakād dviguṇaṃ gandhaṃ datvā kuryācca kajjalīm dvayoḥ samaṃ lohacūrṇaṃ mardayetkanyakādra vaiḥ" },
      { type: "verse", number: "49", sanskrit: "यामयुग्मं ततः पिण्डं कृत्वा ताम्रस्य पात्रके घर्मे धृत्वा रुबूकस्य पत्रैराच्छादयेद् बुधः", text: "yāmayugmaṃ tataḥ piṇḍaṃ kṛtvā tāmrasya pātrake gharme dhṛtvā rubūkasya patrairācchādayed budhaḥ" },
      { type: "verse", number: "50", sanskrit: "यामार्द्धेनोष्णतां यायाद्धान्यराशौ न्यसेत्ततः दत्त्वोपरि शरावं तु त्रिदिनान्ते समुद्धरेत्", text: "yāmārddhenoṣṇatāṃ yāyāddhānyarāśau nyasettataḥ dattvopari śarāvaṃ tu tridinānte samuddharet" },
      { type: "verse", number: "51", sanskrit: "पिष्ट्वा च गालयेद्वस्त्रादेवं वारितरं भवेत् एवं सर्वाणि लोहानि स्वर्णादीन्यपि मारयेत्", text: "piṣṭvā ca gālayedvastrādevaṃ vāritaraṃ bhavet evaṃ sarvāṇi lohāni svarṇādīnyapi mārayet" },
      { type: "verse", number: "52", sanskrit: "सर्वधातूनां मारणे सामान्यविधिः शिलागन्धार्कदुग्धाक्ताः स्वर्णाद्याः सर्वधातवः म्रियन्ते द्वादशपुटैः सत्यं गुरुवचो यथा", text: "sarvadhātūnāṃ māraṇe sāmānyavidhiḥ śilāgandhārkadugdhāktāḥ svarṇādyāḥ sarvadhātavaḥ mriyante dvādaśapuṭaiḥ satyaṃ guruvaco yathā" },
      { type: "verse", number: "53", sanskrit: "अथोपधातूनां शोधनमारणप्रकाराः उपधातूनां गणना माक्षिकं तुत्थकाभ्रौ च नीलाञ्जनशिलालकाः रसकञ्चेति विज्ञेया एते सप्तोपधातवः", text: "athopadhātūnāṃ śodhanamāraṇaprakārāḥ upadhātūnāṃ gaṇanā mākṣikaṃ tutthakābhrau ca nīlāñjanaśilālakāḥ rasakañceti vijñeyā ete saptopadhātavaḥ" },
      { type: "verse", number: "54", sanskrit: "माक्षिकस्य त्रयो भागा भागैकं सैन्धवस्य च मातुलुङ्गद्र वैर्वाऽथ जम्बीरोत्थद्र वैः पचेत्", text: "mākṣikasya trayo bhāgā bhāgaikaṃ saindhavasya ca mātuluṅgadra vairvā'tha jambīrotthadra vaiḥ pacet" },
      { type: "verse", number: "55", sanskrit: "चालयेल्लोहजे पात्रे यावत्पात्रं सुलोहितम् भवेत्तप्तं तु संशुद्धिं स्वर्णमाक्षिकमृच्छति", text: "cālayellohaje pātre yāvatpātraṃ sulohitam bhavettaptaṃ tu saṃśuddhiṃ svarṇamākṣikamṛcchati" },
      { type: "verse", number: "56", sanskrit: "कुलत्थस्य कषायेण घृष्ट्वा तैलेन वा पुटेत् तक्रेण वाजमूत्रेण म्रियते स्वर्णमाक्षिकम्", text: "kulatthasya kaṣāyeṇa ghṛṣṭvā tailena vā puṭet takreṇa vājamūtreṇa mriyate svarṇamākṣikam" },
      { type: "verse", number: "57", sanskrit: "कर्कोटीमेषशृङ्ग्युत्थैर्द्र वैर्जम्बीरजैर्दिनम् भावयेदातपे तीव्रे विमला शुद्ध्य्ति ध्रुवम्", text: "karkoṭīmeṣaśṛṅgyutthairdra vairjambīrajairdinam bhāvayedātape tīvre vimalā śuddhyti dhruvam" },
      { type: "verse", number: "58", sanskrit: "विष्ठया मर्दयेत् तुत्थं मार्जारककपोतयोः", text: "viṣṭhayā mardayet tutthaṃ mārjārakakapotayoḥ" },
      { type: "verse", number: "59", sanskrit: "दशांशं टङ्कणं दत्त्वा पचेन्मृदुपुटे ततः पुटं दध्ना तथा क्षौद्रै र्देयं तुत्थविशुद्धये", text: "daśāṃśaṃ ṭaṅkaṇaṃ dattvā pacenmṛdupuṭe tataḥ puṭaṃ dadhnā tathā kṣaudrai rdeyaṃ tutthaviśuddhaye" },
      { type: "verse", number: "60", sanskrit: "कृष्णाभ्रकं धमेद्वह्नौ ततः क्षीरे विनिक्षिपेत् भिन्नपत्रं तु तत्कृत्वा तण्डुलीयाम्लयोर्द्र वैः भावयेदष्टयामं तदेवं शुद्ध्य्ति चाभ्रकम्", text: "kṛṣṇābhrakaṃ dhamedvahnau tataḥ kṣīre vinikṣipet bhinnapatraṃ tu tatkṛtvā taṇḍulīyāmlayordra vaiḥ bhāvayedaṣṭayāmaṃ tadevaṃ śuddhyti cābhrakam" },
      { type: "verse", number: "61", sanskrit: "कृत्वा धान्याभ्रकं तत्तु शोषयित्थाऽथ मर्दयेत् अर्कक्षीरैर्दिनं खल्वे चक्राकारं च कारयेत्", text: "kṛtvā dhānyābhrakaṃ tattu śoṣayitthā'tha mardayet arkakṣīrairdinaṃ khalve cakrākāraṃ ca kārayet" },
      { type: "verse", number: "62", sanskrit: "वेष्टयेदर्कपत्रैश्च सम्यग्गजपुटे पचेत् पुनर्मर्द्यं पुनः पाच्यं सप्तवारं प्रयत्नतः", text: "veṣṭayedarkapatraiśca samyaggajapuṭe pacet punarmardyaṃ punaḥ pācyaṃ saptavāraṃ prayatnataḥ" },
      { type: "verse", number: "63", sanskrit: "ततो वटजटाक्वाथैस्तद्वद्देयं पुटत्रयम् म्रियते नात्र संदेहः सर्वयोगेषु योजयेत्", text: "tato vaṭajaṭākvāthaistadvaddeyaṃ puṭatrayam mriyate nātra saṃdehaḥ sarvayogeṣu yojayet" },
      { type: "verse", number: "64", sanskrit: "तुल्यं घृतं मृताभ्रेण लोहपात्रे विपाचयेत् घृते जीर्णे तदभ्रं तु सर्वयोगेषु योजयेत्", text: "tulyaṃ ghṛtaṃ mṛtābhreṇa lohapātre vipācayet ghṛte jīrṇe tadabhraṃ tu sarvayogeṣu yojayet" },
      { type: "verse", number: "65", sanskrit: "मृतं त्वभ्रं हरेन्मृत्युं जरापलितनाशनम् अनुपानैश्च संयुक्तं तत्तद्रो गहरं परम्", text: "mṛtaṃ tvabhraṃ harenmṛtyuṃ jarāpalitanāśanam anupānaiśca saṃyuktaṃ tattadro gaharaṃ param" },
      { type: "verse", number: "66", sanskrit: "शुद्धं धान्याभ्रकं मुस्तशुण्ठीषड्भागयोजितम् मर्दयेत्काञ्जिकेनैव दिनं चित्रकजै रसैः", text: "śuddhaṃ dhānyābhrakaṃ mustaśuṇṭhīṣaḍbhāgayojitam mardayetkāñjikenaiva dinaṃ citrakajai rasaiḥ" },
      { type: "verse", number: "67", sanskrit: "ततो गजपुटं दद्यात्तस्मादुद्धृत्य मर्दयेत् त्रिफलावारिणा तद्वत्पुटेदेवं पुटैस्त्रिभिः", text: "tato gajapuṭaṃ dadyāttasmāduddhṛtya mardayet triphalāvāriṇā tadvatpuṭedevaṃ puṭaistribhiḥ" },
      { type: "verse", number: "68", sanskrit: "वलागोमूत्रमुसलीतुलसीसूरणद्र वैः मर्दितं पुटितं वह्नौ त्रित्रिवेलं व्रजेन्मृतिम्", text: "valāgomūtramusalītulasīsūraṇadra vaiḥ marditaṃ puṭitaṃ vahnau tritrivelaṃ vrajenmṛtim" },
      { type: "verse", number: "69", sanskrit: "धान्याभ्रकस्य भागैकं द्वौ भागौ टङ्कणस्य च", text: "dhānyābhrakasya bhāgaikaṃ dvau bhāgau ṭaṅkaṇasya ca" },
      { type: "verse", number: "70", sanskrit: "पिष्ट्वा तदन्धमूषायां रुद्ध्वा तीव्राग्निना पचेत् स्वभावं शीतलं चूर्णं सर्वरोगेषु योजयेत्", text: "piṣṭvā tadandhamūṣāyāṃ ruddhvā tīvrāgninā pacet svabhāvaṃ śītalaṃ cūrṇaṃ sarvarogeṣu yojayet" },
      { type: "verse", number: "71", sanskrit: "नीलाञ्जनं चूर्णयित्वा जम्बीरद्र वभावितम् दिनैकमातपे शुद्धं भवेत्कार्येषु योजयेत्", text: "nīlāñjanaṃ cūrṇayitvā jambīradra vabhāvitam dinaikamātape śuddhaṃ bhavetkāryeṣu yojayet" },
      { type: "verse", number: "72", sanskrit: "एवं गैरिककासीसटङ्कणानि वराटिका तौरी शङ्खं च कङ्कुष्ठं शुद्धिमायाति निश्चितम्", text: "evaṃ gairikakāsīsaṭaṅkaṇāni varāṭikā taurī śaṅkhaṃ ca kaṅkuṣṭhaṃ śuddhimāyāti niścitam" },
      { type: "verse", number: "73", sanskrit: "पचेत्त्र्यहमजामूत्रैर्दोलायन्त्रे मनः शिलाम् भावयेत्सप्तधा पित्तैरजायाः शुद्धिमृच्छति", text: "pacettryahamajāmūtrairdolāyantre manaḥ śilām bhāvayetsaptadhā pittairajāyāḥ śuddhimṛcchati" },
      { type: "verse", number: "74", sanskrit: "तालकं कणशः कृत्वा तच्चूर्णं काञ्जिके क्षिपेत् दोलायन्त्रेण यामैकं ततः कूष्माण्डजैर्द्र वैः", text: "tālakaṃ kaṇaśaḥ kṛtvā taccūrṇaṃ kāñjike kṣipet dolāyantreṇa yāmaikaṃ tataḥ kūṣmāṇḍajairdra vaiḥ" },
      { type: "verse", number: "75", sanskrit: "तिलतैले पचेद्यामं यामं च त्रिफलाजलैः एवं यन्त्रे चतुर्यामं पाच्यं शुद्ध्य्ति तालकम्", text: "tilataile pacedyāmaṃ yāmaṃ ca triphalājalaiḥ evaṃ yantre caturyāmaṃ pācyaṃ śuddhyti tālakam" },
      { type: "verse", number: "76", sanskrit: "नृमूत्रेवाऽथ गोमूत्रे सप्ताहं रसकं पचेत् दोलायन्त्रेण शुद्धिः स्यात्ततः कार्येषु योजयेत्", text: "nṛmūtrevā'tha gomūtre saptāhaṃ rasakaṃ pacet dolāyantreṇa śuddhiḥ syāttataḥ kāryeṣu yojayet" },
      { type: "verse", number: "77", sanskrit: "लाक्षामीनपयश्छागं टङ्कणं मृगशृङ्गकम् पिण्याकं सर्षपाः शिग्रुर्गुञ्जोर्णागुडसैन्धवाः यवतिक्ता घृतं क्षौद्रं  यथालाभं विचूर्णयेत्", text: "lākṣāmīnapayaśchāgaṃ ṭaṅkaṇaṃ mṛgaśṛṅgakam piṇyākaṃ sarṣapāḥ śigrurguñjorṇāguḍasaindhavāḥ yavatiktā ghṛtaṃ kṣaudraṃ  yathālābhaṃ vicūrṇayet" },
      { type: "verse", number: "78", sanskrit: "एभिर्विमिश्रिताः सर्वे धातवो गाढवह्निना मूषाध्माताः प्रजायन्ते मुक्तसत्त्वा न संशयः", text: "ebhirvimiśritāḥ sarve dhātavo gāḍhavahninā mūṣādhmātāḥ prajāyante muktasattvā na saṃśayaḥ" },
      { type: "verse", number: "79", sanskrit: "अथ रत्नानां शोधनमारणप्रकाराः तत्रादौ वज्रशोधनविधिः कुलत्थकोद्र वक्वाथैर्दोलायन्त्रे विपाचयेत् व्याघ्रीकन्दगतं वज्रं त्रिदिनं शुद्धिमृच्छति", text: "atha ratnānāṃ śodhanamāraṇaprakārāḥ tatrādau vajraśodhanavidhiḥ kulatthakodra vakvāthairdolāyantre vipācayet vyāghrīkandagataṃ vajraṃ tridinaṃ śuddhimṛcchati" },
      { type: "verse", number: "80", sanskrit: "तप्तं तप्तं तु तद्वज्रं खरमूत्रैर्निषेचयेत् पुनस्तप्यं पुनः सेच्यमेवं कुर्यात्त्रिसप्तधा", text: "taptaṃ taptaṃ tu tadvajraṃ kharamūtrairniṣecayet punastapyaṃ punaḥ secyamevaṃ kuryāttrisaptadhā" },
      { type: "verse", number: "81", sanskrit: "मत्कुणैस्तालकं पिष्ट्वा यावद्भवति गोलकम् तद्गोले निहितं वज्रं तद्गोलं वह्निना धमेत्", text: "matkuṇaistālakaṃ piṣṭvā yāvadbhavati golakam tadgole nihitaṃ vajraṃ tadgolaṃ vahninā dhamet" },
      { type: "verse", number: "82", sanskrit: "सिञ्चयेदश्वमूत्रेण तद्गोले च क्षिपेत्पुनः रुद्ध्वा ध्मातं पुनः सेच्यमेवं कुर्यात्त्रिसप्तधा", text: "siñcayedaśvamūtreṇa tadgole ca kṣipetpunaḥ ruddhvā dhmātaṃ punaḥ secyamevaṃ kuryāttrisaptadhā" },
      { type: "verse", number: "83", sanskrit: "एवं च म्रियते वज्रं चूर्णं सर्वत्र योजयेत्", text: "evaṃ ca mriyate vajraṃ cūrṇaṃ sarvatra yojayet" },
      { type: "verse", number: "84", sanskrit: "हिङ्गुसैन्धवसंयुक्ते क्वाथे कौलत्थजे क्षिपेत् तप्तं तप्तं पुनर्वज्रं भूयाच्चूर्णं त्रिसप्तधा", text: "hiṅgusaindhavasaṃyukte kvāthe kaulatthaje kṣipet taptaṃ taptaṃ punarvajraṃ bhūyāccūrṇaṃ trisaptadhā" },
      { type: "verse", number: "85", sanskrit: "मण्डूकं कांस्यजे पात्रे निगृह्य स्थापयेत्सुधीः स भीतो मूत्रयेत्तत्र तन्मूत्रे वज्रमावपेत् तप्तं तप्तं च बहुधा वज्रस्यैवं मृतिर्भवेत्", text: "maṇḍūkaṃ kāṃsyaje pātre nigṛhya sthāpayetsudhīḥ sa bhīto mūtrayettatra tanmūtre vajramāvapet taptaṃ taptaṃ ca bahudhā vajrasyaivaṃ mṛtirbhavet" },
      { type: "verse", number: "86", sanskrit: "वैक्रान्तस्य संशोधनमारणविधिः वैक्रान्तं वज्रवच्छोद्ध्यं नीलं वा लोहितं तथा हयमूत्रेण तत्सेच्यं तप्तं तप्तं द्विसप्तधा", text: "vaikrāntasya saṃśodhanamāraṇavidhiḥ vaikrāntaṃ vajravacchoddhyaṃ nīlaṃ vā lohitaṃ tathā hayamūtreṇa tatsecyaṃ taptaṃ taptaṃ dvisaptadhā" },
      { type: "verse", number: "87", sanskrit: "ततस्तु मेषशृङ्ग्युक्तपञ्चाङ्गे गोलके क्षिपेत् पुटेन्मूषापुटे रुद्ध्वा कुर्यादेवं च सप्तधा", text: "tatastu meṣaśṛṅgyuktapañcāṅge golake kṣipet puṭenmūṣāpuṭe ruddhvā kuryādevaṃ ca saptadhā" },
      { type: "verse", number: "88", sanskrit: "वैक्रान्तं भस्मतां याति वज्रस्थाने नियोजयेत्", text: "vaikrāntaṃ bhasmatāṃ yāti vajrasthāne niyojayet" },
      { type: "verse", number: "89", sanskrit: "स्वेदयेद्दोलिकायन्त्रे जयन्त्याः स्वरसेन च मणिमुक्ताप्रवालानां यामकं शोधनं भवेत्", text: "svedayeddolikāyantre jayantyāḥ svarasena ca maṇimuktāpravālānāṃ yāmakaṃ śodhanaṃ bhavet" },
      { type: "verse", number: "90", sanskrit: "कुमार्यास्तण्डुलीयेन स्तन्येन च निषेचयेत् प्रत्येकं सप्तवेलं च तप्ततप्तानि कृत्स्नशः", text: "kumāryāstaṇḍulīyena stanyena ca niṣecayet pratyekaṃ saptavelaṃ ca taptataptāni kṛtsnaśaḥ" },
      { type: "verse", number: "91", sanskrit: "मौक्तिकानि प्रवालानि तथा रत्नान्यशेषतः क्षणाद्विविधवर्णानि म्रियन्ते नात्र संशयः", text: "mauktikāni pravālāni tathā ratnānyaśeṣataḥ kṣaṇādvividhavarṇāni mriyante nātra saṃśayaḥ" },
      { type: "verse", number: "92", sanskrit: "उक्तमाक्षिकवन्मुक्ताः प्रवालानि च मारयेत् वज्रवत्सर्वरत्नानि शोधयेन्मारयेत्तथा", text: "uktamākṣikavanmuktāḥ pravālāni ca mārayet vajravatsarvaratnāni śodhayenmārayettathā" },
      { type: "verse", number: "93", sanskrit: "शिलाजतु समानीय ग्रीष्मतप्तशिलाच्युतम् गोदुग्धैस्त्रिफलाक्वाथैर्भृङ्गद्रा वैश्च मर्दयेत् आतपे दिनमेकैकं तच्छुष्कं शुद्धतां व्रजेत्", text: "śilājatu samānīya grīṣmataptaśilācyutam godugdhaistriphalākvāthairbhṛṅgadrā vaiśca mardayet ātape dinamekaikaṃ tacchuṣkaṃ śuddhatāṃ vrajet" },
      { type: "verse", number: "94", sanskrit: "मुख्यां शिलाजतुशिलां सूक्ष्मखण्डप्रकल्पिताम् निक्षिप्यात्युष्णपानीये यामैकं स्थापयेत्सुधीः", text: "mukhyāṃ śilājatuśilāṃ sūkṣmakhaṇḍaprakalpitām nikṣipyātyuṣṇapānīye yāmaikaṃ sthāpayetsudhīḥ" },
      { type: "verse", number: "95", sanskrit: "मर्दयित्वा ततो नीरं गृह्णीयाद्वस्त्रगालितम् स्थापयित्वा च मृत्पात्रे धारयेदातपे बुधः", text: "mardayitvā tato nīraṃ gṛhṇīyādvastragālitam sthāpayitvā ca mṛtpātre dhārayedātape budhaḥ" },
      { type: "verse", number: "96", sanskrit: "उपरिस्थं घनं यत्स्यात्तत्क्षिपेदन्यपात्रके धारयेदातपे धीमानुपरिस्थं घनं नयेत्", text: "uparisthaṃ ghanaṃ yatsyāttatkṣipedanyapātrake dhārayedātape dhīmānuparisthaṃ ghanaṃ nayet" },
      { type: "verse", number: "97", sanskrit: "एवं पुनः पुनर्नीत्वा द्विमासाभ्यां शिलाजतु भूयात्कार्यक्षमं वह्नौ क्षिप्तं लिङ्गोपमं भवेत्", text: "evaṃ punaḥ punarnītvā dvimāsābhyāṃ śilājatu bhūyātkāryakṣamaṃ vahnau kṣiptaṃ liṅgopamaṃ bhavet" },
      { type: "verse", number: "98", sanskrit: "निर्धूमं च ततः शुद्धं सर्वकर्मसु योजयेत् अधः स्थितं च यच्छेषं तस्मिन्नीरं विनिक्षिपेत्", text: "nirdhūmaṃ ca tataḥ śuddhaṃ sarvakarmasu yojayet adhaḥ sthitaṃ ca yaccheṣaṃ tasminnīraṃ vinikṣipet" },
      { type: "verse", number: "99", sanskrit: "विमर्द्य धारयेद्घर्मे पूर्ववच्चैव तन्नयेत्", text: "vimardya dhārayedgharme pūrvavaccaiva tannayet" },
      { type: "verse", number: "100", sanskrit: "अक्षाङ्गारैर्धमेत्किट्टं लोहजं तद्गवां जलैः सेचयेत्तप्ततप्तं तत्सप्तवारं पुनः पुनः", text: "akṣāṅgārairdhametkiṭṭaṃ lohajaṃ tadgavāṃ jalaiḥ secayettaptataptaṃ tatsaptavāraṃ punaḥ punaḥ" },
      { type: "verse", number: "101", sanskrit: "चूर्णयित्वा ततः क्वाथैर्द्विगुणैस्त्रिफलाभवैः आलोड्य भर्जयेद्वह्नौ मण्डूरं जायते वरम्", text: "cūrṇayitvā tataḥ kvāthairdviguṇaistriphalābhavaiḥ āloḍya bharjayedvahnau maṇḍūraṃ jāyate varam" },
      { type: "verse", number: "102", sanskrit: "क्षीरवृक्षस्य काष्ठानि शुष्काण्यग्नौ प्रदीपयेत् नीत्वा तद्भस्म मृत्पात्रे क्षिप्त्वा नीरे चतुर्गुणे विमर्द्य धारयेद्रा त्रौ प्रातरच्छं जलं नयेत्", text: "kṣīravṛkṣasya kāṣṭhāni śuṣkāṇyagnau pradīpayet nītvā tadbhasma mṛtpātre kṣiptvā nīre caturguṇe vimardya dhārayedrā trau prātaracchaṃ jalaṃ nayet" },
      { type: "verse", number: "103", sanskrit: "तन्नीरं क्वाथयेद्वह्नौ यावत्सर्वं विशुष्यति ततः पात्रात्समुल्लिख्य क्षारो ग्राह्यः सितप्रभः", text: "tannīraṃ kvāthayedvahnau yāvatsarvaṃ viśuṣyati tataḥ pātrātsamullikhya kṣāro grāhyaḥ sitaprabhaḥ" },
      { type: "verse", number: "104", sanskrit: "चूर्णाभः प्रतिसार्यः स्यात्पेयः स्यात्क्वाथवत्स्थितः इति क्षारद्वयं धीमानुक्तकार्येषु योजयेत्", text: "cūrṇābhaḥ pratisāryaḥ syātpeyaḥ syātkvāthavatsthitaḥ iti kṣāradvayaṃ dhīmānuktakāryeṣu yojayet" },
    ],
  },
  {
    sthana: "Мадхьямакханда",
    number: 12,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Раса кальпа санграха — Ртутные препараты" },
      { type: "text", text: "Введение в расашастру — алхимическую медицину с применением ртути и минералов. Правильное очищение (шуддхи) ртути обязательно перед применением." },
      { type: "verse", number: "1", sanskrit: "अथ रसादिशोधनमारणकल्पनानाम द्वादशोऽध्यायः तत्रादौ रसप्रशंसा पारदः सर्वरोगाणां जेता पुष्टिकरः स्मृतः सुज्ञेन साधितः कुर्यात्संसिद्धिं देहलोहयोः", text: "atha rasādiśodhanamāraṇakalpanānāma dvādaśo'dhyāyaḥ tatrādau rasapraśaṃsā pāradaḥ sarvarogāṇāṃ jetā puṣṭikaraḥ smṛtaḥ sujñena sādhitaḥ kuryātsaṃsiddhiṃ dehalohayoḥ" },
      { type: "verse", number: "2", sanskrit: "रसेन्द्र ः! पारदः सूतो हरजः सूतको रसः मिश्रकश्चेति नामानि ज्ञेयानि रसकर्मसु", text: "rasendra ḥ! pāradaḥ sūto harajaḥ sūtako rasaḥ miśrakaśceti nāmāni jñeyāni rasakarmasu" },
      { type: "verse", number: "3", sanskrit: "ताम्रादिधातूनां सूर्यादीनामधिष्ठाननिर्देशः ताम्रतारारनागाश्च हेमवङ्गौ च तीक्ष्णकम् कांस्यकं कान्तलोहं च धातवो नव ये स्मृताः सूर्यादीनां ग्रहाणां ते कथिता नामभिः क्रमात्", text: "tāmrādidhātūnāṃ sūryādīnāmadhiṣṭhānanirdeśaḥ tāmratārāranāgāśca hemavaṅgau ca tīkṣṇakam kāṃsyakaṃ kāntalohaṃ ca dhātavo nava ye smṛtāḥ sūryādīnāṃ grahāṇāṃ te kathitā nāmabhiḥ kramāt" },
      { type: "verse", number: "4", sanskrit: "राजीरसोनमूषायां रसं क्षिप्त्वा विबन्धयेत् वस्त्रेण दोलिकायन्त्रे स्वेदयेत्काञ्जिकैस्त्र्! यहम्", text: "rājīrasonamūṣāyāṃ rasaṃ kṣiptvā vibandhayet vastreṇa dolikāyantre svedayetkāñjikaistr! yaham" },
      { type: "verse", number: "5", sanskrit: "दिनैकं मर्दयेत्सूतं कुमारीसम्भवैर्द्र वैः तथा चित्रकजैः क्वाथैर्मर्दयेदेकवासरम्", text: "dinaikaṃ mardayetsūtaṃ kumārīsambhavairdra vaiḥ tathā citrakajaiḥ kvāthairmardayedekavāsaram" },
      { type: "verse", number: "6", sanskrit: "काकमाचीरसैस्तद्वद् दिनमेकं च मर्दयेत् त्रिफलायास्तथा क्वाथै रसो मर्द्यः प्रयत्नतः", text: "kākamācīrasaistadvad dinamekaṃ ca mardayet triphalāyāstathā kvāthai raso mardyaḥ prayatnataḥ" },
      { type: "verse", number: "7", sanskrit: "ततस्तेभ्यः पृथक्कुर्यात्सूतं प्रक्षाल्य काञ्जिकैः ततः क्षिप्त्वा रसं खल्वे रसादर्द्धं च सैन्धवम्", text: "tatastebhyaḥ pṛthakkuryātsūtaṃ prakṣālya kāñjikaiḥ tataḥ kṣiptvā rasaṃ khalve rasādarddhaṃ ca saindhavam" },
      { type: "verse", number: "8", sanskrit: "ततो राजी रसोनश्च मुख्यश्च नवसादरः", text: "tato rājī rasonaśca mukhyaśca navasādaraḥ" },
      { type: "verse", number: "9", sanskrit: "एतै रससमैस्तद्वत्सूतो मर्द्यस्तुषाम्बुना ततः संशोध्य चक्राभंकृत्वा लिप्त्वा च हिङ्गुना", text: "etai rasasamaistadvatsūto mardyastuṣāmbunā tataḥ saṃśodhya cakrābhaṃkṛtvā liptvā ca hiṅgunā" },
      { type: "verse", number: "10", sanskrit: "द्विस्थालीसम्पुटे धृत्वा पूरयेल्लवणेन च अधः स्थाल्यां ततो मुद्रा ं! दद्याद् दृढतरां बुधः", text: "dvisthālīsampuṭe dhṛtvā pūrayellavaṇena ca adhaḥ sthālyāṃ tato mudrā ṃ! dadyād dṛḍhatarāṃ budhaḥ" },
      { type: "verse", number: "11", sanskrit: "विशोष्याग्निं विधायाधो निषिञ्चेदम्बुनोपरि ततस्तु कुर्यात्तीव्राग्निं तदधः प्रहरत्रयम्", text: "viśoṣyāgniṃ vidhāyādho niṣiñcedambunopari tatastu kuryāttīvrāgniṃ tadadhaḥ praharatrayam" },
      { type: "verse", number: "12", sanskrit: "एवं निपातयेदूर्ध्वंरसो दोषविवर्जितः अथोर्ध्वपिठरीमध्ये लग्नो रसो रसोत्तमः", text: "evaṃ nipātayedūrdhvaṃraso doṣavivarjitaḥ athordhvapiṭharīmadhye lagno raso rasottamaḥ" },
      { type: "verse", number: "13", sanskrit: "लोहपात्रे विनिक्षिप्य घृतमग्नौ प्रतापयेत् तप्ते घृते तत्समानं क्षिपेद्गन्धकजं रजः", text: "lohapātre vinikṣipya ghṛtamagnau pratāpayet tapte ghṛte tatsamānaṃ kṣipedgandhakajaṃ rajaḥ" },
      { type: "verse", number: "14", sanskrit: "विद्रुतं गन्धकं ज्ञात्वा दुग्धमध्ये विनिःक्षिपेत् एवं गंधकशुद्धिः स्यात्सर्वकार्येषु योजयेत्", text: "vidrutaṃ gandhakaṃ jñātvā dugdhamadhye viniḥkṣipet evaṃ gaṃdhakaśuddhiḥ syātsarvakāryeṣu yojayet" },
      { type: "verse", number: "15", sanskrit: "मेषीक्षीरेण दरदमम्लवर्गैश्च भावितम् सप्तवारं प्रयत्नेन शुद्धिमायाति निश्चितम्", text: "meṣīkṣīreṇa daradamamlavargaiśca bhāvitam saptavāraṃ prayatnena śuddhimāyāti niścitam" },
      { type: "verse", number: "16", sanskrit: "निम्बूरसैर्निम्बपत्ररसैर्वा याममात्रकम्", text: "nimbūrasairnimbapatrarasairvā yāmamātrakam" },
      { type: "verse", number: "17", sanskrit: "पिष्ट्वा दरदमूर्ध्वं च पातयेत्सूतयुक्तिवत् ततः शुद्धरसं तस्मान्नीत्वा कार्येषु योजयेत्", text: "piṣṭvā daradamūrdhvaṃ ca pātayetsūtayuktivat tataḥ śuddharasaṃ tasmānnītvā kāryeṣu yojayet" },
      { type: "verse", number: "18", sanskrit: "कालकूटो वत्सनाभः शृङ्गकश्च प्रदीपकः हालाहलो ब्रह्मपुत्रो हारिद्र ः! सक्तुकस्तथा", text: "kālakūṭo vatsanābhaḥ śṛṅgakaśca pradīpakaḥ hālāhalo brahmaputro hāridra ḥ! saktukastathā" },
      { type: "verse", number: "19", sanskrit: "सौराष्ट्रिक इति प्रोक्ता विषभेदा अमी नव अर्कसेहुण्डधत्तूरलाङ्गलीकरवीरकम्", text: "saurāṣṭrika iti proktā viṣabhedā amī nava arkasehuṇḍadhattūralāṅgalīkaravīrakam" },
      { type: "verse", number: "20", sanskrit: "गुञ्जाऽहिफेनावित्येताः सप्तोपविषजातयः एतैर्विमर्दितः सूतश्छिन्नपक्षः प्रजायते मुखं च जायते तस्य धातूंश्च ग्रसते क्षणात्", text: "guñjā'hiphenāvityetāḥ saptopaviṣajātayaḥ etairvimarditaḥ sūtaśchinnapakṣaḥ prajāyate mukhaṃ ca jāyate tasya dhātūṃśca grasate kṣaṇāt" },
      { type: "verse", number: "21", sanskrit: "अथवा त्रिकटुक्षारौ राजी लवणपञ्चकम्", text: "athavā trikaṭukṣārau rājī lavaṇapañcakam" },
      { type: "verse", number: "22", sanskrit: "रसोनो नवसारश्च शिग्रुश्चैकत्र चूर्णितैः समांशैः पारदादेतैर्जम्बीरेण द्र वेण वा निम्बुतोयैः काञ्जिकैर्वा सोष्णखल्वे विमर्दयेत्", text: "rasono navasāraśca śigruścaikatra cūrṇitaiḥ samāṃśaiḥ pāradādetairjambīreṇa dra veṇa vā nimbutoyaiḥ kāñjikairvā soṣṇakhalve vimardayet" },
      { type: "verse", number: "23", sanskrit: "अहोरात्रत्रयेण स्याद्र से धातुचरं मुखम् तृतीयो रसमुखकरणविधिः अथवा बिन्दुलीकीटै रसो मर्द्यस्त्रिवासरम् लवणाम्लैर्मुखं तस्य जायते धातुघस्मरम्", text: "ahorātratrayeṇa syādra se dhātucaraṃ mukham tṛtīyo rasamukhakaraṇavidhiḥ athavā bindulīkīṭai raso mardyastrivāsaram lavaṇāmlairmukhaṃ tasya jāyate dhātughasmaram" },
      { type: "verse", number: "24", sanskrit: "कच्छपयन्त्रेण गन्धकजारणविधिः अथ कच्छपयन्त्रेण गन्धजारणमुच्यते मृत्कुण्डे निक्षिपेत्तोयं तन्मध्ये च शरावकम्", text: "kacchapayantreṇa gandhakajāraṇavidhiḥ atha kacchapayantreṇa gandhajāraṇamucyate mṛtkuṇḍe nikṣipettoyaṃ tanmadhye ca śarāvakam" },
      { type: "verse", number: "25", sanskrit: "महत्कुण्डपिधानाभं मध्ये मेखलया युतम् लिप्त्वा च मेखलामध्यं चूर्णेनात्र रसं क्षिपेत्", text: "mahatkuṇḍapidhānābhaṃ madhye mekhalayā yutam liptvā ca mekhalāmadhyaṃ cūrṇenātra rasaṃ kṣipet" },
      { type: "verse", number: "26", sanskrit: "रसस्योपरि गन्धस्य रजो दद्यात्समांशकम् दत्त्वोपरि शरावं च भस्ममुद्रा ं! प्रदापयेत्", text: "rasasyopari gandhasya rajo dadyātsamāṃśakam dattvopari śarāvaṃ ca bhasmamudrā ṃ! pradāpayet" },
      { type: "verse", number: "27", sanskrit: "तस्योपरि पुटं दद्याच्चतुर्भिर्गोमयोपलैः एवं पुनः पुनर्गन्धं षड्गुणं जारयेद् बुधः", text: "tasyopari puṭaṃ dadyāccaturbhirgomayopalaiḥ evaṃ punaḥ punargandhaṃ ṣaḍguṇaṃ jārayed budhaḥ" },
      { type: "verse", number: "28", sanskrit: "गन्धे जीर्णे भवेत्सूतस्तीक्ष्णाग्निः सर्वकर्मकृत्", text: "gandhe jīrṇe bhavetsūtastīkṣṇāgniḥ sarvakarmakṛt" },
      { type: "verse", number: "29", sanskrit: "धूमसारं रसं तोरीं गन्धकं नवसादरम्", text: "dhūmasāraṃ rasaṃ torīṃ gandhakaṃ navasādaram" },
      { type: "verse", number: "30", sanskrit: "यामैकं मर्दयेदम्लैर्भागं कृत्वा समांशकम् काचकूप्यां विनिक्षिप्य तां च मृद्वस्त्रमुद्र या", text: "yāmaikaṃ mardayedamlairbhāgaṃ kṛtvā samāṃśakam kācakūpyāṃ vinikṣipya tāṃ ca mṛdvastramudra yā" },
      { type: "verse", number: "31", sanskrit: "विलिप्य परितो वक्त्रे मुद्रा ं! दत्त्वा च शोषयेत् अधः सच्छिद्र पिठरीमध्ये कूपीं निवेशयेत्", text: "vilipya parito vaktre mudrā ṃ! dattvā ca śoṣayet adhaḥ sacchidra piṭharīmadhye kūpīṃ niveśayet" },
      { type: "verse", number: "32", sanskrit: "पिठरीं वालुकापूरैर्भृत्वा चाकूपिकागलम् निवेश्य चुल्ल्यां तदधः कुर्याद्वह्निं शनैः शनैः", text: "piṭharīṃ vālukāpūrairbhṛtvā cākūpikāgalam niveśya cullyāṃ tadadhaḥ kuryādvahniṃ śanaiḥ śanaiḥ" },
      { type: "verse", number: "33", sanskrit: "तस्मादप्यधिकं किञ्चित्पावकं ज्वालयेत्क्रमात् एवं द्वादशभिर्यामैर्म्रियते सूतकोत्तमः", text: "tasmādapyadhikaṃ kiñcitpāvakaṃ jvālayetkramāt evaṃ dvādaśabhiryāmairmriyate sūtakottamaḥ" },
      { type: "verse", number: "34", sanskrit: "स्फोटयेत्स्वाङ्गशीतं तमूर्ध्वगं गन्धकं त्यजेत् अधः स्थं मृतसूतं च सर्वकर्मसु योजयेत्", text: "sphoṭayetsvāṅgaśītaṃ tamūrdhvagaṃ gandhakaṃ tyajet adhaḥ sthaṃ mṛtasūtaṃ ca sarvakarmasu yojayet" },
      { type: "verse", number: "35", sanskrit: "अपामार्गस्य बीजानां मूषायुग्मं प्रकल्पयेत् तत्सम्पुटे न्यसेत्सूतं मलयूदुग्धमिश्रितम्", text: "apāmārgasya bījānāṃ mūṣāyugmaṃ prakalpayet tatsampuṭe nyasetsūtaṃ malayūdugdhamiśritam" },
      { type: "verse", number: "36", sanskrit: "द्रो णपुष्पीप्रसूनानि विडङ्गमिरिमेदकः एतच्चूर्णमधोर्ध्वं च दत्त्वा मुद्रा  प्रदीयते", text: "dro ṇapuṣpīprasūnāni viḍaṅgamirimedakaḥ etaccūrṇamadhordhvaṃ ca dattvā mudrā  pradīyate" },
      { type: "verse", number: "37", sanskrit: "तं गोलं सन्धयेत्सम्यङ्मृण्मूषासम्पुटे सुधीः मुद्रा ं! दत्त्वा शोधयित्वा ततो गजपुटे पचेत् एवमेकपुटेनैव जायते भस्म सूतकम्", text: "taṃ golaṃ sandhayetsamyaṅmṛṇmūṣāsampuṭe sudhīḥ mudrā ṃ! dattvā śodhayitvā tato gajapuṭe pacet evamekapuṭenaiva jāyate bhasma sūtakam" },
      { type: "verse", number: "38", sanskrit: "काकोदुम्बरिकादुग्धरसं किञ्चिद्विमर्दयेत्", text: "kākodumbarikādugdharasaṃ kiñcidvimardayet" },
      { type: "verse", number: "39", sanskrit: "तद्दुग्धघृष्टहिङ्गोश्च मूषायुग्मं प्रकल्पयेत् क्षिप्त्वा तत्सम्पुटे सूतं तत्र मुद्रा ं! प्रदापयेत्", text: "taddugdhaghṛṣṭahiṅgośca mūṣāyugmaṃ prakalpayet kṣiptvā tatsampuṭe sūtaṃ tatra mudrā ṃ! pradāpayet" },
      { type: "verse", number: "40", sanskrit: "धृत्वा तं गोलकं प्राज्ञो मृण्मूषासम्पुटेऽधिके पचेन्मृदुपुटेनैव सूतको याति भस्मताम्", text: "dhṛtvā taṃ golakaṃ prājño mṛṇmūṣāsampuṭe'dhike pacenmṛdupuṭenaiva sūtako yāti bhasmatām" },
      { type: "verse", number: "41", sanskrit: "नागवल्लीरसैर्घृष्टः कर्कोटीकन्दगर्भितः मृण्मूषासम्पुटे पक्त्वा सूतो यात्येव भस्मताम्", text: "nāgavallīrasairghṛṣṭaḥ karkoṭīkandagarbhitaḥ mṛṇmūṣāsampuṭe paktvā sūto yātyeva bhasmatām" },
      { type: "verse", number: "42", sanskrit: "खण्डितं हरिणशृङ्गं ज्वालामुख्या रसैः समम् रुद्ध्वा भाण्डे पचेच्चुल्ल्यां यामयुग्मं ततो नयेत्", text: "khaṇḍitaṃ hariṇaśṛṅgaṃ jvālāmukhyā rasaiḥ samam ruddhvā bhāṇḍe paceccullyāṃ yāmayugmaṃ tato nayet" },
      { type: "verse", number: "43", sanskrit: "अष्टांशं त्रिकटुं दद्यान्निष्कमात्रं च भक्षयेत् नागवल्लीरसैः सार्द्धं वातपित्तज्वरापहम्", text: "aṣṭāṃśaṃ trikaṭuṃ dadyānniṣkamātraṃ ca bhakṣayet nāgavallīrasaiḥ sārddhaṃ vātapittajvarāpaham" },
      { type: "verse", number: "44", sanskrit: "अयं ज्वराङ्कुशो नाम रसः सर्वज्वरापहः एकाहिकं द्व्याहिकं च त्र्! याहिकं वा न संशयः", text: "ayaṃ jvarāṅkuśo nāma rasaḥ sarvajvarāpahaḥ ekāhikaṃ dvyāhikaṃ ca tr! yāhikaṃ vā na saṃśayaḥ" },
      { type: "verse", number: "45", sanskrit: "पारदं रसकं तालं तुत्थं टङ्कणगन्धके सर्वमेतत्समं शुद्धं कारवेल्लीरसैर्दिनम्", text: "pāradaṃ rasakaṃ tālaṃ tutthaṃ ṭaṅkaṇagandhake sarvametatsamaṃ śuddhaṃ kāravellīrasairdinam" },
      { type: "verse", number: "46", sanskrit: "मर्दयेल्लेपयेत्तेन ताम्रपात्रोदरं भिषक् अङ्गुल्यर्धप्रमाणेन ततो रुद्ध्वा च तन्मुखम्", text: "mardayellepayettena tāmrapātrodaraṃ bhiṣak aṅgulyardhapramāṇena tato ruddhvā ca tanmukham" },
      { type: "verse", number: "47", sanskrit: "पचेत्तं वालुकायन्त्रे क्षिप्त्वा धान्यानि तन्मुखे यदा स्फुटन्ति धान्यानि तदा सिद्धं विनिर्दिशेत्", text: "pacettaṃ vālukāyantre kṣiptvā dhānyāni tanmukhe yadā sphuṭanti dhānyāni tadā siddhaṃ vinirdiśet" },
      { type: "verse", number: "48", sanskrit: "ततो नयेत्स्वाङ्गशीतं ताम्रपात्रोदराद्भिषक् रसं ज्वरारिनामानं विचूर्ण्य मरिचैः समम्", text: "tato nayetsvāṅgaśītaṃ tāmrapātrodarādbhiṣak rasaṃ jvarārināmānaṃ vicūrṇya maricaiḥ samam" },
      { type: "verse", number: "49", sanskrit: "माषैकं पर्णखण्डेन भक्षयेन्नाशयेज्ज्वरम् त्रिदिनैर्विषमं तीव्रमेकद्वित्रिचतुर्थकम्", text: "māṣaikaṃ parṇakhaṇḍena bhakṣayennāśayejjvaram tridinairviṣamaṃ tīvramekadvitricaturthakam" },
      { type: "verse", number: "50", sanskrit: "तालकं तुत्थकं ताम्रं रसं गन्धं मनःशिलाम् कर्षं कर्षं प्रयोक्तव्यं मर्दयेत् त्रिफलाऽम्बुभिः", text: "tālakaṃ tutthakaṃ tāmraṃ rasaṃ gandhaṃ manaḥśilām karṣaṃ karṣaṃ prayoktavyaṃ mardayet triphalā'mbubhiḥ" },
      { type: "verse", number: "51", sanskrit: "गोलं न्यसेत्सम्पुटके पुटं दद्यात् प्रयत्नतः ततो नीत्वाऽकदुग्धेन वज्रीदुग्धेन सप्तधा", text: "golaṃ nyasetsampuṭake puṭaṃ dadyāt prayatnataḥ tato nītvā'kadugdhena vajrīdugdhena saptadhā" },
      { type: "verse", number: "52", sanskrit: "क्वाथेन दन्त्याः श्यामायाः भावयेत्सप्तधा पुनः माषमात्रं रसं दिव्यं पञ्चाशन्मरिचैर्युतम्", text: "kvāthena dantyāḥ śyāmāyāḥ bhāvayetsaptadhā punaḥ māṣamātraṃ rasaṃ divyaṃ pañcāśanmaricairyutam" },
      { type: "verse", number: "53", sanskrit: "गुडं गद्याणकं चैव तुलसीदलयुग्मकम् भक्षयेत्त्रिदिनं भक्त्या शीतारिर्दुर्लभः परः", text: "guḍaṃ gadyāṇakaṃ caiva tulasīdalayugmakam bhakṣayettridinaṃ bhaktyā śītārirdurlabhaḥ paraḥ" },
      { type: "verse", number: "54", sanskrit: "पथ्यं दुग्धौदनं देयं विषमं शीतपूर्वकम् दाहपूर्वं हरत्याशु तृतीयकचतुर्थकौ द्व्याहिकं सततं चैव वैवर्ण्यं च नियच्छति", text: "pathyaṃ dugdhaudanaṃ deyaṃ viṣamaṃ śītapūrvakam dāhapūrvaṃ haratyāśu tṛtīyakacaturthakau dvyāhikaṃ satataṃ caiva vaivarṇyaṃ ca niyacchati" },
      { type: "verse", number: "55", sanskrit: "भागैकः स्याद्र साच्छुद्धादैलेयः पिप्पली शिवा आकारकरभो गन्धः कटुतैलेन शोधितः", text: "bhāgaikaḥ syādra sācchuddhādaileyaḥ pippalī śivā ākārakarabho gandhaḥ kaṭutailena śodhitaḥ" },
      { type: "verse", number: "56", sanskrit: "फलानि चेन्द्र वारुण्याश्चतुर्भागमिता अमी एकत्र मर्दयेच्चूर्णमिन्द्र वारुणिकारसैः", text: "phalāni cendra vāruṇyāścaturbhāgamitā amī ekatra mardayeccūrṇamindra vāruṇikārasaiḥ" },
      { type: "verse", number: "57", sanskrit: "माषोन्मितां गुटीं कृत्वा दद्यात्सद्योज्वरे बुधः छिन्नारसानुपानेन ज्वरघ्नी गुटिका मता", text: "māṣonmitāṃ guṭīṃ kṛtvā dadyātsadyojvare budhaḥ chinnārasānupānena jvaraghnī guṭikā matā" },
      { type: "verse", number: "58", sanskrit: "शुद्धो बुभुक्षितः सूतो भागद्वयमितो भवेत् तथा गन्धस्य भागौ द्वौ कुर्यात्कज्जलिकां तयोः", text: "śuddho bubhukṣitaḥ sūto bhāgadvayamito bhavet tathā gandhasya bhāgau dvau kuryātkajjalikāṃ tayoḥ" },
      { type: "verse", number: "59", sanskrit: "सूताच्चतुर्गुणेष्वेव कपर्देषु विनिक्षिपेत् भागैकं टङ्कणं दत्त्वा गोक्षीरेण विमर्दयेत्", text: "sūtāccaturguṇeṣveva kapardeṣu vinikṣipet bhāgaikaṃ ṭaṅkaṇaṃ dattvā gokṣīreṇa vimardayet" },
      { type: "verse", number: "60", sanskrit: "तथा शङ्खस्य खण्डानां भागानष्टौ प्रकल्पयेत् क्षिपेत्सर्वं पुटस्यान्तश्चूर्णलिप्तशरावयोः", text: "tathā śaṅkhasya khaṇḍānāṃ bhāgānaṣṭau prakalpayet kṣipetsarvaṃ puṭasyāntaścūrṇaliptaśarāvayoḥ" },
      { type: "verse", number: "61", sanskrit: "गर्त्ते हस्तोन्मिते धृत्वा पुटेद्गजपुटेन च स्वाङ्गशीतं समुद्धृत्य पिष्ट्वा तत्सर्वमेकतः षड्गुञ्जासम्मितं चूर्णमेकोनत्रिंशदूषणैः", text: "gartte hastonmite dhṛtvā puṭedgajapuṭena ca svāṅgaśītaṃ samuddhṛtya piṣṭvā tatsarvamekataḥ ṣaḍguñjāsammitaṃ cūrṇamekonatriṃśadūṣaṇaiḥ" },
      { type: "verse", number: "62", sanskrit: "घृतेन वातजे दद्यान्नवनीतेन पित्तजे क्षौद्रे ण श्लेष्मजे दद्यादतीसारे क्षये तथा", text: "ghṛtena vātaje dadyānnavanītena pittaje kṣaudre ṇa śleṣmaje dadyādatīsāre kṣaye tathā" },
      { type: "verse", number: "63", sanskrit: "अरुचौ ग्रहणीरोगे कार्श्ये मन्दानले तथा कासश्वासेषु गुल्मेषु लोकनाथरसो हितः", text: "arucau grahaṇīroge kārśye mandānale tathā kāsaśvāseṣu gulmeṣu lokanātharaso hitaḥ" },
      { type: "verse", number: "64", sanskrit: "तस्योपरि घृतान्नं च भुञ्जीत कवलत्रयम् मञ्चे क्षणैकमुत्तानः शयीतानुपधानके", text: "tasyopari ghṛtānnaṃ ca bhuñjīta kavalatrayam mañce kṣaṇaikamuttānaḥ śayītānupadhānake" },
      { type: "verse", number: "65", sanskrit: "अनम्लमन्नं सघृतं भुञ्जीत मधुरं दधि प्रायेण जाङ्गलं मांसं प्रदेयं घृतपाचितम्", text: "anamlamannaṃ saghṛtaṃ bhuñjīta madhuraṃ dadhi prāyeṇa jāṅgalaṃ māṃsaṃ pradeyaṃ ghṛtapācitam" },
      { type: "verse", number: "66", sanskrit: "सुदुग्धभक्तंदद्याच्च जातेऽग्नौ सान्ध्यभोजने सघृतान्मुद्गवटकान्व्यञ्जनेष्ववचारयेत्", text: "sudugdhabhaktaṃdadyācca jāte'gnau sāndhyabhojane saghṛtānmudgavaṭakānvyañjaneṣvavacārayet" },
      { type: "verse", number: "67", sanskrit: "तिलामलककल्केन स्नापयेत्सर्पिषाऽथवा अभ्यञ्जयेत्सर्पिषा च स्नानं कोष्णोदकेन च", text: "tilāmalakakalkena snāpayetsarpiṣā'thavā abhyañjayetsarpiṣā ca snānaṃ koṣṇodakena ca" },
      { type: "verse", number: "68", sanskrit: "क्वचित्तैलं न गृह्णीयान्न बिल्वं कारवेल्लकम् वार्ताकं शफरीं चिञ्चां त्यजेद्व्यायाममैथुने", text: "kvacittailaṃ na gṛhṇīyānna bilvaṃ kāravellakam vārtākaṃ śapharīṃ ciñcāṃ tyajedvyāyāmamaithune" },
      { type: "verse", number: "69", sanskrit: "मद्यं सन्धानकं हिङ्गु शुण्ठीं माषान्मसूरकान् कूष्माण्डं राजिकां कोपं काञ्जिकं चैव वर्जयेत्", text: "madyaṃ sandhānakaṃ hiṅgu śuṇṭhīṃ māṣānmasūrakān kūṣmāṇḍaṃ rājikāṃ kopaṃ kāñjikaṃ caiva varjayet" },
      { type: "verse", number: "70", sanskrit: "त्यजेदयुक्तनिद्रा ं! च कांस्यपात्रे च भोजनम् ककारादियुतं सर्वं त्यजेच्छाकफलादिकम्", text: "tyajedayuktanidrā ṃ! ca kāṃsyapātre ca bhojanam kakārādiyutaṃ sarvaṃ tyajecchākaphalādikam" },
      { type: "verse", number: "71", sanskrit: "पथ्योऽय लोकनाथेऽस्तुऐ! शुभनक्षत्रवासरे सेवनविधिः पूर्णातिथौ सिते पक्षे जाते चन्द्र बले तथा", text: "pathyo'ya lokanāthe'stuai! śubhanakṣatravāsare sevanavidhiḥ pūrṇātithau site pakṣe jāte candra bale tathā" },
      { type: "verse", number: "72", sanskrit: "पूजयित्वा लोकनाथं कुमारीं भोजयेत्ततः दानं दत्त्वा द्विघटिकामध्ये ग्राह्यो रसोत्तमः", text: "pūjayitvā lokanāthaṃ kumārīṃ bhojayettataḥ dānaṃ dattvā dvighaṭikāmadhye grāhyo rasottamaḥ" },
      { type: "verse", number: "73", sanskrit: "रसाच्चेज्जायते तापस्तदा शर्करया युतम्", text: "rasāccejjāyate tāpastadā śarkarayā yutam" },
      { type: "verse", number: "74", sanskrit: "सत्त्वं गुडूच्या गृह्णीयाद्वंशरोचनया युतम् खर्जूरं दाडिमं द्रा क्षामिक्षुखण्डानि दापयेत्", text: "sattvaṃ guḍūcyā gṛhṇīyādvaṃśarocanayā yutam kharjūraṃ dāḍimaṃ drā kṣāmikṣukhaṇḍāni dāpayet" },
      { type: "verse", number: "75", sanskrit: "अरुचौ निस्तुषं धान्यं घृतभृष्टं सशर्करम् दद्यात्तथा ज्वरे धान्यगुडूचीक्वाथमाहरेत्", text: "arucau nistuṣaṃ dhānyaṃ ghṛtabhṛṣṭaṃ saśarkaram dadyāttathā jvare dhānyaguḍūcīkvāthamāharet" },
      { type: "verse", number: "76", sanskrit: "उशीरवासकक्वाथं दद्यात्समधुशर्करम् रक्तपित्ते कफे श्वासे कासे च स्वरसंक्षये", text: "uśīravāsakakvāthaṃ dadyātsamadhuśarkaram raktapitte kaphe śvāse kāse ca svarasaṃkṣaye" },
      { type: "verse", number: "77", sanskrit: "अग्निभृष्टजयाचूर्णं मधुना निशि दीयते निद्रा नाशेऽतिसारे च ग्रहण्यां मन्दपावके", text: "agnibhṛṣṭajayācūrṇaṃ madhunā niśi dīyate nidrā nāśe'tisāre ca grahaṇyāṃ mandapāvake" },
      { type: "verse", number: "78", sanskrit: "सौवर्चलाभयाकृष्णाचूर्णमुष्णोदकैः पिबेत् शूलेऽजीर्णे तथा कृष्णा मधुयुक्ता ज्वरे हिता", text: "sauvarcalābhayākṛṣṇācūrṇamuṣṇodakaiḥ pibet śūle'jīrṇe tathā kṛṣṇā madhuyuktā jvare hitā" },
      { type: "verse", number: "79", sanskrit: "प्लीहोदरे वातरक्ते छर्द्यां चैव गुदाङ्कुरे नासिकादिषु रक्तेषु रसं दाडिमपुष्पजम्", text: "plīhodare vātarakte chardyāṃ caiva gudāṅkure nāsikādiṣu rakteṣu rasaṃ dāḍimapuṣpajam" },
      { type: "verse", number: "80", sanskrit: "दूर्वायाः स्वरसं नस्ये प्रदद्याच्छर्करायुतम् कोलमज्जा कणा बर्हिपक्षभस्म सशर्करम्", text: "dūrvāyāḥ svarasaṃ nasye pradadyāccharkarāyutam kolamajjā kaṇā barhipakṣabhasma saśarkaram" },
      { type: "verse", number: "81", sanskrit: "मधुना लेहयेच्छर्दिहिक्काकोपस्य शान्तये विधिरेष प्रयोज्यस्तु सर्वस्मिन्पोट्टलीरसे", text: "madhunā lehayecchardihikkākopasya śāntaye vidhireṣa prayojyastu sarvasminpoṭṭalīrase" },
      { type: "verse", number: "82", sanskrit: "मृगाङ्के हेमगर्भे च मौक्तिकाख्ये रसेषु च इत्ययं लोकनाथाख्यो रसः सर्वरुजो जयेत्", text: "mṛgāṅke hemagarbhe ca mauktikākhye raseṣu ca ityayaṃ lokanāthākhyo rasaḥ sarvarujo jayet" },
      { type: "verse", number: "83", sanskrit: "वराटभस्म मण्डूरं चूर्णयित्वा घृते पचेत् तत्समं मारिचं चूर्णं नागवल्ल्यां विभावितम्", text: "varāṭabhasma maṇḍūraṃ cūrṇayitvā ghṛte pacet tatsamaṃ māricaṃ cūrṇaṃ nāgavallyāṃ vibhāvitam" },
      { type: "verse", number: "84", sanskrit: "तच्चूर्णं मधुना लेह्यमथवा नवनीतकैः माषमात्रं क्षयं हन्ति यामे यामे च भक्षितम्", text: "taccūrṇaṃ madhunā lehyamathavā navanītakaiḥ māṣamātraṃ kṣayaṃ hanti yāme yāme ca bhakṣitam" },
      { type: "verse", number: "85", sanskrit: "लोकनाथरसो ह्येष मण्डलाद्रा जयक्ष्मनुत्", text: "lokanātharaso hyeṣa maṇḍalādrā jayakṣmanut" },
      { type: "verse", number: "86", sanskrit: "भूर्जवत्तनुपत्राणि हेम्नः सूक्ष्माणि कारयेत् तुल्यानि तानि सूतेन खल्वे क्षिप्त्वा विमर्दयेत्", text: "bhūrjavattanupatrāṇi hemnaḥ sūkṣmāṇi kārayet tulyāni tāni sūtena khalve kṣiptvā vimardayet" },
      { type: "verse", number: "87", sanskrit: "काञ्चनाररसेनैव ज्वालामुख्या रसेन वा लाङ्गल्या वा रसैस्तावद्यावद्भवति पिष्टिका", text: "kāñcanārarasenaiva jvālāmukhyā rasena vā lāṅgalyā vā rasaistāvadyāvadbhavati piṣṭikā" },
      { type: "verse", number: "88", sanskrit: "ततो हेम्नश्चतुर्थांशं टङ्कणं तत्र निक्षिपेत् पिष्टमौक्तिकचूर्णं च हेमद्विगुणमावपेत्", text: "tato hemnaścaturthāṃśaṃ ṭaṅkaṇaṃ tatra nikṣipet piṣṭamauktikacūrṇaṃ ca hemadviguṇamāvapet" },
      { type: "verse", number: "89", sanskrit: "तेषु सर्वसमं गन्धं क्षिप्त्वा चैकत्र मर्दयेत् तेषां कृत्वा ततो गोलवासोभिः परिवेष्टयेत्", text: "teṣu sarvasamaṃ gandhaṃ kṣiptvā caikatra mardayet teṣāṃ kṛtvā tato golavāsobhiḥ pariveṣṭayet" },
      { type: "verse", number: "90", sanskrit: "पश्चान्मृदा वेष्टयित्वा शोषयित्वा च धारयेत् शरावसम्पुटस्यान्तस्तत्र मुद्रा ं! प्रदापयेत्", text: "paścānmṛdā veṣṭayitvā śoṣayitvā ca dhārayet śarāvasampuṭasyāntastatra mudrā ṃ! pradāpayet" },
      { type: "verse", number: "91", sanskrit: "लवणापूरिते भाण्डे धारयेत्तं च सम्पुटम् मुद्रा ं! दत्त्वा शोषयित्वा बहुभिर्गोमयैः पुटेत्", text: "lavaṇāpūrite bhāṇḍe dhārayettaṃ ca sampuṭam mudrā ṃ! dattvā śoṣayitvā bahubhirgomayaiḥ puṭet" },
      { type: "verse", number: "92", sanskrit: "ततः शीते समाहृत्य गन्धं सूतसमं क्षिपेत् घृष्ट्वा च पूर्ववत्खल्वे पुटेद् गजपुटेन च", text: "tataḥ śīte samāhṛtya gandhaṃ sūtasamaṃ kṣipet ghṛṣṭvā ca pūrvavatkhalve puṭed gajapuṭena ca" },
      { type: "verse", number: "93", sanskrit: "स्वाङ्गशीतं ततो नीत्वा गुञ्जायुग्मं प्रयोजयेत् अष्टभिर्मरिचैर्युक्तः कृष्णात्रययुतोऽथवा", text: "svāṅgaśītaṃ tato nītvā guñjāyugmaṃ prayojayet aṣṭabhirmaricairyuktaḥ kṛṣṇātrayayuto'thavā" },
      { type: "verse", number: "94", sanskrit: "विलोक्य देयो दोषादीनेकैका रसरक्तिका सर्पिषा मधुना वाऽपि दद्याद्दोषाद्यपेक्षया", text: "vilokya deyo doṣādīnekaikā rasaraktikā sarpiṣā madhunā vā'pi dadyāddoṣādyapekṣayā" },
      { type: "verse", number: "95", sanskrit: "लोकनाथसमं पथ्यं कुर्यात्स्वस्थमनाः शुचिः श्लेष्माणं ग्रहणीं कासं श्वासं क्षयमरोचकम् मृगाङ्कोऽय रसो हन्यात्कृशत्वं बलहीनताम्", text: "lokanāthasamaṃ pathyaṃ kuryātsvasthamanāḥ śuciḥ śleṣmāṇaṃ grahaṇīṃ kāsaṃ śvāsaṃ kṣayamarocakam mṛgāṅko'ya raso hanyātkṛśatvaṃ balahīnatām" },
      { type: "verse", number: "96", sanskrit: "क्षयश्वासादौ हेमगर्भपोट्टलीरसः सूतात्पादप्रमाणेन हेम्नः पिष्टं प्रकल्पयेत् तयोः स्याद् द्विगुणो गन्धो मर्दयेत्काञ्चनारिणा", text: "kṣayaśvāsādau hemagarbhapoṭṭalīrasaḥ sūtātpādapramāṇena hemnaḥ piṣṭaṃ prakalpayet tayoḥ syād dviguṇo gandho mardayetkāñcanāriṇā" },
      { type: "verse", number: "97", sanskrit: "कृत्वा गोलं क्षिपेन्मूषासम्पुटे मुद्र येत्ततः पचेद् भूधरयन्त्रेण वासरत्रितयं बुधः", text: "kṛtvā golaṃ kṣipenmūṣāsampuṭe mudra yettataḥ paced bhūdharayantreṇa vāsaratritayaṃ budhaḥ" },
      { type: "verse", number: "98", sanskrit: "तत उद्धृत्य तत्सर्वं दद्याद् गन्धं च तत्समम् मर्दयेदार्द्र करसैश्चित्रकस्वरसेन च", text: "tata uddhṛtya tatsarvaṃ dadyād gandhaṃ ca tatsamam mardayedārdra karasaiścitrakasvarasena ca" },
      { type: "verse", number: "99", sanskrit: "स्थूलपीतवराटांश्च पूरयेत्तेन युक्तितः एतस्मादौषधात्कुर्यादष्टमांशेन टङ्कणम्", text: "sthūlapītavarāṭāṃśca pūrayettena yuktitaḥ etasmādauṣadhātkuryādaṣṭamāṃśena ṭaṅkaṇam" },
      { type: "verse", number: "100", sanskrit: "टङ्कणार्धं विषं दत्त्वा पिष्ट्वा सेहुण्डदुग्धकैः मुद्र येत्तेन कल्केन वराटानांमुखानि च", text: "ṭaṅkaṇārdhaṃ viṣaṃ dattvā piṣṭvā sehuṇḍadugdhakaiḥ mudra yettena kalkena varāṭānāṃmukhāni ca" },
      { type: "verse", number: "101", sanskrit: "भाण्डे चूर्णप्रलिप्तेऽथ धृत्वा मुद्रा ं! प्रदापयेत् गर्त्ते हस्तोन्मिते धृत्वा पुटेद्गजपुटेन च", text: "bhāṇḍe cūrṇapralipte'tha dhṛtvā mudrā ṃ! pradāpayet gartte hastonmite dhṛtvā puṭedgajapuṭena ca" },
      { type: "verse", number: "102", sanskrit: "स्वाङ्गशीतं रसं ज्ञात्वा प्रदद्याल्लोकनाथवत् पथ्यं मृगाङ्कवज्ज्ञेयं त्रिदिनं लवणं त्यजेत्", text: "svāṅgaśītaṃ rasaṃ jñātvā pradadyāllokanāthavat pathyaṃ mṛgāṅkavajjñeyaṃ tridinaṃ lavaṇaṃ tyajet" },
      { type: "verse", number: "103", sanskrit: "यदा छर्दिर्भवेत्तस्य दद्याच्छिन्नाशृतं तदा मधुयुक्तं तथा श्लेष्मकोपे दद्याद्गुडार्द्र कम्", text: "yadā chardirbhavettasya dadyācchinnāśṛtaṃ tadā madhuyuktaṃ tathā śleṣmakope dadyādguḍārdra kam" },
      { type: "verse", number: "104", sanskrit: "विरेके भर्जिता भङ्गा प्रदेया दधिसंयुता जयेत्कासं क्षयं श्वासं ग्रहणीमरुचिं तथा", text: "vireke bharjitā bhaṅgā pradeyā dadhisaṃyutā jayetkāsaṃ kṣayaṃ śvāsaṃ grahaṇīmaruciṃ tathā" },
      { type: "verse", number: "105", sanskrit: "अग्निं च कुरुते दीप्तं कफवातं नियच्छति हेमगर्भ परो ज्ञेयो रसः पोट्टलिकाऽभिधः", text: "agniṃ ca kurute dīptaṃ kaphavātaṃ niyacchati hemagarbha paro jñeyo rasaḥ poṭṭalikā'bhidhaḥ" },
      { type: "verse", number: "106", sanskrit: "रसस्य भागाश्चत्वारस्तावन्तः कनकस्य च तयोश्च पिष्टिकां कृत्वा गन्धो द्वादशभागकः", text: "rasasya bhāgāścatvārastāvantaḥ kanakasya ca tayośca piṣṭikāṃ kṛtvā gandho dvādaśabhāgakaḥ" },
      { type: "verse", number: "107", sanskrit: "कुर्यात्कज्जलिकां तेषां मुक्ताभागाश्च षोडशः चतुर्विंशच्च शङ्खस्य भागैकं टङ्कणस्य च", text: "kuryātkajjalikāṃ teṣāṃ muktābhāgāśca ṣoḍaśaḥ caturviṃśacca śaṅkhasya bhāgaikaṃ ṭaṅkaṇasya ca" },
      { type: "verse", number: "108", sanskrit: "एकत्र मर्दयेत्सर्वं पक्वनिम्बूकजैः रसैः कृत्वा तेषां ततो गोलं मूषासम्पुटके न्यसेत्", text: "ekatra mardayetsarvaṃ pakvanimbūkajaiḥ rasaiḥ kṛtvā teṣāṃ tato golaṃ mūṣāsampuṭake nyaset" },
      { type: "verse", number: "109", sanskrit: "मुद्रा ं! दत्त्वा ततो हस्तमात्रे गर्त्ते च गोमयैः पुटेद् गजपुटेनैव स्वाङ्गशीतं समुद्धरेत्", text: "mudrā ṃ! dattvā tato hastamātre gartte ca gomayaiḥ puṭed gajapuṭenaiva svāṅgaśītaṃ samuddharet" },
      { type: "verse", number: "110", sanskrit: "पिष्ट्वा गुञ्जाचतुर्मानं दद्याद्गव्याज्यसंयुतम् एकोनत्रिंशदुन्मानमरिचैः सह दीयते", text: "piṣṭvā guñjācaturmānaṃ dadyādgavyājyasaṃyutam ekonatriṃśadunmānamaricaiḥ saha dīyate" },
      { type: "verse", number: "111", sanskrit: "राजते मृण्मये पात्रे काचजे वाऽवलेहयेत् लोकनाथसमं पथ्यं कुर्याच्च स्वस्थमानसः", text: "rājate mṛṇmaye pātre kācaje vā'valehayet lokanāthasamaṃ pathyaṃ kuryācca svasthamānasaḥ" },
      { type: "verse", number: "112", sanskrit: "कासे श्वासे क्षये वाते कफे ग्रहणिकागदे अतिसारे प्रयोक्तव्या पोट्टली हेमगर्भिका", text: "kāse śvāse kṣaye vāte kaphe grahaṇikāgade atisāre prayoktavyā poṭṭalī hemagarbhikā" },
      { type: "verse", number: "113", sanskrit: "विषमज्वरादौ महाज्वराङ्कुशरसः शुद्धसूतो विषं गन्धः प्रत्येकं शाणसम्मिताः धूर्त्तबीजं त्रिशाणं स्यात्सर्वेभ्यो द्विगुणा भवेत्", text: "viṣamajvarādau mahājvarāṅkuśarasaḥ śuddhasūto viṣaṃ gandhaḥ pratyekaṃ śāṇasammitāḥ dhūrttabījaṃ triśāṇaṃ syātsarvebhyo dviguṇā bhavet" },
      { type: "verse", number: "114", sanskrit: "हेमाह्वा कारयेदेषां सूक्ष्मं चूर्णं प्रयत्नतः देयं जम्बीरमज्जाभिश्चूर्णं गुञ्जाद्वयोन्मितम्", text: "hemāhvā kārayedeṣāṃ sūkṣmaṃ cūrṇaṃ prayatnataḥ deyaṃ jambīramajjābhiścūrṇaṃ guñjādvayonmitam" },
      { type: "verse", number: "115", sanskrit: "आर्द्र कस्वरसैर्वाऽपि ज्वरं हन्ति त्रिदोषजम् एकाहिकं द्व्याहिकं वा त्र्! याहिकं वा चतुर्थकम्", text: "ārdra kasvarasairvā'pi jvaraṃ hanti tridoṣajam ekāhikaṃ dvyāhikaṃ vā tr! yāhikaṃ vā caturthakam" },
      { type: "verse", number: "116", sanskrit: "विषमं च ज्वरं हन्याद्विख्यातोऽय ज्वराङ्कुशः", text: "viṣamaṃ ca jvaraṃ hanyādvikhyāto'ya jvarāṅkuśaḥ" },
      { type: "verse", number: "117", sanskrit: "दरदं वत्सनाभं च मरिचं टङ्कणं कणाम् चूर्णयेत्समभागेन रसो ह्यानन्दभैरवः", text: "daradaṃ vatsanābhaṃ ca maricaṃ ṭaṅkaṇaṃ kaṇām cūrṇayetsamabhāgena raso hyānandabhairavaḥ" },
      { type: "verse", number: "118", sanskrit: "गुञ्जैकं वा द्विगुञ्जं वा बलं ज्ञात्वा प्रयोजयेत् मधुना लेहयेच्चानु कुटजस्य फलं त्वचम्", text: "guñjaikaṃ vā dviguñjaṃ vā balaṃ jñātvā prayojayet madhunā lehayeccānu kuṭajasya phalaṃ tvacam" },
      { type: "verse", number: "119", sanskrit: "चूर्णितं कर्षमात्रं तु त्रिदोषोत्थातिसारजित् दध्यन्नं दापयेत्पथ्यं गवाज्यं तक्रमेव च पिपासायां जलं शीतं विजया च हिता निशि", text: "cūrṇitaṃ karṣamātraṃ tu tridoṣotthātisārajit dadhyannaṃ dāpayetpathyaṃ gavājyaṃ takrameva ca pipāsāyāṃ jalaṃ śītaṃ vijayā ca hitā niśi" },
      { type: "verse", number: "120", sanskrit: "विषं पलमितं सूतः शाणिकश्चूर्णयेद् द्वयम् तच्चूर्णं सम्पुटे क्षिप्त्वा कावलिप्तशरावयोः", text: "viṣaṃ palamitaṃ sūtaḥ śāṇikaścūrṇayed dvayam taccūrṇaṃ sampuṭe kṣiptvā kāvaliptaśarāvayoḥ" },
      { type: "verse", number: "121", sanskrit: "मुद्रा ं! दत्त्वा च संशोष्य ततश्चुल्यां निवेशयेत् वह्निं शनैः शनैः कुर्यात्प्रहरद्वयसंख्यया", text: "mudrā ṃ! dattvā ca saṃśoṣya tataśculyāṃ niveśayet vahniṃ śanaiḥ śanaiḥ kuryātpraharadvayasaṃkhyayā" },
      { type: "verse", number: "122", sanskrit: "तत उद्घाटयेन्मुद्रा मुपरिस्थां शरावकात् संलग्नो यो भवेत्सूतस्तं गृह्णीयाच्छनैः शनैः", text: "tata udghāṭayenmudrā muparisthāṃ śarāvakāt saṃlagno yo bhavetsūtastaṃ gṛhṇīyācchanaiḥ śanaiḥ" },
      { type: "verse", number: "123", sanskrit: "वायुस्पर्शो यथा न स्यात्तथा कुप्यां निवेशयेत् यावत्सूच्या मुखे लग्नं कुप्या निर्याति भेषजम्", text: "vāyusparśo yathā na syāttathā kupyāṃ niveśayet yāvatsūcyā mukhe lagnaṃ kupyā niryāti bheṣajam" },
      { type: "verse", number: "124", sanskrit: "तावन्मात्रो रसो देयो मूर्च्छिते सन्निपातिनि क्षुरेण प्रच्छिते मूर्ध्निं तत्राङ्गुल्या च घर्षयेत्", text: "tāvanmātro raso deyo mūrcchite sannipātini kṣureṇa pracchite mūrdhniṃ tatrāṅgulyā ca gharṣayet" },
      { type: "verse", number: "125", sanskrit: "रक्तभेषजसम्पर्कान्मूर्च्छितोऽपि हि जीवति तथैव सर्पदष्टस्तु मृतावस्थोऽपि जीवति", text: "raktabheṣajasamparkānmūrcchito'pi hi jīvati tathaiva sarpadaṣṭastu mṛtāvastho'pi jīvati" },
      { type: "verse", number: "126", sanskrit: "यदा तापो भवेत्तस्य मधुरं तत्र दीयते", text: "yadā tāpo bhavettasya madhuraṃ tatra dīyate" },
      { type: "verse", number: "127", sanskrit: "सूतभस्मसमं गन्धं गन्धात्पादं मनः शिला माक्षिकं पिप्पली व्योषं प्रत्येकं शिलया समम्", text: "sūtabhasmasamaṃ gandhaṃ gandhātpādaṃ manaḥ śilā mākṣikaṃ pippalī vyoṣaṃ pratyekaṃ śilayā samam" },
      { type: "verse", number: "128", sanskrit: "सप्तधा भावयेच्छुष्कं देयं गुञ्जाद्वयं हितम्", text: "saptadhā bhāvayecchuṣkaṃ deyaṃ guñjādvayaṃ hitam" },
      { type: "verse", number: "129", sanskrit: "तालपर्णीरसश्चानु पञ्चकोलशृतोऽथवा जलबन्धुरसो नाम सन्निपातं नियच्छति जलयोगश्च कर्त्तव्यस्तेन वीर्यं भवेद्र से", text: "tālaparṇīrasaścānu pañcakolaśṛto'thavā jalabandhuraso nāma sannipātaṃ niyacchati jalayogaśca karttavyastena vīryaṃ bhavedra se" },
      { type: "verse", number: "130", sanskrit: "शुद्धसूतं विषं गन्धं मरिचं टङ्कणं कणाम् मर्दयेद् धूर्त्तजद्रा वैर्दिनमेकं च शोषयेत्", text: "śuddhasūtaṃ viṣaṃ gandhaṃ maricaṃ ṭaṅkaṇaṃ kaṇām mardayed dhūrttajadrā vairdinamekaṃ ca śoṣayet" },
      { type: "verse", number: "131", sanskrit: "पञ्चवक्त्रो रसो नाम द्विगुञ्जः सन्निपातजित् अर्कमूलकषायं तु सत्र्! यूषमनुपाययेत्", text: "pañcavaktro raso nāma dviguñjaḥ sannipātajit arkamūlakaṣāyaṃ tu satr! yūṣamanupāyayet" },
      { type: "verse", number: "132", sanskrit: "युक्तं दध्योदनं पथ्यं जलयोगं च कारयेत् रसेनानेन शाम्यन्ति सक्षौद्रे ण कफादयः", text: "yuktaṃ dadhyodanaṃ pathyaṃ jalayogaṃ ca kārayet rasenānena śāmyanti sakṣaudre ṇa kaphādayaḥ" },
      { type: "verse", number: "133", sanskrit: "मध्वार्द्र करसं चानुपिबेदग्निविवृद्धये यथेष्टं घृतमांसाशी शक्तो भवति पावकः", text: "madhvārdra karasaṃ cānupibedagnivivṛddhaye yatheṣṭaṃ ghṛtamāṃsāśī śakto bhavati pāvakaḥ" },
      { type: "verse", number: "134", sanskrit: "रसं गन्धकतुल्यांशं धत्तूरफलजद्र वैः मर्दयेद्दिनमेकं तु तत्तुल्यं त्रिकटुं क्षिपेत्", text: "rasaṃ gandhakatulyāṃśaṃ dhattūraphalajadra vaiḥ mardayeddinamekaṃ tu tattulyaṃ trikaṭuṃ kṣipet" },
      { type: "verse", number: "135", sanskrit: "उन्मत्ताख्यो रसो नाम्ना नस्ये स्यात्सन्निपातजित्", text: "unmattākhyo raso nāmnā nasye syātsannipātajit" },
      { type: "verse", number: "136", sanskrit: "निस्त्वग्जैपालबीजं च दशनिष्कं विचूर्णयेत् मरिचं पिप्पलद्यं सूतं प्रतिनिष्कं विमिश्रयेत्", text: "nistvagjaipālabījaṃ ca daśaniṣkaṃ vicūrṇayet maricaṃ pippaladyaṃ sūtaṃ pratiniṣkaṃ vimiśrayet" },
      { type: "verse", number: "137", sanskrit: "भाव्यो जम्बीरजैद्रा र्वैः! सप्ताहं सम्प्रयत्नतः रसोऽयमञ्जने दत्तः सन्निपातं विनाशयेत्", text: "bhāvyo jambīrajaidrā rvaiḥ! saptāhaṃ samprayatnataḥ raso'yamañjane dattaḥ sannipātaṃ vināśayet" },
      { type: "verse", number: "138", sanskrit: "सूतं टङ्कणकं तुल्यं मरिचं सूततुल्यकम् गन्धकं पिप्पलद्यं शुण्ठीं द्वौ द्वौ भागौ विचूर्णयेत्", text: "sūtaṃ ṭaṅkaṇakaṃ tulyaṃ maricaṃ sūtatulyakam gandhakaṃ pippaladyaṃ śuṇṭhīṃ dvau dvau bhāgau vicūrṇayet" },
      { type: "verse", number: "139", sanskrit: "सर्वतुल्यं क्षिपेद्दन्तीबीजं निस्तुषितं भिषक् द्विगुञ्जं रेचनं सिद्धं नाराचोऽय महारसः आध्मानं मलविष्टम्भानुदावर्त्तं च नाशयेत्", text: "sarvatulyaṃ kṣipeddantībījaṃ nistuṣitaṃ bhiṣak dviguñjaṃ recanaṃ siddhaṃ nārāco'ya mahārasaḥ ādhmānaṃ malaviṣṭambhānudāvarttaṃ ca nāśayet" },
      { type: "verse", number: "140", sanskrit: "दरदं टङ्कणं शुण्ठी पिप्पली चेति कार्षिकाः हेमाह्वा पलमात्रा स्याद्दन्तीबीजं च तत्समम्", text: "daradaṃ ṭaṅkaṇaṃ śuṇṭhī pippalī ceti kārṣikāḥ hemāhvā palamātrā syāddantībījaṃ ca tatsamam" },
      { type: "verse", number: "141", sanskrit: "विचूर्ण्यैकत्र सर्वाणि गोदुग्धेनैव पाययेत् त्रिगुञ्जं रेचनं दद्याद्विष्टम्भाध्मानरोगिषु", text: "vicūrṇyaikatra sarvāṇi godugdhenaiva pāyayet triguñjaṃ recanaṃ dadyādviṣṭambhādhmānarogiṣu" },
      { type: "verse", number: "142", sanskrit: "द्वौ भागौ हेमभूतेश्च गगनं चापि तत्समम् लोहभस्म त्रयो भागाश्चत्वारो रसभस्मनः", text: "dvau bhāgau hemabhūteśca gaganaṃ cāpi tatsamam lohabhasma trayo bhāgāścatvāro rasabhasmanaḥ" },
      { type: "verse", number: "143", sanskrit: "वङ्गभस्म त्रिभागं स्यात्सर्वमेकत्र मर्दयेत् प्रवालं मौक्तिकं चैव रससाम्येन दापयेत्", text: "vaṅgabhasma tribhāgaṃ syātsarvamekatra mardayet pravālaṃ mauktikaṃ caiva rasasāmyena dāpayet" },
      { type: "verse", number: "144", sanskrit: "भावना गव्यदुग्धेन रसैर्घृष्ट्वाऽटरुषकैः हरिद्रा वारिणा चैव मोचकन्दरसेन च", text: "bhāvanā gavyadugdhena rasairghṛṣṭvā'ṭaruṣakaiḥ haridrā vāriṇā caiva mocakandarasena ca" },
      { type: "verse", number: "145", sanskrit: "शतपत्ररसेनापि मालत्याः स्वरसेन च पश्चान्मृगमदश्चन्द्र तुलसीरसभावितः", text: "śatapatrarasenāpi mālatyāḥ svarasena ca paścānmṛgamadaścandra tulasīrasabhāvitaḥ" },
      { type: "verse", number: "146", sanskrit: "कुसुमाकर इत्येष वसन्तपदपूर्वकः गुञ्जाद्वयं ददीतास्य मधुना सर्वमेहनुत्", text: "kusumākara ityeṣa vasantapadapūrvakaḥ guñjādvayaṃ dadītāsya madhunā sarvamehanut" },
      { type: "verse", number: "147", sanskrit: "सिताचन्दनसंयुक्तश्चाम्लपित्तादिरोगजित्", text: "sitācandanasaṃyuktaścāmlapittādirogajit" },
      { type: "verse", number: "148", sanskrit: "सूतभस्म त्रयो भागा भागैकं हेमभस्मकम् मृताभ्रस्य च भागैकं शिलागन्धकतालकम्", text: "sūtabhasma trayo bhāgā bhāgaikaṃ hemabhasmakam mṛtābhrasya ca bhāgaikaṃ śilāgandhakatālakam" },
      { type: "verse", number: "149", sanskrit: "प्रतिभागद्वयं शुद्धमेकीकृत्य विचूर्णयेत् वराटान्पूरयेत्तेन छागीक्षीरेण टङ्कणम्", text: "pratibhāgadvayaṃ śuddhamekīkṛtya vicūrṇayet varāṭānpūrayettena chāgīkṣīreṇa ṭaṅkaṇam" },
      { type: "verse", number: "150", sanskrit: "पिष्ट्वा तेन मुखं रुद्ध्वा मृद्भाण्डे सन्निरोधयेत् शुष्कं गजपुटे पक्त्वा चूर्णयेत्स्वाङ्गशीतलम्", text: "piṣṭvā tena mukhaṃ ruddhvā mṛdbhāṇḍe sannirodhayet śuṣkaṃ gajapuṭe paktvā cūrṇayetsvāṅgaśītalam" },
      { type: "verse", number: "151", sanskrit: "रसो राजमृगाङ्कोऽय चतुर्गुञ्जः क्षयापहः दशपिप्पलिकाक्षौद्रै रेकोनत्रिंशदूषणैः", text: "raso rājamṛgāṅko'ya caturguñjaḥ kṣayāpahaḥ daśapippalikākṣaudrai rekonatriṃśadūṣaṇaiḥ" },
      { type: "verse", number: "152", sanskrit: "सघृतं दापयेत्पथ्यं स्त्रीकोपाग्निश्रमांस्त्यजेत् पथ्यं वा लघुमांसानि राजरोगप्रशान्तये", text: "saghṛtaṃ dāpayetpathyaṃ strīkopāgniśramāṃstyajet pathyaṃ vā laghumāṃsāni rājarogapraśāntaye" },
      { type: "verse", number: "153", sanskrit: "शुद्धं सूतं द्विधा गन्धं कुर्यात्खल्वेन कज्जलीम् तयोः समं तीक्ष्णचूर्णं मर्दयेत्कन्यकाद्र वैः", text: "śuddhaṃ sūtaṃ dvidhā gandhaṃ kuryātkhalvena kajjalīm tayoḥ samaṃ tīkṣṇacūrṇaṃ mardayetkanyakādra vaiḥ" },
      { type: "verse", number: "154", sanskrit: "द्वियामान्ते कृतं गोलं ताम्रपात्रे विनिक्षिपेत् आच्छाद्यैरण्डपत्रेण यामार्धेऽत्युष्णता भवेद्", text: "dviyāmānte kṛtaṃ golaṃ tāmrapātre vinikṣipet ācchādyairaṇḍapatreṇa yāmārdhe'tyuṣṇatā bhaved" },
      { type: "verse", number: "155", sanskrit: "धान्यराशौ न्यसेत्पश्चादहोरात्रात्समुद्धरेत् संचूर्ण्य गालयेद्वस्त्रे सत्यं वारितरं भवेत्", text: "dhānyarāśau nyasetpaścādahorātrātsamuddharet saṃcūrṇya gālayedvastre satyaṃ vāritaraṃ bhavet" },
      { type: "verse", number: "156", sanskrit: "भावयेत्कन्यकाद्रा वैः सप्तधा भृङ्गजैस्तथा काकमाचीकुरण्टोत्थद्र वैर्मुण्ड्याः पुनर्नवैः", text: "bhāvayetkanyakādrā vaiḥ saptadhā bhṛṅgajaistathā kākamācīkuraṇṭotthadra vairmuṇḍyāḥ punarnavaiḥ" },
      { type: "verse", number: "157", sanskrit: "सप्तधा तु पृथग्द्रा वैर्भाव्यं शोष्यं तथातपे", text: "saptadhā tu pṛthagdrā vairbhāvyaṃ śoṣyaṃ tathātape" },
      { type: "verse", number: "158", sanskrit: "सिद्धयोगो ह्ययं ख्यातः सिद्धानां च मुखागतः अनुभूतो मया सत्यं सर्वरोगगणापहः", text: "siddhayogo hyayaṃ khyātaḥ siddhānāṃ ca mukhāgataḥ anubhūto mayā satyaṃ sarvarogagaṇāpahaḥ" },
      { type: "verse", number: "159", sanskrit: "स्वर्णादीन्मारयेदेवं चूर्णीकृत्य तु लोहवत् त्रिफलामधुसंयुक्तः सर्वरोगेषु योजयेत्", text: "svarṇādīnmārayedevaṃ cūrṇīkṛtya tu lohavat triphalāmadhusaṃyuktaḥ sarvarogeṣu yojayet" },
      { type: "verse", number: "160", sanskrit: "समभागोन्मितैरेतैः समः पूर्वरसो भवेत्", text: "samabhāgonmitairetaiḥ samaḥ pūrvaraso bhavet" },
      { type: "verse", number: "161", sanskrit: "संचूर्ण्य लेहयेत्क्षौद्रै र्भक्ष्यं निष्कद्वयं द्वयम् स्वयमग्निरसो नाम्ना क्षयकासनिकृन्तनः", text: "saṃcūrṇya lehayetkṣaudrai rbhakṣyaṃ niṣkadvayaṃ dvayam svayamagniraso nāmnā kṣayakāsanikṛntanaḥ" },
      { type: "verse", number: "162", sanskrit: "पारदं गन्धकं शुद्धं मृतलोहं च टङ्कणम् रास्ना विडङ्गत्रिफला देवदारु कटुत्रयम्", text: "pāradaṃ gandhakaṃ śuddhaṃ mṛtalohaṃ ca ṭaṅkaṇam rāsnā viḍaṅgatriphalā devadāru kaṭutrayam" },
      { type: "verse", number: "163", sanskrit: "अमृता पद्मकं क्षौद्रं  विश्वं तुल्यांशचूर्णितम् त्रिगुञ्जं सर्वकासार्त्तः सेवयेदमृतार्णवम्", text: "amṛtā padmakaṃ kṣaudraṃ  viśvaṃ tulyāṃśacūrṇitam triguñjaṃ sarvakāsārttaḥ sevayedamṛtārṇavam" },
      { type: "verse", number: "164", sanskrit: "सूतार्धो गन्धको मर्द्यो यामैकं कन्यकाद्र वैः द्वयोस्तुल्यं ताम्रपत्रं पूर्वकल्केन लेपयेत्", text: "sūtārdho gandhako mardyo yāmaikaṃ kanyakādra vaiḥ dvayostulyaṃ tāmrapatraṃ pūrvakalkena lepayet" },
      { type: "verse", number: "165", sanskrit: "दिनैकंस्थालिकायन्त्रे पक्वमादाय चूर्णयेत् सूर्यावर्त्तो रसो ह्येष द्विगुञ्जः श्वासजिद्भवेत्", text: "dinaikaṃsthālikāyantre pakvamādāya cūrṇayet sūryāvartto raso hyeṣa dviguñjaḥ śvāsajidbhavet" },
      { type: "verse", number: "166", sanskrit: "शुद्धं सूतं मृतं लोहं ताप्यं गन्धकतालके पथ्याऽग्निमन्थं निर्गुडी त्र्! यूषणं टङ्कणं विषम्", text: "śuddhaṃ sūtaṃ mṛtaṃ lohaṃ tāpyaṃ gandhakatālake pathyā'gnimanthaṃ nirguḍī tr! yūṣaṇaṃ ṭaṅkaṇaṃ viṣam" },
      { type: "verse", number: "167", sanskrit: "तुल्यांशं मर्दयेत्खल्वे दिनं निर्गुण्डिकाद्र वैः मुण्डीद्रा वैर्दिनैकं तु द्विगुञ्जं वटकीकृतम्", text: "tulyāṃśaṃ mardayetkhalve dinaṃ nirguṇḍikādra vaiḥ muṇḍīdrā vairdinaikaṃ tu dviguñjaṃ vaṭakīkṛtam" },
      { type: "verse", number: "168", sanskrit: "भक्षयेद्वातरोगार्त्तोनाम्ना स्वच्छन्दभैरवम् रास्नाऽमृतादेवदारुशुण्ठीवातारिजं शृतम् सगुग्गुलुं पिबेत्कोष्णमनुपानं सुखावहम्", text: "bhakṣayedvātarogārttonāmnā svacchandabhairavam rāsnā'mṛtādevadāruśuṇṭhīvātārijaṃ śṛtam sagugguluṃ pibetkoṣṇamanupānaṃ sukhāvaham" },
      { type: "verse", number: "169", sanskrit: "दग्धान्कपर्दिकान्पिष्ट्वा त्र्! यूषणं टङ्कणं विषम् गन्धकं शुद्धसूतं च तुल्यं जम्बीरजैर्द्र वैः", text: "dagdhānkapardikānpiṣṭvā tr! yūṣaṇaṃ ṭaṅkaṇaṃ viṣam gandhakaṃ śuddhasūtaṃ ca tulyaṃ jambīrajairdra vaiḥ" },
      { type: "verse", number: "170", sanskrit: "मर्दयेद्भक्षेयन्माषं मरिचाज्यं लिहेदनु निहन्ति ग्रहणीरोगं पथ्यं तक्रौदनं हितम्", text: "mardayedbhakṣeyanmāṣaṃ maricājyaṃ lihedanu nihanti grahaṇīrogaṃ pathyaṃ takraudanaṃ hitam" },
      { type: "verse", number: "171", sanskrit: "मृतं ताम्रमजाक्षीरैः पाच्यं तुल्यैर्गतद्र वम् तत्ताम्रं शुद्धसूतं च गन्धकं च समं समम्", text: "mṛtaṃ tāmramajākṣīraiḥ pācyaṃ tulyairgatadra vam tattāmraṃ śuddhasūtaṃ ca gandhakaṃ ca samaṃ samam" },
      { type: "verse", number: "172", sanskrit: "निर्गुण्डीस्वरसैर्मर्द्यं तद्गोलं सन्धयेद्दिनम् यामैकं बालुकायन्त्रे पाच्यं योज्यं द्विगुञ्जकम्", text: "nirguṇḍīsvarasairmardyaṃ tadgolaṃ sandhayeddinam yāmaikaṃ bālukāyantre pācyaṃ yojyaṃ dviguñjakam" },
      { type: "verse", number: "173", sanskrit: "बीजपूरकमूलं तु सजलं चानुपाययेत् रसस्त्रिविक्रमो नाम्ना मासैकेनाश्मरीप्रणुत्", text: "bījapūrakamūlaṃ tu sajalaṃ cānupāyayet rasastrivikramo nāmnā māsaikenāśmarīpraṇut" },
      { type: "verse", number: "174", sanskrit: "तालं ताप्यं शिलां सूतं शुद्धं सैन्धवटङ्कणे समांशं चूर्णयेत्खल्वे सूताद् द्विगुणगन्धकम्", text: "tālaṃ tāpyaṃ śilāṃ sūtaṃ śuddhaṃ saindhavaṭaṅkaṇe samāṃśaṃ cūrṇayetkhalve sūtād dviguṇagandhakam" },
      { type: "verse", number: "175", sanskrit: "गन्धतुल्यं मृतं ताम्रं जम्बीरैर्दिनपञ्चकम् मर्द्यं षड्भिः पुटैः पाच्यं भूधरे संपुटोदरे", text: "gandhatulyaṃ mṛtaṃ tāmraṃ jambīrairdinapañcakam mardyaṃ ṣaḍbhiḥ puṭaiḥ pācyaṃ bhūdhare saṃpuṭodare" },
      { type: "verse", number: "176", sanskrit: "पुटे पुटे द्र वैर्मर्द्यं सर्वमेतत्तु षट्पलम् द्विपलं मारितं ताम्रं लोहभस्म चतुष्पलम्", text: "puṭe puṭe dra vairmardyaṃ sarvametattu ṣaṭpalam dvipalaṃ māritaṃ tāmraṃ lohabhasma catuṣpalam" },
      { type: "verse", number: "177", sanskrit: "जम्बीराम्लेन तत्सर्वं दिनं मर्द्यं पुटेल्लघु त्रिंशदंशं विषं चास्य क्षिप्त्वा सर्वं विचूर्णयेत्", text: "jambīrāmlena tatsarvaṃ dinaṃ mardyaṃ puṭellaghu triṃśadaṃśaṃ viṣaṃ cāsya kṣiptvā sarvaṃ vicūrṇayet" },
      { type: "verse", number: "178", sanskrit: "माहिषाज्येन संमिश्रं निष्कार्धं भक्षयेत्सदा मध्वाज्यैर्वाकुचीचूर्णं कर्षमात्रं लिहेदनु", text: "māhiṣājyena saṃmiśraṃ niṣkārdhaṃ bhakṣayetsadā madhvājyairvākucīcūrṇaṃ karṣamātraṃ lihedanu" },
      { type: "verse", number: "179", sanskrit: "सर्वकुष्ठानि हन्त्याशु महातालेश्वरो रसः", text: "sarvakuṣṭhāni hantyāśu mahātāleśvaro rasaḥ" },
      { type: "verse", number: "180", sanskrit: "भस्मसूतसमो गन्धो मृतायस्ताम्रगुग्गुलुः त्रिफला च महानिम्बश्चित्रकश्चशिलाजतु इत्येतच्चूर्णितं कुर्यात्प्रत्येकं शाणषोडशम्", text: "bhasmasūtasamo gandho mṛtāyastāmragugguluḥ triphalā ca mahānimbaścitrakaścaśilājatu ityetaccūrṇitaṃ kuryātpratyekaṃ śāṇaṣoḍaśam" },
      { type: "verse", number: "181", sanskrit: "चतुःषष्टिः करञ्जस्य बीजचूर्णं प्रकल्पयेत् चतुःषष्टिमृतं चाभ्रं मध्वाज्याभ्यां विलोडयेत्", text: "catuḥṣaṣṭiḥ karañjasya bījacūrṇaṃ prakalpayet catuḥṣaṣṭimṛtaṃ cābhraṃ madhvājyābhyāṃ viloḍayet" },
      { type: "verse", number: "182", sanskrit: "स्निग्धे भाण्डे धृतं खादेद् द्विनिष्कं सर्वकुष्ठनुत् रसः कुष्ठकुठारोऽय गलत्कुष्ठनिवारणः", text: "snigdhe bhāṇḍe dhṛtaṃ khāded dviniṣkaṃ sarvakuṣṭhanut rasaḥ kuṣṭhakuṭhāro'ya galatkuṣṭhanivāraṇaḥ" },
      { type: "verse", number: "183", sanskrit: "श्वेतकुष्ठादौ उदयादित्यो रसः शुद्धं सूतं द्विधा गन्धं मर्द्यं कन्याद्र वैर्दिनम् तद्गोलं पिठरीमध्ये ताम्रपात्रेण रोधयेत्", text: "śvetakuṣṭhādau udayādityo rasaḥ śuddhaṃ sūtaṃ dvidhā gandhaṃ mardyaṃ kanyādra vairdinam tadgolaṃ piṭharīmadhye tāmrapātreṇa rodhayet" },
      { type: "verse", number: "184", sanskrit: "सूतकाद् द्विगुणेनैव शुद्धेनाधोमुखेन च पार्श्वे भस्म निधायाथ पात्रोर्ध्वं गोमयं जलम्", text: "sūtakād dviguṇenaiva śuddhenādhomukhena ca pārśve bhasma nidhāyātha pātrordhvaṃ gomayaṃ jalam" },
      { type: "verse", number: "185", sanskrit: "किञ्चित् किञ्चित्प्रदातव्यं चुल्ल्यां यामद्वयं पचेत् चण्डाग्निना तदुद्धृत्य स्वाङ्गशीतं विचूर्णयेत्", text: "kiñcit kiñcitpradātavyaṃ cullyāṃ yāmadvayaṃ pacet caṇḍāgninā taduddhṛtya svāṅgaśītaṃ vicūrṇayet" },
      { type: "verse", number: "186", sanskrit: "विडङ्गं वाकुचीबीजं क्वाथयेत्तेन भावयेत्", text: "viḍaṅgaṃ vākucībījaṃ kvāthayettena bhāvayet" },
      { type: "verse", number: "187", sanskrit: "दिनैकमुदयादित्योरसो देयो द्विगुञ्जकः विचर्चिकां दद्रुकुष्ठं वातरक्तं च नाशयेत्", text: "dinaikamudayādityoraso deyo dviguñjakaḥ vicarcikāṃ dadrukuṣṭhaṃ vātaraktaṃ ca nāśayet" },
      { type: "verse", number: "188", sanskrit: "अनुपानं च कर्तव्यं वाकुचीफलचूर्णकम् खदिरस्य कषायेण समेन परिपाचितम्", text: "anupānaṃ ca kartavyaṃ vākucīphalacūrṇakam khadirasya kaṣāyeṇa samena paripācitam" },
      { type: "verse", number: "189", sanskrit: "त्रिशाणं तद् गवां क्षीरैः क्वाथैर्वा त्रैफलैः पिबेत् त्रिदिनान्ते भवेत्स्फोटः सप्ताहाद्वा किलासके", text: "triśāṇaṃ tad gavāṃ kṣīraiḥ kvāthairvā traiphalaiḥ pibet tridinānte bhavetsphoṭaḥ saptāhādvā kilāsake" },
      { type: "verse", number: "190", sanskrit: "नीलद्यं गुञ्जां च कासीसं धत्तूरं हंसपादिकाम् सूर्यभक्तां च चाङ्गेरीं पिष्ट्वा मूलानिलेपयेत्", text: "nīladyaṃ guñjāṃ ca kāsīsaṃ dhattūraṃ haṃsapādikām sūryabhaktāṃ ca cāṅgerīṃ piṣṭvā mūlānilepayet" },
      { type: "verse", number: "191", sanskrit: "स्फोटस्थानप्रशान्त्यर्थं सप्तरात्रं पुनः पुनः श्वेतकुष्ठं निहन्त्याशु साध्यासाध्यं न संशयः", text: "sphoṭasthānapraśāntyarthaṃ saptarātraṃ punaḥ punaḥ śvetakuṣṭhaṃ nihantyāśu sādhyāsādhyaṃ na saṃśayaḥ" },
      { type: "verse", number: "192", sanskrit: "अपरः श्वित्रलेपोऽपि कथ्यतेऽत्र भिषग्वरैः गुञ्जाफलाग्निचूर्णं च लेपितं श्वेतकुष्ठनुत्", text: "aparaḥ śvitralepo'pi kathyate'tra bhiṣagvaraiḥ guñjāphalāgnicūrṇaṃ ca lepitaṃ śvetakuṣṭhanut" },
      { type: "verse", number: "193", sanskrit: "शिलाऽपामार्गभस्मापि लिप्तं श्वित्रं विनाशयेत्", text: "śilā'pāmārgabhasmāpi liptaṃ śvitraṃ vināśayet" },
      { type: "verse", number: "194", sanskrit: "शुद्धं सूतं चतुर्गन्धं पलं यामं विचूर्णयेत् मृतताम्राभ्रलोहानां दरदस्य पलं पलम् सुवर्णं रजतं चैव प्रत्येकं दशनिष्ककम्", text: "śuddhaṃ sūtaṃ caturgandhaṃ palaṃ yāmaṃ vicūrṇayet mṛtatāmrābhralohānāṃ daradasya palaṃ palam suvarṇaṃ rajataṃ caiva pratyekaṃ daśaniṣkakam" },
      { type: "verse", number: "195", sanskrit: "माषैकं मृतवज्रं च तालं शुद्धं पलद्वयम् जम्बीरोन्मत्तवासाभिः स्नुह्यर्क विषमुष्टिभिः", text: "māṣaikaṃ mṛtavajraṃ ca tālaṃ śuddhaṃ paladvayam jambīronmattavāsābhiḥ snuhyarka viṣamuṣṭibhiḥ" },
      { type: "verse", number: "196", sanskrit: "मर्द्यं हयारिजैद्रा र्वैः! प्रत्येकेन दिनं दिनम् एवं सप्तदिनं मर्द्यं तद्गोलं वस्त्रवेष्टितम्", text: "mardyaṃ hayārijaidrā rvaiḥ! pratyekena dinaṃ dinam evaṃ saptadinaṃ mardyaṃ tadgolaṃ vastraveṣṭitam" },
      { type: "verse", number: "197", sanskrit: "वालुकायन्त्रगं स्वेद्यं त्रिदिनं लघुवह्निना आदाय चूर्णयेच्छ्लक्ष्णं पलैकं योजयेद्विषम्", text: "vālukāyantragaṃ svedyaṃ tridinaṃ laghuvahninā ādāya cūrṇayecchlakṣṇaṃ palaikaṃ yojayedviṣam" },
      { type: "verse", number: "198", sanskrit: "द्विपलं पिप्पलीचूर्णं मिश्रं सर्वेश्वरो रसः द्विगुञ्जो लिह्यते क्षौद्रै ः! सुप्तिमण्डलकुष्ठनुत्", text: "dvipalaṃ pippalīcūrṇaṃ miśraṃ sarveśvaro rasaḥ dviguñjo lihyate kṣaudrai ḥ! suptimaṇḍalakuṣṭhanut" },
      { type: "verse", number: "199", sanskrit: "वाकुचीदेवकाष्ठं च कर्षमात्रं सुचूर्णयेत् लिहेदैरण्डतैलाक्तमनुपानं सुखावहम्", text: "vākucīdevakāṣṭhaṃ ca karṣamātraṃ sucūrṇayet lihedairaṇḍatailāktamanupānaṃ sukhāvaham" },
      { type: "verse", number: "200", sanskrit: "हेमाह्वां पञ्चपलिकां क्षिप्त्वा तक्रघटे पचेत् तक्रे जीर्णे समुद्धृत्य पुनः क्षीरघटे पचेत्", text: "hemāhvāṃ pañcapalikāṃ kṣiptvā takraghaṭe pacet takre jīrṇe samuddhṛtya punaḥ kṣīraghaṭe pacet" },
      { type: "verse", number: "201", sanskrit: "क्षीरे जीर्णे समुद्धृत्य क्षालयित्वा विशोषयेत् तच्चूर्णं पञ्चपलिकं मरिचानां पलद्वयम्", text: "kṣīre jīrṇe samuddhṛtya kṣālayitvā viśoṣayet taccūrṇaṃ pañcapalikaṃ maricānāṃ paladvayam" },
      { type: "verse", number: "202", sanskrit: "पलैकं मूर्च्छितं सूतमेकीकृत्य तु भक्षयेत् निष्कैकं सुप्तिकुष्ठार्त्तः स्वर्णक्षीरीरसो ह्ययम्", text: "palaikaṃ mūrcchitaṃ sūtamekīkṛtya tu bhakṣayet niṣkaikaṃ suptikuṣṭhārttaḥ svarṇakṣīrīraso hyayam" },
      { type: "verse", number: "203", sanskrit: "भस्मसूतं मृतं कान्तं मुण्डभस्म शिलाजतु शुद्धं ताप्यं शिलां व्योषं त्रिफलां कोलबीजकम्", text: "bhasmasūtaṃ mṛtaṃ kāntaṃ muṇḍabhasma śilājatu śuddhaṃ tāpyaṃ śilāṃ vyoṣaṃ triphalāṃ kolabījakam" },
      { type: "verse", number: "204", sanskrit: "कपित्थं रजनीचूर्णं भृङ्गराजेन भावयेत् विंशद्वारं विशोष्याथ मधुयुक्तं लिहेत्सदा", text: "kapitthaṃ rajanīcūrṇaṃ bhṛṅgarājena bhāvayet viṃśadvāraṃ viśoṣyātha madhuyuktaṃ lihetsadā" },
      { type: "verse", number: "205", sanskrit: "निष्कमात्रो हरेन्मेहान्मेहबद्धो रसो महान् महानिम्बस्य बीजानि पिष्ट्वा षट्सम्मितानि च", text: "niṣkamātro harenmehānmehabaddho raso mahān mahānimbasya bījāni piṣṭvā ṣaṭsammitāni ca" },
      { type: "verse", number: "206", sanskrit: "पलतण्डुलतोयेन घृतनिष्कद्वयेन च एकीकृत्य पिबेच्चानु हन्ति मेहं चिरन्तनम्", text: "palataṇḍulatoyena ghṛtaniṣkadvayena ca ekīkṛtya pibeccānu hanti mehaṃ cirantanam" },
      { type: "verse", number: "207", sanskrit: "चतुःसूतस्य गन्धाष्टौ रजनी त्रिफला शिवा प्रत्येकं च द्विभागं स्यात्त्रिवृज्जैपालचित्रकम्", text: "catuḥsūtasya gandhāṣṭau rajanī triphalā śivā pratyekaṃ ca dvibhāgaṃ syāttrivṛjjaipālacitrakam" },
      { type: "verse", number: "208", sanskrit: "प्रत्येकं च त्रिभागं स्यात् त्र्! यूषणं दन्तिजीरके प्रत्येकमष्टभागं स्यादेकीकृत्य विचूर्णयेत्", text: "pratyekaṃ ca tribhāgaṃ syāt tr! yūṣaṇaṃ dantijīrake pratyekamaṣṭabhāgaṃ syādekīkṛtya vicūrṇayet" },
      { type: "verse", number: "209", sanskrit: "प्रत्येकेन क्रमाद्भाव्यं सप्तवारं पृथक्पृथक्", text: "pratyekena kramādbhāvyaṃ saptavāraṃ pṛthakpṛthak" },
      { type: "verse", number: "210", sanskrit: "महावह्निरसो नाम निष्कमुष्णजलैः पिबेत् विरेचनं भवेत्तेन तक्रभक्तं ससैन्धवम्", text: "mahāvahniraso nāma niṣkamuṣṇajalaiḥ pibet virecanaṃ bhavettena takrabhaktaṃ sasaindhavam" },
      { type: "verse", number: "211", sanskrit: "दिनान्ते दापयेत्पथ्यं वर्जयेच्छीतलं जलम् सर्वोदरहरः प्रोक्तो मूढवातहरः परः", text: "dinānte dāpayetpathyaṃ varjayecchītalaṃ jalam sarvodaraharaḥ prokto mūḍhavātaharaḥ paraḥ" },
      { type: "verse", number: "212", sanskrit: "गन्धकं तालकं ताप्यं मृतताम्रं मनः शिलाम् शुद्धं सूतं च तुल्यांशं मर्दयेद्भावयेद् दिनम्", text: "gandhakaṃ tālakaṃ tāpyaṃ mṛtatāmraṃ manaḥ śilām śuddhaṃ sūtaṃ ca tulyāṃśaṃ mardayedbhāvayed dinam" },
      { type: "verse", number: "213", sanskrit: "पिप्पल्यास्तु कषायेण वज्रीक्षीरेण भावयेत् निष्कार्धं भक्षयेत्क्षौद्रै र्गुल्मप्लीहादिकं जयेत्", text: "pippalyāstu kaṣāyeṇa vajrīkṣīreṇa bhāvayet niṣkārdhaṃ bhakṣayetkṣaudrai rgulmaplīhādikaṃ jayet" },
      { type: "verse", number: "214", sanskrit: "रसो विद्याधरो नाम गोमूत्रं च पिबेदनु", text: "raso vidyādharo nāma gomūtraṃ ca pibedanu" },
      { type: "verse", number: "215", sanskrit: "टङ्कणं हारिणं शृङ्गं स्वर्णं शुल्बं मृतं रसम् दिनैकमार्द्र कद्रा वैर्मर्द्यं रुद्ध्वा पुटे पचेत् त्रिनेत्राख्यरसस्यैकं माषं मध्वाज्यकैर्लिहेत्", text: "ṭaṅkaṇaṃ hāriṇaṃ śṛṅgaṃ svarṇaṃ śulbaṃ mṛtaṃ rasam dinaikamārdra kadrā vairmardyaṃ ruddhvā puṭe pacet trinetrākhyarasasyaikaṃ māṣaṃ madhvājyakairlihet" },
      { type: "verse", number: "216", sanskrit: "सैन्धवं जीरकं हिंगु मध्वाज्याभ्यां लिहेदनु पक्तिशूलहरः ख्यातो मासमात्रान्न संशयः", text: "saindhavaṃ jīrakaṃ hiṃgu madhvājyābhyāṃ lihedanu paktiśūlaharaḥ khyāto māsamātrānna saṃśayaḥ" },
      { type: "verse", number: "217", sanskrit: "शुद्धं सूतं द्विधा गन्धं यामैकं मर्दयेद् दृढम् द्वयोस्तुल्यं शुद्धताम्रं सम्पुटे तन्निरोधयेत्", text: "śuddhaṃ sūtaṃ dvidhā gandhaṃ yāmaikaṃ mardayed dṛḍham dvayostulyaṃ śuddhatāmraṃ sampuṭe tannirodhayet" },
      { type: "verse", number: "218", sanskrit: "ऊर्ध्वाधो लवणं दत्त्वा मृद्भाण्डे धारयेद्भिषक् ततो गजपुटे पक्त्वा स्वाङ्गशीतं समुद्धरेत्", text: "ūrdhvādho lavaṇaṃ dattvā mṛdbhāṇḍe dhārayedbhiṣak tato gajapuṭe paktvā svāṅgaśītaṃ samuddharet" },
      { type: "verse", number: "219", sanskrit: "सम्पुटं चूर्णयेत्सूक्ष्मं पर्णखण्डे द्विगुञ्जकम् भक्षयेत्सर्वशूलार्त्तो हिङ्गु शुण्ठी च जीरकम्", text: "sampuṭaṃ cūrṇayetsūkṣmaṃ parṇakhaṇḍe dviguñjakam bhakṣayetsarvaśūlārtto hiṅgu śuṇṭhī ca jīrakam" },
      { type: "verse", number: "220", sanskrit: "वचामरिचजं चूर्णं कर्षमुष्णजलैः पिबेत् असाध्यं नाशयेच्छूलं रसोऽय गजकेसरी", text: "vacāmaricajaṃ cūrṇaṃ karṣamuṣṇajalaiḥ pibet asādhyaṃ nāśayecchūlaṃ raso'ya gajakesarī" },
      { type: "verse", number: "221", sanskrit: "अग्निमान्द्यादौ अग्नितुण्डीवटीरसः शुद्धं सूतं विषं गन्धमजमोदां फलत्रयम् स्वर्जिक्षारं यवक्षारं वह्निसैन्धवजीरकम्", text: "agnimāndyādau agnituṇḍīvaṭīrasaḥ śuddhaṃ sūtaṃ viṣaṃ gandhamajamodāṃ phalatrayam svarjikṣāraṃ yavakṣāraṃ vahnisaindhavajīrakam" },
      { type: "verse", number: "222", sanskrit: "सौवर्चलं विडङ्गानि सामुद्रं  त्र्! यूषणं समम् विषमुष्टिं सर्वतुल्यां जम्बीराम्लेन मर्दयेत्", text: "sauvarcalaṃ viḍaṅgāni sāmudraṃ  tr! yūṣaṇaṃ samam viṣamuṣṭiṃ sarvatulyāṃ jambīrāmlena mardayet" },
      { type: "verse", number: "223", sanskrit: "मरिचाभां वटीं खादेद्वह्निमान्द्यप्रशान्तये", text: "maricābhāṃ vaṭīṃ khādedvahnimāndyapraśāntaye" },
      { type: "verse", number: "224", sanskrit: "शुद्धसूतं विषं गन्धं समं सर्वं विचूर्णयेत् मरिचं सर्वतुल्यांशं कण्टकार्याः फलद्र वैः", text: "śuddhasūtaṃ viṣaṃ gandhaṃ samaṃ sarvaṃ vicūrṇayet maricaṃ sarvatulyāṃśaṃ kaṇṭakāryāḥ phaladra vaiḥ" },
      { type: "verse", number: "225", sanskrit: "वटीं गुञ्जात्रयं खादेत्सर्वाजीर्णप्रशान्तये अजीर्णकण्टकः सोऽय रसो हन्ति विषूचिकाम्", text: "vaṭīṃ guñjātrayaṃ khādetsarvājīrṇapraśāntaye ajīrṇakaṇṭakaḥ so'ya raso hanti viṣūcikām" },
      { type: "verse", number: "226", sanskrit: "मृतं सूतं मृतं ताम्रं हिङ्गु पुष्करमूलकम् सैन्धवं गन्धकं तालं कटुकीं चूर्णयेत्समम्", text: "mṛtaṃ sūtaṃ mṛtaṃ tāmraṃ hiṅgu puṣkaramūlakam saindhavaṃ gandhakaṃ tālaṃ kaṭukīṃ cūrṇayetsamam" },
      { type: "verse", number: "227", sanskrit: "तिक्तकोशातकीद्रा वैर्दिनैकं मर्दयेद् दृढम्", text: "tiktakośātakīdrā vairdinaikaṃ mardayed dṛḍham" },
      { type: "verse", number: "228", sanskrit: "माषमात्रं लिहेत्क्षौद्रै  रसं मन्थानभैरवम् कफरोगप्रशान्त्यर्थं निम्बक्वाथं पिबेदनु", text: "māṣamātraṃ lihetkṣaudrai  rasaṃ manthānabhairavam kapharogapraśāntyarthaṃ nimbakvāthaṃ pibedanu" },
      { type: "verse", number: "229", sanskrit: "सूतहाटकवज्राणि ताम्रं लोहं च माक्षिकम् तालं नीलाञ्जनं तुत्थमहिफेनं समांशकम्", text: "sūtahāṭakavajrāṇi tāmraṃ lohaṃ ca mākṣikam tālaṃ nīlāñjanaṃ tutthamahiphenaṃ samāṃśakam" },
      { type: "verse", number: "230", sanskrit: "पञ्चानां लवणानां च भागमेकं विमर्दयेत् वज्रीक्षीरैर्दिनैकं तु रुद्ध्वाऽधो भूधरे पचेत्", text: "pañcānāṃ lavaṇānāṃ ca bhāgamekaṃ vimardayet vajrīkṣīrairdinaikaṃ tu ruddhvā'dho bhūdhare pacet" },
      { type: "verse", number: "231", sanskrit: "माषैकमार्द्र कद्रा वैर्लेहयेद्वातनाशनम् पिप्पलीमूलजक्वाथं सकृष्णमनुपाययेत्", text: "māṣaikamārdra kadrā vairlehayedvātanāśanam pippalīmūlajakvāthaṃ sakṛṣṇamanupāyayet" },
      { type: "verse", number: "232", sanskrit: "सर्वान्वातविकारांस्तु निहन्त्याक्षेपकादिकान्", text: "sarvānvātavikārāṃstu nihantyākṣepakādikān" },
      { type: "verse", number: "233", sanskrit: "कनकस्याष्टशाणाः स्युः सूतो द्वादशभिर्मतः गन्धोऽपि द्वादश प्रोक्तस्ताम्रंशाणद्वयोन्मितम् अभ्रकं स्याच्चतुः शाणं माक्षिकं च द्विशाणिकम्", text: "kanakasyāṣṭaśāṇāḥ syuḥ sūto dvādaśabhirmataḥ gandho'pi dvādaśa proktastāmraṃśāṇadvayonmitam abhrakaṃ syāccatuḥ śāṇaṃ mākṣikaṃ ca dviśāṇikam" },
      { type: "verse", number: "234", sanskrit: "वङ्गो द्विशाणः सौबीरं त्रिशाणं लोहमष्टकम् विषं त्रिशाणिकं कृत्वा लाङ्गली पलसंमिता", text: "vaṅgo dviśāṇaḥ saubīraṃ triśāṇaṃ lohamaṣṭakam viṣaṃ triśāṇikaṃ kṛtvā lāṅgalī palasaṃmitā" },
      { type: "verse", number: "235", sanskrit: "मर्दयेद्दिनमेकं च रसैरम्लफलोद्भवैः दद्यान्मृदुपुटं वह्नौ ततः सूक्ष्मं विचूर्णयेत्", text: "mardayeddinamekaṃ ca rasairamlaphalodbhavaiḥ dadyānmṛdupuṭaṃ vahnau tataḥ sūkṣmaṃ vicūrṇayet" },
      { type: "verse", number: "236", sanskrit: "माषमात्रो रसो देयः सन्निपाते सुदारुणे आर्द्र कस्वरसेनैव रसोनस्य रसेन वा", text: "māṣamātro raso deyaḥ sannipāte sudāruṇe ārdra kasvarasenaiva rasonasya rasena vā" },
      { type: "verse", number: "237", sanskrit: "किलासं सर्वकुष्ठानि विसर्पं च भगन्दरम् ज्वरं गरमजीर्णं च जयेद्रो गहरो रसः", text: "kilāsaṃ sarvakuṣṭhāni visarpaṃ ca bhagandaram jvaraṃ garamajīrṇaṃ ca jayedro gaharo rasaḥ" },
      { type: "verse", number: "238", sanskrit: "रसो गन्धस्त्रिकर्षः स्यात्कुर्यात्कज्जलिकां तयोः ताराभ्रताम्रवङ्गाहिसाराश्चैकैककार्षिकाः", text: "raso gandhastrikarṣaḥ syātkuryātkajjalikāṃ tayoḥ tārābhratāmravaṅgāhisārāścaikaikakārṣikāḥ" },
      { type: "verse", number: "239", sanskrit: "शिग्रुज्वालामुखीशुण्ठी बिल्वेभ्यस्तण्डुलीयकात् प्रत्येकं स्वरसैः कुर्याद्यामैकैकं विमर्दनम्", text: "śigrujvālāmukhīśuṇṭhī bilvebhyastaṇḍulīyakāt pratyekaṃ svarasaiḥ kuryādyāmaikaikaṃ vimardanam" },
      { type: "verse", number: "240", sanskrit: "कृत्वा गोलं वृतं वस्त्रे लवणापूरिते न्यसेत् काचभाण्डे ततः स्थाल्यां काचकूपीं निवेशयेत्", text: "kṛtvā golaṃ vṛtaṃ vastre lavaṇāpūrite nyaset kācabhāṇḍe tataḥ sthālyāṃ kācakūpīṃ niveśayet" },
      { type: "verse", number: "241", sanskrit: "बालुकाभिः प्रपूर्याथ वह्निर्यामद्वयं भवेत् तत उद्धृत्य तं गोलं चूर्णयित्वा विमिश्रयेत्", text: "bālukābhiḥ prapūryātha vahniryāmadvayaṃ bhavet tata uddhṛtya taṃ golaṃ cūrṇayitvā vimiśrayet" },
      { type: "verse", number: "242", sanskrit: "प्रवालचूर्णकर्षेण शाणमात्रविषेण च कृष्णसर्पस्य गरलैर्द्विवेलं भावयेत्तथा", text: "pravālacūrṇakarṣeṇa śāṇamātraviṣeṇa ca kṛṣṇasarpasya garalairdvivelaṃ bhāvayettathā" },
      { type: "verse", number: "243", sanskrit: "तगरं मुशली मांसी हेमाह्वा वेतसः कणा नीलिनी पद्मकं चैला चित्रकश्च कुठेरकः", text: "tagaraṃ muśalī māṃsī hemāhvā vetasaḥ kaṇā nīlinī padmakaṃ cailā citrakaśca kuṭherakaḥ" },
      { type: "verse", number: "244", sanskrit: "शतपुष्पा देवदाली धत्तूरागस्त्यमुण्डिकाः मधूकजातीमदनरसैरेषां विमर्दयेत्", text: "śatapuṣpā devadālī dhattūrāgastyamuṇḍikāḥ madhūkajātīmadanarasaireṣāṃ vimardayet" },
      { type: "verse", number: "245", sanskrit: "प्रत्येकमेकवेलं च ततः संशोष्य धारयेत् बीजपूरार्द्र कद्रा वैर्मरिचैः षोडशोन्मितैः", text: "pratyekamekavelaṃ ca tataḥ saṃśoṣya dhārayet bījapūrārdra kadrā vairmaricaiḥ ṣoḍaśonmitaiḥ" },
      { type: "verse", number: "246", sanskrit: "रसो द्विगुञ्जाप्रमितः सन्निपातेषु दीयते प्रसिद्धोऽय रसो नाम्ना सन्निपातस्य भैरवः", text: "raso dviguñjāpramitaḥ sannipāteṣu dīyate prasiddho'ya raso nāmnā sannipātasya bhairavaḥ" },
      { type: "verse", number: "247", sanskrit: "तारमौक्तिकहेमानि सारश्चैकैकभागकाः द्विभागो गन्धकः सूतस्त्रिभागो मर्दयेदिमान्", text: "tāramauktikahemāni sāraścaikaikabhāgakāḥ dvibhāgo gandhakaḥ sūtastribhāgo mardayedimān" },
      { type: "verse", number: "248", sanskrit: "कपित्थस्वरसैर्गाढं मृगशृङ्गे ततः क्षिपेत् पुटेन्मध्यपुटेनैव तत उद्धृत्य मर्दयेत्", text: "kapitthasvarasairgāḍhaṃ mṛgaśṛṅge tataḥ kṣipet puṭenmadhyapuṭenaiva tata uddhṛtya mardayet" },
      { type: "verse", number: "249", sanskrit: "बलारसैः सप्तवेलमपामार्गरसैस्त्रिधा लोध्रप्रतिविषामुस्तधातकीन्द्र यवामृताः", text: "balārasaiḥ saptavelamapāmārgarasaistridhā lodhraprativiṣāmustadhātakīndra yavāmṛtāḥ" },
      { type: "verse", number: "250", sanskrit: "प्रत्येकमेषां स्वरसैर्भावना स्यात्त्रिधा त्रिधा माषमात्रोरसोदेयोमधुना मरिचैस्तथा", text: "pratyekameṣāṃ svarasairbhāvanā syāttridhā tridhā māṣamātrorasodeyomadhunā maricaistathā" },
      { type: "verse", number: "251", sanskrit: "हन्यात्सर्वानतीसारान्ग्रहणीं सर्वजामपि कपाटो ग्रहणीरोगे रसोऽय वह्निदीपनः", text: "hanyātsarvānatīsārāngrahaṇīṃ sarvajāmapi kapāṭo grahaṇīroge raso'ya vahnidīpanaḥ" },
      { type: "verse", number: "252", sanskrit: "मृतसूताभ्रकं गन्धं यवक्षारं सटङ्कणम् अग्निमन्थं वचां कुर्यात्सूततुल्यानिमान्सुधीः", text: "mṛtasūtābhrakaṃ gandhaṃ yavakṣāraṃ saṭaṅkaṇam agnimanthaṃ vacāṃ kuryātsūtatulyānimānsudhīḥ" },
      { type: "verse", number: "253", sanskrit: "ततो जयन्तीजम्बीरभृङ्गद्रा वैर्विमर्दयेत् त्रिवासरं ततो गोलं कृत्वा संशोष्य धारयेत्", text: "tato jayantījambīrabhṛṅgadrā vairvimardayet trivāsaraṃ tato golaṃ kṛtvā saṃśoṣya dhārayet" },
      { type: "verse", number: "254", sanskrit: "लोहपात्रे शरावं च दत्त्वोपरि विमुद्र येत् अधो वह्निं शनैः कुर्याद्यामार्धं तत उद्धरेत्", text: "lohapātre śarāvaṃ ca dattvopari vimudra yet adho vahniṃ śanaiḥ kuryādyāmārdhaṃ tata uddharet" },
      { type: "verse", number: "255", sanskrit: "रसतुल्यां प्रतिविषां दद्यान्मोचरसं तथा कपित्थविजयाद्रा वैर्भावयेत्सप्तधा पृथक्", text: "rasatulyāṃ prativiṣāṃ dadyānmocarasaṃ tathā kapitthavijayādrā vairbhāvayetsaptadhā pṛthak" },
      { type: "verse", number: "256", sanskrit: "धातकीन्द्र यवा मुस्ता लोध्रं बिल्वं गुडूचिका एतद्र सैर्भावयित्वा वेलैकैकं च शोषयेत्", text: "dhātakīndra yavā mustā lodhraṃ bilvaṃ guḍūcikā etadra sairbhāvayitvā velaikaikaṃ ca śoṣayet" },
      { type: "verse", number: "257", sanskrit: "रसं वज्रकपाटाख्यं शाणैकं मधुना लिहेत् वह्निं शुण्ठीं विडं बिल्वं लवणं चूर्णयेत्समम्", text: "rasaṃ vajrakapāṭākhyaṃ śāṇaikaṃ madhunā lihet vahniṃ śuṇṭhīṃ viḍaṃ bilvaṃ lavaṇaṃ cūrṇayetsamam" },
      { type: "verse", number: "258", sanskrit: "पिबेदुष्णाम्बुना चानु सर्वजां ग्रहणीं जयेत्", text: "pibeduṣṇāmbunā cānu sarvajāṃ grahaṇīṃ jayet" },
      { type: "verse", number: "259", sanskrit: "तारं वज्रं सुवर्णं च ताम्रं सूतकगन्धकम् लोहं क्रमविवृद्धानि कुर्यादेतानि मात्रया", text: "tāraṃ vajraṃ suvarṇaṃ ca tāmraṃ sūtakagandhakam lohaṃ kramavivṛddhāni kuryādetāni mātrayā" },
      { type: "verse", number: "260", sanskrit: "विमर्द्य कन्यकाद्रा वैर्न्यसेत्काचमये घटे विमुच्य पिठरीमध्ये धारयेत्सैन्धवामृते", text: "vimardya kanyakādrā vairnyasetkācamaye ghaṭe vimucya piṭharīmadhye dhārayetsaindhavāmṛte" },
      { type: "verse", number: "261", sanskrit: "पिठरीं मुद्र येत्सम्यक् ततश्चुल्ल्यां निवेशयेत् वह्निं शनैः शनैः कुर्याद्दिनैकं तत उद्धरेत्", text: "piṭharīṃ mudra yetsamyak tataścullyāṃ niveśayet vahniṃ śanaiḥ śanaiḥ kuryāddinaikaṃ tata uddharet" },
      { type: "verse", number: "262", sanskrit: "स्वाङ्गशीतं च सञ्चूर्ण्य भावयेदर्कदुग्धकैः अश्वगन्धा च काकोली वानरी मुसली क्षुरा", text: "svāṅgaśītaṃ ca sañcūrṇya bhāvayedarkadugdhakaiḥ aśvagandhā ca kākolī vānarī musalī kṣurā" },
      { type: "verse", number: "263", sanskrit: "त्रित्रिवेलं रसैरासां शतावर्याश्च भावयेत् पद्मकन्दकसेरूणां रसैः काशस्य भावयेत्", text: "tritrivelaṃ rasairāsāṃ śatāvaryāśca bhāvayet padmakandakaserūṇāṃ rasaiḥ kāśasya bhāvayet" },
      { type: "verse", number: "264", sanskrit: "पूर्वचूर्णादष्टमांशमेतच्चूर्णं विमिश्रयेत्", text: "pūrvacūrṇādaṣṭamāṃśametaccūrṇaṃ vimiśrayet" },
      { type: "verse", number: "265", sanskrit: "सर्वैः समां शर्करां च दत्त्वा शाणोन्मितं पिबेत् गोदुग्धद्विपलेनैव मधुराहारसेवकः", text: "sarvaiḥ samāṃ śarkarāṃ ca dattvā śāṇonmitaṃ pibet godugdhadvipalenaiva madhurāhārasevakaḥ" },
      { type: "verse", number: "266", sanskrit: "अस्य प्रभावात्सौन्दर्यं बलं तेजोऽभिवर्धते तरुणी रमयेद्बह्वीः शुक्रहानिर्न जायते", text: "asya prabhāvātsaundaryaṃ balaṃ tejo'bhivardhate taruṇī ramayedbahvīḥ śukrahānirna jāyate" },
      { type: "verse", number: "267", sanskrit: "सूतो वज्रमहिर्मुक्ता तारं हेमासिताभ्रकम् रसैः कर्षांशकानेतान्मर्दयेदिरिमेदजैः", text: "sūto vajramahirmuktā tāraṃ hemāsitābhrakam rasaiḥ karṣāṃśakānetānmardayedirimedajaiḥ" },
      { type: "verse", number: "268", sanskrit: "प्रवालचूर्णं गन्धश्च द्विद्विकर्षं विमिश्रयेत् ततोऽश्वगन्धास्वरसैर्विमर्द्य मृगशृङ्गके", text: "pravālacūrṇaṃ gandhaśca dvidvikarṣaṃ vimiśrayet tato'śvagandhāsvarasairvimardya mṛgaśṛṅgake" },
      { type: "verse", number: "269", sanskrit: "क्षिप्त्वा मृदुपुटे पक्त्वा भावयेद्धातकीरसैः काकोली मधुकं मांसी बलात्रयबिसेङ्गुदम्", text: "kṣiptvā mṛdupuṭe paktvā bhāvayeddhātakīrasaiḥ kākolī madhukaṃ māṃsī balātrayabiseṅgudam" },
      { type: "verse", number: "270", sanskrit: "द्रा क्षापिप्पलिवन्दाकं वरी पर्णीचतुष्टयम् परूषकं कसेरुश्च मधूकं वानरी तथा", text: "drā kṣāpippalivandākaṃ varī parṇīcatuṣṭayam parūṣakaṃ kaseruśca madhūkaṃ vānarī tathā" },
      { type: "verse", number: "271", sanskrit: "भावयित्वा रसैरेषां शोषयित्वा विचूर्णयेत् एला त्वक्पत्रकं मांसी लवङ्गागुरुकेशरम्", text: "bhāvayitvā rasaireṣāṃ śoṣayitvā vicūrṇayet elā tvakpatrakaṃ māṃsī lavaṅgāgurukeśaram" },
      { type: "verse", number: "272", sanskrit: "मुस्तं मृगमदः कृष्णा जलं चन्द्र श्च मिश्रयेत् एतच्चूर्णैः शाणमितै रसं कन्दर्पसुन्दरम्", text: "mustaṃ mṛgamadaḥ kṛṣṇā jalaṃ candra śca miśrayet etaccūrṇaiḥ śāṇamitai rasaṃ kandarpasundaram" },
      { type: "verse", number: "273", sanskrit: "खादेच्छाणमितं रात्रौ सिता धात्री विदारिका एतासां कर्षचूर्णेन सर्पिष्कर्षेण संयुतम्", text: "khādecchāṇamitaṃ rātrau sitā dhātrī vidārikā etāsāṃ karṣacūrṇena sarpiṣkarṣeṇa saṃyutam" },
      { type: "verse", number: "274", sanskrit: "तस्यानु द्विपलं क्षीरं पिबेत्सुस्थितमानसः रमणी रमयेद्बह्वीः शुक्रहानिर्न जायते", text: "tasyānu dvipalaṃ kṣīraṃ pibetsusthitamānasaḥ ramaṇī ramayedbahvīḥ śukrahānirna jāyate" },
      { type: "verse", number: "275", sanskrit: "शुद्धं रसेन्द्रं  भागैकं द्विभागं शुद्धगन्धकम् क्षिपेत्कज्जलिकां कुर्यात्तत्र तीक्ष्णभवं रजः", text: "śuddhaṃ rasendraṃ  bhāgaikaṃ dvibhāgaṃ śuddhagandhakam kṣipetkajjalikāṃ kuryāttatra tīkṣṇabhavaṃ rajaḥ" },
      { type: "verse", number: "276", sanskrit: "क्षिप्त्वा कज्जलिकातुल्यं प्रहरैकं विमर्दयेत् ततः कन्याद्र वैर्घर्मे त्रिदिनं परिमर्दयेत्", text: "kṣiptvā kajjalikātulyaṃ praharaikaṃ vimardayet tataḥ kanyādra vairgharme tridinaṃ parimardayet" },
      { type: "verse", number: "277", sanskrit: "ततः सञ्जायते तस्य सोष्णो धूमोद्गमो महान् अत्यन्तं पिण्डितं कृत्वा ताम्रपात्रे निधापयेत्", text: "tataḥ sañjāyate tasya soṣṇo dhūmodgamo mahān atyantaṃ piṇḍitaṃ kṛtvā tāmrapātre nidhāpayet" },
      { type: "verse", number: "278", sanskrit: "मध्ये धान्यैकशूकस्य त्रिदिनं धारयेद् बुधः उद्धृत्य तस्मात्खल्वे च क्षिप्त्वा घर्मे निधाय च", text: "madhye dhānyaikaśūkasya tridinaṃ dhārayed budhaḥ uddhṛtya tasmātkhalve ca kṣiptvā gharme nidhāya ca" },
      { type: "verse", number: "279", sanskrit: "रसैः कुठारच्छिन्नायास्त्रिवेलं परिभावयेत् संशोष्य घर्मे क्वाथैश्च भावयेत्त्रिकटोस्त्रिधा", text: "rasaiḥ kuṭhāracchinnāyāstrivelaṃ paribhāvayet saṃśoṣya gharme kvāthaiśca bhāvayettrikaṭostridhā" },
      { type: "verse", number: "280", sanskrit: "वासाऽमृताचित्रकाणां रसैर्भाव्यं क्रमात्त्रिधा लोहपात्रे ततः क्षिप्त्वा भावयेत्त्रिफलाजलैः", text: "vāsā'mṛtācitrakāṇāṃ rasairbhāvyaṃ kramāttridhā lohapātre tataḥ kṣiptvā bhāvayettriphalājalaiḥ" },
      { type: "verse", number: "281", sanskrit: "पलाशकदलीद्रा वैर्बीजकस्य शृतेन च", text: "palāśakadalīdrā vairbījakasya śṛtena ca" },
      { type: "verse", number: "282", sanskrit: "नीलिकाऽलम्बुषाद्रा वैर्बब्बूलफलिकारसैः भावयेत्त्रित्रिवेलं च ततो नागबलारसैः", text: "nīlikā'lambuṣādrā vairbabbūlaphalikārasaiḥ bhāvayettritrivelaṃ ca tato nāgabalārasaiḥ" },
      { type: "verse", number: "283", sanskrit: "ततः प्रातर्लिहेत्क्षौद्र घृताभ्यां कोलमात्रकम् पलमात्रं वराक्वाथं पिबेदस्यानुपानकम्", text: "tataḥ prātarlihetkṣaudra ghṛtābhyāṃ kolamātrakam palamātraṃ varākvāthaṃ pibedasyānupānakam" },
      { type: "verse", number: "284", sanskrit: "मासत्रयं शीलितं स्याद्वलीपलितनाशनम् मन्दाग्निं श्वासकासौ च पाण्डुतां कफमारुतौ", text: "māsatrayaṃ śīlitaṃ syādvalīpalitanāśanam mandāgniṃ śvāsakāsau ca pāṇḍutāṃ kaphamārutau" },
      { type: "verse", number: "285", sanskrit: "पिप्पलीमधुसंयुक्तं हन्यादेतन्न संशयः वातास्रं मूत्रदोषांश्च ग्रहणीं गुदजां रुजम्", text: "pippalīmadhusaṃyuktaṃ hanyādetanna saṃśayaḥ vātāsraṃ mūtradoṣāṃśca grahaṇīṃ gudajāṃ rujam" },
      { type: "verse", number: "286", sanskrit: "अण्डवृद्धिं जयेदेतच्छिन्नासत्त्वमधुप्लुतम् बलवर्णकरं वृष्यमायुष्यं परमं स्मृतम्", text: "aṇḍavṛddhiṃ jayedetacchinnāsattvamadhuplutam balavarṇakaraṃ vṛṣyamāyuṣyaṃ paramaṃ smṛtam" },
      { type: "verse", number: "287", sanskrit: "जयेत्सर्वामयान्कालादिदं लोहरसायनम् कूष्माण्डं तिलतैलं च माषान्नं राजिकां तथा", text: "jayetsarvāmayānkālādidaṃ loharasāyanam kūṣmāṇḍaṃ tilatailaṃ ca māṣānnaṃ rājikāṃ tathā" },
      { type: "verse", number: "288", sanskrit: "मद्यमम्लरसं चैव त्यजेल्लोहस्य सेवकः", text: "madyamamlarasaṃ caiva tyajellohasya sevakaḥ" },
      { type: "verse", number: "289", sanskrit: "जैपालं रहितं त्वगङ्कुररसज्ञाभिर्मले माहिषे निक्षिप्तं त्र्! यहमुष्णतोयविमलं खल्वे सवासोऽदितम् लिप्तं नूतनखर्प रेषु विगतस्नेहं रजःसन्निभं निम्बूकाम्बुविभावितं च बहुशः शुद्धं गुणाढ्यं भवेत्", text: "jaipālaṃ rahitaṃ tvagaṅkurarasajñābhirmale māhiṣe nikṣiptaṃ tr! yahamuṣṇatoyavimalaṃ khalve savāso'ditam liptaṃ nūtanakharpa reṣu vigatasnehaṃ rajaḥsannibhaṃ nimbūkāmbuvibhāvitaṃ ca bahuśaḥ śuddhaṃ guṇāḍhyaṃ bhavet" },
      { type: "verse", number: "290", sanskrit: "विषं तु खण्डशः कृत्वा वस्त्रखण्डेन बन्धयेत् गोमूत्रमध्ये निक्षिप्य स्थापयेदातपे त्र्! यहम्", text: "viṣaṃ tu khaṇḍaśaḥ kṛtvā vastrakhaṇḍena bandhayet gomūtramadhye nikṣipya sthāpayedātape tr! yaham" },
      { type: "verse", number: "291", sanskrit: "गोमूत्रं च प्रदातव्यं नूतनं प्रत्यहं बुधैः त्र्! यहेऽतीते समुद्धृत्य शोषयेन्मृदु पेषयेत् शुद्ध्य्त्येवं विषं तच्च योग्यं भवति चार्त्तिजित्", text: "gomūtraṃ ca pradātavyaṃ nūtanaṃ pratyahaṃ budhaiḥ tr! yahe'tīte samuddhṛtya śoṣayenmṛdu peṣayet śuddhytyevaṃ viṣaṃ tacca yogyaṃ bhavati cārttijit" },
      { type: "verse", number: "292", sanskrit: "खण्डीकृत्य विषं वस्त्रपरिबद्धं तु दोलया", text: "khaṇḍīkṛtya viṣaṃ vastraparibaddhaṃ tu dolayā" },
      { type: "verse", number: "293", sanskrit: "अजापयसि संस्विन्नं यामतः शुद्धिमाप्नुयात् अजादुग्धाभावतस्तु गव्यक्षीरेण शोधयेत्", text: "ajāpayasi saṃsvinnaṃ yāmataḥ śuddhimāpnuyāt ajādugdhābhāvatastu gavyakṣīreṇa śodhayet" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 1,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Вамана видхи — Терапия рвотой" },
      { type: "text", text: "Подробный протокол вамана-кармы (терапевтической рвоты). Подготовка, проведение, признаки успеха и постпроцедурный режим. Шарангадхара уточняет детали для практикующего врача." },
      { type: "verse", number: "1", sanskrit: "अथ स्नेहपानविधिर्नाम प्रथमोऽध्यायः अथ स्नेहस्य भेदास्तत्पानकालश्च स्नेहश्चतुर्विंधः प्रोक्तो घृतं तैलं वसा तथा मज्जा च तं पिबेन्मत्तर्याः किचिदभ्युदिते रवौ", text: "atha snehapānavidhirnāma prathamo'dhyāyaḥ atha snehasya bhedāstatpānakālaśca snehaścaturviṃdhaḥ prokto ghṛtaṃ tailaṃ vasā tathā majjā ca taṃ pibenmattaryāḥ kicidabhyudite ravau" },
      { type: "verse", number: "2", sanskrit: "योनिभेदेन स्नेहस्य द्वैविध्यम् स्थावरो जङ्गमश्चैव द्वियोनिः स्नेह उच्यते", text: "yonibhedena snehasya dvaividhyam sthāvaro jaṅgamaścaiva dviyoniḥ sneha ucyate" },
      { type: "verse", number: "3", sanskrit: "स्थावरजङ्गमयोः श्रेष्ठस्नेहनामनिर्देशः तिलतैलं स्थावरेषु जङ्गमेषु घृतं वरम्", text: "sthāvarajaṅgamayoḥ śreṣṭhasnehanāmanirdeśaḥ tilatailaṃ sthāvareṣu jaṅgameṣu ghṛtaṃ varam" },
      { type: "verse", number: "4", sanskrit: "द्वाभ्यां त्रिभिश्चतुर्भिस्तैर्यमकस्त्रिवृतो महान्", text: "dvābhyāṃ tribhiścaturbhistairyamakastrivṛto mahān" },
      { type: "verse", number: "5", sanskrit: "पिबेत् त्र्! यहं चतुरहं पञ्चाहं षडहं तथा सप्तरात्रात्परं स्नेहं आत्मीभवति सेवितः", text: "pibet tr! yahaṃ caturahaṃ pañcāhaṃ ṣaḍahaṃ tathā saptarātrātparaṃ snehaṃ ātmībhavati sevitaḥ" },
      { type: "verse", number: "6", sanskrit: "दोषकालाग्निवयसां बलं दृष्ट्वा प्रयोजयेत् हीनां च मध्यमां ज्येष्ठां मात्रां स्नेहस्य बुद्धिमान्", text: "doṣakālāgnivayasāṃ balaṃ dṛṣṭvā prayojayet hīnāṃ ca madhyamāṃ jyeṣṭhāṃ mātrāṃ snehasya buddhimān" },
      { type: "verse", number: "7", sanskrit: "अमात्रादिसेवितस्नेहस्य दोषास्तदुपायाश्च अमात्रया तथाऽकाले मिथ्याहारविहारतः स्नेहः करोति शोफार्शस्तन्द्रा निद्रा विसंज्ञताः प्रकुर्याल्लङ्घनं तत्र स्वेदं ज्ञात्वा विरेचनम्", text: "amātrādisevitasnehasya doṣāstadupāyāśca amātrayā tathā'kāle mithyāhāravihārataḥ snehaḥ karoti śophārśastandrā nidrā visaṃjñatāḥ prakuryāllaṅghanaṃ tatra svedaṃ jñātvā virecanam" },
      { type: "verse", number: "8", sanskrit: "देया दीप्ताग्नये मात्रा स्नेहस्य पलसंमिता मध्यमाय त्रिकर्षा स्याज्जघन्याय द्विकार्षिकी", text: "deyā dīptāgnaye mātrā snehasya palasaṃmitā madhyamāya trikarṣā syājjaghanyāya dvikārṣikī" },
      { type: "verse", number: "9", sanskrit: "स्नेहपानमात्राया अन्ये भेदाः अथवा स्नेहमात्राः स्युस्तिस्रोऽन्या सर्वसम्मताः अहोरात्रेण महती जीर्यत्यह्नि तु मध्यमा जीर्यत्यल्पा दिनार्धेन सा विज्ञेया सुखावहा", text: "snehapānamātrāyā anye bhedāḥ athavā snehamātrāḥ syustisro'nyā sarvasammatāḥ ahorātreṇa mahatī jīryatyahni tu madhyamā jīryatyalpā dinārdhena sā vijñeyā sukhāvahā" },
      { type: "verse", number: "10", sanskrit: "अल्पा स्याद्दीपनी वृष्या स्वल्पदोषेषु पूजिता मध्यमा स्नेहनी ज्ञेया बृंहणी भ्रमहारिणी", text: "alpā syāddīpanī vṛṣyā svalpadoṣeṣu pūjitā madhyamā snehanī jñeyā bṛṃhaṇī bhramahāriṇī" },
      { type: "verse", number: "11", sanskrit: "ज्येष्ठा कुष्ठविषोन्मादग्रहापस्मारनाशिनी", text: "jyeṣṭhā kuṣṭhaviṣonmādagrahāpasmāranāśinī" },
      { type: "verse", number: "12", sanskrit: "दोषानुसारेण घृतपानेऽनुपानव्यवस्था केवलं पैत्तिके सर्पिर्वातिके लवणान्वितम् पेयं बहुकफे चापि व्योषक्षारसमन्वितम्", text: "doṣānusāreṇa ghṛtapāne'nupānavyavasthā kevalaṃ paittike sarpirvātike lavaṇānvitam peyaṃ bahukaphe cāpi vyoṣakṣārasamanvitam" },
      { type: "verse", number: "13", sanskrit: "रूक्षक्षतविषार्त्तानां वातपित्तविकारिणाम् हीनमेधास्मृतीनां च सर्पिष्पानं प्रशस्यते", text: "rūkṣakṣataviṣārttānāṃ vātapittavikāriṇām hīnamedhāsmṛtīnāṃ ca sarpiṣpānaṃ praśasyate" },
      { type: "verse", number: "14", sanskrit: "कृमिकोष्ठानिलाविष्टाः प्रवृद्धकफमेदसः पिबेयुस्तैलसात्म्या ये तैलं दार्ढ्यार्थिनस्तु ये", text: "kṛmikoṣṭhānilāviṣṭāḥ pravṛddhakaphamedasaḥ pibeyustailasātmyā ye tailaṃ dārḍhyārthinastu ye" },
      { type: "verse", number: "15", sanskrit: "व्यायामकर्षिताः शुष्करेतोरक्ता महारुजः महाग्निमारुतप्राणा वसायोग्या नराः स्मृताः", text: "vyāyāmakarṣitāḥ śuṣkaretoraktā mahārujaḥ mahāgnimārutaprāṇā vasāyogyā narāḥ smṛtāḥ" },
      { type: "verse", number: "16", sanskrit: "क्रूराशयाः क्लेशसहा वातार्त्ता दीप्तवह्नयः मज्जानं च पिबेयुस्ते सपिर्वा सर्वतो हितम्", text: "krūrāśayāḥ kleśasahā vātārttā dīptavahnayaḥ majjānaṃ ca pibeyuste sapirvā sarvato hitam" },
      { type: "verse", number: "17", sanskrit: "शीतकाले दिवा स्नेहमुष्णकाले पिबेन्निशि वातपित्ताधिके रात्रौ वातश्लेष्माधिके दिवा", text: "śītakāle divā snehamuṣṇakāle pibenniśi vātapittādhike rātrau vātaśleṣmādhike divā" },
      { type: "verse", number: "18", sanskrit: "तैलं घृतं वा युञ्जीत दृष्ट्वा दोषबलाबलम्", text: "tailaṃ ghṛtaṃ vā yuñjīta dṛṣṭvā doṣabalābalam" },
      { type: "verse", number: "19", sanskrit: "घृते कोष्णजलं पेयं तैले यूषः प्रशस्यते वसामज्ज्ञोः पिबेन्मण्डमनुपानं सुखावहम्", text: "ghṛte koṣṇajalaṃ peyaṃ taile yūṣaḥ praśasyate vasāmajjñoḥ pibenmaṇḍamanupānaṃ sukhāvaham" },
      { type: "verse", number: "20", sanskrit: "स्नेहद्विषः शिशून्वृद्धान्सुकुमारान्कृशानपि उष्णकामानुष्णकाले सह भक्तेन पाययेत्", text: "snehadviṣaḥ śiśūnvṛddhānsukumārānkṛśānapi uṣṇakāmānuṣṇakāle saha bhaktena pāyayet" },
      { type: "verse", number: "21", sanskrit: "सर्पिष्मती बहुतिला यवागूः स्वल्पतण्डुला सुखोष्णा सेव्यमाना तु सद्यः स्नेहनकारिणी", text: "sarpiṣmatī bahutilā yavāgūḥ svalpataṇḍulā sukhoṣṇā sevyamānā tu sadyaḥ snehanakāriṇī" },
      { type: "verse", number: "22", sanskrit: "शर्कराचूर्णसम्भृष्टे दोहनस्थे घृते तु गाम् दुग्ध्वा क्षीरं पिबेदुष्णं सद्यःस्नेहनमुच्यते", text: "śarkarācūrṇasambhṛṣṭe dohanasthe ghṛte tu gām dugdhvā kṣīraṃ pibeduṣṇaṃ sadyaḥsnehanamucyate" },
      { type: "verse", number: "23", sanskrit: "मिथ्याचाराद्बहुत्वाद्वा यस्य स्नेहो न जीर्यति विष्टभ्य वाऽपि जीर्येत वारिणोष्णेन वामयेत्", text: "mithyācārādbahutvādvā yasya sneho na jīryati viṣṭabhya vā'pi jīryeta vāriṇoṣṇena vāmayet" },
      { type: "verse", number: "24", sanskrit: "स्नेहस्याजीर्णशङ्कायां पिबेदुष्णोदकं नरः तेनोद्गारो भवेच्छुद्धो भक्तं प्रति रुचिस्तथा", text: "snehasyājīrṇaśaṅkāyāṃ pibeduṣṇodakaṃ naraḥ tenodgāro bhavecchuddho bhaktaṃ prati rucistathā" },
      { type: "verse", number: "25", sanskrit: "स्नेहेन पैक्तिकस्याग्निर्यदा तीक्ष्णतरीकृतः तदाऽस्योदीरयेत्तृष्णां स्नेहमुष्णाम्बुना वमेत् शीतं जलं पाययेच्च पिपासा तेन शाम्यति", text: "snehena paiktikasyāgniryadā tīkṣṇatarīkṛtaḥ tadā'syodīrayettṛṣṇāṃ snehamuṣṇāmbunā vamet śītaṃ jalaṃ pāyayecca pipāsā tena śāmyati" },
      { type: "verse", number: "26", sanskrit: "अजीर्णी वर्जयेत्स्नेहमुदरी तरुणज्वरी दुर्बलोऽरोचकी स्थूलो मूर्च्छार्त्तो मदपीडितः दत्तवस्तिर्विरिक्तश्च वान्तस्तृष्णाश्रमान्वितः अकालप्रसवा नारी दुर्दिने च विवर्जयेत्", text: "ajīrṇī varjayetsnehamudarī taruṇajvarī durbalo'rocakī sthūlo mūrcchārtto madapīḍitaḥ dattavastirviriktaśca vāntastṛṣṇāśramānvitaḥ akālaprasavā nārī durdine ca vivarjayet" },
      { type: "verse", number: "27", sanskrit: "वृद्धा बालाः कृशा रूक्षाः क्षीणास्राः क्षीणरेतसः वातार्त्तास्तिमिरार्त्ता ये तेषां स्नेहनमुत्तमम्", text: "vṛddhā bālāḥ kṛśā rūkṣāḥ kṣīṇāsrāḥ kṣīṇaretasaḥ vātārttāstimirārttā ye teṣāṃ snehanamuttamam" },
      { type: "verse", number: "28", sanskrit: "वातानुलोम्यं दीप्तोऽग्निर्वर्चः स्निग्धमसंहतम्", text: "vātānulomyaṃ dīpto'gnirvarcaḥ snigdhamasaṃhatam" },
      { type: "verse", number: "29", sanskrit: "मृदुस्निग्धाङ्गताऽग्लानिः स्नेहावेगोऽथ लाघवम् विमलेन्द्रि यता सम्यक् स्निग्धे रूक्षे विपर्ययः", text: "mṛdusnigdhāṅgatā'glāniḥ snehāvego'tha lāghavam vimalendri yatā samyak snigdhe rūkṣe viparyayaḥ" },
      { type: "verse", number: "30", sanskrit: "भक्तद्वेषो मुखस्रावो गुदे दाहः प्रवाहिका तन्द्रा ऽतिसारः पाण्डुत्वं भृशं स्निग्धस्य लक्षणम्", text: "bhaktadveṣo mukhasrāvo gude dāhaḥ pravāhikā tandrā 'tisāraḥ pāṇḍutvaṃ bhṛśaṃ snigdhasya lakṣaṇam" },
      { type: "verse", number: "31", sanskrit: "रूक्षस्य स्नेहनं स्नेहैरतिस्निग्धस्य रूक्षणम् श्यामाकचणकाद्यैश्च तक्रपिण्याकसक्तुभिः", text: "rūkṣasya snehanaṃ snehairatisnigdhasya rūkṣaṇam śyāmākacaṇakādyaiśca takrapiṇyākasaktubhiḥ" },
      { type: "verse", number: "32", sanskrit: "दीप्ताग्निःशुद्धकोष्ठश्च पुष्टधातुर्दृढेन्द्रि यः निर्जरो बलवर्णाढ्यः स्नेहसेवी भवेन्नरः", text: "dīptāgniḥśuddhakoṣṭhaśca puṣṭadhāturdṛḍhendri yaḥ nirjaro balavarṇāḍhyaḥ snehasevī bhavennaraḥ" },
      { type: "verse", number: "33", sanskrit: "स्नेहे व्यायामसंशीतवेगाघातप्रजागरान् दिवास्वप्नमभिष्यन्दि रूक्षान्नं च विवर्जयेत्", text: "snehe vyāyāmasaṃśītavegāghātaprajāgarān divāsvapnamabhiṣyandi rūkṣānnaṃ ca vivarjayet" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 2,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Виречана видхи — Слабительная терапия" },
      { type: "text", text: "Протокол виречана-кармы (терапевтического очищения кишечника). Выбор слабительного по конституции, правила подготовки и постпроцедурного питания." },
      { type: "verse", number: "1", sanskrit: "अथ स्वेदविधिर्नाम द्वितीयोऽध्यायः तत्रादौ स्वेदभेदाः स्वेदश्चतुर्विधः प्रोक्तस्तापोष्मौ स्वेदसंज्ञितौ उपनाहो द्र वः स्वेदः सर्वे वातार्त्तिहारिणः", text: "atha svedavidhirnāma dvitīyo'dhyāyaḥ tatrādau svedabhedāḥ svedaścaturvidhaḥ proktastāpoṣmau svedasaṃjñitau upanāho dra vaḥ svedaḥ sarve vātārttihāriṇaḥ" },
      { type: "verse", number: "2", sanskrit: "स्वेदौ तापोष्मजौ प्रायःश्लेष्मघ्नौ समुदीरितौ उपनाहस्तु वातघ्नः पित्तसङ्गे द्र वो हितः", text: "svedau tāpoṣmajau prāyaḥśleṣmaghnau samudīritau upanāhastu vātaghnaḥ pittasaṅge dra vo hitaḥ" },
      { type: "verse", number: "3", sanskrit: "रोगिबलाद्यनुसारेण स्वेदस्य त्रैविध्यनिर्देशः महाबले महाव्याधौ शीते स्वेदो महान्स्मृतः दुर्बले दुर्बलः स्वेदो मध्ये मध्यतमो मतः", text: "rogibalādyanusāreṇa svedasya traividhyanirdeśaḥ mahābale mahāvyādhau śīte svedo mahānsmṛtaḥ durbale durbalaḥ svedo madhye madhyatamo mataḥ" },
      { type: "verse", number: "4", sanskrit: "दोषविशेषेण स्वेदविशेषनिर्देशः बलासे रूक्षणः स्वेदो रूक्षस्निग्धः कफानिले कफमेदावृते वाते कोष्णं गेहं रवेः करान्", text: "doṣaviśeṣeṇa svedaviśeṣanirdeśaḥ balāse rūkṣaṇaḥ svedo rūkṣasnigdhaḥ kaphānile kaphamedāvṛte vāte koṣṇaṃ gehaṃ raveḥ karān" },
      { type: "verse", number: "5", sanskrit: "नियुद्धं मार्गगमनं गुरुप्रावरणं ध्रुवम् चिन्ताव्यायामभाराश्च सेवेतामयमुक्तये", text: "niyuddhaṃ mārgagamanaṃ guruprāvaraṇaṃ dhruvam cintāvyāyāmabhārāśca sevetāmayamuktaye" },
      { type: "verse", number: "6", sanskrit: "येषां नस्यं विधातव्यं वस्तिश्चापि हि देहिनाम् शोधनीयाश्च ये केचित्पूर्वं स्वेद्याश्च ते मताः", text: "yeṣāṃ nasyaṃ vidhātavyaṃ vastiścāpi hi dehinām śodhanīyāśca ye kecitpūrvaṃ svedyāśca te matāḥ" },
      { type: "verse", number: "7", sanskrit: "स्वेद्याः पूर्वं त्रयः प्लीहभगन्दर्यर्शसस्तथा अश्मर्यश्चातुरो जन्तुः समये शस्त्रकर्मणः", text: "svedyāḥ pūrvaṃ trayaḥ plīhabhagandaryarśasastathā aśmaryaścāturo jantuḥ samaye śastrakarmaṇaḥ" },
      { type: "verse", number: "8", sanskrit: "पश्चात्स्वेद्या गते शल्ये मूढगर्भगदे तथा काले प्रजाताऽकाले वा पश्चात्स्वेद्या नितम्बिनी", text: "paścātsvedyā gate śalye mūḍhagarbhagade tathā kāle prajātā'kāle vā paścātsvedyā nitambinī" },
      { type: "verse", number: "9", sanskrit: "सर्वान्स्वेद्यान्निवाते च जीर्णाहारे च कारयेत्", text: "sarvānsvedyānnivāte ca jīrṇāhāre ca kārayet" },
      { type: "verse", number: "10", sanskrit: "स्वेदाद्धातुस्थिता दोषाः स्नेहक्लिन्नस्य देहिनः द्र वत्वं प्राप्य कोष्ठान्तर्गता यान्ति विरेचताम्", text: "svedāddhātusthitā doṣāḥ snehaklinnasya dehinaḥ dra vatvaṃ prāpya koṣṭhāntargatā yānti virecatām" },
      { type: "verse", number: "11", sanskrit: "स्विद्यमानशरीरस्य हृदयं शीतलैः स्पृशेत् स्नेहाभ्यक्तशरीरस्य शीतैराच्छाद्य चक्षुषी", text: "svidyamānaśarīrasya hṛdayaṃ śītalaiḥ spṛśet snehābhyaktaśarīrasya śītairācchādya cakṣuṣī" },
      { type: "verse", number: "12", sanskrit: "अजीर्णी दुर्बलो मेही क्षतक्षीणः पिपासितः अतिसारी रक्तपित्ती पाण्डुरोगी तथोदरी", text: "ajīrṇī durbalo mehī kṣatakṣīṇaḥ pipāsitaḥ atisārī raktapittī pāṇḍurogī tathodarī" },
      { type: "verse", number: "13", sanskrit: "मदार्त्तो गर्भिणी चैव न हि स्वेद्या विजानता एतानपि मृदुस्वेदैः स्वेदसाध्यानुपाचरेत्", text: "madārtto garbhiṇī caiva na hi svedyā vijānatā etānapi mṛdusvedaiḥ svedasādhyānupācaret" },
      { type: "verse", number: "14", sanskrit: "मृदुस्वेदं प्रयुञ्जीत तथा हृन्मुष्कदृष्टिषु", text: "mṛdusvedaṃ prayuñjīta tathā hṛnmuṣkadṛṣṭiṣu" },
      { type: "verse", number: "15", sanskrit: "अतिस्वेदात् सन्धिपीडा दाहस्तृष्णा क्लमो भ्रमः पित्तासृक्पिटिकाकोपस्तत्र शीतैरुपाचरेत्", text: "atisvedāt sandhipīḍā dāhastṛṣṇā klamo bhramaḥ pittāsṛkpiṭikākopastatra śītairupācaret" },
      { type: "verse", number: "16", sanskrit: "तेषु तापामिधः स्वेदो वालुकावस्त्रपाणिभिः कपालकन्दुकाङ्गारैर्यथायोग्यं प्रयुज्यते", text: "teṣu tāpāmidhaḥ svedo vālukāvastrapāṇibhiḥ kapālakandukāṅgārairyathāyogyaṃ prayujyate" },
      { type: "verse", number: "17", sanskrit: "ऊष्मस्वेदः प्रयोक्तव्यो लोहपिण्डेष्टकाश्मभिः प्रतप्तैरम्लसिक्तैश्च कार्ये रल्लकवेष्टिते", text: "ūṣmasvedaḥ prayoktavyo lohapiṇḍeṣṭakāśmabhiḥ prataptairamlasiktaiśca kārye rallakaveṣṭite" },
      { type: "verse", number: "18", sanskrit: "अथवा वातनिर्णाशिद्र व्यक्वाथरसादिभिः उष्णैर्घंटं पूरयित्वा पार्श्वे छिद्रं  निधाय च विमुद्र य्स्यां त्रिखण्डां च धातुजां काष्ठवंशजाम् षडङ्गुलास्यां गोपुच्छां नलद्यं युञ्ज्याद् द्विहस्तिकाम्", text: "athavā vātanirṇāśidra vyakvātharasādibhiḥ uṣṇairghaṃṭaṃ pūrayitvā pārśve chidraṃ  nidhāya ca vimudra ysyāṃ trikhaṇḍāṃ ca dhātujāṃ kāṣṭhavaṃśajām ṣaḍaṅgulāsyāṃ gopucchāṃ naladyaṃ yuñjyād dvihastikām" },
      { type: "verse", number: "19", sanskrit: "सुखोपविष्टं स्वभ्यक्तं गुरुप्रावरणावृतम् हस्तिशुण्डिकया नाड्या स्वेदयेद्वातरोगिणम्", text: "sukhopaviṣṭaṃ svabhyaktaṃ guruprāvaraṇāvṛtam hastiśuṇḍikayā nāḍyā svedayedvātarogiṇam" },
      { type: "verse", number: "20", sanskrit: "पुरुषायाममात्रां वा भूमिमुत्कीर्य खादिरैः काष्ठैर्दग्ध्वा तथाऽभ्युक्ष्य क्षीरधान्याम्लवारिभिः", text: "puruṣāyāmamātrāṃ vā bhūmimutkīrya khādiraiḥ kāṣṭhairdagdhvā tathā'bhyukṣya kṣīradhānyāmlavāribhiḥ" },
      { type: "verse", number: "21", sanskrit: "वातघ्नपत्रैराच्छाद्य शयानं स्वेदयेन्नरम् एवं माषादिभिः स्विन्नैः शयानं स्वेदमाचरेत्", text: "vātaghnapatrairācchādya śayānaṃ svedayennaram evaṃ māṣādibhiḥ svinnaiḥ śayānaṃ svedamācaret" },
      { type: "verse", number: "22", sanskrit: "अथोपनाहस्वेदं च कुर्याद्वातहरौषधैः प्रदिह्य देहं वातार्त्तं क्षीरमांसरसान्वितैः अम्लपिष्टैः सलवणैः सुखोष्णैः स्नेहसंयुतैः", text: "athopanāhasvedaṃ ca kuryādvātaharauṣadhaiḥ pradihya dehaṃ vātārttaṃ kṣīramāṃsarasānvitaiḥ amlapiṣṭaiḥ salavaṇaiḥ sukhoṣṇaiḥ snehasaṃyutaiḥ" },
      { type: "verse", number: "23", sanskrit: "उपग्राम्यानूपमांसैर्जीवनीयगणेन च", text: "upagrāmyānūpamāṃsairjīvanīyagaṇena ca" },
      { type: "verse", number: "24", sanskrit: "दधिसौवीरकक्षारैर्वीरतर्वादिना तथा कुलत्थमाषगोधूमैरतसीतिलसर्षपैः", text: "dadhisauvīrakakṣārairvīratarvādinā tathā kulatthamāṣagodhūmairatasītilasarṣapaiḥ" },
      { type: "verse", number: "25", sanskrit: "एरण्डमूलबीजैश्च रास्नामूलकशिग्रुभिः", text: "eraṇḍamūlabījaiśca rāsnāmūlakaśigrubhiḥ" },
      { type: "verse", number: "26", sanskrit: "मिशिकृष्णाकुठेरैश्च लवणैरम्लसंयुतैः प्रसारिण्यश्वगन्धाभ्यां बलाभिर्दशमूलकैः", text: "miśikṛṣṇākuṭheraiśca lavaṇairamlasaṃyutaiḥ prasāriṇyaśvagandhābhyāṃ balābhirdaśamūlakaiḥ" },
      { type: "verse", number: "27", sanskrit: "गुडूचीवानरीबीजैर्यथालाभं समाहृतैः क्षुण्णैः स्विन्नैश्च वस्त्रेण बद्धैः संस्वेदयेन्नरम्", text: "guḍūcīvānarībījairyathālābhaṃ samāhṛtaiḥ kṣuṇṇaiḥ svinnaiśca vastreṇa baddhaiḥ saṃsvedayennaram" },
      { type: "verse", number: "28", sanskrit: "द्र वस्वेदस्तु वातघ्नद्र व्यक्वाथेन पूरिते कटाहे कोष्ठके वाऽपि सूपविष्टोऽवगाहयेत्", text: "dra vasvedastu vātaghnadra vyakvāthena pūrite kaṭāhe koṣṭhake vā'pi sūpaviṣṭo'vagāhayet" },
      { type: "verse", number: "29", sanskrit: "नाभेः षडङ्गुलं यावन्मग्नः क्वाथस्य धारया", text: "nābheḥ ṣaḍaṅgulaṃ yāvanmagnaḥ kvāthasya dhārayā" },
      { type: "verse", number: "30", sanskrit: "कोष्णया स्कन्धयोः सिक्तस्तिष्ठेत्स्निग्धतनुर्नरः एवं तैलेन दुग्धेन सर्पिषा स्वेदयेन्नरम्", text: "koṣṇayā skandhayoḥ siktastiṣṭhetsnigdhatanurnaraḥ evaṃ tailena dugdhena sarpiṣā svedayennaram" },
      { type: "verse", number: "31", sanskrit: "एकान्तरे द्व्यन्तरे वा स्नेहो युक्तोऽवगाहने", text: "ekāntare dvyantare vā sneho yukto'vagāhane" },
      { type: "verse", number: "32", sanskrit: "शिरामुखैर्लोमकूपैर्धमनीभिश्च तर्पयेत् शरीरे बलमाधत्ते युक्तः स्नेहोऽवगाहने", text: "śirāmukhairlomakūpairdhamanībhiśca tarpayet śarīre balamādhatte yuktaḥ sneho'vagāhane" },
      { type: "verse", number: "33", sanskrit: "स्नेहसिक्तस्य धातुवृद्धौ हेतुः जलसिक्तस्य वर्धन्ते यथा मूलेऽङकुरास्तरोः तथा धातुविवृद्धिर्हि स्नेहसिक्तस्य जायते नातः परतरः कश्चिदुपायो वातनाशनः", text: "snehasiktasya dhātuvṛddhau hetuḥ jalasiktasya vardhante yathā mūle'ṅakurāstaroḥ tathā dhātuvivṛddhirhi snehasiktasya jāyate nātaḥ parataraḥ kaścidupāyo vātanāśanaḥ" },
      { type: "verse", number: "34", sanskrit: "शीतशूलाद्युपरमे स्तम्भगौरवनिग्रहे दीप्ताग्नौ मार्दवे जाते स्वेदनाद्विरतिर्मता", text: "śītaśūlādyuparame stambhagauravanigrahe dīptāgnau mārdave jāte svedanādviratirmatā" },
      { type: "verse", number: "35", sanskrit: "स्वेदनोत्तरं कर्त्तव्यकर्माणि सम्यक् स्विन्नं विमृदितं स्नानमुष्णाम्बुभिः शनैः भोजयेच्चानभिष्यन्दि व्यायामं च न कारयेत्", text: "svedanottaraṃ karttavyakarmāṇi samyak svinnaṃ vimṛditaṃ snānamuṣṇāmbubhiḥ śanaiḥ bhojayeccānabhiṣyandi vyāyāmaṃ ca na kārayet" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 3,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Насья видхи — Назальная терапия" },
      { type: "text", text: "Насья — введение лекарств через нос как метод лечения болезней головы, шеи и органов чувств. Пять типов насьи и правила применения." },
      { type: "verse", number: "1", sanskrit: "अथ वमनविधिर्नाम तृतीयोऽध्यायः तत्र वमनविरेचनयोः कालः शरत्काले वसन्ते च प्रावृट्काले च देहिनाम् वमनं रेचनं चैव कारयेत्कुशलो भिषक्", text: "atha vamanavidhirnāma tṛtīyo'dhyāyaḥ tatra vamanavirecanayoḥ kālaḥ śaratkāle vasante ca prāvṛṭkāle ca dehinām vamanaṃ recanaṃ caiva kārayetkuśalo bhiṣak" },
      { type: "verse", number: "2", sanskrit: "बलवन्तं कफव्याप्तं हृल्लासार्त्तिनिपीडितम् तथा वमनसात्म्यं च धीरचित्तं च वामयेत्", text: "balavantaṃ kaphavyāptaṃ hṛllāsārttinipīḍitam tathā vamanasātmyaṃ ca dhīracittaṃ ca vāmayet" },
      { type: "verse", number: "3", sanskrit: "विषदोषे स्तन्यरोगे मन्देऽग्नौ श्लीपदेऽबुदे हृद्रो गकुष्ठवीसर्पमेहाजीर्णभ्रमेषु च", text: "viṣadoṣe stanyaroge mande'gnau ślīpade'bude hṛdro gakuṣṭhavīsarpamehājīrṇabhrameṣu ca" },
      { type: "verse", number: "4", sanskrit: "अपस्मारे ज्वरोन्मादे तथा रक्तातिसारिषु", text: "apasmāre jvaronmāde tathā raktātisāriṣu" },
      { type: "verse", number: "5", sanskrit: "नासाताल्वोष्ठपाकेषु कर्णस्रावे द्विजिह्वके गलशुण्ड्यामतीसारे पित्तश्लेष्मगदे तथा मेदोगदेऽरुचौ चैव वमनं कारयेद्भिषक्", text: "nāsātālvoṣṭhapākeṣu karṇasrāve dvijihvake galaśuṇḍyāmatīsāre pittaśleṣmagade tathā medogade'rucau caiva vamanaṃ kārayedbhiṣak" },
      { type: "verse", number: "6", sanskrit: "न वामनीयस्तिमिरी न गुल्मी नोदरी कृशः", text: "na vāmanīyastimirī na gulmī nodarī kṛśaḥ" },
      { type: "verse", number: "7", sanskrit: "नातिवृद्धो गर्भिणी च न स्थूलो न क्षतातुरः मदार्त्तो बालको रूक्षः क्षुधितश्च निरूहितः", text: "nātivṛddho garbhiṇī ca na sthūlo na kṣatāturaḥ madārtto bālako rūkṣaḥ kṣudhitaśca nirūhitaḥ" },
      { type: "verse", number: "8", sanskrit: "उदावत्तर्यूर्ध्वरक्ती च दुश्छर्दिः केवलानिली पाण्डुरोगी कृमिव्याप्तः पठनात्स्वरघातकः", text: "udāvattaryūrdhvaraktī ca duśchardiḥ kevalānilī pāṇḍurogī kṛmivyāptaḥ paṭhanātsvaraghātakaḥ" },
      { type: "verse", number: "9", sanskrit: "एतेऽप्यजीर्णव्यथिता वाम्या ये विषपीडिताः कफव्याप्ताश्च ते वाम्या मधुकक्वाथपानतः", text: "ete'pyajīrṇavyathitā vāmyā ye viṣapīḍitāḥ kaphavyāptāśca te vāmyā madhukakvāthapānataḥ" },
      { type: "verse", number: "10", sanskrit: "सुकुमारं कृशं बालं वृद्धं भीरुं न वामयेत् पीत्वा यवागूमाकण्ठं क्षीरतक्रदधीनि वा", text: "sukumāraṃ kṛśaṃ bālaṃ vṛddhaṃ bhīruṃ na vāmayet pītvā yavāgūmākaṇṭhaṃ kṣīratakradadhīni vā" },
      { type: "verse", number: "11", sanskrit: "असात्म्यैः श्लेष्मलैर्भोज्यैर्दोषानुत्क्लिश्य देहिनः स्निग्धस्विन्नाय वमनं दत्तं सम्यक्प्रवर्त्तते", text: "asātmyaiḥ śleṣmalairbhojyairdoṣānutkliśya dehinaḥ snigdhasvinnāya vamanaṃ dattaṃ samyakpravarttate" },
      { type: "verse", number: "12", sanskrit: "क्रमेण वमनविरेचनयोर्हितकरपदार्थाः वमनेषु च सर्वेषु सैन्धवं मधु वा हितम् बीभत्सं वमनं दद्याद्विपरीतं विरेचनम्", text: "krameṇa vamanavirecanayorhitakarapadārthāḥ vamaneṣu ca sarveṣu saindhavaṃ madhu vā hitam bībhatsaṃ vamanaṃ dadyādviparītaṃ virecanam" },
      { type: "verse", number: "13", sanskrit: "क्वाथ्यद्र व्यस्य कुडवं श्रपयित्वा जलाढके अर्धभागावशिष्टं च वमनेष्ववचारयेत्", text: "kvāthyadra vyasya kuḍavaṃ śrapayitvā jalāḍhake ardhabhāgāvaśiṣṭaṃ ca vamaneṣvavacārayet" },
      { type: "verse", number: "14", sanskrit: "क्वाथपाने नवप्रस्था ज्येष्ठा मात्रा प्रकीर्त्तिता मध्यमा षण्मिता प्रोक्ता त्रिप्रस्था च कनीयसी", text: "kvāthapāne navaprasthā jyeṣṭhā mātrā prakīrttitā madhyamā ṣaṇmitā proktā triprasthā ca kanīyasī" },
      { type: "verse", number: "15", sanskrit: "कल्कचूर्णावलेहानां त्रिपलं श्रेष्ठमात्रया मध्यमं द्विपलं विद्यात्कनीयस्तु पलं भवेत्", text: "kalkacūrṇāvalehānāṃ tripalaṃ śreṣṭhamātrayā madhyamaṃ dvipalaṃ vidyātkanīyastu palaṃ bhavet" },
      { type: "verse", number: "16", sanskrit: "उत्तमादिभेदेन वमनवेगसंख्याभेदाः वमने चापि वेगाः स्युरष्टौ पित्तान्तमुत्तमाः षड्वेगा मध्यमा वेगाश्चत्वारस्त्ववरे मताः", text: "uttamādibhedena vamanavegasaṃkhyābhedāḥ vamane cāpi vegāḥ syuraṣṭau pittāntamuttamāḥ ṣaḍvegā madhyamā vegāścatvārastvavare matāḥ" },
      { type: "verse", number: "17", sanskrit: "वमने च विरेके च तथा शोणितमोक्षणे सार्धत्रयोदशपलं प्रस्थमाहुर्मनीषिणः", text: "vamane ca vireke ca tathā śoṇitamokṣaṇe sārdhatrayodaśapalaṃ prasthamāhurmanīṣiṇaḥ" },
      { type: "verse", number: "18", sanskrit: "दोषविशेषेण वामकद्र व्यविशेषनिर्देशः कफं कटुकतीक्ष्णोष्णैः पित्तं स्वादु हिमैर्जयेत् सुस्वादुलवणाम्लोष्णैः संसृष्टं वायुना कफम्", text: "doṣaviśeṣeṇa vāmakadra vyaviśeṣanirdeśaḥ kaphaṃ kaṭukatīkṣṇoṣṇaiḥ pittaṃ svādu himairjayet susvādulavaṇāmloṣṇaiḥ saṃsṛṣṭaṃ vāyunā kapham" },
      { type: "verse", number: "19", sanskrit: "कृष्णा राठफलं सिन्धु कफे कोष्णजलैः पिबेत् पटोलवासानिम्बैश्च पित्ते शीतजलं पिबेत्", text: "kṛṣṇā rāṭhaphalaṃ sindhu kaphe koṣṇajalaiḥ pibet paṭolavāsānimbaiśca pitte śītajalaṃ pibet" },
      { type: "verse", number: "20", sanskrit: "सश्लेष्मवातपीडायां सक्षीरं मदनं पिबेत् अजीर्णे कोष्णपानीयैः सिन्धु पीत्वा वमेत्सुधीः", text: "saśleṣmavātapīḍāyāṃ sakṣīraṃ madanaṃ pibet ajīrṇe koṣṇapānīyaiḥ sindhu pītvā vametsudhīḥ" },
      { type: "verse", number: "21", sanskrit: "वमनं पाययित्वा च जानुमात्रासने स्थितम् कण्ठमेरण्डनालेन स्पृशन्तं वामयेद्भिषक् ललाटं वमतः पुंसः पार्श्वे द्वे च प्रदापयेत्", text: "vamanaṃ pāyayitvā ca jānumātrāsane sthitam kaṇṭhameraṇḍanālena spṛśantaṃ vāmayedbhiṣak lalāṭaṃ vamataḥ puṃsaḥ pārśve dve ca pradāpayet" },
      { type: "verse", number: "22", sanskrit: "प्रसेको हृद्ग्रहः कोठः कण्डूर्दुश्छर्दिताद्भवेत्", text: "praseko hṛdgrahaḥ koṭhaḥ kaṇḍūrduścharditādbhavet" },
      { type: "verse", number: "23", sanskrit: "अतिवान्ते भवेत्तृष्णा हिक्कोद्गारौ विसंज्ञता जिह्वानिःसर्पणं चाक्ष्णोर्व्यावृत्तिर्हनुसंहतिः रक्तच्छर्दिः ष्ठीवनं च कण्ठे पीडा च जायते", text: "ativānte bhavettṛṣṇā hikkodgārau visaṃjñatā jihvāniḥsarpaṇaṃ cākṣṇorvyāvṛttirhanusaṃhatiḥ raktacchardiḥ ṣṭhīvanaṃ ca kaṇṭhe pīḍā ca jāyate" },
      { type: "verse", number: "24", sanskrit: "वमनस्यातियोगी तु मृदु कुर्याद्विरेचनम्", text: "vamanasyātiyogī tu mṛdu kuryādvirecanam" },
      { type: "verse", number: "25", sanskrit: "वमनान्तः प्रविष्टायां जिह्वायां कवलग्रहः स्निग्धाम्ललवणैर्हृद्यैर्घृतक्षीररसैर्हितः", text: "vamanāntaḥ praviṣṭāyāṃ jihvāyāṃ kavalagrahaḥ snigdhāmlalavaṇairhṛdyairghṛtakṣīrarasairhitaḥ" },
      { type: "verse", number: "26", sanskrit: "फलान्यम्लानि खादेयुस्तस्य चान्येऽग्रतो नराः निःसृतां तु तिलद्रा क्षाकल्कं लिप्त्वा प्रवेशयेत्", text: "phalānyamlāni khādeyustasya cānye'grato narāḥ niḥsṛtāṃ tu tiladrā kṣākalkaṃ liptvā praveśayet" },
      { type: "verse", number: "27", sanskrit: "व्यावृत्तेऽक्ष्णि घृताभ्यक्ते पीडयेच्च शनैः शनैः हनुमोक्षे स्मृतः स्वेदो नस्यं च श्लेष्मवातहृत्", text: "vyāvṛtte'kṣṇi ghṛtābhyakte pīḍayecca śanaiḥ śanaiḥ hanumokṣe smṛtaḥ svedo nasyaṃ ca śleṣmavātahṛt" },
      { type: "verse", number: "28", sanskrit: "रक्तपित्तविधानेन रक्तच्छर्दिमुपाचरेत् धात्रीरसाञ्जनोशीरलाजाचन्दनवारिभिः", text: "raktapittavidhānena raktacchardimupācaret dhātrīrasāñjanośīralājācandanavāribhiḥ" },
      { type: "verse", number: "29", sanskrit: "मन्थं कृत्वा पाययेच्च सघृतक्षौद्र शर्करम् शाम्यन्त्यनेन तृष्णाद्याः पीडाश्छर्दिसमुद्भवाः", text: "manthaṃ kṛtvā pāyayecca saghṛtakṣaudra śarkaram śāmyantyanena tṛṣṇādyāḥ pīḍāśchardisamudbhavāḥ" },
      { type: "verse", number: "30", sanskrit: "हृकत्कण्ठशिरसां शुद्धिर्दीप्ताग्नित्वं च लाघवम् कफपित्तविनाशश्च सम्यग्वान्तस्य चेष्टितम्", text: "hṛkatkaṇṭhaśirasāṃ śuddhirdīptāgnitvaṃ ca lāghavam kaphapittavināśaśca samyagvāntasya ceṣṭitam" },
      { type: "verse", number: "31", sanskrit: "ततोऽपराह्णे दीप्ताग्निं मुद्गषष्टिकशालिभिः हृद्यैश्च जाङ्गलरसैः कृत्वा यूषं च भोजयेत्", text: "tato'parāhṇe dīptāgniṃ mudgaṣaṣṭikaśālibhiḥ hṛdyaiśca jāṅgalarasaiḥ kṛtvā yūṣaṃ ca bhojayet" },
      { type: "verse", number: "32", sanskrit: "तन्द्रा  निद्रा स्यदौर्गन्ध्यं कण्डूश्च ग्रहणी विषम् सुवान्तस्य न पीडायै भवन्त्येते कदाचन", text: "tandrā  nidrā syadaurgandhyaṃ kaṇḍūśca grahaṇī viṣam suvāntasya na pīḍāyai bhavantyete kadācana" },
      { type: "verse", number: "33", sanskrit: "अजीर्णं शीतपानीयं व्यायामं मैथुनं तथा स्नेहाभ्यङ्गं प्रकोपं च दिनैकं वर्जयेत्सुधीः", text: "ajīrṇaṃ śītapānīyaṃ vyāyāmaṃ maithunaṃ tathā snehābhyaṅgaṃ prakopaṃ ca dinaikaṃ varjayetsudhīḥ" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 4,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Нируха видхи — Очищающие клизмы" },
      { type: "text", text: "Протокол нируха-бaсти (деко кционных клизм). Состав раствора: отвар Дашамулы, мёд, соль, масло, паста. Детальные инструкции по объёму, температуре, позиции." },
      { type: "verse", number: "1", sanskrit: "अथ विरेचनविधिर्नाम चतुर्थोऽध्यायः तत्र विरेचनविषयः स्निग्ध स्विन्नस्य वान्तस्य दद्यात्सम्यग्विरेचनम्", text: "atha virecanavidhirnāma caturtho'dhyāyaḥ tatra virecanaviṣayaḥ snigdha svinnasya vāntasya dadyātsamyagvirecanam" },
      { type: "verse", number: "2", sanskrit: "अवान्तस्य त्वधःस्रस्तो ग्रहणीं छादयेत्कफः मन्दाग्निं गौरवं कुर्याज्जनयेद्वा प्रवाहिकाम्", text: "avāntasya tvadhaḥsrasto grahaṇīṃ chādayetkaphaḥ mandāgniṃ gauravaṃ kuryājjanayedvā pravāhikām" },
      { type: "verse", number: "3", sanskrit: "अथवा पाचनैरामं बलासं च विपाचयेत् स्निग्धस्य स्नेहनैः कार्यं स्वेदैः स्विन्नस्य रेचनम्", text: "athavā pācanairāmaṃ balāsaṃ ca vipācayet snigdhasya snehanaiḥ kāryaṃ svedaiḥ svinnasya recanam" },
      { type: "verse", number: "4", sanskrit: "शरदृतौ वसन्ते च देहशुद्ध्यै विरेचयेत् अन्यदात्ययिके काले शोधनं शीलयेद् बुधः", text: "śaradṛtau vasante ca dehaśuddhyai virecayet anyadātyayike kāle śodhanaṃ śīlayed budhaḥ" },
      { type: "verse", number: "5", sanskrit: "दोषाः कदाचित्कुप्यन्ति जिता लङ्घनपाचनैः ये तु संशोधनैः शुद्धा न तेषां पुनरुद्भवः", text: "doṣāḥ kadācitkupyanti jitā laṅghanapācanaiḥ ye tu saṃśodhanaiḥ śuddhā na teṣāṃ punarudbhavaḥ" },
      { type: "verse", number: "6", sanskrit: "पित्ते विरेचनं युञ्ज्यादामोद्भूते गदे तथा उदरे च तथाऽध्माने कोष्ठशुद्ध्यै विशेषतः", text: "pitte virecanaṃ yuñjyādāmodbhūte gade tathā udare ca tathā'dhmāne koṣṭhaśuddhyai viśeṣataḥ" },
      { type: "verse", number: "7", sanskrit: "बालवृद्धावतिस्निग्धः क्षतक्षीणो भयान्वितः श्रान्तस्तृषार्त्तः स्थूलश्च गर्भिणी च नवज्वरी", text: "bālavṛddhāvatisnigdhaḥ kṣatakṣīṇo bhayānvitaḥ śrāntastṛṣārttaḥ sthūlaśca garbhiṇī ca navajvarī" },
      { type: "verse", number: "8", sanskrit: "नवप्रसूता नारी च मन्दाग्निश्च मदात्ययी शल्यार्दितश्चरूक्षश्च न विरेच्या विजानता", text: "navaprasūtā nārī ca mandāgniśca madātyayī śalyārditaścarūkṣaśca na virecyā vijānatā" },
      { type: "verse", number: "9", sanskrit: "जीर्णज्वरी गरव्याप्तो वातरक्ती भगन्दरी अर्शःपाण्डूदरग्रन्थिहृद्रो गारुचिपीडिताः योनिरोगप्रमेहार्त्ता गुल्मप्लीहव्रणार्दिताः", text: "jīrṇajvarī garavyāpto vātaraktī bhagandarī arśaḥpāṇḍūdaragranthihṛdro gārucipīḍitāḥ yonirogapramehārttā gulmaplīhavraṇārditāḥ" },
      { type: "verse", number: "10", sanskrit: "विद्र धिच्छर्दिविस्फोटविषूचीकुष्ठसंयुताः कर्णनासाशिरोवक्त्रगुदमेढ्रामयान्विताः", text: "vidra dhicchardivisphoṭaviṣūcīkuṣṭhasaṃyutāḥ karṇanāsāśirovaktragudameḍhrāmayānvitāḥ" },
      { type: "verse", number: "11", sanskrit: "प्लीहशोथाक्षिरोगार्त्ताः कृमिक्षीणानिलार्दिताः शूलिनो मूत्रघातार्त्ता विरेकार्हा नरा मताः", text: "plīhaśothākṣirogārttāḥ kṛmikṣīṇānilārditāḥ śūlino mūtraghātārttā virekārhā narā matāḥ" },
      { type: "verse", number: "12", sanskrit: "बहुपित्तो मृदुः कोष्ठो बहुश्लेष्मा च मध्यमः बहुवातः क्रूरकोष्ठो दुर्वि रेच्यः स कथ्यते", text: "bahupitto mṛduḥ koṣṭho bahuśleṣmā ca madhyamaḥ bahuvātaḥ krūrakoṣṭho durvi recyaḥ sa kathyate" },
      { type: "verse", number: "13", sanskrit: "मृद्वी मात्रा मृदौ कोष्ठे मध्यकोष्ठे च मध्यमा क्रूरे तीक्ष्णा मता द्र व्यैर्मृदुमध्यमतीक्ष्णकैः", text: "mṛdvī mātrā mṛdau koṣṭhe madhyakoṣṭhe ca madhyamā krūre tīkṣṇā matā dra vyairmṛdumadhyamatīkṣṇakaiḥ" },
      { type: "verse", number: "14", sanskrit: "मृद्वादिविरेचनद्र व्यनिर्देशः मृदुद्रा र्क्षा!पयश्चञ्चुतैलैरपि विरिच्यते मध्यमस्त्रिवृतातिक्ताराजवृक्षैर्विरिच्यते क्रूरः स्नुक्पयसा हेमक्षीरदन्तीफलादिभिः", text: "mṛdvādivirecanadra vyanirdeśaḥ mṛdudrā rkṣā!payaścañcutailairapi viricyate madhyamastrivṛtātiktārājavṛkṣairviricyate krūraḥ snukpayasā hemakṣīradantīphalādibhiḥ" },
      { type: "verse", number: "15", sanskrit: "विरेचनसंख्याऽनुसारेण मात्राया उत्तमत्वादिनिर्देशः मात्रोत्तमा विरेकस्य त्रिंशद्वेगैः कफान्तिका वेगैर्विंशतिभिर्मध्या हीनोक्ता दशवेगिका", text: "virecanasaṃkhyā'nusāreṇa mātrāyā uttamatvādinirdeśaḥ mātrottamā virekasya triṃśadvegaiḥ kaphāntikā vegairviṃśatibhirmadhyā hīnoktā daśavegikā" },
      { type: "verse", number: "16", sanskrit: "विरेके कषायादीनां मात्रानिर्देशः द्विपलं श्रेष्ठमाख्यातं मध्यमं च पलं भवेत् पलार्धे च कषायाणां कनीयस्तु विरेचनम्", text: "vireke kaṣāyādīnāṃ mātrānirdeśaḥ dvipalaṃ śreṣṭhamākhyātaṃ madhyamaṃ ca palaṃ bhavet palārdhe ca kaṣāyāṇāṃ kanīyastu virecanam" },
      { type: "verse", number: "17", sanskrit: "कल्कमोदकचूर्णानां कर्षं मध्वाज्यलेहतः कर्षद्वयं पलं वाऽपि वयोरोगाद्यपेक्षया", text: "kalkamodakacūrṇānāṃ karṣaṃ madhvājyalehataḥ karṣadvayaṃ palaṃ vā'pi vayorogādyapekṣayā" },
      { type: "verse", number: "18", sanskrit: "कोष्ठानुसारेण विरेकौषधव्यवस्था पित्तोत्तरे त्रिवृच्चूर्णं द्रा क्षाक्वाथादिभिः पिबेत् त्रिफलाक्वाथगोमूत्रैः पिबेद् व्योषं कफार्दितः", text: "koṣṭhānusāreṇa virekauṣadhavyavasthā pittottare trivṛccūrṇaṃ drā kṣākvāthādibhiḥ pibet triphalākvāthagomūtraiḥ pibed vyoṣaṃ kaphārditaḥ" },
      { type: "verse", number: "19", sanskrit: "त्रिवृत्सैन्धवशुण्ठीनां चूर्णमम्लैः पिबेन्नरः वातार्दितो विरेकाय जाङ्गलानां रसेन वा", text: "trivṛtsaindhavaśuṇṭhīnāṃ cūrṇamamlaiḥ pibennaraḥ vātārdito virekāya jāṅgalānāṃ rasena vā" },
      { type: "verse", number: "20", sanskrit: "एरण्डतैलं त्रिफलाक्वाथेन द्विगुणेन च युक्तं पीतं पयोभिर्वा न चिरेण विरिच्यते", text: "eraṇḍatailaṃ triphalākvāthena dviguṇena ca yuktaṃ pītaṃ payobhirvā na cireṇa viricyate" },
      { type: "verse", number: "21", sanskrit: "वर्षादिषडृतुषु क्रमेण षड् विरेचनयोगाः त्रिवृता कौटजं बीजं पिप्पली विश्वभेषजम्", text: "varṣādiṣaḍṛtuṣu krameṇa ṣaḍ virecanayogāḥ trivṛtā kauṭajaṃ bījaṃ pippalī viśvabheṣajam" },
      { type: "verse", number: "22", sanskrit: "समृद्वीकारसक्षौद्रं  वर्षाकाले विरेचनम् त्रिवृद्दुरालभामुस्ताशर्करोदीच्यचन्दनम्", text: "samṛdvīkārasakṣaudraṃ  varṣākāle virecanam trivṛddurālabhāmustāśarkarodīcyacandanam" },
      { type: "verse", number: "23", sanskrit: "द्रा क्षाऽम्बुना सयष्टीकं शीतलं च घनात्यये त्रिवृतां चित्रकं पाठामजाजीं सरलां वचाम्", text: "drā kṣā'mbunā sayaṣṭīkaṃ śītalaṃ ca ghanātyaye trivṛtāṃ citrakaṃ pāṭhāmajājīṃ saralāṃ vacām" },
      { type: "verse", number: "24", sanskrit: "हेमक्षीरीं च हेमन्ते चूर्णमुष्णाम्बुना पिबेत् पिप्पली नागरं सिन्धु श्यामा त्रिवृतया सह", text: "hemakṣīrīṃ ca hemante cūrṇamuṣṇāmbunā pibet pippalī nāgaraṃ sindhu śyāmā trivṛtayā saha" },
      { type: "verse", number: "25", sanskrit: "लिहेत्क्षौद्रे ण शिशिरे वसन्ते च विरेचनम् त्रिवृता शर्करा तुल्या ग्रीष्मकाले विरेचनम्", text: "lihetkṣaudre ṇa śiśire vasante ca virecanam trivṛtā śarkarā tulyā grīṣmakāle virecanam" },
      { type: "verse", number: "26", sanskrit: "त्रिवृतां हपुषां दन्तीं सप्तलां कटुरोहिणीम् स्वर्णक्षीरीं च सञ्चूर्ण्य गोमूत्रे भावयेत् त्र्! यहम् एष सर्वर्त्तुको योगः स्निग्धानां मलदोषहा", text: "trivṛtāṃ hapuṣāṃ dantīṃ saptalāṃ kaṭurohiṇīm svarṇakṣīrīṃ ca sañcūrṇya gomūtre bhāvayet tr! yaham eṣa sarvarttuko yogaḥ snigdhānāṃ maladoṣahā" },
      { type: "verse", number: "27", sanskrit: "अभया मरिचं शुण्ठीविडङ्गामलकानि च", text: "abhayā maricaṃ śuṇṭhīviḍaṅgāmalakāni ca" },
      { type: "verse", number: "28", sanskrit: "पिप्पली पिप्पलीमूलं त्वक्पत्रं मुस्तमेव च एतानि समभागानि दन्ती च द्विगुणा भवेत्", text: "pippalī pippalīmūlaṃ tvakpatraṃ mustameva ca etāni samabhāgāni dantī ca dviguṇā bhavet" },
      { type: "verse", number: "29", sanskrit: "त्रिवृदष्टगुणा ज्ञेया षड्गुणा चात्र शर्करा मधुना मोदकान्कृत्वा कर्षमात्रप्रमाणतः", text: "trivṛdaṣṭaguṇā jñeyā ṣaḍguṇā cātra śarkarā madhunā modakānkṛtvā karṣamātrapramāṇataḥ" },
      { type: "verse", number: "30", sanskrit: "एकैकं भक्षयेत्प्रातः शीतं चानुपिबेज्जलम् तावद्विरिच्यते जन्तुर्यावदुष्णं न सेवते", text: "ekaikaṃ bhakṣayetprātaḥ śītaṃ cānupibejjalam tāvadviricyate janturyāvaduṣṇaṃ na sevate" },
      { type: "verse", number: "31", sanskrit: "पानाहारविहारेषु भवेन्निर्यन्त्रणः सदा विषमज्वरमन्दाग्निपाण्डुकासभगन्दरान्", text: "pānāhāravihāreṣu bhavenniryantraṇaḥ sadā viṣamajvaramandāgnipāṇḍukāsabhagandarān" },
      { type: "verse", number: "32", sanskrit: "विदाहप्लीहमेहांश्च यक्ष्माणं नयनामयान्", text: "vidāhaplīhamehāṃśca yakṣmāṇaṃ nayanāmayān" },
      { type: "verse", number: "33", sanskrit: "वातरोगांस्तथाध्मानं मूत्रकृच्छ्राणि चाश्मरीम् पृष्ठपार्श्वोरुजघनजङ्घोदररुजं जयेत्", text: "vātarogāṃstathādhmānaṃ mūtrakṛcchrāṇi cāśmarīm pṛṣṭhapārśvorujaghanajaṅghodararujaṃ jayet" },
      { type: "verse", number: "34", sanskrit: "सततं शीलनादेषां पलितानि प्रणाशयेत् अभयामोदका ह्येते रसायनवराः स्मृताः", text: "satataṃ śīlanādeṣāṃ palitāni praṇāśayet abhayāmodakā hyete rasāyanavarāḥ smṛtāḥ" },
      { type: "verse", number: "35", sanskrit: "विरेचनान्ते कर्त्तव्यकर्मोपदेशः पीत्वा विरेचनं शीतजलैः संसिच्य चक्षुषी सुगन्धिं किंचिदाघ्राय ताम्बूलं शीलयेन्नरः", text: "virecanānte karttavyakarmopadeśaḥ pītvā virecanaṃ śītajalaiḥ saṃsicya cakṣuṣī sugandhiṃ kiṃcidāghrāya tāmbūlaṃ śīlayennaraḥ" },
      { type: "verse", number: "36", sanskrit: "निर्वातस्थो न वेगांश्च धारयेन्न स्वपेत्तथा शीताम्बु न स्पृशेत्क्वापि कोष्णनीरं पिबेन्मुहुः", text: "nirvātastho na vegāṃśca dhārayenna svapettathā śītāmbu na spṛśetkvāpi koṣṇanīraṃ pibenmuhuḥ" },
      { type: "verse", number: "37", sanskrit: "बलासौषधपित्तानि वायुर्वान्ते यथा व्रजेत् रेकात्तथा मलं पित्तं भेषजं च कफो व्रजेत्", text: "balāsauṣadhapittāni vāyurvānte yathā vrajet rekāttathā malaṃ pittaṃ bheṣajaṃ ca kapho vrajet" },
      { type: "verse", number: "38", sanskrit: "दुर्विरिक्तस्य नाभेस्तु स्तब्धत्वं कुक्षिशूलता पुरीषवातसङ्गश्च कण्डूमण्डलगौरवाः विदाहोऽरुचिराध्मानं भ्रमश्छर्दिश्च जायते", text: "durviriktasya nābhestu stabdhatvaṃ kukṣiśūlatā purīṣavātasaṅgaśca kaṇḍūmaṇḍalagauravāḥ vidāho'rucirādhmānaṃ bhramaśchardiśca jāyate" },
      { type: "verse", number: "39", sanskrit: "तं पुनः पाचनैः स्नेहैः पक्त्वा संस्निह्य रेचयेत् तेनास्योपद्र वा यान्ति दीप्तोऽग्निर्लघुता भवेत्", text: "taṃ punaḥ pācanaiḥ snehaiḥ paktvā saṃsnihya recayet tenāsyopadra vā yānti dīpto'gnirlaghutā bhavet" },
      { type: "verse", number: "40", sanskrit: "विरेकस्यातियोगेन मूर्च्छा भ्रंशो गुदस्य च", text: "virekasyātiyogena mūrcchā bhraṃśo gudasya ca" },
      { type: "verse", number: "41", sanskrit: "शूलं कफातियोगः स्यान्मांसधावनसन्निभम् मेदोनिभं जलाभासं रक्तं चापि विरिच्यते", text: "śūlaṃ kaphātiyogaḥ syānmāṃsadhāvanasannibham medonibhaṃ jalābhāsaṃ raktaṃ cāpi viricyate" },
      { type: "verse", number: "42", sanskrit: "तस्य शीताम्बुभिः सिक्त्वा शरीरं तण्डुलाम्बुभिः मधुमिश्रैस्तथा शीतैः कारयेद्वमनं मृदु", text: "tasya śītāmbubhiḥ siktvā śarīraṃ taṇḍulāmbubhiḥ madhumiśraistathā śītaiḥ kārayedvamanaṃ mṛdu" },
      { type: "verse", number: "43", sanskrit: "सहकारत्वचः कल्को दध्ना सौवीरकेण वा पिष्टो नाभिप्रलेपेन हन्त्यतीसारमुल्बणम्", text: "sahakāratvacaḥ kalko dadhnā sauvīrakeṇa vā piṣṭo nābhipralepena hantyatīsāramulbaṇam" },
      { type: "verse", number: "44", sanskrit: "अजाक्षीरं रसं वाऽपि वैष्किरं हारिणं तथा शालिभिः षष्टिकैः स्वल्पं मसूरैर्वाऽपि भोजयेत्", text: "ajākṣīraṃ rasaṃ vā'pi vaiṣkiraṃ hāriṇaṃ tathā śālibhiḥ ṣaṣṭikaiḥ svalpaṃ masūrairvā'pi bhojayet" },
      { type: "verse", number: "45", sanskrit: "शीतैः संग्राहिभिर्द्र व्यैः कुर्यात्संग्रहणं भिषक्", text: "śītaiḥ saṃgrāhibhirdra vyaiḥ kuryātsaṃgrahaṇaṃ bhiṣak" },
      { type: "verse", number: "46", sanskrit: "लाघवे मनसस्तुष्टावनुलोमे गतेऽनिले सुविरिक्तं नरं ज्ञात्वा पाचनं पाययेन्निशि", text: "lāghave manasastuṣṭāvanulome gate'nile suviriktaṃ naraṃ jñātvā pācanaṃ pāyayenniśi" },
      { type: "verse", number: "47", sanskrit: "इन्द्रि याणां बलं बुद्धेः प्रसादो वह्निदीपनम् धातुस्थैर्यं वयः स्थैर्यं भवेद्रे चनसेवनात्", text: "indri yāṇāṃ balaṃ buddheḥ prasādo vahnidīpanam dhātusthairyaṃ vayaḥ sthairyaṃ bhavedre canasevanāt" },
      { type: "verse", number: "48", sanskrit: "प्रवातसेवां शीताम्बु स्नेहाभ्यङ्गमजीर्णताम् व्यायामं मैथुनं चैव न सेवेत विरेचितः", text: "pravātasevāṃ śītāmbu snehābhyaṅgamajīrṇatām vyāyāmaṃ maithunaṃ caiva na seveta virecitaḥ" },
      { type: "verse", number: "49", sanskrit: "विरिक्तस्य पथ्यार्थे पेयादिद्र व्याणि शालिषष्टिकमुद्गाद्यैर्यवागूं भोजयेत्कृताम् जाङ्गलैर्विष्किराणां वा रसैः शाल्योदनं हितम्", text: "viriktasya pathyārthe peyādidra vyāṇi śāliṣaṣṭikamudgādyairyavāgūṃ bhojayetkṛtām jāṅgalairviṣkirāṇāṃ vā rasaiḥ śālyodanaṃ hitam" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 5,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Ануваса видхи — Питательные клизмы" },
      { type: "text", text: "Ануваса-бaсти (масляная ретентивная клизма). Состав, техника введения и критерии правильного удержания. Показания: Вата-болезни, истощение, постоперационный уход." },
      { type: "verse", number: "1", sanskrit: "अथ बस्तिविधिर्नाम पञ्चमोऽध्यायः तत्र बस्तेर्भेदो निरुक्तिश्च बस्तिर्द्विधाऽनुवासाख्यो निरूहश्च ततः परम् बस्तिभिर्दीयते यस्मात्तस्माद्बस्तिरिति स्मृतः", text: "atha bastividhirnāma pañcamo'dhyāyaḥ tatra basterbhedo niruktiśca bastirdvidhā'nuvāsākhyo nirūhaśca tataḥ param bastibhirdīyate yasmāttasmādbastiriti smṛtaḥ" },
      { type: "verse", number: "2", sanskrit: "यः स्नेहैर्दीयते स स्यादनुवासननामकः कषायक्षीरतैलैर्यो निरूहः स निगद्यते", text: "yaḥ snehairdīyate sa syādanuvāsananāmakaḥ kaṣāyakṣīratailairyo nirūhaḥ sa nigadyate" },
      { type: "verse", number: "3", sanskrit: "तत्रानुवासनाख्यो हि बस्तिर्यः सोऽत्र कथ्यते पूर्वमेव ततो बस्तिर्निरूहाख्यो भविष्यति", text: "tatrānuvāsanākhyo hi bastiryaḥ so'tra kathyate pūrvameva tato bastirnirūhākhyo bhaviṣyati" },
      { type: "verse", number: "4", sanskrit: "निरूहादुत्तरश्चैव बस्तिः स्यादुत्तराभिधः अनुवासनभेदश्च मात्राबस्तिरुदीरितः", text: "nirūhāduttaraścaiva bastiḥ syāduttarābhidhaḥ anuvāsanabhedaśca mātrābastirudīritaḥ" },
      { type: "verse", number: "5", sanskrit: "पलद्वयं तस्य मात्रा तस्मादर्धाऽपि वा भवेत्", text: "paladvayaṃ tasya mātrā tasmādardhā'pi vā bhavet" },
      { type: "verse", number: "6", sanskrit: "अनुवास्यस्तु रूक्षः स्यात्तीक्ष्णाग्निः केवलानिली", text: "anuvāsyastu rūkṣaḥ syāttīkṣṇāgniḥ kevalānilī" },
      { type: "verse", number: "7", sanskrit: "नानुवास्यस्तु कुष्ठी स्यान्मेही स्थूलस्तथोदरी नास्थाप्या नानुवास्याः स्युरजीर्णोन्मादतृड्युताः शोकमूर्च्छाऽरुचिभयश्वासकासक्षयातुराः", text: "nānuvāsyastu kuṣṭhī syānmehī sthūlastathodarī nāsthāpyā nānuvāsyāḥ syurajīrṇonmādatṛḍyutāḥ śokamūrcchā'rucibhayaśvāsakāsakṣayāturāḥ" },
      { type: "verse", number: "8", sanskrit: "नेत्रं कार्यं सुवर्णादिधातुभिर्वृक्षवेणुभिः नलैर्दन्तैर्विषाणाग्रैर्मणिभिर्वा विधीयते", text: "netraṃ kāryaṃ suvarṇādidhātubhirvṛkṣaveṇubhiḥ nalairdantairviṣāṇāgrairmaṇibhirvā vidhīyate" },
      { type: "verse", number: "9", sanskrit: "आयुर्विभेदेन नेत्रपरिमाणभेदाः एकवर्षात्तु षड्वर्षं यावन्मानं षडङ्गुलम् ततो द्वादशकं यावन्मानं स्यादष्टसम्मितम् ततः परं द्वादशभिरङ्गुलैर्नेत्रदीर्घता", text: "āyurvibhedena netraparimāṇabhedāḥ ekavarṣāttu ṣaḍvarṣaṃ yāvanmānaṃ ṣaḍaṅgulam tato dvādaśakaṃ yāvanmānaṃ syādaṣṭasammitam tataḥ paraṃ dvādaśabhiraṅgulairnetradīrghatā" },
      { type: "verse", number: "10", sanskrit: "मुद्गच्छिद्रं  कलायाभं छिद्रं  कोलास्थिसन्निभम् यथासङ्ख्यं भवेन्नेत्रं श्लक्ष्णं गोपुच्छसन्निभम्", text: "mudgacchidraṃ  kalāyābhaṃ chidraṃ  kolāsthisannibham yathāsaṅkhyaṃ bhavennetraṃ ślakṣṇaṃ gopucchasannibham" },
      { type: "verse", number: "11", sanskrit: "आतुराङ्गुष्ठमानेन मूले स्थूलं विधीयते कनिष्ठिकापरीणाहमग्रे च गुटिकामुखम्", text: "āturāṅguṣṭhamānena mūle sthūlaṃ vidhīyate kaniṣṭhikāparīṇāhamagre ca guṭikāmukham" },
      { type: "verse", number: "12", sanskrit: "तन्मूले कर्णिके द्वे च कार्ये भागाच्चतुर्थकात् योजयेत्तत्र बस्तिं च बन्धद्वयविधानतः", text: "tanmūle karṇike dve ca kārye bhāgāccaturthakāt yojayettatra bastiṃ ca bandhadvayavidhānataḥ" },
      { type: "verse", number: "13", sanskrit: "बस्तिपुटकोपयोगिद्र व्यनिर्देशः मृगाजशूकरगवां महिषस्यापि वा भवेत् मूत्रकोशस्य बस्तिस्तु तदलाभेन चर्मजः कषायरक्तः सुमृदुर्बस्तिः स्निग्धो दृढो हितः", text: "bastipuṭakopayogidra vyanirdeśaḥ mṛgājaśūkaragavāṃ mahiṣasyāpi vā bhavet mūtrakośasya bastistu tadalābhena carmajaḥ kaṣāyaraktaḥ sumṛdurbastiḥ snigdho dṛḍho hitaḥ" },
      { type: "verse", number: "14", sanskrit: "व्रणबस्तेस्तु नेत्रं स्याछ्लक्ष्णमष्टाङ्गुलोन्मितम् मुद्गच्छिद्रं  गृध्रपक्षनलिकापरिणाहि च", text: "vraṇabastestu netraṃ syāchlakṣṇamaṣṭāṅgulonmitam mudgacchidraṃ  gṛdhrapakṣanalikāpariṇāhi ca" },
      { type: "verse", number: "15", sanskrit: "शरीरोपचयं वर्णं बलमारोग्यमायुषः कुरुते परिवृद्धिं च बस्तिः सम्यगुपासितः", text: "śarīropacayaṃ varṇaṃ balamārogyamāyuṣaḥ kurute parivṛddhiṃ ca bastiḥ samyagupāsitaḥ" },
      { type: "verse", number: "16", sanskrit: "दिवा शीते वसन्ते च स्नेहबस्तिः प्रदीयते ग्रीष्मवर्षाशरत्काले रात्रौ स्यादनुवासनम्", text: "divā śīte vasante ca snehabastiḥ pradīyate grīṣmavarṣāśaratkāle rātrau syādanuvāsanam" },
      { type: "verse", number: "17", sanskrit: "न चातिस्निग्धमशनं भोजयित्वाऽनुवासयेत्", text: "na cātisnigdhamaśanaṃ bhojayitvā'nuvāsayet" },
      { type: "verse", number: "18", sanskrit: "मदं मूर्च्छां च जनयेद् द्विधा स्नेहः प्रयोजितः रूक्षं भुक्तवतोऽत्यन्नं बलं वर्णश्च हीयते", text: "madaṃ mūrcchāṃ ca janayed dvidhā snehaḥ prayojitaḥ rūkṣaṃ bhuktavato'tyannaṃ balaṃ varṇaśca hīyate" },
      { type: "verse", number: "19", sanskrit: "हीनमात्रावुभौ बस्ती नातिकार्यकरौ स्मृतौ अतिमात्रौ तथानाहक्लमातीसारकारकौ", text: "hīnamātrāvubhau bastī nātikāryakarau smṛtau atimātrau tathānāhaklamātīsārakārakau" },
      { type: "verse", number: "20", sanskrit: "उत्तमस्य पलैः षड्भिर्मध्यमस्य पलैस्त्रिभिः पलाद्यर्धेन हीनस्य युक्ता मात्राऽनुवासने", text: "uttamasya palaiḥ ṣaḍbhirmadhyamasya palaistribhiḥ palādyardhena hīnasya yuktā mātrā'nuvāsane" },
      { type: "verse", number: "21", sanskrit: "स्नेहबस्तौ सैन्धवशताह्वाचूर्णप्रक्षेपमानम् शताह्वासैन्धवाभ्यां च देयं स्नेहे च चूर्णकम् तन्मात्रोत्तममध्यान्त्याः षट्चतुर्द्वयमाषकैः", text: "snehabastau saindhavaśatāhvācūrṇaprakṣepamānam śatāhvāsaindhavābhyāṃ ca deyaṃ snehe ca cūrṇakam tanmātrottamamadhyāntyāḥ ṣaṭcaturdvayamāṣakaiḥ" },
      { type: "verse", number: "22", sanskrit: "विरेचनानन्तरमेवानुवासनदानस्य नियमः विरेचनात्सप्तरात्रे गते जातबलाय च भक्तान्नायानुवास्याय बस्तिर्देयोऽनुवासनः", text: "virecanānantaramevānuvāsanadānasya niyamaḥ virecanātsaptarātre gate jātabalāya ca bhaktānnāyānuvāsyāya bastirdeyo'nuvāsanaḥ" },
      { type: "verse", number: "23", sanskrit: "अथानुवास्यं स्वभ्यक्तमुष्णाम्बुस्वेदितं शनैः भोजयित्वा यथाशास्त्रं कृतचङ्क्रमणं ततः", text: "athānuvāsyaṃ svabhyaktamuṣṇāmbusveditaṃ śanaiḥ bhojayitvā yathāśāstraṃ kṛtacaṅkramaṇaṃ tataḥ" },
      { type: "verse", number: "24", sanskrit: "उत्सृष्टानिलविण्मूत्रं योजयेत्स्नेहबस्तिना सुप्तस्य वामपार्श्वेन वामजङ्घाप्रसारिणः", text: "utsṛṣṭānilaviṇmūtraṃ yojayetsnehabastinā suptasya vāmapārśvena vāmajaṅghāprasāriṇaḥ" },
      { type: "verse", number: "25", sanskrit: "कुञ्चितापरजङ्घस्य नेत्रं स्निग्धगुदे न्यसेत् बद्ध्वा बस्तिमुखं स्रूत्रैर्वामहस्तेन धारयेत्", text: "kuñcitāparajaṅghasya netraṃ snigdhagude nyaset baddhvā bastimukhaṃ srūtrairvāmahastena dhārayet" },
      { type: "verse", number: "26", sanskrit: "पीडयेद्दक्षिणेनैव मध्यवेगेन धीरधीः जृम्भाकासक्षवादींश्च बस्तिकाले न कारयेत्", text: "pīḍayeddakṣiṇenaiva madhyavegena dhīradhīḥ jṛmbhākāsakṣavādīṃśca bastikāle na kārayet" },
      { type: "verse", number: "27", sanskrit: "त्रिंशन्मात्रामितः कालः प्रोक्तो बस्तेस्तु पीडने ततः प्रणिहितः स्नेह उत्तानो वाक्शतं भवेत्", text: "triṃśanmātrāmitaḥ kālaḥ prokto bastestu pīḍane tataḥ praṇihitaḥ sneha uttāno vākśataṃ bhavet" },
      { type: "verse", number: "28", sanskrit: "जानुमण्डलमावेष्ट्य कुर्याच्छोटिकया युतम् एका मात्रा भवेदेषा सर्वत्रैष विनिश्चयः", text: "jānumaṇḍalamāveṣṭya kuryācchoṭikayā yutam ekā mātrā bhavedeṣā sarvatraiṣa viniścayaḥ" },
      { type: "verse", number: "29", sanskrit: "प्रसारितैः सर्वगात्रैर्यथावीर्यं विसर्पति ताडयेत्तलयोरेनं त्रीन्वारांश्च शनैः शनैः", text: "prasāritaiḥ sarvagātrairyathāvīryaṃ visarpati tāḍayettalayorenaṃ trīnvārāṃśca śanaiḥ śanaiḥ" },
      { type: "verse", number: "30", sanskrit: "स्फिजोश्चैवं ततः श्रोणीं शय्यां चैवोत्क्षिपेत्ततः जाते विधाने तु ततः कुर्यान्निद्रा ं! यथासुखम्", text: "sphijoścaivaṃ tataḥ śroṇīṃ śayyāṃ caivotkṣipettataḥ jāte vidhāne tu tataḥ kuryānnidrā ṃ! yathāsukham" },
      { type: "verse", number: "31", sanskrit: "सानिलः सपुरीषश्च स्नेहः प्रत्येति यस्य तु उपद्र वं विना शीघ्रं स सम्यगनुवासितः", text: "sānilaḥ sapurīṣaśca snehaḥ pratyeti yasya tu upadra vaṃ vinā śīghraṃ sa samyaganuvāsitaḥ" },
      { type: "verse", number: "32", sanskrit: "जीर्णान्नमथ सायाह्ने स्नेहेप्रत्यागते पुनः लघ्वन्नं भोजयेत्कामं दीप्ताग्निस्तु नरो यदि", text: "jīrṇānnamatha sāyāhne snehepratyāgate punaḥ laghvannaṃ bhojayetkāmaṃ dīptāgnistu naro yadi" },
      { type: "verse", number: "33", sanskrit: "अनुवासिताय दातव्यमितरेऽह्नि सुखोदकम् धान्यशुण्ठीकषायो वा स्नेहव्यापत्तिनाशनम्", text: "anuvāsitāya dātavyamitare'hni sukhodakam dhānyaśuṇṭhīkaṣāyo vā snehavyāpattināśanam" },
      { type: "verse", number: "34", sanskrit: "दोषानुसारेण बस्तिमानसंख्यानिर्देशः अनेन विधिना षड् वा सप्तवाऽष्टौ नवापि वा विधेया बस्तयस्तेषामन्ते चैवनिरूहणम्", text: "doṣānusāreṇa bastimānasaṃkhyānirdeśaḥ anena vidhinā ṣaḍ vā saptavā'ṣṭau navāpi vā vidheyā bastayasteṣāmante caivanirūhaṇam" },
      { type: "verse", number: "35", sanskrit: "संख्यात्मकस्नेहबस्तीनां गुणाः दत्तस्तु प्रथमो वस्तिः स्नेहयेद्बस्तिवङ्क्षणैः सम्यग्दत्तो द्वितीयस्तु मूर्धस्थमनिलं जयेत्", text: "saṃkhyātmakasnehabastīnāṃ guṇāḥ dattastu prathamo vastiḥ snehayedbastivaṅkṣaṇaiḥ samyagdatto dvitīyastu mūrdhasthamanilaṃ jayet" },
      { type: "verse", number: "36", sanskrit: "बलं वर्णं च जनयेत्तृतीयस्तु प्रयोजितः चतुर्थपञ्चमौ दत्तौ स्नेहयेतां रसासृजी", text: "balaṃ varṇaṃ ca janayettṛtīyastu prayojitaḥ caturthapañcamau dattau snehayetāṃ rasāsṛjī" },
      { type: "verse", number: "37", sanskrit: "षष्ठो मांसं स्नेहयति सप्तमो मेद एव च अष्टमो नवमश्चापि मज्जानं च यथाक्रमम्", text: "ṣaṣṭho māṃsaṃ snehayati saptamo meda eva ca aṣṭamo navamaścāpi majjānaṃ ca yathākramam" },
      { type: "verse", number: "38", sanskrit: "एवं शुक्रगतान्दोषान्द्विगुणः साधु साधयेत् अष्टादशाष्टादशकान्बस्तीनां यो निषेवयेत् स कुञ्जरबलोऽप्यश्वं जयेत्तुल्योऽमरप्रभः", text: "evaṃ śukragatāndoṣāndviguṇaḥ sādhu sādhayet aṣṭādaśāṣṭādaśakānbastīnāṃ yo niṣevayet sa kuñjarabalo'pyaśvaṃ jayettulyo'maraprabhaḥ" },
      { type: "verse", number: "39", sanskrit: "रूक्षाय बहुवाताय स्नेहबस्तिं दिने दिने दद्याद् वैद्यस्तथाऽन्येषामन्यां बाधामपाहरेत्", text: "rūkṣāya bahuvātāya snehabastiṃ dine dine dadyād vaidyastathā'nyeṣāmanyāṃ bādhāmapāharet" },
      { type: "verse", number: "40", sanskrit: "स्नेहोऽल्पमात्रो रूक्षाणां दीर्घकालमनत्ययः तथा निरूहः स्निग्धानामल्पमात्रः प्रशस्यते", text: "sneho'lpamātro rūkṣāṇāṃ dīrghakālamanatyayaḥ tathā nirūhaḥ snigdhānāmalpamātraḥ praśasyate" },
      { type: "verse", number: "41", sanskrit: "बस्तिदत्तस्नेहस्य तात्कालिकप्रत्यागतौ कर्त्तव्यं कर्म अथवा यस्य तत्कालं स्नेहो निर्याति केवलः तस्यान्योऽन्यतरो देयो न हि स्निह्यत्यतिष्ठति", text: "bastidattasnehasya tātkālikapratyāgatau karttavyaṃ karma athavā yasya tatkālaṃ sneho niryāti kevalaḥ tasyānyo'nyataro deyo na hi snihyatyatiṣṭhati" },
      { type: "verse", number: "42", sanskrit: "अनुवासनबस्तिस्नेहानिःसृतावुपद्र वास्तच्चिकित्सा च अशुद्धस्य मलोन्मिश्रः स्नेहो नैति यदा पुनः तदा शैथिल्यमाध्मानं शूलं श्वासश्च जायते", text: "anuvāsanabastisnehāniḥsṛtāvupadra vāstaccikitsā ca aśuddhasya malonmiśraḥ sneho naiti yadā punaḥ tadā śaithilyamādhmānaṃ śūlaṃ śvāsaśca jāyate" },
      { type: "verse", number: "43", sanskrit: "पक्वाशये गुरुत्वं च तत्र दद्यान्निरूहणम् तीक्ष्णं तीक्ष्णौषधैर्युक्ताफलवर्तिंर्हिता तथा", text: "pakvāśaye gurutvaṃ ca tatra dadyānnirūhaṇam tīkṣṇaṃ tīkṣṇauṣadhairyuktāphalavartiṃrhitā tathā" },
      { type: "verse", number: "44", sanskrit: "यथाऽनुलोमनं वायुर्मलं स्नेहश्च जायते तथा विरेचनं दद्यात्तीक्ष्णं नस्यं च शस्यते", text: "yathā'nulomanaṃ vāyurmalaṃ snehaśca jāyate tathā virecanaṃ dadyāttīkṣṇaṃ nasyaṃ ca śasyate" },
      { type: "verse", number: "45", sanskrit: "स्नेहबस्तेरनिःसृतावप्युपद्र वानुत्पत्तौ कर्त्तव्यं कर्म यस्य नोपद्र वं कुर्यात्स्नेहबस्तिरनिःसृतः सर्वोऽल्पो वा वृते रौक्ष्यादुपेक्ष्यः स विजानता", text: "snehabasteraniḥsṛtāvapyupadra vānutpattau karttavyaṃ karma yasya nopadra vaṃ kuryātsnehabastiraniḥsṛtaḥ sarvo'lpo vā vṛte raukṣyādupekṣyaḥ sa vijānatā" },
      { type: "verse", number: "46", sanskrit: "अहोरात्रादनिःसृते स्नेहे प्रतीकारः अनायातं त्वहोरात्रे स्नेहं संशोधनैर्ह रेत् स्नेहबस्तावनायाते नान्यः स्नेहो विधीयते", text: "ahorātrādaniḥsṛte snehe pratīkāraḥ anāyātaṃ tvahorātre snehaṃ saṃśodhanairha ret snehabastāvanāyāte nānyaḥ sneho vidhīyate" },
      { type: "verse", number: "47", sanskrit: "अनुवासनार्थं गुडूच्यादितैलम् गुडूच्येरण्डपूतीकभार्ङ्गीविषकरोहिषम् शतावरीं सहचरं काकनासां पलोन्मिताम्", text: "anuvāsanārthaṃ guḍūcyāditailam guḍūcyeraṇḍapūtīkabhārṅgīviṣakarohiṣam śatāvarīṃ sahacaraṃ kākanāsāṃ palonmitām" },
      { type: "verse", number: "48", sanskrit: "चतुद्रो र्णे!ऽम्भसः पक्त्वा द्रो णशेषेण तेन च", text: "catudro rṇe!'mbhasaḥ paktvā dro ṇaśeṣeṇa tena ca" },
      { type: "verse", number: "49", sanskrit: "पचेत्तैलाढकं पेष्यैर्जीवनीयैः पलोन्मितैः अनुवासनमेतद्धि सर्ववातविकारनुत्", text: "pacettailāḍhakaṃ peṣyairjīvanīyaiḥ palonmitaiḥ anuvāsanametaddhi sarvavātavikāranut" },
      { type: "verse", number: "50", sanskrit: "षटसप्ततिव्यापदस्तु जायन्ते बस्तिकर्मणः दूषितात्समुदायेन ताश्चिकित्स्यास्तु सुश्रुतात्", text: "ṣaṭasaptativyāpadastu jāyante bastikarmaṇaḥ dūṣitātsamudāyena tāścikitsyāstu suśrutāt" },
      { type: "verse", number: "51", sanskrit: "पानहारविहाराश्च परिहाराश्च कृत्स्नशः स्नेहपानसमाः कार्या नात्रकार्याविचारणा", text: "pānahāravihārāśca parihārāśca kṛtsnaśaḥ snehapānasamāḥ kāryā nātrakāryāvicāraṇā" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 6,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Широ дхара видхи — Масляный полив головы" },
      { type: "text", text: "Широ-дхара — ритмичное непрерывное поливание головы тёплым маслом. Это уникальный аюрведический метод для болезней нервной системы и ума." },
      { type: "verse", number: "1", sanskrit: "अथ निरूहबस्तिविधिर्नाम षष्ठोऽध्यायः तत्र तद्भेदानाह निरूहबस्तिर्बहुधा भिद्यते कारणान्तरैः तैरेव तस्य नामानि कृतानि मुनिपुङ्गवैः", text: "atha nirūhabastividhirnāma ṣaṣṭho'dhyāyaḥ tatra tadbhedānāha nirūhabastirbahudhā bhidyate kāraṇāntaraiḥ taireva tasya nāmāni kṛtāni munipuṅgavaiḥ" },
      { type: "verse", number: "2", sanskrit: "निरूहस्यापरं नाम प्रोक्तमास्थापनं बुधैः स्वस्थानस्थापनाद्दोषधातूनां स्थापनं मतम्", text: "nirūhasyāparaṃ nāma proktamāsthāpanaṃ budhaiḥ svasthānasthāpanāddoṣadhātūnāṃ sthāpanaṃ matam" },
      { type: "verse", number: "3", sanskrit: "निरूहस्य प्रमाणं च प्रस्थं पादोत्तरं परम् मध्यमं प्रस्थमुद्दिष्टं हीनस्य कुडवास्त्रयः", text: "nirūhasya pramāṇaṃ ca prasthaṃ pādottaraṃ param madhyamaṃ prasthamuddiṣṭaṃ hīnasya kuḍavāstrayaḥ" },
      { type: "verse", number: "4", sanskrit: "अतिस्निग्धोत्क्लिष्टदोषौ क्षतोरस्कः कृशस्तथा आध्मानच्छर्दिहिक्काऽश कासश्वासप्रपीडितः", text: "atisnigdhotkliṣṭadoṣau kṣatoraskaḥ kṛśastathā ādhmānacchardihikkā'śa kāsaśvāsaprapīḍitaḥ" },
      { type: "verse", number: "5", sanskrit: "गुदशोफातिसारार्त्तो विषूचीकुष्ठसंयुतः गर्भिणी मधुमेही च नास्थाप्यश्च जलोदरी", text: "gudaśophātisārārtto viṣūcīkuṣṭhasaṃyutaḥ garbhiṇī madhumehī ca nāsthāpyaśca jalodarī" },
      { type: "verse", number: "6", sanskrit: "वातव्याधावुदावर्त्ते वातासृग्विषमज्वरे मूर्च्छातृष्णोदरानाहमूत्रकृच्छ्राश्मरीषु च", text: "vātavyādhāvudāvartte vātāsṛgviṣamajvare mūrcchātṛṣṇodarānāhamūtrakṛcchrāśmarīṣu ca" },
      { type: "verse", number: "7", sanskrit: "वृद्धासृग्दरमन्दाग्निप्रमेहेषु निरूहणम् शूलेऽम्लपित्ते हृद्रो गे योजयेद्विधिवद् बुधः", text: "vṛddhāsṛgdaramandāgniprameheṣu nirūhaṇam śūle'mlapitte hṛdro ge yojayedvidhivad budhaḥ" },
      { type: "verse", number: "8", sanskrit: "उत्सृष्टानिलविण्मूत्रं स्निग्धस्विन्नमभोजितम् मध्याह्ने गृहमध्ये च यथायोग्यं निरूहयेत्", text: "utsṛṣṭānilaviṇmūtraṃ snigdhasvinnamabhojitam madhyāhne gṛhamadhye ca yathāyogyaṃ nirūhayet" },
      { type: "verse", number: "9", sanskrit: "स्नेहबस्तिविधानेन बुधः कुर्यान्निरूहणम् जाते निरूहे च ततो भवेदुत्कटकासनः", text: "snehabastividhānena budhaḥ kuryānnirūhaṇam jāte nirūhe ca tato bhavedutkaṭakāsanaḥ" },
      { type: "verse", number: "10", sanskrit: "तिष्ठेन्मुहूर्त्तमात्रं तु निरूहागमनेच्छया अनायातं मुहूर्तं तु निरूहं शौधनैर्ह रेत् निरूहैरेव मतिमान्क्षारमूत्राम्लसैन्धवैः", text: "tiṣṭhenmuhūrttamātraṃ tu nirūhāgamanecchayā anāyātaṃ muhūrtaṃ tu nirūhaṃ śaudhanairha ret nirūhaireva matimānkṣāramūtrāmlasaindhavaiḥ" },
      { type: "verse", number: "11", sanskrit: "यस्य क्रमेण गच्छन्ति विट्पित्तकफवायवः लाघवं चोपजायेत सुनिरूहं तमादिशेत्", text: "yasya krameṇa gacchanti viṭpittakaphavāyavaḥ lāghavaṃ copajāyeta sunirūhaṃ tamādiśet" },
      { type: "verse", number: "12", sanskrit: "यस्य स्याद्बस्तिरल्पाल्पवेगो हीनमलानिलः मूर्च्छार्त्तिजाड्यारुचिमान्दुर्निरूहं तमादिशेत्", text: "yasya syādbastiralpālpavego hīnamalānilaḥ mūrcchārttijāḍyārucimāndurnirūhaṃ tamādiśet" },
      { type: "verse", number: "13", sanskrit: "निरूहस्य बस्तिदानविधेयतानिर्देशः अनेन विधिना युञ्ज्यान्निरूहं बस्तिदानवित् ॠ द्वितीयं वा तृतीयं वा चतुर्थं वा यथोचितम्", text: "nirūhasya bastidānavidheyatānirdeśaḥ anena vidhinā yuñjyānnirūhaṃ bastidānavit ṝ dvitīyaṃ vā tṛtīyaṃ vā caturthaṃ vā yathocitam" },
      { type: "verse", number: "14", sanskrit: "पित्तश्लेष्मानिलाविष्टं क्षीरयूषरसैः क्रमात् निरूहं भोजयित्वा च ततस्तदनुवासयेत्", text: "pittaśleṣmānilāviṣṭaṃ kṣīrayūṣarasaiḥ kramāt nirūhaṃ bhojayitvā ca tatastadanuvāsayet" },
      { type: "verse", number: "15", sanskrit: "सुकुमारस्य वृद्धस्य बालस्य च मृदुर्हितः बस्तिस्तीक्ष्णः प्रयुक्तस्तु तेषां हन्याद् बलायुषी", text: "sukumārasya vṛddhasya bālasya ca mṛdurhitaḥ bastistīkṣṇaḥ prayuktastu teṣāṃ hanyād balāyuṣī" },
      { type: "verse", number: "16", sanskrit: "उत्क्लेशनादिबस्तीनां प्रयोगकालनिर्देशः दद्यादुत्क्लेशनं पूर्वं मध्ये दोषहरं ततः पश्चात्संशमनीयं च दद्याद्बस्तिं विचक्षणः", text: "utkleśanādibastīnāṃ prayogakālanirdeśaḥ dadyādutkleśanaṃ pūrvaṃ madhye doṣaharaṃ tataḥ paścātsaṃśamanīyaṃ ca dadyādbastiṃ vicakṣaṇaḥ" },
      { type: "verse", number: "17", sanskrit: "एरण्डबीजं मधुकं पिप्पली सैन्धवं वचा हपुषाफलकल्कश्च बस्तिरुत्क्लेशनः स्मृतः", text: "eraṇḍabījaṃ madhukaṃ pippalī saindhavaṃ vacā hapuṣāphalakalkaśca bastirutkleśanaḥ smṛtaḥ" },
      { type: "verse", number: "18", sanskrit: "शताह्वा मधुकं बिल्वं कौटजं फलमेव च सकाञ्जिकः सगोमूत्रो बस्तिर्दोषहरः स्मृतः", text: "śatāhvā madhukaṃ bilvaṃ kauṭajaṃ phalameva ca sakāñjikaḥ sagomūtro bastirdoṣaharaḥ smṛtaḥ" },
      { type: "verse", number: "19", sanskrit: "प्रियङ्गुर्मधुकं मुस्ता तथैव च रसाञ्जनम् सक्षीरः शस्यते बस्तिर्दोषाणां शमनः स्मृतः", text: "priyaṅgurmadhukaṃ mustā tathaiva ca rasāñjanam sakṣīraḥ śasyate bastirdoṣāṇāṃ śamanaḥ smṛtaḥ" },
      { type: "verse", number: "20", sanskrit: "शोधनद्र व्यनिष्क्वाथैस्तत्कल्कैः स्नेहसैन्धवैः युक्त्या खजेन मथिता बस्तयः शोधनाः स्मृताः", text: "śodhanadra vyaniṣkvāthaistatkalkaiḥ snehasaindhavaiḥ yuktyā khajena mathitā bastayaḥ śodhanāḥ smṛtāḥ" },
      { type: "verse", number: "21", sanskrit: "त्रिफलाक्वाथगोमूत्रक्षौद्र क्षारसमायुताः ऊषकादिप्रतीवापैर्बस्तयो लेखनाः स्मृताः", text: "triphalākvāthagomūtrakṣaudra kṣārasamāyutāḥ ūṣakādipratīvāpairbastayo lekhanāḥ smṛtāḥ" },
      { type: "verse", number: "22", sanskrit: "बृंहणद्र व्यनिष्क्वाथकल्कैर्मधुरकैर्युताः सर्पिर्मांसरसोपेता बस्तयो बृंहणाः स्मृताः", text: "bṛṃhaṇadra vyaniṣkvāthakalkairmadhurakairyutāḥ sarpirmāṃsarasopetā bastayo bṛṃhaṇāḥ smṛtāḥ" },
      { type: "verse", number: "23", sanskrit: "क्षीरसिद्धाः क्षौद्र युक्ता नाम्ना पिच्छिलसंज्ञिताः", text: "kṣīrasiddhāḥ kṣaudra yuktā nāmnā picchilasaṃjñitāḥ" },
      { type: "verse", number: "24", sanskrit: "अजोरभ्रैणरुधिरैर्युक्ता देया विचक्षणैः मात्रा पिच्छिलबस्तीनां पलैर्द्वादशभिर्मता", text: "ajorabhraiṇarudhirairyuktā deyā vicakṣaṇaiḥ mātrā picchilabastīnāṃ palairdvādaśabhirmatā" },
      { type: "verse", number: "25", sanskrit: "निरूहार्थं द्र व्याणां परिमाणपूर्वकं विधानम् दत्त्वादौ सैन्धवस्याक्षं मधुनः प्रसृतिद्वयम् विनिर्मथ्य ततो दद्यात्स्नेहस्य प्रसृतित्रयम्", text: "nirūhārthaṃ dra vyāṇāṃ parimāṇapūrvakaṃ vidhānam dattvādau saindhavasyākṣaṃ madhunaḥ prasṛtidvayam vinirmathya tato dadyātsnehasya prasṛtitrayam" },
      { type: "verse", number: "26", sanskrit: "एकीभूते ततः स्नेहे कल्कस्य प्रसृतिं क्षिपेत् संमूर्च्छिते कषायं तु चतुःप्रसृतिसंमितम्", text: "ekībhūte tataḥ snehe kalkasya prasṛtiṃ kṣipet saṃmūrcchite kaṣāyaṃ tu catuḥprasṛtisaṃmitam" },
      { type: "verse", number: "27", sanskrit: "क्षिप्त्वा विमथ्य दद्याच्च निरूहं कुशलो भिषक् वाते चतुष्पलं क्षौद्रं  दद्यात्स्नेहस्य षट्पलम्", text: "kṣiptvā vimathya dadyācca nirūhaṃ kuśalo bhiṣak vāte catuṣpalaṃ kṣaudraṃ  dadyātsnehasya ṣaṭpalam" },
      { type: "verse", number: "28", sanskrit: "पित्ते चतुष्पलं क्षौद्रं  स्नेहं दद्यात्पलत्रयम् कफे च षट्पलं क्षौद्रं  क्षिपेत्स्नेहं चतुष्पलम्", text: "pitte catuṣpalaṃ kṣaudraṃ  snehaṃ dadyātpalatrayam kaphe ca ṣaṭpalaṃ kṣaudraṃ  kṣipetsnehaṃ catuṣpalam" },
      { type: "verse", number: "29", sanskrit: "एरण्डक्वाथतुल्यांशं मधु तैलं पलाष्टकम्", text: "eraṇḍakvāthatulyāṃśaṃ madhu tailaṃ palāṣṭakam" },
      { type: "verse", number: "30", sanskrit: "शतपुष्पापलार्धेन सैन्धवार्धेन संयुतम् मधुतैलिकसंज्ञोऽय बस्तिः खजविलोडितः", text: "śatapuṣpāpalārdhena saindhavārdhena saṃyutam madhutailikasaṃjño'ya bastiḥ khajaviloḍitaḥ" },
      { type: "verse", number: "31", sanskrit: "बलवर्णकरश्चैव वृष्यो दीपनबृंहणः", text: "balavarṇakaraścaiva vṛṣyo dīpanabṛṃhaṇaḥ" },
      { type: "verse", number: "32", sanskrit: "क्षौद्रा ज्यक्षीरतैलानां प्रसृतं प्रसृतं भवेत् हपुषासैन्धवाक्षांशो बस्तिः स्याद्दीपनः परः", text: "kṣaudrā jyakṣīratailānāṃ prasṛtaṃ prasṛtaṃ bhavet hapuṣāsaindhavākṣāṃśo bastiḥ syāddīpanaḥ paraḥ" },
      { type: "verse", number: "33", sanskrit: "एरण्डमूलनिष्क्वाथो मधु तैलं ससैन्धवम् एष युक्तरथो बस्तिः सवचापिप्पलीफलः", text: "eraṇḍamūlaniṣkvātho madhu tailaṃ sasaindhavam eṣa yuktaratho bastiḥ savacāpippalīphalaḥ" },
      { type: "verse", number: "34", sanskrit: "पञ्चमूलस्य निष्क्वाथस्तैलं मागधिका मधु ससैन्धवः समधुकः सिद्धबस्तिरिति स्मृतः", text: "pañcamūlasya niṣkvāthastailaṃ māgadhikā madhu sasaindhavaḥ samadhukaḥ siddhabastiriti smṛtaḥ" },
      { type: "verse", number: "35", sanskrit: "स्नानमुष्णोदकैः कुर्याद्दिवास्वप्नमजीर्णताम् वर्जयेदपरं सर्वमाचरेत्स्नेहबस्तिवत्", text: "snānamuṣṇodakaiḥ kuryāddivāsvapnamajīrṇatām varjayedaparaṃ sarvamācaretsnehabastivat" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 7,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Тарпана нетра видхи — Питание глаз" },
      { type: "text", text: "Нетра-тарпана — удержание тёплого гхи над глазами в специальных плотинах из теста. Показания: сухость глаз, усталость, начальная катаракта." },
      { type: "verse", number: "1", sanskrit: "अथोत्तरबस्तिविधिर्नाम सप्तमोऽध्यायः तत्रादावुत्तरबस्तिस्वरूपम् अतः परं प्रवक्ष्यामि बस्तिमुत्तरसञ्ज्ञितम् द्वादशाङ्गुलकं नेत्रं मध्ये च कृतकर्णिकम् मालतीपुष्पवृन्ताभं छिद्रं  सर्षपसन्निभम्", text: "athottarabastividhirnāma saptamo'dhyāyaḥ tatrādāvuttarabastisvarūpam ataḥ paraṃ pravakṣyāmi bastimuttarasañjñitam dvādaśāṅgulakaṃ netraṃ madhye ca kṛtakarṇikam mālatīpuṣpavṛntābhaṃ chidraṃ  sarṣapasannibham" },
      { type: "verse", number: "2", sanskrit: "पञ्चविंशतिवर्षाणामधो मात्रा द्विकार्षिकी तदूर्ध्वं पलमात्रा च स्नेहस्योक्ता भिषग्वरैः", text: "pañcaviṃśativarṣāṇāmadho mātrā dvikārṣikī tadūrdhvaṃ palamātrā ca snehasyoktā bhiṣagvaraiḥ" },
      { type: "verse", number: "3", sanskrit: "अथास्थापनशुद्धस्य तृप्तस्य स्नानभोजनैः स्थितस्य जानुमात्रे च पीठेऽन्विष्य शलाकया", text: "athāsthāpanaśuddhasya tṛptasya snānabhojanaiḥ sthitasya jānumātre ca pīṭhe'nviṣya śalākayā" },
      { type: "verse", number: "4", sanskrit: "स्निग्धया मेढ्रमार्गे च ततो नेत्रं नियोजयेत् शनैः शनैर्घृताभ्यक्तं मेढ्ररन्ध्रेऽङ्गुलानि षट्", text: "snigdhayā meḍhramārge ca tato netraṃ niyojayet śanaiḥ śanairghṛtābhyaktaṃ meḍhrarandhre'ṅgulāni ṣaṭ" },
      { type: "verse", number: "5", sanskrit: "ततोऽवपीडयेद्बस्तिं शनैर्नेत्रं च निर्ह रेत् ततः प्रत्यागते स्नेहे स्नेहबस्तिक्रमो हितः", text: "tato'vapīḍayedbastiṃ śanairnetraṃ ca nirha ret tataḥ pratyāgate snehe snehabastikramo hitaḥ" },
      { type: "verse", number: "6", sanskrit: "स्त्रीणां कनिष्ठिकास्थूलं नेत्रं कुर्याद् दशांगुलम्", text: "strīṇāṃ kaniṣṭhikāsthūlaṃ netraṃ kuryād daśāṃgulam" },
      { type: "verse", number: "7", sanskrit: "मुद्गप्रवेशं योज्यं च योन्यन्तश्चतुरङ्गुलम् द्व्यङ्गुलं मूत्रमार्गे च सूक्ष्मं नेत्रं नियोजयेत्", text: "mudgapraveśaṃ yojyaṃ ca yonyantaścaturaṅgulam dvyaṅgulaṃ mūtramārge ca sūkṣmaṃ netraṃ niyojayet" },
      { type: "verse", number: "8", sanskrit: "मूत्रकृच्छ्रविकारेषु बालानां त्वेकमङ्गुलम् शनैर्निष्कम्पमाधेयं सूक्ष्मं नेत्रं विचक्षणः", text: "mūtrakṛcchravikāreṣu bālānāṃ tvekamaṅgulam śanairniṣkampamādheyaṃ sūkṣmaṃ netraṃ vicakṣaṇaḥ" },
      { type: "verse", number: "9", sanskrit: "स्त्रीणां बालानां च स्नेहमात्रा योनिमार्गेषु नारीणां स्नेहमात्रा द्विपालिकी मूत्रमार्गे पलोन्मानां बालानां च द्विकार्षिकी", text: "strīṇāṃ bālānāṃ ca snehamātrā yonimārgeṣu nārīṇāṃ snehamātrā dvipālikī mūtramārge palonmānāṃ bālānāṃ ca dvikārṣikī" },
      { type: "verse", number: "10", sanskrit: "उत्तानायै स्त्रियै दद्यादूर्ध्वजान्वै विचक्षणः अप्रत्यागच्छति भिषग्बस्तावुत्तरसंज्ञिते", text: "uttānāyai striyai dadyādūrdhvajānvai vicakṣaṇaḥ apratyāgacchati bhiṣagbastāvuttarasaṃjñite" },
      { type: "verse", number: "11", sanskrit: "भूयो बस्तिं निदध्याच्च संयुक्तैः शोधनैर्गणैः फलवर्त्तिं निदध्याद्वा योनिमार्गे दृढां भिषक्", text: "bhūyo bastiṃ nidadhyācca saṃyuktaiḥ śodhanairgaṇaiḥ phalavarttiṃ nidadhyādvā yonimārge dṛḍhāṃ bhiṣak" },
      { type: "verse", number: "12", sanskrit: "सूत्रैर्विनिर्मितां स्निग्धां शोधनद्र व्यसंयुताम् दह्यमाने तथा बस्तौ दद्याद्बस्तिं विशारदः", text: "sūtrairvinirmitāṃ snigdhāṃ śodhanadra vyasaṃyutām dahyamāne tathā bastau dadyādbastiṃ viśāradaḥ" },
      { type: "verse", number: "13", sanskrit: "क्षीरिवृक्षकषायेण पयसा शीतलेन वा बस्तिः शुक्ररुजः पुंसां स्त्रीणामार्त्तवजां रुजम् हन्यादुत्तरबस्तिस्तु नोचितो मेहिनां क्वचित्", text: "kṣīrivṛkṣakaṣāyeṇa payasā śītalena vā bastiḥ śukrarujaḥ puṃsāṃ strīṇāmārttavajāṃ rujam hanyāduttarabastistu nocito mehināṃ kvacit" },
      { type: "verse", number: "14", sanskrit: "सम्यग्दत्तस्य लिङ्गानि व्यापदःक्रम एव च बस्तेरुत्तरसंज्ञस्य समानं स्नेहबस्तिना", text: "samyagdattasya liṅgāni vyāpadaḥkrama eva ca basteruttarasaṃjñasya samānaṃ snehabastinā" },
      { type: "verse", number: "15", sanskrit: "घृताभ्यक्ते गुदे क्षेप्या श्लक्ष्णा स्वाङ्गुष्ठसंनिभा मलप्रवर्त्तिनी वर्त्तिः फलवर्त्तिश्च सा स्मृता", text: "ghṛtābhyakte gude kṣepyā ślakṣṇā svāṅguṣṭhasaṃnibhā malapravarttinī varttiḥ phalavarttiśca sā smṛtā" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 8,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Карна пурана видхи — Масляная терапия ушей" },
      { type: "text", text: "Карна-пурана — заполнение слухового прохода тёплым маслом. Показания: тиннитус, сухость ушного канала, тугоухость Вата-типа, боль в ухе." },
      { type: "verse", number: "1", sanskrit: "अथ नस्यविधिर्नाम अष्टमोऽध्यायः तत्र नस्यस्य निरुक्तिर्नाम च नस्यं तत्कथ्यते धीरैर्नासाग्राह्यं यदौषधम् नावनं नस्यकर्मेति तस्य नामद्वयं मतम्", text: "atha nasyavidhirnāma aṣṭamo'dhyāyaḥ tatra nasyasya niruktirnāma ca nasyaṃ tatkathyate dhīrairnāsāgrāhyaṃ yadauṣadham nāvanaṃ nasyakarmeti tasya nāmadvayaṃ matam" },
      { type: "verse", number: "2", sanskrit: "नस्यभेदो द्विधा प्रोक्तो रेचनं स्नेहनं तथा रेचनं कर्षणं प्रोक्तं स्नेहनं बृंहणं मतम्", text: "nasyabhedo dvidhā prokto recanaṃ snehanaṃ tathā recanaṃ karṣaṇaṃ proktaṃ snehanaṃ bṛṃhaṇaṃ matam" },
      { type: "verse", number: "3", sanskrit: "कफपित्तानिलध्वंसे पूर्वमध्यापराह्णके दिने तु गृह्यते नस्यं रात्रावप्युत्कटे गदे", text: "kaphapittāniladhvaṃse pūrvamadhyāparāhṇake dine tu gṛhyate nasyaṃ rātrāvapyutkaṭe gade" },
      { type: "verse", number: "4", sanskrit: "नस्यं त्यजेद्भोजनान्ते दुर्दिने चापतर्पणे तथा नवप्रतिश्यायी गर्भिणी गरदूषितः", text: "nasyaṃ tyajedbhojanānte durdine cāpatarpaṇe tathā navapratiśyāyī garbhiṇī garadūṣitaḥ" },
      { type: "verse", number: "5", sanskrit: "अजीर्णीदत्तबस्तिश्च पीतस्नेहोदकासवः क्रुद्धः शोकाभिभूतश्च तृषाऽत्तो वृद्धबालकौ वेगावरोधी स्नातश्च स्नातुकामश्च वर्जयेत्", text: "ajīrṇīdattabastiśca pītasnehodakāsavaḥ kruddhaḥ śokābhibhūtaśca tṛṣā'tto vṛddhabālakau vegāvarodhī snātaśca snātukāmaśca varjayet" },
      { type: "verse", number: "6", sanskrit: "अष्टवर्षस्य बालस्य नस्यकर्म समाचरेत् अशीतिवर्षादूर्ध्वं च नावनं नैव दीयते", text: "aṣṭavarṣasya bālasya nasyakarma samācaret aśītivarṣādūrdhvaṃ ca nāvanaṃ naiva dīyate" },
      { type: "verse", number: "7", sanskrit: "अथ वैरेचनं नस्यं ग्राह्यं तैलैः सुतीक्ष्णकैः तीक्ष्णभेषजसिद्धैर्वा स्नेहैः क्वाथै रसैस्तथा", text: "atha vairecanaṃ nasyaṃ grāhyaṃ tailaiḥ sutīkṣṇakaiḥ tīkṣṇabheṣajasiddhairvā snehaiḥ kvāthai rasaistathā" },
      { type: "verse", number: "8", sanskrit: "नासिकारन्ध्रयोरष्टौ षट् चत्वारश्च बिन्दवः प्रत्येकं रेचने योज्या मुख्यमध्यान्त्यमात्रया", text: "nāsikārandhrayoraṣṭau ṣaṭ catvāraśca bindavaḥ pratyekaṃ recane yojyā mukhyamadhyāntyamātrayā" },
      { type: "verse", number: "9", sanskrit: "नस्यकर्मणि दातव्यं शाणैकं तीक्ष्णमौषधम् हिङ्गु स्याद्यावमात्रं तु माषैकं सैन्धवं मतम्", text: "nasyakarmaṇi dātavyaṃ śāṇaikaṃ tīkṣṇamauṣadham hiṅgu syādyāvamātraṃ tu māṣaikaṃ saindhavaṃ matam" },
      { type: "verse", number: "10", sanskrit: "क्षीरं चैवाष्टशाणं स्यात्पानीयं च त्रिकार्षिकम् कार्षिकं मधुरं द्र व्यं नस्यकर्मणि योजयेत्", text: "kṣīraṃ caivāṣṭaśāṇaṃ syātpānīyaṃ ca trikārṣikam kārṣikaṃ madhuraṃ dra vyaṃ nasyakarmaṇi yojayet" },
      { type: "verse", number: "11", sanskrit: "अवपीडः प्रधमनं द्वौ भेदावपरौ स्मृतौ शिरोविरेचनस्यात्र तौ तु देयौ यथायथम्", text: "avapīḍaḥ pradhamanaṃ dvau bhedāvaparau smṛtau śirovirecanasyātra tau tu deyau yathāyatham" },
      { type: "verse", number: "12", sanskrit: "कल्कीकृतादौषधाद्यः पीडितो निःसृतो रसः सोऽवपीडः समुद्दिष्टस्तीक्ष्णद्र व्यसमुद्भवः", text: "kalkīkṛtādauṣadhādyaḥ pīḍito niḥsṛto rasaḥ so'vapīḍaḥ samuddiṣṭastīkṣṇadra vyasamudbhavaḥ" },
      { type: "verse", number: "13", sanskrit: "षडङ्गुला द्विवक्रा वा नाडी चूर्णं तया धमेत् तीक्ष्णं कोलमितं वक्त्रवातैः प्रधमनं हि तत्", text: "ṣaḍaṅgulā dvivakrā vā nāḍī cūrṇaṃ tayā dhamet tīkṣṇaṃ kolamitaṃ vaktravātaiḥ pradhamanaṃ hi tat" },
      { type: "verse", number: "14", sanskrit: "ऊर्ध्वजत्रुगते रोगे कफजे स्वरसंक्षये अरोचके प्रतिश्याये शिरःशूले च पीनसे शोफापस्मारकुष्ठेषु नस्यं वैरेचनं हितम्", text: "ūrdhvajatrugate roge kaphaje svarasaṃkṣaye arocake pratiśyāye śiraḥśūle ca pīnase śophāpasmārakuṣṭheṣu nasyaṃ vairecanaṃ hitam" },
      { type: "verse", number: "15", sanskrit: "भीरुस्त्रीकृशबालानां नस्यं स्नेहेन दीयते", text: "bhīrustrīkṛśabālānāṃ nasyaṃ snehena dīyate" },
      { type: "verse", number: "16", sanskrit: "गलरोगे सन्निपाते निद्रा यां विषमज्वरे मनोविकारे कृमिषु युज्यते चावपीडनम्", text: "galaroge sannipāte nidrā yāṃ viṣamajvare manovikāre kṛmiṣu yujyate cāvapīḍanam" },
      { type: "verse", number: "17", sanskrit: "अत्यन्तोत्कटदोषेषु विसंज्ञेषु च दीयते चूर्णं प्रधमनं धीरैस्तद्धि तीक्ष्णतरं यतः", text: "atyantotkaṭadoṣeṣu visaṃjñeṣu ca dīyate cūrṇaṃ pradhamanaṃ dhīraistaddhi tīkṣṇataraṃ yataḥ" },
      { type: "verse", number: "18", sanskrit: "अथावपीडनप्रधमनयोः कतिपययोगाः नस्यं स्याद् गुडशुण्ठीभ्यां पिप्पल्या सैन्धवेन च जलपिष्टेन तेनाक्षिकर्णनासाशिरोगदाः", text: "athāvapīḍanapradhamanayoḥ katipayayogāḥ nasyaṃ syād guḍaśuṇṭhībhyāṃ pippalyā saindhavena ca jalapiṣṭena tenākṣikarṇanāsāśirogadāḥ" },
      { type: "verse", number: "19", sanskrit: "मन्याहनुगलोद्भूता नश्यन्ति भुजपृष्ठजाः", text: "manyāhanugalodbhūtā naśyanti bhujapṛṣṭhajāḥ" },
      { type: "verse", number: "20", sanskrit: "मधूकसारकृष्णाभ्यां वचामरिचसैन्धवैः नस्यं कोष्णजले पिष्टं दद्यात्सञ्ज्ञाप्रबोधनम् अपस्मारे तथोन्मादे सन्निपातेऽपतन्त्रके", text: "madhūkasārakṛṣṇābhyāṃ vacāmaricasaindhavaiḥ nasyaṃ koṣṇajale piṣṭaṃ dadyātsañjñāprabodhanam apasmāre tathonmāde sannipāte'patantrake" },
      { type: "verse", number: "21", sanskrit: "तन्द्रा यां सैन्धवादि नस्यम् सैन्धवं श्वेतमरिचं सर्षपाः कुष्ठमेव च बस्तमूत्रेण पिष्टानि नस्यं तन्द्रा निवारणम्", text: "tandrā yāṃ saindhavādi nasyam saindhavaṃ śvetamaricaṃ sarṣapāḥ kuṣṭhameva ca bastamūtreṇa piṣṭāni nasyaṃ tandrā nivāraṇam" },
      { type: "verse", number: "22", sanskrit: "रोहितमत्स्यपित्तेन भावितं सैन्धवं वचा", text: "rohitamatsyapittena bhāvitaṃ saindhavaṃ vacā" },
      { type: "verse", number: "23", sanskrit: "मरिचं पिप्पली शुण्ठी कङ्कोलं लशुनं परम् कट्फलं चेति तच्चूर्णं देयं प्रधमनं बुधैः", text: "maricaṃ pippalī śuṇṭhī kaṅkolaṃ laśunaṃ param kaṭphalaṃ ceti taccūrṇaṃ deyaṃ pradhamanaṃ budhaiḥ" },
      { type: "verse", number: "24", sanskrit: "अथ बृंहणनस्यस्य कल्पना कथ्यतेऽधुना मर्शश्च प्रतिमर्शश्च द्वौ भेदौ स्नेहनौ मतौ", text: "atha bṛṃhaṇanasyasya kalpanā kathyate'dhunā marśaśca pratimarśaśca dvau bhedau snehanau matau" },
      { type: "verse", number: "25", sanskrit: "मर्शस्य तर्पणी मात्रा मुख्या शाणैः स्मृताऽष्टभिः मध्यमा च चतुःशाणैर्हीना शाणमिता स्मृता", text: "marśasya tarpaṇī mātrā mukhyā śāṇaiḥ smṛtā'ṣṭabhiḥ madhyamā ca catuḥśāṇairhīnā śāṇamitā smṛtā" },
      { type: "verse", number: "26", sanskrit: "एकैकस्मिंस्तु मात्रेयं देया नासापुटे बुधैः मर्शस्य द्वित्रिवेलं वा वीक्ष्य दोषबलाबलम्", text: "ekaikasmiṃstu mātreyaṃ deyā nāsāpuṭe budhaiḥ marśasya dvitrivelaṃ vā vīkṣya doṣabalābalam" },
      { type: "verse", number: "27", sanskrit: "एकान्तरं द्व्यन्तरं वा नस्यं दद्याद्विचक्षणः त्र्! यहं पञ्चाहमथवा सप्ताहंवा सुयन्त्रितम्", text: "ekāntaraṃ dvyantaraṃ vā nasyaṃ dadyādvicakṣaṇaḥ tr! yahaṃ pañcāhamathavā saptāhaṃvā suyantritam" },
      { type: "verse", number: "28", sanskrit: "मर्शे शिरोविरेके च व्यापदो विविधाः स्मृताः दोषोत्क्लेशात्क्षयाच्चैव विज्ञेयास्ता यथाक्रमम्", text: "marśe śirovireke ca vyāpado vividhāḥ smṛtāḥ doṣotkleśātkṣayāccaiva vijñeyāstā yathākramam" },
      { type: "verse", number: "29", sanskrit: "दोषोत्क्लेशनिमित्तासु युञ्ज्याद्वमनशोधनम् अथ क्षयनिमित्तासु यथास्वं बृंहणं हितम्", text: "doṣotkleśanimittāsu yuñjyādvamanaśodhanam atha kṣayanimittāsu yathāsvaṃ bṛṃhaṇaṃ hitam" },
      { type: "verse", number: "30", sanskrit: "शिरोनासाऽक्षिरोगेषु सूर्यावर्त्तार्धभेदके दन्तरोगे बले हीने मन्याबाह्वंसजे गदे", text: "śironāsā'kṣirogeṣu sūryāvarttārdhabhedake dantaroge bale hīne manyābāhvaṃsaje gade" },
      { type: "verse", number: "31", sanskrit: "मुखशोषे कर्णनादे वातपित्तगदे तथा अकालपलिते चैव केशश्मश्रुप्रपातने युज्यते बृंहणं नस्यं स्नेहैर्वा मधुरद्र वैः", text: "mukhaśoṣe karṇanāde vātapittagade tathā akālapalite caiva keśaśmaśruprapātane yujyate bṛṃhaṇaṃ nasyaṃ snehairvā madhuradra vaiḥ" },
      { type: "verse", number: "32", sanskrit: "सशर्करं पयःपिष्ठं भृष्टमाज्येन कुङ्कुमम्", text: "saśarkaraṃ payaḥpiṣṭhaṃ bhṛṣṭamājyena kuṅkumam" },
      { type: "verse", number: "33", sanskrit: "नस्यप्रयोगतो हन्याद्वातरक्तभवा रुजः भ्रूशङ्खाक्षिशिरः कर्णसूर्यावर्त्तार्धभेदकान्", text: "nasyaprayogato hanyādvātaraktabhavā rujaḥ bhrūśaṅkhākṣiśiraḥ karṇasūryāvarttārdhabhedakān" },
      { type: "verse", number: "34", sanskrit: "नस्यं स्यादणुतैलेन तथा नारायणेन वा माषादिना वा सर्पिर्भिस्तत्तद्भेषजसाधितैः", text: "nasyaṃ syādaṇutailena tathā nārāyaṇena vā māṣādinā vā sarpirbhistattadbheṣajasādhitaiḥ" },
      { type: "verse", number: "35", sanskrit: "दोषानुसारेण नस्ये स्नेहव्यस्था तैलं कफे स्याद्वाते च केवले पवने वसा दद्यान्नस्यं सदा पित्ते सर्पिर्मज्जानमेव च", text: "doṣānusāreṇa nasye snehavyasthā tailaṃ kaphe syādvāte ca kevale pavane vasā dadyānnasyaṃ sadā pitte sarpirmajjānameva ca" },
      { type: "verse", number: "36", sanskrit: "कृतोऽश्वगन्धया क्वाथो हिङ्गुसैन्धवसंयुतः", text: "kṛto'śvagandhayā kvātho hiṅgusaindhavasaṃyutaḥ" },
      { type: "verse", number: "37", sanskrit: "कोष्णो नस्यप्रयोगेण पक्षाघातं सकम्पनम् जयेदर्दितवातं च मन्यास्तम्भापबाहुकौ", text: "koṣṇo nasyaprayogeṇa pakṣāghātaṃ sakampanam jayedarditavātaṃ ca manyāstambhāpabāhukau" },
      { type: "verse", number: "38", sanskrit: "प्रतिमर्शस्य मात्रा तु द्विद्विबिन्दुमिता मता प्रत्येकशो नस्तकयोः स्नेहेनेति विनिश्चितम्", text: "pratimarśasya mātrā tu dvidvibindumitā matā pratyekaśo nastakayoḥ sneheneti viniścitam" },
      { type: "verse", number: "39", sanskrit: "स्नेहे ग्रन्थिद्वयं यावन्निमग्ना चोद्धृता ततः तर्जनी यं स्रवेद्विन्दुं सा मात्रा बिन्दुसञ्ज्ञिता", text: "snehe granthidvayaṃ yāvannimagnā coddhṛtā tataḥ tarjanī yaṃ sravedvinduṃ sā mātrā bindusañjñitā" },
      { type: "verse", number: "40", sanskrit: "एवं विधैर्बिन्दुसञ्ज्ञैरष्टभिः शाण उच्यते स देयो मर्शनस्ये तु प्रतिमर्शो द्विबिन्दुकः", text: "evaṃ vidhairbindusañjñairaṣṭabhiḥ śāṇa ucyate sa deyo marśanasye tu pratimarśo dvibindukaḥ" },
      { type: "verse", number: "41", sanskrit: "प्रतिमर्शनस्यस्य चतुर्दशसमयः समयाः प्रतिमर्शस्य बुधैः प्रोक्ताश्चतुर्दश प्रभाते दन्तकाष्ठान्ते गृहान्निर्गमने तथा", text: "pratimarśanasyasya caturdaśasamayaḥ samayāḥ pratimarśasya budhaiḥ proktāścaturdaśa prabhāte dantakāṣṭhānte gṛhānnirgamane tathā" },
      { type: "verse", number: "42", sanskrit: "व्यायामाध्वव्यवायान्ते विण्मूत्रान्तेऽञ्जने कृते कवलान्ते भोजनान्ते दिवासुप्तोत्थिते तथा वमनान्ते तथा सायं प्रतिमर्शः प्रयुज्यते", text: "vyāyāmādhvavyavāyānte viṇmūtrānte'ñjane kṛte kavalānte bhojanānte divāsuptotthite tathā vamanānte tathā sāyaṃ pratimarśaḥ prayujyate" },
      { type: "verse", number: "43", sanskrit: "प्रतिमर्शनस्यस्य निषिक्तलक्षणम् ईषदुच्छिक्कनात्स्नेहो यदा वक्त्रं प्रपद्यते", text: "pratimarśanasyasya niṣiktalakṣaṇam īṣaducchikkanātsneho yadā vaktraṃ prapadyate" },
      { type: "verse", number: "44", sanskrit: "नस्ये निषिक्तं तं विद्यात्प्रतिमर्शप्रमाणतः उच्छिन्दन्न पिबेच्चैतन्निष्ठीवेन्मुखमागतम्", text: "nasye niṣiktaṃ taṃ vidyātpratimarśapramāṇataḥ ucchindanna pibeccaitanniṣṭhīvenmukhamāgatam" },
      { type: "verse", number: "45", sanskrit: "क्षीणे तृष्णास्यशीर्षार्त्ते बाले वृद्धे च युज्यते प्रतिमर्शेनशाम्यन्ति रोगाश्चैवोर्ध्वजत्रुजाः वलीपलितनाशश्च बलमिन्द्रि यजं भवेत्", text: "kṣīṇe tṛṣṇāsyaśīrṣārtte bāle vṛddhe ca yujyate pratimarśenaśāmyanti rogāścaivordhvajatrujāḥ valīpalitanāśaśca balamindri yajaṃ bhavet" },
      { type: "verse", number: "46", sanskrit: "बिभीतनिम्बगम्भारी शिवा शेलुश्च काकिनी एकैकतैलनस्येन पलितं नश्यति ध्रुवम्", text: "bibhītanimbagambhārī śivā śeluśca kākinī ekaikatailanasyena palitaṃ naśyati dhruvam" },
      { type: "verse", number: "47", sanskrit: "अथ नस्यविधिं वक्ष्ये नस्यग्रहणहेतवे देशे वातरजोमुक्ते कृतदन्तनिघर्षणम्", text: "atha nasyavidhiṃ vakṣye nasyagrahaṇahetave deśe vātarajomukte kṛtadantanigharṣaṇam" },
      { type: "verse", number: "48", sanskrit: "विशुद्धं धूमपानेन स्विन्नभालगलं तथा उत्तानशायिनं किंचित्प्रलम्बशिरसं नरम्", text: "viśuddhaṃ dhūmapānena svinnabhālagalaṃ tathā uttānaśāyinaṃ kiṃcitpralambaśirasaṃ naram" },
      { type: "verse", number: "49", sanskrit: "आस्तीर्णहस्तपादं च वस्त्राच्छादितलोचनम् समुन्नमितनासाऽग्र वैद्यौ नस्येन योजयेत्", text: "āstīrṇahastapādaṃ ca vastrācchāditalocanam samunnamitanāsā'gra vaidyau nasyena yojayet" },
      { type: "verse", number: "50", sanskrit: "कोष्णमच्छिन्नधारं च हेमतारादिशुक्तिभिः शुक्त्या वा यत्र युक्त्या वा प्लोतैर्वा नस्यमाचरेत्", text: "koṣṇamacchinnadhāraṃ ca hematārādiśuktibhiḥ śuktyā vā yatra yuktyā vā plotairvā nasyamācaret" },
      { type: "verse", number: "51", sanskrit: "नस्यप्रयोगसमये वर्ज्या विषयाः नस्येष्वासिच्यमानेषु शिरो नैव प्रकम्पयेत् न कुप्येन्न प्रभाषेत नोच्छिन्देन्नहसेत्तथा", text: "nasyaprayogasamaye varjyā viṣayāḥ nasyeṣvāsicyamāneṣu śiro naiva prakampayet na kupyenna prabhāṣeta nocchindennahasettathā" },
      { type: "verse", number: "52", sanskrit: "एतैर्हि विहितः स्नेहो नैवान्तः संप्रपद्यते", text: "etairhi vihitaḥ sneho naivāntaḥ saṃprapadyate" },
      { type: "verse", number: "53", sanskrit: "ततः कासप्रतिश्यायशिरोऽक्षिगदसम्भवः शृङ्गाटकमभिप्लाव्य स्थापयेन्न गिलेद् द्र वम्", text: "tataḥ kāsapratiśyāyaśiro'kṣigadasambhavaḥ śṛṅgāṭakamabhiplāvya sthāpayenna giled dra vam" },
      { type: "verse", number: "54", sanskrit: "पञ्च सप्त दशैव स्युर्मात्रा नस्यस्य धारणे", text: "pañca sapta daśaiva syurmātrā nasyasya dhāraṇe" },
      { type: "verse", number: "55", sanskrit: "नस्यधारणानन्तरं कर्त्तव्यकर्म उपविश्याथ निष्ठीवेन्नासावक्त्रगतं द्र वम् वामदक्षिणपार्श्वाभ्यां निष्ठीवेत्सम्मुखे न हि", text: "nasyadhāraṇānantaraṃ karttavyakarma upaviśyātha niṣṭhīvennāsāvaktragataṃ dra vam vāmadakṣiṇapārśvābhyāṃ niṣṭhīvetsammukhe na hi" },
      { type: "verse", number: "56", sanskrit: "नस्ये नीते मनस्तापं रजः क्रोधं च सन्त्यजेत् शयीत निद्रा ं! त्यक्त्वा च प्रोत्तानो वाक्शतं नरः तथा वैरेचनस्यान्ते धूमो वा कवलो हितः", text: "nasye nīte manastāpaṃ rajaḥ krodhaṃ ca santyajet śayīta nidrā ṃ! tyaktvā ca prottāno vākśataṃ naraḥ tathā vairecanasyānte dhūmo vā kavalo hitaḥ" },
      { type: "verse", number: "57", sanskrit: "नस्ये त्रीण्युपदिष्टानि लक्षणानि प्रयोगतः शुद्धिहीनातियोगानि विशेषाच्छास्त्रचिन्तकैः", text: "nasye trīṇyupadiṣṭāni lakṣaṇāni prayogataḥ śuddhihīnātiyogāni viśeṣācchāstracintakaiḥ" },
      { type: "verse", number: "58", sanskrit: "लाघवं मनसः शुद्धिः स्रोतसां व्याधिसंक्षयः चित्तेन्द्रि यप्रसादश्च शिरसः शुद्धिलक्षणम्", text: "lāghavaṃ manasaḥ śuddhiḥ srotasāṃ vyādhisaṃkṣayaḥ cittendri yaprasādaśca śirasaḥ śuddhilakṣaṇam" },
      { type: "verse", number: "59", sanskrit: "कण्डूपदेहोगुरुता स्रोतसां कफसंस्रवः मूर्ध्नि हीनविशुद्धेस्तु लक्षणं परिकीर्त्तितम्", text: "kaṇḍūpadehogurutā srotasāṃ kaphasaṃsravaḥ mūrdhni hīnaviśuddhestu lakṣaṇaṃ parikīrttitam" },
      { type: "verse", number: "60", sanskrit: "मस्तुलुङ्गागमो वातवृद्धिरिन्द्रि यविभ्रमः शून्यता शिरसश्चापि मूर्ध्नि गाढं विरेचिते", text: "mastuluṅgāgamo vātavṛddhirindri yavibhramaḥ śūnyatā śirasaścāpi mūrdhni gāḍhaṃ virecite" },
      { type: "verse", number: "61", sanskrit: "हीनातिशुद्धे शिरसि कफवातघ्नमाचरेत् सम्यग्विशुद्धे शिरसि सर्पिर्नस्ये निषेचयेत्", text: "hīnātiśuddhe śirasi kaphavātaghnamācaret samyagviśuddhe śirasi sarpirnasye niṣecayet" },
      { type: "verse", number: "62", sanskrit: "अतिस्निग्धस्य लक्षणं चिकित्सा च कफप्रसेकः शिरसो गुरुतेन्द्रि यविभ्रमः लक्षणं तदतिस्निग्धे तत्र रूक्षं प्रदापयेत् भोजयेच्चानभिष्यन्दि नस्याचारिकमादिशेत्", text: "atisnigdhasya lakṣaṇaṃ cikitsā ca kaphaprasekaḥ śiraso gurutendri yavibhramaḥ lakṣaṇaṃ tadatisnigdhe tatra rūkṣaṃ pradāpayet bhojayeccānabhiṣyandi nasyācārikamādiśet" },
      { type: "verse", number: "63", sanskrit: "वमनं रेचनं नस्यं निरूहश्चानुवासनम् एतानि पञ्च कर्माणि कथितानि मुनीश्वरैः", text: "vamanaṃ recanaṃ nasyaṃ nirūhaścānuvāsanam etāni pañca karmāṇi kathitāni munīśvaraiḥ" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 9,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Абхьянга видхи — Масляный массаж" },
      { type: "text", text: "Абхьянга — ежедневный масляный массаж всего тела как часть Диначарьи (ежедневного режима). Описываются техника, масла по конституции и ожидаемые результаты." },
      { type: "verse", number: "1", sanskrit: "अथ धूमपानविधिर्नाम नवमोऽध्यायः तत्र धूमसंख्या धूमस्तु षड्विधः प्रोक्तः शमनो बृंहणस्तथा रेचनः कासहा चैव वामनो व्रणधूपनः", text: "atha dhūmapānavidhirnāma navamo'dhyāyaḥ tatra dhūmasaṃkhyā dhūmastu ṣaḍvidhaḥ proktaḥ śamano bṛṃhaṇastathā recanaḥ kāsahā caiva vāmano vraṇadhūpanaḥ" },
      { type: "verse", number: "2", sanskrit: "शमनबृंहणरेचनधूमानां पर्यायाः शमनस्य तु पर्यायौ मध्यः प्रायोगिकस्तथा बृंहणस्यापि पर्यायौ स्नेहनो मृदुरेव च रेचनस्यापि पर्यायौ शोधनस्तीक्ष्ण एव च", text: "śamanabṛṃhaṇarecanadhūmānāṃ paryāyāḥ śamanasya tu paryāyau madhyaḥ prāyogikastathā bṛṃhaṇasyāpi paryāyau snehano mṛdureva ca recanasyāpi paryāyau śodhanastīkṣṇa eva ca" },
      { type: "verse", number: "3", sanskrit: "अधूमार्हाश्च खल्वेते श्रान्तो भीतश्च दुःखितः", text: "adhūmārhāśca khalvete śrānto bhītaśca duḥkhitaḥ" },
      { type: "verse", number: "4", sanskrit: "दत्तबस्तिर्विरिक्तश्च रात्रौ जागरितस्तथा पिपासितश्च दाहार्तस्तालुशोषी तथोदरी", text: "dattabastirviriktaśca rātrau jāgaritastathā pipāsitaśca dāhārtastāluśoṣī tathodarī" },
      { type: "verse", number: "5", sanskrit: "शिरोऽभितापी तिमिरी छर्द्याध्मानप्रपीडितः क्षतोरस्कः प्रमेहार्तः पाण्डुरोगी च गर्भिणी", text: "śiro'bhitāpī timirī chardyādhmānaprapīḍitaḥ kṣatoraskaḥ pramehārtaḥ pāṇḍurogī ca garbhiṇī" },
      { type: "verse", number: "6", sanskrit: "रूक्षः क्षीणोऽभ्यवहृतक्षीरक्षौद्र घृतासवः भुक्तान्नदधिमत्स्यश्च बालो वृद्धः कृशस्तथा", text: "rūkṣaḥ kṣīṇo'bhyavahṛtakṣīrakṣaudra ghṛtāsavaḥ bhuktānnadadhimatsyaśca bālo vṛddhaḥ kṛśastathā" },
      { type: "verse", number: "7", sanskrit: "अकाले धूमपाने दोषस्तत्प्रतीकारश्च अकाले चातिपीतश्च धूमः कुर्यादुपद्र वान् तत्रेष्टं सर्पिषः पानं नावनाञ्जनतर्पणम्", text: "akāle dhūmapāne doṣastatpratīkāraśca akāle cātipītaśca dhūmaḥ kuryādupadra vān tatreṣṭaṃ sarpiṣaḥ pānaṃ nāvanāñjanatarpaṇam" },
      { type: "verse", number: "8", sanskrit: "सर्पिरिक्षुरसं द्रा क्षां पयो वा शर्कराम्बु वा मधुराम्लौ रसौ वाऽपि शमनाय प्रदापयेत्", text: "sarpirikṣurasaṃ drā kṣāṃ payo vā śarkarāmbu vā madhurāmlau rasau vā'pi śamanāya pradāpayet" },
      { type: "verse", number: "9", sanskrit: "धूमस्तु द्वादशाद्वर्षाद् गृह्यतेऽशीतिकान्न च कासश्वासप्रतिश्यायान्मन्याहनुशिरोरुजः", text: "dhūmastu dvādaśādvarṣād gṛhyate'śītikānna ca kāsaśvāsapratiśyāyānmanyāhanuśirorujaḥ" },
      { type: "verse", number: "10", sanskrit: "वातश्लेष्मविकारांश्च हन्याद् धूमः सुयोजितः धूमप्रयोगात्पुरुषः प्रसन्नेन्द्रि यवाङ्मनाः दृढकेशद्विजश्मश्रुः सुगन्धिवदनो भवेत्", text: "vātaśleṣmavikārāṃśca hanyād dhūmaḥ suyojitaḥ dhūmaprayogātpuruṣaḥ prasannendri yavāṅmanāḥ dṛḍhakeśadvijaśmaśruḥ sugandhivadano bhavet" },
      { type: "verse", number: "11", sanskrit: "धूमनाडी भवेत्तत्र त्रिखण्डा च त्रिपर्विका", text: "dhūmanāḍī bhavettatra trikhaṇḍā ca triparvikā" },
      { type: "verse", number: "12", sanskrit: "कनिष्ठिकापरीणाहा राजमाषागमान्तरा धूमनाडी भवेद्दीर्घा शमने रोगिणोऽङ्गुलैः", text: "kaniṣṭhikāparīṇāhā rājamāṣāgamāntarā dhūmanāḍī bhaveddīrghā śamane rogiṇo'ṅgulaiḥ" },
      { type: "verse", number: "13", sanskrit: "चत्वारिंशन्मितैस्तद्वद् द्वात्रिंशद्भिर्मृदौ मता तीक्ष्णे चतुर्विंशतिभिः कासघ्नी षोडशोन्मितैः", text: "catvāriṃśanmitaistadvad dvātriṃśadbhirmṛdau matā tīkṣṇe caturviṃśatibhiḥ kāsaghnī ṣoḍaśonmitaiḥ" },
      { type: "verse", number: "14", sanskrit: "दशाङ्गुलैर्वामनीये तथा स्याद् व्रणनाडिका कलायमण्डलस्थूला कुलत्थागमरन्ध्रिका", text: "daśāṅgulairvāmanīye tathā syād vraṇanāḍikā kalāyamaṇḍalasthūlā kulatthāgamarandhrikā" },
      { type: "verse", number: "15", sanskrit: "अथेषिकां प्रलिम्पेच्च सुश्लक्ष्णां द्वादशाङ्गुलाम् धूमद्र व्यस्य कल्केन लेपश्चाष्टाङ्गुलः स्मृतः", text: "atheṣikāṃ pralimpecca suślakṣṇāṃ dvādaśāṅgulām dhūmadra vyasya kalkena lepaścāṣṭāṅgulaḥ smṛtaḥ" },
      { type: "verse", number: "16", sanskrit: "कल्कं कर्षमितं लिप्त्वा छायाशुष्कं च कारयेत् ईषिकामपनीयाथ स्नेहाक्तां वर्त्तिमादरात्", text: "kalkaṃ karṣamitaṃ liptvā chāyāśuṣkaṃ ca kārayet īṣikāmapanīyātha snehāktāṃ varttimādarāt" },
      { type: "verse", number: "17", sanskrit: "अङ्गारैर्दीपितां कृत्वा धृत्वा नेत्रस्य रन्ध्रके वदनेन पिबेद् धूमं वदनेनैव सन्त्यजेत्", text: "aṅgārairdīpitāṃ kṛtvā dhṛtvā netrasya randhrake vadanena pibed dhūmaṃ vadanenaiva santyajet" },
      { type: "verse", number: "18", sanskrit: "नासिकाभ्यां ततः पीत्वा मुखेनैव वमेत्सुधीः शरावसम्पुटे क्षिप्त्वा कल्कमङ्गारदीपितम् छिद्रे  नेत्रं निवेश्याथ व्रणं तेनैव धूपयेत्", text: "nāsikābhyāṃ tataḥ pītvā mukhenaiva vametsudhīḥ śarāvasampuṭe kṣiptvā kalkamaṅgāradīpitam chidre  netraṃ niveśyātha vraṇaṃ tenaiva dhūpayet" },
      { type: "verse", number: "19", sanskrit: "एलादिकल्कं शमने स्निग्धं सर्जरसं मृदौ रेचने तीक्ष्णकल्कं च कासघ्नं क्षुद्रि कोषणम्", text: "elādikalkaṃ śamane snigdhaṃ sarjarasaṃ mṛdau recane tīkṣṇakalkaṃ ca kāsaghnaṃ kṣudri koṣaṇam" },
      { type: "verse", number: "20", sanskrit: "वामने स्नायुचर्माद्यं दद्याद् धूमस्य पानकम् व्रणे निम्बवचाद्यं च धूपनं सम्प्रशस्यते", text: "vāmane snāyucarmādyaṃ dadyād dhūmasya pānakam vraṇe nimbavacādyaṃ ca dhūpanaṃ sampraśasyate" },
      { type: "verse", number: "21", sanskrit: "अन्येऽपि धूमा गेहेषु कर्तव्या रोगशान्तये", text: "anye'pi dhūmā geheṣu kartavyā rogaśāntaye" },
      { type: "verse", number: "22", sanskrit: "मयूरपिच्छं निम्बस्य पत्राणि बृहतीफलम् मरिचं हिङ्गु मांसी च बीजं कार्पाससम्भवम्", text: "mayūrapicchaṃ nimbasya patrāṇi bṛhatīphalam maricaṃ hiṅgu māṃsī ca bījaṃ kārpāsasambhavam" },
      { type: "verse", number: "23", sanskrit: "छागरोमाहिनिर्मोकं विष्ठा वैडालिकी तथा गजदन्तश्च तच्चूर्णं किच्चिद्घृतविमिश्रितम्", text: "chāgaromāhinirmokaṃ viṣṭhā vaiḍālikī tathā gajadantaśca taccūrṇaṃ kiccidghṛtavimiśritam" },
      { type: "verse", number: "24", sanskrit: "गेहेषु धूपनं दत्तं सर्वान्बालग्रहाञ्जयेत् पिशाचान्राक्षसाञ्जित्वा सर्वज्वरहरं भवेत्", text: "geheṣu dhūpanaṃ dattaṃ sarvānbālagrahāñjayet piśācānrākṣasāñjitvā sarvajvaraharaṃ bhavet" },
      { type: "verse", number: "25", sanskrit: "धूमपाने पथ्यं नेत्रद्र व्याणि च परिहारस्तु धूमेषु कार्यो रेचननस्यवत् नेत्राणि धातुजान्याहुर्नलवंशादिजान्यपि", text: "dhūmapāne pathyaṃ netradra vyāṇi ca parihārastu dhūmeṣu kāryo recananasyavat netrāṇi dhātujānyāhurnalavaṃśādijānyapi" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 10,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Свэда видхи — Паровая терапия" },
      { type: "text", text: "Сведана (паровая терапия) — методы потогонного лечения. Шарангадхара систематизирует 13 видов сведаны: паровая баня, горячие обёртывания, горячие компрессы." },
      { type: "verse", number: "1", sanskrit: "अथ गण्डूषकवलप्रतिसारणविधिर्नाम दशमोऽध्यायः तत्र गण्डूषकवलयोर्भेदा! चतुर्विधः स्याद्गण्डूषः स्नैहिकः शमनस्तथा शोधनो रोपणश्चैव कवलश्चापि तद्विधः", text: "atha gaṇḍūṣakavalapratisāraṇavidhirnāma daśamo'dhyāyaḥ tatra gaṇḍūṣakavalayorbhedā! caturvidhaḥ syādgaṇḍūṣaḥ snaihikaḥ śamanastathā śodhano ropaṇaścaiva kavalaścāpi tadvidhaḥ" },
      { type: "verse", number: "2", sanskrit: "स्निग्धोष्णैः स्नैहिको वाते स्वादुशीतैः प्रसादनः पित्ते कट्वम्ललवणैरुष्णैः संशोधनः कफे", text: "snigdhoṣṇaiḥ snaihiko vāte svāduśītaiḥ prasādanaḥ pitte kaṭvamlalavaṇairuṣṇaiḥ saṃśodhanaḥ kaphe" },
      { type: "verse", number: "3", sanskrit: "कषायतिक्तमधुरैः कदुष्णो रोपणो व्रणे चतुष्प्रकारो गण्डूषः कवलश्चापि कीर्त्तितः", text: "kaṣāyatiktamadhuraiḥ kaduṣṇo ropaṇo vraṇe catuṣprakāro gaṇḍūṣaḥ kavalaścāpi kīrttitaḥ" },
      { type: "verse", number: "4", sanskrit: "असञ्चारी मुखे पूर्णे गण्डूषः कवलश्चरः तत्र द्र वेण गण्डूषः कल्केन कवलः स्मृतः", text: "asañcārī mukhe pūrṇe gaṇḍūṣaḥ kavalaścaraḥ tatra dra veṇa gaṇḍūṣaḥ kalkena kavalaḥ smṛtaḥ" },
      { type: "verse", number: "5", sanskrit: "दद्याद् द्र वेषु चूर्णं च गण्डूषे कोलमात्रकम् कर्षप्रमाणः कल्कश्च दीयते कवले बुधैः", text: "dadyād dra veṣu cūrṇaṃ ca gaṇḍūṣe kolamātrakam karṣapramāṇaḥ kalkaśca dīyate kavale budhaiḥ" },
      { type: "verse", number: "6", sanskrit: "गण्डूषस्य योग्याऽवस्था तद्धारणप्रमाणं च धार्यन्ते पञ्चमाद्वर्षाद्गण्डूषकवलादयः गण्डूषान्सुस्थितः कुर्यात्स्विन्नभालगलादिकः", text: "gaṇḍūṣasya yogyā'vasthā taddhāraṇapramāṇaṃ ca dhāryante pañcamādvarṣādgaṇḍūṣakavalādayaḥ gaṇḍūṣānsusthitaḥ kuryātsvinnabhālagalādikaḥ" },
      { type: "verse", number: "7", sanskrit: "मनुष्यस्त्रींस्तथा पञ्च सप्त वा दोषनाशनात् कफपूर्णास्यता यावच्छेदो दोषस्य वा भवेत् नेत्रघ्राणस्रुतिर्यावत्तावद् गण्डूषधारणम्", text: "manuṣyastrīṃstathā pañca sapta vā doṣanāśanāt kaphapūrṇāsyatā yāvacchedo doṣasya vā bhavet netraghrāṇasrutiryāvattāvad gaṇḍūṣadhāraṇam" },
      { type: "verse", number: "8", sanskrit: "तिलकल्कोदकं क्षीरं स्नेहो वा स्नैहिके हितः", text: "tilakalkodakaṃ kṣīraṃ sneho vā snaihike hitaḥ" },
      { type: "verse", number: "9", sanskrit: "तिला नीलोत्पलं सर्पिः शर्करा क्षीरमेव च सक्षौद्रो  हनुवक्त्रस्थो गण्डूषो दाहनाशनः", text: "tilā nīlotpalaṃ sarpiḥ śarkarā kṣīrameva ca sakṣaudro  hanuvaktrastho gaṇḍūṣo dāhanāśanaḥ" },
      { type: "verse", number: "10", sanskrit: "वैशद्यं जनयत्यास्ये सन्दधाति मुखव्रणान् दाहतृष्णाप्रशमनं मधुगण्डूषधारणम्", text: "vaiśadyaṃ janayatyāsye sandadhāti mukhavraṇān dāhatṛṣṇāpraśamanaṃ madhugaṇḍūṣadhāraṇam" },
      { type: "verse", number: "11", sanskrit: "विषक्षाराग्निदग्धे च सर्पिधार्यं पयोऽथवा", text: "viṣakṣārāgnidagdhe ca sarpidhāryaṃ payo'thavā" },
      { type: "verse", number: "12", sanskrit: "तैलसैन्धवगण्डूषो दन्तचाले प्रशस्यते", text: "tailasaindhavagaṇḍūṣo dantacāle praśasyate" },
      { type: "verse", number: "13", sanskrit: "मुखशोषे कफे च हितः काञ्जिकगण्डूषः शोषं मुखस्य वैरस्यं गण्डूषः काञ्जिको जयेत् सिन्धुत्रिकटुराजीभिरार्द्र केण कफे हितः", text: "mukhaśoṣe kaphe ca hitaḥ kāñjikagaṇḍūṣaḥ śoṣaṃ mukhasya vairasyaṃ gaṇḍūṣaḥ kāñjiko jayet sindhutrikaṭurājībhirārdra keṇa kaphe hitaḥ" },
      { type: "verse", number: "14", sanskrit: "त्रिफलामधुगण्डूषः कफासृक्पित्तनाशनः", text: "triphalāmadhugaṇḍūṣaḥ kaphāsṛkpittanāśanaḥ" },
      { type: "verse", number: "15", sanskrit: "दार्वी गुडूची त्रिफला द्रा क्षा जात्याश्च पल्लवाः यवासश्चेति तत्क्वाथः षष्ठांशक्षौद्र संयुतः शीतो मुखे धृतो हन्यान्मुखपाकं त्रिदोषजम्", text: "dārvī guḍūcī triphalā drā kṣā jātyāśca pallavāḥ yavāsaśceti tatkvāthaḥ ṣaṣṭhāṃśakṣaudra saṃyutaḥ śīto mukhe dhṛto hanyānmukhapākaṃ tridoṣajam" },
      { type: "verse", number: "16", sanskrit: "गण्डूषादिषु परस्परं द्र व्यैक्यम् यस्यौषधस्य गण्डूषस्तस्यैव प्रतिसारणम् कवलश्चापि तस्यैव ज्ञेयोऽत्र कुशलैर्न रैः", text: "gaṇḍūṣādiṣu parasparaṃ dra vyaikyam yasyauṣadhasya gaṇḍūṣastasyaiva pratisāraṇam kavalaścāpi tasyaiva jñeyo'tra kuśalairna raiḥ" },
      { type: "verse", number: "17", sanskrit: "केसरं मातुलुङ्गस्य सैन्धवोषणसंयुतम् हन्यात्कवलतो जाड्यमरुचिं कफवातजाम्", text: "kesaraṃ mātuluṅgasya saindhavoṣaṇasaṃyutam hanyātkavalato jāḍyamaruciṃ kaphavātajām" },
      { type: "verse", number: "18", sanskrit: "कल्कोऽवलेहश्चूर्णं च त्रिविधं प्रतिसारणम् अङ्गुल्यग्रगृहीतं च यथास्वं मुखरोगिणाम्", text: "kalko'valehaścūrṇaṃ ca trividhaṃ pratisāraṇam aṅgulyagragṛhītaṃ ca yathāsvaṃ mukharogiṇām" },
      { type: "verse", number: "19", sanskrit: "दन्तमुखकण्ठरोगेषु प्रतिसारणचूर्णम् कुष्ठं दार्वी समङ्गा च पाठा तिक्ता च पीतिका तेजनी मुस्तलोध्रे च चूर्णं स्यात्प्रतिसारणम् रक्तस्रुतिं दन्तपीडां शोथं दाहं च नाशयेत्", text: "dantamukhakaṇṭharogeṣu pratisāraṇacūrṇam kuṣṭhaṃ dārvī samaṅgā ca pāṭhā tiktā ca pītikā tejanī mustalodhre ca cūrṇaṃ syātpratisāraṇam raktasrutiṃ dantapīḍāṃ śothaṃ dāhaṃ ca nāśayet" },
      { type: "verse", number: "20", sanskrit: "गण्डूषादीनां हीनातियोगजा दोषाः हीनयोगात्कफोत्क्लेशो रसाज्ञानारुची तथा अतियोगान्मुखे पाकः शोषस्तृष्णा क्लमो भवेत्", text: "gaṇḍūṣādīnāṃ hīnātiyogajā doṣāḥ hīnayogātkaphotkleśo rasājñānārucī tathā atiyogānmukhe pākaḥ śoṣastṛṣṇā klamo bhavet" },
      { type: "verse", number: "21", sanskrit: "व्याधेरपचयस्तुष्टिर्वैशद्यं वक्त्रलाघवम् इन्द्रि याणां प्रसादश्च गण्डूषे शुद्धिलक्षणम्", text: "vyādherapacayastuṣṭirvaiśadyaṃ vaktralāghavam indri yāṇāṃ prasādaśca gaṇḍūṣe śuddhilakṣaṇam" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 11,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Раса видьяди санграха — Расаяна" },
      { type: "text", text: "Систематика расаяна-терапии: препараты, укрепляющие все семь дхату и оджас. Шарангадхара добавляет к классическим расаянам Чараки новые препараты своей эпохи." },
      { type: "verse", number: "1", sanskrit: "अथ लेपविधिर्नाम एकादशोऽध्यायः लेपस्य नामानि तद्भेदाश्च आलेपस्य च नामानि लिप्तो लेपश्च लेपनम् दोषघ्नो विषहा वर्ण्यो मुखलेपस्त्रिधा मतः", text: "atha lepavidhirnāma ekādaśo'dhyāyaḥ lepasya nāmāni tadbhedāśca ālepasya ca nāmāni lipto lepaśca lepanam doṣaghno viṣahā varṇyo mukhalepastridhā mataḥ" },
      { type: "verse", number: "2", sanskrit: "आद्रो र्! व्याधिहरः स स्याच्छुष्को दूषयतिच्छविम्", text: "ādro r! vyādhiharaḥ sa syācchuṣko dūṣayaticchavim" },
      { type: "verse", number: "3", sanskrit: "पुनर्नवा दारु शुण्ठीं सिद्धार्थं शिग्रुमेव च पिष्ट्वा चैवारनालेन प्रलेपः सर्वशोथजित्", text: "punarnavā dāru śuṇṭhīṃ siddhārthaṃ śigrumeva ca piṣṭvā caivāranālena pralepaḥ sarvaśothajit" },
      { type: "verse", number: "4", sanskrit: "बिभीतफलमज्जाया लेपो दाहार्त्तिनाशनः", text: "bibhītaphalamajjāyā lepo dāhārttināśanaḥ" },
      { type: "verse", number: "5", sanskrit: "शिरीषं मधुयष्टी च तगरं रक्तचन्दनम् एला मांसी निशायुग्मं कुष्ठं बालकमेव च इति संचूर्ण्य लेपोऽय पञ्चमांशघृतप्लुतः", text: "śirīṣaṃ madhuyaṣṭī ca tagaraṃ raktacandanam elā māṃsī niśāyugmaṃ kuṣṭhaṃ bālakameva ca iti saṃcūrṇya lepo'ya pañcamāṃśaghṛtaplutaḥ" },
      { type: "verse", number: "6", sanskrit: "जलेन क्रियते सुज्ञैर्दशाङ्ग इति संज्ञितः विसर्पान्विषविस्फोटशोथान्दुष्टव्रणाञ्जयेत्", text: "jalena kriyate sujñairdaśāṅga iti saṃjñitaḥ visarpānviṣavisphoṭaśothānduṣṭavraṇāñjayet" },
      { type: "verse", number: "7", sanskrit: "अजादुग्धतिलैर्लेपो नवनीतेन संयुतः शोथमारुष्करं हन्ति लेपो वा कृष्णमृत्तिकैः", text: "ajādugdhatilairlepo navanītena saṃyutaḥ śothamāruṣkaraṃ hanti lepo vā kṛṣṇamṛttikaiḥ" },
      { type: "verse", number: "8", sanskrit: "लेपो धान्याम्बुसम्पिष्टः कीटविस्फोटनाशनः", text: "lepo dhānyāmbusampiṣṭaḥ kīṭavisphoṭanāśanaḥ" },
      { type: "verse", number: "9", sanskrit: "वटाङ्कुरा मसूराश्च व्यङ्गघ्ना मुखकान्तिदाः", text: "vaṭāṅkurā masūrāśca vyaṅgaghnā mukhakāntidāḥ" },
      { type: "verse", number: "10", sanskrit: "मातुलुङ्गजटा सर्पिः शिला गोशकृतो रसः मुखकान्तिकरो लेपः पिटिकाव्यङ्गकालजित्", text: "mātuluṅgajaṭā sarpiḥ śilā gośakṛto rasaḥ mukhakāntikaro lepaḥ piṭikāvyaṅgakālajit" },
      { type: "verse", number: "11", sanskrit: "तद्वद्गोरोचनायुक्तं मरिचं मुखलेपनम् सिद्धार्थकवचालोध्रसैन्धवैश्च प्रलेपनम्", text: "tadvadgorocanāyuktaṃ maricaṃ mukhalepanam siddhārthakavacālodhrasaindhavaiśca pralepanam" },
      { type: "verse", number: "12", sanskrit: "व्यङ्गेषु चार्जुनत्वग्वामञ्जिष्ठा वा समाक्षिका लेपः सनवनीतो वा श्वेताश्वखुरजामषी", text: "vyaṅgeṣu cārjunatvagvāmañjiṣṭhā vā samākṣikā lepaḥ sanavanīto vā śvetāśvakhurajāmaṣī" },
      { type: "verse", number: "13", sanskrit: "अर्कक्षीरहरिद्रा भ्यां मर्दयित्वा विलेपनात् मुखकार्ष्ण्यं शमं याति चिरकालोद्भवं ध्रुवम्", text: "arkakṣīraharidrā bhyāṃ mardayitvā vilepanāt mukhakārṣṇyaṃ śamaṃ yāti cirakālodbhavaṃ dhruvam" },
      { type: "verse", number: "14", sanskrit: "वटस्य पाण्डुपत्राणि मालती रक्तचन्दनम्", text: "vaṭasya pāṇḍupatrāṇi mālatī raktacandanam" },
      { type: "verse", number: "15", sanskrit: "कुष्ठं कालीयकं लोध्रमेभिर्लेपं प्रयोजयेत् तारुण्यपिटिकाव्यङ्गनीलिकादिविनाशनम्", text: "kuṣṭhaṃ kālīyakaṃ lodhramebhirlepaṃ prayojayet tāruṇyapiṭikāvyaṅganīlikādivināśanam" },
      { type: "verse", number: "16", sanskrit: "पुराणमथ पिण्याकं पुरीषं कुक्कुटस्य च मूत्रपिष्टः प्रलेपोऽय शीघ्रं हन्यादरुंषिकाम्", text: "purāṇamatha piṇyākaṃ purīṣaṃ kukkuṭasya ca mūtrapiṣṭaḥ pralepo'ya śīghraṃ hanyādaruṃṣikām" },
      { type: "verse", number: "17", sanskrit: "खदिरारिष्टजम्बूनां त्वग्भिर्वा मूत्रसंयुतैः कुटजत्वक्सैन्धवं च लेपो हन्यादरुंषिकाम्", text: "khadirāriṣṭajambūnāṃ tvagbhirvā mūtrasaṃyutaiḥ kuṭajatvaksaindhavaṃ ca lepo hanyādaruṃṣikām" },
      { type: "verse", number: "18", sanskrit: "प्रियाल बीजमधुककुष्ठमाषैः ससैन्धवैः कार्यो दारुणके मूर्ध्नि प्रलेपो मधुसंयुतः", text: "priyāla bījamadhukakuṣṭhamāṣaiḥ sasaindhavaiḥ kāryo dāruṇake mūrdhni pralepo madhusaṃyutaḥ" },
      { type: "verse", number: "19", sanskrit: "दुग्धेन खाखसं बीजं प्रलेपाद्दारुणं जयेत् आम्रबीजस्य चूर्णं तु शिवाचूर्णसमं द्वयम् दुग्धपिष्टः प्रलेपोऽय दारुणं हन्ति दारुणम्", text: "dugdhena khākhasaṃ bījaṃ pralepāddāruṇaṃ jayet āmrabījasya cūrṇaṃ tu śivācūrṇasamaṃ dvayam dugdhapiṣṭaḥ pralepo'ya dāruṇaṃ hanti dāruṇam" },
      { type: "verse", number: "20", sanskrit: "रसस्तिक्तपटोलस्य पत्राणां तद्विलेपनात् इन्द्र लुप्तं शमं याति त्रिभिरेव दिनैर्ध्रुवम्", text: "rasastiktapaṭolasya patrāṇāṃ tadvilepanāt indra luptaṃ śamaṃ yāti tribhireva dinairdhruvam" },
      { type: "verse", number: "21", sanskrit: "इन्द्र लुप्तापहो लेपो मधुना बृहतीरसः गुञ्जामूलं फलं वाऽपि भल्लातकरसोऽपि वा", text: "indra luptāpaho lepo madhunā bṛhatīrasaḥ guñjāmūlaṃ phalaṃ vā'pi bhallātakaraso'pi vā" },
      { type: "verse", number: "22", sanskrit: "गोक्षुरस्तिलपुष्पाणि तुल्ये च मधुसर्पिषी शिरः प्रलेपनं तेन केशसंवर्धनं परम्", text: "gokṣurastilapuṣpāṇi tulye ca madhusarpiṣī śiraḥ pralepanaṃ tena keśasaṃvardhanaṃ param" },
      { type: "verse", number: "23", sanskrit: "हस्तिदन्तमषीं कृत्वा छागीदुग्धं रसाञ्जनम् रोमाण्यनेन जायन्ते लेपात्पाणितलेष्वपि", text: "hastidantamaṣīṃ kṛtvā chāgīdugdhaṃ rasāñjanam romāṇyanena jāyante lepātpāṇitaleṣvapi" },
      { type: "verse", number: "24", sanskrit: "इन्द्र लुप्तं शमं याति केशाः स्युः सघना दृढाः", text: "indra luptaṃ śamaṃ yāti keśāḥ syuḥ saghanā dṛḍhāḥ" },
      { type: "verse", number: "25", sanskrit: "चतुष्पदानां त्वग्रोमनखशृङ्गास्थिभस्मभिः तैलेन सह लेपोऽय रोमसंजननः परः", text: "catuṣpadānāṃ tvagromanakhaśṛṅgāsthibhasmabhiḥ tailena saha lepo'ya romasaṃjananaḥ paraḥ" },
      { type: "verse", number: "26", sanskrit: "इन्द्र वारुणिकाबीजतैलेनाभ्यङ्गमाचरेत् प्रत्यहं तेन जायन्ते कुन्तला भृङ्गसन्निभाः", text: "indra vāruṇikābījatailenābhyaṅgamācaret pratyahaṃ tena jāyante kuntalā bhṛṅgasannibhāḥ" },
      { type: "verse", number: "27", sanskrit: "अयोरजो भृङ्गराजस्त्रिफला कृष्णमृत्तिका स्थितमिक्षुरसे मासं लेपनात्पलितं जयेत्", text: "ayorajo bhṛṅgarājastriphalā kṛṣṇamṛttikā sthitamikṣurase māsaṃ lepanātpalitaṃ jayet" },
      { type: "verse", number: "28", sanskrit: "धात्रीफलत्रयं पथ्ये द्वे तथैकं बिभीतकम् पञ्चाम्रमज्जा लोहस्य कर्षैकं च प्रदीयते", text: "dhātrīphalatrayaṃ pathye dve tathaikaṃ bibhītakam pañcāmramajjā lohasya karṣaikaṃ ca pradīyate" },
      { type: "verse", number: "29", sanskrit: "पिष्ट्वा लोहमये भाण्डे स्थापयेदुषितं निशि लेपोऽय हन्ति न चिरादकालपलितं महत्", text: "piṣṭvā lohamaye bhāṇḍe sthāpayeduṣitaṃ niśi lepo'ya hanti na cirādakālapalitaṃ mahat" },
      { type: "verse", number: "30", sanskrit: "त्रिफला नीलिकापत्रं लोहं भृङ्गरजः समम् अविमूत्रेण सम्पिष्टं लेपात्कृष्णीकरं स्मृतम्", text: "triphalā nīlikāpatraṃ lohaṃ bhṛṅgarajaḥ samam avimūtreṇa sampiṣṭaṃ lepātkṛṣṇīkaraṃ smṛtam" },
      { type: "verse", number: "31", sanskrit: "त्रिफला लोहचूर्णं च दाडिमत्वग्बिसं तथा प्रत्येकं पञ्चपलिकं चूर्णं कुर्याद्विचक्षणः", text: "triphalā lohacūrṇaṃ ca dāḍimatvagbisaṃ tathā pratyekaṃ pañcapalikaṃ cūrṇaṃ kuryādvicakṣaṇaḥ" },
      { type: "verse", number: "32", sanskrit: "भृङ्गराजरसस्यापि प्रस्थषट्कं प्रदापयेत् क्षिप्त्वा लोहमये पात्रे भूमिमध्ये निधापयेत्", text: "bhṛṅgarājarasasyāpi prasthaṣaṭkaṃ pradāpayet kṣiptvā lohamaye pātre bhūmimadhye nidhāpayet" },
      { type: "verse", number: "33", sanskrit: "मासमेकं ततः कुर्याच्छागीदुग्धेन लेपनम् कूर्चे शिरसि रात्रौ च संवेष्ट्यैरण्डपत्रकैः", text: "māsamekaṃ tataḥ kuryācchāgīdugdhena lepanam kūrce śirasi rātrau ca saṃveṣṭyairaṇḍapatrakaiḥ" },
      { type: "verse", number: "34", sanskrit: "स्वपेत्प्रातस्ततः कुर्यात्स्नानं तेन च जायते पलितस्य विनाशश्च त्रिभिर्लेपैर्न संशयः", text: "svapetprātastataḥ kuryātsnānaṃ tena ca jāyate palitasya vināśaśca tribhirlepairna saṃśayaḥ" },
      { type: "verse", number: "35", sanskrit: "शङ्खचूर्णस्य भागौ द्वौ हरितालं च भागिकम्", text: "śaṅkhacūrṇasya bhāgau dvau haritālaṃ ca bhāgikam" },
      { type: "verse", number: "36", sanskrit: "मनः शिला चार्धभागा स्वर्जिका चैकभागिका लेपोऽय वारिपिष्टस्तु केशानुत्पाट्य दीयते", text: "manaḥ śilā cārdhabhāgā svarjikā caikabhāgikā lepo'ya vāripiṣṭastu keśānutpāṭya dīyate" },
      { type: "verse", number: "37", sanskrit: "अनया लेपयुक्त्या च सप्तवेलं प्रयुक्तया निर्मूलं केशस्थानं स्यात्क्षपणस्य शिरो यथा", text: "anayā lepayuktyā ca saptavelaṃ prayuktayā nirmūlaṃ keśasthānaṃ syātkṣapaṇasya śiro yathā" },
      { type: "verse", number: "38", sanskrit: "तालकं शाणयुग्मं स्यात्षट् शाणं शङ्खचूर्णकम् द्विशाणिकं पलाशस्य क्षारं दत्त्वा प्रमर्दयेत्", text: "tālakaṃ śāṇayugmaṃ syātṣaṭ śāṇaṃ śaṅkhacūrṇakam dviśāṇikaṃ palāśasya kṣāraṃ dattvā pramardayet" },
      { type: "verse", number: "39", sanskrit: "कदलीदण्डतोयेन रविपत्ररसेन वा अस्यापि सप्तभिर्लेपै रोम्णां शातनमुत्तमम्", text: "kadalīdaṇḍatoyena ravipatrarasena vā asyāpi saptabhirlepai romṇāṃ śātanamuttamam" },
      { type: "verse", number: "40", sanskrit: "सुवर्णपुष्पी कासीसं विडङ्गानि मनः शिला रोचना सैन्धवं चैव लेपनाच्छिवत्रनाशनम्", text: "suvarṇapuṣpī kāsīsaṃ viḍaṅgāni manaḥ śilā rocanā saindhavaṃ caiva lepanācchivatranāśanam" },
      { type: "verse", number: "41", sanskrit: "वायस्येडगजाकुष्ठकृष्णाभिर्गुटिका कृता बस्तमूत्रेण सम्पिष्टा प्रलेपाच्छिवत्रनाशिनी", text: "vāyasyeḍagajākuṣṭhakṛṣṇābhirguṭikā kṛtā bastamūtreṇa sampiṣṭā pralepācchivatranāśinī" },
      { type: "verse", number: "42", sanskrit: "तालकं शाणमात्रं स्याच्चतुःशाणा च वाकुची गोमूत्रपिष्टं तच्चूर्णं लेपनाच्छिक्त्रनाशनम्", text: "tālakaṃ śāṇamātraṃ syāccatuḥśāṇā ca vākucī gomūtrapiṣṭaṃ taccūrṇaṃ lepanācchiktranāśanam" },
      { type: "verse", number: "43", sanskrit: "वाकुची वेतसो लाक्षा काकोदुम्बरिका कणा रसाञ्जनमयश्चूर्णं तिलाः कृष्णास्तदेकतः", text: "vākucī vetaso lākṣā kākodumbarikā kaṇā rasāñjanamayaścūrṇaṃ tilāḥ kṛṣṇāstadekataḥ" },
      { type: "verse", number: "44", sanskrit: "चूर्णयित्वा गवां पित्तैः पिष्ट्वा च गुटिका कृता अस्याः प्रलेपाच्छिवत्राणि प्रणश्यन्त्यतिवेगतः", text: "cūrṇayitvā gavāṃ pittaiḥ piṣṭvā ca guṭikā kṛtā asyāḥ pralepācchivatrāṇi praṇaśyantyativegataḥ" },
      { type: "verse", number: "45", sanskrit: "धात्री सर्जरसश्चैव यवक्षारश्च चूर्णितः सौवीरेण प्रलेपोऽय प्रयोज्यः सिध्मनाशने", text: "dhātrī sarjarasaścaiva yavakṣāraśca cūrṇitaḥ sauvīreṇa pralepo'ya prayojyaḥ sidhmanāśane" },
      { type: "verse", number: "46", sanskrit: "दार्वी मूलकबीजानि तालकं सुरदारु च ताम्बूलपत्रं सर्वाणि कार्षिकाणि पृथक्पृथक्", text: "dārvī mūlakabījāni tālakaṃ suradāru ca tāmbūlapatraṃ sarvāṇi kārṣikāṇi pṛthakpṛthak" },
      { type: "verse", number: "47", sanskrit: "शङ्खचूर्णं शाणमात्रं सर्वाण्येकत्र कारयेत् लेपोऽय वारिणा पिष्टः सिध्मनां नाशनः परः", text: "śaṅkhacūrṇaṃ śāṇamātraṃ sarvāṇyekatra kārayet lepo'ya vāriṇā piṣṭaḥ sidhmanāṃ nāśanaḥ paraḥ" },
      { type: "verse", number: "48", sanskrit: "हरीतकी सैन्धवं च गैरिकं च रसाञ्जनम् विडालको जले पिष्टः सर्वनेत्रामयापहः", text: "harītakī saindhavaṃ ca gairikaṃ ca rasāñjanam viḍālako jale piṣṭaḥ sarvanetrāmayāpahaḥ" },
      { type: "verse", number: "49", sanskrit: "रसाञ्जनं व्योषयुतं सम्पिष्टं वटकीकृतम् कण्डूं पाकान्वितां हन्ति लेपादञ्जननामिकाम्", text: "rasāñjanaṃ vyoṣayutaṃ sampiṣṭaṃ vaṭakīkṛtam kaṇḍūṃ pākānvitāṃ hanti lepādañjananāmikām" },
      { type: "verse", number: "50", sanskrit: "प्रपुन्नाटस्य बीजानि वाकुची सर्षपास्तिलाः कुष्ठं निशाद्वयं मुस्तं पिष्ट्वा तक्रेण चैकतः प्रलेपादस्य नश्यन्ति दद्रू कण्डूविचर्चिकाः", text: "prapunnāṭasya bījāni vākucī sarṣapāstilāḥ kuṣṭhaṃ niśādvayaṃ mustaṃ piṣṭvā takreṇa caikataḥ pralepādasya naśyanti dadrū kaṇḍūvicarcikāḥ" },
      { type: "verse", number: "51", sanskrit: "हेमक्षीरी विडङ्गानि दरदं गन्धकस्तथा दद्रू घ्नः कुष्ठसिन्दूरे सर्वाण्येकत्र मर्दयेत्", text: "hemakṣīrī viḍaṅgāni daradaṃ gandhakastathā dadrū ghnaḥ kuṣṭhasindūre sarvāṇyekatra mardayet" },
      { type: "verse", number: "52", sanskrit: "धत्तूरनिम्बताम्बूलीपत्राणां स्वरसैः पृथक् अस्य प्रलेपमात्रेण पामादद्रू विर्चिकाः", text: "dhattūranimbatāmbūlīpatrāṇāṃ svarasaiḥ pṛthak asya pralepamātreṇa pāmādadrū vircikāḥ" },
      { type: "verse", number: "53", sanskrit: "कण्डूश्च रकसश्चैव प्रशमं यान्ति वेगतः", text: "kaṇḍūśca rakasaścaiva praśamaṃ yānti vegataḥ" },
      { type: "verse", number: "54", sanskrit: "दूर्वाऽभया सैन्धवं च चक्रमर्दः कुठेरकः एभिस्तक्रयुतो लेपः कण्डूपामाविनाशनः", text: "dūrvā'bhayā saindhavaṃ ca cakramardaḥ kuṭherakaḥ ebhistakrayuto lepaḥ kaṇḍūpāmāvināśanaḥ" },
      { type: "verse", number: "55", sanskrit: "दूर्वानिशायुतो लेपः कण्डूपामाविनाशनः कृमिदद्रुहरश्चैव शीतपित्तापहः स्मृतः", text: "dūrvāniśāyuto lepaḥ kaṇḍūpāmāvināśanaḥ kṛmidadruharaścaiva śītapittāpahaḥ smṛtaḥ" },
      { type: "verse", number: "56", sanskrit: "सिद्धार्थरजनीकुष्ठप्रपुन्नाटतिलैः सह कटुतैलेन संमिश्रं दद्रू घ्नं च प्रलेपनम्", text: "siddhārtharajanīkuṣṭhaprapunnāṭatilaiḥ saha kaṭutailena saṃmiśraṃ dadrū ghnaṃ ca pralepanam" },
      { type: "verse", number: "57", sanskrit: "रास्ना नीलोत्पलं दारु चन्दनं मधुकं बला घृतक्षीरयुतो लेपो वातवीसर्पनाशनः", text: "rāsnā nīlotpalaṃ dāru candanaṃ madhukaṃ balā ghṛtakṣīrayuto lepo vātavīsarpanāśanaḥ" },
      { type: "verse", number: "58", sanskrit: "मृणालं चन्दनं लोध्रमुशीरं कमलोत्पलम् सारिवामलकी पथ्या लेपः पित्तविसर्पनुत्", text: "mṛṇālaṃ candanaṃ lodhramuśīraṃ kamalotpalam sārivāmalakī pathyā lepaḥ pittavisarpanut" },
      { type: "verse", number: "59", sanskrit: "त्रिफला पद्मकोशीरं समङ्गा करवीरकम् नलमूलमनन्ता च लेपः श्लेष्मविसर्पहा", text: "triphalā padmakośīraṃ samaṅgā karavīrakam nalamūlamanantā ca lepaḥ śleṣmavisarpahā" },
      { type: "verse", number: "60", sanskrit: "मांसी सर्जरसो लोध्रं मधुकं सहरेणुकम् मूर्वा नीलोत्पलं पद्मं शिरीषकुसुमैः सह प्रलेपः पित्तवातास्रे शतधौतघृतप्लुतः", text: "māṃsī sarjaraso lodhraṃ madhukaṃ sahareṇukam mūrvā nīlotpalaṃ padmaṃ śirīṣakusumaiḥ saha pralepaḥ pittavātāsre śatadhautaghṛtaplutaḥ" },
      { type: "verse", number: "61", sanskrit: "आमलं घृतभृष्टं तु पिष्टं काञ्जिकवारिभिः जयेन्मूर्ध्नि प्रलेपेन रक्तं नासिकया सृतम्", text: "āmalaṃ ghṛtabhṛṣṭaṃ tu piṣṭaṃ kāñjikavāribhiḥ jayenmūrdhni pralepena raktaṃ nāsikayā sṛtam" },
      { type: "verse", number: "62", sanskrit: "कुष्ठमेरण्डतैलेन लेपात्काञ्जिकपेषितम् शिरोऽत्ति वातजां हन्यात्पुष्पं वा मुचुकुन्दजम्", text: "kuṣṭhameraṇḍatailena lepātkāñjikapeṣitam śiro'tti vātajāṃ hanyātpuṣpaṃ vā mucukundajam" },
      { type: "verse", number: "63", sanskrit: "देवदारुं नतं कुष्ठं नलदं विश्वभेषजम् सकाञ्जिकः स्नेहयुक्तो लेपो वातशिरोऽत्तिनुत्", text: "devadāruṃ nataṃ kuṣṭhaṃ naladaṃ viśvabheṣajam sakāñjikaḥ snehayukto lepo vātaśiro'ttinut" },
      { type: "verse", number: "64", sanskrit: "क्षीरपिष्टैः प्रलेपः स्याद्र क्तपित्तशिरोऽत्तिजित्", text: "kṣīrapiṣṭaiḥ pralepaḥ syādra ktapittaśiro'ttijit" },
      { type: "verse", number: "65", sanskrit: "दूर्वोशीरनलानां च मूलैः कुर्यात्प्रलेपनम्", text: "dūrvośīranalānāṃ ca mūlaiḥ kuryātpralepanam" },
      { type: "verse", number: "66", sanskrit: "शिरोऽत्ति पित्तजां हन्याद्र क्तपित्तरुजं तथा", text: "śiro'tti pittajāṃ hanyādra ktapittarujaṃ tathā" },
      { type: "verse", number: "67", sanskrit: "मांसीरास्नारुबूकश्च कोष्णो लेपः कफार्त्तिनुत्", text: "māṃsīrāsnārubūkaśca koṣṇo lepaḥ kaphārttinut" },
      { type: "verse", number: "68", sanskrit: "शुण्ठीकुष्ठप्रपुन्नाटदेवकाष्ठैः सरोहिषैः मूत्रपिष्टैः सुखोष्णैश्च लेपः श्लेष्मशिरोऽत्तिनुत्", text: "śuṇṭhīkuṣṭhaprapunnāṭadevakāṣṭhaiḥ sarohiṣaiḥ mūtrapiṣṭaiḥ sukhoṣṇaiśca lepaḥ śleṣmaśiro'ttinut" },
      { type: "verse", number: "69", sanskrit: "लेपः सकाञ्जिकस्नेहः सूर्यावर्त्तार्धभेदयोः", text: "lepaḥ sakāñjikasnehaḥ sūryāvarttārdhabhedayoḥ" },
      { type: "verse", number: "70", sanskrit: "वरी नीलोत्पलं दूर्वा तिलाः कृष्णा पुनर्नवा शङ्खकेऽनन्तवाते च लेपः सर्वशिरोऽत्तिजित्", text: "varī nīlotpalaṃ dūrvā tilāḥ kṛṣṇā punarnavā śaṅkhake'nantavāte ca lepaḥ sarvaśiro'ttijit" },
      { type: "verse", number: "71", sanskrit: "अथ लेपविधिश्चान्यः प्रोच्यते सुज्ञसम्मतः द्वौ तस्य कथितौ भेदौ प्रलेपाख्यप्रदेहकौ", text: "atha lepavidhiścānyaḥ procyate sujñasammataḥ dvau tasya kathitau bhedau pralepākhyapradehakau" },
      { type: "verse", number: "72", sanskrit: "चर्माद्र रं! माहिषं यद्वत्प्रोन्नतं सा मितिस्तयोः शीतस्तनुर्विशोषी च प्रलेपः परिकीर्त्तितः आद्रो र्! घनस्तथोष्णः स्यात्प्रदेहः श्लेष्मवातहा", text: "carmādra raṃ! māhiṣaṃ yadvatpronnataṃ sā mitistayoḥ śītastanurviśoṣī ca pralepaḥ parikīrttitaḥ ādro r! ghanastathoṣṇaḥ syātpradehaḥ śleṣmavātahā" },
      { type: "verse", number: "73", sanskrit: "रोमाभिमुखमादेयौ प्रलेपाख्यप्रदेहकौ वीर्यं सम्यग्विशत्याशु रोमकूपैः शिरामुखैः", text: "romābhimukhamādeyau pralepākhyapradehakau vīryaṃ samyagviśatyāśu romakūpaiḥ śirāmukhaiḥ" },
      { type: "verse", number: "74", sanskrit: "न रात्रौ लेपनं कुर्याच्छुष्यमाणं न धारयेत् शुष्यमाणमुपेक्षेत प्रदेहं पीडनं प्रति", text: "na rātrau lepanaṃ kuryācchuṣyamāṇaṃ na dhārayet śuṣyamāṇamupekṣeta pradehaṃ pīḍanaṃ prati" },
      { type: "verse", number: "75", sanskrit: "तमसा पिहतो ह्यूष्मा रोमकूपमुखे स्थितः विना लेपेन निर्याति रात्रौ नो लेपयेदतः", text: "tamasā pihato hyūṣmā romakūpamukhe sthitaḥ vinā lepena niryāti rātrau no lepayedataḥ" },
      { type: "verse", number: "76", sanskrit: "रात्रावपि प्रलेपादिविधिः कार्यो विचक्षणैः अपक्वशोथे गम्भीरे रक्तश्लेष्मसमुद्भवे", text: "rātrāvapi pralepādividhiḥ kāryo vicakṣaṇaiḥ apakvaśothe gambhīre raktaśleṣmasamudbhave" },
      { type: "verse", number: "77", sanskrit: "आदौ शोथहरो लेपो द्वितीयो रक्तसेचनः तृतीयश्चोपनाहः स्याच्चतुर्थः पाटनक्रमः", text: "ādau śothaharo lepo dvitīyo raktasecanaḥ tṛtīyaścopanāhaḥ syāccaturthaḥ pāṭanakramaḥ" },
      { type: "verse", number: "78", sanskrit: "पञ्चमः शोधनो भूयात्षष्ठो रोपण इष्यते सप्तमो वर्णकरणो व्रणस्यैते क्रमा मताः", text: "pañcamaḥ śodhano bhūyātṣaṣṭho ropaṇa iṣyate saptamo varṇakaraṇo vraṇasyaite kramā matāḥ" },
      { type: "verse", number: "79", sanskrit: "बीजपूरजटा हिंस्रा देवदारु महौषधम् रास्नाऽग्निमन्थो लेपोऽय वातशोथविनाशनः", text: "bījapūrajaṭā hiṃsrā devadāru mahauṣadham rāsnā'gnimantho lepo'ya vātaśothavināśanaḥ" },
      { type: "verse", number: "80", sanskrit: "मधुकं चन्दनं मूर्वा नलमूलं च पद्मकम् उशीरं बालकं पद्मं पित्तशोथे प्रलेपनम्", text: "madhukaṃ candanaṃ mūrvā nalamūlaṃ ca padmakam uśīraṃ bālakaṃ padmaṃ pittaśothe pralepanam" },
      { type: "verse", number: "81", sanskrit: "कृष्णा पुराणपिण्याकं शिग्रुत्वक्सिकता शिवा मूत्रपिष्टः सुखोष्णोऽय प्रदेहः श्लेष्मशोथहा", text: "kṛṣṇā purāṇapiṇyākaṃ śigrutvaksikatā śivā mūtrapiṣṭaḥ sukhoṣṇo'ya pradehaḥ śleṣmaśothahā" },
      { type: "verse", number: "82", sanskrit: "आगन्तुकरक्तजव्रणशोथघ्नो लेपः द्वे निशे चन्दने द्वे च शिवा दूर्वा पुनर्नवा", text: "āgantukaraktajavraṇaśothaghno lepaḥ dve niśe candane dve ca śivā dūrvā punarnavā" },
      { type: "verse", number: "83", sanskrit: "उशीरं पद्मकं लोध्रं गैरिकं च रसाञ्जनम् आगन्तुके रक्तजे च शोथे कुर्यात्प्रलेपनम्", text: "uśīraṃ padmakaṃ lodhraṃ gairikaṃ ca rasāñjanam āgantuke raktaje ca śothe kuryātpralepanam" },
      { type: "verse", number: "84", sanskrit: "शणमूलकशिग्रूणां फलानि तिलसर्षपाः सवचः किण्वमतसी प्रदेहः पाचनः स्मृतः", text: "śaṇamūlakaśigrūṇāṃ phalāni tilasarṣapāḥ savacaḥ kiṇvamatasī pradehaḥ pācanaḥ smṛtaḥ" },
      { type: "verse", number: "85", sanskrit: "दन्ती चित्रकमूलत्वक्स्नुह्यर्कपयसी गुडः भल्लातकास्थिकासीसं सैन्धवं दारणः स्मृतः", text: "dantī citrakamūlatvaksnuhyarkapayasī guḍaḥ bhallātakāsthikāsīsaṃ saindhavaṃ dāraṇaḥ smṛtaḥ" },
      { type: "verse", number: "86", sanskrit: "चिरबिल्वोऽग्निको दन्ती चित्रको हयमारकः कपोतकङ्कगृध्राणां मलं लेपेन दारणम्", text: "cirabilvo'gniko dantī citrako hayamārakaḥ kapotakaṅkagṛdhrāṇāṃ malaṃ lepena dāraṇam" },
      { type: "verse", number: "87", sanskrit: "स्वर्जिकायावशूकाद्याः क्षारा लेपेन दारणाः हेमक्षीर्यास्तथा लेपो व्रणे परमदारणः", text: "svarjikāyāvaśūkādyāḥ kṣārā lepena dāraṇāḥ hemakṣīryāstathā lepo vraṇe paramadāraṇaḥ" },
      { type: "verse", number: "88", sanskrit: "त्रिवृद्घृतयुतैः पिष्टैः प्रलेपो व्रणशोधनः", text: "trivṛdghṛtayutaiḥ piṣṭaiḥ pralepo vraṇaśodhanaḥ" },
      { type: "verse", number: "89", sanskrit: "निम्बपत्रघृतक्षौद्र दार्वीमधुकसंयुतः तिलैश्च सह संयुक्तो लेपः शोधनरोपणः", text: "nimbapatraghṛtakṣaudra dārvīmadhukasaṃyutaḥ tilaiśca saha saṃyukto lepaḥ śodhanaropaṇaḥ" },
      { type: "verse", number: "90", sanskrit: "करञ्जारिष्टनिर्गुण्डीलेपो हन्याद् व्रणकृमीन् लशुनस्याथवा लेपो हिङ्गुनिम्बभवोऽथवा", text: "karañjāriṣṭanirguṇḍīlepo hanyād vraṇakṛmīn laśunasyāthavā lepo hiṅgunimbabhavo'thavā" },
      { type: "verse", number: "91", sanskrit: "निम्बपत्रं तिला दन्ती त्रिवृत्सैन्धवमाक्षिकम् द्रुष्टव्रणप्रशमनो लेपः शोधनरोपणः", text: "nimbapatraṃ tilā dantī trivṛtsaindhavamākṣikam druṣṭavraṇapraśamano lepaḥ śodhanaropaṇaḥ" },
      { type: "verse", number: "92", sanskrit: "मदनस्य फलं तिक्तां पिष्ट्वा काञ्जिकवारिणा कोष्णं कुर्यान्नाभिलेपं शूलशान्तिर्भवेत्ततः", text: "madanasya phalaṃ tiktāṃ piṣṭvā kāñjikavāriṇā koṣṇaṃ kuryānnābhilepaṃ śūlaśāntirbhavettataḥ" },
      { type: "verse", number: "93", sanskrit: "सुखोष्णो बहलो लेपः प्रयोज्यो वातविद्र धौ", text: "sukhoṣṇo bahalo lepaḥ prayojyo vātavidra dhau" },
      { type: "verse", number: "94", sanskrit: "पैत्तिके सर्पिषा लाजामधुकैः शर्कराऽन्वितैः प्रलिम्पेत्क्षीरपिष्टैर्वा पयस्योशीरचन्दनैः", text: "paittike sarpiṣā lājāmadhukaiḥ śarkarā'nvitaiḥ pralimpetkṣīrapiṣṭairvā payasyośīracandanaiḥ" },
      { type: "verse", number: "95", sanskrit: "इष्टिका सिकता लोहकिट्टं गोशकृता सह सुखोष्णश्च प्रदेहोऽय मूत्रैः स्याच्छ्लेष्मविद्र धौ", text: "iṣṭikā sikatā lohakiṭṭaṃ gośakṛtā saha sukhoṣṇaśca pradeho'ya mūtraiḥ syācchleṣmavidra dhau" },
      { type: "verse", number: "96", sanskrit: "क्षीरेण विद्र धौ लेपो रक्तागन्तुनिमित्तजे", text: "kṣīreṇa vidra dhau lepo raktāgantunimittaje" },
      { type: "verse", number: "97", sanskrit: "निचुलः शिग्रुबीजानि दशमूलमथापि वा प्रदेहो वातगण्डेषु सुखोष्णः सम्प्रदीयते", text: "niculaḥ śigrubījāni daśamūlamathāpi vā pradeho vātagaṇḍeṣu sukhoṣṇaḥ sampradīyate" },
      { type: "verse", number: "98", sanskrit: "देवदारु विशाला च कफगण्डे प्रदेहकः", text: "devadāru viśālā ca kaphagaṇḍe pradehakaḥ" },
      { type: "verse", number: "99", sanskrit: "सर्षपारिष्टपत्राणि दग्ध्वा भल्लातकैः सह छागमूत्रेण संपिष्टमपचीघ्नं प्रलेपनम्", text: "sarṣapāriṣṭapatrāṇi dagdhvā bhallātakaiḥ saha chāgamūtreṇa saṃpiṣṭamapacīghnaṃ pralepanam" },
      { type: "verse", number: "100", sanskrit: "सर्षपाः शिग्रुबीजानि शणबीजातसीयवाः मूलकस्य च बीजानि तक्रेणाम्लेन पेषयेत् गण्डमालाऽबुदं गण्डं लेपेनानेन शाम्यति", text: "sarṣapāḥ śigrubījāni śaṇabījātasīyavāḥ mūlakasya ca bījāni takreṇāmlena peṣayet gaṇḍamālā'budaṃ gaṇḍaṃ lepenānena śāmyati" },
      { type: "verse", number: "101", sanskrit: "तक्षयित्वा क्षुरेणाङ्गं केवलानिलपीडितम् तत्र प्रदेहं दद्याच्च पिष्टं गुञ्जाफलैः कृतम्", text: "takṣayitvā kṣureṇāṅgaṃ kevalānilapīḍitam tatra pradehaṃ dadyācca piṣṭaṃ guñjāphalaiḥ kṛtam" },
      { type: "verse", number: "102", sanskrit: "तेनापबाहुजा पीडा विश्वाची गृध्रसी तथा अन्याऽपि वातजा पीडा प्रशमं याति वेगतः", text: "tenāpabāhujā pīḍā viśvācī gṛdhrasī tathā anyā'pi vātajā pīḍā praśamaṃ yāti vegataḥ" },
      { type: "verse", number: "103", sanskrit: "प्रलेपः श्लीपदं हन्ति चिरोत्थमपि दारुणम्", text: "pralepaḥ ślīpadaṃ hanti cirotthamapi dāruṇam" },
      { type: "verse", number: "104", sanskrit: "काञ्जिकेन तु संपिष्टं कुरण्डघ्नं प्रलेपनम्", text: "kāñjikena tu saṃpiṣṭaṃ kuraṇḍaghnaṃ pralepanam" },
      { type: "verse", number: "105", sanskrit: "करवीरस्य मूलेन परिपिष्टेन वारिणा असाध्याऽपि व्रजत्यस्तं लिङ्गोत्था रुक्प्रलेपनात्", text: "karavīrasya mūlena paripiṣṭena vāriṇā asādhyā'pi vrajatyastaṃ liṅgotthā rukpralepanāt" },
      { type: "verse", number: "106", sanskrit: "दहेत्कटाहे त्रिफलां सा मषी मधुसंयुता उपदंशे प्रलेपोऽय सद्यो रोपयति व्रणम्", text: "dahetkaṭāhe triphalāṃ sā maṣī madhusaṃyutā upadaṃśe pralepo'ya sadyo ropayati vraṇam" },
      { type: "verse", number: "107", sanskrit: "रसाञ्जनं शिरीषेण पथ्यया च समन्वितम् सक्षौद्रं  लेपनं योज्यमुपदंशगदापहम्", text: "rasāñjanaṃ śirīṣeṇa pathyayā ca samanvitam sakṣaudraṃ  lepanaṃ yojyamupadaṃśagadāpaham" },
      { type: "verse", number: "108", sanskrit: "अग्निदग्धे तुगाक्षीरीप्लक्षचन्दनगैरिकैः सामृतैः सर्पिषा स्निग्धैरालेपं कारयेद्भिषक्", text: "agnidagdhe tugākṣīrīplakṣacandanagairikaiḥ sāmṛtaiḥ sarpiṣā snigdhairālepaṃ kārayedbhiṣak" },
      { type: "verse", number: "109", sanskrit: "तिन्दुकीत्वक्कषायैर्वा घृतमिश्रः प्रलेपयेत् यवान्दग्ध्वा मषी कार्या तैलेन युतया तथा दद्यात्सर्वाग्निदग्धेषु प्रलेपो व्रणरोपणः", text: "tindukītvakkaṣāyairvā ghṛtamiśraḥ pralepayet yavāndagdhvā maṣī kāryā tailena yutayā tathā dadyātsarvāgnidagdheṣu pralepo vraṇaropaṇaḥ" },
      { type: "verse", number: "110", sanskrit: "मधुना योनिमालिम्पेद् गाढीकरणमुत्तमम्", text: "madhunā yonimālimped gāḍhīkaraṇamuttamam" },
      { type: "verse", number: "111", sanskrit: "गतेऽपि यौवने स्त्रीणां योनिर्गाढाऽतिजायते", text: "gate'pi yauvane strīṇāṃ yonirgāḍhā'tijāyate" },
      { type: "verse", number: "112", sanskrit: "मरिचं सैन्धवं कृष्णा तगरं बृहतीफलम्", text: "maricaṃ saindhavaṃ kṛṣṇā tagaraṃ bṛhatīphalam" },
      { type: "verse", number: "113", sanskrit: "अपामार्गस्तिलाः कुष्ठं यवा माषाश्च सर्षपाः अश्वगन्धा च तच्चूर्णं मधुना सह योजयेत्", text: "apāmārgastilāḥ kuṣṭhaṃ yavā māṣāśca sarṣapāḥ aśvagandhā ca taccūrṇaṃ madhunā saha yojayet" },
      { type: "verse", number: "114", sanskrit: "अस्य सन्ततलेपेन मर्दनाच्च प्रजायते लिङ्गवृद्धिः स्तनोत्सेधः संहतिर्भुजकर्णयोः", text: "asya santatalepena mardanācca prajāyate liṅgavṛddhiḥ stanotsedhaḥ saṃhatirbhujakarṇayoḥ" },
      { type: "verse", number: "115", sanskrit: "सिताऽश्वगन्धासिन्धूत्थछागक्षीरैर्घृतं पचेत् तल्लेपान्मर्दनाल्लिङ्गवृद्धिः सञ्जायते परा", text: "sitā'śvagandhāsindhūtthachāgakṣīrairghṛtaṃ pacet tallepānmardanālliṅgavṛddhiḥ sañjāyate parā" },
      { type: "verse", number: "116", sanskrit: "इन्द्र वारुणिकापत्ररसैः सूतं विमर्दयेत् रक्तस्य करवीरस्य काष्ठेन च मुहुर्मुहुः तल्लिप्तलिङ्गसंयोगाद्योनिद्रा वोऽभिजायते", text: "indra vāruṇikāpatrarasaiḥ sūtaṃ vimardayet raktasya karavīrasya kāṣṭhena ca muhurmuhuḥ talliptaliṅgasaṃyogādyonidrā vo'bhijāyate" },
      { type: "verse", number: "117", sanskrit: "ताम्बूलपत्रचूर्णं तु चूर्णं कुष्ठशिवाभवम् वारिणा लेपनं कुर्याद् गात्रदौर्गन्ध्यनाशनम्", text: "tāmbūlapatracūrṇaṃ tu cūrṇaṃ kuṣṭhaśivābhavam vāriṇā lepanaṃ kuryād gātradaurgandhyanāśanam" },
      { type: "verse", number: "118", sanskrit: "कुलित्थसक्तवः कुष्ठं मांसी चन्दनजं रजः", text: "kulitthasaktavaḥ kuṣṭhaṃ māṃsī candanajaṃ rajaḥ" },
      { type: "verse", number: "119", sanskrit: "सक्तवश्चणकस्यैव त्वक्चैवैकत्र कारयेत् स्वेददौर्गन्ध्यनाशश्च जायतेऽस्यावधूलनात्", text: "saktavaścaṇakasyaiva tvakcaivaikatra kārayet svedadaurgandhyanāśaśca jāyate'syāvadhūlanāt" },
      { type: "verse", number: "120", sanskrit: "वचा सौवर्चलं कुष्ठं रजन्यौ मरिचानि च एतल्लेपप्रभावेण वशीकरणमुत्तमम्", text: "vacā sauvarcalaṃ kuṣṭhaṃ rajanyau maricāni ca etallepaprabhāveṇa vaśīkaraṇamuttamam" },
      { type: "verse", number: "121", sanskrit: "अभ्यङ्गः परिषेकश्च पिचुर्बस्तिरिति क्रमात् मूर्धतैलं चतुर्धा स्याद्बलवच्च यथोत्तरम्", text: "abhyaṅgaḥ pariṣekaśca picurbastiriti kramāt mūrdhatailaṃ caturdhā syādbalavacca yathottaram" },
      { type: "verse", number: "122", sanskrit: "केवलशिरोबस्तिविधिकथने हेतुनिर्देशः त्रयोऽभ्यङ्गादयः पूर्वे प्रसिद्धाःसर्वतःस्मृताः शिरोबस्तिविधिश्चात्र प्रोच्यतेसुज्ञसंमतः", text: "kevalaśirobastividhikathane hetunirdeśaḥ trayo'bhyaṅgādayaḥ pūrve prasiddhāḥsarvataḥsmṛtāḥ śirobastividhiścātra procyatesujñasaṃmataḥ" },
      { type: "verse", number: "123", sanskrit: "शिरोबस्तिश्चर्मणःस्याद् द्विमुखो द्वादशाङ्गुलः शिरः प्रमाणं तं बद्ध्वा मस्तके माषपिष्टकैः सन्धिरोधं विधायादौ स्नेहैः कोष्णैः प्रपूरयेत्", text: "śirobastiścarmaṇaḥsyād dvimukho dvādaśāṅgulaḥ śiraḥ pramāṇaṃ taṃ baddhvā mastake māṣapiṣṭakaiḥ sandhirodhaṃ vidhāyādau snehaiḥ koṣṇaiḥ prapūrayet" },
      { type: "verse", number: "124", sanskrit: "तत्र शिरोबस्तिधारणकालविधिनिर्देशः तावद्धार्यस्तु यावत्स्यान्नासानेत्रमुखस्रुतिः वेदनोपशमोवाऽपि मात्राणां वा सहस्रकम्", text: "tatra śirobastidhāraṇakālavidhinirdeśaḥ tāvaddhāryastu yāvatsyānnāsānetramukhasrutiḥ vedanopaśamovā'pi mātrāṇāṃ vā sahasrakam" },
      { type: "verse", number: "125", sanskrit: "विना भोजनमेवात्र शिरोबस्तिः प्रशस्यते प्रयोज्यस्तु शिरोबस्तिः पञ्चसप्ताहमेव वा", text: "vinā bhojanamevātra śirobastiḥ praśasyate prayojyastu śirobastiḥ pañcasaptāhameva vā" },
      { type: "verse", number: "126", sanskrit: "विमोच्य शिरसोबस्तिं गृह्णीयाच्च समन्ततः उर्ध्वकायं ततः कोष्णनीरैः स्नानं च कारयेत्", text: "vimocya śirasobastiṃ gṛhṇīyācca samantataḥ urdhvakāyaṃ tataḥ koṣṇanīraiḥ snānaṃ ca kārayet" },
      { type: "verse", number: "127", sanskrit: "अनेन दुर्जया रोगा वातजा यान्ति सङ्क्षयम् शिरः कम्पादयस्तेन सर्वकालेषु युज्यते", text: "anena durjayā rogā vātajā yānti saṅkṣayam śiraḥ kampādayastena sarvakāleṣu yujyate" },
      { type: "verse", number: "128", sanskrit: "स्वेदयेत्कर्णदेशं तु किञ्चिन्नुः पार्श्वशायिनः मूत्रैः स्नेहै रसैः कोष्णैस्ततः श्रोत्रं प्रपूरयेत्", text: "svedayetkarṇadeśaṃ tu kiñcinnuḥ pārśvaśāyinaḥ mūtraiḥ snehai rasaiḥ koṣṇaistataḥ śrotraṃ prapūrayet" },
      { type: "verse", number: "129", sanskrit: "कर्णं च पूरितं रक्षेच्छतं पञ्चशतानि वा सहस्रं वाऽपि मात्राणां श्रोत्रकण्ठशिरोगदे", text: "karṇaṃ ca pūritaṃ rakṣecchataṃ pañcaśatāni vā sahasraṃ vā'pi mātrāṇāṃ śrotrakaṇṭhaśirogade" },
      { type: "verse", number: "130", sanskrit: "स्वजानुनः करावर्त्तं कुर्याच्छोटिकया युतम् एषा मात्रा भवेदेका सर्वत्रैवैष निश्चयः", text: "svajānunaḥ karāvarttaṃ kuryācchoṭikayā yutam eṣā mātrā bhavedekā sarvatraivaiṣa niścayaḥ" },
      { type: "verse", number: "131", sanskrit: "रसाद्यनुसारेण कर्णपूरणसमयभेदः रसाद्यैः पूरणं कर्णे भोजनात्प्राक्प्रशस्यते तैलाद्यैः पूरणं कर्णे भास्करेऽस्तमुपागते", text: "rasādyanusāreṇa karṇapūraṇasamayabhedaḥ rasādyaiḥ pūraṇaṃ karṇe bhojanātprākpraśasyate tailādyaiḥ pūraṇaṃ karṇe bhāskare'stamupāgate" },
      { type: "verse", number: "132", sanskrit: "पीतार्कपत्रमाज्येन लिप्तं वह्नौ प्रतापयेत् तद्र सः श्रवणे क्षिप्तः कर्णशूलहरः परः", text: "pītārkapatramājyena liptaṃ vahnau pratāpayet tadra saḥ śravaṇe kṣiptaḥ karṇaśūlaharaḥ paraḥ" },
      { type: "verse", number: "133", sanskrit: "कर्णशूलातुरे कोष्णं बस्तमूत्रं ससैन्धवम् निःक्षिपेत्तेन शाम्यन्ति शूलपाकादिका रुजः", text: "karṇaśūlāture koṣṇaṃ bastamūtraṃ sasaindhavam niḥkṣipettena śāmyanti śūlapākādikā rujaḥ" },
      { type: "verse", number: "134", sanskrit: "शृङ्गबेरं च मधुकं मधु सैन्धवमामलम्", text: "śṛṅgaberaṃ ca madhukaṃ madhu saindhavamāmalam" },
      { type: "verse", number: "135", sanskrit: "तिलपर्णीरसस्तैलं टङ्कणं निम्बुकद्र वम् कदुष्णं कर्णयोर्देयमेतद्वा वेदनाऽपहम्", text: "tilaparṇīrasastailaṃ ṭaṅkaṇaṃ nimbukadra vam kaduṣṇaṃ karṇayordeyametadvā vedanā'paham" },
      { type: "verse", number: "136", sanskrit: "कपित्थमातुलुङ्गाम्लशृबेररसैः शुभैः सुखोष्णैः पूरयेत्कर्णं कर्णशूलोपशान्तये", text: "kapitthamātuluṅgāmlaśṛberarasaiḥ śubhaiḥ sukhoṣṇaiḥ pūrayetkarṇaṃ karṇaśūlopaśāntaye" },
      { type: "verse", number: "137", sanskrit: "सन्निदध्यात्स्नुहीकाण्डे कोरितेतच्छदावृते", text: "sannidadhyātsnuhīkāṇḍe koritetacchadāvṛte" },
      { type: "verse", number: "138", sanskrit: "पुटपाकक्रमं कृत्वा रसैस्तच्च प्रपूरयेत् सुखोष्णैस्तेन शाम्यन्ति कर्णपीडाः सुदारुणाः", text: "puṭapākakramaṃ kṛtvā rasaistacca prapūrayet sukhoṣṇaistena śāmyanti karṇapīḍāḥ sudāruṇāḥ" },
      { type: "verse", number: "139", sanskrit: "महतः पञ्चमूलस्य काण्डान्यष्टाङ्गुलानि च क्षौमेणावेष्ट्य संसिच्य तैलेनादीपयेत्ततः", text: "mahataḥ pañcamūlasya kāṇḍānyaṣṭāṅgulāni ca kṣaumeṇāveṣṭya saṃsicya tailenādīpayettataḥ" },
      { type: "verse", number: "140", sanskrit: "यत्तैलं च्यवते तेभ्यः सुखोष्णं तेन पूरयेत् ज्ञेयं तद्दीपिकातैलंसद्यो गृह्णातिवेदनाम् एवं स्याद्दीपिकातैलं कुष्ठे देवतरौ तथा", text: "yattailaṃ cyavate tebhyaḥ sukhoṣṇaṃ tena pūrayet jñeyaṃ taddīpikātailaṃsadyo gṛhṇātivedanām evaṃ syāddīpikātailaṃ kuṣṭhe devatarau tathā" },
      { type: "verse", number: "141", sanskrit: "तैलं स्योनाकमूलेन मन्देऽग्नौ परिपाचितम् हरेदाशु त्रिदोषोत्थं कर्णशूलं प्रपूरणात्", text: "tailaṃ syonākamūlena mande'gnau paripācitam haredāśu tridoṣotthaṃ karṇaśūlaṃ prapūraṇāt" },
      { type: "verse", number: "142", sanskrit: "कल्कक्वाथेन यष्ट्याह्वकाकोलीमाषधान्यकैः सूकरस्य वसां पक्त्वा कर्णनादार्त्तिनाशिनी", text: "kalkakvāthena yaṣṭyāhvakākolīmāṣadhānyakaiḥ sūkarasya vasāṃ paktvā karṇanādārttināśinī" },
      { type: "verse", number: "143", sanskrit: "स्वर्जिका मूलकं शुष्कं हिङ्गु कृष्णासमन्वितम्", text: "svarjikā mūlakaṃ śuṣkaṃ hiṅgu kṛṣṇāsamanvitam" },
      { type: "verse", number: "144", sanskrit: "शतपुष्पा च तैस्तैलं पक्वं शुक्तचतुर्गुणम् प्रणादं शूलबाधिर्यं स्रावं कर्णस्य नाशयेत्", text: "śatapuṣpā ca taistailaṃ pakvaṃ śuktacaturguṇam praṇādaṃ śūlabādhiryaṃ srāvaṃ karṇasya nāśayet" },
      { type: "verse", number: "145", sanskrit: "अपामार्गक्षारजले तत्क्षारं कल्कितं क्षिपेत् तेन पक्वं जयेत्तैलं बाधिर्यं कर्णनादकम्", text: "apāmārgakṣārajale tatkṣāraṃ kalkitaṃ kṣipet tena pakvaṃ jayettailaṃ bādhiryaṃ karṇanādakam" },
      { type: "verse", number: "146", sanskrit: "शम्बूकस्य तु मांसेन पचेत्तैलं तु सार्षपम् तस्य पूरणमात्रेण कर्णनाडी प्रशाम्यति", text: "śambūkasya tu māṃsena pacettailaṃ tu sārṣapam tasya pūraṇamātreṇa karṇanāḍī praśāmyati" },
      { type: "verse", number: "147", sanskrit: "चूर्णं पञ्चकषायाणां कपित्थरसमेव च कर्णस्रावे प्रशंसन्ति पूरणं मधुना सह", text: "cūrṇaṃ pañcakaṣāyāṇāṃ kapittharasameva ca karṇasrāve praśaṃsanti pūraṇaṃ madhunā saha" },
      { type: "verse", number: "148", sanskrit: "तिन्दुकान्यभया लोध्रः समङ्गा चामलक्यपि ज्ञेयाः पञ्च कषायास्तु कर्मण्यस्मिन्भिषग्वरैः", text: "tindukānyabhayā lodhraḥ samaṅgā cāmalakyapi jñeyāḥ pañca kaṣāyāstu karmaṇyasminbhiṣagvaraiḥ" },
      { type: "verse", number: "149", sanskrit: "कर्णस्रावादौ स्वर्जिकादियोगः स्वर्जिकाचूर्णसंयुक्तं बीजपूररसं क्षिपेत् कर्णस्रावरुजा दाहाः प्रणश्यन्ति न संशयः", text: "karṇasrāvādau svarjikādiyogaḥ svarjikācūrṇasaṃyuktaṃ bījapūrarasaṃ kṣipet karṇasrāvarujā dāhāḥ praṇaśyanti na saṃśayaḥ" },
      { type: "verse", number: "150", sanskrit: "आम्रजम्बूप्रवालानि मधूकस्य वटस्य च एभिः संसाधितं तैलं पूतिकर्णोपशान्तिकृत्", text: "āmrajambūpravālāni madhūkasya vaṭasya ca ebhiḥ saṃsādhitaṃ tailaṃ pūtikarṇopaśāntikṛt" },
      { type: "verse", number: "151", sanskrit: "पूरणं हरितालेन गवां मूत्रयुतेन च अथवा सार्षपं तैलं कर्णकीटहरं परम्", text: "pūraṇaṃ haritālena gavāṃ mūtrayutena ca athavā sārṣapaṃ tailaṃ karṇakīṭaharaṃ param" },
      { type: "verse", number: "152", sanskrit: "स्वरसं शिग्रुमूलस्य सूर्यावर्त्तरसं तथा त्र्! यूषणं चूर्णितं चैव कपिकच्छूजटारसम् कृत्वैकत्र क्षिपेत्कर्णे कर्णकीटहरं परम्", text: "svarasaṃ śigrumūlasya sūryāvarttarasaṃ tathā tr! yūṣaṇaṃ cūrṇitaṃ caiva kapikacchūjaṭārasam kṛtvaikatra kṣipetkarṇe karṇakīṭaharaṃ param" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 12,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Вришья карма санграха — Репродуктивное омоложение" },
      { type: "text", text: "Вришья (ваджикарана) — применение афродизиакальных препаратов для укрепления репродуктивного здоровья. Шарангадхара систематизирует препараты по силе и показаниям." },
      { type: "verse", number: "1", sanskrit: "अथ शोणितस्रावविधिर्नाम द्वादशोऽध्यायः तत्र शोणितस्रावमानम् शोणितं स्रावयेज्जन्तोरामयं प्रसमीक्ष्य च प्रस्थं प्रस्थार्द्धकं वाऽपि प्रस्थार्धार्धमथापि वा", text: "atha śoṇitasrāvavidhirnāma dvādaśo'dhyāyaḥ tatra śoṇitasrāvamānam śoṇitaṃ srāvayejjantorāmayaṃ prasamīkṣya ca prasthaṃ prasthārddhakaṃ vā'pi prasthārdhārdhamathāpi vā" },
      { type: "verse", number: "2", sanskrit: "शरत्काले स्वभावेन कुर्याद्र क्तस्रुतिं नरः त्वग्दोषग्रन्थिशोथाद्या न स्यू रक्तस्रुतेर्यतः", text: "śaratkāle svabhāvena kuryādra ktasrutiṃ naraḥ tvagdoṣagranthiśothādyā na syū raktasruteryataḥ" },
      { type: "verse", number: "3", sanskrit: "मधुरं वर्णतो रक्तमशीतोष्णं तथा गुरु शोणितं स्निग्धविस्रं स्याद्विदाहश्चास्य पित्तवत्", text: "madhuraṃ varṇato raktamaśītoṣṇaṃ tathā guru śoṇitaṃ snigdhavisraṃ syādvidāhaścāsya pittavat" },
      { type: "verse", number: "4", sanskrit: "विस्रता द्र वता रागश्चलनं विलयस्तथा भूम्यादिपञ्चभूतानामेते रक्तगुणाः स्मृताः", text: "visratā dra vatā rāgaścalanaṃ vilayastathā bhūmyādipañcabhūtānāmete raktaguṇāḥ smṛtāḥ" },
      { type: "verse", number: "5", sanskrit: "रक्ते दुष्टे वेदना स्यात्पाको दाहश्च जायते रक्तमण्डलता कण्डूः शोथश्च पिटिकोद्गमः", text: "rakte duṣṭe vedanā syātpāko dāhaśca jāyate raktamaṇḍalatā kaṇḍūḥ śothaśca piṭikodgamaḥ" },
      { type: "verse", number: "6", sanskrit: "वृद्धे रक्ताङ्गनेत्रत्वं शिराणां पूरणं तथा गात्राणां गौरवं निद्रा  मदो दाहश्च जायते", text: "vṛddhe raktāṅganetratvaṃ śirāṇāṃ pūraṇaṃ tathā gātrāṇāṃ gauravaṃ nidrā  mado dāhaśca jāyate" },
      { type: "verse", number: "7", sanskrit: "क्षीणेऽम्लमधुराकाङ्क्षा मूर्च्छा च त्वचि रूक्षता शैथिल्यं च शिराणां स्याद्वातादुन्मार्गगामिता", text: "kṣīṇe'mlamadhurākāṅkṣā mūrcchā ca tvaci rūkṣatā śaithilyaṃ ca śirāṇāṃ syādvātādunmārgagāmitā" },
      { type: "verse", number: "8", sanskrit: "अरुणं फेनिलं रूक्षं परुषं तनु शीघ्रगम् अस्कन्दि सूचिनिस्तोदि रक्तं स्याद्वातदूषितम्", text: "aruṇaṃ phenilaṃ rūkṣaṃ paruṣaṃ tanu śīghragam askandi sūcinistodi raktaṃ syādvātadūṣitam" },
      { type: "verse", number: "9", sanskrit: "पित्तेन पीतं हरितं नीलं श्यावं च विस्रकम् अस्कन्द्युष्णं मक्षिकाणां पिपीलानामनिष्टकम्", text: "pittena pītaṃ haritaṃ nīlaṃ śyāvaṃ ca visrakam askandyuṣṇaṃ makṣikāṇāṃ pipīlānāmaniṣṭakam" },
      { type: "verse", number: "10", sanskrit: "शीतलं बहलं स्निग्धं गैरिकोदकसन्निभम् मांसपेशीप्रभं स्कन्दि मन्दगं कफदूषितम्", text: "śītalaṃ bahalaṃ snigdhaṃ gairikodakasannibham māṃsapeśīprabhaṃ skandi mandagaṃ kaphadūṣitam" },
      { type: "verse", number: "11", sanskrit: "द्विदोषदुष्टं संसृष्टं त्रिदुष्टं पूतिगन्धकम् सर्वलक्षणसंयुक्तं काञ्जिकाभं च जायते", text: "dvidoṣaduṣṭaṃ saṃsṛṣṭaṃ triduṣṭaṃ pūtigandhakam sarvalakṣaṇasaṃyuktaṃ kāñjikābhaṃ ca jāyate" },
      { type: "verse", number: "12", sanskrit: "विषदुष्टं भवेच्छ्यावं नासिकोन्मार्गगं तथा विस्रं काञ्जिकसङ्काशं सर्वकुष्ठकरं बहु", text: "viṣaduṣṭaṃ bhavecchyāvaṃ nāsikonmārgagaṃ tathā visraṃ kāñjikasaṅkāśaṃ sarvakuṣṭhakaraṃ bahu" },
      { type: "verse", number: "13", sanskrit: "इन्द्र गोपप्रभं ज्ञेयं प्रकृतिस्थमसंहतम्", text: "indra gopaprabhaṃ jñeyaṃ prakṛtisthamasaṃhatam" },
      { type: "verse", number: "14", sanskrit: "शोथे दाहेऽङ्गपाके च रक्तवर्णेऽसृजः स्रुतौ वातरक्ते तथा कुष्ठे सपीडे दुर्जयेऽनिले पाणिरोगे श्लीपदे च विषदुष्टे च शोणिते", text: "śothe dāhe'ṅgapāke ca raktavarṇe'sṛjaḥ srutau vātarakte tathā kuṣṭhe sapīḍe durjaye'nile pāṇiroge ślīpade ca viṣaduṣṭe ca śoṇite" },
      { type: "verse", number: "15", sanskrit: "ग्रन्थ्यर्बुदापचीक्षुद्र रोगरक्ताधिमन्थिषु विदारीस्तनरोगेषु गात्राणां सादगौरवे", text: "granthyarbudāpacīkṣudra rogaraktādhimanthiṣu vidārīstanarogeṣu gātrāṇāṃ sādagaurave" },
      { type: "verse", number: "16", sanskrit: "रक्ताभिष्यन्दतन्द्रा यां पूतिघ्राणास्यदेहके यकृत्प्लीहविसर्पेषु विद्र धौ पिटिकोद्गमे", text: "raktābhiṣyandatandrā yāṃ pūtighrāṇāsyadehake yakṛtplīhavisarpeṣu vidra dhau piṭikodgame" },
      { type: "verse", number: "17", sanskrit: "कर्णोष्ठघ्राणवक्त्राणां पाके दाहे शिरोरुजि उपदंशे रक्तपित्ते रक्तस्रावः प्रशस्यते", text: "karṇoṣṭhaghrāṇavaktrāṇāṃ pāke dāhe śiroruji upadaṃśe raktapitte raktasrāvaḥ praśasyate" },
      { type: "verse", number: "18", sanskrit: "एषु रोगेषु शृङ्गैर्वा जलौकाऽलाबुकैरपि अथवाऽपि शिरामोक्षैः कुर्याद्र क्तस्रुतिं नरः", text: "eṣu rogeṣu śṛṅgairvā jalaukā'lābukairapi athavā'pi śirāmokṣaiḥ kuryādra ktasrutiṃ naraḥ" },
      { type: "verse", number: "19", sanskrit: "न कुर्वीत शिरामोक्षं कृशस्यातिव्यवायिनः क्लीबस्य भीरोर्गर्भिण्याः सूतिकापाण्डुरोगिणाम्", text: "na kurvīta śirāmokṣaṃ kṛśasyātivyavāyinaḥ klībasya bhīrorgarbhiṇyāḥ sūtikāpāṇḍurogiṇām" },
      { type: "verse", number: "20", sanskrit: "पञ्चकर्मविशुद्धस्य पीतस्नेहस्य चार्शसाम् सर्वाङ्गशोथयुक्तानामुदरश्वासकासिनाम्", text: "pañcakarmaviśuddhasya pītasnehasya cārśasām sarvāṅgaśothayuktānāmudaraśvāsakāsinām" },
      { type: "verse", number: "21", sanskrit: "ऊनषोडशवर्षस्य गतसप्ततिकस्य च", text: "ūnaṣoḍaśavarṣasya gatasaptatikasya ca" },
      { type: "verse", number: "22", sanskrit: "आघातस्रुतरक्तस्य शिरामोक्षो न शस्यते एषां चात्ययिकेरोगे जलौकाभिस्तु निर्ह रेत्", text: "āghātasrutaraktasya śirāmokṣo na śasyate eṣāṃ cātyayikeroge jalaukābhistu nirha ret" },
      { type: "verse", number: "23", sanskrit: "विषदुष्टरक्तस्य स्रावप्रकारः तथा च विषदुष्टानां शिरामोक्षोऽपि शस्यते", text: "viṣaduṣṭaraktasya srāvaprakāraḥ tathā ca viṣaduṣṭānāṃ śirāmokṣo'pi śasyate" },
      { type: "verse", number: "24", sanskrit: "वातादिदोषानुसारेण रक्तस्रावप्रकारः गोशृङ्गेण जलौकाभिरलाबुभिरपि त्रिधा वातपित्तकफैर्दुष्टं शोणितं स्रावयेद् बुधः", text: "vātādidoṣānusāreṇa raktasrāvaprakāraḥ gośṛṅgeṇa jalaukābhiralābubhirapi tridhā vātapittakaphairduṣṭaṃ śoṇitaṃ srāvayed budhaḥ" },
      { type: "verse", number: "25", sanskrit: "द्विदोषाभ्यां तु सन्दुष्टं त्रिदोषैरपि दूषितम् शोणितं स्रावयेद्युक्त्या शिरामोक्षैः पदैस्तथा", text: "dvidoṣābhyāṃ tu sanduṣṭaṃ tridoṣairapi dūṣitam śoṇitaṃ srāvayedyuktyā śirāmokṣaiḥ padaistathā" },
      { type: "verse", number: "26", sanskrit: "शृङ्गादीनां शोणितग्रहणे प्रमाणम् गृह्णाति शोणितं शृङ्गं दशाङ्गुलमितं बलात् जलौका हस्तमात्रं तु तुम्बी च द्वादशाङ्गुलम् पदमङ्गुलमात्रस्य शिरा सर्वाङ्गशोधिनी", text: "śṛṅgādīnāṃ śoṇitagrahaṇe pramāṇam gṛhṇāti śoṇitaṃ śṛṅgaṃ daśāṅgulamitaṃ balāt jalaukā hastamātraṃ tu tumbī ca dvādaśāṅgulam padamaṅgulamātrasya śirā sarvāṅgaśodhinī" },
      { type: "verse", number: "27", sanskrit: "शीते निरन्ने मूर्च्छाऽतिनिद्रा भीतिमदश्रमैः युतानां न स्रवेद्र क्तं तथा विण्मूत्रसङ्गिनाम्", text: "śīte niranne mūrcchā'tinidrā bhītimadaśramaiḥ yutānāṃ na sravedra ktaṃ tathā viṇmūtrasaṅginām" },
      { type: "verse", number: "28", sanskrit: "अप्रवर्त्तितरक्ते च कुष्ठत्रिकटुसैन्धवैः मर्दयेद् व्रणवक्त्रं च तेन सम्यक्प्रवर्त्तते", text: "apravarttitarakte ca kuṣṭhatrikaṭusaindhavaiḥ mardayed vraṇavaktraṃ ca tena samyakpravarttate" },
      { type: "verse", number: "29", sanskrit: "तस्मान्न शीते नात्युष्णे न स्विन्ने नातितापिते पीत्वा यवागूं तृप्तस्य स्रावयेच्छोणितं बुधः", text: "tasmānna śīte nātyuṣṇe na svinne nātitāpite pītvā yavāgūṃ tṛptasya srāvayecchoṇitaṃ budhaḥ" },
      { type: "verse", number: "30", sanskrit: "अतिस्विन्नस्योष्णकाले तथ्वातिशिराव्यधात् अतिप्रवर्त्तते रक्तं तत्र कुर्यात्प्रतिक्रियाम्", text: "atisvinnasyoṣṇakāle tathvātiśirāvyadhāt atipravarttate raktaṃ tatra kuryātpratikriyām" },
      { type: "verse", number: "31", sanskrit: "अतिप्रवृत्ते रक्ते च लोध्रसर्जरसाञ्जनैः यवगोधूमचूणैर्वा धवधन्वनगैरिकैः", text: "atipravṛtte rakte ca lodhrasarjarasāñjanaiḥ yavagodhūmacūṇairvā dhavadhanvanagairikaiḥ" },
      { type: "verse", number: "32", sanskrit: "सर्पनिर्मोकचूर्णैर्वा भस्मना क्षौमवस्त्रयोः मुखं व्रणस्य बध्वा च शीतैश्चोपचरेद्व्रणम्", text: "sarpanirmokacūrṇairvā bhasmanā kṣaumavastrayoḥ mukhaṃ vraṇasya badhvā ca śītaiścopacaredvraṇam" },
      { type: "verse", number: "33", sanskrit: "विध्येदूर्ध्वशिरां तां च दहेत्क्षारेण वाऽग्निना व्रणं कषायः सन्धत्ते रक्तं स्कन्दयते हिमम् व्रणास्यं पाचयेत्क्षारो दाहः सङ्कोचयेच्छिराम्", text: "vidhyedūrdhvaśirāṃ tāṃ ca dahetkṣāreṇa vā'gninā vraṇaṃ kaṣāyaḥ sandhatte raktaṃ skandayate himam vraṇāsyaṃ pācayetkṣāro dāhaḥ saṅkocayecchirām" },
      { type: "verse", number: "34", sanskrit: "तत्र मुष्कशोथे कराङ्गुष्ठदाहनिर्देशः वामाण्डशोथे दक्षस्य करस्याङ्गुष्ठमूलजाम्", text: "tatra muṣkaśothe karāṅguṣṭhadāhanirdeśaḥ vāmāṇḍaśothe dakṣasya karasyāṅguṣṭhamūlajām" },
      { type: "verse", number: "35", sanskrit: "दहेच्छिरां व्यत्यये तु वामाङ्गुष्ठशिरां दहेत् शिरादाहप्रभावेण मुष्कशोथः प्रणश्यति", text: "dahecchirāṃ vyatyaye tu vāmāṅguṣṭhaśirāṃ dahet śirādāhaprabhāveṇa muṣkaśothaḥ praṇaśyati" },
      { type: "verse", number: "36", sanskrit: "विषूच्यां पार्ष्णिदाहव्यवस्था विषूच्यां पार्ष्णिदाहेन जायतेऽग्ने प्रदीपनम् सङ्कुचन्ति यतस्तेन रसश्लेष्मवहाः शिराः", text: "viṣūcyāṃ pārṣṇidāhavyavasthā viṣūcyāṃ pārṣṇidāhena jāyate'gne pradīpanam saṅkucanti yatastena rasaśleṣmavahāḥ śirāḥ" },
      { type: "verse", number: "37", sanskrit: "रक्तजबालयकृत्प्लीहवृद्धौ तत्स्थानदाहव्यवस्था यदावृद्धिर्यकृत्प्लीह्नोः शिशोः सञ्जायतेऽसृजः तदा तत्स्थानदाहेन सङ्कुचन्त्यसृजः शिराः", text: "raktajabālayakṛtplīhavṛddhau tatsthānadāhavyavasthā yadāvṛddhiryakṛtplīhnoḥ śiśoḥ sañjāyate'sṛjaḥ tadā tatsthānadāhena saṅkucantyasṛjaḥ śirāḥ" },
      { type: "verse", number: "38", sanskrit: "रक्ते दुष्टेऽवशिष्टेऽपि व्याधिर्नैव प्रकुप्यति अतः स्राव्यं सावशेषं रक्ते नातिक्रमो हितः", text: "rakte duṣṭe'vaśiṣṭe'pi vyādhirnaiva prakupyati ataḥ srāvyaṃ sāvaśeṣaṃ rakte nātikramo hitaḥ" },
      { type: "verse", number: "39", sanskrit: "आन्ध्यमाक्षेपकं तृष्णां तिमिरं शिरसो रुजम् पक्षाघातं श्वासकासौ हिक्कां दाहं च पांडुताम् कुरुतेऽतिस्रुतं रक्तं मरणं वा करोति च", text: "āndhyamākṣepakaṃ tṛṣṇāṃ timiraṃ śiraso rujam pakṣāghātaṃ śvāsakāsau hikkāṃ dāhaṃ ca pāṃḍutām kurute'tisrutaṃ raktaṃ maraṇaṃ vā karoti ca" },
      { type: "verse", number: "40", sanskrit: "देहस्योत्पत्तिरसृजा देहस्तेनैव धार्यते विना तेन व्रजेज्जीवो रक्षेद्र क्तमतोबुधः", text: "dehasyotpattirasṛjā dehastenaiva dhāryate vinā tena vrajejjīvo rakṣedra ktamatobudhaḥ" },
      { type: "verse", number: "41", sanskrit: "स्रुते रक्तेऽपि दोषकोपे प्रतीकारः शीतोपचारः कुपिते स्रुतरक्तस्य मारुते कोष्णेन सर्पिषा शोथं सव्यथं परिषेचयेत्", text: "srute rakte'pi doṣakope pratīkāraḥ śītopacāraḥ kupite srutaraktasya mārute koṣṇena sarpiṣā śothaṃ savyathaṃ pariṣecayet" },
      { type: "verse", number: "42", sanskrit: "रक्तस्रुतिक्षीणस्य पथ्यव्यवस्था क्षीणस्यैणशशोरभ्रहरिणच्छागमांसजः रसः समुचितः पाने क्षीरं वा षष्टिका हिताः", text: "raktasrutikṣīṇasya pathyavyavasthā kṣīṇasyaiṇaśaśorabhrahariṇacchāgamāṃsajaḥ rasaḥ samucitaḥ pāne kṣīraṃ vā ṣaṣṭikā hitāḥ" },
      { type: "verse", number: "43", sanskrit: "पीडाशान्तिर्लघुत्वं च व्याधेरुद्रे कसंक्षयः मनः स्वास्थ्यं भवेच्चिह्नं सम्यग्विस्रावितेऽसृजि", text: "pīḍāśāntirlaghutvaṃ ca vyādherudre kasaṃkṣayaḥ manaḥ svāsthyaṃ bhaveccihnaṃ samyagvisrāvite'sṛji" },
      { type: "verse", number: "44", sanskrit: "रक्तस्रावोत्तरं वर्ज्याविषयाः व्यायाममैथुनक्रोधशीतस्नानप्रवातकान्", text: "raktasrāvottaraṃ varjyāviṣayāḥ vyāyāmamaithunakrodhaśītasnānapravātakān" },
      { type: "verse", number: "45", sanskrit: "एकाशनं दिवास्वप्नं क्षाराम्लकटुभोजनम् शोकं वादमजीर्णं च त्यजेदाबलदर्शनात्", text: "ekāśanaṃ divāsvapnaṃ kṣārāmlakaṭubhojanam śokaṃ vādamajīrṇaṃ ca tyajedābaladarśanāt" },
    ],
  },
  {
    sthana: "Уттаракханда",
    number: 13,
    lang: 'sa',
    content: [
      { type: "heading", heading: "Паримана санграха — Завершение" },
      { type: "text", text: "Заключительная глава Шарангадхара-самхиты подводит итог всей системе аюрведической фармакологии. Автор призывает к чистоте в приготовлении лекарств." },
      { type: "verse", number: "1", sanskrit: "अथ नेत्रप्रसादनकर्मनाम त्रयोदशोऽध्यायः तत्रादौ तन्नामानि सेकं आश्च्योतनं पिण्डी बिडालस्तर्पणं तथा पुटपाकोऽञ्जनं चैभिः कल्पैर्नेत्रमुपाचरेत्", text: "atha netraprasādanakarmanāma trayodaśo'dhyāyaḥ tatrādau tannāmāni sekaṃ āścyotanaṃ piṇḍī biḍālastarpaṇaṃ tathā puṭapāko'ñjanaṃ caibhiḥ kalpairnetramupācaret" },
      { type: "verse", number: "2", sanskrit: "सेकस्तु सूक्ष्मधाराभिः सर्वस्मिन्नयने हितः मीलिताक्षस्य मत्तर्यस्य प्रदेयश्चतुरङ्गुलात्", text: "sekastu sūkṣmadhārābhiḥ sarvasminnayane hitaḥ mīlitākṣasya mattaryasya pradeyaścaturaṅgulāt" },
      { type: "verse", number: "3", sanskrit: "स चापि स्नेहनो वाते रक्ते पित्ते च रोपणः लेखनश्च कफे कार्यस्तस्य मात्राऽधुनोच्यते", text: "sa cāpi snehano vāte rakte pitte ca ropaṇaḥ lekhanaśca kaphe kāryastasya mātrā'dhunocyate" },
      { type: "verse", number: "4", sanskrit: "षड्वाक्शतैः स्नेहनेषु चतुर्भिश्चैव रोपणे वाक्शतैश्च त्रिभिः कार्यः सेकोलेखनकर्मणि", text: "ṣaḍvākśataiḥ snehaneṣu caturbhiścaiva ropaṇe vākśataiśca tribhiḥ kāryaḥ sekolekhanakarmaṇi" },
      { type: "verse", number: "5", sanskrit: "कार्यस्तु दिवसे सेको रात्रौ चात्ययिके गदे", text: "kāryastu divase seko rātrau cātyayike gade" },
      { type: "verse", number: "6", sanskrit: "एरण्डत्वक्पत्रमूलैः शृतमाजं पयोहितम् सुखोष्णं सेचनं नेत्रे वाताभिष्यन्दनाशनम्", text: "eraṇḍatvakpatramūlaiḥ śṛtamājaṃ payohitam sukhoṣṇaṃ secanaṃ netre vātābhiṣyandanāśanam" },
      { type: "verse", number: "7", sanskrit: "वाताभिष्यन्द मारुतपर्ययशुष्काक्षिपाकेषु सेकौ परिषेकोहितोनेत्रे पयः कोष्णं ससैन्धवम् रजनीदारुसिद्धं वा सैन्धवेनसमन्वितम्", text: "vātābhiṣyanda mārutaparyayaśuṣkākṣipākeṣu sekau pariṣekohitonetre payaḥ koṣṇaṃ sasaindhavam rajanīdārusiddhaṃ vā saindhavenasamanvitam" },
      { type: "verse", number: "8", sanskrit: "वाताभिष्यन्दशमनं हितं मारुतपर्यये शुष्काक्षिपाके च हितमिदं सेचनकं सदा", text: "vātābhiṣyandaśamanaṃ hitaṃ mārutaparyaye śuṣkākṣipāke ca hitamidaṃ secanakaṃ sadā" },
      { type: "verse", number: "9", sanskrit: "साबरं मधुकं तुल्यं घृतभृष्टं सुचूर्णितम् छागक्षीरे घृतं सेकात्पित्तरक्ताभिघातजित्", text: "sābaraṃ madhukaṃ tulyaṃ ghṛtabhṛṣṭaṃ sucūrṇitam chāgakṣīre ghṛtaṃ sekātpittaraktābhighātajit" },
      { type: "verse", number: "10", sanskrit: "त्रिफलालोध्रयष्टीभिः शर्कराभद्र मुस्तकैः पिष्टः शीताम्बुना सेको रक्ताभिष्यन्दनाशनः", text: "triphalālodhrayaṣṭībhiḥ śarkarābhadra mustakaiḥ piṣṭaḥ śītāmbunā seko raktābhiṣyandanāśanaḥ" },
      { type: "verse", number: "11", sanskrit: "पुण्डरीकयुतः सेको रक्ताभिष्यन्दनाशनः", text: "puṇḍarīkayutaḥ seko raktābhiṣyandanāśanaḥ" },
      { type: "verse", number: "12", sanskrit: "श्वेतलोध्रं घृते भृष्टं चूर्णितं पटविस्रुतम् उष्णाम्बुना विमृदितं सेकाच्छूलघ्नमम्बके", text: "śvetalodhraṃ ghṛte bhṛṣṭaṃ cūrṇitaṃ paṭavisrutam uṣṇāmbunā vimṛditaṃ sekācchūlaghnamambake" },
      { type: "verse", number: "13", sanskrit: "अथाश्च्योतनकं कार्यं निशायां न कथंचन", text: "athāścyotanakaṃ kāryaṃ niśāyāṃ na kathaṃcana" },
      { type: "verse", number: "14", sanskrit: "उन्मीलितेऽक्ष्णि दृङ्मध्ये बिन्दुभिर्द्व्यङ्गुलाद्धितम्", text: "unmīlite'kṣṇi dṛṅmadhye bindubhirdvyaṅgulāddhitam" },
      { type: "verse", number: "15", sanskrit: "गुणानुसारेण बिन्दुप्रक्षेपसंख्यानिर्देशः बिन्दवोऽष्टौ लेखनेषु स्नेहने दश बिन्दवः रोपणे द्वादश प्रोक्तास्ते शीतेकोष्णरूपिणः उष्णे च शीतरूपाः स्युः सर्वत्रैवैष निश्चयः", text: "guṇānusāreṇa binduprakṣepasaṃkhyānirdeśaḥ bindavo'ṣṭau lekhaneṣu snehane daśa bindavaḥ ropaṇe dvādaśa proktāste śītekoṣṇarūpiṇaḥ uṣṇe ca śītarūpāḥ syuḥ sarvatraivaiṣa niścayaḥ" },
      { type: "verse", number: "16", sanskrit: "वाते तिक्तं तथा स्निग्धं पित्ते मधुरशीतलम् तिक्तोष्णरूक्षं च कफे क्रमादाश्च्योतनं हितम्", text: "vāte tiktaṃ tathā snigdhaṃ pitte madhuraśītalam tiktoṣṇarūkṣaṃ ca kaphe kramādāścyotanaṃ hitam" },
      { type: "verse", number: "17", sanskrit: "आश्च्योतनानां सर्वेषां मात्रा स्याद्वाक्शतं हिता निमेषोन्मेषणं पुंसामङ्गुल्याच्छोटिकाऽथवा गुर्वक्षरोच्चारणं वा वाङ्मात्रेयं स्मृता बुधैः", text: "āścyotanānāṃ sarveṣāṃ mātrā syādvākśataṃ hitā nimeṣonmeṣaṇaṃ puṃsāmaṅgulyācchoṭikā'thavā gurvakṣaroccāraṇaṃ vā vāṅmātreyaṃ smṛtā budhaiḥ" },
      { type: "verse", number: "18", sanskrit: "बिल्वादिपञ्चमूलेन बृहत्येरण्डशिग्रुभिः क्वाथ आश्च्योतने कोष्णो वाताभिष्यन्दनाशनः", text: "bilvādipañcamūlena bṛhatyeraṇḍaśigrubhiḥ kvātha āścyotane koṣṇo vātābhiṣyandanāśanaḥ" },
      { type: "verse", number: "19", sanskrit: "अम्बुपिष्टैर्निम्बपत्रैस्त्वचं लोध्रस्य लेपयेत् प्रताप्य वह्निना पिष्ट्वा तद्र सो नेत्रपूरणात् वातोत्थं रक्तपित्तोत्थमभिष्यन्दं विनाशयेत्", text: "ambupiṣṭairnimbapatraistvacaṃ lodhrasya lepayet pratāpya vahninā piṣṭvā tadra so netrapūraṇāt vātotthaṃ raktapittotthamabhiṣyandaṃ vināśayet" },
      { type: "verse", number: "20", sanskrit: "त्रिफलाश्च्योतनं नेत्रे सर्वाभिष्यन्दनाशनम्", text: "triphalāścyotanaṃ netre sarvābhiṣyandanāśanam" },
      { type: "verse", number: "21", sanskrit: "स्त्रीस्तन्याश्च्योतनं नेत्रे रक्तपित्तानिलार्त्तिजित् क्षीरसर्पिर्घृतं वाऽपि वातरक्तरुजं जयेत्", text: "strīstanyāścyotanaṃ netre raktapittānilārttijit kṣīrasarpirghṛtaṃ vā'pi vātaraktarujaṃ jayet" },
      { type: "verse", number: "22", sanskrit: "पिण्डी कवलिका प्रोक्ता बद्ध्य्ते पट्टवस्त्रकैः नेत्राभिष्यन्दयोग्या सा व्रणेष्वपि निबद्ध्यते", text: "piṇḍī kavalikā proktā baddhyte paṭṭavastrakaiḥ netrābhiṣyandayogyā sā vraṇeṣvapi nibaddhyate" },
      { type: "verse", number: "23", sanskrit: "अभिष्यन्दाधिमन्थयोः शिरोविरेचनम् अभिष्यन्देऽधिमन्थे च सञ्जाते श्लेष्मसम्भवे स्निग्धस्विन्नोत्तमाङ्गस्य शिरस्तीक्ष्णैर्विरेचयेत्", text: "abhiṣyandādhimanthayoḥ śirovirecanam abhiṣyande'dhimanthe ca sañjāte śleṣmasambhave snigdhasvinnottamāṅgasya śirastīkṣṇairvirecayet" },
      { type: "verse", number: "24", sanskrit: "अधिमन्थेषु सर्वेषु ललाटे वेधयेच्छिराम् अशान्ते सर्वथा मन्थे भ्रुवोरुपरि दाहयेत्", text: "adhimantheṣu sarveṣu lalāṭe vedhayecchirām aśānte sarvathā manthe bhruvorupari dāhayet" },
      { type: "verse", number: "25", sanskrit: "सर्वाभिष्यन्दे पिण्डिकाप्रयोगः अभिष्यन्देषु सर्वेषु बध्नीयात्पिण्डिकां बुधः", text: "sarvābhiṣyande piṇḍikāprayogaḥ abhiṣyandeṣu sarveṣu badhnīyātpiṇḍikāṃ budhaḥ" },
      { type: "verse", number: "26", sanskrit: "वाताभिष्यन्दे पिण्डिकाप्रयोगः वातामिष्यन्दशान्त्यर्थं स्निग्धोष्णा पिण्डिका भवेत् एरण्डपत्रमूलत्वङ्निर्मिता वातनाशिनी", text: "vātābhiṣyande piṇḍikāprayogaḥ vātāmiṣyandaśāntyarthaṃ snigdhoṣṇā piṇḍikā bhavet eraṇḍapatramūlatvaṅnirmitā vātanāśinī" },
      { type: "verse", number: "27", sanskrit: "पित्ताभिष्यन्दे पिण्डीद्वयम् पित्ताभिष्यन्दनाशाय धात्रीपिंडी सुखावहा महा निम्बफलोद्भूता पिंडी वा पित्तनाशिनी", text: "pittābhiṣyande piṇḍīdvayam pittābhiṣyandanāśāya dhātrīpiṃḍī sukhāvahā mahā nimbaphalodbhūtā piṃḍī vā pittanāśinī" },
      { type: "verse", number: "28", sanskrit: "शिग्रुपत्रकृता पिण्डी श्लेष्माभिष्यन्दनाशिनी", text: "śigrupatrakṛtā piṇḍī śleṣmābhiṣyandanāśinī" },
      { type: "verse", number: "29", sanskrit: "कफपित्ताभिष्यन्दे पिण्डीद्वयम् निम्बपत्रकृता पिण्डी श्लेष्मपित्तहरा भवेत् त्रिफलापिण्डिका प्रोक्ता नाशने श्लेष्मपित्तयोः", text: "kaphapittābhiṣyande piṇḍīdvayam nimbapatrakṛtā piṇḍī śleṣmapittaharā bhavet triphalāpiṇḍikā proktā nāśane śleṣmapittayoḥ" },
      { type: "verse", number: "30", sanskrit: "पिष्ट्वा काञ्जिकतोयेन घृतभृष्टा च पिण्डिका लोध्रस्य हरति क्षिप्रमभिष्यन्दमसृग्भवम्", text: "piṣṭvā kāñjikatoyena ghṛtabhṛṣṭā ca piṇḍikā lodhrasya harati kṣipramabhiṣyandamasṛgbhavam" },
      { type: "verse", number: "31", sanskrit: "शुण्ठीनिम्बदलैः पिण्डी सुखोष्णा स्वल्पसैन्धवा धार्या चक्षुषि संयोगाच्छोथकण्डूव्यथाऽपहा", text: "śuṇṭhīnimbadalaiḥ piṇḍī sukhoṣṇā svalpasaindhavā dhāryā cakṣuṣi saṃyogācchothakaṇḍūvyathā'pahā" },
      { type: "verse", number: "32", sanskrit: "बिडालको बहिर्लेपो नेत्रे पक्ष्मविवर्जितः तस्य मात्रा परिज्ञेया मुखलेपविधानवत्", text: "biḍālako bahirlepo netre pakṣmavivarjitaḥ tasya mātrā parijñeyā mukhalepavidhānavat" },
      { type: "verse", number: "33", sanskrit: "यष्टीगैरिकसिन्धूत्थदार्वीतार्क्ष्यः समांशकैः जलपिष्टैर्बहिर्लेपः सर्वनेत्रामयापहः", text: "yaṣṭīgairikasindhūtthadārvītārkṣyaḥ samāṃśakaiḥ jalapiṣṭairbahirlepaḥ sarvanetrāmayāpahaḥ" },
      { type: "verse", number: "34", sanskrit: "रसाञ्जनेन वा लेपः पथ्याविश्वदलैरपि कुमारिकाऽग्निपत्रैर्वा दाडिमीपल्लवैरपि वचाहरिद्रा निम्बैर्वा तथा नागरगैरिकैः", text: "rasāñjanena vā lepaḥ pathyāviśvadalairapi kumārikā'gnipatrairvā dāḍimīpallavairapi vacāharidrā nimbairvā tathā nāgaragairikaiḥ" },
      { type: "verse", number: "35", sanskrit: "दग्ध्वा ससैन्धवं लोध्रं मधूच्छिष्टयुते घृते पिष्टमञ्जनलेपाभ्यां सद्यो नेत्ररुजाऽपहम्", text: "dagdhvā sasaindhavaṃ lodhraṃ madhūcchiṣṭayute ghṛte piṣṭamañjanalepābhyāṃ sadyo netrarujā'paham" },
      { type: "verse", number: "36", sanskrit: "लोहस्य पात्रे संघृष्टो रसो निम्बफलोद्भवः किञ्चिद्घनो बहिर्लेपान्नेत्रबाधां व्यपोहति", text: "lohasya pātre saṃghṛṣṭo raso nimbaphalodbhavaḥ kiñcidghano bahirlepānnetrabādhāṃ vyapohati" },
      { type: "verse", number: "37", sanskrit: "संचूर्ण्य मरिचं केशराजस्वरसमर्दनात् लेपनादर्मणां नाशं करोत्येष प्रयोगराट्", text: "saṃcūrṇya maricaṃ keśarājasvarasamardanāt lepanādarmaṇāṃ nāśaṃ karotyeṣa prayogarāṭ" },
      { type: "verse", number: "38", sanskrit: "स्विन्नां भित्वा विनिष्पीड्य भिन्नामञ्जननामिकाम् शिलैलानतसिन्धूत्थैः सक्षौद्रै ः! प्रतिसारयेत्", text: "svinnāṃ bhitvā viniṣpīḍya bhinnāmañjananāmikām śilailānatasindhūtthaiḥ sakṣaudrai ḥ! pratisārayet" },
      { type: "verse", number: "39", sanskrit: "तत्रादौ तर्पणयोग्यनेत्रलक्षणम् अथ तर्पणकं वच्मि नेत्रतृप्तिकरं परम् यद्रू क्षं परिशुष्कं च नेत्रं कुटिलमाविलम्", text: "tatrādau tarpaṇayogyanetralakṣaṇam atha tarpaṇakaṃ vacmi netratṛptikaraṃ param yadrū kṣaṃ pariśuṣkaṃ ca netraṃ kuṭilamāvilam" },
      { type: "verse", number: "40", sanskrit: "शीर्णपक्ष्मशिरोत्पातकृच्छ्रोन्मीलन संयुतम् तिमिरार्जुनशुक्राद्यैरभिष्यन्दाधिमन्थकैः", text: "śīrṇapakṣmaśirotpātakṛcchronmīlana saṃyutam timirārjunaśukrādyairabhiṣyandādhimanthakaiḥ" },
      { type: "verse", number: "41", sanskrit: "शुष्काक्षिपाकशोथाभ्यां युक्तं वातविपर्ययैः तन्नेत्रं तर्पणे योज्यं नेत्ररोगविशारदैः तर्पणे वर्ज्यविषयाः दुर्दिनात्युष्णशीतेषु चिन्तायासभ्रमेषु च अशान्तोपद्र वे चाक्ष्णि तर्पणं न प्रशस्यते", text: "śuṣkākṣipākaśothābhyāṃ yuktaṃ vātaviparyayaiḥ tannetraṃ tarpaṇe yojyaṃ netrarogaviśāradaiḥ tarpaṇe varjyaviṣayāḥ durdinātyuṣṇaśīteṣu cintāyāsabhrameṣu ca aśāntopadra ve cākṣṇi tarpaṇaṃ na praśasyate" },
      { type: "verse", number: "42", sanskrit: "वातातपरजोहीने देशे चोत्तानशायिनः आधारौ माषचूर्णेन क्लिन्नेन परिमण्डलौ", text: "vātātaparajohīne deśe cottānaśāyinaḥ ādhārau māṣacūrṇena klinnena parimaṇḍalau" },
      { type: "verse", number: "43", sanskrit: "समौ दृढावसम्बाधौ कर्त्तव्यौ नेत्रकोशयोः पूरयेद् घृतमण्डेन विलीनेन सुखोदकैः अथवा शतधौतेन सर्पिषा क्षीरजेन वा", text: "samau dṛḍhāvasambādhau karttavyau netrakośayoḥ pūrayed ghṛtamaṇḍena vilīnena sukhodakaiḥ athavā śatadhautena sarpiṣā kṣīrajena vā" },
      { type: "verse", number: "44", sanskrit: "निमग्नान्यक्षिपक्ष्माणि यावत्स्युस्तावदेव हि पूरयेन्मीलिते नेत्रे तत उन्मीलयेच्छनैः", text: "nimagnānyakṣipakṣmāṇi yāvatsyustāvadeva hi pūrayenmīlite netre tata unmīlayecchanaiḥ" },
      { type: "verse", number: "45", sanskrit: "धारयेद्वर्त्मरोगेषु वाङ्मात्राणां शतं बुधः", text: "dhārayedvartmarogeṣu vāṅmātrāṇāṃ śataṃ budhaḥ" },
      { type: "verse", number: "46", sanskrit: "स्वच्छे कफे सन्धिरोगे मात्रापञ्चशतं हितम् शुक्ले च षट्शतं कृष्णरोगे सप्तशतं मतम्", text: "svacche kaphe sandhiroge mātrāpañcaśataṃ hitam śukle ca ṣaṭśataṃ kṛṣṇaroge saptaśataṃ matam" },
      { type: "verse", number: "47", sanskrit: "दृष्टिरोगेष्वष्टशतमधिमन्थे सहस्रकम् सहस्रं वातरोगेषु धार्यमेवं हि तर्पणम्", text: "dṛṣṭirogeṣvaṣṭaśatamadhimanthe sahasrakam sahasraṃ vātarogeṣu dhāryamevaṃ hi tarpaṇam" },
      { type: "verse", number: "48", sanskrit: "स्विन्नेन यवपिष्टेन स्नेहवीर्येरितं ततः यथास्वं धूमपानेन कफमस्य विशोधयेत्", text: "svinnena yavapiṣṭena snehavīryeritaṃ tataḥ yathāsvaṃ dhūmapānena kaphamasya viśodhayet" },
      { type: "verse", number: "49", sanskrit: "एकाहं वा त्र्! यहं वाऽपि पञ्चाहं चेष्यते परम्", text: "ekāhaṃ vā tr! yahaṃ vā'pi pañcāhaṃ ceṣyate param" },
      { type: "verse", number: "50", sanskrit: "तर्पणे तृप्तिलिङ्गानि नेत्रेष्वेतानि भावयेत् सुखस्वप्नावबोधत्वं वैशद्यं वर्णपाटवम् निवृत्तिर्व्याधिशान्तिश्च क्रियालाघवमेव च", text: "tarpaṇe tṛptiliṅgāni netreṣvetāni bhāvayet sukhasvapnāvabodhatvaṃ vaiśadyaṃ varṇapāṭavam nivṛttirvyādhiśāntiśca kriyālāghavameva ca" },
      { type: "verse", number: "51", sanskrit: "अथ साश्रु गुरु स्निग्धं नेत्रं स्यादतितर्पितम्", text: "atha sāśru guru snigdhaṃ netraṃ syādatitarpitam" },
      { type: "verse", number: "52", sanskrit: "रूक्षमस्राविलं रुग्णं नेत्रं स्याद्धीनतर्पितम्", text: "rūkṣamasrāvilaṃ rugṇaṃ netraṃ syāddhīnatarpitam" },
      { type: "verse", number: "53", sanskrit: "रूक्षस्निग्धोपचाराभ्यामेतयोः स्यात्प्रतिक्रिया", text: "rūkṣasnigdhopacārābhyāmetayoḥ syātpratikriyā" },
      { type: "verse", number: "54", sanskrit: "अत ऊर्ध्वं प्रवक्ष्यामि पुटपाकस्य साधनम् द्वौ बिल्वमात्रौ मांसस्य पिण्डौ स्निग्धौ सुपेषितौ", text: "ata ūrdhvaṃ pravakṣyāmi puṭapākasya sādhanam dvau bilvamātrau māṃsasya piṇḍau snigdhau supeṣitau" },
      { type: "verse", number: "55", sanskrit: "द्र व्याणां बिल्वमात्रं तु द्र वाणां कुडवो मतः तदेकस्थं समालोड्य पत्रैः सुपरिवेष्टितम् पुटपाकेन तत्पक्त्वा गृह्णीयात्तद्र सं बुधः दृष्टिमध्ये निषेच्यः स्यान्नित्यमुत्तानशायिनः", text: "dra vyāṇāṃ bilvamātraṃ tu dra vāṇāṃ kuḍavo mataḥ tadekasthaṃ samāloḍya patraiḥ supariveṣṭitam puṭapākena tatpaktvā gṛhṇīyāttadra saṃ budhaḥ dṛṣṭimadhye niṣecyaḥ syānnityamuttānaśāyinaḥ" },
      { type: "verse", number: "56", sanskrit: "स्नेहनो लेखनश्चैव रोपणश्चेति स त्रिधा", text: "snehano lekhanaścaiva ropaṇaśceti sa tridhā" },
      { type: "verse", number: "57", sanskrit: "हितः स्निग्धोऽतिरूक्षस्य स्निग्धस्यापि हि लेखनः दृष्टेर्बलार्थमितरः पित्तासृग्व्रणवातनुत्", text: "hitaḥ snigdho'tirūkṣasya snigdhasyāpi hi lekhanaḥ dṛṣṭerbalārthamitaraḥ pittāsṛgvraṇavātanut" },
      { type: "verse", number: "58", sanskrit: "सर्पिर्मांसवसामज्जामेदःस्वाद्वौषधैः कृतः स्नेहनः पुटपाकस्तु धार्यो द्वे वाक्शते दृशोः", text: "sarpirmāṃsavasāmajjāmedaḥsvādvauṣadhaiḥ kṛtaḥ snehanaḥ puṭapākastu dhāryo dve vākśate dṛśoḥ" },
      { type: "verse", number: "59", sanskrit: "जाङ्गलानां यकृन्मांसैर्लेखनद्र व्यसंयुतैः कृष्णलोहरजस्ताम्रशङ्खविद्रुमसिन्धुजैः समुद्र फेनकासीसस्रोतोजदधिमस्तुभिः लेखनो वाक्शतं धार्यस्तस्यैतावद्विधारणम्", text: "jāṅgalānāṃ yakṛnmāṃsairlekhanadra vyasaṃyutaiḥ kṛṣṇaloharajastāmraśaṅkhavidrumasindhujaiḥ samudra phenakāsīsasrotojadadhimastubhiḥ lekhano vākśataṃ dhāryastasyaitāvadvidhāraṇam" },
      { type: "verse", number: "60", sanskrit: "स्तन्यजाङ्गलमध्वाज्यतिक्तकद्र व्यपाचितः लेखनात्त्रिगुणो धार्यः पुटपाकस्तु रोपणः", text: "stanyajāṅgalamadhvājyatiktakadra vyapācitaḥ lekhanāttriguṇo dhāryaḥ puṭapākastu ropaṇaḥ" },
      { type: "verse", number: "61", sanskrit: "वितरेत्तर्पणोक्तां तु क्रियां व्यापत्तिदर्शने", text: "vitarettarpaṇoktāṃ tu kriyāṃ vyāpattidarśane" },
      { type: "verse", number: "62", sanskrit: "अथ सम्पक्वदोषस्य प्राप्तमञ्जनमाचरेत् हेमन्ते शिशिरे चैव मध्याह्नेऽञ्जनमिष्यते", text: "atha sampakvadoṣasya prāptamañjanamācaret hemante śiśire caiva madhyāhne'ñjanamiṣyate" },
      { type: "verse", number: "63", sanskrit: "पूर्वाह्णे चापराह्णेच ग्रीष्मे शरदि चेष्यते वर्षासु नाभ्रे नात्युष्णे वसन्ते च सदैव हि", text: "pūrvāhṇe cāparāhṇeca grīṣme śaradi ceṣyate varṣāsu nābhre nātyuṣṇe vasante ca sadaiva hi" },
      { type: "verse", number: "64", sanskrit: "लेखनं रोपणं चैव तथा स्यात्स्नेहनाञ्जनम्", text: "lekhanaṃ ropaṇaṃ caiva tathā syātsnehanāñjanam" },
      { type: "verse", number: "65", sanskrit: "लेखनं क्षारतीक्ष्णाम्लरसैरञ्जनमिष्यते कषायतिक्तरसयुक्सस्नेहं रोपणं मतम् मधुरं स्नेहसम्पन्नमञ्जनं च प्रसादनम्", text: "lekhanaṃ kṣāratīkṣṇāmlarasairañjanamiṣyate kaṣāyatiktarasayuksasnehaṃ ropaṇaṃ matam madhuraṃ snehasampannamañjanaṃ ca prasādanam" },
      { type: "verse", number: "66", sanskrit: "गुटिकारसचूर्णानि त्रिविधान्यञ्जनानि च कुर्याच्छलाकयाऽङ्गुल्या हीनानि च यथोत्तरम्", text: "guṭikārasacūrṇāni trividhānyañjanāni ca kuryācchalākayā'ṅgulyā hīnāni ca yathottaram" },
      { type: "verse", number: "67", sanskrit: "श्रान्ते प्ररुदिते भीते पीतमद्ये नवज्वरे अजीर्णे वेगघाते च नाञ्जनं सम्प्रशस्यते", text: "śrānte prarudite bhīte pītamadye navajvare ajīrṇe vegaghāte ca nāñjanaṃ sampraśasyate" },
      { type: "verse", number: "68", sanskrit: "हरेणुमात्रां कुर्वीत वर्त्तिं तीक्ष्णाञ्जने भिषक् प्रमाणं मध्यमेऽध्यर्द्धं द्विगुणं तु मृदौ भवेत्", text: "hareṇumātrāṃ kurvīta varttiṃ tīkṣṇāñjane bhiṣak pramāṇaṃ madhyame'dhyarddhaṃ dviguṇaṃ tu mṛdau bhavet" },
      { type: "verse", number: "69", sanskrit: "रसक्रिया तूत्तमा स्यात्त्रिविडङ्गमिता हिता मध्यमा द्विविडङ्गा स्याद्धीना त्वेकविडङ्गिका", text: "rasakriyā tūttamā syāttriviḍaṅgamitā hitā madhyamā dviviḍaṅgā syāddhīnā tvekaviḍaṅgikā" },
      { type: "verse", number: "70", sanskrit: "वैरेचनिकचूर्णं तु द्विशलाकं विधीयते मृदौ तु त्रिशलाकं स्याच्चतस्रः स्नैहिकेऽञ्जने", text: "vairecanikacūrṇaṃ tu dviśalākaṃ vidhīyate mṛdau tu triśalākaṃ syāccatasraḥ snaihike'ñjane" },
      { type: "verse", number: "71", sanskrit: "मुखयोः कुण्ठिता श्लक्ष्णा शलाकाऽष्टाङ्गुलोन्मिता अश्मजा धातुजा वा स्यात्कलायपरिमण्डला", text: "mukhayoḥ kuṇṭhitā ślakṣṇā śalākā'ṣṭāṅgulonmitā aśmajā dhātujā vā syātkalāyaparimaṇḍalā" },
      { type: "verse", number: "72", sanskrit: "ताम्रलोहाश्मसञ्जाता शलाका लेखने मता सुवर्णरजतोद्भूता शलाका स्नेहने मता अङ्गुली च मृदुत्वेन कथिता रोपणे बुधैः", text: "tāmralohāśmasañjātā śalākā lekhane matā suvarṇarajatodbhūtā śalākā snehane matā aṅgulī ca mṛdutvena kathitā ropaṇe budhaiḥ" },
      { type: "verse", number: "73", sanskrit: "सायं प्रातर्वाञ्जनं स्यात्तत्सदा नैव कारयेत्", text: "sāyaṃ prātarvāñjanaṃ syāttatsadā naiva kārayet" },
      { type: "verse", number: "74", sanskrit: "नातिशीतोष्णवाताभ्रवेलायां सम्प्रशस्यते कृष्णभागादधः कुर्यादपाङ्गं यावदञ्जनम्", text: "nātiśītoṣṇavātābhravelāyāṃ sampraśasyate kṛṣṇabhāgādadhaḥ kuryādapāṅgaṃ yāvadañjanam" },
      { type: "verse", number: "75", sanskrit: "शङ्खनाभिर्बिभीतस्य मज्जा पथ्या मनः शिला पिप्पली मरिचं कुष्ठं वचा चेति समांशकम्", text: "śaṅkhanābhirbibhītasya majjā pathyā manaḥ śilā pippalī maricaṃ kuṣṭhaṃ vacā ceti samāṃśakam" },
      { type: "verse", number: "76", sanskrit: "छागीक्षीरेण संपिष्य वर्त्तिं कृत्वा यवोन्मिताम् हरेणुमात्रां संघृष्य जलैः कुर्यादथाञ्जनम्", text: "chāgīkṣīreṇa saṃpiṣya varttiṃ kṛtvā yavonmitām hareṇumātrāṃ saṃghṛṣya jalaiḥ kuryādathāñjanam" },
      { type: "verse", number: "77", sanskrit: "तिमिरं मांसवृद्धिं च काचं पटलमर्बुदम् रात्र्! यान्ध्यं वार्षिकं पुष्पं वर्त्तिश्चन्द्रो दया जयेत्", text: "timiraṃ māṃsavṛddhiṃ ca kācaṃ paṭalamarbudam rātr! yāndhyaṃ vārṣikaṃ puṣpaṃ varttiścandro dayā jayet" },
      { type: "verse", number: "78", sanskrit: "पलाशपुष्पस्वरसैर्बहुशः परिभाविता करञ्जीबीजवर्त्तिस्तु दृष्टेः पुष्पं विनाशयेत्", text: "palāśapuṣpasvarasairbahuśaḥ paribhāvitā karañjībījavarttistu dṛṣṭeḥ puṣpaṃ vināśayet" },
      { type: "verse", number: "79", sanskrit: "समुद्र फेनसिन्धूत्थशङ्खदक्षाण्डवल्कलैः शिग्रुबीजयुतैर्वर्त्तिः शुक्रादींश्छस्त्रवल्लिखेत्", text: "samudra phenasindhūtthaśaṅkhadakṣāṇḍavalkalaiḥ śigrubījayutairvarttiḥ śukrādīṃśchastravallikhet" },
      { type: "verse", number: "80", sanskrit: "शङ्खमुक्ताऽम्भोधिफेनयुतैः सर्वैर्विचूर्णितैः दन्तवर्त्तिः कृता श्लक्ष्णा शुक्राणां नाशिनी परा", text: "śaṅkhamuktā'mbhodhiphenayutaiḥ sarvairvicūrṇitaiḥ dantavarttiḥ kṛtā ślakṣṇā śukrāṇāṃ nāśinī parā" },
      { type: "verse", number: "81", sanskrit: "नीलोत्पलं शिग्रुबीजं नागकेशरकं तथा एतत्कल्कैः कृता वर्त्तिरतिनिद्रा ं! निवारयेत्", text: "nīlotpalaṃ śigrubījaṃ nāgakeśarakaṃ tathā etatkalkaiḥ kṛtā varttiratinidrā ṃ! nivārayet" },
      { type: "verse", number: "82", sanskrit: "तिलपुष्पाण्यशीतिः स्युः षष्टिसंख्याः कणाकणाः", text: "tilapuṣpāṇyaśītiḥ syuḥ ṣaṣṭisaṃkhyāḥ kaṇākaṇāḥ" },
      { type: "verse", number: "83", sanskrit: "जातीकुसुमपञ्चाशन्मरिचानि च षोडश सूक्ष्मं पिष्ट्वा जले वर्त्तिः कृता कुसुमिकाऽभिधा", text: "jātīkusumapañcāśanmaricāni ca ṣoḍaśa sūkṣmaṃ piṣṭvā jale varttiḥ kṛtā kusumikā'bhidhā" },
      { type: "verse", number: "84", sanskrit: "तिमिरार्जुनशुक्राणां नाशिनी मांसवृद्धिहृत् एतस्याश्चाञ्जने मात्रा प्रोक्ता सार्धहरेणुका", text: "timirārjunaśukrāṇāṃ nāśinī māṃsavṛddhihṛt etasyāścāñjane mātrā proktā sārdhahareṇukā" },
      { type: "verse", number: "85", sanskrit: "रसाञ्जनं हरिद्रे  द्वे मालतीनिम्बपल्लवाः गोशकृद्र ससंयुक्ता वर्त्तिर्नक्तान्ध्यनाशिनी", text: "rasāñjanaṃ haridre  dve mālatīnimbapallavāḥ gośakṛdra sasaṃyuktā varttirnaktāndhyanāśinī" },
      { type: "verse", number: "86", sanskrit: "धात्र्! यक्षपथ्याबीजानि एकद्वित्रिगुणानि च पिष्ट्वा वर्त्तिं जलैः कुर्यादञ्जनं द्विहरेणुकम् नेत्रस्रावं हरत्याशु वातरक्तरुजं तथा", text: "dhātr! yakṣapathyābījāni ekadvitriguṇāni ca piṣṭvā varttiṃ jalaiḥ kuryādañjanaṃ dvihareṇukam netrasrāvaṃ haratyāśu vātaraktarujaṃ tathā" },
      { type: "verse", number: "87", sanskrit: "तुत्थमाक्षिकसिन्धूत्थं सिताशङ्खमनः शिलाः गैरिकोदधिफेनं च मरिचं चेति चूर्णयेत्", text: "tutthamākṣikasindhūtthaṃ sitāśaṅkhamanaḥ śilāḥ gairikodadhiphenaṃ ca maricaṃ ceti cūrṇayet" },
      { type: "verse", number: "88", sanskrit: "संयोज्य मधुना कुर्यादञ्जनार्थं रसक्रियाम् वर्त्मरोगार्मतिमिरकाचशुक्रहरां पराम्", text: "saṃyojya madhunā kuryādañjanārthaṃ rasakriyām vartmarogārmatimirakācaśukraharāṃ parām" },
      { type: "verse", number: "89", sanskrit: "वटक्षीरेण संयुक्तो मुख्यःकर्पूरजःकणः क्षिप्रमञ्जनतो हन्ति कुसुमं तु द्विमासिकम्", text: "vaṭakṣīreṇa saṃyukto mukhyaḥkarpūrajaḥkaṇaḥ kṣipramañjanato hanti kusumaṃ tu dvimāsikam" },
      { type: "verse", number: "90", sanskrit: "क्षौद्रा श्वलालासंघृष्टैर्मरिचैर्नेत्रमञ्जयेत् अतिनिद्रा  शमं याति तमः सूर्योदयादिव", text: "kṣaudrā śvalālāsaṃghṛṣṭairmaricairnetramañjayet atinidrā  śamaṃ yāti tamaḥ sūryodayādiva" },
      { type: "verse", number: "91", sanskrit: "जातीपुष्पं प्रवालं च मरिचं कटुकी वचा सैन्धवं बस्तमूत्रेण पिष्टं तन्द्रा घ्नमञ्जनम्", text: "jātīpuṣpaṃ pravālaṃ ca maricaṃ kaṭukī vacā saindhavaṃ bastamūtreṇa piṣṭaṃ tandrā ghnamañjanam" },
      { type: "verse", number: "92", sanskrit: "अञ्जनं स्यात्प्रबोधाय सरसोनशिलावचैः", text: "añjanaṃ syātprabodhāya sarasonaśilāvacaiḥ" },
      { type: "verse", number: "93", sanskrit: "दार्वी पटोलं मधुकं सनिम्बं पद्मकोत्पलम्", text: "dārvī paṭolaṃ madhukaṃ sanimbaṃ padmakotpalam" },
      { type: "verse", number: "94", sanskrit: "प्रपौण्डरीकं चैतानि पचेत्तोये चतुर्गुणे विपाच्य पादशेषं तु शृतं नीत्वा पुनः पचेत्", text: "prapauṇḍarīkaṃ caitāni pacettoye caturguṇe vipācya pādaśeṣaṃ tu śṛtaṃ nītvā punaḥ pacet" },
      { type: "verse", number: "95", sanskrit: "शीते तस्मिन्मधुसितां दद्यात्पादांशिकां नरः रसक्रियैषा दाहाश्रुरक्तरागरुजोहरेत्", text: "śīte tasminmadhusitāṃ dadyātpādāṃśikāṃ naraḥ rasakriyaiṣā dāhāśruraktarāgarujoharet" },
      { type: "verse", number: "96", sanskrit: "रसाञ्जनं सर्जरसो जातीपुष्पं मनः शिला समुद्र फेनो लवणं गैरिकं मरिचानि च", text: "rasāñjanaṃ sarjaraso jātīpuṣpaṃ manaḥ śilā samudra pheno lavaṇaṃ gairikaṃ maricāni ca" },
      { type: "verse", number: "97", sanskrit: "एतत्समांशंमधुना पिष्ट्वा प्रक्लिन्नवर्त्मनि अञ्जनं क्लेदकण्डूघ्नंपक्ष्मणां च प्ररोहणम्", text: "etatsamāṃśaṃmadhunā piṣṭvā praklinnavartmani añjanaṃ kledakaṇḍūghnaṃpakṣmaṇāṃ ca prarohaṇam" },
      { type: "verse", number: "98", sanskrit: "गुडूचीस्वरसः कर्षः क्षौद्रं  स्यान्माषकोन्मितम् सैन्धवं क्षौद्र तुल्यं स्यात्सर्वमेकत्र मर्दयेत्", text: "guḍūcīsvarasaḥ karṣaḥ kṣaudraṃ  syānmāṣakonmitam saindhavaṃ kṣaudra tulyaṃ syātsarvamekatra mardayet" },
      { type: "verse", number: "99", sanskrit: "अञ्जयेन्नयनं तेन पिल्लार्मतिमिरं जयेत् काचं कण्डूं लिङ्गनाशंशुक्लकृष्णगतान्गदान्", text: "añjayennayanaṃ tena pillārmatimiraṃ jayet kācaṃ kaṇḍūṃ liṅganāśaṃśuklakṛṣṇagatāngadān" },
      { type: "verse", number: "100", sanskrit: "दुग्धेन कण्डूं क्षौद्रे ण नेत्रस्रावं च सर्पिषा पुष्पं तैलेन तिमिरं काञ्जिकेन निशान्ध्यताम् पुनर्नवा जयेदाशु भास्करस्तिमिरं यथा", text: "dugdhena kaṇḍūṃ kṣaudre ṇa netrasrāvaṃ ca sarpiṣā puṣpaṃ tailena timiraṃ kāñjikena niśāndhyatām punarnavā jayedāśu bhāskarastimiraṃ yathā" },
      { type: "verse", number: "101", sanskrit: "बब्बूलदलनिःक्वाथो लेहीभूतस्तदञ्जनात् नेत्रस्रावं जयत्येष मधुयुक्तो न संशयः", text: "babbūladalaniḥkvātho lehībhūtastadañjanāt netrasrāvaṃ jayatyeṣa madhuyukto na saṃśayaḥ" },
      { type: "verse", number: "102", sanskrit: "हिज्जलस्य फलं घृष्ट्वा पानीये नित्यमञ्जनम् चक्षुःस्रावोपशान्त्यर्थं कार्यमेतन्महौषधम्", text: "hijjalasya phalaṃ ghṛṣṭvā pānīye nityamañjanam cakṣuḥsrāvopaśāntyarthaṃ kāryametanmahauṣadham" },
      { type: "verse", number: "103", sanskrit: "नेत्रप्रसादनं कतकादिरसाञ्जनम् कतकस्यफलं घृष्ट्वा मधुना नेत्रमञ्जयेत् ईषत्कर्पूरसहितं स्मृतं नेत्रप्रसादनम्", text: "netraprasādanaṃ katakādirasāñjanam katakasyaphalaṃ ghṛṣṭvā madhunā netramañjayet īṣatkarpūrasahitaṃ smṛtaṃ netraprasādanam" },
      { type: "verse", number: "104", sanskrit: "सर्पिः क्षौद्रं  चाञ्जनं स्याच्छिरोत्पातस्य शान्तये", text: "sarpiḥ kṣaudraṃ  cāñjanaṃ syācchirotpātasya śāntaye" },
      { type: "verse", number: "105", sanskrit: "कृष्णसर्पवसा शङ्खः कतकात्फलमञ्जनम् रसक्रियेयमचिरादन्धानां दर्शनप्रदा", text: "kṛṣṇasarpavasā śaṅkhaḥ katakātphalamañjanam rasakriyeyamacirādandhānāṃ darśanapradā" },
      { type: "verse", number: "106", sanskrit: "द्र व्यैरञ्जनयोगोऽय पुष्पार्मादिविलेखनः", text: "dra vyairañjanayogo'ya puṣpārmādivilekhanaḥ" },
      { type: "verse", number: "107", sanskrit: "कणा छागयकृन्मध्ये पक्त्वा नेत्रयुगेऽञ्जिता अचिराद्धन्ति नक्तान्ध्यं तद्वत्सक्षौद्र मूषणम्", text: "kaṇā chāgayakṛnmadhye paktvā netrayuge'ñjitā acirāddhanti naktāndhyaṃ tadvatsakṣaudra mūṣaṇam" },
      { type: "verse", number: "108", sanskrit: "शाणार्धं मरिचं द्वौ च पिप्पल्यर्णवफेनयोः शाणार्धं सैन्धवं शाणा नव सौवीरकाञ्जनात्", text: "śāṇārdhaṃ maricaṃ dvau ca pippalyarṇavaphenayoḥ śāṇārdhaṃ saindhavaṃ śāṇā nava sauvīrakāñjanāt" },
      { type: "verse", number: "109", sanskrit: "पिष्टं सुसूक्ष्मं चित्रायां चूर्णाञ्जनमिदं शुभम् कण्डूकाचकफार्त्तानां मलानां च विशोधनम्", text: "piṣṭaṃ susūkṣmaṃ citrāyāṃ cūrṇāñjanamidaṃ śubham kaṇḍūkācakaphārttānāṃ malānāṃ ca viśodhanam" },
      { type: "verse", number: "110", sanskrit: "शिलायां रसकं पिष्ट्वा सम्यगाप्लाव्य वारिणा गृह्णीयात्तज्जलं सर्वं त्यजेच्चूर्णमधोगतम्", text: "śilāyāṃ rasakaṃ piṣṭvā samyagāplāvya vāriṇā gṛhṇīyāttajjalaṃ sarvaṃ tyajeccūrṇamadhogatam" },
      { type: "verse", number: "111", sanskrit: "शुष्कं च तज्जलं सर्वं पर्पटीसंनिभं भवेत् विचूर्ण्य भावयेत्सम्यक्त्रिवेलं त्रिफलारसैः", text: "śuṣkaṃ ca tajjalaṃ sarvaṃ parpaṭīsaṃnibhaṃ bhavet vicūrṇya bhāvayetsamyaktrivelaṃ triphalārasaiḥ" },
      { type: "verse", number: "112", sanskrit: "कर्पूरस्य रजस्तत्र दशमांशेन निक्षिपेत् अञ्जयेन्नयने तेन सर्वदोषहरं हि तत् सर्वरोगहरं चूर्णं चक्षुषोः सुखकारि च", text: "karpūrasya rajastatra daśamāṃśena nikṣipet añjayennayane tena sarvadoṣaharaṃ hi tat sarvarogaharaṃ cūrṇaṃ cakṣuṣoḥ sukhakāri ca" },
      { type: "verse", number: "113", sanskrit: "अग्नितप्तं हि सौवीरं निषिञ्चेत्त्रिफलारसैः सप्तवेलं तथा स्तन्यैः स्त्रीणां सिक्तं विचूर्णितम्", text: "agnitaptaṃ hi sauvīraṃ niṣiñcettriphalārasaiḥ saptavelaṃ tathā stanyaiḥ strīṇāṃ siktaṃ vicūrṇitam" },
      { type: "verse", number: "114", sanskrit: "अञ्जयेत्तेन नयने प्रत्यहं चक्षुषोर्हितम् सर्वानक्षिविकारांस्तु हन्यादेतन्न संशयः", text: "añjayettena nayane pratyahaṃ cakṣuṣorhitam sarvānakṣivikārāṃstu hanyādetanna saṃśayaḥ" },
      { type: "verse", number: "115", sanskrit: "त्रिफलाभृङ्गशुण्ठीनां रसैस्तद्वच्च सर्पिषा", text: "triphalābhṛṅgaśuṇṭhīnāṃ rasaistadvacca sarpiṣā" },
      { type: "verse", number: "116", sanskrit: "गोमूत्रमध्वजाक्षीरैः सिक्तो नागः प्रतापितः तच्छलाका हरत्येव सर्वान्नेत्रभवान्गदान्", text: "gomūtramadhvajākṣīraiḥ sikto nāgaḥ pratāpitaḥ tacchalākā haratyeva sarvānnetrabhavāngadān" },
      { type: "verse", number: "117", sanskrit: "गतदोषमपेताश्रु संपश्यन्सम्यगम्भसि प्रक्षाल्याक्षि यथादोषं कार्यं प्रत्यञ्जनं ततः", text: "gatadoṣamapetāśru saṃpaśyansamyagambhasi prakṣālyākṣi yathādoṣaṃ kāryaṃ pratyañjanaṃ tataḥ" },
      { type: "verse", number: "118", sanskrit: "न वाऽनिर्गतदोषेऽक्ष्णि धावनं संप्रयोजयेत् प्रत्यञ्जनं तीक्ष्णतप्ते नेत्रे चूर्णं प्रसादनम्", text: "na vā'nirgatadoṣe'kṣṇi dhāvanaṃ saṃprayojayet pratyañjanaṃ tīkṣṇatapte netre cūrṇaṃ prasādanam" },
      { type: "verse", number: "119", sanskrit: "शुद्धे नागे द्रुते तुल्यं शुद्धं सूतं विनिक्षिपेत् कृष्णाञ्जनं तयोस्तुल्यं सर्वमेकत्र चूर्णयेत्", text: "śuddhe nāge drute tulyaṃ śuddhaṃ sūtaṃ vinikṣipet kṛṣṇāñjanaṃ tayostulyaṃ sarvamekatra cūrṇayet" },
      { type: "verse", number: "120", sanskrit: "दशमांशेन कर्पूरं तस्मिंश्चूर्णे प्रदापयेत् एतत्प्रत्यञ्जनं नेत्रगदजिन्नयनामृतम्", text: "daśamāṃśena karpūraṃ tasmiṃścūrṇe pradāpayet etatpratyañjanaṃ netragadajinnayanāmṛtam" },
      { type: "verse", number: "121", sanskrit: "जयपालभवां मज्जां भावयेन्निम्बुकद्र वैः एकविंशतिवेलं तत्ततो वर्त्तिं प्रकल्पयेत्", text: "jayapālabhavāṃ majjāṃ bhāvayennimbukadra vaiḥ ekaviṃśativelaṃ tattato varttiṃ prakalpayet" },
      { type: "verse", number: "122", sanskrit: "मनुष्यलालया घृष्ट्वा ततो नेत्रे तयाऽञ्जयेत् सर्पदष्टविषं जित्वा संजीवयति मानवम्", text: "manuṣyalālayā ghṛṣṭvā tato netre tayā'ñjayet sarpadaṣṭaviṣaṃ jitvā saṃjīvayati mānavam" },
      { type: "verse", number: "123", sanskrit: "भुक्त्वा पाणितलं घृष्ट्वा चक्षुषोर्दीयते यदि जाता रोगा विनश्यन्ति तिमिराणि तथैव च", text: "bhuktvā pāṇitalaṃ ghṛṣṭvā cakṣuṣordīyate yadi jātā rogā vinaśyanti timirāṇi tathaiva ca" },
      { type: "verse", number: "124", sanskrit: "शीताम्बुपूरितमुखः प्रतिवासरं यः कालत्रयेण नयनद्वितयं जलेन आसिञ्चति ध्रुवमसौ न कदाचिदक्षिरोगव्यथाविधुरतां भजते मनुष्यः", text: "śītāmbupūritamukhaḥ prativāsaraṃ yaḥ kālatrayeṇa nayanadvitayaṃ jalena āsiñcati dhruvamasau na kadācidakṣirogavyathāvidhuratāṃ bhajate manuṣyaḥ" },
      { type: "verse", number: "125", sanskrit: "ग्रन्थकर्तृकृतं नम्रनिवेदनम् आयुर्वेदसमुद्र स्य गूढार्थमणिसंचयम् ज्ञात्वा कैश्चिद् बुधैस्तैस्तु कृता विविधसंहिताः", text: "granthakartṛkṛtaṃ namranivedanam āyurvedasamudra sya gūḍhārthamaṇisaṃcayam jñātvā kaiścid budhaistaistu kṛtā vividhasaṃhitāḥ" },
      { type: "verse", number: "126", sanskrit: "किञ्चिदर्थं ततो नीत्वा कृतेयं संहिता मया कृपाकटाक्षनिक्षेपमस्यां कुर्वन्तु साधवः", text: "kiñcidarthaṃ tato nītvā kṛteyaṃ saṃhitā mayā kṛpākaṭākṣanikṣepamasyāṃ kurvantu sādhavaḥ" },
      { type: "verse", number: "127", sanskrit: "विविधगदार्तिदरिद्र नाशनं या हरिरमणीव करोति योगरत्नैः विलसतु शार्ङ्गधरस्य संहिता सा जन हृदयेषु सरोजनिर्मलेषु", text: "vividhagadārtidaridra nāśanaṃ yā hariramaṇīva karoti yogaratnaiḥ vilasatu śārṅgadharasya saṃhitā sā jana hṛdayeṣu sarojanirmaleṣu" },
      { type: "verse", number: "128", sanskrit: "अल्पायुषामल्पधियामिदानीं कृतं समस्तश्रुतिपाठशक्त्या तदत्र युक्तं प्रतिबीजमात्रमभ्यस्यतामात्महितं प्रयत्नात्", text: "alpāyuṣāmalpadhiyāmidānīṃ kṛtaṃ samastaśrutipāṭhaśaktyā tadatra yuktaṃ pratibījamātramabhyasyatāmātmahitaṃ prayatnāt" },
    ],
  },
];
